BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS introductions (
	book_number NUMERIC NOT NULL DEFAULT 0, 
	introduction TEXT NOT NULL DEFAULT '', 
	PRIMARY KEY (book_number));
INSERT INTO "introductions" ("book_number","introduction") VALUES (0,'<p>பரிசுத்த வேதாகமம் 2017 - Tamil Holy Bible 2017 - Old Version - O.V</p>
<p>Also called as பரிசுத்த வேதாகமம் பழைய திருப்புதல், ஐக்கிய திருப்புதல், பாவர் மொழிப்பெயர்ப்பு, Tamil Bible Old Version, Union Version, Bower Version, OV version</p>
<p><b>Published Year:</b> 1871, Updated 2017</p>
<p><b>Published By:</b> First by British and Foreign Bible Society, now by Bible Society of India, Ceylon Bible Society, Emmanuel Publications, Tamil Bible Society, etc</p>
<p><b>Translated By:</b> Rev. Dr. Henry Bower (1812-1885), missionary of SPG, Society for the Propagation of the Gospel, with the assistance of E. Sundaram Pillai and others. The New Testament was published in 1863 and the Old Testament in 1868; but the renderings of the Bower Committee aroused grave dissatisfaction in north Ceylon and a conference of delegates from both sides was called. A mutually accepted version of the whole Bible called the Union Version, because of the representative character of those who had produced it, was published in 1871.</p>
<p><b>Copyright:</b> Public Domain. This version named Tamil Old Version / Bower Version is available in Public Domain. High volumes of printing is done by Bible Society of India and updating the text is done by various organizations like Bible Society of India, Bridge Connectivity Solutions, etc.</p>'),
 (10,'<p><b>ஆதியாகமம் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>ஆதியாகமம் புத்தகத்தின் எழுத்தாளர் யார் என்று குறிப்பாக அடையாளம் கண்டுகொள்ளப்படவில்லை. ஆனால், பாரம்பரியமாக, தொன்றுதொட்டு தொடர்ச்சியாக இந்த புத்தகத்தின் எழுத்தாளர் மோசே என்று நம்பப்பட்டும் கருதப்பட்டும் வருகிறது. ஆதியாகமத்தின் எழுத்தாளர் மோசேதான் என்பதை மறுப்பதற்கு உறுதியான காரணங்கள் எதுவும் இல்லை.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>ஆதியாகமம் புத்தகம் எப்போது எழுதப்பட்டது என்று அதில் குறிப்பிடவில்லை. மோசே இஸ்ரவேலரை எகிப்தின் அடிமைத்தனத்திலிருந்து விடுவித்து புறப்படப்பண்ணி வெளியே அழைத்துச் சென்ற காலத்திற்கும் அவரது மரணத்திற்கும் இடையில், எழுதப்பட்டிருக்கலாம் என நம்பபடுகிறது. அதாவது கி.மு. 1440 முதல் கி.மு. 1400 வரையிலுள்ள காலத்தில் எழுதப்பட்டிருக்கலாம்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>ஆதியாகமம் புத்தகம் சில நேரங்களில் முழு வேதாகமத்தினுடைய \"விதைக்கரு\" என்று அழைக்கப்படுகிறது. வேதாகமத்திலுள்ள பெரும்பாலான முக்கிய கோட்பாடுகள் ஆதியாகமம் புத்தகத்தில் \"விதை\" வடிவத்தில் அறிமுகப்படுத்தப்பட்டுள்ளன. மனிதனின் வீழ்ச்சி, அவனுடைய இரட்சிப்பு அல்லது மீட்பினைக் குறித்த தேவனுடைய வாக்குறுதியும் பதிவு செய்யப்பட்டுள்ளது (ஆதியாகமம் 3:15). சிருஷ்டிப்பின் கோட்பாடுகள், பாவத்தின் குற்றச்சாட்டு, நீதிமானாக்குதல், பிராயச்சித்தம், சீரழிவு, கோபம், கருணை, இறையாண்மை, பொறுப்பு மற்றும் இன்னும் பலதும் ஆதியாகமம் எனப்படும் இந்த புத்தகத்தில் அவைகளின் தோற்றம் குறிப்பிடப்பட்டுள்ளன.</p><p>வாழ்க்கையின் பல பெரிய கேள்விகளுக்கு ஆதியாகமத்தில் பதில் அளிக்கப்படுகிறது. (1) நான் எங்கிருந்து வந்தேன்? (தேவன் நம்மைப் படைத்தார் - ஆதியாகமம் 1:1) (2) நான் ஏன் இங்கே இருக்கிறேன்? (தேவனோடு உறவு கொள்ள நாம் இங்கு வந்துள்ளோம் - ஆதியாகமம் 15:6) (3) நான் எங்கே போகிறேன்? (மரணத்திற்குப் பிறகு நமக்கு ஒரு இடம் இருக்கிறது - ஆதியாகமம் 25:8). ஆதியாகமம் புத்தகம், விஞ்ஞானி, வரலாற்றாசிரியர், இறையியலாளர், இல்லத்தரசி, விவசாயி, பயணி மற்றும் தேவனுடைய மனிதனோ மனுஷியோ யாவருக்கும் ஏற்றதாக இருந்து முறையிடுகிறது. மனிதகுலத்திற்கான தேவனுடைய திட்டமான வேதாகமத்தின் கதைக்கு இந்த புத்தகம் ஒரு பொருத்தமான தொடக்கமாகும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>ஆதியாகமம் 1:1, \"ஆதியிலே தேவன் வானத்தையும் பூமியையும் சிருஷ்டித்தார்.\"</p><p>ஆதியாகமம் 3:15, \"உனக்கும் ஸ்திரீக்கும், உன் வித்துக்கும் அவள் வித்துக்கும் பகை உண்டாக்குவேன்; அவர் உன் தலையை நசுக்குவார், நீ அவர் குதிங்காலை நசுக்குவாய் என்றார்.\"</p><p>ஆதியாகமம் 12:2-3, \"நான் உன்னைப் பெரிய ஜாதியாக்கி, உன்னை ஆசீர்வதித்து, உன் பேரைப் பெருமைப்படுத்துவேன்; நீ ஆசீர்வாதமாய் இருப்பாய். உன்னை ஆசீர்வதிக்கிறவர்களை ஆசீர்வதிப்பேன், உன்னைச் சபிக்கிறவனைச் சபிப்பேன்; பூமியிலுள்ள வம்சங்களெல்லாம் உனக்குள் ஆசீர்வதிக்கப்படும் என்றார்.\"</p><p>ஆதியாகமம் 50:20, \"நீங்கள் எனக்குத் தீமைசெய்ய நினைத்தீர்கள்; தேவனோ, இப்பொழுது நடந்துவருகிறபடியே, வெகு ஜனங்களை உயிரோடே காக்கும்படிக்கு, அதை நன்மையாக முடியப்பண்ணினார்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>ஆதியாகமம் புத்தகத்தை இரண்டு பிரிவுகளாகப் பிரிக்கலாம்: ஆதி வரலாறு மற்றும் முற்பிதாக்களின் வரலாறு. ஆதி வரலாற்றுப் பதிவுகள் (1) சிருஷ்டிப்பு (ஆதியாகமம் 1-2 அதிகாரங்கள்); (2) மனிதனின் வீழ்ச்சி (ஆதியாகமம் 3-5 அதிகாரங்கள்); (3) ஜலப்பிரளயம் (ஆதியாகமம் 6-9 அதிகாரங்கள்); மற்றும் (4) சிதறடிக்கப்படுதல் (ஆதியாகமம் 10-11 அதிகாரங்கள்) ஆகியவற்றை பதிவுச் செய்கிறது. முற்பிதாக்களின் வரலாறு நான்கு முக்கியமான மனிதர்களின் வாழ்க்கையை பதிவு செய்கிறது: (1) ஆபிரகாம் (ஆதியாகமம் 12-25:8); (2) ஈசாக்கு (ஆதியாகமம் 21:1-35-29); (3) யாக்கோபு (ஆதியாகமம் 25:21-50: 14); மற்றும் (4) யோசேப்பு (ஆதியாகமம் 30:22-50:26).</p><p>தேவன் பாவத்தில் விழாத நன்றாக இருந்த ஒரு பிரபஞ்சத்தை படைத்தார். அவருடன் தனிப்பட்ட உறவைப் பெற தேவன் மனிதகுலத்தைப் படைத்தார். ஆதாமும் ஏவாளும் கீழ்ப்படியாமையால் பாவம் செய்து அதன் மூலமாக தீமையையும் மரணத்தையும் உலகிற்குக் கொண்டு வந்தார்கள். தேவன் எதையும் நல்லதாகக் காணும் ஒரே ஒரு குடும்பம் மட்டும் தவிர்த்து உலகில் மீதமுள்ள அனைவரும் அனைத்தும் தீமைக்குள்ளாக சீராக அதிகரித்து இருந்தன. தீமையைத் துடைக்க தேவன் ஜலப்பிரளயத்தை அனுப்பினார், ஆனால் நோவாவையும் அவருடைய குடும்பத்தினரையும் பேழையில் இருந்த விலங்குகளுடன் மீட்டார். ஜலப்பிரளயத்திற்குப் பிறகு, மனிதகுலம் மீண்டும் பலுகிப்பெருகி உலகம் முழுவதும் பரவத் தொடங்கியது.</p><p>தேவன் ஆபிரகாமைத் தேர்ந்தெடுத்தார், அவர் மூலம் தேர்ந்தெடுக்கப்பட்ட மக்களையும் இறுதியில் வாக்களிக்கப்பட்ட மேசியாவையும் வரும்படி செய்தார். தேர்ந்தெடுக்கப்பட்ட வரிசை ஆபிரகாமின் குமாரன் ஈசாக்கிற்கும், பின்னர் ஈசாக்கின் குமாரன் யாக்கோபுவுக்கும் அனுப்பப்பட்டது. தேவன் யாக்கோபின் பெயரை இஸ்ரவேல் என்று மாற்றினார், அவருடைய பன்னிரண்டு குமாரர்களும் இஸ்ரவேலின் பன்னிரண்டு கோத்திரங்களின் பிதாக்களானார்கள். தேவன் தமது இறையாண்மையில், யாக்கோபின் குமாரன் யோசேப்பை எகிப்துக்கு அனுப்பினார். சகோதரர்களால் தீமையை நோக்கமாகக் கொண்ட இந்த செயல், தேவனால் நன்மை செய்யப்பட வேண்டும் என்று, இறுதியில் எகிப்தில் பெரும் அதிகாரமுள்ள சக்தியாக உயர்ந்த யோசேப்பு அவர்களால் பேரழிவுகரமான பஞ்சத்திலிருந்து யாக்கோபும் அவரது குடும்பத்தினரும் காப்பாற்றப்பட்டனர்.</p><p><b>முன்னிழல்கள்:</b></p><p>பல புதிய ஏற்பாட்டு கருப்பொருள்கள் ஆதியாகமத்தில் வேர்களைக் கொண்டுள்ளன. இயேசு கிறிஸ்து சாத்தானின் வல்லமையை அழிக்கும் ஸ்திரீயின் வித்து (ஆதி. 3:15). யோசேப்பைப் போலவே, இயேசுவை சிலுவையில் அறைந்தவர்கள் அதை தீமைக்காக நோக்கினாலும், தம்முடைய குமாரனுடைய பலியின் மூலம் மனிதகுலத்தின் நன்மைக்கான தேவனின் திட்டம் நன்மைக்காகவே கருதப்பட்டது. வேதாகமத்தில் சித்தரிக்கப்பட்டுள்ள பல மீதியானவர்களில் நோவாவும் அவருடைய குடும்பத்தினரும் முதன்மையானவர்கள் ஆகும். மிகுந்த முரண்பாடுகள் மற்றும் கடினமான சூழ்நிலைகள் இருந்தபோதிலும், உண்மையுள்ளவர்களின் மீதியை தேவன் எப்போதும் தனக்காகவே பாதுகாக்கிறார். இஸ்ரவேலரின் எஞ்சியவர்கள் பாபிலோனிய சிறைவாசத்திற்குப் பிறகு எருசலேமுக்குத் திரும்பினர்; ஏசாயா மற்றும் எரேமியாவில் விவரிக்கப்பட்டுள்ள எல்லா துன்புறுத்தல்களினாலும் தேவன் ஒரு மீதியான கூட்டத்தை பாதுகாத்தார்; 7000 ஆசாரியர்களில் எஞ்சியவர்கள் யேசபேலின் கோபத்திலிருந்து பாதுகாக்கப்பட்டார்கள்; யூதர்களில் எஞ்சியவர்கள் ஒரு நாள் அவர்களின் உண்மையான மேசியாவை ஏற்றுக்கொள்வார்கள் என்று தேவன் வாக்குப்பண்ணினார் (ரோமர் 11). தேவன் மேல் ஆபிரகாம் காண்பித்த விசுவாசம், தேவனுடைய பரிசாகவும் யூதருக்கும் புறஜாதியினருக்கும் இரட்சிப்பின் அடிப்படையாகவும் இருக்கும்படி செய்தது (எபேசியர் 2:8-9; எபிரெயர் 11).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>ஆதியாகமத்தின் முக்கிய கருப்பொருள் தேவனுடைய நித்திய இருப்பு மற்றும் அவர் உலகத்தை உருவாக்கியதாகும். தேவனுடைய இருப்பைக் காக்க எழுத்தாளரின் தரப்பில் எந்த முயற்சியும் இல்லை; தேவன் எல்லாவற்றிற்கும் மேலாக சர்வவல்லமையுள்ளவர், எப்போதும் இருக்கிறவராகவே இருந்தார், எப்போதும் இருப்பார் என்று எழுத்தாளர் எளிய நடையில் கூறுகிறார். அதேபோல், ஆதியாகமத்தின் உண்மைகளை மறுப்பவர்களின் கூற்றுக்கள் ஒருபுறம் இருந்தபோதிலும், நமக்கு இவைகளின் மேல் நம்பிக்கை உள்ளது. எல்லா மக்களும், கலாச்சாரம், தேசியம் அல்லது மொழி ஆகியவற்றைப் பொருட்படுத்தாமல், சிருஷ்டிகருக்கு பொறுப்புக் கூற வேண்டியவர்களாக இருக்கிறார்கள். ஆனால் மனிதனுடைய வீழ்ச்சியின் போது, உலகிற்கு அறிமுகப்படுத்தப்பட்ட பாவத்தின் காரணமாக, நாம் தேவனிடமிருந்து பிரிக்கப்படுகிறோம். ஆனால் ஒரு சிறிய தேசமான இஸ்ரவேல் மூலம், மனிதகுலத்திற்கான தேவனுடைய மீட்பின் திட்டம் வெளிப்படுத்தப்பட்டு அது அனைவருக்கும் கிடைத்தது. அந்த திட்டத்தில் தான் நாமும் பயனடைந்து மகிழ்ச்சியடைகிறோம்.</p><p>தேவன் பிரபஞ்சத்தையும், பூமியையும், அதிலுள்ள ஒவ்வொரு உயிரினத்தையும் படைத்தார். நம் வாழ்வில் உள்ள கவலைகளை கையாள நாம் பூரணமாக அவரை நம்பலாம். தேவன் ஒரு நம்பிக்கையற்ற சூழ்நிலையை எடுத்து முற்றிலுமாய் அதை மாற்ற வல்லவராக இருக்கிறார்; அதாவது ஆபிரகாமும் சாராவும் குழந்தை இல்லாதவர்களாக இருந்தார்கள், ஆனால் அவர்கள் தேவனை நம்பினபடியால் தேவன் அவர்களை ஆசிர்வதித்தார். நாமும் வெறுமனே அவரை நம்பி அவருக்கு கீழ்ப்படிந்தால் ஆச்சரியமான காரியங்களைத் தேவன் செய்வார். யோசேப்பைப் போலவே நம் வாழ்க்கையிலும் பயங்கரமான மற்றும் அநியாயமான விஷயங்கள் நடக்கக்கூடும், ஆனால் தேவன் மீதும் அவருடைய இறையாண்மைத் திட்டத்தின் மீதும் நம்பிக்கை இருந்தால், தேவன் எப்போதும் ஒரு சிறந்த நன்மையைக் கொண்டுவருவார். \"அன்றியும், அவருடைய தீர்மானத்தின்படி அழைக்கப்பட்டவர்களாய் தேவனிடத்தில் அன்புகூருகிறவர்களுக்குச் சகலமும் நன்மைக்கு ஏதுவாக நடக்கிறதென்று அறிந்திருக்கிறோம்\" (ரோமர் 8:28).</p><p><b>ஆதியில் வானபூமி  படைப்பு</b></p><p><b>படைப்புதொடர்ச்சி</b></p><p>சுமார் கி.மு. 4004 - ஆதாமின் வீழ்ச்சி</p><p>சுமார் கி.மு. 3017 - ஏனோக்கு எடுக்கப்படல்</p><p>சுமார் கி.மு. 2348 - ஜலபிரளயம்</p><p>சுமார் கி.மு. 2241 -2008 - பூமி பிளத்தல் (பேலேகின் காலம்)</p><p>சுமார் கி.மு. 1921 (2091) - ஆபிரகாமின் 2-ம் அழைப்பு</p><p>சுமார் கி.மு. 896 (2066) - ஈசாக்கின் (சந்ததி) பிறப்பு</p><p>சுமார் கி.மு. 1836 (2006) - யாக்கோபின் பிறப்பு இஸ்ரவேல்,</p><p>சுமார் கி.மு. 1706 (1876) - யாக்கோபு எகிப்துக்குச் செல்லுதல்</p><p>சுமார் கி.மு.1635 1805) - யோசேப்பின் மரணம்</p><p><b>ஆசிரியர் குறிப்பு.</b></p><p>பெயர் - மோசே (பொருள்: இழுத்தெடுக்கப்பட்டவர்)</p><p>பெற்றோர் - தந்தை அம்ராம்</p><p>தாய் - யோகெபேத் (யாத் 6 : 20). பின்பு பார்வோனின் மகளால் தத்தெடுக்கப்பட்டவர்</p><p>சொந்த இடம் - எகிப்து</p><p>தொழில் - அரண்மனை கல்வி, பின்பு ஆடு மேய்ப்பு அதன்பின் இலட்சக்கணக்கான மக்களை கானானுக்கு வழிநடத்தியது\"</p><p>திருப்புமுனை  - மந்தைமேய்த்துக் கொண்டிருக்கும்போது\" முட்செடியில் தேவனைத் தரிசித்தபின் வந்த அழைப்பு</p><p>ஆர்வம் - எபிரெயரை விடுவித்து, பத்திரமாக</p><p>கானானுக்கு வழிநடத்துவது</p><p>சாதனைகள்  - பார்வோனுக்கு முன் அற்புதங்களைச் செய்தது, ஐந்தாகமங்களை எழுதியது. உலகத்தோற்றம் பற்றிய</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் முதல் நூல்</p><p>அதிகாரங்கள் - 50</p><p>வசனங்கள் - 1533</p><p>வரலாற்று வசனங்கள் - 1385</p><p>கேளவிகள் - 148</p><p>தீர்ககதரிசனங்க - 146</p><p>நிறைவேறிய தீர்க்க தரிசனங்கள் - 123</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 23</p><p>சிறிய அதிகாரங்கள் - 16</p><p>பெரிய அதிகாரங்கள் - 24</p><p>கட்டளைகள் - 106</p><p>வாக்குத்தத்தங்கள் - 71</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 95</p><p>எச்சரிக்கைகள் - 326</p><p>முதல் தோட்டக்காரர் - ஆதாம் (2 : 15)</p><p>முதல் நகர அமைப்பாளர் - காயீன் (4:1)</p><p>முதல் மேய்ப்பன் - ஆபேல் (4 : 2)</p><p>முதல் பலதார மணம் புரிந்தவர் - லாமேக்கு (4 : 19)</p><p>முதல் இசைக்கலைஞர் - யூபால் (4 ; 21)</p><p>முதல் கொல்லர் - தூபால்காயீன் (4:22)</p><p>இறக்காத முதல் மனிதர் - ஏனோக்கு (5 : 21)</p><p>முதல் கப்பல் கட்டியவர் - நோவா (6 : 9)</p><p>முதல் அரசன்-நிம்ரோத் (10: 8)</p><p>முதல் கோபுரப் பணி - பாபேலில் (1)</p><p>முதல் செங்கல் பணி -  பாபேலில் (1)</p><p>முதல் குகை வாசிகள் - லோத்தும் புதல்விகளும் (19:30)</p><p>முதல் நிலப் பதிவு உடன்பாடு - ஆபிரகாம் செய்தது (23)</p><p>முதல் நடுகல் குறிப்பு - ராகேலுடையது (35 : 20)</p>'),
 (100,'<p><b>2 சாமுவேலின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>2 சாமுவேல் புத்தகம் அதன் எழுத்தாளர் யார் என்பதைக்குறித்து குறிப்பாக அடையாளம் காண்பிக்கவில்லை. சாமுவேல் தீர்க்கதரிசி 1 சாமுவேல் புத்தகத்தில் இறந்துவிடுவதால், அது அவராக இருக்க முடியாது. சாத்தியமான எழுத்தாளர்களில் தீர்க்கதரிசிகளாகிய நாத்தான் மற்றும் காத் ஆகியோர் அடங்குவர் (1 நாளாகமம் 29:29-ஐக் காண்க).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>முதலில், 1 மற்றும் 2 சாமுவேலின் புத்தகங்கள் ஒரே புத்தகமாக இருந்தன. செப்டுவஜின்ட்டின் மொழிபெயர்ப்பாளர்கள் அவைகளைப் இரண்டாகப் பிரித்தனர், அன்றிலிருந்து அந்த பிரிவுகளை நாம் தக்க வைத்துக் கொண்டோம். 1 சாமுவேலின் நிகழ்வுகள் சுமார் 100 ஆண்டுகள், அதாவது கி.மு. 1100 முதல் கி.மு. 1000 வரையிலுள்ள காலத்தில் சம்பவித்தவைகளை உள்ளடக்கியுள்ளன. 2 சாமுவேலின் நிகழ்வுகள் இன்னும் 40 ஆண்டுகள் நிகழ்வுகளை உள்ளடக்கியது. எழுதப்பட்ட காலம் கி.மு. 960 ஆம் ஆண்டிற்கு பிறகு.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>2 சாமுவேல் புத்தகம் தாவீது ராஜாவினுடைய ராஜ்யபாரம் குறித்த பதிவாகும். இந்த புத்தகம் தாவீதோடு தேவன் செய்த உடன்படிக்கையை அதன் வரலாற்று சூழலில் வைக்கிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>\"உன் வீடும், உன் ராஜ்யமும், என்றென்றைக்கும் உனக்கு முன்பாக ஸ்திரப்பட்டிருக்கும்; உன் ராஜாசனம் என்றென்றைக்கும் நிலைபெற்றிருக்கும் என்கிறார் என்று சொல்லச்சொன்னார்\" (2 சாமுவேல் 7:16).</p><p>\"ராஜா தன் முகத்தை மூடிக்கொண்டு, மகா சத்தமாய்: என் மகனாகிய அப்சலோமே, அப்சலோமாகிய என் மகனே, என் மகனே என்று அலறிக்கொண்டிருந்தான்\" (2 சாமுவேல் 19:4).</p><p>\"கர்த்தர் என் கன்மலையும், என் கோட்டையும், என் இரட்சகருமானவர். தேவன் நான் நம்பியிருக்கிற துருக்கமும், என் கேடகமும், என் இரட்சணியக்கொம்பும், என் உயர்ந்த அடைக்கலமும், என் புகலிடமும், என் இரட்சகருமானவர்; என்னை வல்லடிக்கு நீங்கலாக்கி இரட்சிக்கிறவர் அவரே. ஸ்துதிக்குப் பாத்திரராகிய கர்த்தரை நோக்கிக் கூப்பிடுவேன்; அதனால் என் சத்துருக்களுக்கு நீங்கலாக்கிஇ ரட்சிக்கப்படுவேன்\" (2 சாமுவேல் 22:2-4).</p><p><b>சுருக்கமான திரட்டு:</b></p><p>2 சாமுவேலின் புத்தகத்தை இரண்டு முக்கிய பிரிவுகளாகப் பிரிக்கலாம் - தாவீதின் வெற்றிகள் (1-10 வரையிலுள்ள அதிகாரங்கள்) மற்றும் தாவீதின் பாடுகள் (11-20 வரையிலுள்ள அதிகாரங்கள்). புத்தகத்தின் கடைசி பகுதி (21-24 வரையிலுள்ள அதிகாரங்கள்) என்பது காலவரிசை அல்லாத பின் இணைப்பு ஆகும், இது தாவீதின் ராஜ்யபாரத்தின் கூடுதல் விவரங்களைக் கொண்டுள்ளது.</p><p>சவுல் மற்றும் அவரது குமாரர்களின் மரணம் பற்றிய செய்தியை தாவீது பெறுவதுடன் இந்த புத்தகம் தொடங்குகிறது. அவர் துக்க நேரத்தை அறிவிக்கிறார். விரைவில், தாவீது யூதாவின்மீது ராஜாவாக முடிசூட்டப்படுகிறார், அதே சமயம் சவுலின் எஞ்சிய குமாரர்களில் ஒருவரான இஸ்போசேத் இஸ்ரவேலின் ராஜாவாக முடிசூட்டப்படுகிறான் (அதிகாரம் 2). ஒரு உள்நாட்டு யுத்தம் தொடர்கிறது, ஆனால் இஸ்போசேத் கொலை செய்யப்படுகிறார், இஸ்ரவேலர்கள் தாவீதை அவர்கள் மீது ஆட்சி செய்யும்படி கேட்கிறார்கள் (4-5 அதிகாரங்கள்).</p><p>தாவீது நாட்டின் தலைநகரை எபிரோனிலிருந்து எருசலேமுக்கு மாற்றி பின்னர் உடன்படிக்கைப் பெட்டியையும் கொண்டுவருகிறார் (5-6 அதிகாரங்கள்). எருசலேமில் ஒரு ஆலயத்தைக் கட்டுவதற்கான டேவிட் திட்டம் தேவனால் தடை செய்யப்படுகிறது, பின்னர் தாவீதுக்கு பின்வரும் விஷயங்களை தேவன் உறுதியளிக்கிறார்: 1) தாவீதுக்குப் பிறகு அவனது சின்காசனன்த்தில் அமர்ந்து ஆட்சி செய்ய ஒரு குமாரன் இருப்பான்; 2) தாவீதின் குமாரன் தேவாலயத்தைக் கட்டுவான்; 3) தாவீதின் வம்சத்தால் ஆக்கிரமிக்கப்பட்ட சிங்காசனம் என்றென்றும் நிறுவப்படும்; மற்றும் 4) தாவீதின் வீட்டிலிருந்து தேவன் ஒருபோதும் இரக்கத்தை எடுக்க மாட்டார் (2 சாமுவேல் 7:4-16).</p><p>தாவீது இஸ்ரவேலைச் சுற்றியுள்ள பல எதிரி நாடுகளை வென்றெடுக்க வழிநடத்துகிறார். யோனாத்தானின் ஊனமுற்ற குமாரனான மேவிபோசேத்தை எடுத்துக்கொள்வதன் மூலம் யோனாத்தானின் குடும்பத்தினரிடம் அவர் இரக்கம் காட்டுகிறார் (8-10 வரையிலுள்ள அதிகாரங்கள்).</p><p>பின்னர் தாவீது வீழ்ச்சியடைகிறார். அவர் பத்சேபாள் என்ற அழகான பெண்ணுக்காக ஆசைப்படுகிறார், அவளுடன் விபச்சார பாவம் செய்கிறார், பின்னர் அவரது கணவனாகிய உரியாவை கொலை செய்கிறார் (அதிகாரம் 11). நாத்தான் தீர்க்கதரிசி தாவீதை தனது பாவத்தால் எதிர்கொள்ளும்போது மற்றும் கண்டித்து உணர்த்துபோது, தாவீது அதை ஒப்புக்கொள்கிறான், தேவன் பிறகு அவனுக்கு தயவுகாண்பித்து அவனை மன்னிகிறார். ஆயினும், கர்த்தர் தாவீதிடம் அவனது சொந்த வீட்டிலிருந்தே பிரச்சினைகள் எழும் என்று கூறுகிறார்.</p><p>தாவீதின் முதற்பேரானவனாகிய அம்னோன் தனது பகுதி-சகோதரியான தாமாரை கற்பழிக்கும்போது சிக்கல் ஏற்படுகிறது. பதிலடி கொடுக்கும் விதமாக, தாமாரின் சகோதரர் அப்சலோம் அம்னோனைக் கொலை செய்கிறார். அப்சலோம் தனது தந்தையின் கோபத்தை எதிர்கொள்வதை விட எருசலேமை விட்டு வெளியேறுகிறார். பின்னர், அப்சலோம் தாவீதுக்கு எதிராக ஒரு கிளர்ச்சியை நடத்துகிறார், மேலும் தாவீதின் முன்னாள் கூட்டாளிகள் சிலர் கிளர்ச்சியில் சேருகிறார்கள் (15-16 வரையிலுள்ள அதிகாரங்கள்). தாவீது எருசலேமிலிருந்து வெளியேற்றப்படுகிறான், அப்சலோம் தன்னை ஒரு குறுகிய காலத்திற்கு ராஜாவாக அமைத்துக் கொள்கிறான். எவ்வாறாயினும், தந்தையின் ஸ்தானத்தை அபகரித்த துராக்கிரமி தூக்கி எறியப்படுகிறார், மேலும் தாவீதின் விருப்பத்திற்கு மாறாக அப்சலோம் கொல்லப்படுகிறான். மடிந்து வீழ்ந்த தன் மகனுக்கு தாவீது துக்கம் அனுஷ்டிக்கிறார்.</p><p>அமைதியின்மை பற்றிய ஒரு பொதுவான உணர்வு தாவீது ஆட்சியின் எஞ்சிய பகுதியைப் பாதிக்கிறது. இஸ்ரவேல் புருஷர்கள் யூதாவிலிருந்து பிரிந்து செல்வதாக அச்சுறுத்துகிறார்கள், இப்பொழுது தாவீது மற்றொரு எழுச்சியை அடக்க வேண்டும் (அதிகாரம் 20).</p><p>இந்த புத்தகத்தின் பிற்சேர்க்கையில் தேசத்தில் மூன்று ஆண்டுகள் பஞ்சம் (அதிகாரம் 21), தாவீதின் பாட்டு (அதிகாரம் 22), தாவீதின் துணிச்சலான போர்வீரர்களின் காரியங்கள் பற்றிய பதிவு (அதிகாரம் 23), மற்றும் தாவீதின் பாவமான மக்கள் தொகை கணக்கெடுப்பு காரியம் மற்றும் அடுத்தடுத்த வாதிகள் பற்றிய தகவல்கள் அடங்கும் (அதிகாரம் 24).</p><p><b>முன்னிழல்கள்:</b></p><p>கர்த்தராகிய இயேசு கிறிஸ்து முதன்மையாக 2 சாமுவேலின் இரண்டு பகுதிகளில் காணப்படுகிறார். முதலாவதாக, தாவீதின் உடன்படிக்கை 2 சாமுவேல் 7:16-ல் கோடிட்டுக் காட்டப்பட்டுள்ளது: \"உன் வீடும், உன் ராஜ்யமும், என்றென்றைக்கும் உனக்கு முன்பாக ஸ்திரப்பட்டிருக்கும்; உன் ராஜாசனம் என்றென்றைக்கும் நிலைபெற்றிருக்கும்\" மற்றும் லூக்கா 1:3-33-ல் இயேசுவின் பிறப்பை அறிவிக்க மரியாளிடத்தில் தோன்றிய தேவதூதனின் வார்த்தைகளில் மீண்டும் வலியுறுத்தினார்: \"அவர் பெரியவராயிருப்பார், உன்னதமானவருடைய குமாரன் என்னப்படுவார்; கர்த்தராகிய தேவன் அவருடைய பிதாவாகிய தாவீதின் சிங்காசனத்தை அவருக்குக் கொடுப்பார்.\" கிறிஸ்து தாவீதின் உடன்படிக்கையை நிறைவேற்றுகிறவராக இருக்கிறார்; தாவீதின் வரிசையில் அவர் தேவனுடைய குமாரன், அவர் என்றென்றும் ஆட்சி செய்வார்.</p><p>இரண்டாவதாக, இயேசு தமது வாழ்க்கையின் முடிவில் தாவீதின் பாடலில் காணப்படுகிறார் (2 சாமுவேல் 22:2-51). அவர் தனது பாறை, கோட்டை மற்றும் விடுவிப்பவர், தனது அடைக்கலம் மற்றும் மீட்பர் என்று பாடுகிறார். இயேசு நம்முடைய பாறை (1 கொரிந்தியர் 10:4; 1 பேதுரு 2:7-9), இஸ்ரவேலை மீட்பவர் (ரோமர் 11:25-27), நாம் கோட்டையை \"நமக்கு முன் வைக்கப்பட்ட நம்பிக்கையைப் பற்றிக்கொள்ளும்படி அடைக்கலமாய் ஓடிவந்த நமக்கு இரண்டு மாறாத விசேஷங்களினால் நிறைந்த ஆறுதலுண்டாகும்படிக்கு எவ்வளவேனும் பொய்யுரையாத தேவன் அப்படிச் செய்தார்\" (எபிரெயர் 6:18), நம்முடைய ஒரே இரட்சகர் (லூக்கா 2:11; 2 தீமோத்தேயு 1:10).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>யார் வேண்டுமானாலும் விழலாம். தேவனைப் பின்பற்ற உண்மையிலேயே விரும்பிய, தேவனால் ஆசீர்வதிக்கப்பட்ட தாவீதைப் போன்ற ஒரு மனிதர் கூட சோதனையால் பாதிக்கப்படுகிறார். பத்சேபாளுடன் தாவீது செய்த பாவம் நம் இருதயத்தையும், கண்களையும், மனதையும் பாதுகாக்க நம் அனைவருக்கும் ஒரு எச்சரிக்கையாக இருக்க வேண்டும். நம்முடைய ஆவிக்குரிய முதிர்ச்சியைப் பற்றிய பெருமை மற்றும் நம்முடைய சொந்த பலத்தில் சோதனையை சந்திக்கும் திறன் ஆகியவை வீழ்ச்சிக்கான முதல் படியாகும் (1 கொரிந்தியர் 10:12).</p><p>நாம் உண்மையிலேயே மனந்திரும்பும்போது மிகக் கொடூரமான பாவங்களைக் கூட மன்னிக்க தேவன் கிருபை அருளுவார். இருப்பினும், பாவத்தால் ஏற்படும் காயத்தை குணப்படுத்துவது எப்போதும் அதன் வடுவை அழிக்காது. பாவம் இயற்கையான விளைவுகளை ஏற்படுத்துகிறது, அவர் மன்னிக்கப்பட்ட பிறகும், தாவீது விதைத்ததை அவர் அறுவடை செய்தார். வேறொரு புருஷனின் மனைவியுடனான சட்டவிரோத சயனித்ததிலிருந்து அவரது மகன் அவரிடமிருந்து பறிக்கப்பட்டான் (2 சாமுவேல் 12: 14-24) மற்றும் தாவீது தனது பரலோகத் தகப்பனுடனான அன்பான உறவில் முறிந்த துன்பத்தை அனுபவித்தார் (சங்கீதம் 32 மற்றும் 51). பின்னர் மன்னிப்பைத் தேடுவதை விட, முதன் முதலில் அந்த பாவத்தை செய்யாமல் தவிர்ப்பது எவ்வளவு நல்லதாக இருக்கிறது!</p><p>சுமார் கி.மு.1031(1080) - சவுலின் பிறப்பு</p><p>சுமார் கி.மு.1001 (050) - சவுல் அரசராதல்</p><p>சுமார் கி.மு. 991 (1040) - தாவீது பிறத்தல்</p><p>சுமார் கி.மு.976 (1025) - தாவீது அபிஷேகம் பண்ணப்படல்</p><p>சுமார் கி.மு. 962 (1010) - சவுலின் மரணம்</p><p>சுமார் கி.மு.962 (1010) - தாவீது எபிரோனில் யூத அரசராதல்</p><p>சுமார் கி.மு.954 1003) - தாவீது முழு இஸ்ரவேலின் அரசராதல்</p><p>சுமார் கி.மு.921 (970) - தாவீதின் மரணம்</p><p>சுமார் கி.மு. 921 (970) - சாலொமோன் அரசராதவ்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - சாமுவேல் (தேவனிடம் கேட்டுப் பெற்ற/ தேவனின் நாமம்)</p><p>இடம் - ராமா (1சாமு 1: 17:17) இது வட எருசலேமின் எப்பிராயீம் மலைப் பகுதியில் இருக்கிறது.</p><p>குடும்பம் - தந்தை - எல்க்கானா /தாய் - அன்னாள்</p><p>உறவினர் - மூன்று சகோதரர்கள், 2 சகோதரிகள் (2 : 21), தந்தையின் பிற பிள்ளைகள்</p><p>பிள்ளைகள் - யோவேல், அபியா (8 : 2)</p><p>ஆன்மீக வழிகாட்டி - ஏலி நியாயாதிபதி</p><p>தொழில் - நியாயம் விசாரித்தல், தீர்க்கதரிசனம் உரைத்தல்</p><p>ஆர்வம் - நசரேயராக நடந்து கொள்வது (1: 11)</p><p>பட்டப்பெயர் - நடமாடும் நீதிமன்றம்</p><p>சாதனை - இறுதி நியாயாதிபதியாக பணியாற்றியது இஸ்ரவேலின் (1சாமு 7:15-7) இரு பெரிய அரசர்களை அபிஷேகம் பண்ணியது.</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 10-ஆம் நூல்</p><p>அதிகாரங்கள் - 24</p><p>வசனங்கள் - 695</p><p>கேள்விகள் - 125</p><p>வரலாற்றுத் தொடர்பு வசனங்கள் - 679</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 7</p><p>தேவனின் சிறப்புச் செய்திகள் -11</p><p>கட்டளைகள் - 70</p><p>வாக்குத்தத்தங்கள் - 13</p><p>எச்சரிக்கைகள் - 25</p>'),
 (110,'<p><b>1 ராஜாக்களின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>1 ராஜாக்களின் புத்தகம் குறிப்பாக அதன் எழுத்தாளரின் பெயரை யார் என்று குறிப்பாக குறிப்பிடவில்லை. மரபு வழியாக தொன்றுதொட்டு நம்பி வருவது என்னவென்றால், இது எரேமியா தீர்க்கதரிசியினால் எழுதப்பட்டது என்பதாகும்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>1 ராஜாக்களின் புத்தகம் கி.மு. 560 முதல் கி.மு. 540 வரையிலுள்ள காலக்கட்டத்தின் இடையில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>இந்த புத்தகம் 1 மற்றும் 2 சாமுவேல் புத்தகங்களின் தொடர்ச்சியாகும், மேலும் தாவீதின் மரணத்திற்குப் பிறகு சாலமோன் ராஜ்யபாரத்திற்கு வந்ததன் மூலம் தொடங்குகிறது. கதை ஒரு இஸ்ரவேலின் ஐக்கிய ராஜ்யத்துடன் தொடங்குகிறது, ஆனால் யூதா மற்றும் இஸ்ரவேல் என்று அழைக்கப்படும் 2 ராஜ்யங்களாகப் பிரிக்கப்பட்ட நிலையில் முடிகிறது. 1 மற்றும் 2 ராஜாக்கள் புத்தகங்கள் எபிரேய மொழி வேதாகமத்தில் ஒரு புத்தகமாக இணைக்கப்பட்டுள்ளன.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>1 ராஜாக்கள் 1:39, \"உன் குமாரனாகிய சாலொமோன் எனக்குப்பின் அரசாண்டு, அவனே என் ஸ்தானத்தில் என் சிங்காசனத்தின்மேல் வீற்றிருப்பான் என்று நான் உனக்கு இஸ்ரவேலின் தேவனாகிய கர்த்தர்மேல் ஆணையிட்டபடியே, இன்றைக்குச் செய்து தீர்ப்பேன்.\"</p><p>1 ராஜாக்கள் 9:3, \"கர்த்தர் அவனை நோக்கி: நீ என் சமுகத்தில் செய்த உன் விண்ணப்பத்தையும் உன் வேண்டுதலையும் கேட்டேன்; நீ கட்டின இந்த ஆலயத்தில் என் நாமம் என்றைக்கும் விளங்கத்தக்கதாக, அதைப் பரிசுத்தமாக்கினேன்; என் கண்களும் என் இருதயமும் எந்நாளும் அங்கேயிருக்கும்.\"</p><p>1 ராஜாக்கள் 12:16, \"ராஜா தங்களுக்குச் செவிகொடாததை இஸ்ரவேலர் எல்லாரும் கண்டபோது, ஜனங்கள் ராஜாவுக்கு மறுஉத்தரவாக: தாவீதோடே எங்களுக்குப் பங்கேது? ஈசாயின் குமாரனிடத்தில் எங்களுக்குச் சுதந்தரம் இல்லை; இஸ்ரவேலே, உன் கூடாரங்களுக்குப் போய்விடு; இப்போது தாவீதே, உன் சொந்த வீட்டைப் பார்த்துக்கொள் என்று சொல்லி, இஸ்ரவேலர் தங்கள் கூடாரங்களுக்குப் போய்விட்டார்கள்.\"</p><p>1 ராஜாக்கள் 12:28, \"ஆகையால் ராஜாவானவன் யோசனைபண்ணி, பொன்னினால் இரண்டு கன்றுக்குட்டிகளை உண்டாக்கி, ஜனங்களைப் பார்த்து: நீங்கள் எருசலேமுக்குப் போகிறது உங்களுக்கு வருத்தம்; இஸ்ரவேலரே, இதோ, இவைகள் உங்களை எகிப்துதேசத்திலிருந்து வரப்பண்ணின உங்கள் தேவர்கள் என்று சொன்னான்.\"</p><p>1 ராஜாக்கள் 17:1, \"கீலேயாத்தின் குடிகளிலே திஸ்பியனாகிய எலியா ஆகாபை நோக்கி: என் வாக்கின்படியே அன்றி இந்த வருஷங்களிலே பனியும் மழையும் பெய்யாதிருக்கும் என்று இஸ்ரவேலின் தேவனாகிய கர்த்தருக்கு முன்பாக நிற்கிற நான் அவருடைய ஜீவனைக்கொண்டு சொல்லுகிறேன் என்றான்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>1 ராஜாக்களின் புத்தகம் சாலமோனிலிருந்து தொடங்கி எலியாவுடன் முடிவடைகிறது. இரண்டிற்கும் இடையிலான வேறுபாடு என்னவென்பதைப் பற்றிய ஒரு கருத்தை இந்த இடப்பட்ட காலம் உங்களுக்குத் தருகிறது. தாவீதுக்கும் பத்சேபாளுக்கும் இடையில் ஒரு அரண்மனை ஊழலுக்குப் பிறகு சாலமோன் பிறந்தார். அவரது தந்தையைப் போலவே, சாலமோனுக்கும் பெண்களுக்குமாக உள்ள ஒரு பலவீனம் இருந்தது, அது அவரை வீழ்த்தும்படி செய்தது. சாலமோன் முதலில் எல்லாவற்றையும் மிக நன்றாகச் செய்தார், ஞானத்திற்காக தேவனிடத்தில் ஜெபித்து, ஏறக்குறைய ஏழு வருடங்கள் எடுத்து தேவனுக்கு ஒரு ஆலயத்தைக் கட்டினார். ஆனால் பின்னர் அவர் தனக்காக ஒரு அரண்மனையை கட்ட 13 ஆண்டுகள் எடுத்துக்கொண்டார். அவர் பல மனைவிகளைக் குவித்ததால், அது அவர்களுடைய சிலைகளை வணங்க அவரை வழிநடத்தியது, அவரை தேவனிடமிருந்து விலக்கியது. சாலமோனின் மரணத்திற்குப் பிறகு, இஸ்ரவேல் தொடர்ச்சியான ராஜாக்களால் ஆளப்பட்டது, அவர்களில் பெரும்பாலோனோர் தீயவர்களும் விக்கிரகாராதனையுமானவர்களாக இருந்தார்கள். இது, தேசத்தை தேவனிடமிருந்து விலக்கிக் கொண்டு சென்றது, எலியாவின் பிரசங்கத்தால் கூட அவர்களை மீண்டும் கொண்டு வர முடியவில்லை. இஸ்ரவேலில் பாகாலின் வழிபாட்டை புதிய உயரத்திற்குக் கொண்டுவந்த ஆகாபும் அவருடைய ராணியான யேசபேலும் மிகவும் தீய ராஜாக்களில் அடங்குவர். எலியா இஸ்ரவேலரை யெகோவாவின் வழிபாட்டிற்கு திருப்ப முயன்றார், பாகாலின் விக்கிரகாராதனை ஆசாரியர்களை கர்மேல் மலையில் தேவனுடன் மோதிக் கொள்ள சவால் விட்டார். இறுதியில் தேவனே வென்றார். இது யேசபேல் மகாராணியை கோபப்படுத்தியது. எலியாவின் மரணத்திற்கு அவள் கட்டளையிட்டாள், அதனால் அவன் ஓடிப்போய் வனாந்தரத்தில் ஒளிந்து கொண்டான். மனச்சோர்வடைந்து சோர்ந்துபோன அவர் இப்படியாக கூறினார்: \"தான் சாகவேண்டும் என்று கோரி: போதும் கர்த்தாவே, என் ஆத்துமாவை எடுத்துக்கொள்ளும்; நான் என் பிதாக்களைப்பார்க்கிலும் நல்லவன் அல்ல என்று சொன்னான்.\" ஆனால் தேவன் தீர்க்கதரிசியிடம் உணவையும் ஊக்கத்தையும் அனுப்பி, \"அமைதியான மெல்லிய சத்தத்தில்\" அவரிடம் பேசினார், மேலும் இந்த செயல்பாட்டில் அவரது உயிரை பாதுகாத்து மேலும் தமது வேலைக்காக பயன்படுத்தினார்.</p><p><b>முன்னிழல்கள்:</b></p><p>எருசலேமிலுள்ள ஆலயத்தில், மகா பரிசுத்த ஸ்தலத்தில் தேவனுடைய ஆவியானவர் வசிப்பது, நாம் கிறிஸ்துவை விசுவாசித்து நம்முடைய சொந்த இரட்சராக ஏற்றுக்கொண்ட நம்முடைய இரட்சிப்பின் தருணத்திலிருந்து பரிசுத்த ஆவியானவர் நமக்குள் வசிக்கிறார் என்பதை முன்னறிவிக்கிறது. விக்கிரகாராதனையை இஸ்ரவேலர் கைவிட்டதைப் போலவே, தேவனிடமிருந்து நம்மைப் பிரிக்கும் எதையும் நாம் தள்ளி ஒதுக்கி வைக்கவேண்டும். நாம் அவருடைய ஜனங்கள், ஜீவனுள்ள தேவனுடைய ஆலயம். 2 கொரிந்தியர் 6:16 நமக்கு சொல்கிறது, \"தேவனுடைய ஆலயத்துக்கும் விக்கிரகங்களுக்கும் சம்பந்தமேது? நான் அவர்களுக்குள்ளே வாசம்பண்ணி, அவர்களுக்குள்ளே உலாவி அவர்கள் தேவனாயிருப்பேன், அவர்கள் என் ஜனங்களாயிருப்பார்கள் என்று, தேவன் சொன்னபடி, நீங்கள் ஜீவனுள்ள தேவனுடைய ஆலயமாயிருக்கிறீர்களே.\"</p><p>எலியா தீர்க்கதரிசி கிறிஸ்துவின் மற்றும் புதிய ஏற்பாட்டின் அப்போஸ்தலர்களுக்கு முன்னோடியாக இருக்கிறார். எலியா மெய்யாகவே தேவனுடைய மனிதன் என்பதை நிரூபிக்க அற்புதமான காரியங்களைச் செய்யும்படிக்கு தேவன் அவருக்கு உதவினார். அவர் சாறிபாத்தின் விதவையின் மகனை மரித்தோரிலிருந்து உயிரோடு எழுப்பினார், \"நீர் தேவனுடைய மனுஷன் என்றும், உம்முடைய வாயிலிருந்து பிறக்கும் கர்த்தரின் வார்த்தை உண்மை என்றும், இதினால் இப்போது அறிந்திருக்கிறேன்\" என்று அந்த விதபை சொன்னாள். அதேபோல், தேவனுடைய மனிதர்கள் தம்முடைய வல்லமையின் மூலம் அவருடைய வார்த்தைகளைப் பேசியவர்கள் என்பது புதிய ஏற்பாட்டில் தெளிவாகத் தெரிகிறது. இயேசு லாசருவை மரித்தோரிலிருந்து உயிர்த்தெழுப்பியது மட்டுமல்லாமல், நாயீன் ஊர் விதவையின் மகனையும் (லூக்கா 7:14-15), யவீருவின் மகளையும் (லூக்கா 8:52-56) உயிரோடு எழுப்பினார். அப்போஸ்தலனாகிய பேதுரு தொற்காளை உயிரோடு எழுப்பினார் (அப்போஸ்தலர் 9:40), பவுல் ஐத்திகுவை உயிரோடு எழுப்பினார் (அப்போஸ்தலர் 20:9-12).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>1 ராஜாக்களின் புத்தகம் விசுவாசிகளுக்கு பல போதனைகளைக் கொண்டுள்ளது. நாம் வைத்திருக்கும் நிறுவனத்தைப் பற்றியும், குறிப்பாக நெருங்கிய தொடர்புகள் மற்றும் திருமணத்தைப் பற்றியும் ஒரு எச்சரிக்கையை நாம் காண்கிறோம். சாலமோனைப் போலவே, அந்நிய ஜாதி பெண்களை மணந்த இஸ்ரவேலின் ராஜாக்கள் தங்களையும் அவர்கள் தீமைக்கு ஆளானதோடு இல்லாமல் ஜனங்களையும் அம்பலப்படுத்தினர். கிறிஸ்துவ விசுவாசிகள் என்கிற வகையில், நண்பர்கள், வணிக கூட்டாளிகள், வாழ்க்கைத் துணைவர்கள் என நாம் யாரைத் தேர்ந்தெடுப்பது என்பதில் நாம் மிகவும் கவனமாக இருக்க வேண்டும். \"மோசம்போகாதிருங்கள்; ஆகாத சம்பாஷணைகள் நல்லொழுக்கங்களைக் கெடுக்கும்\" (1 கொரிந்தியர் 15:33).</p><p>வனாந்தரத்தில் எலியாவின் அனுபவம் ஒரு மதிப்புமிக்க பாடத்தை கற்பிக்கிறது. கர்மேல் மலையில் பாகாலின் 450 தீர்க்கதரிசிகள் மீது அவர் பெற்ற நம்பமுடியாத வெற்றிக்கு பின்னர், யேசபேலைப் பின்தொடர்ந்து உயிரோடு தப்பி ஓடியபோது அவரது மகிழ்ச்சி துக்கமாக மாறியது. இத்தகைய \"மலை உச்சியின்\" அனுபவங்கள் பெரும்பாலும் ஒரு மந்தநிலை மற்றும் மனச்சோர்வு மற்றும் ஊக்கம் ஆகியவற்றைத் தொடர்ந்து கொண்டுவரும். கிறிஸ்தவ வாழ்க்கையில் இந்த வகை அனுபவங்களுக்கு நாம் எச்சரிக்கையாக இருக்க வேண்டும். ஆனால் நம்முடைய தேவன் உண்மையுள்ளவர், அவர் ஒருபோதும் நம்மை விட்டு விலகுவதில்லை, மற்றும் ஒருபோதும் கைவிடமாட்டார். எலியாவை ஊக்குவித்த அமைதியான, மெல்லிய சத்தம் நம்மையும் ஊக்குவிக்கும்.</p><p>சுமார் கி.மு. 941 (990) - சாலொமோனின் பிறப்பு</p><p>சுமார் கி.மு. 921 (970) - தாவீதின் மரணம். சாலொமோனின் பதவி ஏற்பு</p><p>சுமார் கி.மு. 917 (966) - சாலொமோன் தேவாலயப் பணி தொடங்குதல்</p><p>சுமார் கி.மு. 910 (959) - தேவாலயப் பணி நிறைவடைவு</p><p>சுமார் கி.மு.880 (931) - நாடு பிளவுறுதல்</p><p>சுமார் கி.மு. 814 (865) - எலியாவின் தீர்க்கதரிசனப் பணி தொடக்கம்</p><p>சுமார் கி.மு.819 (870) - யோசபாத் யூதாவின் அரசராதல்</p><p>சுமார் கி.மு.802 (853) - அகசியா இஸ்ரவேலின் அரசராதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - எரேமியா (கர்த்தரை உயர்த்துங்கள் / கர்த்தர் துரத்துவார்)</p><p>தந்தை பெயர் - இல்க்கியா ஆசாரியர்</p><p>ஊர் - ஆனதோத், பென்யமீன் எல்லையிலிருந்த லேவியரின் பட்டணம்</p><p>தொழில் - தீர்க்கதரிசி</p><p>படைப்புகள் - பல நூற்களின் ஆசிரியர். இராஜாக்கள் நூற்கள், எரேமியா, புலம்பல்</p><p>சிறப்புப் பெயர்கள் - புலம்பலின் தீர்க்கதரிசி, தனிமையின் தீர்க்கதரிசி, ஓர் உடைந்த உள்ளம், கடின வார்த்தை கூறிய மென்மையான இதயத் துக்குரியவர், அழுது அழுது அழிவைக் கூறியவர்</p><p>சாதனை - பலமுறை சிறையிருப்பிலும், விமர்சனங்க ளிலும், மிரட்டல்களில் அகப்பட்ட போதும் சத்தியத்துக்காக துணிந்து நின்றவர்.</p><p>தீர்க்கதரிசன - பல தீர்க்கதரிசன நிறைவேறுதல்களை</p><p>கண்ணாரக் கண்டவர்.</p><p>ஆண்டுகள் - சுமார் 52 (சுமார் 626 - 574)</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 11-வது நூல்</p><p>அதிகாரங்கள் - 22</p><p>வசனங்கள் - 816</p><p>கேள்விகள் - 66</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 71</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசளம் - 1</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 36</p><p>கட்டளைகள் - 92</p><p>எச்சரிக்கைகள் - 73</p><p>வாக்குத்தத்தங்கள் - 6</p>'),
 (120,'<p><b>2 ராஜாக்களின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>2 ராஜாக்கள் புத்தகம் அதன் எழுத்தாளரின் பெயரைக் குறிப்பிடவில்லை. மரபு வழியாக தொன்றுதொட்டு நம்பப்பட்டு வருவது என்னவென்றால், எரேமியா தீர்க்கதரிசி தான் 1 மற்றும் 2 ராஜாக்கள் புத்தகங்ளை எழுதியவர் என்பதாகும்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>2 ராஜாக்களின் புத்தகம், 1 ராஜாக்களுடன், கி.மு. 560 முதல் கி.மு. 540 வரையிலான காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>2 ராஜாக்களின் புத்தகம் 1 ராஜாக்களின் புத்தகத்தின் தொடர்ச்சியாகும். பிளவுபட்ட ராஜ்யங்கள் (இஸ்ரவேல் மற்றும் யூதா) பற்றிய ராஜாக்களின் கதையை இது தொடர்கிறது. 2 ராஜாக்களின் புத்தகம் முறையே இஸ்ரவேல் மற்றும் யூதா ஜனங்களை அசீரியா மற்றும் பாபிலோனுக்கு சிறைபடுத்தி நாடுகடத்தப்படுவதோடு முடிவடைகிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>2 ராஜாக்கள் 17:7-8: \"எகிப்தின் ராஜாவாகிய பார்வோனுடைய கையின்கீழிருந்த தங்களை எகிப்து தேசத்திலிருந்து வரப்பண்ணின தங்கள் தேவனாகிய கர்த்தருக்கு விரோதமாக இஸ்ரவேல் புத்திரர் பாவஞ்செய்து, அந்நிய தேவர்களுக்குப் பயந்து நடந்து, கர்த்தர் இஸ்ரவேல் புத்திரருக்கு முன்பாகத் துரத்தின ஜாதிகளின் வழிபாடுகளிலும் இஸ்ரவேல் ராஜாக்களின் வழிபாடுகளிலும் நடந்துகொண்டிருந்தார்கள்.\"</p><p>2 ராஜாக்கள் 22: 1-2: \"யோசியா ராஜாவாகிறபோது, எட்டு வயதாயிருந்து, முப்பத்தொரு வருஷம் எருசலேமில் அரசாண்டான்; போஸ்காத் ஊரானாகிய அதாயாவின் குமாரத்தியான அவன் தாயின் பேர் எதிதாள். அவன் கர்த்தரின் பார்வைக்குச் செம்மையானதைச் செய்து, தன் தகப்பனாகிய தாவீதின் வழியிலெல்லாம் வலது இடதுபுறம் விலகாமல் நடந்தான்.\"</p><p>2 ராஜாக்கள் 24:2: \"அப்பொழுது கர்த்தர் கல்தேயரின் தண்டுகளையும், சீரியரின் தண்டுகளையும், மோவாபியரின் தண்டுகளையும், அம்மோன் புத்திரரின் தண்டுகளையும், அவன் மேல் வரவிட்டார்; தீர்க்கதரிசிகளாகிய தம்முடைய ஊழியக்காரரைக்கொண்டு கர்த்தர் சொன்ன வார்த்தையின்படியே அவர் அவைகளை யூதாவை அழிக்கும்படிக்கு வரவிட்டார்.\"</p><p>2 ராஜாக்கள் 8:19: \"கர்த்தர்: உன் குமாரருக்குள்ளே எந்நாளும் ஒரு விளக்கை உனக்குக் கட்டளையிடுவேன் என்று தம்முடைய தாசனாகிய தாவீதுக்குச் சொன்னதின்படியே, அவனிமித்தம் அவர் யூதாவை முற்றிலும் கெடுக்கவில்லை.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>பிளவுபட்ட ராஜ்யத்தின் வீழ்ச்சியை இரண்டாம் ராஜாக்கள் புத்தகம் சித்தரிக்கின்றன. தேவனுடைய தீர்ப்பு நெருங்கிவிட்டது, ஆனால் அவர்கள் மனந்திரும்ப மாட்டார்கள் என்று தீர்க்கதரிசிகள் தொடர்ந்து மக்களுக்கு எச்சரிக்கை விடுத்தார்கள். இஸ்ரவேல் ராஜ்யம் பலமுறை பொல்லாத துன்மார்க்கமான ராஜாக்களால் ஆளப்பட்டது, யூதாவின் ராஜாக்களில் சிலர் நல்லவர்களாக இருந்தாலும், அவர்களில் பெரும்பாலோனோர் ஜனங்களை யெகோவாவின் வழிபாட்டிலிருந்து விலக்குகிறவர்களாக இருந்தார்கள். சில நல்ல ராஜாக்கள், எலிசா மற்றும் பிற தீர்க்கதரிசிகளுடன் சேர்ந்து, நாட்டின் வீழ்ச்சியைத் தடுக்க முடியாமல் போனது. இஸ்ரவேலின் வடக்கு ராஜ்யம் இறுதியில் அசீரியர்களால் சிறையாக்கப்பட்டு சிதறிடிக்கப்பட்டது, சுமார் 136 ஆண்டுகளுக்குப் பிறகு தெற்கு ராஜ்யமாகிய யூதா பாபிலோனியர்களால் சிறையாக்கப்பட்டு அடிமைத்தனத்திற்குள்ளாகப் போனது.</p><p>2 ராஜாக்கள் புத்தகத்தில் மூன்று முக்கிய கருப்பொருள்கள் உள்ளன. முதலாவதாக, கர்த்தர் தம்முடைய ஜனங்கள் கீழ்ப்படியாதபோது அவர்களை நியாயந்தீர்த்தார். இஸ்ரவேலரின் துரோகம் ராஜாக்களின் தீய விக்கிரகாராதனையில் பிரதிபலித்தது, இதன் விளைவாக தேவன் அவர்களுடைய கலகத்திற்கு எதிராக அவருடைய நீதியான கோபத்தை வெளிப்படுத்தினார். இரண்டாவதாக, தேவனுடைய உண்மையான தீர்க்கதரிசிகளின் வார்த்தை எப்போதும் நிறைவேறும். கர்த்தர் எப்பொழுதும் அவருடைய வார்த்தையைக் காக்கிறவர், ஆகவே அவருடைய தீர்க்கதரிசிகளின் வார்த்தைகளும் எப்போதும் உண்மைதான். மூன்றாவதாக, கர்த்தர் உண்மையுள்ளவர். அவர் தாவீதுக்கு அளித்த வாக்குறுதியை நினைவு கூர்ந்தார் (2 சாமுவேல் 7:10-13), ஜனங்களின் கீழ்ப்படியாமையும் அவர்களை ஆட்சி செய்த தீய ராஜாக்கள் இருந்தபோதிலும், கர்த்தர் தாவீதின் குடும்பத்தை முடிவுக்குக் கொண்டுவரவில்லை.</p><p><b>முன்னிழல்கள்:</b></p><p>ஏழைகள், பலவீனமானவர்கள், ஒடுக்கப்பட்டவர்கள், வரி வசூலிப்பவர்கள், சமாரியர்கள், மற்றும் புறஜாதியார் போன்றோர்கள் தேவனுடைய கிருபைக்கு தகுதியற்றவர்கள் என்று கருதப்பட்ட யூதர்களிடம், தேவனுடைய இரக்கத்தின் மகத்தான உண்மையை விளக்குவதற்கு 1 ராஜாக்கள் மற்றும் 2 ராஜாக்களில் உள்ள நாகமான், சாறிபாத்தின் விதவையின் கதைகளை இயேசு பயன்படுத்துகிறார் -. ஒரு ஏழை விதவை மற்றும் தொழுநோயாளியின் உதாரணங்களை மேற்கோள் காட்டுவதன் மூலம், தெய்வீக இறையாண்மையின் கிருபையின் மிகப் பெரிய தேவை உள்ளவர்களுக்கு குணமாகவும் ஊழியமாகவும் குணப்படுத்தும் சிறந்த மருத்துவராக இயேசு தன்னைக் காட்டினார். இதே உண்மைதான் கிறிஸ்துவின் உடலின் மர்மத்தின் அடிப்படையாக இருந்தது, அவருடைய திருச்சபை, சமூகத்தின் அனைத்து மட்டங்களிலிருந்தும், ஆண், பெண், பணக்காரர், ஏழை, யூதர் மற்றும் புறஜாதியார் (எபேசியர் 3:1-6).</p><p>எலிசாவின் பல அற்புதங்கள் இயேசுவின் அற்புதங்களை முன்னறிவித்தன. எலிசா சூனேமியாள் பெண்ணின் மகனை உயிரோடு எழுப்பினார் (2 ராஜாக்கள் 4:34-35), தொழுநோயால் அவதிப்பட்ட நாகமானைக் குணப்படுத்தினார் (2 ராஜாக்கள் 5:1-19), மற்றும் நூறு பேருக்கு உணவளிக்க ரொட்டிகளைப் பெருக்கினார் (2 ராஜாக்கள் 4:42-44).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>தேவன் பாவத்தை வெறுக்கிறார், அதை காலவரையின்றி தொடர அவர் அனுமதிக்க மாட்டார். நாம் அவருக்கு சொந்தமானவர்களாக இருந்தால், நாம் அவருக்குக் கீழ்ப்படியாதபோது அவருடைய ஒழுக்கத்தை எதிர்பார்க்கலாம். ஒரு அன்பான தகப்பன் தனது பிள்ளைகளை அவர்களின் நன்மைக்காகவும், அவர்கள் உண்மையில் அவருக்கே உரியவர் என்பதை நிரூபிக்கவும் திருத்துகிறார். தேவன் சில சமயங்களில் அவிசுவாசிகளைப் பயன்படுத்தி தம் மக்களுக்கு திருத்தம் கொண்டு வரக்கூடும், மேலும் தீர்ப்பை வழங்குவதற்கு முன்பு அவர் நமக்கு எச்சரிக்கை செய்கிறார். கிறிஸ்தவர்களாகிய, அவருடைய பாதையிலிருந்து நாம் தவறான வழியில் செல்லும்போது நமக்கு வழிகாட்டவும் எச்சரிக்கவும் அவருடைய வார்த்தை இருக்கிறது. பழைய தீர்க்கதரிசிகளைப் போலவே, அவருடைய வார்த்தையும் நம்பகமானது, எப்போதும் உண்மையை பேசுகிறது. தேவனுடைய ஜனங்களிடம் உண்மையுள்ளவர் ஒருபோதும் தோல்வியடைய விடமாட்டார்.</p><p>கிறிஸ்துவின் சரீரத்தைப் பொறுத்தவரை விதவை மற்றும் தொழுநோயாளியின் கதைகள் நமக்கு எடுத்துக்காட்டுகள். ஒரு எலிசா சமுதாயத்தின் மிகக் குறைந்த மட்டங்களில் இருந்து பரிதாபப்பட்டார், கிறிஸ்துவைச் சேர்ந்த அனைவரையும் நம் தேவாலயங்களுக்குள் வரவேற்க வேண்டும். தேவன் \"பட்சபாதம் காண்பிப்பவர்\" அல்ல (அப்போஸ்தலர் 10:34), நாமும் அப்படி இருக்கக்கூடாது.</p><p>சுமார் கி.மு.880 (931) - நாடு பிளவுறுதல்</p><p>சுமார் கி.மு.814 (865) - எலியாவின் ஊழியத் தொடக்கம்</p><p>சுமார் கி.மு.802 (853) - இஸ்ரவேலின் அகசியாவின் ஆட்சி</p><p>சுமார் கி.மு. 797 (848) - எலியா பரலோகம் எடுக்கப்படல், எலிசாவின் திருப்பணி தொடக்கம்</p><p>சுமார் கி.மு. 797 (848) - யோராமின் ஆட்சி தொடக்கம்</p><p>சுமார் கி.மு. 746 (797) - எலிசாவின் திருப்பணி முடிவடைதல்</p><p>சுமார் கி.மு. 670 (721) - ஓசேயாவின் ஆட்சி முடிவு  இஸ்ரவேல் சிறை செல்லுதல்</p><p>சுமார் கி.மு.535 (586) - சிதேக்கியாவின் ஆட்சி முடிவு. யூதா சிறை செல்லுதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - எரேமியா (கர்த்தரை உயர்த்துங்கள் / கர்த்தர் துரத்துவார்)</p><p>தந்தை பெயர் - இல்க்கியா ஆசாரியர்</p><p>ஊர் - ஆனதோத், பென்யமீன் எல்லையிலிருந்த லேவியரின் பட்டணம்</p><p>தொழில் - தீர்க்கதரிசி</p><p>படைப்புகள் - பல நூற்களின் ஆசிரியர். இராஜாக்கள் நூற்கள், எரேமியா, புலம்பல்</p><p>சிறப்புப் பெயர்கள் - புலம்பலின் தீர்க்கதரிசி, தனிமையின் தீர்க்கதரிசி, ஓர் உடைந்த உள்ளம், கடின வார்த்தை கூறிய மென்மையான இதயத் துக்குரியவர், அழுது அழுது அழிவைக் கூறியவர்</p><p>சாதனை - பலமுறை சிறையிருப்பிலும், விமர்சனங்க ளிலும், மிரட்டல்களில் அகப்பட்ட போதும் சத்தியத்துக்காக துணிந்து நின்றவர்.</p><p>தீர்க்கதரிசன - பல தீர்க்கதரிசன நிறைவேறுதல்களை</p><p>கண்ணாரக் கண்டவர்.</p><p>ஆண்டுகள் - சுமார் 52 (சுமார் 626 - 574)</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 11-வது நூல்</p><p>அதிகாரங்கள் - 22</p><p>வசனங்கள் - 816</p><p>கேள்விகள் - 66</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 71</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனம் - 1</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 36</p><p>கட்டளைகள் - 92</p><p>எச்சரிக்கைகள் - 73</p><p>வாக்குத்தத்தங்கள் - 6</p>'),
 (130,'<p><b>1 நாளாகமம் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>1 நாளாகமம் புத்தகம் அதன் எழுத்தாளர் யார் என்பதைக்குறித்து ஒன்றும் குறிப்பிடவில்லை. பாரம்பரியமாக தொன்றுதொட்டு நம்பப்பட்டு வருவது என்னவென்றால், 1 மற்றும் 2 நாளாகமம் புத்தகங்கள் எஸ்றாவால் எழுதப்பட்டது என்பதாகும்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>1 நாளாகமம் புத்தகம் கி.மு. 450 முதல் கி.மு. 425 வரையிலுள்ள காலத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>1 & 2 நாளாகமம் புத்தகங்கள் பெரும்பாலும் 1 & 2 சாமுவேல் மற்றும் 1 & 2 ராஜாக்கள் புத்தகங்களைப் போன்ற தகவல்களை உள்ளடக்கியது. 1 & 2 நாளாகமப் புத்தகங்கள் அந்தக் காலத்தின் ஆசாரிய அம்சத்தைக் குறித்து அதிக கவனம் செலுத்துகிறது. 1 நாளாகமம் புத்தகம் சிறைபட்டு நாடுகடத்தப்பட்ட பின்னர் இஸ்ரவேலுக்குத் திரும்புபவர்களுக்கு தேவனை எவ்வாறு நமஸ்கரித்து சேவிப்பது என்பதைப் புரிந்துகொள்வதற்காக எழுதப்பட்டது. தெற்கு ராஜ்யமாகிய யூதாவின் வரலாறு, யூதா, பெஞ்சமின் மற்றும் லேவி கோத்திரங்களைக் மையமாகக் கொண்டது. இந்த கோத்திரங்கள் தேவனுக்கு அதிக விசுவாசமுள்ளவர்களாக இருந்தனர்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>1 நாளாகமம் 11:1-2, \"இஸ்ரவேலர் எல்லாரும் எப்ரோனிலிருக்கிற தாவீதினிடத்தில் கூடிவந்து: இதோ, நாங்கள் உம்முடைய எலும்பும் உம்முடைய மாம்சமுமானவர்கள். சவுல் இன்னும் ராஜாவாயிருக்கும்போதே, நீர் இஸ்ரவேலை நடத்திக்கொண்டுபோய் நடத்திக்கொண்டுவருவீர்; என் ஜனமாகிய இஸ்ரவேலை நீர் மேய்த்து, என் ஜனமாகிய இஸ்ரவேலின்மேல் தலைவனாயிருப்பீர் என்று உம்முடைய தேவனாகிய கர்த்தர் உமக்குச் சொல்லியும் இருக்கிறார் என்றார்கள்.\"</p><p>1 நாளாகமம் 21:13, \"அப்பொழுது தாவீது கர்த்தரை நோக்கி: கொடிய இடுக்கணில் அகப்பட்டிருக்கிறேன்; இப்போது நான் கர்த்தருடைய கையிலே விழுவேனாக; அவருடைய இரக்கங்கள் மகா பெரியது; மனுஷர் கையிலே விழாதிருப்பேனாக என்றான்.\"</p><p>1 நாளாகமம் 29:11, \"கர்த்தாவே, மாட்சிமையும் வல்லமையும் மகிமையும் ஜெயமும் மகத்துவமும் உம்முடையவைகள்; வானத்திலும் பூமியிலும் உள்ளவைகளெல்லாம் உம்முடையவைகள்; கர்த்தாவே, ராஜ்யமும் உம்முடையது; தேவரீர் எல்லாருக்கும் தலைவராய் உயர்ந்திருக்கிறீர்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>1 நாளாகமத்தின் முதல் 9 அதிகாரங்கள், பட்டியல்கள் மற்றும் வம்சவரலாறுக்கு அர்ப்பணிக்கப்பட்டுள்ளது. மேலும் 1 நாளாகமம் புத்தகம் முழுவதும் பல பட்டியல்களும் வம்சவரலாறுகளும் சிதறிக்கிடக்கின்றன. இடையில், 1 நாளாகமம் புத்தகம் தாவீது சிங்காசனத்திற்கு ஏறியதையும் அதன் பின்னர் அவர் செய்த செயல்களையும் பதிவு செய்கிறது. தாவீதின் குமாரன் சாலமோன் இஸ்ரவேலின் ராஜாவாகியதோடு புத்தகம் முடிகிறது. சுருக்கமாக கோடிட்டுக் காட்டப்பட வேண்டுமானால், 1 நாளாகமம் புத்தகம் பின்வருமாறு வரையறுக்கப்படுகிறது: அதிகாரங்கள் 1:1-9:23 - தேர்ந்தெடுக்கப்பட்ட வம்சவரலாறு; அதிகாரங்கள் 9:24-12:40 - தாவீதின் உயர்வு; அதிகாரங்கள் 13: 1-20: 30 – தாவீதின் ராஜ்யபாரம்.</p><p><b>முன்னிழல்கள்:</b></p><p>1 நாளாகமம் 16:33-ல் தாவீது தேவனுக்கு நன்றி செலுத்தும் துதியில், தேவன் \"பூமியை நியாயந்தீர்க்க\" வரும் நேரத்தை அவர் குறிப்பிடுகிறார். இது மத்தேயு 25-ஐ முன்னறிவிக்கிறது, அதில் இயேசு இந்த பூமிக்கு நியாயந்தீர்க்க வரும் நேரத்தை விவரிக்கிறார். பத்து கன்னிகைகள் மற்றும் தாலந்துகளின் உவமைகள் மூலம், கிறிஸ்துவின் இரத்தம் இல்லாமல் தங்கள் பாவங்களை மூடிமறைப்பவர்கள் \"காரிருளில்\" தள்ளப்படுவார்கள் என்று அவர் எச்சரிக்கிறார். அவர் தம் ஜனங்களை ஆயத்தமாக இருக்கும்படி ஊக்குவிக்கிறார், ஏனென்றால் அவர் வரும்போது, செம்மறி ஆடுகளை வெள்ளாடுகளிலிருந்து பிரிப்பார்.</p><p>17-ஆம் அதிகாரத்தில் தேவன் மீண்டும் வலியுறுத்துகின்ற தாவீதின் உடன்படிக்கையின் ஒரு பகுதி, தாவீதின் சந்ததியினராக இருக்கும் வருங்கால மேசியாவைக் குறிக்கிறது. 13-14 வசனங்கள் தேவனுடைய வீட்டை ஸ்தாபிக்கும் குமாரனை விவரிக்கின்றன, அதன் சிங்காசனம் என்றென்றும் நிலைநாட்டப்படும். இது இயேசு கிறிஸ்துவை மட்டுமே குறிக்க முடியும்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>1 நாளாகமம் போன்ற வம்சாவளிகள் நமக்கு வறண்டதாகத் தோன்றலாம், ஆனால் இது தேவன் தம்முடைய ஒவ்வொரு பிள்ளைகளையும் தனிப்பட்ட முறையில் அறிந்திருக்கிறார் என்பதை நினைவூட்டுகிறது, நம் தலையில் உள்ள முடிகளின் எண்ணிக்கை வரை கூட அவர் அறிந்திருக்கிறார் (மத்தேயு 10:30). நாம் யார், நாம் என்ன செய்கிறோம் என்பது தேவனுடைய மனதில் என்றென்றும் எழுதப்பட்டிருப்பதால் நாம் ஆறுதல் பெறலாம். நாம் கிறிஸ்துவைச் சேர்ந்தவர்கள் என்றால், நம்முடைய பெயர்கள் ஆட்டுக்குட்டியானவரின் ஜீவ புஸ்தகத்தில் என்றென்றும் எழுதப்பட்டுள்ளன (வெளிப்படுத்துதல் 13:8).</p><p>தேவன் தம் ஜனத்திற்கு உண்மையுள்ளவர், அவருடைய வாக்குறுதிகளைக் காக்கிறவராயிருக்கிறார். 1 நாளாகமம் புத்தகத்தில், தாவீது எல்லா இஸ்ரவேலருக்கும் ராஜாவாகியபோது தேவன் கொடுத்த வாக்குறுதியை நிறைவேற்றுவதைக் காண்கிறோம் (1 நாளாகமம் 11:1-3). அவர் நமக்கு அளித்த வாக்குறுதிகள் நிறைவேறும் என்பதில் நாம் உறுதியாக இருக்க முடியும். தன்னைப் பின்பற்றுபவர்களுக்கும், மனந்திரும்புதலுடன் கிறிஸ்துவிடம் வருபவர்களுக்கும், அவருடைய வார்த்தையைக் கடைப்பிடிப்பவர்களுக்கும் அவர் ஆசீர்வாதம் அளித்துள்ளார்.</p><p>கீழ்ப்படிதல் ஆசீர்வாதத்தைத் தருகிறது; கீழ்ப்படியாமை நியாயத்தீர்ப்பைக் கொண்டுவருகிறது. 1 நாளாகமம், அத்துடன் 1 & 2 சாமுவேல் மற்றும் 1 & 2 ராஜாக்கள் ஆகிய புத்தகங்கள் பாவம், மனந்திரும்புதல், மன்னிப்பு மற்றும் இஸ்ரவேல் தேசத்தின் மறுசீரமைப்பு ஆகியவற்றின் ஒரு காலவரிசையாகும். அதேபோல், தேவன் நம்மிடம் பொறுமையாக இருக்கிறார், உண்மையான மனந்திரும்புதலோடு நாம் அவரிடம் வரும்போது நம்முடைய பாவத்தை அவர் மன்னிப்பார் (1 யோவான் 1:9). நம்முடைய துக்கசமயத்து ஜெபத்தை அவர் கேட்கிறார், நம்முடைய பாவத்தை மன்னிப்பார், அவருடனான கூட்டுறவுக்கு அல்லது ஐக்கியத்திற்கு நம்மை மீட்டெடுக்கிறார், மகிழ்ச்சியின் பாதையில் நம்மை கொண்டுச் சென்று அமைக்கிறார் என்பதில் நாம் ஆறுதல் பெறலாம்.</p><p>சுமார் கி.மு. 1921 (2091) - ஆபிரகாமின் அழைப்பு</p><p>சுமார் கி.மு.1491 (1446) - இஸ்ரவேல் எகிப்திலிருந்து புறப்படுதல்</p><p>சுமார் கி.மு. 1451 (1406) - கானானில் வாழத் தொடங்குதல்</p><p>சுமார் கி.மு. 1001 (1050) -  முதல் அரசர் - சவுல்</p><p>சுமார் கி.மு. 976 (1025)  - தாவீது முதலில் அபிஷேகம் செய்யப்படல்</p><p>சுமார் கி.மு. 962 (1010) - தாவீது எபிரோனில் அரசராதல்</p><p>சுமார் கி.மு. 954 (1003)-  தாவீது முழு இஸ்ரவேலின் அரசராதல்</p><p>சுமார் கி.மு. 921 (970) - தாவீதின் மரணம், சாலொமோன் அரசராதல்</p><p>சுமார் கி.மு.917 (966) - முதல் தேவாலயப் பணியைத் தொடங்குதல்</p><p>சுமார் கி.மு.910 (959) - தேவாலயப் பணி நிறைவடைதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - எஸ்றா ( உதவி)</p><p>ஊர் - பாபிலோன் சிறையிருப்பு, எருசலேம்</p><p>தகப்பன் பெயர் - செராயா (7 : 1)</p><p>கோத்திரம் - லேவி கோத்திரம், ஆரோனின் வழிமரபு (7 : 5)</p><p>தொழில் - ஆசாரியர், வேதபாரகர், தலைவர்</p><p>சமகாலத்தோர் - நெகேமியா, அர்த்தசஷ்டா அரசர்</p><p>திருப்பு முனை  - சிறையிருப்பிலிருந்து எருசலேம் வருதல்</p><p>ஆர்வம் - வேதத்தை ஆராய்ந்து, கடைபிடித்து போதித்தல் ஆவியானவர் தூண்டுதலால் நூல்களைப் படைத்தல்</p><p>சாதனை - இவர் படைத்த நூற்களாக 1, 2 நாளாகமம், எஸ்றா ஆகியன கருதப்படுகின்றன. சங்கீதம் 119-ம் இவரது கைவண்ணமே எனக் கருதப்படுகிறது.  நெகேமியா நூல் படைப்புக்கும் இவரே காரணமாக இருக்கலாம் என்ற ஊகம் உண்டு.</p><p>சிறப்பு - வேதத்தைப் போதித்து. மக்களை நல்வழிப்படுத்தி வெகுகாலம் நிலைத்திருக்க ஏற்ற ஒரு வடிவமைப்பை அந்த சமூகத்துக்குக் கட்டளையிட்டார்.</p><p>பட்டம் - வேதபாரகர், சமூக வடிவமைப்பாளர்.</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 13-வது நூல்</p><p>அதிகாரங்கள் - 29</p><p>வசனங்கள் - 942</p><p>வரலாற்றுத் தொடர்பு வசனங்கள் - 927</p><p>நிறைவேறிய தீர்க்கத் தரிசனங்கள் - 81</p><p>நிறைவேற வேண்டிய தீர்க்கத் தரிசனங்கள் - 71</p><p>எச்சரிக்கைகள் - 30</p><p>கட்டளைகள் - 53</p><p>கேள்விகள் - 19</p><p>வாக்குத்தத்தங்கள் - 9</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 8</p>'),
 (140,'<p><b>2 நாளாகமம் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>1 நாளாகமம் புத்தகம் அதன் எழுத்தாளர் யார் என்பதைக்குறித்து ஒன்றும் குறிப்பிடவில்லை. பாரம்பரியமாக தொன்றுதொட்டு நம்பப்பட்டு வருவது என்னவென்றால், 1 மற்றும் 2 நாளாகமம் புத்தகங்கள் எஸ்றாவால் எழுதப்பட்டது என்பதாகும்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>1 நாளாகமம் புத்தகம் கி.மு. 450 முதல் கி.மு. 425 வரையிலுள்ள காலத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>1 & 2 நாளாகமம் புத்தகங்கள் பெரும்பாலும் 1 & 2 சாமுவேல் மற்றும் 1 & 2 ராஜாக்கள் புத்தகங்கள் போலவே தகவல்களை உள்ளடக்கியுள்ளது. 1 & 2 நாளாகமப் புத்தகங்கள் அந்தக் காலத்தின் ஆசாரிய அம்சத்தைக் குறித்து அதிக கவனம் செலுத்துகிறது. 2 நாளாகமம் புத்தகம் முக்கியமாக தேசத்தினுடைய மதப்பிரகராமான வரலாற்றைக்குரித்த ஒரு மதிப்பாய்வாகும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>2 நாளாகமம் 2:1, \"சாலொமோன் கர்த்தருடைய நாமத்திற்கு ஒரு ஆலயத்தையும், தன் ராஜரிகத்திற்கு ஒரு அரமனையையும் கட்ட நிர்ணயம்பண்ணினான்.\"</p><p>2 நாளாகமம் 29:1-3, \"எசேக்கியா இருபத்தைந்தாம் வயதில் ராஜாவாகி, இருபத்தொன்பது வருஷம் எருசலேமில் அரசாண்டான்; சகரியாவின் குமாரத்தியாகிய அவனுடைய தாயின்பேர் அபியாள். அவன் தன் தகப்பனாகிய தாவீது செய்தபடியெல்லாம் கர்த்தரின் பார்வைக்குச் செம்மையானதைச் செய்தான். அவன் தன் ராஜ்யபாரத்தின் முதலாம் வருஷம் முதலாம் மாதத்தில் கர்த்தருடைய ஆலயத்தின் கதவுகளைத் திறந்து, அவைகளைப் பழுதுபார்த்தான்.\"</p><p>2 நாளாகமம் 36:14, \"ஆசாரியரில் பிரதானமானவர்கள் யாவரும் ஜனங்களும் கூடிப் புறஜாதிகளுடைய சகல அருவருப்புகளின்படியும் மிகவும் துரோகம்பண்ணி, கர்த்தர் எருசலேமிலே பரிசுத்தம்பண்ணின அவருடைய ஆலயத்தை தீட்டுப்படுத்தினார்கள்.\"</p><p>2 நாளாகமம் 36:23, \"அவருடைய ஜனங்கள் எல்லாரிலும் எவன் உங்களுக்குள் இருக்கிறானோ அவன்போகட்டும், அவனுடைய தேவனாகிய கர்த்தர் அவனோடிருப்பாராக என்று பெர்சியாவின் ராஜாவாகிய கோரேஸ் அறிவிக்கிறார் என்று, தன் ராஜ்யம் எங்கும் எழுதியனுப்பி விளம்பரம்பண்ணினான்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>1 & 2 நாளாகமம் புத்தகங்கள்தெற்கு தேசமாகிய யூதாவின் ராஜ்யத்தைக் குறித்து குறிப்பிடுகிறது, அதாவது சாலமோனின் ராஜ்யபாரம் தொடங்கி யூதா பாபிலோனுக்கு சிறைவாசம் போவதோடு முடிகிறது. யூதாவின் வீழ்ச்சி ஏமாற்றமளிக்கிறது, ஆனாலும் ஜனங்களை தேவனிடம் திருப்புவதற்கு ஆர்வத்துடன் முயலும் ஆவிக்குரிய சீர்திருத்தவாதிகளுக்கு முக்கியத்துவம் கொடுக்கப்படுகிறது. தீய குணமுள்ள துன்மார்க்கமான ராஜாக்களைப் பற்றியோ அல்லது நல்ல ராஜாக்களின் தோல்விகளைப் பற்றியோ அதிகம் கூறப்படவில்லை; நன்மையான காரியங்கள் மட்டுமே வலியுறுத்தப்படுகிறது. 2 நாளாகமம் ஒரு ஆசாரிய முன்னோக்கை எடுத்துக்கொள்வதால், இஸ்ரவேலின் வடக்கு ராஜ்யம் அவர்களுடைய தவறான வழிபாடு மற்றும் எருசலேம் ஆலயத்தை ஒப்புக்கொள்ள மறுத்ததால் அரிதாகவே குறிப்பிடப்பட்டுள்ளது. எருசலேம் மற்றும் தேவாலயத்தின் அழிவுடன் இரண்டாம் நாளாகமம் முடிகிறது.</p><p><b>முன்னிழல்கள்:</b></p><p>பழைய ஏற்பாட்டிலுள்ள ராஜாக்கள் மற்றும் தேவாலயங்கள் பற்றிய அனைத்து குறிப்புகளையும் போலவே, அவற்றில் உண்மையான ராஜாதி ராஜாவான இயேசு கிறிஸ்துவின் பரிசுத்த ஆவியின் ஆலயத்தின் பிரதிபலிப்பைக் காண்கிறோம். இஸ்ரவேலின் ராஜாக்களில் மிகச் சிறந்தவர்கள் கூட எல்லா பாவமுள்ள மனிதர்களின் தவறுகளையும் கொண்டிருந்தார்கள், ஜனங்களை அபூரணமாக வழிநடத்தினார்கள். ஆனால் இயேசு ராஜாதி ராஜாவாக ஆயிரம் ஆண்டு ஆட்சி செய்ய பூமிக்கு வரும்போது, தாவீதின் மெய்யான வாரிசாக பூமியெங்கும் சிங்காசனத்தில் தன்னை நிலைநிறுத்துவார். அப்போதுதான் நமக்கு ஒரு சரியான மற்றும் நிலையான ராஜா இருப்பார், அவர் நீதியிலும் பரிசுத்தத்திலும் ஆட்சி செய்வார், இஸ்ரவேலின் ராஜாக்களில் மிகச் சிறந்தவர் என கனவு மட்டுமே காண முடியும்.</p><p>இதேபோல், சாலமோன் கட்டிய பெரிய ஆலயம் என்றென்றும் நிலைத்திருக்க வடிவமைக்கப்படவில்லை. 150 ஆண்டுகளுக்குப் பிறகு, உருவ வழிபாட்டிற்கு திரும்பிய வருங்கால சந்ததியினரால் சிதைவடைதல் மற்றும் பழுதடைதல் ஆகியவற்றை சரிசெய்ய வேண்டியிருந்தது (2 ராஜாக்கள் 12). ஆனால் பரிசுத்த ஆவியின் ஆலயமாக இருக்கிறவர்கள் – அதாவது கிறிஸ்துவுக்கு சொந்தமானவர்கள் – என்றென்றும் வாழ்வார்கள். இயேசுவுக்கு சொந்தமான நம் அந்த ஆலயம், கைகளால் அல்ல, தேவனுடைய சித்தத்தினால் (யோவான் 1:12-13) கட்டப்பட்டதாகும். நமக்குள் வாழும் ஆவியானவர் ஒருபோதும் நம்மை விட்டு விலக மாட்டார், ஒரு நாள் நம்மை தேவனுடைய கைகளில் பாதுகாப்பாக விடுவிப்பார் (எபேசியர் 1:13; 4:30). எந்த பூமிக்குரிய தேவாலயத்திலும் இப்படிப்பட்ட வாக்குறுதி இல்லை.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>ஒவ்வொரு தலைமுறையையும் கடந்த காலத்திலிருந்து மதிப்பிடுவதற்கும், ஒவ்வொருவரும் தங்கள் கீழ்ப்படிதலுக்காக ஏன் ஆசீர்வதிக்கப்பட்டார்கள் அல்லது அவர்களின் துன்மார்க்கத்திற்காக தண்டிக்கப்பட்டார்கள் என்பதையும் அறிய நாளாகமம் புத்தகத்தின் வாசகர்கள் அழைக்கப்படுகிறார்கள். ஆனால், இந்த தலைமுறையினரின் அவலநிலையை நம்முடைய நிலைமைகளுடன், தனித்தனியாக ஒப்பிட்டுப் பார்க்க வேண்டும். நாம் அல்லது நம் தேசம் அல்லது நமது தேவாலயம் கஷ்டங்களை அனுபவித்து வருகின்ற என்றால், நம்முடைய நம்பிக்கைகளையும், பல்வேறு ராஜாக்களின் கீழ் இஸ்ரவேலரின் அனுபவங்களுடன் அந்த நம்பிக்கைகளை நாம் எவ்வாறு செயல்படுத்துகிறோம் என்பதையும் ஒப்பிடுவது நமக்கு நன்மையானதாக அமையும். தேவன் பாவத்தை வெறுக்கிறார், அவர் அதைப் பொறுத்துக்கொள்ளவும் மாட்டார். நாளாகமம் நமக்கு எதையாவது கற்பிக்கிறது என்றால், அது நாம் மனத்தாழ்மையுடன் ஜெபித்து மனந்திரும்புகிறவர்களை மன்னிக்கவும் குணப்படுத்தவும் தேவன் விரும்புகிறார் என்பதாகும் (1 யோவான் 1:9).</p><p>தேவனிடமிருந்து நீங்கள் விரும்பிய எதையும் நீங்கள் பெற முடிந்தால், நீங்கள் என்ன கேட்பீர்கள்? அற்புதமான செல்வமா? உங்களுக்கும் உங்கள் அன்புக்குரியவர்களுக்கும் சரியான/நிலையான ஆரோக்கியமா? ஜீவன் மற்றும் மரணத்தின்மேல் அதிகாரமா? இதைப் பற்றி யோசிப்பது ஆச்சரியமாக இருக்கிறது, இல்லையா? ஆனால் இன்னும் ஆச்சரியம் என்னவென்றால், தேவன் சாலொமோனுக்கு அத்தகைய வாய்ப்பை வழங்கினார், அவர் இவற்றில் எதையும் தேர்வு செய்யவில்லை. அவர் கேட்டது, தேவன் தனக்கு ஒதுக்கிய பணியை நிறைவு செய்வதற்கும் அதைச் சிறப்பாகச் செய்வதற்கும் வேண்டிய ஞானமும் அறிவும் வேண்டுமெனக் கேட்டார். நமக்குக் கற்ப்பிப்பது என்னவென்றால், தேவன் நம் ஒவ்வொருவருக்கும் நிறைவேற்ற ஒரு கற்பனையைக் கொடுத்திருக்கிறார், தேவனிடமிருந்து நாம் பெறக்கூடிய மிகப் பெரிய ஆசீர்வாதம், நம் வாழ்விற்காக அவருடைய சித்தத்தை நிறைவேற்றும் திறன் மட்டுமேயாகும். அதற்காக, செயலிலும் மனப்பான்மையிலும் கிறிஸ்தவத் தன்மைக்கு நம்மைத் தூண்டுவதற்காக அவருடைய சித்தத்தை அறிந்துகொள்ள \"பரத்திலிருந்து வரும் ஞானம்\" (யாக்கோபு 3:17) நமக்குத் தேவையாயிருக்கிறது (யாக்கோபு 3:13).</p><p>சுமார் கி.மு.1001 (1050) - முதல் அரசர் சவுல்</p><p>சுமார் கி.மு. 962 (1010) - தாவீது எபிரோனில் அரசர்</p><p>சுமார் கி.மு. 921 (970) - சாலொமோன் அரசராதல்</p><p>சுமார் கி.மு. 917 (966) - தேவாலயப் பணி தொடக்கம்</p><p>சுமார் கி.மு. 910 (959) - தேவாலயப் பணி நிறைவு</p><p>சுமார் கி.மு. 880 (931) - நாடு பிளவுறுதல்</p><p>சுமார் கி.மு. 819 (870) - யோசபாத் அரசராதல்</p><p>சுமார் கி.மு. 546 (597) - சிதேக்கியா அரசராதல்</p><p>சுமார் கி.மு. 535 (586) - எருசலேம் அழிக்கப்படுதல்</p><p>சுமார் கி.மு. 485 (536) - கோரேசின் கட்டளை</p><p><b>எருசலேம் தேவாலயம்</b></p><p>கட்ட ஆசைப்பட்டவர் - தாவீது</p><p>கட்டியவர்  - சாலொமோன்</p><p>பணி தொடங்கிய ஆண்டு - சுமார் கி.மு. 917 (966)</p><p>பணி நிறைவடைந்த ஆண்டு - சுமார் கி.மு. 910 (959)</p><p>பணி பொருட்கள் மதிப்பு - கோடிக் கணக்கான ரூபாய்</p><p>அழிக்கப்பட்ட ஆண்டு - சுமார் கி.மு. 477 (586)</p><p>திரும்பக் கட்டப்பட்ட ஆண்டு - சுமார் கி.மு. 426-405 (536-515)</p><p>திரும்பக் கட்ட உதவியோர் - செருபாபேல், யோசுவா</p><p>மீண்டும் புதுக்கியவர் - ஏரோது</p><p>புதுக்குதல் பணி நிறைவடைந்த ஆண்டு - சுமார் கி.பி. 65</p><p>இறுதியாக அழிக்கப்பட்ட ஆண்டு - சுமார் கி. பி. 70/69</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - எஸ்றா ( உதவி)</p><p>ஊர் - பாபிலோன் சிறையிருப்பு, எருசலேம்</p><p>தகப்பன் பெயர் - செராயா (7 : 1)</p><p>கோத்திரம் - லேவி கோத்திரம், ஆரோனின் வழிமரபு (7 : 5)</p><p>தொழில் - ஆசாரியர், வேதபாரகர், தலைவர்</p><p>சமகாலத்தோர் - நெகேமியா, அர்த்தசஷ்டா அரசர்</p><p>திருப்பு முனை  - சிறையிருப்பிலிருந்து எருசலேம் வருதல்</p><p>ஆர்வம் - வேதத்தை ஆராய்ந்து, கடைபிடித்து போதித்தல் ஆவியானவர் தூண்டுதலால் நூல்களைப் படைத்தல்</p><p>சாதனை - இவர் படைத்த நூற்களாக 1, 2 நாளாகமம், எஸ்றா ஆகியன கருதப்படுகின்றன. சங்கீதம் 119-ம் இவரது கைவண்ணமே எனக் கருதப்படுகிறது.  நெகேமியா நூல் படைப்புக்கும் இவரே காரணமாக இருக்கலாம் என்ற ஊகம் உண்டு.</p><p>சிறப்பு - வேதத்தைப் போதித்து. மக்களை நல்வழிப்படுத்தி வெகுகாலம் நிலைத்திருக்க ஏற்ற ஒரு வடிவமைப்பை அந்த சமூகத்துக்குக் கட்டளையிட்டார்.</p><p>பட்டம் - வேதபாரகர், சமூக வடிவமைப்பாளர்.</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 14-வது நூல்</p><p>அதிகாரங்கள் - 36</p><p>வசனங்கள் - 822</p><p>வரலாற்றுத் தொடர்புடைய வசனங்கள் - 583</p><p>நிறைவேறிய தீர்க்க தர்சனங்கள் 31</p><p>எச்சரிக்கைகள் - 42</p><p>நிறைவேற வேண்டிய தீர்க்கத் தரிசனங்கள்  -7</p><p>கட்டளைகள் - 45</p><p>வாக்குத்தத்தங்கள் - 8</p><p>தேவனிடமிருந்து சிறப்பச்செய்திக - 21</p><p>கேள்விகள் - 47</p>'),
 (150,'<p><b>எஸ்றாவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>எஸ்ரா புத்தகம் குறிப்பாக அதன் எழுத்தாளரின் பெயரை யாரென்று குறிப்பிடவில்லை. எஸ்றா தீர்க்கதரிசி தான் எஸ்றா புத்தகத்தை எழுதினார் என்பது பாரம்பரியம். எஸ்றா 7-ஆம் அதிகாரத்தில் காட்சியில் தோன்றியவுடன், எஸ்றா புத்தகத்தின் எழுத்தாளர் மூன்றாவது நபரிடமிருந்து எழுதுவதிலிருந்து முதல் நபராக மாறுகிறார் என்பது சுவாரஸ்யமானது. இது எஸ்றா எழுத்தாளராக இருப்பதற்கான நம்பகத்தன்மையையும் வழங்குகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>எஸ்றா புத்தகம் கி.மு. 460 முதல் கி.மு. 440 வரையிலுள்ள காலத்திற்கு இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>பாபிலோனிய சிறையிருப்பிலிருந்து திரும்பிய நேரத்தில் மற்றும் அடுத்தடுத்த ஆண்டுகளில் இஸ்ரவேல் தேசத்தில் நிகழும் நிகழ்வுகளுக்கு எஸ்றாவின் புத்தகம் அர்ப்பணிக்கப்பட்டுள்ளது, இது கி.மு. 538 ஆம் ஆண்டு துவங்கி சுமார் ஒரு நூற்றாண்டு காலத்தை உள்ளடக்கியது. எஸ்றா புத்தகத்தின் முக்கியத்துவம் தேவாலயத்தின் புனரமைப்புக்கு முக்கியத்துவம் அளிக்கிறது. இந்த புத்தகத்தில் விரிவான வம்சவரலாறுகளின் பதிவுகள் உள்ளன, முக்கியமாக ஆரோனின் சந்ததியினரின் பங்களிப்பில் ஆசாரியத்துவத்திற்கான கூற்றுக்களை நிறுவுவதற்கான நோக்கத்திற்காக இப்படி குறிப்பிடப்பட்டுள்ளது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>எஸ்றா 3:11, \"கர்த்தர் நல்லவர், இஸ்ரவேலின்மேல் அவருடைய கிருபை என்றுமுள்ளது என்று அவரைப் புகழ்ந்து துதிக்கையில், மாறிமாறிப் பாடினார்கள்; கர்த்தரைத் துதிக்கையில், ஜனங்களெல்லாரும் கர்த்தருடைய ஆலயத்தின் அஸ்திபாரம் போடப்படுகிறதினிமித்தம் மகா கெம்பீரமாய் ஆரவாரித்தார்கள்.\"</p><p>எஸ்றா 7:6, \"இந்த எஸ்றா இஸ்ரவேலின் தேவனாகிய கர்த்தர் அருளிய மோசேயின் நியாயப்பிரமாணத்திலே தேறின வேதபாரகனாயிருந்தான்; அவனுடைய தேவனாகிய கர்த்தருடைய கரம் அவன்மேல் இருந்ததினால், அவன் கேட்டவைகளையெல்லாம் ராஜா அவனுக்குக் கொடுத்தான்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>புத்தகத்தை பின்வருமாறு பிரிக்கலாம்: 1-6 வரையிலுள்ள அதிகாரங்கள் – செருபாபேலின் கீழ் முதல் திரும்பி வருதல், மற்றும் இரண்டாவது ஆலயத்தைக் கட்டுதல். 7-10 வரையிலுள்ள அதிகாரங்கள் – எஸ்றாவின் ஊழியம். 6 மற்றும் 7 அதிகாரங்களுக்கு இடையில் அரை நூற்றாண்டுக்கு மேலாகிவிட்டதால், எஸ்றா எருசலேமில் தனது ஊழியத்தைத் தொடங்கிய நேரத்தில் புத்தகத்தின் முதல் பகுதியின் எழுத்துக்கள் இறந்துவிட்டன. எஸ்றா மற்றும் நெகேமியா புத்தகங்களில் முக்கியத்துவம் வாய்ந்த ஒருவர் எஸ்றா. இரண்டு புத்தகங்களும் பாவ அறிக்கை ஜெபத்துடன் (எஸ்ரா 9; நெகேமியா 9) முடிவடைகின்றன, பின்னர் ஜனம் அவர்கள் விழுந்த பாவ நடைமுறைகளிலிருந்து பிரிக்கப்பட்டனர். இந்த விவரிப்பில் (எஸ்ரா 5:1) அறிமுகப்படுத்தப்பட்ட தீர்க்கதரிசிகளாகிய ஆகாய் மற்றும் சகரியா ஆகியோரின் ஊக்கமளிக்கும் செய்திகளின் தன்மை குறித்த சில கருத்துக்கள், அவர்களின் பெயர்களைக் கொண்ட தீர்க்கதரிசன புத்தகங்களில் காணலாம்.</p><p>நெகேமியா புத்தகத்தின் ஆரம்பத்தில் விவரிக்கப்பட்டுள்ள அர்தசஷ்டா ராஜாவின் ஆணை வரை ஆலயத்தை மீண்டும் கட்டியெழுப்பும் விவரங்கள் எஸ்றாவின் புத்தகம் உள்ளடக்கியுள்ளது. எஸ்றாவின் நாட்களில் ஆகாய் பிரதான தீர்க்கதரிசியாக இருந்தார், நெகேமியாவின் நாட்களில் சகரியா பிரதான தீர்க்கதரிசியாக இருந்தார்.</p><p><b>முன்னிழல்கள்:</b></p><p>இஸ்ரவேலர்களில் மீதியானவர்களின் வேதாகம கருப்பொருளின் தொடர்ச்சியை எஸ்றா புத்தகத்தில் காண்கிறோம். பேரழிவு அல்லது நியாயத்தீர்ப்பு வரும்போதெல்லாம், தேவன் எப்போதுமே தனக்கென ஒரு சிறிய மீதியானவர்களை காப்பாற்றுகிறார் - நோவாவையும் அவருடைய குடும்பத்தினரையும் ஜலப்பிரளய அழிவிலிருந்து காப்பாற்றுகிறார்; சோதோம் மற்றும் கொமோராவைச் சேர்ந்த லோத்தின் குடும்பம்; ஆகாப் மற்றும் யேசபேலின் துன்புறுத்தல்களுக்கு மத்தியிலும் 7000 தீர்க்கதரிசிகள் இஸ்ரவேலில் பாதுகாக்கப்பட்டுள்ளனர். இஸ்ரவேலர்கள் எகிப்தில் அடிமைகளாக சிறைபட்டு இருந்தபோது, தேவன் தம்முடைய எஞ்சியவர்களை விடுவித்து வாக்குப்பண்ணப்பட்ட தேசத்திற்கு அழைத்துச் சென்றார். எஸ்ரா 2:64-67-ல் சுமார் ஐம்பதாயிரம் பேர் யூதேயா தேசத்திற்குத் திரும்புகிறார்கள், ஆனாலும், தாவீது ராஜாவின் கீழ் செழிப்பான நாட்களில் இஸ்ரவேலில் இருந்த எண்ணிக்கையுடன் தங்களை ஒப்பிட்டுப் பார்க்கும்போது, \"நாம் இந்த நாளில் ஒரு மீதமுள்ளவர்களாக இருக்கிறோம்.\" இந்த கருப்பொருள் புதிய ஏற்பாட்டில் கொண்டு செல்லப்படுகிறது, \"அப்படிப்போல இக்காலத்திலேயும் கிருபையினாலே உண்டாகும் தெரிந்துகொள்ளுதலின்படி ஒரு பங்கு மீதியாயிருக்கிறது\" (ரோமர் 11:5) என்று பவுல் கூறுகிறார். இயேசுவின் நாட்களில் பெரும்பாலான ஜனங்கள் அவரை நிராகரித்த போதிலும், தேவன் தம்முடைய குமாரனிலும், அவருடைய கிருபையின் உடன்படிக்கையிலும் ஒதுக்கி வைத்திருந்த ஒரு சில ஜனங்கள் இருந்தார்கள். கிறிஸ்துவுக்குப் பிறகு எல்லா தலைமுறைகளிலும், நித்திய ஜீவனுக்கு இட்டுச்செல்லும் குறுகிய பாதையில் விசுவாசிகளின் கால்கள் உள்ளன (மத்தேயு 7:13:14). பரிசுத்த ஆவியின் வல்லமையின் மூலம் இந்த எஞ்சியவர்கள் பாதுகாக்கப்படுகிறார்கள், அவர்களை முத்திரையிட்டவர், கடைசி நாளில் யாவரையும் பாதுகாப்பாக விடுவிப்பார்கள் (2 கொரிந்தியர் 1:22; எபேசியர் 4:30).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>எஸ்றா புத்தகம் நம்பிக்கை மற்றும் மறுசீரமைப்பின் ஒரு காலக்கதையாகும். பாவத்தினாலும், தேவனுக்கு எதிரான கிளர்ச்சியினாலும் பாதிக்கப்பட்டுள்ள கிறிஸ்தவருக்கு, மன்னிக்கும் தேவன் நம்முடையவராக இருக்கிறார், மனந்திரும்புதலிலும் முறிவிலும் அவரைத் தேடும்போது நம்மைத் திருப்பி விடாத ஒரு தேவன் அவர் (1 யோவான் 1:9). இஸ்ரவேலர்கள் எருசலேமுக்குத் திரும்புவதும், ஆலயத்தை மீண்டும் கட்டியெழுப்புவதும் ஒவ்வொரு கிறிஸ்தவரின் வாழ்க்கையிலும் பாவத்தின் சிறையிலிருந்தும் தேவனுக்கு எதிரான கிளர்ச்சியிலிருந்தும் திரும்பி வந்து அவரை அன்டிக்கொல்வது அவருக்குள் கொண்டிருக்கிற ஒரு அன்பான வரவேற்பு இல்லத்தைக் காண்கிறது. நாம் எவ்வளவு காலம் விலகி இருந்தபோதிலும், அவர் நம்மை மன்னித்து, அவருடைய குடும்பத்தில் நம்மை மீண்டும் ஏற்றுக்கொள்ளத் தயாராக இருக்கிறார். நம்முடைய வாழ்க்கையை எவ்வாறு கட்டியெழுப்புவது, நம்முடைய இருதயங்களை எவ்வாறு உயிர்ப்பிப்பது என்பதை நமக்குக் காண்பிக்க அவர் தயாராக இருக்கிறார், அதில் பரிசுத்த ஆவியின் ஆலயம் உள்ளது. எருசலேமிலுள்ள ஆலயத்தை மீண்டும் கட்டியெழுப்புவதைப் போலவே, நம்முடைய வாழ்க்கையை அவருடைய சேவைக்காக புதுப்பித்து, மறுசீரமைக்கும் பணியை தேவன் கண்காணிக்கிறார்.</p><p>ஆலயத்தை மீண்டும் கட்டியெழுப்ப தேவனுடைய விரோதிகளின் எதிர்ப்பு உண்டாயிருந்த காரியம் நம் ஆத்துமாக்களின் எதிரிக்கு பொதுவான ஒரு மாதிரியைக் காட்டுகிறது. நம்மை ஏமாற்றுவதற்கும் தேவனுடைய திட்டங்களைத் தடுக்க முயற்சிப்பதற்கும் தேவனுடைய நோக்கங்களுடன் ஒத்திசைந்தவர்களை சாத்தான் பயன்படுத்துகிறான். எஸ்றா 4:2 கிறிஸ்துவை வணங்குவதாகக் கூறுபவர்களின் ஏமாற்றுப் பேச்சை விவரிக்கிறது, ஆனால் அவர்களின் உண்மையான நோக்கம் தகர்க்கப்பட்டு அழிக்கப்பட வேண்டும் என்பதாகும், கட்டியெழுப்பக்கூடாது என்பதே அவர்களின் எண்ணம். அத்தகைய வஞ்சக ஏமாற்றுக்காரர்களுக்கு எதிராக நாம் எச்சரிக்கையாக இருக்க வேண்டும், இஸ்ரவேலர்கள் செய்ததைப் போலவே அவர்களுக்கு பதிலளிக்கவும், அவர்களின் மென்மையான வார்த்தைகளாலும், விசுவாசத்தின் தவறான மாதிரிகளால் ஏமாற மறுக்கிறவர்களாக இருக்கவேண்டும்.</p><p>சுமார் கி.மு. 670 (721) - சமாரியா அழிவு</p><p>சுமார் கி.மு. 535 (588) - எருசலேம் அழிவு</p><p>சுமார் கி.மு. 485 (536) - கோரேசின் கட்டளை</p><p>சுமார் கி.மு. 485 (536) - செருபாபேல் தலைமையில் முதல் குழு திரும்புதல்</p><p>சுமார் கி.மு. 485 (516) - தேவாலயப் பணி நிறைவு</p><p>சுமார் கி.மு.407 (458) - எஸ்றா தலைமையில் இரண்டாவது குழு திரும்புதல்</p><p>சுமார் கி.மு.394 (445) - நெகேமியா தலைமையில் மூன்றாவது குழு</p><p>திரும்புதல்</p><p>சுமார் கி.மு.394 (445) - எருசலேம் மதில் கட்டப்படுதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - எஸ்றா ( உதவி)</p><p>ஊர் - பாபிலோன் சிறையிருப்பு, எருசலேம்</p><p>தகப்பன் பெயர் - செராயா (7 : 1)</p><p>கோத்திரம் - லேவி கோத்திரம், ஆரோனின் வழிமரபு (7 : 5)</p><p>தொழில் - ஆசாரியர், வேதபாரகர், தலைவர்</p><p>சமகாலத்தோர் - நெகேமியா, அர்த்தசஷ்டா அரசர்</p><p>திருப்பு முனை  - சிறையிருப்பிலிருந்து எருசலேம் வருதல்</p><p>ஆர்வம் - வேதத்தை ஆராய்ந்து, கடைபிடித்து போதித்தல் ஆவியானவர் தூண்டுதலால் நூல்களைப் படைத்தல்</p><p>சாதனை - இவர் படைத்த நூற்களாக 1, 2 நாளாகமம், எஸ்றா ஆகியன கருதப்படுகின்றன. சங்கீதம் 119-ம் இவரது கைவண்ணமே எனக் கருதப்படுகிறது.  நெகேமியா நூல் படைப்புக்கும் இவரே காரணமாக இருக்கலாம் என்ற ஊகம் உண்டு.</p><p>சிறப்பு - வேதத்தைப் போதித்து. மக்களை நல்வழிப்படுத்தி வெகுகாலம் நிலைத்திருக்க ஏற்ற ஒரு வடிவமைப்பை அந்த சமூகத்துக்குக் கட்டளையிட்டார்.</p><p>பட்டம் - வேதபாரகர், சமூக வடிவமைப்பாளர்.</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 15-வது நூல்</p><p>அதிகாரங்கள் - 10</p><p>வசனங்கள் - 280</p><p>கேள்விகள் - 9</p><p>கட்டளைகள் - 43</p>'),
 (160,'<p><b>நெகேமியாவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>நெகேமியா புத்தகம் அதன் எழுத்தாளரை யாரென்று குறிப்பாக குறிப்பிடவில்லை, ஆனால் யூத மற்றும் கிறிஸ்தவ மரபுகள் எஸ்றாவை எழுத்தாளராக அங்கீகரிக்கின்றன. இது எஸ்றா மற்றும் நெகேமியாவின் புத்தகங்கள் முதலில் ஒரே புத்தகமாக இருந்தன என்கிற உண்மையை அடிப்படையாகக் கொண்டதாகும்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>நெகேமியா புத்தகம் கி.மு. 445 முதல் கி.மு. 420 வரையிலுள்ள காலத்திற்கு இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்ட நோக்கம்:</b></p><p>வேதாகமத்தின் வரலாற்று புத்தகங்களில் ஒன்றான நெகேமியா புத்தகம், பாபிலோனிய சிறையிருப்பிலிருந்து இஸ்ரவேலர்கள் திரும்பிய கதையையும், எருசலேமில் ஆலயத்தை மீண்டும் கட்டியெழுப்பிய கதையையும் தொடர்கிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>நெகேமியா 1:3, \"அதற்கு அவர்கள்: சிறையிருப்பில் மீந்திருக்கிறவர்கள் அந்தத் தேசத்திலே மகா தீங்கையும் நிந்தையையும் அநுபவிக்கிறார்கள்; எருசலேமின் அலங்கம் இடிபட்டதும், அதின் வாசல்கள் அக்கினியால் சுட்டெரிக்கப்பட்டதுமாய்க் கிடக்கிறது என்றார்கள்.\"</p><p>நெகேமியா 1:11, \"ஆண்டவரே, உமது அடியானின் ஜெபத்தையும், உமது நாமத்துக்குப் பயப்படவேண்டும் என்று விரும்புகிற உமது அடியாரின் ஜெபத்தையும் உமது செவிகள் கவனித்திருப்பதாக; இன்றைக்கு உமது அடியானுக்குக் காரியத்தைக் கைக்கூடி வரப்பண்ணி, இந்த மனுஷனுக்கு முன்பாக எனக்கு இரக்கம் கிடைக்கப்பண்ணியருளும் என்று பிரார்த்தித்தேன். நான் ராஜாவுக்குப் பானபாத்திரக்காரனாயிருந்தேன்.\"</p><p>நெகேமியா 6:15-16, \"அப்படியே அலங்கமானது ஐம்பத்திரண்டு நாளைக்குள்ளே கட்டப்பட்டு, எலூல் மாதம் இருபத்தைந்தாந்தேதியிலே முடிந்தது. எங்கள் பகைஞர் எல்லாரும் அதைக் கேட்டபோதும், எங்கள் சுற்றுப்புறத்தாராகிய புறஜாதியான அனைவரும் கண்டபோதும், மிகவும் முனையற்றுப்போய், இந்தக் கிரியை எங்கள் தேவனால் கைகூடி வந்ததென்று அறிந்தார்கள்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>எருசலேமில் உள்ள ஆலயம் புனரமைக்கப்படுவதாக செய்தி வந்தபோது நெகேமியா பெர்சியாவில் ஒரு எபிரேயராக இருந்தார். நகரத்தைப் பாதுகாக்க சுவர் இல்லை என்பதை அறிந்து அவர் அதைக் கட்டுவதற்கு ஆர்வத்துடன் எழுந்தார். நகரத்தை காப்பாற்ற தன்னைப் பயன்படுத்தும்படி நெகேமியா தேவனை அழைத்தார். பெர்சிய மன்னரான அர்தசஷ்டாவின் இதயத்தை மென்மையாக்குவதன் மூலம் தேவன் நெகேமியாவின் ஜெபத்திற்கு பதிலளித்தார், ராஜா தனது அனுமதியோடு மட்டுமல்லாமல், இந்த திட்டத்தில் பயன்படுத்த வேண்டிய பொருட்களையும் வழங்கினார். இறுதியில் நெகேமியா எருசலேமுக்குத் திரும்புவதற்கு ராஜா அனுமதி அளிக்கிறார், அங்கு அவர் ஆளுநராக்கப்படுகிறார்.</p><p>எதிர்ப்புகள் மற்றும் குற்றச்சாட்டுகளுக்கு மத்தியிலும் அலங்கம் கட்டப்பட்டது மற்றும் எதிரிகள் அமைதியாக்கப்பட்டனர். நெகேமியாவால் ஈர்க்கப்பட்ட ஜனங்கள், அதிக எதிர்ப்பையும் மீறி, குறிப்பிடத்தக்க 52 நாட்களில் அலங்கத்தை முடிக்க அதிக பணம், பொருட்கள் மற்றும் மனிதவளத்தின் தசமபாகம் கொடுத்தார்கள். எவ்வாறாயினும், இந்த ஒன்றுபட்ட முயற்சி குறுகிய காலமே ஆகும், ஏனென்றால் நெகேமியா சிறிது நேரம் இடைவேளை விட்டு வெளியேறும்போது எருசலேம் மீண்டும் விசுவாசதுரோகத்திற்குள் விழுகிறது. அவர் எருசலேமுக்குத் திரும்பியபோது, நெகேமியா சுவர்கள் வலுவாக இருப்பதைக் கண்டார், ஆனால் மக்கள் பலவீனமாக இருந்தனர். மக்களுக்கு ஒழுக்கத்தை கற்பிக்கும் பணியை அவர் அமைத்தார், அவர் வார்த்தைகளை குறைவாக்கவில்லை. \"அவர்களையும் நான் கடிந்துகொண்டு அவர்கள்மேல் வரும் சாபத்தைக் கூறி அவர்களில் சிலரை அடித்து, மயிரைப் பிய்த்து\" (13:25). ஜெபத்தின் மூலமாகவும், தேவனுடைய வார்த்தையைப் படித்து பின்பற்றுவதன் மூலமும் புத்துயிர் பெற மக்களை ஊக்குவிப்பதன் மூலமும் அவர் உண்மையான வழிபாட்டை மீண்டும் நிலைநிறுத்தினார்.</p><p><b>முன்னிழல்கள்:</b></p><p>நெகேமியா ஒரு ஜெபிக்கிற மனிதராக இருந்தார், அவர் தனது மக்களுக்காக உணர்ச்சிவசமாக ஜெபித்தார் (நெகேமியா 1). தேவனுடைய ஜனங்களுக்காக அவர் காட்டிய வைராக்கியமான பரிந்துரையானது, நம்முடைய பெரிய மத்தியஸ்தரான இயேசு கிறிஸ்துவை முன்னறிவிக்கிறது, அவர் யோவான் 17-ல் அவருடைய பிரதான ஆசாரிய ஜெபத்தில் தம் மக்களுக்காக ஆவலுடன் ஜெபித்தார். நெகேமியா மற்றும் இயேசு இருவரும் தேவனுடைய மக்கள் மீது எரியும் அன்பைக் கொண்டிருந்தார்கள், அவர்கள் தேவனிடம் ஜெபத்தில் தங்களையே ஊற்றினார்கள், அவர்களுக்காக சிங்காசனத்திற்கு முன்பாக பரிந்துரை செய்தனர்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நெகேமியா இஸ்ரவேலர்களை வேதத்தின் எழுத்துக்களுக்குள்ள கனம் மற்றும் அன்பிற்கு இட்டுச் சென்றார். நெகேமியா, தேவன்மீது வைத்திருந்த அன்பு மற்றும் தேவனை மதிக்கப்படுவதையும் மகிமைப்படுத்துவதையும் காண விரும்பியதன் காரணமாக, இஸ்ரவேலரை இவ்வளவு காலமாக தேவன் விரும்பிய விசுவாசத்தையும் கீழ்ப்படிதலையும் நோக்கி இட்டுச் சென்றார். அதேபோல், கிறிஸ்தவர்கள் வேதத்தின் சத்தியங்களை நேசிக்க வேண்டும், மதிக்க வேண்டும், அவற்றை நினைவாற்றலுக்கு அர்ப்பணிக்கவும், இரவும் பகலும் தியானிக்கவும், ஒவ்வொரு ஆவிக்குரிய தேவைகளையும் பூர்த்தி செய்வதற்காக அவர்களிடம் திரும்பவும் வேண்டும். 2 தீமோத்தேயு 3:16-17 நமக்கு சொல்லுகிறது \"வேதவாக்கியங்களெல்லாம் தேவஆவியினால் அருளப்பட்டிருக்கிறது; தேவனுடைய மனுஷன் தேறினவனாகவும், எந்த நற்கிரியையுஞ் செய்யத் தகுதியுள்ளவனாகவும் இருக்கும்படி, அவைகள் உபதேசத்துக்கும், கடிந்துகொள்ளுதலுக்கும் சீர்திருத்தலுக்கும், நீதியைப் படிப்பிக்குதலுக்கும் பிரயோஜனமுள்ளவைகளாயிருக்கிறது.\" இஸ்ரவேலரின் ஆவிக்குரிய மறுமலர்ச்சியை/எழுப்புதலை நாம் அனுபவிக்க எதிர்பார்க்கிறோம் என்றால் (நெகேமியா 8: 1-8), நாம் தேவனுடைய வார்த்தையிலிருந்து தொடங்க வேண்டும்.</p><p>ஆவிக்குரிய அல்லது சரீரப்பிரகாரமான துன்பங்களைக் கொண்ட மற்றவர்களிடம் நாம் ஒவ்வொருவரும் உண்மையான இரக்கத்தைக் கொண்டிருக்க வேண்டும். இரக்கத்தை உணர, இன்னும், உதவ எதுவும் செய்யாதது, வேதாகம அடிப்படையில் ஆதாரமற்றது. சில சமயங்களில் மற்றவர்களுக்கு முறையாக ஊழியம் செய்வதற்காக நம் சொந்த வசதியை நாம் விட்டுவிட வேண்டியிருக்கும். சரியான நேரத்தோடு நம் நேரத்தையும் பணத்தையும் கொடுப்பதற்கு முன்பு நாம் ஒரு காரணத்தை முழுமையாக நம்ப வேண்டும். தேவனை நம் மூலமாக ஊழியம் செய்ய நாம் அனுமதிக்கும்போது, அவிசுவாசிகள் கூட இது தேவனுடைய வேலை என்பதை அறிந்து கொள்வார்கள்.</p><p>சுமார் கி.மு. 670 (721) - சமாரியா அழிவு</p><p>சுமார் கி.மு. 535 (586) - எருசலேம் அழிவு</p><p>சுமார் கி.மு. 485 (536) - கோரேசின் கட்டளை</p><p>சுமார் கி.மு. 485 (536) - செருபாபேல் தலைமையில் முதல்குழு திரும்புதல்</p><p>சுமார் கி.மு. 465 (516) - தேவாலயப் பணி நிறைவு</p><p>சுமார் கி.மு. 407 (458) - எஸ்றா தலைமையில் இரண்டாவது குழு திரும்புதல்</p><p>சுமார் கி.மு.394 (445) - நெகேமியா தலைமையில் மூன்றாவது குழு திரும்புதல்</p><p>சுமார் கி.மு.394 (445) - எருசலேம் அலங்கம் கட்டப்படுதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - நெகேமியா {தேவ ஆறுதல்)</p><p>தந்தை பெயர் - அகலியா</p><p>ஊர் - பெர்சியா, எருசலேம்</p><p>தொழில் - பானபாத்திரக்காரர்,பின்பு கோட்டை கட்டுபவர்,ஆளுநர்</p><p>சம காலத்தோர் - எஸ்றா, அர்த்தசஷ்டா</p><p>எதிரிகள் - சன்பல்லாத், தொபியா</p><p>திருப்பு முனை - எருசலேமின் அலங்கம் இடிபட்டுக் கிடக்கும் செய்தியை சகோதரரான ஆனானி மூலம் கேள்விப்பட்டது.</p><p>ஆர்வம் - எருசலேமின் அலங்கத்தை எடுத்துக் கட்டுதல்</p><p>சாதனை - எதிர்ப்புகளின் நடுவில் 52 நாளுக்குள் எருசலேமின் அலங்கத்தை எடுத்துக் கட்டியது மக்கள் வாழ்வைச் சீர்திருத்தியது.</p><p>சிறப்பு - சுயநலமில்லாப் பணியும், துணிச்சலான பணியும் செய்து, இடிந்த எருசலேமின் வாழ்வை எடுத்து நிறுத்தியவர்</p><p>பட்டப்பெயர் - வாளும் கரண்டியும் ஏந்தியவர்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 16-வது நூல்</p><p>அதிகாரங்கள் - 13</p><p>வசனங்கள் - 406</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 3</p><p>எச்சரிக்கைகள் - 3</p><p>கட்டளைகள் - 14</p>'),
 (190,'<p><b>எஸ்தரின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>எஸ்தர் புத்தகம் குறிப்பாக அதன் எழுத்தாளரின் பெயரைக் குறிப்பிடவில்லை. மிகவும் பிரபலமான மரபு வழி பாரம்பரிய நம்பிக்கையானது, மொர்தெகாய் (எஸ்தர் புத்தகத்தில் ஒரு முக்கியமான கதாபாத்திரம்), எஸ்றா மற்றும் நெகேமியா (பெர்சிய பழக்கவழக்கங்களை நன்கு அறிந்திருப்பவர்கள்) போன்றோர்களில் ஒருவர் எழுதியிருக்க வேண்டும் என்பதாகும்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>எஸ்தர் புத்தகம் கி.மு. 460 முதல் கி.மு. 350 வரையிலுள்ள காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>எஸ்தர் புத்தகத்தின் நோக்கம் கடவுளின் உறுதிப்பாட்டைக் காண்பிப்பதாகும், குறிப்பாக அவர் தேர்ந்தெடுத்த மக்கள் இஸ்ரேலைப் பொறுத்தவரை. எஸ்தர் புத்தகம் பூரிம் விருந்து மற்றும் அதன் நிரந்தர கண்காணிப்பின் கடமையை பதிவு செய்கிறது. எஸ்தர் மூலமாக கடவுளால் கொண்டுவரப்பட்ட யூத தேசத்தின் பெரும் விடுதலையை நினைவுகூரும் விதமாக பூரிம் விருந்தில் எஸ்தர் புத்தகம் வாசிக்கப்பட்டது. பூரிம் காலத்தில் யூதர்கள் இன்றும் எஸ்தரைப் படிக்கிறார்கள்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>எஸ்தர் 2:15, \"எஸ்தர் ராஜாவினிடத்தில் பிரவேசிக்கிறதற்கு முறைவந்தபோது, அவள் ஸ்திரீகளைக் காவல்பண்ணுகிற ராஜாவின் பிரதானியாகிய யேகாய் நியமித்த காரியமேயல்லாமல் வேறொன்றும் கேட்கவில்லை; எஸ்தருக்குத் தன்னைக் காண்கிற எல்லார் கண்களிலும் தயை கிடைத்தது.\"</p><p>எஸ்தர் 4:14, \"நீ இந்தக் காலத்திலே மவுனமாயிருந்தால், யூதருக்குச் சகாயமும் இரட்சிப்பும் வேறொரு இடத்திலிருந்து எழும்பும், அப்பொழுது நீயும் உன் தகப்பன் குடும்பத்தாரும் அழிவீர்கள்; நீ இப்படிப்பட்ட காலத்துக்கு உதவியாயிருக்கும்படி உனக்கு ராஜமேன்மை கிடைத்திருக்கலாமே, யாருக்குத் தெரியும், என்று சொல்லச்சொன்னான்.\"</p><p>எஸ்தர் 6:13, \"ஆமான் தனக்கு நேரிட்ட எல்லாவற்றையும் தன் மனைவியாகிய சிரேஷுக்கும் தன் சிநேகிதர் எல்லாருக்கும் அறிவித்தபோது, அவனுடைய ஆலோசனைக்காரரும் அவன் மனைவியாகிய சிரேஷும் அவனைப் பார்த்து: மொர்தெகாய்க்கு முன்பாக நீர் தாழ்ந்துபோகத் தொடங்கினீர்; அவன் யூதகுலமானால், நீர் அவனை மேற்கொள்ளாமல் அவனுக்கு முன்பாகத் தாழ்ந்துபோவது நிச்சயம் என்றார்கள்.\"</p><p>எஸ்தர் 7:3, \"அப்பொழுது ராஜாத்தியாகிய எஸ்தர் பிரதியுத்தரமாக: ராஜாவே, உம்முடைய கண்களில் எனக்குக் கிருபை கிடைத்து, ராஜாவுக்குச் சித்தமாயிருந்தால் என் வேண்டுதலுக்கு என் ஜீவனும், என் மன்றாட்டுக்கு என் ஜனங்களும் எனக்குக் கட்டளையிடப்படுவதாக.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>எஸ்தரின் புத்தகத்தை மூன்று முக்கிய பிரிவுகளாகப் பிரிக்கலாம். 1:1-2:18 வரையிலுள்ள அதிகாரங்கள் - எஸ்தர் வஸ்திக்கு பதிலாக தேர்ந்தெடுக்கப்படுதல்; 2:19-7:10 வரையிலுள்ள அதிகாரங்கள் - மொர்தெகாய் ஆமானை வெற்றிபெறுதல்; 8:1-10:3 வரையிலுள்ள அதிகாரங்கள் - அவர்களை அழிக்க மேற்கொண்ட ஆமானின் முயற்சியில் இஸ்ரவேல் தப்பிக்கிறது. குணவதியாகிய எஸ்தர் தனது ஜனம் ஆபத்தில் இருப்பதை உணர்ந்ததால் அவள் தன் மரணத்தையும் பொருட்படுத்தாமல் ராஜாவின் முன்பாக செல்ல துணிவு கொண்டாள். ஒரு கொடிய சூழ்ச்சியாக இருக்கக்கூடியதை அவள் விருப்பத்துடன் செய்தாள், அவளுடைய கணவனின் ராஜ்யத்தில் இரண்டாவது ஸ்தானத்தில் இருந்த ஆமானை பிடிக்க வகைதேடினாள். அவள் ஒரு புத்திசாலி மற்றும் மிகவும் தகுதியான எதிரியை நிரூபித்தார், அதே நேரத்தில் அவரது கணவர்-ராஜாவிற்கு முன்பாக மனத்தாழ்மையும் மரியாதை கொண்டவளாகவும் இருந்தாள்.</p><p>ஆதியாகமம் 41:34-37-ல் உள்ள யோசேப்பின் கதையைப் போலவே, இரண்டு கதைகளும் யூதர்களின் விதியைக் கட்டுப்படுத்தும் அந்நிய ராஜாக்களை உள்ளடக்கியது ஆகும். இரு கணக்குகளும் தங்கள் ஜனங்கள் மற்றும் தேசத்தின் இரட்சிப்பின் வழிவகைகளை வழங்கும் இஸ்ரவேலர்களில் தனிநபர்களின் வீரத்தை காட்டுகின்றன. தேவனுடைய கை தெளிவாகத் தெரிகிறது, அதில் ஒரு மோசமான சூழ்நிலை தோன்றுவது உண்மையில் சர்வவல்லமையுள்ள தேவனுடைய கட்டுப்பாட்டில் உள்ளது, அவர் இறுதியில் ஜனங்களின் நன்மையை இதயத்தில் வைத்திருக்கிறார். இந்த கதையின் மையத்தில் யூதர்களுக்கும் அமலேக்கியர்களுக்கும் இடையிலான பிளவு உள்ளது, இது யாத்திராகமம் புத்தகத்தில் தொடங்கியதாக பதிவு செய்யப்பட்டுள்ளது. யூதர்களின் முழுமையாக அழித்துப்போடும்படியான பழைய ஏற்பாட்டு காலத்தில் பதிவு செய்யப்பட்ட இறுதி முயற்சிதான் ஆமான் மேற்கொண்ட முயற்சி. அவனது திட்டங்கள் இறுதியில் அவனது சொந்த மறைவு மற்றும் அவனது எதிரியாக தோன்றிய மொர்தெகாயை தனது சொந்த நிலைக்கு உயர்த்தியது, அத்துடன் யூதர்களின் இரட்சிப்பு ஆகியவற்றுடன் முடிவடைகிறது.</p><p>விருந்து என்பது இந்த புத்தகத்தின் முக்கிய கருப்பொருள், பதிவு செய்யப்பட்ட ஏறக்குறைய பத்து விருந்துகள் உள்ளன, மேலும் பல நிகழ்வுகள் இந்த விருந்துகளில் திட்டமிடப்பட்டன அல்லது அம்பலப்படுத்தப்பட்டன. இந்த புத்தகத்தில் தேவனுடைய பெயர் எந்த இடத்திலும் குறிப்பிடப்படவில்லை என்றாலும், சூசாவின் யூதர்கள் மூன்று நாட்கள் உண்ணாவிரதம் மற்றும் ஜெபம் செய்தபோது தேவனுடைய தலையீட்டை நாடினார்கள் என்பது தெளிவாகத் தெரிகிறது (எஸ்தர் 4:16). அவர்களுடைய அழிவை அனுமதிக்கும் சட்டம் மேதியர்கள் மற்றும் பெர்சியர்களின் சட்டங்களின்படி எழுதப்பட்டிருந்தாலும், அதை மாற்றமுடியாததாக மாற்றியமைத்த போதிலும், அவர்களின் ஜெபங்களுக்கு பதிலளிக்க வழி தெளிவுபடுத்தப்பட்டது. ஒரு முறை ராஜாவுக்கு முன்பாக அழைக்கப்படாமல் இரண்டு முறை எஸ்தர் தன் உயிரைப் பணயம் வைத்தாள் (எஸ்தர் 4:1-2; 8:3). ஆமானின் அழிவில் அவள் திருப்தியடையவில்லை; அவள் தன் மக்களைக் காப்பாற்றுவதில் நோக்கம் கொண்டிருந்தாள். பூரிம் விருந்தின் ஆரம்பம் அனைவருக்கும் காணும்படி எழுதப்பட்டு பாதுகாக்கப்படுகிறது, இன்றும் அனுசரிக்கப்படுகிறது. தேவனால் தேர்ந்தெடுக்கப்பட்ட மக்களுக்கு, அவருடைய பெயரை நேரடியாகக் குறிப்பிடாமல் இருந்தபோதிலும், எஸ்தரின் ஞானத்தினாலும் மனத்தாழ்மையினாலும் மரணதண்டனையிலிருந்து தேவனால் காக்கப்பட்டார்கள்.</p><p><b>முன்னிழல்கள்:</b></p><p>எஸ்தரில், தேவனுடைய நோக்கங்களுக்கு எதிராகவும், குறிப்பாக அவருடைய வாக்குறுதியளிக்கப்பட்ட மேசியாவுக்கு எதிராகவும் சாத்தானின் தொடர்ச்சியான போராட்டத்தை திரைக்குப் பின்னால் பார்க்கிறோம். மனித இனத்தில் கிறிஸ்துவின் நுழைவு யூத இனம் இருப்பதைக் கணித்துள்ளது. யூதர்களை அழிப்பதற்காக ஆமான் சதி செய்ததைப் போலவே, கிறிஸ்துவுக்கும் தேவனுடைய மக்களுக்கும் எதிராக சாத்தான் தன்னை நிலைநிறுத்திக் கொண்டான். மொர்தெகாயுக்காக அவர் கட்டிய தூக்கு மேடையில் ஆமான் தோற்கடிக்கப்பட்டதைப் போலவே, கிறிஸ்துவும் அவருடைய ஆவிக்குரிய சந்ததியை அழிக்க எதிரி வகுத்த ஆயுதத்தை பயன்படுத்துகிறார். மேசியாவை அழிக்க சாத்தான் திட்டமிட்ட சிலுவையை பொறுத்தவரை, கிறிஸ்து \"நமக்கு எதிரிடையாகவும் கட்டளைகளால் நமக்கு விரோதமாகவும் இருந்த கையெழுத்தைக் குலைத்து, அதை நடுவிலிராதபடிக்கு எடுத்து, சிலுவையின்மேல் ஆணியடித்து; துரைத்தனங்களையும் அதிகாரங்களையும் உரிந்துகொண்டு, வெளியரங்கமான கோலமாக்கி, அவைகளின்மேல் சிலுவையிலே வெற்றிசிறந்தார்\" (கொலோசெயர் 2:14-15). மொர்தெகாயுக்காக ஆமான் கட்டிய தூக்கு மரத்தில் ஆமான் தூக்கிடப்பட்டதைப் போலவே, கிறிஸ்துவை அழிக்க பிசாசு எழுப்பிய சிலுவையால் பிசாசே நசுக்கப்பட்டான்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>வாழ்க்கையில் நம் சூழ்நிலைகளில் தேவனுடைய கரத்தைப் பார்ப்பதற்கும், விஷயங்களை தற்செயலாகக் காண்பதற்கும் இடையில் நாம் செய்யும் தேர்வை எஸ்தர் புத்தகம் விளக்கி காண்பிக்கிறது. தேவன் பிரபஞ்சத்தின் இறையாண்மை கொண்ட ஆட்சியாளர், அவருடைய திட்டங்கள் வெறும் தீய மனிதர்களின் செயல்களால் நகர்த்தப்படாது என்பதில் நாம் உறுதியாக இருக்க முடியும். அவரது பெயர் புத்தகத்தில் குறிப்பிடப்படவில்லை என்றாலும், தனிநபர்கள் மற்றும் தேசம் ஆகிய இரு மக்களுக்கும் அவர் அளித்த அக்கறை முழுவதும் தெளிவாகத் தெரிகிறது. உதாரணமாக, அகாஸ்வேரு ராஜாவுக்கு சரியான நேரத்தில் தூக்கமின்மைக்கு சர்வவல்லமையுள்ள தேவனின் செயல்பாட்டையும் செல்வாக்கையும் காண நாம் தவற முடியாது. மொர்தெகாய் மற்றும் எஸ்தரின் உதாரணம் மூலம், நம்முடைய தேவன் நேரடியாக நம்முடைய ஆவிகளுடன் தொடர்புகொள்வதற்கு அடிக்கடி பயன்படுத்தும் மௌனமான அன்பு மொழி இந்த புத்தகத்தில் காட்டப்பட்டுள்ளது.</p><p>எஸ்தர் ஒரு தெய்வீக மற்றும் கற்றுக்கொள்ளக்கூடிய ஆவி இருப்பதை நிரூபித்தார், அது மிகுந்த பலத்தையும் விருப்பமான கீழ்ப்படிதலையும் காட்டியது. எஸ்தரின் மனத்தாழ்மை தன்னைச் சுற்றியுள்ளவர்களிடமிருந்து மிகவும் வித்தியாசமாக இருந்தது, இதனால் அவர் ராணியின் நிலைக்கு உயர்த்தப்பட்டார். மரியாதைக்குரிய மற்றும் தாழ்மையுடன் இருப்பது, மனிதனால் சாத்தியமில்லாத சூழ்நிலைகளில் கூட கடினமாக இருந்தாலும், பெரும்பாலும் நமக்கும் மற்றவர்களுக்கும் சொல்லப்படாத ஆசீர்வாதத்தின் பாத்திரமாக நம்மை அது அமைக்கிறது என்பதை அவர் நமக்குக் காட்டுகிறார். வாழ்க்கையின் எல்லா பகுதிகளிலும், குறிப்பாக சோதனைகளில் அவளுடைய தெய்வீக மனப்பான்மையைப் பின்பற்றுவது நல்லது. எழுதப்பட்ட எழுத்தில் ஒரு முறைகூட புகார் அல்லது மோசமான அணுகுமுறை இல்லை. தன்னைச் சுற்றியுள்ளவர்களின் \"ஆதரவை\" எஸ்தர் வென்றாள் என்று பல முறை படித்தோம். அத்தகைய தயவுதான் இறுதியில் அவளுடைய மக்களைக் காப்பாற்றியது. நியாயமற்ற துன்புறுத்தல்களைக் கூட ஏற்றுக்கொள்வதோடு, மனத்தாழ்மையும், தேவன் மீது சாய்வதற்கான உறுதியும் சேர்ந்து ஒரு நேர்மறையான அணுகுமுறையைப் பேணுவதற்கான எஸ்தரின் முன்மாதிரியைப் பின்பற்றுவதால் நமக்கும் அத்தகைய உதவி வழங்கப்படலாம். இது போன்ற ஒரு காலத்திற்கு தேவன் நம்மையும் ஒரு குறிப்பிட்ட நிலையில் வைத்திருக்கிறார் என்பது யாருக்குத் தெரியும்?</p><p>சுமார் கி.மு. 535 (586) - எருசலேம் வீழ்ச்சி</p><p>சுமார் கி.மு. 487 (538) - பெர்சியா பாபிலோனை வெல்லுதல்</p><p>சுமார் கி.மு. 485 (536) - சிறையிருப்பிலிருந்து முதல் குழு எருசலேம்</p><p>திரும்புதல்</p><p>சுமார் கி.மு. 465 (516) - இரண்டாம் தேவாலயப்பணி நிறைவு</p><p>சுமார் கி.மு. 435 (486) - அகாஸ்வேரு அரியணையேறுதல்</p><p>சுமார் கி.மு. 432 (483) - வஸ்தி அரசிப்பட்டத்திலிருந்து நீக்கப்படுதல்</p><p>சுமார் கி.மு. 428 (479) - எஸ்தர் அரசியாக்கப்படுதல்</p><p>கி.மு. 423 (474) - ஆமானானின் கொலைத் திட்டமும், தேவ</p><p>ஜனங்களின் வெற்றியும்</p><p>சுமார் கி.மு. 414 (465) - அகாஸ்வேரு ஆட்சி முடிவும் அர்த்தசஸ்டா பதவியேற்பும்</p><p>சுமார் கி.மு.407 (458) - சிறையிருப்பிலிருந்து இரண்டாம் குழு</p><p>எருசலேம் திரும்புதல்</p><p>சுமார் கி.மு.394 (445) - சிறையிருப்பிலிருந்து மூன்றாம் குழு எருசலேம் திரும்புதல்</p><p>சுமார் கி.மு.394 (445) - அலங்கப்பணி நிறைவடைதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>ஆசிரியர் - ஒரு யூதர்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 17-வது நூல்</p><p>அதிகாரங்கள் -10</p><p>வசனங்கள் - 167</p><p>கட்டளைகள் - 11</p><p>கேள்விகள் - 21</p><p>தீர்க்கதரிசனம் - இல்லை</p><p>வாக்குத்தத்ம்-இல்லை</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - இல்லை</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 17-வது நூல்</p><p>அதிகாரங்கள் - 10</p><p>வசனங்கள் - 167</p><p>கட்டளைகள் - 11</p><p>கேள்விகள் - 21</p>'),
 (20,'<p><b>யாத்திராகமம் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>யாத்திராகமம் புத்தகத்தை எழுதியவர் மோசே (யாத்திராகமம் 17:14; 24: 4-7; 34:27).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>யாத்திராகமம் புத்தகம் கி.மு. 1440 மற்றும் கி.பி. 1400 ஆகிய ஆண்டுகளின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>\"யாத்திராகமம்\" என்ற சொல்லுக்கு புறப்பாடு என்று பொருள். தேவனுடைய குறித்த நேரத்தில், எகிப்திலிருந்து இஸ்ரவேலர்கள் வெளியேறுவது அதாவது ஆபிரகாமின் சந்ததியினருக்கான அடிமைத்தனத்திலிருந்து விடுவிக்கப்பட்டு வெளியேறும் முடிவைக் குறித்தது (ஆதியாகமம் 15:13), ஆபிரகாமுக்கு அவருடைய சந்ததியினர் வாக்குப்பண்ணப்பட்ட தேசத்தில் வாழ்வதோடு அல்லாமல் அவர்கள் பலுகிப்பெருகி ஒரு பெரிய தேசமாக மாறுவார்கள் (ஆதியாகமம் 12:1-3, 7) என்று ஆபிரகாமிற்கு தேவன் வாக்குப் பண்ணியிருந்தார். எகிப்திலிருந்து யாக்கோபின் சந்ததியினரின் விரைவான வளர்ச்சியை அவர்களின் வாக்களிக்கப்பட்ட தேசத்தில் தேவன் ஆளும் தேசத்தை ஸ்தாபிப்பதை புத்தகத்தின் நோக்கமாக காணலாம்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>யாத்திராகமம் 1:8, \"யோசேப்பை அறியாத புதிய ராஜன் ஒருவன் எகிப்தில் தோன்றினான்.\"</p><p>யாத்திராகமம் 2:24-25, \"தேவன் அவர்கள் பெருமூச்சைக் கேட்டு, தாம் ஆபிரகாமோடும் ஈசாக்கோடும் யாக்கோபோடும் செய்த உடன்படிக்கையை நினைவுகூர்ந்தார். தேவன் இஸ்ரவேல் புத்திரரைக் கண்ணோக்கினார்; தேவன் அவர்களை நினைத்தருளினார்.\"</p><p>யாத்திராகமம் 12:27, \"இது கர்த்தருடைய பஸ்காவாகிய பலி; அவர் எகிப்தியரை அதம்பண்ணி, நம்முடைய வீடுகளைத் தப்பப்பண்ணினபோது, எகிப்திலிருந்த இஸ்ரவேல் புத்திரருடைய வீடுகளைக் கடந்துபோனார் என்று நீங்கள் சொல்லவேண்டும் என்றான். அப்பொழுது ஜனங்கள் தலைவணங்கிப் பணிந்துகொண்டார்கள்.\"</p><p>யாத்திராகமம் 20:2-3, \"உன்னை அடிமைத்தன வீடாகிய எகிப்து தேசத்திலிருந்து புறப்படப்பண்ணின உன் தேவனாகிய கர்த்தர் நானே. என்னையன்றி உனக்கு வேறே தேவர்கள் உண்டாயிருக்கவேண்டாம்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>தேவன் தம்முடைய தெரிந்துகொள்ளப்பட்ட ஜனங்களாகிய யூதர்களுடன் இடைபடுவதிலிருந்து அதாவது ஆதியாகமம் முடிகிற அந்த இடத்திலிருந்து யாத்திராகமம் தொடங்குகிறது. எகிப்தில் அதிகாரமும் வல்லமையும் வாய்ந்த யோசேப்பின் விருந்தினர்களாக இஸ்ரவேலர்கள் எகிப்துக்குள் நுழைந்த காலத்திலிருந்து, அடிமைத்தனத்தின் உச்சக்கட்டமாக கொடூரமான அடிமைத்தனத்திலிருந்து அவர்கள் விடுவிக்கப்படும் வரை, அதாவது யோசேப்பை அறியாத புதிய ராஜன் ஒருவன் எகிப்தில் தோன்றி (யாத்திராகமம் 1:8) அவர்களை கொடூரமாக நடத்தும் நிலையிலிருந்து மீட்கப்படுவதாகும்.</p><p>1-14 வரையிலுள்ள அதிகாரங்கள், பார்வோனின் கீழ் யூதர்களை ஒடுக்குவதற்கான நிலைமைகள், மோசே அவர்களின் ஒரு மீட்பராக எழுப்பப்படுதல், தேவன் மோசேயின் மூலமாக எகிப்துக்குக் கொண்டுவந்த வாதைகள், இஸ்ரவேலின் தலைவனாகிய மோசே கூறின தேவனுடைய வார்த்தைக்கு பார்வோன் கீழ்ப்படிய மறுத்தல், இறுதியாக எகிப்திலிருந்து புறப்படுதல் போன்றவைகளை விவரிக்கிறது. தேவனுடைய இறையாண்மையும் அவரது வல்லமையுள்ள கரமும் எகிப்தின்மேல் அவர் கொண்டுவந்த வாதிகளில் தெளிவாக காணப்படுகிறது - இது முதற்பேறானவரின் மரணத்தின் வாதை மற்றும் முதல் பஸ்காவின் ஆசரிப்புடன் முடிவடைகிறது – அதன் பின்பு, இஸ்ரவேலரின் விடுதலைப்பயணம், செங்கடலை இரண்டாகப் பிளத்தல் மற்றும் எகிப்தியரினுடைய இராணுவம் செங்கடலில் அழிக்கப்படுதல்.</p><p>யாத்திராகமத்தின் நடுப்பகுதி, இஸ்ரவேலர்கள் வனாந்தரத்தில் அலைந்து திரிவதும், தேவன் தம் ஜனத்தினை அற்புதமாக போஷித்தலையும் வழங்குவதற்கு அர்ப்பணிக்கப்பட்டுள்ளது. ஆனால், அவர் அவர்களுக்கு வானத்திலிருந்து மன்னாவையும், கசப்பிலிருந்து மதுரமான தண்ணீரையும், ஒரு பாறையிலிருந்து தண்ணீரும், அவர்களை அழிக்க எண்ணின எதிரிகளிடமிருந்து வெற்றி, அவருடைய கையால் கல்பலகையில் எழுதப்பட்ட நியாயப்பிரமாணம், மற்றும் இரவில் அக்கினி ஸ்தம்பமாகவும் பகலில் மேகஸ்தம்பமாகவும் அவருடைய பிரசன்னம், இப்படியெல்லாம் உண்டாயிருந்தும், ஜனங்கள் தொடர்ந்து முணுமுணுத்து, அவருக்கு எதிராகக் கலகம் செய்தனர்.</p><p>புத்தகத்தின் கடைசி மூன்றில் உடன்படிக்கைப் பெட்டியை உருவாக்குதல், ஆசரிப்புக் கூடாரத்திற்கான திட்டத்தை அதன் பல்வேறு பலிகள், பலிபீடங்கள், பணிமுட்டுகள், பண்டிகைகள் மற்றும் ஆராதனை முறைமைகள் போன்றவற்றை விவரிக்கிறது.</p><p><b>முன்னிழல்கள்:</b></p><p>இஸ்ரவேலர்கள் தேவனுக்கு கொண்டுவரத் தேவையான பல்வேறு பலிகள், இறுதி பலியினை சுட்டிக்காண்பிக்கும் ஒரு சித்திரமாகும், தேவனுடைய பஸ்கா ஆட்டுக்குட்டி, இயேசு கிறிஸ்துவே. எகிப்தின் கடைசி வாதையின் இரவில், ஒரு பழுதற்ற ஆட்டுக்குட்டி கொல்லப்பட்டு, அதன் இரத்தம் தேவனுடைய ஜனங்கள் வசித்துவந்த வீடுகளின் நிலைக்கால்களிலும், வீட்டு வாசல்களில் பூசப்பட்டு, சங்காரத் தூதனிடமிருந்து அவர்களைப் பாதுகாக்கிறது. இது தேவனுடைய ஆட்டுக்குட்டியானவராகிய இயேசுவை முன்னறிவித்தது (1 பேதுரு 1:19), அவருடைய இரத்தம் நமக்குப் பொருந்தியது, அது நித்திய ஜீவனை உறுதி செய்கிறது. யாத்திராகமம் புத்தகத்தில் கிறிஸ்துவின் அடையாள விளக்கக்காட்சிகளில் யாத்திராகமம் 17: 6-ல் உள்ள பாறையிலிருந்து வரும் தண்ணீரின் கதை உள்ளது. ஜனங்களுக்கு குடிப்பதற்காக கொடுக்கும் தண்ணீரை வழங்க மோசே பாறையை அடித்தது போல, தேவன் நம்முடைய இரட்சிப்பின் பாறையாகிய இயேசு கிறிஸ்துவை நம்முடைய பாவத்திற்காக அவரை சிலுவையில் அறையும்படி ஒப்புக்கொடுத்தார், அந்த பாறையிலிருந்து ஜீவத்தண்ணீரின் ஈவு வந்தது (யோவான் 4:10). வனாந்தரத்தில் மன்னாவை வழங்குவது கிறிஸ்துவின் சரியான சித்திரமாகும், அவரே நமது ஜீவ அப்பம் (யோவான் 6:48), இது நமக்கு நித்திய ஜீவனைக் கொடுக்க தேவனால் வழங்கப்பட்டது.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>மோசேயின் நியாயப்பிரமாணம் மனிதகுலத்தால் கைக்கொள்ள இயலாது என்பதைக் காட்டுவதற்காக ஒரு பகுதியாக வழங்கப்பட்டது. நியாயப்பிரமாணத்தைக் கடைப்பிடிப்பதன் மூலம் நாம் தேவனைப் பிரியப்படுத்த முடியாது; ஆகையால், \"இயேசு கிறிஸ்துவைப்பற்றும் விசுவாசத்தினாலேயன்றி, நியாயப்பிரமாணத்தின் கிரியைகளினாலே மனுஷன் நீதிமானாக்கப்படுவதில்லையென்று அறிந்து, நியாயப்பிரமாணத்தின் கிரியைகளினாலல்ல,கிறிஸ்துவைப்பற்றும் விசுவாசத்தினாலே நீதிமான்களாக்கப்படும்படிக்குக் கிறிஸ்து இயேசுவின்மேல் விசுவாசிகளானோம். நியாயப்பிரமாணத்தின் கிரியைகளினாலே எந்த மனுஷனும் நீதிமானாக்கப்படுவதில்லையே\" (கலாத்தியர் 2:16) என்று பவுல் வலியுறுத்துகிறார்.</p><p>அடிமைத்தனத்திலிருந்து விடுவிக்கப்பட்ட இஸ்ரவேலர்களின் வனாந்திர பயணத்தின்போது, வானத்திலிருந்து மன்னா மற்றும் வனாந்தரத்தில் உள்ள காடைகள் கொடுத்தது ஆகியவை அவருடைய ஜனங்களுக்கு அவர் அளித்த கிருபையின் போஷிப்பு என்பது தெளிவான அறிகுறிகளாகும். நம்முடைய எல்லா தேவைகளையும் பூர்த்தி செய்வதாக தேவன் வாக்குறுதி அளித்துள்ளார். \"தம்முடைய குமாரனும் நம்முடைய கர்த்தருமாயிருக்கிற இயேசுகிறிஸ்துவுடனே ஐக்கியமாயிருப்பதற்கு உங்களை அழைத்த தேவன் உண்மையுள்ளவர்\" (1 கொரிந்தியர் 1:9).</p><p>நாம் கர்த்தரை நம்ப வேண்டும், ஏனென்றால் அவர் நம்மை எல்லாவற்றிலிருந்தும் விடுவிக்க முடியும். ஆனால் பாவம் என்றென்றும் தண்டிக்கப்படாமல் இருக்க தேவன் ஒருபோதும் அனுமதிப்பதில்லை. இதன் விளைவாக, அவருடைய தண்டனையிலும் நீதியிலும் நாம் அவரை நம்பலாம். தேவன் ஒரு மோசமான சூழ்நிலையிலிருந்து நம்மை அகற்றும்போது, நாம் அவற்றிற்கே திரும்பிச் செல்ல முயற்சிக்கக்கூடாது. தேவன் நம்மிடம் கோரிக்கைகளை வைக்கும்போது, அவருக்கு கீழ்படிந்து அவருக்கு நாம் இணங்க வேண்டும் என்று அவர் எதிர்பார்க்கிறார், ஆனால் அதே நேரத்தில் அவர் கிருபையையும் இரக்கத்தையும் அளிக்கிறார், ஏனென்றால் நாம் நாமாக நமது சொந்த முயற்சியில் முழுமையாகக் கீழ்ப்படிய முடியாது என்பதை அவர் அறிவார்.</p><p>சுமார் கி.மு. 1706 (1876) - இஸ்ரவேலர் எகிப்து சென்றது</p><p>சுமார் கி.மு.1635 (1805) - யோசேப்பின் மரணம்</p><p>சுமார் கி.மு. 1571 (1527) - மோசேயின் பிறப்பு</p><p>சுமார் கி.மு. 1531 (1487) - மோசே மீதியானுக்குத் தப்பி ஓடுதல்</p><p>சுமார் கி.மு. 1491 (1446) - ஆபீப் 14 பஸ்கா ஆடு அடிக்கப்படல்</p><p>சுமார் கி.மு. 1491 (1446) - ஆபீப் 15 இஸ்ரவேலர் ராமசேசை விட்டுப்</p><p>புறப்படுதல்</p><p>சுமார் கி.மு.1491 (1446) - ஆபீப் 22 செங்கடலைப் பிளந்து</p><p>முன்னேறுதல்</p><p>சுமார். கி.மு. 1491 (1446) - சீவான் நியாயப்பிரமாணம்</p><p>வழங்கப்படுதல்</p><p>சுமார் கி.மு. 1490 (1445) - ஆபீப் 10 ஆசாரிப்புக் கூடாரம் நிறுவுதல்</p><p>சுமார் கி.மு. 1451 (1408) - இஸ்ரவேலர் கானானில் காலடி வைத்தல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - மோசே (பொருள்: இழுத்தெடுக்கப்பட்டவர்)</p><p>பெற்றோர் - தந்தை அம்ராம்</p><p>தாய் - யோகெபேத் (யாத் 6 : 20). பின்பு பார்வோனின் மகளால் தத்தெடுக்கப்பட்டவர்</p><p>சொந்த இடம் - எகிப்து</p><p>தொழில் - அரண்மனை கல்வி, பின்பு ஆடு மேய்ப்பு அதன்பின் இலட்சக்கணக்கான மக்களை கானானுக்கு வழிநடத்தியது\"</p><p>திருப்புமுனை  - மந்தைமேய்த்துக் கொண்டிருக்கும்போது\" முட்செடியில் தேவனைத் தரிசித்தபின் வந்த அழைப்பு</p><p>ஆர்வம் - எபிரெயரை விடுவித்து, பத்திரமாக</p><p>கானானுக்கு வழிநடத்துவது</p><p>சாதனைகள்  - பார்வோனுக்கு முன் அற்புதங்களைச் செய்தது, ஐந்தாகமங்களை எழுதியது. உலகத்தோற்றம் பற்றிய</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் இரண்டாவது நூல்</p><p>அதிகாரங்கள் - 40</p><p>வசனங்கள் - 1213</p><p>வரலாற்றுத் தொடர்புடைய வசனங்கள் - 1089</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 129</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 2</p><p>கேள்விகள் - 58</p><p>தேவனிடமிருந்து நேரடியான செய்திகள் - 73</p><p>கட்டளைகள் - 827</p><p>அறிக்கைகள் - 240</p><p>வாக்குத்தத்தங்கள் - 28</p><p>மோசேயின் - 35</p><p>அற்புதங்கள் அடங்க அற்புதங்கள் - 42</p>'),
 (220,'<p><b>யோபு புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>யோபுவின் புத்தகம் குறிப்பாக அதன் எழுத்தாளர் யாரென்று அவர் பெயரைக் குறிப்பிடவில்லை. யோபு, எலிஹு, மோசே மற்றும் சாலமோன் ஆகியோர்கள் பெரும்பாலும் இந்த புத்தகத்தை எழுதிய எழுத்தாளராக பரிந்துரைக்கப்படுகிறார்கள்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>யோபு புத்தகத்தின் எழுத்தாளர் பொருத்து இந்த புத்தகம் எப்பொழுது எழுதப்பட்டது என்பது தீர்மானிக்கப்படும். மோசே எழுத்தாளராக இருந்தால், எழுதப்பட்டகாலம் சுமார் கி.மு. 1440. சாலமோன் எழுத்தாளராக இருந்தால், எழுதப்பட்ட காலம் சுமார் கி.மு. 950. நமக்கு இதை எழுதிய எழுத்தாளர் யாரென்று தெரியாததால், இந்த புத்தகம் எழுதப்பட்ட காலத்தையும் நம்மால் அறிய முடியாது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>பின்வருவனவற்றைப் நாம் புரிந்துகொள்ள யோபுவின் புத்தகம் நமக்கு உதவுகிறது: தேவனுடைய அனுமதி இல்லாமல், சாத்தானால் பொருளாதாரம் மற்றும் உடல் ரீதியான அழிவை நம்மீது கொண்டு வர முடியாது. சாத்தானால் என்ன செய்ய முடியும் மற்றும் செய்ய முடியாது என்பதை நிர்ணயிப்பதில் தேவனுக்கு வல்லமை இருக்கிறது. உலகில் உள்ள அனைத்து துன்பங்களுக்கும் பின்னால் உள்ள \"ஏன்\" என்பதைப் புரிந்துகொள்வது நமது மனித திறனுக்கு அப்பாற்பட்டது. துன்மார்க்கர் தங்களின் நியாயமான நிலுவைகளைப் பெறுவார்கள். நம்முடைய வாழ்க்கை முறைகளில் நம்முடைய துன்பங்களையும் பாவத்தையும் எப்போதும் குறை சொல்ல முடியாது. ஆத்துமாவை சுத்திகரிக்க, சோதிக்க, கற்பிக்க அல்லது பலப்படுத்த சில நேரங்களில் துன்பங்கள் நம் வாழ்வில் அனுமதிக்கப்படலாம். தேவன் போதுமானவராக இருக்கிறார், வாழ்க்கையின் எல்லா சூழ்நிலைகளிலும் நம்முடைய அன்பையும் புகழையும் ஸ்துதியையும் பெற்றுக்கொள்வதற்கு தகுதியுடையவராகவே இருக்கிறார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>யோபு 1:1, \"ஊத்ஸ் தேசத்திலே யோபு என்னும் பேர்கொண்ட ஒரு மனுஷன் இருந்தான்; அந்த மனுஷன் உத்தமனும் சன்மார்க்கனும், தேவனுக்குப் பயந்து, பொல்லாப்புக்கு விலகுகிறவனுமாயிருந்தான்.\"</p><p>யோபு 1:21, \"நிர்வாணியாய் என் தாயின் கர்ப்பத்திலிருந்து வந்தேன்; நிர்வாணியாய் அவ்விடத்துக்குத் திரும்புவேன்; கர்த்தர் கொடுத்தார், கர்த்தர் எடுத்தார்; கர்த்தருடைய நாமத்துக்கு ஸ்தோத்திரம் என்றான்.\"</p><p>யோபு 38:1-2, \"அப்பொழுது கர்த்தர்: பெருங்காற்றிலிருந்து யோபுக்கு உத்தரவாக: அறிவில்லாத வார்த்தைகளினால் ஆலோசனையை அந்தகாரப்படுத்துகிற இவன் யார்?\"</p><p>யோபு 42:5-6, \"என் காதினால் உம்மைக்குறித்துக் கேள்விப்பட்டேன்; இப்பொழுதோ என் கண் உம்மைக் காண்கிறது. ஆகையால் நான் என்னை அருவருத்து, தூளிலும் சாம்பலிலும் இருந்து மனஸ்தாபப்படுகிறேன் என்றான்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>பரலோகத்தில் நிகழ்கிற ஒரு காட்சியுடன் புத்தகம் துவங்குகிறது, அங்கு சாத்தான் தேவனுக்கு முன்பாக யோபுவைக் குற்றம் சாட்டுகிறான். யோபு தேவனுக்கு மட்டுமே சேவை செய்கிறார் என்று அவர் வலியுறுத்துகிறார், ஏனென்றால் தேவன் அவரைப் பாதுகாக்கிறார், மேலும் யோபுவின் விசுவாசத்தையும் அவரது நம்பிக்கையையும் சோதிக்க தேவனுடைய அனுமதியை நாடுகிறார். தேவன் தனது அனுமதியை சில எல்லைகளுக்குள் வரையறுத்து வழங்குகிறார். நீதிமான்கள் ஏன் துன்பப்படுகிறார்கள்? யோபு தனது குடும்பத்தையும், செல்வத்தையும், ஆரோக்கியத்தையும் இழந்த பிறகு எழுப்பப்பட்ட கேள்வி இது. யோபின் மூன்று நண்பர்களான எலிப்பாஸ், பில்தாத் மற்றும் சோப்பார், அவரை \"ஆறுதல்படுத்த\" வருகிறார்கள், மேலும் அவரது தொடர்ச்சியான துயரங்களைப் பற்றி விவாதிக்கிறார்கள். அவருடைய துன்பம் அவருடைய வாழ்க்கையில் பாவத்திற்கான தண்டனை என்று அவர்கள் வலியுறுத்துகிறார்கள். யோபு, இவை அனைத்தினாலும் தேவனுக்கு அர்ப்பணிப்புடன் இருக்கிறார், அவருடைய வாழ்க்கையில் உண்டாயிருந்த பாவத்தில் ஒன்றல்ல என்று வாதிடுகிறார். நான்காவது மனிதரான எலிஹு, யோபுவிடம் தன்னைத் தாழ்த்திக் கொள்ள வேண்டும் என்றும், தன் வாழ்க்கையைத் தூய்மைப்படுத்த தேவனுடைய சோதனைகளைப் பயன்படுத்திக்கொள்ள வேண்டும் என்றும் கூறுகிறார். இறுதியாக, யோபு தேவனையே கேள்விக்குள்ளாக்குகிறார், மேலும் தேவனுடைய இறையாண்மையைப் பற்றியும், கர்த்தரை முழுமையாக நம்ப வேண்டியதன் அவசியத்தைப் பற்றியும் மதிப்புமிக்க படிப்பினைகளைக் கற்றுக்கொள்கிறார். யோபு பின்னர் அவரது முந்தைய நிலைக்கு அப்பால் ஆரோக்கியம், மகிழ்ச்சி மற்றும் செழிப்புக்கு மீட்டெடுக்கப்படுகிறது.</p><p><b>முன்னிழல்கள்:</b></p><p>யோபு தனது துயரத்தின் காரணத்தை யோசித்துக்கொண்டிருந்தபோது, மூன்று கேள்விகள் அவரது நினைவுக்கு வந்தன, அவை அனைத்தும் நம் கர்த்தராகிய இயேசு கிறிஸ்துவில் மட்டுமே பதிலளிக்கப்படுகின்றன. இந்த கேள்விகள் 14 ஆம் அத்தியாயத்தில் நிகழ்கின்றன. முதலாவதாக, 4-வது வசனத்தில், யோபு \"அசுத்தமானதிலிருந்து சுத்தமானதைப் பிறப்பிக்கத்தக்கவன் உண்டோ? ஒருவனுமில்லை\" என்று கூறுகிறார். யோபுவின் கேள்வி ஒரு இதயத்திலிருந்து வருகிறது, அது தேவனைப் பிரியப்படுத்தவோ அல்லது அவருடைய பார்வையில் நியாயப்படுத்தவோ முடியாது என்பதை அங்கீகரிக்கிறது. தேவன் பரிசுத்தர்; நாம் இல்லை. ஆகையால், மனிதனுக்கும் தேவனுக்கும் இடையில் ஒரு பெரிய இடைவெளி உள்ளது, இது பாவத்தால் ஏற்படுகிறது. ஆனால் யோபுவின் வேதனையான கேள்விக்கான பதில் இயேசு கிறிஸ்துவில் காணப்படுகிறது. அவர் நம்முடைய பாவத்திற்கான தண்டனையை செலுத்தி, அதை அவருடைய நீதிக்காக பரிமாறிக்கொண்டார், இதன் மூலம் தேவனுடைய பார்வையில் நம்மை ஏற்றுக்கொள்ளும்படி செய்தார் (எபிரெயர் 10:14; கொலோசெயர் 1:21-23; 2 கொரிந்தியர் 5:17).</p><p>யோபுவின் இரண்டாவது கேள்வி, \"மனுஷனோவென்றால் செத்தபின் ஒழிந்துபோகிறான், மனுபுத்திரன் ஜீவித்துப்போனபின் அவன் எங்கே?\" (வசனம் 10). இது நித்தியம் மற்றும் ஜீவன் மற்றும் மரணம் பற்றிய மற்றொரு கேள்வி, அது கிறிஸ்துவில் மட்டுமே பதிலளிக்கப்படுகிறது. கிறிஸ்துவுடன், ‘அவர் எங்கே?’ என்பதற்கான கேள்வியின் பதில் பரலோகத்தில் நித்திய ஜீவன். கிறிஸ்து இல்லாமல், பதில் \"புறம்பான இருளில்\" ஒரு நித்தியம், அங்கு \"அழுகை மற்றும் பற்கடிப்பு\" உண்டாயிருக்கும் (மத்தேயு 25:30).</p><p>14-ஆம் வசனத்தில் காணப்படும் யோபுவின் மூன்றாவது கேள்வி, \"மனுஷன் செத்தபின் பிழைப்பானோ?\" என்பதுதான். மறுபடியும், கிறிஸ்துவில் இதன் பதில் காணப்படுகிறது. நாம் அவரிடத்தில் அவரோடு இருந்தால் நாம் மீண்டும் ஜீவன் பெற்று வாழ்வோம். \"அழிவுள்ளதாகிய இது அழியாமையையும், சாவுக்கேதுவாகிய இது சாவாமையையும் தரித்துக்கொள்ளும்போது, மரணம் ஜெயமாக விழுங்கப்பட்டது என்று எழுதியிருக்கிற வார்த்தை நிறைவேறும். மரணமே! உன் கூர் எங்கே? பாதாளமே! உன் ஜெயம் எங்கே?\" (1 கொரிந்தியர் 15:54-55).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>திரைக்குப் பின்னால் ஒரு \"அண்ட மோதல்\" நடந்து கொண்டிருப்பதை யோபுவின் புத்தகம் நமக்கு நினைவூட்டுகிறது. தேவன் எதையாவது அனுமதிக்கிறார் என்று பெரும்பாலும் நாம் ஆச்சரியப்படுகிறோம், முழுப் படத்தையும் பார்க்காமல், தேவனுடைய நன்மையை நாம் கேள்விக்குள்ளாக்குகிறோம் அல்லது சந்தேகிக்கிறோம். எல்லா சூழ்நிலைகளிலும் தேவனை நம்புவதற்கு யோபுவின் புத்தகம் நமக்குக் கற்பிக்கிறது. நாம் தேவனை நம்ப வேண்டும், நமக்கு புரியாதபோது மட்டுமல்ல, ஆனால் நமக்கு புரியவில்லை என்றாலும் அவரையே நம்பவேண்டும். சங்கீதக்காரன் நமக்கு சொல்லுகிறார், \"தேவனுடைய வழி உத்தமமானது; கர்த்தருடைய வசனம் புடமிடப்பட்டது; தம்மை நம்புகிற அனைவருக்கும் அவர் கேடகமாயிருக்கிறார்\" (சங்கீதம் 18:30). தேவனுடைய வழிகள் \"பரிபூரணமானவை\" என்றால், அவர் எதைச் செய்கிறாரோ, அவர் எதை அனுமதித்தாலும் அது சரியானது என்று நாம் நிச்சயமாக நம்பலாம். இது நமக்கு சாத்தியமில்லை என்று தோன்றலாம், ஆனால் நம் மனம் தேவனுடைய மனம் அல்ல. அவர் நமக்கு நினைவூட்டுவது போல, அவருடைய மனதை நாம் முழுமையாகப் புரிந்துகொள்வோம் என்று எதிர்பார்க்க முடியாது என்பது உண்மைதான், \"என் நினைவுகள் உங்கள் நினைவுகள் அல்ல; உங்கள் வழிகள் என் வழிகளும் அல்லவென்று கர்த்தர் சொல்லுகிறார். பூமியைப்பார்க்கிலும் வானங்கள் எப்படி உயர்ந்திருக்கிறதோ, அப்படியே உங்கள் வழிகளைப்பார்க்கிலும் என் வழிகளும், உங்கள் நினைவுகளைப்பார்க்கிலும் என் நினைவுகளும் உயர்ந்திருக்கிறது\" (ஏசாயா 55:8-9). ஆயினும்கூட, தேவனுக்குக் கீழ்ப்படிவதும், அவரை நம்புவதும், அவருடைய சித்தத்திற்குக் கீழ்ப்படிவதும், நாம் புரிந்துகொண்டாலும் இல்லாவிட்டாலும் அது நமது பொறுப்பாக இருக்கிறது.</p><p>சுமார் கி.மு.4004 - (தெரியாது) படைப்பும் வீழ்ச்சியும்</p><p>சுமார் கி.மு.2348-2347 - (தெரியாது) ஜலப்பிரளயம்</p><p>சுமார் கி.மு. 1996-1821 (2166-1991) - ஆபிரகாமின் வாழ்வு</p><p>சுமார் கி.மு. 1896-1715 (2066-1885) - ஈசாக்கின் வாழ்வு</p><p>சுமார் கி.மு.1836-1689 (2006-1859) - யாக்கோபின் வாழ்வு</p><p>சுமார் கி.மு. 1745-1635 (1915-1805) - யோசேப்பின் வாழ்வு</p><p>சுமார் கி.மு. 1571-1452 (1527-1407) - மோசேயின் வாழ்வு</p><p>யோபு நியாயப்பிரமாண காலத்துக்கு முன்பு.. ஆபிரகாமுக்கு முன்போ, ஆபிரகாமின் சமகாலத்திலோ, அதற்குச் சற்று பின்போ, வாழ்ந்திருக்க வேண்டும்.</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - யோபு. பெயரின் பொருள் பற்றி கருத்து வேறுபாடுகள் உண்டு  \"தந்தை எங்கே/திரும்பியவர்/ துன்புறுத்தப்பட்டவர்/ பகையாக்கப்பட்டவர் என்றெல்லாம் பொருள்கள் ஊகிக்கப்படுகின்றன</p><p>பிறந்த இடம் - ஊக்ஸ்</p><p>குடும்பம் - சகோதர, சகோதரிகள் உண்டு (42 : 11 ஒரு மனைவி 2 : 9)</p><p>பிள்ளைகள் - முதலில் 7 புதல்வர்கள் 3 புதல்விகள் பின்பும் 7 புதல்வர்கள் 3 புதல்விகள் இரண்டாவது முறை பிறந்த புதல்விகள் பெயர் எமீமாள், கெத்சீயா, கெரேனாப்புக்</p><p>வாழ்க்கை  நிலை - பெரும் பணக்காரர் முதிலில் 7000 ஆடு. 3000 ஒட்டகம், 1000 காளை, 500 கழுதைகள், பின்பு இருமடங்கு</p><p>தொழில் - நீதிபதியாகவும், குடும்ப ஆசாரியராகவும் செயல்பட்டார்</p><p>(29: 7-25, 1: 5, 42: 7-9)</p><p>சிறப்பு - சோதனையைச் சகித்தவருக்கு சிறந்த வேதாகமச் சான்றானார் (யாக் 5 : 11)</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 18-வது நூல்</p><p>அதிகாரங்கள் - 42</p><p>வசனங்கள் - 1070</p><p>வரலாற்றுத் தொடர்பு வசனங்கள் - 1066</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 1</p><p>நிறைவேறாத தீர்க்கதரிசனங்கள் - 3</p><p>கேள்விகள் - 329</p><p>கட்டளைகள் - 13</p><p>எச்சரிப்புகள் - 4</p><p>தேவனிடமிருந்து சிறப்பு செய்திகள்  -10</p>'),
 (230,'<p><b>சங்கீதப் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>சங்கீதங்களை அறிமுகப்படுத்தும் சுருக்கமான விளக்கங்கள் ஏறக்குறைய 73 நிகழ்வுகளில் தாவீது எழுத்தாளராக பட்டியலிடப்பட்டுள்ளன. இந்த சங்கீதங்களில் பலவற்றில் தாவீதின் ஆளுமையும் அடையாளமும் தெளிவாக முத்திரையிடப்பட்டுள்ளன. தாவீது தனிப்பட்ட பல சங்கீதங்களை எழுதினார் என்பது தெளிவாகத் தெரிந்தாலும், அவர் நிச்சயமாக முழுத் தொகுப்பையும் எழுதியவர் அல்ல. சங்கீதங்களில் இரண்டு (72) மற்றும் (127) தாவீதின் குமாரனும் வாரிசுமான சாலமோனால் எழுதப்பட்டது. சங்கீதம் 90 மோசேயின் ஜெபம். 12 சங்கீதங்கள் அதாவது 50 மற்றும் 73—83 வரையிலுள்ள சங்கீதங்கள் மற்றொரு குழுவாகிய ஆசாபின் குடும்பத்தினரால் பாடப்பட்டதாகும். கோராவின் புத்திரர்கள் 11 சங்கீதங்களை எழுதினர் (42, 44-49, 84-85,87-88). 88-ஆம் சங்கீதம் ஹேமானும், 89வது சங்கீதம் எஸ்றாஹியரான ஏத்தானால் எழுதப்பட்டது. சாலமன் மற்றும் மோசேயைத் தவிர, இந்த கூடுதல் ஆசிரியர்கள் அனைவரும் ஆசாரியர்கள் அல்லது லேவியர்கள், தாவீதின் ஆட்சிக் காலத்தில் பரிசுத்த ஸ்தலத்தின் வழிபாட்டிற்கு இசையை வழங்குவதற்கு பொறுப்பானவர்கள் ஆகும். ஐம்பது சங்கீதங்கள் எந்தவொரு குறிப்பிட்ட நபரையும் எழுத்தாளராக குறிப்பிடாமல் இருக்கின்றன.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>எழுத்தாளர் யார் என்கிற கேள்வியை கவனமாக ஆராய்ந்தோமானால், சங்கீதங்களால் உட்கொள்ளப்பட்ட விஷயங்கள் அவை பல நூற்றாண்டுகளின் காலப்பகுதியைக் கொண்டுள்ளன என்பதை வெளிப்படுத்துகின்றன. சேகரிப்பில் உள்ள மிகப் பழமையான சங்கீதம் அநேகமாக மோசேயின் ஜெபம் (90), இது கடவுளின் நித்தியத்துடன் ஒப்பிடும்போது மனிதனின் பலவீனத்தை பிரதிபலிக்கிறது. சமீபத்திய சங்கீதம் அநேகமாக (137), பாபிலோனியர்களால் எபிரேயர்கள் சிறைபிடிக்கப்பட்டுப் போன நாட்களில் தெளிவாக எழுதப்பட்ட புலம்பல் பாடல் ஆகும், சுமார் கி.மு. 586 முதல் கி.மு. 538.</p><p>150 தனிப்பட்ட சங்கீதங்கள் இஸ்ரேலின் வரலாற்றில் ஆயிரம் ஆண்டுகளில் பல்வேறு நபர்களால் எழுதப்பட்டன என்பது தெளிவாகிறது. சிறைப்பிடிப்பு சுமார் கி.மு. 537-ல் முடிவுக்கு வந்தது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>சங்கீத புத்தகம் 150 தனிப்பட்ட சங்கீதங்களைக் கொண்ட வேதாகமத்தின் மிக நீளமான புத்தகமாகும். தேவன் மற்றும் அவருடைய படைப்பு, யுத்தம், ஆராதனை, ஞானம், பாவம் மற்றும் தீமை, தீர்ப்பு, நீதி மற்றும் மேசியாவின் வருகை போன்ற பாடங்களை சங்கீதங்கள் கையாளுகின்றன என்பதால் இது மிகவும் மாறுபட்ட ஒன்றாகும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>சங்கீதம் 19:1, \"வானங்கள் தேவனுடைய மகிமையை வெளிப்படுத்துகிறது, ஆகாயவிரிவு அவருடைய கரங்களின் கிரியையை அறிவிக்கிறது.\"</p><p>சங்கீதம் 22:16-19, \"நாய்கள் என்னைச் சூழ்ந்திருக்கிறது; பொல்லாதவர்களின் கூட்டம் என்னை வளைந்துகொண்டது; என் கைகளையும் என் கால்களையும் உருவக் குத்தினார்கள். என் எலும்புகளையெல்லாம் நான் எண்ணலாம்; அவர்கள் என்னை நோக்கிப் பார்த்துக்கொண்டிருக்கிறார்கள். என் வஸ்திரங்களைத் தங்களுக்குள்ளே பங்கிட்டு, என் உடையின்பேரில் சீட்டுப்போடுகிறார்கள். ஆனாலும் கர்த்தாவே, நீர் எனக்குத் தூரமாகாதேயும்; என் பெலனே, எனக்குச் சகாயம்பண்ணத் தீவிரித்துக்கொள்ளும்.\"</p><p>சங்கீதம் 23:1, \"கர்த்தர் என் மேய்ப்பராயிருக்கிறார்; நான் தாழ்ச்சியடையேன்.\"</p><p>சங்கீதம் 29:1-2, \"பலவான்களின் புத்திரரே, கர்த்தருக்கு மகிமையையும் வல்லமையையும் செலுத்துங்கள்; கர்த்தருக்கே அதைச் செலுத்துங்கள். கர்த்தருடைய நாமத்திற்குரிய மகிமையை அவருக்குச் செலுத்துங்கள்; பரிசுத்த அலங்காரத்துடனே கர்த்தரைத் தொழுதுகொள்ளுங்கள்.\"</p><p>சங்கீதம் 51:10, \"தேவனே, சுத்த இருதயத்தை என்னிலே சிருஷ்டியும், நிலைவரமான ஆவியை என் உள்ளத்திலே புதுப்பியும்.\"</p><p>சங்கீதம் 119:1-2, \"கர்த்தருடைய வேதத்தின்படி நடக்கிற உத்தம மார்க்கத்தார் பாக்கியவான்கள். அவருடைய சாட்சிகளைக் கைக்கொண்டு, அவரை முழு இருதயத்தோடும் தேடுகிறவர்கள் பாக்கியவான்கள்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>சங்கீதம் புத்தகம் என்பது ஜெபங்கள், கவிதைகள் மற்றும் துதிப்பாடல்களின் தொகுப்பாகும். இந்த புத்தகத்தின் பகுதிகள் பண்டைய இஸ்ரவேலர்களின் வழிபாட்டு சேவைகளில் ஒரு துதிப்பாடலாக பயன்படுத்தப்பட்டன. சங்கீதங்களின் இசை பாரம்பரியம் அதன் தலைப்பால் நிரூபிக்கப்பட்டுள்ளது. இது ஒரு கிரேக்க வார்த்தையிலிருந்து வருகிறது, அதாவது \"ஒரு இசைக் கருவியின் பாடலுடன் பாடிய பாடல்.\"</p><p><b>முன்னிழல்கள்:</b></p><p>தேவன் தம் ஜனத்திற்காக ஒரு மீட்பரை வழங்குவது சங்கீதத்தில் தொடர்ச்சியான கருப்பொருள் ஆகும். மேசியாவின் தீர்க்கதரிசன சித்திரங்கள் ஏராளமான சங்கீதங்களில் காணப்படுகின்றன. சங்கீதம் 2:1-12 மேசியாவின் வெற்றியையும் ராஜ்யத்தையும் சித்தரிக்கிறது. சங்கீதம் 16:8-11 அவருடைய மரணத்தையும் உயிர்த்தெழுதலையும் முன்னறிவிக்கிறது. சங்கீதம் 22 சிலுவையில் துன்பப்படுகிற இரட்சகரைக் காட்டுகிறது மற்றும் சிலுவையில் அறையப்பட்ட விரிவான தீர்க்கதரிசனங்களை முன்வைக்கிறது, இவை அனைத்தும் பரிபூரணமாக நிறைவேற்றப்பட்டன. மேசியா மற்றும் அவருடைய மணவாட்டியின் மகிமைகள் சங்கீதம் 45:6-7-ல் உள்ளன, சங்கீதம் 72:6-17, 89:3-37, 110:1-7 மற்றும் 132:12-18 ஆகியவை மகிமையையும் அவரது ஆட்சியின் உலகளாவிய தன்மையையும் முன்வைக்கின்றன.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>ஆவியினால் அல்லது கிறிஸ்துவின் வார்த்தையினால் நிரப்பப்பட்டதன் முடிவுகளில் ஒன்று ஸ்துதி பாடுவதாகும். ஆரம்பகால தேவாலயத்தின் \"பாடல் புத்தகம்\" தான் சங்கீதங்கள், அவை கிறிஸ்துவில் புதிய சத்தியத்தைப் பிரதிபலித்தன.</p><p>எல்லா சங்கீதங்களிலும் தேவன் ஒரே கர்த்தராகும். ஆனால் நம் வாழ்வின் குறிப்பிட்ட சூழ்நிலைகளுக்கு ஏற்ப நாம் அவருக்கு வெவ்வேறு வழிகளில் பதிலளிக்கிறோம். நாம் என்ன ஒரு அற்புதமான தேவனை வணங்குகிறோம் என்று சங்கீதக்காரர் அறிவிக்கிறார், நம்முடைய மனித அனுபவங்களுக்கு அப்பாற்பட்டவர், உயர்ந்தவர், ஆனால் தொடுவதற்கு போதுமான நெருக்கமானவர், வாழ்க்கைப் பாதையில் நம்மோடு நடந்து செல்வவர்.</p><p>நம்முடைய எல்லா உணர்வுகளையும் நாம் கடவுளிடம் கொண்டு வர முடியும் – அவை எவ்வளவு எதிர்மறையாக இருந்தாலும் அல்லது புகார் கொடுத்தாலும் - அவர் கேட்பார், புரிந்துகொள்வார் என்று நாம் உறுதியாக நம்பலாம். வாழ்க்கையின் பிரச்சினைகளால் நம்மை மூழ்கடித்து விடுவதால், அனைவரின் மிக ஆழமான ஜெபம் உதவிக்கான நிலை அவரை நோக்கி அழுதல் என்று சங்கீதக்காரன் நமக்குக் கற்பிக்கிறார்.</p><p>சுமார் கி.மு.1491-393 (1446-445) -  சங்கீதம் எழுதப்படல்</p><p>சுமார் கி.மு. 1491 (1446)  - இஸ்ரவேலர் விடுதலைப்பயணம் புறப்படுதல்</p><p>சுமார் கி.மு. 1451 (1406) - கானானை வந்தடைதல்</p><p>சுமார் கி.மு. 1434 (1375) - நியாயாதிபதிகள் ஆட்சி தொடக்கம்</p><p>சுமார் கி.மு. 1001 (1050) - சவுலின் ஆட்சி தொடக்கம்</p><p>சுமார் கி.மு. 982 (1010) - தாவீதின் எபிரோன் ஆட்சி தொடக்கம்</p><p>சுமார் கி.மு.880 (931) - தேசம் பிளவுறுதல்</p><p>சுமார் கி.மு. 535 (586) - எருசலேம் வீழ்ச்சியடைதல்</p><p>சுமார் கி.மு. 484 (536) - இஸ்ரவேலர் முதலில் திரும்பி வருதல்</p><p>சுமார் கி.மு. 405 (458) - எஸ்றா எருசலேமுக்கு</p><p>சுமார் கி.மு. 393 (446) - நெகேமியா தலைமையில் திரும்பி வருதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p><b>இந்நூலின் ஆசிரியர்களாக குறிப்பிடப்படுவோர் பலர்</b></p><p>1 - மோசே - 1 சங்கீதம் சங் 90 சங்கீதம் 91-ம் மோசேயினுடையது என்றக் கருத்தும் உண்டு</p><p>2 - தாவீது - 73 சங்கீதங்கள்</p><p>3 - ஆசாப் - 12 சங்கீதங்கள் (சங் 50, 73-83)</p><p>4 - சரலொமோன் - 2 சங்கீதங்கள் (சங் 72, 127)</p><p>5 - ஏமான் - 1 சங்கீதம் (சங் 88)</p><p>6 - ஏத்தான் - 1 சங்கீதம் (சங் 89)</p><p>7 - கோராகு புத்திரர் - 12 சங்கீதங்கள் (ஆசிரியராகவோ. பெற்றுக் கொண்டவர்களாகவோ, இருக்கலாம்)</p><p>8 - எசேக்கியா - 10 ஆரோகணச் சங்கீதங்கள் (கருத்து வேறுபாடு உண்டு</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 19-வது நூல்</p><p>அதிகாரங்கள் - 150</p><p>வசனங்கள் - 2461</p><p>வரலாற்றுத்தொடர்பு வசளங்கள் - 2,027</p><p>நிறைவேறிய தீர்க்க தரிசனங்கள் - 162</p><p>நிறைவேறாத தீர்க்கதரிசனங்கள் - 274</p><p>கேள்விகள் - 164</p><p>கட்டளைகள் - 413</p><p>தேவ செயல்பாடுகள் - 338</p><p>தீர்மானங்கள் - 24</p><p>தேவ துதிகள் - 174</p><p>குற்றம் சாட்டுதல்கள் - 118</p><p>யூதாவைக் குறித்தவை - 72</p><p>தேவ சத்தியங்கள் - 865</p><p>தேவ வசனம் பற்றியவை - 235</p><p>காட்சி அறிக்கைகள் - 182</p><p>வாக்குத்தததங்கள் - 97</p><p>மேசியாவைக் குறித்தவை - 128</p><p>ஆசீர்வாதங்கள் - 281</p><p>பாடலாசிரியர்களைக் குறித்தவை - 190</p><p>நியாயச் செயல்கள் -78</p><p>தீயச் செயல்கள் - 101</p><p>பாவங்கள் - 233</p><p>விண்ணப்பங்கள் - 582</p><p>விண்ணப்பக் காரணங்கள் - 187</p>'),
 (240,'<p><b>நீதிமொழிகள் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>தாவீதின் குமாரனாகிய சாலமோன் ராஜா நீதிமொழிகளின் முதன்மையான எழுத்தாளராகும். அவரது பெயர் 1:1, 10:1, மற்றும் 25:1 ஆகிய வசனங்களில் காணப்படுகிறது. சாலமோன் தன்னுடையதைத் தவிர வேறு பழமொழிகளையும் சேகரித்து திருத்தியுள்ளார் என்றும் நாம் கருதலாம், ஏனெனில் பிரசங்கி 12:9 கூறுகிறது, \"மேலும், பிரசங்கி ஞானவானாயிருந்தபடியால், அவன் ஜனத்துக்கு அறிவைப்போதித்து, கவனமாய்க் கேட்டாராய்ந்து அநேகம் நீதிமொழிகளைச் சேர்த்து எழுதினான்.\" உண்மையில், மிஷில் ஷெலோமோ என்ற எபிரேய தலைப்பு \"சாலமோனின் நீதிமொழிகள்\" என்று மொழிபெயர்க்கப்பட்டுள்ளது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>சாலமோன் பழமொழிகள் கி.மு. 900-ல் அவர் ராஜாவாக இருந்த காலத்தில், இஸ்ரேல் தேசம் ஆவிக்குரிய ரீதியாகவும், அரசியல் ரீதியாகவும், கலாச்சார ரீதியாகவும், பொருளாதார ரீதியாகவும் உச்சத்தை அடைந்தது. இஸ்ரவேலின் நற்பெயர் அதிகரித்தபோது, சாலமோன் ராஜாவின் புகழும் ஓங்கி வளர்ந்தது. தெரிந்த உலகின் தொலைதூரத்திலிருந்து வெளிநாட்டு பிரமுகர்கள் புத்திசாலித்தனமான ஞானமுள்ள மன்னர் பேசுவதைக் கேட்க அதிக தூரம் பயணம் செய்து வந்தனர் (1 ராஜா. 4:34).</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>அறிவு என்பது மூல உண்மைகளை குவிப்பதைத் தவிர வேறில்லை, ஆனால் ஞானம் என்பது மக்கள், நிகழ்வுகள் மற்றும் சூழ்நிலைகளை தேவன் பார்க்கும்போது பார்க்கும் திறன் ஆகும். நீதிமொழிகள் புத்தகத்தில், சாலமோன் தேவனுடைய மனதை உயர்ந்த மற்றும் பொதுவான, சாதாரண, அன்றாட சூழ்நிலைகளிலும் வெளிப்படுத்துகிறார். சாலமோன் ராஜாவின் கவனத்தை எந்த தலைப்பும் தப்பவில்லை என்று தெரிகிறது. தனிப்பட்ட நடத்தை, பாலியல் உறவுகள், வணிகம், செல்வம், தொண்டு, லட்சியம், ஒழுக்கம், கடன், குழந்தை வளர்ப்பு, தன்மை, ஆல்கஹால், அரசியல், பழிவாங்குதல் மற்றும் தெய்வபக்தி தொடர்பான பல விஷயங்கள் இந்த மேலான ஞானமான தொகுப்பில் உள்ளடக்கப்பட்ட பல தலைப்புகளில் அடங்கும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>நீதிமொழிகள் 1:5, \"புத்திமான் இவைகளைக் கேட்டு, அறிவில் தேறுவான்; விவேகி நல்லாலோசனைகளை அடைவான்.\"</p><p>நீதிமொழிகள் 1:7, \"கர்த்தருக்குப் பயப்படுதலே ஞானத்தின் ஆரம்பம்; மூடர் ஞானத்தையும் போதகத்தையும் அசட்டைபண்ணுகிறார்கள்.\"</p><p>நீதிமொழிகள் 4:5, \"ஞானத்தைச் சம்பாதி, புத்தியையும் சம்பாதி; என் வாயின் வார்த்தைகளை மறவாமலும் விட்டு விலகாமலும் இரு.\"</p><p>நீதிமொழிகள் 8:13-14, \"தீமையை வெறுப்பதே கர்த்தருக்குப் பயப்படும் பயம்; பெருமையையும், அகந்தையையும், தீய வழியையும், புரட்டுவாயையும் நான் வெறுக்கிறேன். ஆலோசனையும் மெய்ஞ்ஞானமும் என்னுடையவைகள்; நானே புத்தி, வல்லமை என்னுடையது.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>நீதிமொழிகள் புத்தகத்தை சுருக்கமாகக் கூறுவது சற்று கடினம், ஏனென்றால் வேதாகமத்தின் பல புத்தகங்களைப் போலல்லாமல், அதன் பக்கங்களில் குறிப்பிட்ட சதி அல்லது கதைக்களம் எதுவும் இல்லை; அதேபோல், புத்தகத்தில் பிரதான கதாபாத்திரம் என்று எதுவும் இல்லை. இந்த புத்தகத்தின் மைய நிலையை எடுக்கும் ஞானம், வரலாறு, மக்கள் மற்றும் கலாச்சாரங்கள் முழுவதையும் கடந்த ஒரு பிரமாண்டமான, தெய்வீக ஞானம் ஆகும். இந்த அற்புதமான கருவூலத்தின் ஒரு முழுமையான வாசிப்பு கூட, புத்திசாலித்தனமான சாலமோன் ராஜாவின் குறுகிய கூற்றுகள் மூவாயிரம் ஆண்டுகளுக்கு முன்பு இருந்ததைப் போலவே இன்றும் பொருத்தமானவை என்பதை வெளிப்படுத்துகின்றன.</p><p><b>முன்னிழல்கள்:</b></p><p>ஞானத்தின் கருப்பொருளும் நம் வாழ்வில் அதன் அவசியமும் கிறிஸ்துவில் அதன் நிறைவைக் காண்கின்றன. ஞானத்தைத் தேடுவதற்கும், ஞானத்தைப் பெறுவதற்கும், ஞானத்தைப் புரிந்துகொள்வதற்கும் நீதிமொழிகளில் நாம் தொடர்ந்து அறிவுறுத்தப்படுகிறோம். கர்த்தருக்குப் பயப்படுவதுதான் ஞானத்தின் ஆரம்பம் (1:7; 9:10) என்று நீதிமொழிகள் நமக்குச் சொல்லுகின்றன, அதையே மீண்டும் மீண்டும் வலியுறுத்திச் சொல்லுகின்றன. கர்த்தருடைய கோபத்தையும் நீதியையும் பற்றிய நம்முடைய அச்சமே நம்மை கிறிஸ்துவிடம் கவனம் செலுத்துகிறது, அவர் தேவனுடைய ஞானத்தின் உருவகமாக இருக்கிறார், மனிதகுலத்திற்கான மீட்பின் மகத்தான திட்டத்தில் வெளிப்படுத்தப்பட்டுள்ளது. கிறிஸ்துவில், \"அவருக்குள் ஞானம் அறிவு என்பவைகளாகிய பொக்கிஷங்களெல்லாம் அடங்கியிருக்கிறது\" (கொலோசெயர் 2:3), ஞானத்தைத் தேடுவதற்கும், தேவனுக்கு நாம் பயப்படுவதற்கான தீர்வுக்கும், \"அவரே தேவனால் நமக்கு ஞானமும் நீதியும் பரிசுத்தமும் மீட்புமானார்\" (1 கொரிந்தியர் 1:31) இதுதான் நமக்குத் தேவையாயிருக்கிறது. கிறிஸ்துவில் மட்டுமே காணப்படும் ஞானம் உலகின் முட்டாள்தனத்திற்கு முரணானது, இது நம் பார்வையில் ஞானமாக இருக்க ஊக்குவிக்கிறது. அதுபோல நீதிமொழிகள், உலகின் வழி கடவுளின் வழி அல்ல (நீதிமொழிகள் 3:7) மற்றும் உலகின் வழி மரணத்திற்கு மட்டுமே வழிவகுக்கிறது (நீதிமொழிகள் 14:12; 16:25) என்றும் கூறுகிறது.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>இந்த புத்தகத்தில் மறுக்கமுடியாத நடைமுறை பயன்பாடு உள்ளது, ஏனெனில் அனைத்து வகையான சிக்கலான சிக்கல்களுக்கும் பிரச்சனைகளுக்கும் ஆரோக்கியமான மற்றும் விவேகமான பதில்கள் அதன் முப்பத்தொன்று அதிகாரங்களில் காணப்படுகின்றன. நிச்சயமாக, நீதிமொழிகள் இதுவரை எழுதப்பட்ட மிகப் பெரிய \"எப்படி\" புத்தகம் மற்றும் சாலமோனின் படிப்பினைகளை இதயத்திற்கு எடுத்துச் செல்ல நல்ல அறிவு உள்ளவர்கள் விரைவாக தேவபக்தி, செழிப்பு மற்றும் மனநிறைவு ஆகியவற்றைக் கண்டுபிடிப்பார்கள்.</p><p>நீதிமொழிகள் புத்தகத்தின் தொடர்ச்சியான வாக்குறுதி என்னவென்றால், ஞானத்தைத் தேர்ந்தெடுத்து தேவனைப் பின்பற்றுபவர்கள் பல வழிகளில் ஆசீர்வதிக்கப்படுவார்கள்: நீண்ட ஆயுளுடன் (9:11); செழிப்பு (2:20-22); மகிழ்ச்சி (3: 13-18); தேவனுடைய நன்மை (12:21) போன்றவைகளை அடைவார்கள். அவரை நிராகரிப்பவர்கள், மறுபுறம், அவமானத்தையும் மரணத்தையும் அனுபவிக்கிறவர்களாக இருப்பார்கள் (3:35; 10:21). தேவனை நிராகரிப்பது என்பது ஞானத்திற்குப் பதிலாக முட்டாள்தனத்தைத் தேர்ந்தெடுப்பது மற்றும் தேவன், அவருடைய வார்த்தை, அவருடைய ஞானம் மற்றும் அவருடைய ஆசீர்வாதங்களிலிருந்து நம்மைப் பிரிப்பதாகும்.</p><p>சுமார் கி.மு 962 (1010) - தாவீது அரசராதல்</p><p>சுமார் கி.மு 921 (970) - சாலொமோன் அரசராதல்</p><p>சுமார் கி.மு.921-880 (970-931) - பெரும்பாலான நீதிமொழிகள் எழுதப்பட்டது</p><p>சுமார் கி.மு 880 (931) - இஸ்ரவேல் பிளவுறுதல்</p><p>சுமார் கி.மு 670 (721) - இஸ்ரவேல் (வடக்கு) அடிமையாக</p><p>செல்லுதல்</p><p>சுமார் கி.மு 665 (716) - எசேக்கியா அரசராதல்</p><p>சுமார் கி.மு 636 (687) - எசேக்கியா ஆட்சி முடிவு. \"மனாசே அரசராதல்</p><p>சுமார் கி.மு 665-636 (716-687) - நீதிமொழிகள் தொகுக்கப்படல்</p><p>சுமார் கி.மு.535 (586) - எருசலேம் வீழ்ச்சி</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - எரேமியா (கர்த்தரை உயர்த்துங்கள் / கர்த்தர் துரத்துவார்)</p><p>தந்தை பெயர் - இல்க்கியா ஆசாரியர்</p><p>ஊர் - ஆனதோத், பென்யமீன் எல்லையிலிருந்த லேவியரின் பட்டணம்</p><p>தொழில் - தீர்க்கதரிசி</p><p>படைப்புகள் - பல நூற்களின் ஆசிரியர். இராஜாக்கள் நூற்கள், எரேமியா, புலம்பல்</p><p>சிறப்புப் பெயர்கள் - புலம்பலின் தீர்க்கதரிசி, தனிமையின் தீர்க்கதரிசி, ஓர் உடைந்த உள்ளம், கடின வார்த்தை கூறிய மென்மையான இதயத் துக்குரியவர், அழுது அழுது அழிவைக் கூறியவர்</p><p>சாதனை - பலமுறை சிறையிருப்பிலும், விமர்சனங்க ளிலும், மிரட்டல்களில் அகப்பட்ட போதும் சத்தியத்துக்காக துணிந்து நின்றவர்.</p><p>தீர்க்கதரிசன - பல தீர்க்கதரிசன நிறைவேறுதல்களை</p><p>கண்ணாரக் கண்டவர்.</p><p>ஆண்டுகள் - சுமார் 52 (சுமார் 626 - 574)</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 20-வது நூல்</p><p>அதிகாரங்கள் - 31</p><p>வசனங்கள் - 915</p><p>கேள்விகள் - 49</p><p>நிறைவேறாத தீர்க்கதரிசனங்கள் - 27</p><p>பாவங்கள் - 67</p><p>மூடர்களைக் குறித்தவை - 66</p><p>சோம்பலைப் பற்றியவை - 28</p><p>அரசர்களைப் பற்றியவை - 22</p><p>சீரழிவுகள் - 25</p><p>கட்டளைகள் - 215</p><p>வாக்குத்தத்தங்கள் -120</p><p>ஆசீர்வாதங்கள் - 27</p><p>வாழ்வு புதிர்கள் - 24</p><p>நற் செயல்கள் - 17</p><p>நீதி மொழிகள் - 560</p>'),
 (250,'<p><b>பிரசங்கி புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>பிரசங்கி புத்தகம் அதன் எழுத்தாளரை நேரடியாக அடையாளம் காண்பிக்கவில்லை. சாலமோன் இந்த புத்தகத்தை எழுதினார் என்பதைக் குறிக்கும் சில வசனங்கள் உள்ளன. சாலமோனின் மரணத்திற்குப் பிறகு, மேலும் நூறு ஆண்டுகளுக்குப் பிறகு, வேறொருவர் புத்தகத்தை எழுதியதாகக் கூறக்கூடிய சூழலில் சில தடயங்கள் உள்ளன. இருப்பினும், எழுத்தாளர் உண்மையில் சாலமோன் என்பது வழக்கமான மற்றும் பொதுவான நம்பிக்கை.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>இஸ்ரவேலின் ராஜாவாக சாலமோன் சுமார் கி.மு. 970 முதல் கிமு. 930 வரை ஆட்சி புரிந்தார். பிரசங்கி புத்தகம் அவருடைய ஆட்சியின் முடிவில் எழுதப்பட்டிருக்கலாம், தோராயமாக கி.மு. 935.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>பிரசங்கி புத்தகம் என்பது ஒரு முன்னோக்கு புத்தகம் ஆகும். \"பிரசங்கி\" (கே.ஜே.வி) அல்லது \"ஆசிரியர்\" (என்.ஐ.வி) விவரிப்பு உலக விஷயங்களில் மகிழ்ச்சியைத் தேடுவதால் தவிர்க்க முடியாமல் ஏற்படும் மனச்சோர்வை வெளிப்படுத்துகிறது. இந்த புத்தகம் கிறிஸ்தவர்களுக்கு ஒரு நபரின் கண்களால் உலகைப் பார்க்க ஒரு வாய்ப்பை அளிக்கிறது, அவர் மிகவும் புத்திசாலி என்றாலும், தற்காலிக, மனித விஷயங்களில் அர்த்தத்தைக் கண்டுபிடிக்க முயற்சிக்கிறார். உலக இன்பத்தின் ஒவ்வொரு வடிவமும் பிரசங்கியால் ஆராயப்படுகிறது, அது எதுவுமே அவருக்கு ஒரு அர்த்தத்தை அளிக்காது.</p><p>இறுதியில், தனிப்பட்ட அர்த்தத்தைக் கண்டுபிடிப்பதற்கான ஒரே வழி தேவனை நம்பி அவரில் நம்பிக்கை வைப்பதுதான் என்பதை பிரசங்கி ஏற்றுக்கொள்கிறார். தேவன் இல்லாமல் வாழ்க்கை சுருக்கமாகவும் இறுதியில் பயனற்றதாகவும் இருக்கிறது என்கிற உண்மையை அவர் ஏற்றுக்கொள்ள முடிவு செய்கிறார். தற்காலிக இன்பத்திற்கு பதிலாக நித்திய தேவன்மீது கவனம் செலுத்தும்படி பிரசங்கி வாசகருக்கு அறிவுறுத்துகிறார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>பிரசங்கி 1:2, \"மாயை, மாயை, எல்லாம் மாயை என்று பிரசங்கி சொல்லுகிறான்.\"</p><p>பிரசங்கி 1:18, \"அதிக ஞானத்திலே அதிக சலிப்புணடு; அறிவுபெருத்தவன் நோவுபெருத்தவன்.\"</p><p>பிரசங்கி 2:11, \"என் கைகள் செய்த சகல வேலைகளையும், நான் பட்ட எல்லாப் பிரயாசத்தையும் கண்ணோக்கிப் பார்த்தேன்; இதோ, எல்லாம் மாயையும், மனதுக்குச் சஞ்சலமுமாயிருந்தது; சூரியனுக்குக் கீழே பலன் ஒன்றுமில்லை.\"</p><p>பிரசங்கி 12:1, \"என் கைகள் செய்த சகல வேலைகளையும், நான் பட்ட எல்லாப் பிரயாசத்தையும் கண்ணோக்கிப் பார்த்தேன்; இதோ, எல்லாம் மாயையும், மனதுக்குச் சஞ்சலமுமாயிருந்தது; சூரியனுக்குக் கீழே பலன் ஒன்றுமில்லை.\"</p><p>பிரசங்கி 12:13, \"காரியத்தின் கடைத்தொகையை கேட்போமாக, தேவனுக்குப் பயந்து, அவர் கற்பனைகளைக் கைக்கொள்; எல்லா மனுஷர்மேலும் விழுந்த கடமை இதுவே.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>பிரசங்கி புத்தகத்தின் மொழியில் இரண்டு சொற்றொடர்கள் அடிக்கடி சொல்லப்படுகின்றன. கே.ஜே.வி-யில் \"மாயை\" என்றும், என்.ஐ.வி-யில் \"அர்த்தமற்றது\" என்றும் மொழிபெயர்க்கப்பட்ட சொல் அடிக்கடி தோன்றுகிறது, மேலும் உலக விஷயங்களின் தற்காலிக தன்மையை வலியுறுத்த இது பயன்படுத்தப்படுகிறது. இறுதியில், மிகவும் ஈர்க்கக்கூடிய மனித சாதனைகள் கூட பின்னால் விடப்படும். \"சூரியனுக்குக் கீழே\" என்ற சொற்றொடர் 28 முறை நிகழ்கிறது, மேலும் இது மரண உலகத்தைக் குறிக்கிறது. பிரசங்கி \"சூரியனுக்குக் கீழே உள்ள அனைத்தையும்\" குறிப்பிடும்போது, அவர் பூமிக்குரிய, தற்காலிக, மனித விஷயங்களைப் பற்றி பேசுகிறார்.</p><p>பிரசங்கி புத்தகத்தின் முதல் ஏழு அதிகாரங்களில் பிரசங்கி பூர்த்திசெய்ய முயற்சிக்கும் \"சூரியனுக்கு அடியில்\" இருக்கும் உலக விஷயங்கள் அனைத்தையும் விவரிக்கிறது. அவர் அறிவியல் கண்டுபிடிப்பு (1:10-11), ஞானம் மற்றும் தத்துவம் (1:13-18) ), மகிழ்ச்சி (2:1), ஆல்கஹால் (2:3), கட்டிடக்கலை (2:4), சொத்து (2:7-8), மற்றும் ஆடம்பரம் (2:8). பொருள்முதல்வாதம் (2:19-20), மற்றும் தார்மீக குறியீடுகள் (8-9 அத்தியாயங்கள் உட்பட) போன்ற பொருளைக் கண்டறிய பிரசங்கி வெவ்வேறு தத்துவங்களை நோக்கி தனது மனதைத் திருப்பினார். எல்லாவற்றையும் அர்த்தமற்றது என்று அவர் கண்டறிந்தார், கடவுள் இல்லாமல், எந்த நோக்கமும் நீண்ட ஆயுளும் இல்லாத ஒரு தற்காலிக திசைதிருப்பல் ஆகும்.</p><p>பிரசங்கி 8-12 அத்தியாயங்கள் ஒரு வாழ்க்கை எவ்வாறு வாழ வேண்டும் என்பதற்கான பிரசங்கியின் பரிந்துரைகளையும் கருத்துகளையும் விவரிக்கிறது. தேவன் இல்லாமல், வாழ்க்கையில் எந்த உண்மையும் அர்த்தமும் இல்லை என்ற முடிவுக்கு அவர் வருகிறார். அவர் பல தீமைகளைக் கண்டார், மேலும் மனிதனின் மிகச் சிறந்த சாதனைகள் கூட நீண்ட காலத்திற்கு ஒன்றும் பயனில்லை என்பதை உணர்ந்தார். ஆகவே, தேவனை இளமையிலிருந்து அதாவது வாலிப வயதில் ஒப்புக்கொள்ளவும் (12:1) அவருடைய சித்தத்தைப் பின்பற்றவும் அவர் வாசகருக்கு அறிவுறுத்துகிறார் (12:13-14).</p><p><b>முன்னிழல்கள்:</b></p><p>பிரசங்கி புத்தகத்தில் விவரிக்கப்பட்டுள்ள அனைத்து மாயைகளுக்கும், பதில் கிறிஸ்துவே. பிரசங்கி 3:17-ன் படி, தேவன் நீதிமான்களையும் துன்மார்க்கரையும் நியாயந்தீர்க்கிறார், நீதிமான்கள் கிறிஸ்துவில் இருப்பவர்கள் மட்டுமே (2 கொரிந்தியர் 5:21). தேவன் நித்தியத்திற்கான விருப்பத்தை நம் இருதயங்களில் வைத்திருக்கிறார் (பிரசங்கி 3:11) கிறிஸ்துவின் மூலம் நித்திய ஜீவனுக்கான வழியை வழங்கியுள்ளார் (யோவான் 3:16). உலகின் செல்வத்திற்குப் பின்னால் பாடுபடுவது வீண் மட்டுமல்ல, ஏனெனில் அது திருப்தியும் அளிக்காது (பிரசங்கி 5:10), ஆனால் நாம் அதை அடைய முடிந்தாலும், கிறிஸ்து இல்லாமல் நாம் நம் ஆத்துமாக்களை இழப்போம், அதில் நமக்கு என்ன லாபம் இருக்கிறது? (மாற்கு 8:36). இறுதியில், பிரசங்கி புத்தகத்தில் விவரிக்கப்பட்டுள்ள ஒவ்வொரு ஏமாற்றமும், மாயையும் கிறிஸ்துவில் அதன் தீர்வையும், தேவனுடைய ஞானத்தையும், வாழ்க்கையில் காணக்கூடிய ஒரே உண்மையான அர்த்தத்தையும் கொண்டுள்ளது.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>தேவனை அறியாதவர்கள் புரிந்துகொள்ளும் வெறுமையையும் விரக்தியையும் புரிந்து கொள்ள கிறிஸ்தவருக்கு பிரசங்கி புத்தகம் ஒரு நல்ல வாய்ப்பை வழங்குகிறது. கிறிஸ்துவில் இரட்சிப்பு நம்பிக்கை இல்லாதவர்கள் ஒரு வாழ்க்கையை எதிர்கொள்கிறார்கள், அது இறுதியில் முடிவடையும் மற்றும் பொருத்தமற்றதாகிவிடும். இரட்சிப்பு இல்லை, தேவன் இல்லை என்றால், வாழ்க்கைக்கு எந்த அர்த்தமும் இல்லை, ஆனால் அதற்கான நோக்கமோ திசையோ இல்லை. தேவனைத் தவிர \"சூரியனுக்குக் கீழான\" உலகம் வெறுப்பாகவும், கொடூரமாகவும், நியாயமற்றதாகவும், சுருக்கமாகவும், \"முற்றிலும் அர்த்தமற்றதாகவும்\" இருக்கிறது. ஆனால் கிறிஸ்துவுடன் உள்ள வாழ்க்கை என்பது ஒரு பரலோகத்தில் வரவிருக்கும் மகிமைகளின் நிழல் மட்டுமே.</p><p>சுமார் கி.மு 1001 (1050) - சவுல் அரசராதல்</p><p>சுமார் கி.மு 962 (1010) - தாவீது எபிரோனில் அரசராதல்</p><p>சுமார் கி.மு 921 (970) - சாலொமோன் அரசராதல்</p><p>சுமார் கி.மு 917 (966) - தேவாலயப்பணி தொடக்கம்</p><p>சுமார் கி.மு 910 (959) - தேவாலயப் பணி நிறைவு</p><p>சுமார் கி.மு 921-880 (970-931) - பிரசங்கி நூலை எழுதுதல்</p><p>சுமார் கி.மு 880 (931) - ரெகொபெயாம் அரசராதல் தேசம் பிளவுறுதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - எரேமியா (கர்த்தரை உயர்த்துங்கள் / கர்த்தர் துரத்துவார்)</p><p>தந்தை பெயர் - இல்க்கியா ஆசாரியர்</p><p>ஊர் - ஆனதோத், பென்யமீன் எல்லையிலிருந்த லேவியரின் பட்டணம்</p><p>தொழில் - தீர்க்கதரிசி</p><p>படைப்புகள் - பல நூற்களின் ஆசிரியர். இராஜாக்கள் நூற்கள், எரேமியா, புலம்பல்</p><p>சிறப்புப் பெயர்கள் - புலம்பலின் தீர்க்கதரிசி, தனிமையின் தீர்க்கதரிசி, ஓர் உடைந்த உள்ளம், கடின வார்த்தை கூறிய மென்மையான இதயத் துக்குரியவர், அழுது அழுது அழிவைக் கூறியவர்</p><p>சாதனை - பலமுறை சிறையிருப்பிலும், விமர்சனங்க ளிலும், மிரட்டல்களில் அகப்பட்ட போதும் சத்தியத்துக்காக துணிந்து நின்றவர்.</p><p>தீர்க்கதரிசன - பல தீர்க்கதரிசன நிறைவேறுதல்களை</p><p>கண்ணாரக் கண்டவர்.</p><p>ஆண்டுகள் - சுமார் 52 (சுமார் 626 - 574)</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 21-வது நூல்</p><p>அதிகாரங்கள் - 12</p><p>வசனங்கள் 222</p><p>கேள்விகள் - 33</p><p>கட்டளைகள் - 34</p><p>வாக்குத்தத்தம் - 1</p>'),
 (260,'<p><b>உன்னதபாட்டு</b></p><p><b>எழுத்தாளர்:</b></p><p>உன்னதபாட்டுப் புத்தகத்தின் முதல் வசனத்தின்படி சாலமோன் இந்த புத்தகத்தை எழுதினார் என்பது தெளிவாகிறது. சாலமோன் எழுதிய 1,005 பாடல்களில் இந்த பாடல் ஒன்றாகும் (1 இராஜாக்கள் 4:32). \"உன்னதபாட்டு\" என்கிற தலைப்பு ஒரு நிகரில்லாத மிகையானது என்பதாகும், அதாவது இது மிகச் சிறந்தது என்பதைக் குறிக்கிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>இந்த புத்தகம் பெரும்பாலும் சாலமோன் தனது ராஜ்யபாரத்தின் ஆரம்பத்தில் எழுதியிருக்கலாம். அது கி.மு. 965 காலஅளவை குறிக்கிறதாக இருக்கிறது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>சாலமோனின் உன்னதபாட்டு என்பது ஒரு கணவனுக்கும் மனைவிக்கும் இடையிலான அன்பின் நற்பண்புகளை புகழ்வதற்காக எழுதப்பட்ட ஒரு பாடல் கவிதையாகும். இந்த கவிதையானது திருமணத்தை தேவனின் வடிவமைப்பாக தெளிவாக முன்வைக்கிறது. ஒரு ஆணும் பெண்ணும் திருமண சூழலில் ஒன்றாக வாழ வேண்டும், ஒருவருக்கொருவர் ஆவிக்குரிய ரீதியாகவும், உணர்ச்சி ரீதியாகவும், உடல் ரீதியாகவும் நேசிக்க வேண்டும் என்பதை வலியுறுத்துகிறது.</p><p>இந்த புத்தகம் இரண்டு உச்சங்களை எதிர்த்து நிற்கிறது: ஒன்று துறவறம்/சன்யாசம் (அனைத்து இன்பத்தையும் மறுப்பது) மற்றொன்று ஹெடோனிசம் (இன்பத்தை மட்டுமே பின்தொடர்வது). சாலமோனின் உன்னதபாட்டில் விவரிக்கப்பட்டுள்ள திருமணம் கவனிப்பு, அர்ப்பணிப்பு மற்றும் மகிழ்ச்சியின் ஒரு மாதிரியாகும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>உன்னதபாட்டு 2:7; 3:5; 8:4 – \"எருசலேமின் குமாரத்திகளே! எனக்குப் பிரியமானவளுக்கு மனதாகுமட்டும், நீங்கள் அவளை விழிக்கப்பண்ணாமலும் எழுப்பாமலுமிருக்கும்படி வெளிமான்கள்மேலும் வெளியின் மரைகள்மேலும் உங்களை ஆணையிடுகிறேன்.\"</p><p>உன்னதபாட்டு 5:1 - \"சிநேகிதரே! புசியுங்கள்; பிரியமானவர்களே! குடியுங்கள், பூர்த்தியாய்க் குடியுங்கள்.\"</p><p>உன்னதபாட்டு 8:6-7 – \"நீர் என்னை உமது இருதயத்தின்மேல் முத்திரையைப்போலவும், உமது புயத்தின்மேல் முத்திரையைப்போலவும் வைத்துக்கொள்ளும்; நேசம் மரணத்தைப்போல் வலிது; நேசவைராக்கியம் பாதாளத்தைப்போல் கொடிதாயிருக்கிறது; அதின் தழல் அக்கினித்தழலும் அதின் ஜுவாலை கடும் ஜுவாலையுமாயிருக்கிறது. திரளான தண்ணீர்கள் நேசத்தை அவிக்கமாட்டாது, வெள்ளங்களும் அதைத் தணிக்கமாட்டாது; ஒருவன் தன் வீட்டிலுள்ள ஆஸ்திகளையெல்லாம் நேசத்துக்காகக் கொடுத்தாலும், அது முற்றிலும் அசட்டைபண்ணப்படும்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>இந்த கவிதை ஒரு கணவனுக்கும் (ராஜா) அவனது மனைவிக்கும் (சூலமித்தியாள்) இடையிலான உரையாடலின் வடிவத்தை கொடுக்கிறது. நாம் இந்த புத்தகத்தை மூன்று பிரிவுகளாகப் பிரிக்கலாம்: திருமணம் நாடி காதலாடுதல் (1:1-3:5); திருமணம் (3:6 - 5:1); மற்றும் திருமணத்தில் முதிர்ச்சியடைதல் (5:2 - 8:14).</p><p>திருமணத்திற்கு முன்பே இந்த பாடல் தொடங்குகிறது, மணமகள் தன்னுடன் திருமணம் செய்து கொள்ள விரும்புவதால், அவள் அவனுடைய நெருங்கிய உறவுகளை எதிர்நோக்குகிறாள். இருப்பினும், அன்பை இயற்கையாகவே, அதன் சொந்த நேரத்தில் வளர விடுமாறு அவள் அறிவுறுத்துகிறாள். ராஜா சூலமத்தியின் அழகைப் புகழ்ந்து, அவளுடைய தோற்றத்தைப் பற்றிய பாதுகாப்பின்மை உணர்வுகளை முறியடித்து விடுகிறான். சூலமித்திக்கு ஒரு கனவு இருக்கிறது, அதில் அவள் சாலமோனை இழந்து அவனை நகரமெங்கும் தேடுகிறாள். நகர காவலாளிகளின் உதவியுடன், அவள் தன் பிரியமானவரைக் கண்டுபிடித்து அவரிடம் ஒட்டிக்கொண்டு, அவரை ஒரு பாதுகாப்பான இடத்திற்கு அழைத்துச் செல்கிறாள். விழித்தவுடன், அன்பை கட்டாயப்படுத்த வேண்டாம் என்று தனது உத்தரவை மீண்டும் சொல்கிறாள்.</p><p>திருமண இரவில், கணவர் தனது மனைவியின் அழகை மீண்டும் புகழ்ந்து பேசுகிறார், மேலும் மிகவும் குறியீட்டு மொழியில் உருவகமாக, மனைவியானவள் தனது துணையாளரை அவள் வழங்கும் அனைத்திலும் பங்கேற்க அழைக்கிறாள். அவர்கள் அன்பை ஒருவருக்கொருவர் பரிமாறிக்கொள்ளுகிறார்கள், தேவன் அவர்களின் சங்கமத்தை ஆசீர்வதிக்கிறார்.</p><p>திருமணம் முதிர்ச்சியடையும் போது, கணவனும் மனைவியும் ஒரு கடினமான நேரத்தை கடந்து செல்கிறார்கள், இது மற்றொரு கனவில் உருவகமாக குறிக்கப்படுகிறது. இந்த இரண்டாவது கனவில், சூலமத்தியாள் தனது கணவனை மறுக்கிறார், அவர் வெளியேறுகிறார். குற்ற உணர்ச்சியைக் கடந்து, அவள் அவனைத் தேடுகிறாள்; ஆனால் இந்த நேரத்தில், அவளுக்கு உதவி செய்வதற்குப் பதிலாக, காவலாளிகள் அவளை அடிக்கிறார்கள் – அவள் கொண்டிருக்கிற வேதனையடைந்த மனசாட்சியின் அடையாளமாக இது இருக்கிறது. காதலர்கள் மீண்டும் ஒப்புரவாகி ஒன்றிணைந்து சமரசம் செய்யப்படுவதால் விஷயங்கள் மகிழ்ச்சியுடன் முடிவடைகின்றன.</p><p>பாடல் முடிவடையும் போது, கணவன்-மனைவி இருவரும் தங்கள் அன்பில் நம்பிக்கையுடனும் பாதுகாப்பாகவும் இருக்கிறார்கள், அவர்கள் உண்மையான அன்பின் நீடித்த தன்மையைக் குறித்துப் பாடுகிறார்கள், மேலும் அவர்கள் இருவரும் ஒருவருக்கொருவர் முன்னிலையில் இருக்க விரும்புகிறார்கள்.</p><p><b>முன்னிழல்கள்:</b></p><p>சில வேதாகம வியாக்கியான வல்லுனர்கள் சாலமோனின் உன்னதபாட்டை கிறிஸ்துவின் மற்றும் அவருடைய திருச்சபையின் சரியான அடையாளமாக இருப்பதாக பிரதிநிதித்துவத்தைக் காண்கிறார்கள். இதில் கிறிஸ்து ராஜாவாகக் காணப்படுகிறார், அதே சமயம் திருச்சபையானது சூலமித்தியாளைக் குறிக்கப்படுகிறது. திருமணத்தை சித்தரிப்பதாக இந்த புத்தகம் உண்மையில் புரிந்து கொள்ளப்பட வேண்டும் என்று நாங்கள் நம்புகிற அதேவேளையில், திருச்சபையையும் அவளுடைய ராஜாவாகிய கர்த்தராகிய இயேசுவுடனான உறவையும் முன்னறிவிக்கும் சில கூறுகள் இதில் அடங்கியுள்ளன. கர்த்தராகிய இயேசுவால் தேடப்பட்டு வாங்கப்பட்ட ஒவ்வொரு விசுவாசியின் அனுபவத்தையும் சாலமன் 2:4லுள்ள பாடல் வரிகள் விவரிக்கிறது. நாம் ஒரு பெரிய ஆவிக்குரிய செல்வத்தின் திரட்சியுள்ள இடத்தில் இருக்கிறோம், அவருடைய அன்பினால் மூடப்பட்டிருக்கிறோம். 2 ஆம் அதிகாரத்தின் 16-வது வசனம் இவ்வாறு கூறுகிறது: \"என் நேசர் என்னுடையவர், நான் அவருடையவள். அவர் லீலி புஷ்பங்களுக்குள்ளே மேய்கிறார்\". இங்கே கிறிஸ்துவினுடைய விசுவாசியின் பாதுகாப்பு மட்டுமல்ல (யோவான் 10:28-29), ஆனால் நல்ல மேய்ப்பன் தனது ஆடுகளை-விசுவாசிகளை அறிந்திருக்கிறார், நமக்காக அவருடைய உயிரையே கொடுக்கிறார் (யோவான் 10:11). அவர் மூலமாக, நாம் இனி பாவத்தால் கறைபடாமல், நம்முடைய \"கறைகள்\" அவருடைய இரத்தத்தால் அகற்றப்பட்டுவிட்டோம் (உன்னதபாட்டு 4:7; எபேசியர் 5:27).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நமது உலகம் திருமணத்தைப் பற்றிய காரியங்களில் குழப்பமடைகிறது. விவாகரத்தின் பரவலான செயல்பாடுகள் மற்றும் திருமணத்தை மறுவரையறை செய்வதற்கான நவீன முயற்சிகள், சாலமோனின் உன்னதபாட்டுக்கு முற்றிலும் மாறுபட்டவையாகும். திருமணம், கொண்டாடப்பட வேண்டும், அனுபவிக்கப்பட வேண்டும், மதிக்கப்பட வேண்டும் என்று வேதாகம கவிஞர் கூறுகிறார். நம்முடைய திருமணங்களை வலுப்படுத்த இந்த புத்தகம் சில நடைமுறை வழிகாட்டுதல்களை வழங்குகிறது:</p><p>1) உங்கள் வாழ்க்கைத்துணைக்குத் தேவையான கவனத்தை அவருக்குக் கொடுங்கள். உங்கள் மனைவியை உண்மையாக அறிந்துகொள்ள நேரம் ஒதுக்குங்கள்.</p><p>2) வெற்றிகரமான உறவுக்கு விமர்சனமல்ல ஊக்கமும் புகழும் இன்றியமையாததாக இருக்கிறது.</p><p>3) ஒருவருக்கொருவர் மகிழுங்கள். சில பயணங்களைத் திட்டமிடுங்கள். ஒருவருக்கொருவர் சுறுசுறுப்புடன், விளையாட்டுத்தனமாக இருங்கள். தேவன் நியமித்த ஈவாகிய திருமண அன்பில் மகிழ்ச்சியாயிருங்கள்.</p><p>4) உங்கள் வாழ்க்கைத்துணைக்கு உங்கள் உறுதிப்பாட்டை உறுதிப்படுத்த தேவையானதைச் செய்யுங்கள். உங்கள் சபதங்களை புதுப்பிக்கவும்; பிரச்சினைகள் மூலம் வேலை மற்றும் விவாகரத்து ஒரு தீர்வாக கருத வேண்டாம். நீங்கள் இருவரும் ஆழ்ந்த அமைதியான, பாதுகாப்பான அன்பில் வாழ தேவன் விரும்புகிறார்.</p><p>சுமார் கி.மு. 1001 (1050) - சவுல் அரசராதல்</p><p>சுமார் கி.மு. 962 (1010) - தாவீது எபிரோனில் அரசராதல்</p><p>சுமார் கி.மு. 921 (970) - சாலொமோன் அரசராதல்</p><p>சுமார் கி.மு. 923-880(972-931) - உன்னதப்பாட்டு நூல் எழுதப்பட்ட காலம்</p><p>சுமார் கி.மு.880  (931) - ரெகொபெயாம் அரசரால் தேசம்</p><p>பிளவுறுதல்</p><p>சுமார் கி.மு. 670 (721) - இஸ்ரவேல் (வடக்கு அரசு) அடிமையாகச் செல்லுதல்</p><p>சுமார் கி.மு.535 (586) - எருசலேம் வீழ்ச்சி</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - சாலொமோன்</p><p>பார்க்க - 1இராஜாக்கள் நூல்</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 22-வது நூல்</p><p>அதிகாரங்கள் - 8</p><p>வசனங்கள் - 17</p><p>கேள்விகள் - 3</p><p>கட்டளைகள் - 14</p>'),
 (290,'<p><b>ஏசாயாவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>ஏசாயா 1:1, ஏசாயா புத்தகத்தின் எழுத்தாளரை ஏசாயா தீர்க்கதரிசி என்று அடையாளப்படுத்துகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>ஏசாயா புத்தகம் கி.மு. 739 முதல் கி.மு. 681 வரையிலுள்ள காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>ஏசாயா தீர்க்கதரிசி முதன்மையாக யூதா ராஜ்யத்திற்கு தீர்க்கதரிசனம் சொல்ல அழைக்கப்பட்டார். யூதா மறுமலர்ச்சி மற்றும் கிளர்ச்சி காலங்களை கடந்து கொண்டிருந்தது. அசீரியா மற்றும் எகிப்தால் யூதா அழிக்கப்படும் என்று அச்சுறுத்தப்பட்டார்கள், ஆனால் தேவனுடைய இரக்கத்தால் காப்பாற்றப்பட்டார்கள். ஏசாயா பாவத்திலிருந்து மனந்திரும்புதலின் செய்தியையும், எதிர்காலத்தில் தேவனுடைய விடுதலையின் நம்பிக்கையான எதிர்பார்ப்பையும் அறிவித்தார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>ஏசாயா 6:8, \"பின்பு யாரை நான் அனுப்புவேன், யார் நமது காரியமாய்ப் போவான் என்று உரைக்கிற ஆண்டவருடைய சத்தத்தைக் கேட்டேன். அதற்கு நான்: இதோ, அடியேன் இருக்கிறேன்; என்னை அனுப்பும் என்றேன்.\"</p><p>ஏசாயா 7:14, \"ஆதலால் ஆண்டவர் தாமே உங்களுக்கு ஒரு அடையாளத்தைக் கொடுப்பார்; இதோ, ஒரு கன்னிகை கர்ப்பவதியாகி ஒரு குமாரனைப் பெறுவாள், அவருக்கு இம்மானுவேல் என்று பேரிடுவாள்.\"</p><p>ஏசாயா 9:6, \"நமக்கு ஒரு பாலகன் பிறந்தார்; நமக்கு ஒரு குமாரன் கொடுக்கப்பட்டார்; கர்த்தத்துவம் அவர் தோளின்மேலிருக்கும்; அவர் நாமம் அதிசயமானவர், ஆலோசனைக் கர்த்தா, வல்லமையுள்ள தேவன், நித்திய பிதா, சமாதானப்பிரபு என்னப்படும்.\"</p><p>ஏசாயா 14:12-13, \"அதிகாலையின் மகனாகிய விடிவெள்ளியே, நீ வானத்திலிருந்து விழுந்தாயே! ஜாதிகளை ஈனப்படுத்தினவனே, நீ தரையிலே விழ வெட்டப்பட்டாயே! நான் வானத்துக்கு ஏறுவேன், தேவனுடைய நட்சத்திரங்களுக்குமேலாக என் சிங்காசனத்தை உயர்த்துவேன்; வடபுறங்களிலுள்ள ஆராதனைக் கூட்டத்தின் பர்வதத்திலே வீற்றிருப்பேன் என்றும்,\"</p><p>ஏசாயா 53:5-6, \"நம்முடைய மீறுதல்களினிமித்தம் அவர் காயப்பட்டு, நம்முடைய அக்கிரமங்களினிமித்தம் அவர் நொறுக்கப்பட்டார்; நமக்குச் சமாதானத்தை உண்டுபண்ணும் ஆக்கினை அவர்மேல் வந்தது; அவருடைய தழும்புகளால் குணமாகிறோம். நாமெல்லாரும் ஆடுகளைப்போல வழிதப்பித்திரிந்து, அவனவன் தன்தன் வழியிலே போனோம்; கர்த்தரோ நம்மெல்லாருடைய அக்கிரமத்தையும் அவர்மேல் விழப்பண்ணினார்.\"</p><p>ஏசாயா 65:25, \"ஓநாயும் ஆட்டுக்குட்டியும் ஒருமித்து மேயும்; சிங்கம் மாட்டைப்போல வைக்கோலைத் தின்னும்; புழுதி சர்ப்பத்துக்கு இரையாகும்; என் பரிசுத்த பர்வதமெங்கும் அவைகள் தீங்குசெய்வதுமில்லை, கேடுண்டாக்குவதுமில்லையென்று கர்த்தர் சொல்லுகிறார்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>ஏசாயா புத்தகம் தேவனுடைய நியாயத்தீர்ப்பையும் இரட்சிப்பையும் வெளிப்படுத்துகிறது. தேவன் \"பரிசுத்தர், பரிசுத்தர், பரிசுத்தர்\" (ஏசாயா 6:3), ஆகவே பாவம் தண்டிக்கப்படாமல் இருக்க அவர் அனுமதிக்க முடியாது (ஏசாயா 1:2; 2:11-20; 5:30; 34:1-2; 42:25) ). தேவனுடைய வரவிருக்கும் நியாயத்தீர்ப்பை \"பட்சிக்கிற அக்கினி\" என்று ஏசாயா சித்தரிக்கிறார் (ஏசாயா 1:31; 30:33).</p><p>அதே சமயம், தேவன் இரக்கம், கிருபை மற்றும் மனதுருகும் இரக்கத்தின் தேவனாக இருக்கிறார் என்பதை ஏசாயா புரிந்துகொள்கிறார் (ஏசாயா 5:25; 11:16; 14:1-2; 32:2; 40:3; 41:14-16). இஸ்ரவேல் தேசம் (யூதா மற்றும் இஸ்ரேல் இரண்டும்) தேவனுடைய கட்டளைகளுக்கு குருடாகவும் செவிடாகவும் இருக்கிறது (ஏசாயா 6:9-10; 42:7). யூதா தேசம் ஒரு திராட்சைத் தோட்டத்துடன் ஒப்பிடப்படுகிறது, அது மிதிக்கப்படும் (ஏசாயா 5:1-7). அவருடைய இரக்கம் மற்றும் இஸ்ரேலுக்கு அவர் அளித்த வாக்குறுதிகள் காரணமாக மட்டுமே, இஸ்ரேலையும் யூதாவையும் முற்றிலுமாக அழிக்க தேவன் அனுமதிக்க மாட்டார். அவர் மறுசீரமைப்பு செய்து, மன்னிப்பளித்து மற்றும் அவர்களை குணப்படுத்துவார் (43:2; 43:16-19; 52:10-12).</p><p>பழைய ஏற்பாட்டில் உள்ள வேறு எந்த ஒரு புத்தகத்தையும் விட, ஏசாயா புத்தகம் மேசியா மூலம் வரும் இரட்சிப்பில் கூடுதல் கவனம் செலுத்துகிறது. மேசியா ஒரு நாள் நீதியிலும் நியாயத்திலும் ஆட்சி செய்வார் (ஏசாயா 9:7; 32:1). மேசியாவின் ஆட்சி இஸ்ரேலுக்கு சமாதானத்தையும் பாதுகாப்பையும் தரும் (ஏசாயா 11:6-9). மேசியாவின் மூலம், இஸ்ரேல் எல்லா தேசங்களுக்கும் ஒரு வெளிச்சமாக இருக்கும் (ஏசாயா 42:6; 55:4-5). பூமியில்மேல் மேசியாவின் ராஜ்யம் (ஏசாயா 65-66 அதிகாரங்கள்) ஏசாயா புத்தகம் முழுவதும் சுட்டிக்காட்டப்படுகிற குறிக்கோளாக இருக்கிறது. மேசியாவின் ஆட்சியின் போதுதான் தேவனுடைய நீதியானது உலகிற்கு முழுமையாக வெளிப்படும்.</p><p>ஒரு முரண்பாடாக, ஏசாயா புத்தகம் மேசியாவை துன்பப்படுபவராக முன்வைக்கிறது. மேசியா பாவத்திற்காக துன்பப்படுவதை ஏசாயா 53 அதிகாரம் மிகதெளிவாக விவரிக்கிறது. அவருடைய காயங்களின் மூலம்தான் குணமடைதல் பெறப்படுகிறது. அவருடைய பாடுகளின் மூலம்தான் நம்முடைய அக்கிரமங்கள் நீக்கப்படுகின்றன. இந்த வெளிப்படையான முரண்பாடு இயேசு கிறிஸ்துவின் நபரில் முழுமையாகத் தீர்க்கப்படுகிறது. இயேசு தனது முதல் வருகையில், ஏசாயா 53 ஆம் அதிகாரத்தில் குறிப்பிடப்பட்டுள்ளபடி பாடுகளை அனுபவிக்கிற ஊழியராக இருந்தார். அவருடைய இரண்டாவது வருகையில், இயேசு சமாதான பிரபுவாக வென்று வெற்றிவாகை சூடி ஆளும் ராஜாதி ராஜாவாக இருப்பார் (ஏசாயா 9:6).</p><p><b>முன்னிழல்கள்:</b></p><p>மேலே குறிப்பிட்டுள்ளபடி, ஏசாயாவின் 53-ஆம் அதிகாரம் வரவிருக்கும் மேசியாவையும், நம்முடைய பாவங்களை சுமந்து தீர்ப்பதற்காக அவர் தாங்கிக் கொள்ளும் துன்பங்களையும் விவரிக்கிறது. தேவன் தனது இறையாண்மையில், இந்த அதிகாரத்தின் ஒவ்வொரு தீர்க்கதரிசனத்தையும், பழைய ஏற்பாட்டின் மற்ற அனைத்து மேசியாவின் தீர்க்கதரிசனங்களையும் நிறைவேற்ற சிலுவையில் அறையப்பட ஒவ்வொரு விவரத்தையும் திட்டமிட்டார். 53-ஆம் அத்தியாயத்தின் சித்திரங்கள் வருத்தம் அளிக்கிற மற்றும் நிறைவேறப்போகிற தீர்க்கதரிசனமானது நற்செய்தியின் முழுமையான சித்திரத்தைக் கொண்டுள்ளது. இயேசு வெறுக்கப்பட்டு நிராகரிக்கப்பட்டார் (வச. 3; லூக்கா 13:34; யோவான் 1:10-11), தேவனால் நொறுக்கப்பட்டார் (வச .4; மத்தேயு 27:46), நம்முடைய மீறுதல்களுக்காக காயப்பட்டார் (வச. 5; யோவான் 19:34; 1 பேதுரு 2:24). அவருடைய துன்பத்தினால், அவர் நமக்குத் தகுதியான தண்டனையைச் செலுத்தி, நம்முடைய பாவங்களுக்காக இறுதியான மற்றும் பரிபூரணமான பலியானார் (வச. 5; எபிரெயர் 10:10). அவர் பாவமற்றவராக இருந்தபோதிலும், தேவன் நம்முடைய பாவத்தை அவர்மீது வைத்தார், நாம் அவருக்குள் தேவனுடைய நீதியாக மாறினோம் (2 கொரிந்தியர் 5:21).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>ஏசாயா புத்தகம் நம்முடைய இரட்சகரை மறுக்கமுடியாத விவரங்களோடு மிகவும் விரிவாக நமக்கு முன்வைக்கிறது. அவர் மட்டும்தான் பரலோகத்திற்கு செல்லுவதற்கான ஒரே வழி, தேவனுடைய கிருபையைப் பெறுவதற்கான ஒரே வழியும் ஒரே சத்தியமும் ஒரே ஜீவனும் அவரே (யோவான் 14:6; அப்போஸ்தலர் 4:12). கிறிஸ்து நமக்குக் கொடுத்த விலையை அறிந்தால், \"இவ்வளவு பெரிதான இரட்சிப்பை\" நாம் எவ்வாறு புறக்கணிக்கவோ அல்லது நிராகரிக்கவோ முடியும்? (எபிரெயர் 2:3). கிறிஸ்துவிடம் வந்து அவர் அளிக்கும் இரட்சிப்பை மட்டுமே தழுவுவதற்கு பூமியில் சில, குறுகிய ஆண்டுகள் மட்டுமே உள்ளன. மரணத்திற்குப் பிறகு இரண்டாவது வாய்ப்பு இல்லை, நரகத்தில் நித்தியகாலமாக தண்டனை.</p><p>கிறிஸ்துவை விசுவாசிப்பதாகக் கூறும் நபர்கள் இரு முகம் கொண்டவர்கள், நயவஞ்சகர்கள் என்று உங்களுக்குத் தெரியுமா? ஏசாயா இஸ்ரவேல் தேசத்தை எப்படிப் பார்த்தார் என்பதற்கான சிறந்த சுருக்கம் அதுவாக இருக்கலாம். இஸ்ரவேல் நீதியின் தோற்றத்தைக் கொண்டிருந்தது, ஆனால் அது ஒரு ஒரு புறம்பான முகப்பாக மட்டுமே இருந்தது. ஏசாயா புத்தகத்தில், ஏசாயா தீர்க்கதரிசி இஸ்ரேலுக்கு வெளியில் மட்டுமல்ல, முழு இருதயத்தோடும் தேவனுக்குக் கீழ்ப்படியும்படி சவால் விடுக்கிறார். ஏசாயாவின் விருப்பம் என்னவென்றால், அவருடைய வார்த்தைகளைக் கேட்டு வாசிப்பவர்கள் துன்மார்க்கத்திலிருந்து விலகி, மன்னிப்பு மற்றும் குணப்படுத்துதலுக்காக திரும்பவேண்டும் என்பது மட்டுமேயாகும்.</p><p>சுமார் கி.மு.880 (931) - இஸ்ரவேல் பிளவுறுதல்</p><p>சுமார் கி.மு.713 (767) - அசரியா (உசியா) யூதாவின் அரசராதல்</p><p>சுமார் கி.மு.687 (740) - யோதாம் யூதாவின் அரசராதல்</p><p>சுமார் கி.மு. 681 (732) - ஆகாஸ் யூதாவின் அரசராதல்</p><p>சுமார் கி.மு.679 (730) - இஸ்ரவேல் - சீரியா கூட்டுப் படையெடுப்பு</p><p>சுமார் கி.மு. 677 (728) - தமஸ்கு அசீரியாவின் கையில் வீழ்தல்</p><p>சுமார் கி.மு. 665 (716) - எசேக்கியா யூதாவின் அரசராதல்</p><p>சுமார் கி.மு. 670 (721) - வடக்கு அரசு சிறையிருப்பு செல்லுதல்</p><p>சுமார் கி.மு, 636 (687) - மனாசே யூதாவின் அரசராதல்</p><p>சுமார் கி.மு. 535 (586) - யூதா பாபிலோனிய சிறையிருப்பு செல்லுதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - ஏசாயா (இரட்சிப்பு தேவனிடமிருந்து / கர்த்தரின் இரட்சிப்பு)</p><p>தகப்பனார் பெயர் - ஆமோத்ஸ் (1 : 1,2 : 1) அரச குலத்தைச் சார்ந்தவர்)</p><p>ஊர் - எருசலேம் (7 : 13)</p><p>மனைவி - தீர்க்கதரிசியானவள் (8 : 3)</p><p>பிள்ளைகள் - சேயார்யாகுபு (7 : 5) மகேர்சலால் அஸ் பாஷ் (7 : 3,14, 8 : 3)(இம்மானுவேல்)</p><p>தொழில் - அரசு அதிகாரி (7) பின்பு தீர்க்கதரிசி</p><p>முடிவு - பாரம்பரிய கூற்றுப்படி மனாசே அரசரின் காலத்தில் வாளால் அறுத்து கொலை (ஒப்பிடுக. எபி 11: 37)</p><p>பிறநூற்கள் - இவர் எழுதியதாக சிவரால் கருதப்படும் பிற நூல். உசியாவின் நடபடிகள் (1நாளா 26 : 22)</p><p>பட்டப்பெயர்கள் - மேசியா தீர்க்கதரிசி\", \"பழைய ஏற்பாட்டு சுவிசேஷகர்\", \"சுவிசேஷ தீர்க்கதரிசி\", \"தீர்க்கதரிசிகளின் பிரபு\"</p><p>சாதனை - அழகிய இலக்கிய நடையில் தீர்க்கதரிசன நூலைப் படைத்தது.</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 23-வது நூல்</p><p>அதிகாரங்கள் - 66</p><p>வசனங்கள் - 1292</p><p>நிறைவேறிய நீர்க்கதரிசனங்கள் - 395</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 634</p><p>எச்சரிக்கைகள் - 1,313</p><p>நிறைவேறிய எச்சரிக்கைகள் - 449</p><p>நிறைவேற வேண்டிய எச்சரிக்கைகள் - 864</p><p>வரலாற்றுத் தொடர்புடைய வசனங்கள் - 273</p><p>கேள்விகள் - 190</p><p>வாக்குத்தத்ங்கள் - 120</p><p>கட்டளைகள் - 308</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 71</p>'),
 (30,'<p><b>லேவியராகமம் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>லேவியராகமம் புத்தகத்தை எழுதியவர் மோசே.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>லேவியராகமம் புத்தகம் கி.மு. 1440 முதல் கி.மு. 1400 வரையிலுள்ள இடைப்பட்ட காலத்தில் எழுதப்பட்டது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>இஸ்ரவேலர்கள் 400 ஆண்டுகளாக எகிப்தில் சிறைப்படுத்தப்பட்ட அடிமைத்தனத்திற்குட்பட்டிருந்ததால், தேவனைப்பற்றிய கருத்து பலதெய்வ கோட்பாடு, மற்றும் அன்னியஜாதிகளால் / எகிப்தியர்களால் சிதைக்கப்பட்டது. லேவியராகமம் புத்தகத்தின் நோக்கம், ஒரு பாவமுள்ள, ஆனால் மீட்கப்பட்ட ஜனங்களை பரிசுத்த தேவனுடனான உறவில் வழிநடத்த அறிவுறுத்தலும் சட்டங்களும் வழங்குவதாகும். பரிசுத்த தேவனுக்குப் பதிலளிக்கும் விதமாக தனிப்பட்ட பரிசுத்தத்தின் தேவை குறித்து லேவியராகமத்தில் ஒரு முக்கியத்துவம் உள்ளது. சரியான பலிகளை வழங்குவதன் மூலம் பாவத்திற்கு பரிகாரம் செய்ய வேண்டும் (அத்தியாயங்கள் 8-10). உணவில் (சுத்தமான மற்றும் அசுத்தமான உணவுகள்), பிரசவம் மற்றும் கவனமாக கட்டுப்படுத்தப்படும் நோய்கள் (11-15 அதிகாரங்கள்) இந்த புத்தகத்தில் விவரிக்கப்பட்டுள்ளன. ஜனங்களின் ஒட்டுமொத்த பாவத்திற்காக வருடாந்திர பலி செய்யப்படும் பாவப்பரிகார நாளை 16-ஆம் அதிகாரம் விவரிக்கிறது. மேலும், தேவனுடைய ஜனங்கள் தங்களின் தனிப்பட்ட, தார்மீக மற்றும் சமூக வாழ்வில் கவனமாக இருக்க வேண்டும், அன்றைய புறஜாதிகளின் தற்போதைய நடைமுறைகளுக்கு மாறாக, அவர்களைச் சுற்றிலும் எல்லா வகையிலும் பாதுகாத்துக்கொள்ள வேண்டும் (17-22 அதிகாரங்கள்).</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>லேவியராகமம் 1:4, \"அது தன் பாவநிவிர்த்திக்கென்று அங்கிகரிக்கப்படும்படி தன் கையை அதின் தலையின்மேல் வைத்து.\"</p><p>லேவியராகமம் 17:11, \"மாம்சத்தின் உயிர் இரத்தத்தில் இருக்கிறது; நான் அதை உங்களுக்குப் பலிபீடத்தின்மேல் உங்கள் ஆத்துமாக்களுக்காகப் பாவநிவிர்த்தி செய்யும்படிக்குக் கட்டளையிட்டேன்; ஆத்துமாவிற்காகப் பாவநிவிர்த்தி செய்கிறது இரத்தமே.\"</p><p>லேவியராகமம் 19:18, \"பழிக்குப்பழி வாங்காமலும், உன் ஜனப்புத்திரர்மேல் பொறாமைகொள்ளாமலும், உன்னில் நீ அன்புகூருவதுபோல் பிறனிலும் அன்புகூருவாயாக; நான் கர்த்தர்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>1-7 வரையிலுள்ள அதிகாரங்கள் சாதாரண பாமர மக்களுக்கும் மற்றும் ஆசாரிய வர்க்கத்தும் தேவையான பலிகளைக் கோடிட்டுக் காட்டுகின்றன. 8-10 வரையிலுள்ள அதிகாரங்கள் ஆரோனையும் அவருடைய குமாரர்களையும் ஆசாரியத்துவத்திற்கு ஒப்புக்கொடுத்ததை விவரிக்கின்றன. 11-16 வரையிலுள்ள அதிகாரங்கள் பல்வேறு வகையான தீட்டான காரியங்களுக்கான நியமங்கள் பரிந்துரைக்கப்படுகின்றன. இறுதியிலுள்ள 10 அதிகாரங்கள் நடைமுறை பரிசுத்தத்திர்கான தேவனுடைய வழிகாட்டுதல்கள் அடங்கியுள்ளன. யெகோவா தேவனை ஆராதித்து வணங்குவதில் பல்வேறு பண்டிகைகள் மற்றும் அவைகளின் ஆசரிப்புகள் நிறுவப்பட்டன, தேவனுடைய கடவுளின் நியாயப்பிரமாண சட்டங்களின்படி அவைகள் நடைமுறையில் இருந்தன. ஆசீர்வாதங்கள் அல்லது சாபங்கள் தேவனுடைய கட்டளைகளைக் கடைப்பிடிப்பது அல்லது புறக்கணிப்பதை சார்ந்து இருந்தன (அதிகாரம் 26). கர்த்தருக்கான பொருத்தனைகள் அல்லது நேர்ச்சைகள் 27 ஆம் அதிகாரத்தில் விவரிக்கப்பட்டுள்ளது.</p><p>லேவியராகமத்தின் முதன்மையான உட்கருத்து பரிசுத்தம் ஆகும். தம்முடைய ஜனங்களில் பரிசுத்தத்திற்கான தேவனுடைய கோரிக்கை அவருடைய சொந்த பரிசுத்த தன்மையை அடிப்படையாகக் கொண்டது. பாவப்பரிகாரம் என்பது ஒரு தொடர்புடைய உட்கருத்தாகும். தேவனுக்கு முன்பாக நாம் பரிசுத்தத்தைப் பேண வேண்டும், சரியான பாவப்பரிகாரத்தின் மூலம் மட்டுமே அந்த பரிசுத்தத்தை அடைய முடியும்.</p><p><b>முன்னிழல்கள்:</b></p><p>வழிபாட்டின் சடங்கு நடைமுறைகள் பல வழிகளில் நம்முடைய இரட்சகராகிய கர்த்தராகிய இயேசு கிறிஸ்துவின் நபர் மற்றும் வேலையை மையமாகக்கொண்டு இருக்கின்றன. மோசேயின் நியாயப்பிரமாணம் \"வரப்போகிற நன்மைகளின் பொருளாயிராமல், அவைகளின் நிழலாய்மாத்திரம் இருக்கிறது\" என்று எபிரெயர் 10:1 நமக்குச் சொல்கிறது, இதன் பொருள் ஜனங்களின் பாவத்திற்காக ஆசாரியர்கள் அன்றாடம் செலுத்தும் பலிகள் இறுதியாக வரப்போகிற பலியின் நிழல் அல்லது பிரதிபலிப்பாகும் - இயேசு கிறிஸ்து, அவரை நம்புகிறவர்களுக்கு அவருடைய சிலுவைப்பலி எல்லா நேரத்திலும் போதுமானதாக இருக்கும். கிறிஸ்துவின் நீதிக்காக கிறிஸ்தவர்கள் தங்கள் பாவத்தை பரிமாறிக்கொண்டபோது, நியாயப்பிரமாணத்தால் தற்காலிகமாக வழங்கப்பட்ட பரிசுத்தம் ஒரு நாள் பரிசுத்தத்தின் முழுமையான நிலையில் அடையத்தக்கதாக மாற்றப்படும் (2 கொரிந்தியர் 5:21).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>தேவன் தம்முடைய பரிசுத்தத்தை மிகவும் தீவிரமாக எடுத்துக்கொள்கிறார், எனவே நாமும் அவ்வாறு செய்ய வேண்டும். பின்நவீனத்துவ திருச்சபையின் போக்கு என்னவென்றால், தேவனை நம்முடைய சாயலில் உருவாக்குவது, அவருடைய வார்த்தை விவரிக்கும் பொருள்களுக்குப் பதிலாக நாம் அவரிடம் இருக்க விரும்பும் பண்புகளை அவருக்குக் கொடுப்பது. தேவனுடைய முழுமையான பரிசுத்தத்தன்மை, அவருடைய அதிசயமான மகிமை, அவருடைய \"சேரக்கூடாத ஒளியில் வாசம்பண்ணும்\" (1 தீமோத்தேயு 6:16) பல கிறிஸ்தவர்களுக்கு அந்நியமான கருத்துக்களாக இருக்கின்றன. நாம் அவருடைய பார்வையில் பிரியமுள்ள நடப்பை அடைவதற்காக வெளிச்சத்தில் நடக்கவும், நம் வாழ்வில் இருளை விலக்கவும் அழைக்கப்படுகிறோம். பரிசுத்தமான தேவன் தம் மக்களில் அப்பட்டமான, வெட்கம்கெட்ட பாவத்தை சகித்துக்கொள்ள முடியாது, அவருடைய பரிசுத்தமானது அதைத் தண்டித்தே ஆகவேண்டும். பாவம் அல்லது தேவன் அதை வெறுத்து தண்டிப்பதைப் பற்றிய நமது அணுகுமுறைகளில் நாம் சுறுசுறுப்பாக இருக்கவேண்டும், அதை எந்த வகையிலும் வெளிச்சம் போடக்கூடாது.</p><p>நம் சார்பாக நமது இயேசுவின் சிலுவை மரணம் காரணமாக அமைந்ததால், நாம் இனி மிருகங்களை/விலங்குகளை பலியிட வேண்டியதில்லை என்பதற்காக கர்த்தரைத் துதியுங்கள். லேவியராகமம் என்பது மாற்றீடு பற்றியது. மிருகங்களின் மரணம் பாவம் செய்தவர்களுக்கு மாற்று தண்டனையாகும். அதே வழியில், ஆனால் எல்லையற்றது மற்றும் சிறந்தது, சிலுவையில் மரித்த இயேசுவின் பலி, அது நம் பாவங்களுக்கு மாற்றாக இருந்தது. தேவன் கிறிஸ்துவின் நீதியை அவர் நம்மில் காண்கிறார் என்பதால், இப்போது நாம் பயமின்றி முழுமையான பரிசுத்தமுள்ள தேவனுக்கு முன்பாக நிற்க முடியும்.</p><p>கி.மு. 1836 (2006) - யாக்கோபின் பிறப்பு</p><p>கி.மு. 1706 (1876) - இஸ்ரவேலர் எகிப்து சென்றது</p><p>கி.மு. 1689 (1859) - யாக்கோபின் மரணம்</p><p>கி.மு. 1635 (1805) - யோசேப்பின் மரணம்.</p><p>கி.மு. 1571 (1527) - மோசேயின் பிறப்பு</p><p>கி.மு. 1491 (1446)  - யாத்திராகம பயணத் தொடக்கம்</p><p>கி.மு.1490 (1445)  - ஆசாரிப்புக் கூடார் நிறுத்துதல்</p><p>கி.மு. 1490 (1445)  - முதல் கணக்கெடுப்பு</p><p>கி.மு. 1452 (1407) - மிரியாம், ஆரோன், மோசே ஆகியோர் மரணம்</p><p>கி.மு. 1451 (1406) - கானானில் கால் பதித்தல்</p><p><b>ஆசிரியர் குறிப்பு.</b></p><p>பெயர் - மோசே (பொருள்: இழுத்தெடுக்கப்பட்டவர்)</p><p>பெற்றோர் - தந்தை அம்ராம்,</p><p>தாய் - யோகெபேத் (யாத் 6 : 20). பின்பு பார்வோனின் மகளால் தத்தெடுக்கப்பட்டவர்</p><p>சொந்த இடம் - எகிப்து</p><p>தொழில் - அரண்மனை கல்வி, பின்பு ஆடு மேய்ப்பு அதன்பின் இலட்சக்கணக்கான மக்களை கானானுக்கு வழிநடத்தியது\"</p><p>திருப்புமுனை  - மந்தைமேய்த்துக் கொண்டிருக்கும்போது\" முட்செடியில் தேவனைத் தரிசித்தபின் வந்த அழைப்பு</p><p>ஆர்வம் - எபிரெயரை விடுவித்து, பத்திரமாக</p><p>கானானுக்கு வழிநடத்துவது</p><p>சாதனைகள்  - பார்வோனுக்கு முன் அற்புதங்களைச் செய்தது, ஐந்தாகமங்களை எழுதியது. உலகத்தோற்றம் பற்றிய</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் - 3 ஆம் நூல்</p><p>அதிகாரங்கள் - 27</p><p>வசனங்கள் - 859</p><p>கேள்விகள் - 3</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 58</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 6</p><p>வரலாற்று வசனங்கள் - 799</p><p>கட்டளைகள் - 795</p><p>வாக்குத்தத்தங்கள் - 26</p><p>எச்சரிக்கைகள் - 125</p><p>தேவளிடமிருந்து சிறப்புச் செய்திகள் - 35</p><p>லேவியராகமத்தின் மையக்கருத்து வசனங்கள் - லேவி. 17: 11, 20: 7.8</p><p>மையப் பொருள் பொதிந்த அதிகாரம் - லேவி 16.</p>'),
 (300,'<p><b>எரேமியாவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>எரேமியா முதல் அதிகாரம், முதலாவது வசனம் எரேமியா தீர்க்கதரிசியை இந்த எரேமியா புத்தகத்தின் எழுத்தாளராக அடையாளம் காண்பிக்கிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>எரேமியா புத்தகம் கி.மு. 630 முதல் கி.மு. 580 வரையிலுள்ள காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>எரேமியா புத்தகம் யூதா தேசத்திற்கு இறுதியான தீர்க்கதரிசனங்களை பதிவுசெய்கிறது, தேசம் மனந்திரும்பாவிட்டால் அழிவை எதிர்கொள்ளும் என்று கடுமையாக எச்சரிக்கிறது. எரேமியா தேசத்தை தேவனிடமாக திரும்புமாறு அழைக்கிறார். அதே சமயம், மனந்திரும்பாத விக்கிரகாராதனை மற்றும் ஒழுக்கக்கேடு காரணமாக யூதாவினுடைய அழிவின் தவிர்க்க முடியாத தன்மையையும் எரேமியா காண்கிறார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>எரேமியா 1:5, \"நான் உன்னைத் தாயின் வயிற்றில் உருவாக்கு முன்னே உன்னை அறிந்தேன்; நீ கர்ப்பத்திலிருந்து வெளிப்படுமுன்னே நான் உன்னைப் பரிசுத்தம்பண்ணி, உன்னை ஜாதிகளுக்குத் தீர்க்கதரிசியாகக் கட்டளையிட்டேன் என்று சொன்னார்.\"</p><p>எரேமியா 17:9, \"எல்லாவற்றைப்பார்க்கிலும் இருதயமே திருக்குள்ளதும் மகா கேடுள்ளதுமாயிருக்கிறது, அதை அறியத்தக்கவன் யார்?\"</p><p>எரேமியா 29:10-11, \"பாபிலோனிலே எழுபதுவருஷம் நிறைவேறினபின்பு நான் உங்களைச் சந்தித்து, உங்களை இவ்விடத்துக்குத் திரும்பிவரப்பண்ணும்படிக்கு உங்கள்மேல் என் நல்வார்த்தையை நிறைவேறப்பண்ணுவேன் என்று கர்த்தர் சொல்லுகிறார். நீங்கள் எதிர்பார்த்திருக்கும் முடிவை உங்களுக்கு கொடுக்கும்படிக்கு நான் உங்கள்பேரில் நினைத்திருக்கிற நினைவுகளை அறிவேன் என்று கர்த்தர் சொல்லுகிறார்; அவைகள் தீமைக்கல்ல, சமாதானத்துக்கேதுவான நினைவுகளே.\"</p><p>எரேமியா 52:12-13, \"ஐந்தாம் மாதம் பத்தாந்தேதியிலே, பாபிலோன் ராஜாவுக்கு முன்பாக நிற்கிறவனாகிய காவற்சேனாதிபதியான நேபுசராதான் எருசலேமுக்கு வந்தான்; அது நேபுகாத்நேச்சார் என்னும் ராஜா பாபிலோனை அரசாளுகிற பத்தொன்பதாம் வருஷமாயிருந்தது. அவன் கர்த்தருடைய ஆலயத்தையும், ராஜாவின் அரமனையையும், எருசலேமிலுள்ள எல்லா வீடுகளையும், ஒவ்வொரு பெரிய மனிதனுடைய வீட்டையும் அக்கினியினால் சுட்டெரித்துப்போட்டான்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>எரேமியாவின் புத்தகம் முதன்மையாக யூதாவின் மீது விக்கிரகாராதனையை முடிவுக்கு கொண்டு வருவதற்கான செய்தியாகும் (எரேமியா 7:30-34; 16:10-13; 22:9; 32:29; 44:2-3). கடைசி நீதியுள்ள ராஜாவான யோசியா ராஜாவின் மரணத்திற்குப் பிறகு, யூத தேசம் தேவனையும் அவருடைய கட்டளைகளையும் முற்றிலும் கைவிட்டுவிட்டது. எரேமியா யூதாவை ஒரு விபச்சாரியுடன் ஒப்பிடுகிறார் (எரேமியா 2:20; 3:1-3). விக்கிரகாராதனையை மிகக் கடுமையாக நியாயந்தீர்ப்பேன் என்று தேவன் வாக்குறுதி அளித்திருந்தார் (லேவியராகமம் 26:31-33; உபாகமம் 28:49-68), தேவனுடைய நியாயத்தீர்ப்பு நெருங்கிவிட்டதாக எரேமியா யூதாவிற்கு எச்சரிக்கை விடுவிக்கிறார். தேவன் யூதாவை எண்ணற்ற சந்தர்ப்பங்களில் அழிவிலிருந்து விடுவித்தார், ஆனால் அவருடைய இரக்கம் அதன் முடிவில் இருந்தது. நேபுகாத்நேச்சார் ராஜா யூதாவை வென்று அதை அவருக்குக் கீழ்ப்படுத்துவதாக எரேமியா பதிவு செய்கிறார் (எரேமியா 24:1). மேலும் கலகத்தின் பின்னர், யூதாவையும் எருசலேமையும் அழிக்கவும் பாழாக்கவும் தேவன் நேபுகாத்நேச்சரையும் அவனுடைய பாபிலோனியப் படைகளையும் திரும்ப அழைத்து வந்தார் (எரேமியா 52-ஆம் அதிகாரம்). இந்த மிகக் கடுமையான நியாயத்தீர்ப்பில் கூட, தேவன் அவர்களுக்குக் கொடுத்த தேசத்தில் யூதாவை மீட்டெடுப்பதாக அவர் வாக்குறுதி அளிக்கிறார் (எரேமியா 29:10).</p><p><b>முன்னிழல்கள்:</b></p><p>எரேமியா 23:5-6 வரையிலுள்ள வசனங்கள், வரவிருக்கும் மேசியாவாகிய இயேசு கிறிஸ்துவின் தீர்க்கதரிசனத்தை முன்வைக்கிறது. தீர்க்கதரிசி அவரை தாவீதின் வீட்டிலிருந்து தோன்றுகிற ஒரு கிளை என்று விவரிக்கிறார் (வச. 5; மத்தேயு 1), ஞானத்திலும் நீதியிலும் ஆட்சி செய்யும் ராஜாவாக சித்தரிக்கப்படுகிறார் (வச. 5, வெளிப்படுத்துதல் 11:15). தான் தேர்ந்தெடுத்தவர்களுக்கு இரட்சிப்பை அளிப்பதால், கிறிஸ்துவே இஸ்ரவேலால் அவளுடைய உண்மையான மேசியாவாக அங்கீகரிக்கப்படுவார் (வச. 6; ரோமர் 11:26).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>எரேமியா தீர்க்கதரிசி கொடுப்பதற்கு மிகவும் கடினமான நியாயத்தீர்ப்பின் செய்தியைக் கொண்டிருந்தார். எரேமியா யூதா தேசத்தை நேசித்தார், ஆனால் அவர் அதனைக்காட்டிலும் கூடுதலாக மிகவும் அதிகமாக தேவனை நேசித்தார். எரேமியா தனது சொந்த மக்களுக்கு ஒரு தொடர்ச்சியான தீர்ப்பை வழங்குவது எவ்வளவு வேதனையானது, எரேமியா செய்யும்படி மற்றும் சொல்லும்படியாக தேவன் சொன்னவிகளுக்கு அவர் கீழ்ப்படிந்தார். எரேமியா யூதாவிற்காக தேவனிடமிருந்து இரக்கத்தை கோரினார், ஜெபித்தார், ஆனால் தேவன் நல்லவர், நீதியுள்ளவர், நியாயம் செய்கிறவர் என்று உறுதியாக நம்பினார். நாமும் தேவனுக்குக் கீழ்ப்படிய வேண்டும், அது கடினமாக இருக்கும்போது கூட, தேவனுடைய சித்தத்தை நம்முடைய சொந்த விருப்ப ஆசைகளை விட முக்கியமானது என்று நாம் அங்கீகரிக்க வேண்டும், மேலும் தேவன் தனது எல்லையற்ற அளவில்லாத ஞானத்திலும், முழுமையான திட்டத்திலும், அவருடைய பிள்ளைகளுக்கு மிகச் சிறந்ததைக் கொண்டு வருவார் என்றும் நம்பவேண்டும் (ரோமர் 8:28) .</p><p>சுமார் கி.மு. 670 (721) - இஸ்ரவேலின் வீழ்ச்சி</p><p>சுமார் கி.மு. 589 (640) - யோசியா அரசராதல்</p><p>சுமார் கி.மு. 575 (626) - எரேமியா தீர்க்கதரிசியாக அழைக்கப்படுதல்</p><p>சுமார் கி.மு. 557 (608) - யோசியாவின் மெகிதோ மரணம் யோவாகாஸ் பதவியேற்பு</p><p>சுமார் கி.மு. 557 (608) - யோயாக்கீம் பதவியேற்பு:</p><p>சுமார் கி.மு. 555 (606) - நேபுகாத்நேச்சாரின் முதல் படையெடுப்பு</p><p>சுமார் கி.மு. 546-(597) - யோயாக்கீன் அரசராக முயற்சி நேபுகாத்நேச்சாரின் இரண்டாம் படையெடுப்பு</p><p>சுமார் கி.மு. 546 (597) - சிதேக்கியா அரசராதல்</p><p>சுமார் கி.மு, 535 (586) - நேபுகாத் நேச்சாரின் மூன்றாம் படையெடுப்பு எருசலேமின் வீழ்ச்சி</p><p>சுமார் கி.மு. 534 (585) - எரேமியா எகிப்தில்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - எரேமியா (கர்த்தரை உயர்த்துங்கள் / கர்த்தர் துரத்துவார்)</p><p>தந்தை பெயர் - இல்க்கியா ஆசாரியர்</p><p>ஊர் - ஆனதோத், பென்யமீன் எல்லையிலிருந்த லேவியரின் பட்டணம்</p><p>தொழில் - தீர்க்கதரிசி</p><p>படைப்புகள் - பல நூற்களின் ஆசிரியர். இராஜாக்கள் நூற்கள், எரேமியா, புலம்பல்</p><p>சிறப்புப் பெயர்கள் - புலம்பலின் தீர்க்கதரிசி, தனிமையின் தீர்க்கதரிசி, ஓர் உடைந்த உள்ளம், கடின வார்த்தை கூறிய மென்மையான இதயத் துக்குரியவர், அழுது அழுது அழிவைக் கூறியவர்</p><p>சாதனை - பலமுறை சிறையிருப்பிலும், விமர்சனங்க ளிலும், மிரட்டல்களில் அகப்பட்ட போதும் சத்தியத்துக்காக துணிந்து நின்றவர்.</p><p>தீர்க்கதரிசன - பல தீர்க்கதரிசன நிறைவேறுதல்களை</p><p>கண்ணாரக் கண்டவர்.</p><p>ஆண்டுகள் - சுமார் 52 (சுமார் 626 - 574)</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 24-வது நூல்</p><p>அதிகாரங்கள் - 52</p><p>வசனங்கள் - 1364</p><p>வரலாற்று வசனங்கள் - 580</p><p>எச்சரிக்கைகள் - 1002</p><p>நிறைவேறிய தீர்ககதரிசனங்கள் - 666</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 180</p><p>நிறைவேறிய எச்சரிக்கைகள் - 779</p><p>நிறைவேற வேண்டிய எச்சரிக்கைகள் -  223</p><p>கேள்விகள் -154</p><p>கட்டளைகள் - 303</p><p>வாக்குத்தத்தங்கள் - 16</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 62</p>'),
 (310,'<p><b>புலம்பல் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>புலம்பல் புத்தகம் அதன் எழுத்தாளரை வெளிப்படையாக யாரென்று அடையாளம் காண்பிக்கவில்லை. எரேமியா தீர்க்கதரிசி புலம்பல் புத்தகத்தை எழுதினார் என்பது பாரம்பரியம். பாபிலோனியர்கள் எருசலேமை அழித்ததற்கு இதை எழுதிய எழுத்தாளர் சாட்சியாக இருக்கிறார் என்று இந்த பார்வை கருதுகிறது. எரேமியா இந்த தகுதிக்கு மிகவும் சரியாகப் பொருந்துகிறார் (2 நாளாகமம் 35:25; 36:21-22).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>புலம்பல் புத்தகம் கி.மு. 586 மற்றும் கி.மு. 575-க்கு இடையில் எழுதப்பட்டிருக்கலாம், அதாவது எருசலேமின் வீழ்ச்சியின் போது அல்லது அது நிகழ்ந்த விரைவில் எழுதப்பட்டிருக்கலாம்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>யூதா தேசத்தின் தொடர்ச்சியான மற்றும் மனந்திரும்பி வருத்தப்படாத விக்கிரக ஆராதனையின் விளைவாக, எருசலேம் நகரத்தை முற்றுகையிடவும்,தேசத்தை கொள்ளையடிக்கவும், எரிக்கவும் அழிக்கவும் தேவன் பாபிலோனியர்களை அனுமதித்தார். ஏறக்குறைய 400 ஆண்டுகளாக நின்றிருந்த சாலமோனின் தேவாலயம் எரிக்கப்பட்டு தரைமட்டமானது. இந்த நிகழ்வுகளை நேரில் கண்ட சாட்சியான எரேமியா தீர்க்கதரிசி, யூதாவிற்கும் எருசலேமுக்கும் என்ன நடந்தது என்பதற்கான புலம்பலாக இந்த புலம்பல் புத்தகத்தை எழுதினார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>புலம்பல்கள் 2:17, \"கர்த்தர் தாம் நினைத்ததைச் செய்தார்; பூர்வநாட்கள் முதற்கொண்டு தாம் கட்டளையிட்ட தமது வார்த்தையை நிறைவேற்றினார்; அவர் தப்பவிடாமல் நிர்மூலமாக்கி, உன்மேல் பகைஞன் சந்தோஷிக்கும்படி செய்தார்; உன் சத்துருக்களின் கொம்பை உயர்த்தினார்.\"</p><p>புலம்பல்கள் 3:22-23, \"நாம் நிர்மூலமாகாதிருக்கிறது கர்த்தருடைய கிருபையே, அவருடைய இரக்கங்களுக்கு முடிவில்லை. அவைகள் காலைதோறும் புதியவைகள்; உமது உண்மை பெரிதாயிருக்கிறது.</p><p>புலம்பல்கள் 5:19-22, \"கர்த்தாவே, நீர் என்றென்றைக்கும் இருக்கிறீர்; உம்முடைய சிங்காசனம் தலைமுறை தலைமுறையாக நிலைநிற்கும். தேவரீர் என்றைக்கும் எங்களை மறந்து, நெடுங்காலமாக எங்களைக் கைவிட்டிருப்பதென்ன? கர்த்தாவே, எங்களை உம்மிடத்தில் திருப்பிக்கொள்ளும், அப்பொழுது திரும்புவோம்; பூர்வகாலத்திலிருந்தது போல எங்கள் நாட்களைப் புதியவைகளாக்கும். எங்களை முற்றிலும் வெறுத்துவிடுவீரோ? எங்கள்பேரில் கடுங்கோபமாயிருக்கிறீரே!\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>புலம்பல் புத்தகம் ஐந்து அதிகாரங்களாகப் பிரிக்கப்பட்டுள்ளது. ஒவ்வொரு அதிகாரமும் ஒரு தனி கவிதையை குறிக்கும் விதமாக இருக்கிறது. மூலமொழியாகிய எபிரேய மொழியில், வசனங்கள் அகரவரிசையில் எழுதப்பட்டதாகும், அவற்றின் ஒவ்வொரு வசனமும் எபிரேய எழுத்துக்களின் அடுத்தடுத்த எழுத்துடன் தொடங்குகின்றன. புலம்பல் புத்தகத்தில், எருசலேம் மீது தீர்ப்பைக் கொண்டுவருவதற்கான தேவனுடைய கருவி பாபிலோனியர்கள் என்பதை எரேமியா தீர்க்கதரிசி புரிந்துகொள்கிறார் (புலம்பல் 1:12-15; 2:1-8; 4:11). தேவனுடைய கோபத்தை கொட்டுவதற்கு பாவமும் கழகமும் தான் காரணம் என்று புலம்பல்கள் தெளிவுபடுத்துகின்றன (1:8-9; 4:13; 5:16). துயரத்தின் போது புலம்பல் மிகவும் பொருத்தமானது, ஆனால் அது விரைவாக மனச்சோர்வு மற்றும் மனந்திரும்புதலுக்கு வழிவகுக்க வேண்டும் (புலம்பல் 3:40-42; 5:21-22).</p><p><b>முன்னிழல்கள்:</b></p><p>எரேமியா தனது ஜனத்தின் மீதும் அவர்களின் நகரத்தின் மீதும் ஆழ்ந்த மற்றும் நிலையான ஆர்வம் கொண்டிருந்தமைக்காக அவர் \"அழுகிற தீர்க்கதரிசி\" என்று அறியப்பட்டார் (புலம்பல் 3:48-49). ஜனங்களின் பாவங்கள் குறித்தும், தேவனை அவர்கள் நிராகரித்ததாலும் இதே துக்கம் இயேசு எருசலேமை நெருங்கி ரோமர்களின் கைகளில் அது அழிவை எதிர்நோக்கியபோது வெளிப்படுத்தினார் (லூக்கா 19:41-44). யூதர்கள் தங்கள் மேசியாவை நிராகரித்ததால், தேவன் தம் ஜனங்களை தண்டிக்க ரோமர்கள் முற்றுகையைப் பயன்படுத்தினார். ஆனால், தம்முடைய பிள்ளைகளைத் தண்டிப்பதில் தேவன் மகிழ்ச்சியடையவில்லை, பாவத்திற்கான ஏற்பாடாக இயேசு கிறிஸ்துவை அவர் அளித்திருப்பது ஜனங்கள்மீது அவருக்கு இருக்கும் அவருடைய மிகுந்த இரக்கத்தைக் காட்டுகிறது. ஒரு நாள், கிறிஸ்துவின் மூலமாக, தேவன் எல்லா கண்ணீரையும் துடைப்பார் (வெளிப்படுத்துதல் 7:17).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>பயங்கரமான நியாயத்தீர்ப்பில் கூட, தேவன் உண்மையுள்ள மற்றும் உண்மையை காக்கிற தேவனாக இருக்கிறார் (புலம்பல் 3:24-25). நாம் அவரிடமிருந்து எவ்வளவு தூரம் விலகிச் சென்றிருந்தாலும், நாம் அவரிடம் திரும்பி அவரை இரக்கமுள்ளவராகவும் மன்னிப்பவராகவும் காணலாம் என்ற நம்பிக்கை உள்ளது (1 யோவான் 1:9). நம்முடைய தேவன் ஒரு அன்பான தேவன் (புலம்பல் 3:22), அவருடைய மிகுந்த அன்பும் இரக்கமும் காரணமாக, நம்முடைய பாவங்களில் நாம் அழிந்துபோகாமல், அவருடன் நித்தியமாக வாழும்படி அவர் தம்முடைய குமாரனை அனுப்பினார் (யோவான் 3:16). தேவனுடைய உண்மையும் (புலம்பல் 3:23) மற்றும் மீட்பும் (புலம்பல் 3:26) நமக்கு மிகுந்த நம்பிக்கையையும் ஆறுதலையும் தரும் பண்புகளாகும். அவர் அக்கறையற்ற, சலன புத்தியுள்ள ஒரு தேவன் அல்ல, ஆனால் அவரிடம் திரும்பும் அனைவரையும் அவர் விடுவிப்பார், அவருடைய தயவைப் பெற அவர்களால் எதுவும் செய்ய முடியாது என்பதை ஒப்புக்கொள்கிறார்கள், மேலும் நாம் அழிந்து போகாமல் மற்றும் நிர்மூலமாகாமல் இருக்க கர்த்தருடைய இரக்கத்தைப் பெற அவரை அழைக்கிறோம் (புலம்பல் 3:22 ).</p><p>சுமார் கி.மு. 670 (721) - இஸ்ரவேலின் வீழ்ச்சி</p><p>சுமார் கி.மு. 575 (626) -  எரேமியா தீர்க்கதரிசியாக அழைக்கப்படல்</p><p>சுமார் கி.மு. 555 (606) - நேபுகாத் நேச்சாரின் முதல் படையெடுப்பு</p><p>சுமார் கி.மு. 546 (597) - நேபுகாத் நேச்சாரின் இரண்டாம் படையெடுப்பு.</p><p>சுமார் கி.மு. 546 (597) - சிதேக்கியா அரசராதல்</p><p>சுமார் கி.மு. 538 (589) - நேபுகாத் நேச்சாரின் மூன்றாம் படையெடுப்பு எருசலேம் முற்றுகையிடப்படுதல்</p><p>சுமார் கி.மு.535 (586) - எருசலேம் வீழ்ச்சியடைதல்</p><p>சுமார் கி.மு. 535 (586) - புலம்பல் நூல் எழுதப்படுதல்</p><p>சுமார் கி.மு. 534 (585) - எரேமியா எகிப்தில்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - எரேமியா (கர்த்தரை உயர்த்துங்கள் / கர்த்தர் துரத்துவார்)</p><p>தந்தை பெயர் - இல்க்கியா ஆசாரியர்</p><p>ஊர் - ஆனதோத், பென்யமீன் எல்லையிலிருந்த லேவியரின் பட்டணம்</p><p>தொழில் - தீர்க்கதரிசி</p><p>படைப்புகள் - பல நூற்களின் ஆசிரியர். இராஜாக்கள் நூற்கள், எரேமியா, புலம்பல்</p><p>சிறப்புப் பெயர்கள் - புலம்பலின் தீர்க்கதரிசி, தனிமையின் தீர்க்கதரிசி, ஓர் உடைந்த உள்ளம், கடின வார்த்தை கூறிய மென்மையான இதயத் துக்குரியவர், அழுது அழுது அழிவைக் கூறியவர்</p><p>சாதனை - பலமுறை சிறையிருப்பிலும், விமர்சனங்க ளிலும், மிரட்டல்களில் அகப்பட்ட போதும் சத்தியத்துக்காக துணிந்து நின்றவர்.</p><p>தீர்க்கதரிசன - பல தீர்க்கதரிசன நிறைவேறுதல்களை</p><p>கண்ணாரக் கண்டவர்.</p><p>ஆண்டுகள் - சுமார் 52 (சுமார் 626 - 574)</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 25-வது நூல்</p><p>அதிகாரங்கள் - 5</p><p>வசனங்கள் - 154</p><p>தீர்க்கதரிசன வசனங்கள் - 2</p><p>கேள்விகள் -13</p><p>கட்டளைகள் - 3</p><p>எச்சரிக்கைகள் - 2</p>'),
 (330,'<p><b>எசேக்கியேல் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>எசேக்கியேல் தீர்க்கதரிசி இந்த புத்தகத்தை எழுதியவர் ஆகும் (எசேக்கியேல் 1:3). அவர் எரேமியா மற்றும் தானியேல் இருவருக்கும் சமகாலத்தவர் ஆகும்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>எசேக்கியேல் புத்தகம் கி.மு. 593 மற்றும் கி.மு. 565-ன் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும். அதாவது யூதர்களின் பாபிலோனிய சிறையிருப்பின்போது எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>எசேக்கியேல் மிகுந்த பாவமுள்ள மற்றும் முற்றிலும் நம்பிக்கையற்றவர்களாக இருந்த தனது தலைமுறையினருக்கு தேவனுடைய ஊழியத்தை நிறைவேற்றினார். தனது தீர்க்கதரிசன ஊழியத்தின் மூலம் அவர்களை உடனடியாக மனந்திரும்புதலுக்கும் தொலைதூர எதிர்காலத்தில் நம்பிக்கையுடனும் இருக்கும்படிக்கு கொண்டுவர முயன்றார். அவர் அதைக் கற்பித்தார்: (1) தேவன் மனித தூதுவர்கள் மூலம் செயல்படுகிறார்; (2) தோல்வி மற்றும் விரக்தியில் கூட தேவனுடைய ஜனங்கள் தேவனுடைய இறையாண்மையை உறுதிப்படுத்த வேண்டும்; (3) தேவனுடைய வார்த்தை ஒருபோதும் தோல்வியடையாது; (4) தேவன் எங்கும் நிறைந்திருக்கும் சர்வவியாபியாகும், ஆகவே அவரை எங்கும் தொழுதுகொள்ள முடியும்; (5) ஆசீர்வாதங்களைப் பெற எதிர்பார்க்கிற ஜனம் தேவனுக்குக் கீழ்ப்படிய வேண்டும்; (6) தேவனுடைய ராஜ்யம் வரும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>எசேக்கியேல் 2:3-6, \"அவர் என்னை நோக்கி: மனுபுத்திரனே, எனக்கு விரோதமாய் எழும்பின கலகக்கார ஜாதியாகிய இஸ்ரவேல் புத்திரரிடத்திற்கு நான் உன்னை அனுப்புகிறேன்; அவர்களும் அவர்கள் பிதாக்களும் இந்நாள்வரைக்கும் எனக்கு விரோதமாய்த் துரோகஞ்செய்தார்கள். அவர்கள் கடினமுகமும் முரட்டாட்ட இருதயமுமுள்ள புத்திரர்; அவர்களிடத்திற்கு நான் உன்னை அனுப்புகின்றேன்; கர்த்தராகிய ஆண்டவர் இன்னின்னதை உரைக்கிறார் என்று அவர்களோடே சொல்லு. கலகவீட்டாரகிய அவர்கள் கேட்டாலும் சரி, கேளாவிட்டாலும் சரி, தங்களுக்குள்ளே ஒரு தீர்க்கதரிசி உண்டென்கிறதை அவர்கள் அறியவேண்டும். மனுபுத்திரனே; நீ அவர்களுக்குப் பயப்படவேண்டாம்; அவர்கள் வார்த்தைகளுக்கும் அஞ்சவேண்டாம்; நெரிஞ்சில்களுக்குள்ளும் முள்ளுகளுக்குள்ளும் நீ தங்கியிருந்தாலும், நீ அவர்கள் வார்த்தைகளுக்குப் பயப்படாமலும் அவர்கள் முகத்துக்குக் கலங்காமலுமிரு; அவர்கள் கலகவீட்டார்.\"</p><p>எசேக்கியேல் 18:4, \"இதோ, எல்லா ஆத்துமாக்களும் என்னுடையவைகள்; தகப்பனின் ஆத்துமா எப்படியோ, அப்படியே மகனின் ஆத்துமாவும் என்னுடையது; பாவஞ்செய்கிற ஆத்துமாவே சாகும்.\"</p><p>எசேக்கியேல் 28:12-14, \"மனுபுத்திரனே நீ தீரு ராஜாவைக்குறித்துப் புலம்பி அவனை நோக்கி: கர்த்தராகிய ஆண்டவர் உரைக்கிறது என்னவென்றால். நீ விசித்திரமாய்ச் செய்யப்பட்ட முத்திரைமோதிரம்; நீ ஞானத்தால் நிறைந்தவன்; பூரண அழகுள்ளவன். நீ தேவனுடைய தோட்டமாகிய ஏதேனில் இருந்தவன்; பத்மராகம் புஷ்பராகம், வைரம், படிகப்பச்சை, கோமேதகம், யஸ்பி, இந்திரநீலம், மரகதம், மாணிக்கம் முதலான சகவித இரத்தினங்களும் பொன்னும் உன்னை மூடிக்கொண்டிருக்கிறது சிருஷ்டிக்கப்பட்ட நாளில் உன் மேளவாத்தியங்களும் உன் நாகசுரங்களும் உன்னிடத்தில் ஆயத்தப்பட்டிருந்தது. நீ காப்பாற்றுகிறதற்காக அபிஷேகம்பண்ணப்பட்ட கேருப்; தேவனுடைய பரிசுத்த பர்வதத்தில் உன்னை வைத்தேன்; அக்கினிமயமான கற்களின் நடுவே உலாவினாய்.\"</p><p>எசேக்கியேல் 33:11, \"கர்த்தராகிய ஆண்டவர் உரைக்கிறது என்னவென்றால்: நான் துன்மார்க்கனுடைய மரணத்தை விரும்பாமல், துன்மார்க்கன் தன் வழியைவிட்டுத் திரும்பிப் பிழைப்பதையே விரும்புகிறேன் என்று என் ஜீவனைக்கொண்டு சொல்லுகிறேன்; இஸ்ரவேல் வம்சத்தாரே, உங்கள் பொல்லாத வழிகளைவிட்டுத் திரும்புங்கள், திரும்புங்கள்; நீங்கள் ஏன் சாகவேண்டும் என்கிறார் என்று அவர்களோடே சொல்லு.\"</p><p>எசேக்கியேல் 48:35, \"சுற்றிலும் அதின் அளவு பதினெண்ணாயிரங்கோலாகும்; அந்நாள்முதல் நகரம் யேகோவா ஷம்மா என்னும் பெயர்பெறும்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>வழிதவறிய உலகத்தை நீங்கள் எவ்வாறு சமாளிக்க முடியும்? தனது வாழ்க்கையில் முப்பதாவது வயதில் ஆசாரியராக ஊழியத்தைத் தொடங்க விதிக்கப்பட்ட எசேக்கியேல், தனது தாயகத்திலிருந்து பிடுங்கப்பட்டு, இருபத்தைந்து வயதில் பாபிலோனுக்கு அணிவகுத்துச் சென்றார். ஐந்து ஆண்டுகளாக அவர் விரக்தியில் தவித்தார். முப்பது வயதில் யெகோவாவின் மகிமையின் கம்பீரமான பார்வை பாபிலோனில் இருப்பதைக் கவர்ந்தது. ஆசாரியன் / தீர்க்கதரிசி தேவன் எசேக்கியேலின் பூர்வீக நிலத்தின் குறுகிய கட்டுப்பாடுகளுடன் மட்டுப்படுத்தப்படவில்லை என்பதைக் கண்டுபிடித்தார். மாறாக, அவர் ஒரு உலகளாவிய தேவன், அவர் நபர்களையும் தேசங்களையும் கட்டளையிடுகிறார், கட்டுப்படுத்துகிறார். பாபிலோனில், தேவன் எசேக்கியேலுக்காக அவருடைய வார்த்தையை ஜனங்களுக்கு வழங்கினார். அவரது அழைப்பு அனுபவம் எசேக்கியேலை மாற்றியது. அவர் தேவனுடைய வார்த்தையில் தீவிரமாக தன்னை அர்ப்பணித்தார். சிறைபிடிக்கப்பட்டவர்களின் கசப்பான சூழ்நிலையில் அவர்களுக்கு உதவ தனிப்பட்ட முறையில் எதுவும் இல்லை என்பதை அவர் உணர்ந்தார், ஆனால் தேவனுடைய வார்த்தை அவர்களின் நிலைக்கு பேசியதாகவும், அதில் அவர்களுக்கு வெற்றியைக் கொடுக்க முடியும் என்றும் அவர் நம்பினார். தேவனுடைய வார்த்தையை தம் மக்களுக்கு தெரிவிக்க எசேக்கியேல் பல்வேறு முறைகளைப் பயன்படுத்தினார். கவனத்தை ஈர்க்க எருசலேம், அடையாள நடவடிக்கைகள் மற்றும் அசாதாரண நடத்தை ஆகியவற்றை சித்தரிப்பதில் அவர் கலையைப் பயன்படுத்தினார். எருசலேமுக்கும் அதன் குடிமக்களுக்கும் தேவன் என்ன செய்வார் என்பதை நிரூபிக்க அவர் தலைமுடியையும் தாடியையும் வெட்டினார்.</p><p><b>எசேக்கியேலின் புத்தகத்தை நான்கு பிரிவுகளாகப் பிரிக்கலாம்:</b></p><p><b>1-24 அதிகாரங்கள்:</b></p><p>எருசலேமின் அழிவு பற்றிய தீர்க்கதரிசனங்கள்</p><p><b>25-32 அதிகாரங்கள்:</b></p><p>அருகிலுள்ள நாடுகள் பற்றிய தேவனுடைய நியாயத்தீர்ப்பின் தீர்க்கதரிசனங்கள்</p><p><b>33 அதிகாரம்:</b></p><p>இஸ்ரவேலுக்கு மனந்திரும்புதலுக்கான கடைசி அழைப்பு</p><p><b>34-48 அதிகாரங்கள்:</b></p><p>இஸ்ரவேலின் எதிர்கால மறுசீரமைப்பு தொடர்பான தீர்க்கதரிசனங்கள்</p><p><b>முன்னிழல்கள்:</b></p><p>எசேக்கியேல் 34வது அதிகாரம் என்பது இஸ்ரவேலின் தலைவர்களை தம் ஜனங்களை மோசமாக கவனித்துக்கொள்வதற்கான பொய்யான மேய்ப்பர்கள் என்று தேவன் கண்டிக்கும் அதிகாரமாகும். இஸ்ரவேலின் ஆடுகளை பராமரிப்பதற்கு பதிலாக, அவர்கள் தங்களையே கவனித்துக் கொண்டனர். அவர்கள் நன்றாக சாப்பிட்டார்கள், நன்கு ஆடை அணிந்திருந்தார்கள், அவர்கள் வைக்கப்பட்டிருந்த மக்களால் நன்கு கவனிக்கப்பட்டார்கள் (எசேக்கியேல் 34:1-3). இதற்கு நேர்மாறாக, ஆடுகளுக்காக தனது உயிரைக் கொடுக்கும் நல்ல மேய்ப்பன் இயேசு, மந்தையை அழிக்கும் ஓநாய்களிடமிருந்து அவர்களைப் பாதுகாக்கிறார் (யோவான் 10:11-12). 34 வது அதிகாரத்தின் 4-வது வசனம், மேய்ப்பர்கள் பலவீனமானவர்கள், நோய்வாய்ப்பட்டவர்கள், காயமடைந்தவர்கள் மற்றும் இழந்தவர்கள் என ஊழியம் செய்யத் தவறியவர்களை விவரிக்கிறது. நம்முடைய ஆவிக்குரிய காயங்களை குணமாக்கும் பெரிய வைத்தியராகிய இயேசு (ஏசாயா 53:5) சிலுவையில் மரித்ததன் மூலம் நம்மை குணமாக்க வல்லவராயிருக்கிறார். இழந்ததைத் தேடுவதும் காப்பாற்றுவதும் தான் அவரின் பிரதான நோக்கமாகும் அதற்காகவே அவர் இந்த உலகிற்கு வந்தார் (லூக்கா 19:10).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>ஆபிரகாம், மோசே மற்றும் தீர்க்கதரிசிகளின் தேவனுடனான ஒரு புதிய மற்றும் உயிருள்ள சந்திப்பில் சேர எசேக்கியேல் புத்தகம் நம்மை அழைக்கிறது. நாம் வெல்ல வேண்டும் அல்லது நாம் வெல்லப்படுவோம். எசேக்கியேல் நமக்கு சவால் விடுகிறார்: தேவனுடைய வல்லமை, அறிவு, நித்திய இருப்பு மற்றும் பரிசுத்தம் பற்றிய வாழ்க்கையை மாற்றும் பார்வையை அனுபவிக்கவும் தேவன் நம்மை வழிநடத்தட்டும்; ஒவ்வொரு மனித இதயத்திலும் இருக்கும் தீமையின் ஆழத்தையும் அர்ப்பணிப்பையும் புரிந்து கொள்ளுங்கள்; துன்மார்க்கர்களுக்கு வரும் ஆபத்தை எச்சரிப்பதற்கு தேவன் தம் ஊழியர்களை அழைத்து அறிவிக்க பொறுப்பேற்கிறார் என்பதை அங்கீகரிக்கவேண்டும்; புதிய உடன்படிக்கையை அவருடைய இரத்தத்தில் காணப்பட வேண்டும் என்று சொன்ன இயேசு கிறிஸ்துவுடன் ஒரு வாழ்க்கை உறவை அனுபவிக்கவேண்டும்.</p><p>சுமார் கி.மு. 557 (608) - யோயாக்கீம் யூத அரசராதல்</p><p>சுமார் கி.மு. 555 (606) - தானியேலும் பாபிலோனிய குழுவும் சிறைசெல்லுதல்</p><p>சுமார் கி.மு. 546 (597) - யோயாக்கீன் யூத அரசராதல் எசேக்கியேலும் குழுவும் பாபிலோனிய சிறைசெல்தல்</p><p>சிதேக்கியா யூத அரசராதல்</p><p>சுமார் கி.மு. 542 518 - 1593-571) - எசேக்கியேலின் தீர்க்கதரிசன</p><p>ஊழியம்</p><p>சுமார் கி.மு. 535 (686) - எருசலேமின் அழிவு.</p><p>சுமார் கி.மு. 485 (536) - கோரேசின் விடுதலை விளம்பரம்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - எசேக்கியேல் ( தேவன் பெலப்படுத்துகிறார்)</p><p>தகப்பன் பெயர் - பூசி</p><p>தொழில் - ஆசாரிய தீர்க்கதரிசி</p><p>ஊர் - எருசலேமுக்கு அருகாமை பின்பு பாபிலோன் கேபார் நதியோரம் தெலாபீப் என்ற குடியிருப்புப் பகுதி</p><p>குடும்பம் - மணமானவர் (24 : 28) பிள்ளைகள் பற்றி எந்த குறிப்பும் இல்லை</p><p>சிறப்புப் பெயர் - பாபிலோன் தெருவோர பிரசங்கியான யூதர்\". \"கடின இதயமுடைய ஜனங்களின் தீர்க்கதரிசி’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 26-வது நூல்</p><p>அதிகாரங்கள் - 48</p><p>வசனங்கள் - 1273</p><p>வரலாற்று வசனங்கள் - 310</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 53</p><p>நிறைவேறாத தீர்க்கதரிசனங்கள் - 433</p><p>எச்சரிக்கைகள் - 953</p><p>நிறைவேறிய எச்சரிக்கைகள் - 659</p><p>நிறைவேற வேண்டிய எச்சரிக்கைகள்  - 294</p><p>கட்டளைகள் - 345</p><p>வாக்குத்தத்தங்கள் - 25</p><p>கேள்விகள் - 80</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 179</p>'),
 (340,'<p><b>தானியேல் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>தானியேல் புத்தகம் அதன் எழுத்தாளராக தானியேல் தீர்க்கதரிசியை அடையாளப்படுத்துகிறது (தானியேல் 9:2; 10:2). இயேசு தானியேலை அதன் எழுத்தாளராக குறிப்பிடுகிறார் (மத்தேயு 24:15).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>தானியேல் புத்தகம் கி.மு. 540 முதல் கி.மு. 530 வரையிலுள்ள காலக்கட்டத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>கி.மு. 605-ல், பாபிலோனின் மாமன்னன் நேபுகாத்நேச்சார் யூதாவைக் கைப்பற்றி, அதன் குடிமக்கள் பலரை பாபிலோனுக்கு நாடு கடத்தியிருந்தார் – அதில் தானியேலும் கொண்டு செல்லப்பட்டார். நேபுகாத்நேச்சாரின் அரசவையில், நேபுகாத்நேச்சரைப் பின்பற்றிய பல ஆட்சியாளர்களில் தானியேலும் பணியாற்றினார். தானியேல் புத்தகம் தானியேல் தீர்க்கதரிசியின் செயல்கள், தீர்க்கதரிசனங்கள் மற்றும் தரிசனங்களை பதிவு செய்கிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>தானியேல் 1:19-20, \"ராஜா அவர்களோடே பேசினான்; அவர்கள் எல்லாருக்குள்ளும் தானியேல், அனனியா, மீஷாவேல், அசரியா என்பவர்களைப்போல வேறொருவரும் காணப்படவில்லை; ஆகையால் இவர்கள் ராஜசமுகத்தில் நின்றார்கள். ஞானத்துக்கும் புத்திக்கும் அடுத்த எந்த விஷயத்தில் ராஜா அவர்களைக் கேட்டு விசாரித்தானோ, அதிலே தன் ராஜ்யம் எங்குமுள்ள சகல சாஸ்திரிகளிலும் ஜோசியரிலும் அவர்களைப் பத்துமடங்கு சமர்த்தராகக் கண்டான்.\"</p><p>தானியேல் 2:31, \"ராஜாவே, நீர் ஒரு பெரிய சிலையைக்கண்டீர்; அந்தப் பெரிய சிலை மிகுந்த பிரகாசமுள்ளதாயிருந்தது; அது உமக்கு எதிரே நின்றது; அதின் ரூபம் பயங்கரமாயிருந்தது.\"</p><p>தானியேல் 3:17-18, \"நாங்கள் ஆராதிக்கிற தேவன் எங்களைத் தப்புவிக்க வல்லவராயிருக்கிறார்; அவர் எரிகிற அக்கினிச்சூளைக்கும், ராஜாவாகிய உம்முடைய கைக்கும் நீங்கலாக்கி விடுவிப்பார்; விடுவிக்காமற்போனாலும், நாங்கள் உம்முடைய தேவர்களுக்கு ஆராதனை செய்வதுமில்லை, நீர் நிறுத்தின பொற்சிலையைப் பணிந்துகொள்வதுமில்லை என்கிறது ராஜாவாகிய உமக்குத் தெரிந்திருக்கக்கடவது என்றார்கள்.\"</p><p>தானியேல் 4:34-35, \"அந்த நாட்கள் சென்றபின்பு, நேபுகாத்நேச்சாராகிய நான் என் கண்களை வானத்துக்கு ஏறெடுத்தேன்; என் புத்தி எனக்குத் திரும்பி வந்தது; அப்பொழுது நான் உன்னதமானவரை ஸ்தோத்திரித்து, என்றென்றைக்கும் ஜீவித்திருக்கிறவரைப் புகழ்ந்து மகிமைப்படுத்தினேன்; அவருடைய கர்த்தத்துவமே நித்திய கர்த்தத்துவம், அவருடைய ராஜ்யமே தலைமுறை தலைமுறையாக நிற்கும். பூமியின் குடிகள் எல்லாம் ஒன்றுமில்லையென்று எண்ணப்படுகிறார்கள்; அவர் தமது சித்தத்தின்படியே வானத்தின் சேனையையும் பூமியின் குடிகளையும் நடத்துகிறார், அவருடைய கையைத் தடுத்து, அவரை நோக்கி: என்ன செய்கிறீரென்று சொல்லத்தக்கவன் ஒருவனும் இல்லை என்றேன்.\"</p><p>தானியேல் 9:25-27, \"இப்போதும் நீ அறிந்து உணர்ந்துகொள்ளவேண்டியது என்னவென்றால்: எருசலேமைத் திரும்ப எடுப்பித்துக்கட்டுகிறதற்கான கட்டளை வெளிப்படுவதுமுதல், பிரபுவாகிய மேசியா வருமட்டும் ஏழு வாரமும், அறுபத்திரண்டு வாரமும் செல்லும்; அவைகளில் வீதிகளும் அலங்கங்களும் மறுபடியும் கட்டப்படும்; ஆனாலும் இடுக்கமான காலங்களில் இப்படியாகும். அந்த அறுபத்திரண்டு வாரங்களுக்குப் பின்பு மேசியா சங்கரிக்கப்படுவார்; ஆனாலும் தமக்காக அல்ல; நகரத்தையும் பரிசுத்த ஸ்தலத்தையும் வரப்போகிற பிரபுவின் ஜனங்கள் அழித்துப்போடுவார்கள்; அதின்முடிவு ஜலப்பிரவாகம்போல இருக்கும்; முடிவுபரியந்தம் யுத்தமும் நாசமும் உண்டாக நியமிக்கப்பட்டது. அவர் ஒரு வாரமளவும் அநேகருக்கு உடன்படிக்கையை உறுதிப்படுத்தி, அந்த வாரம் பாதி சென்றபோது பலியையும் காணிக்கையையும் ஒழியப்பண்ணுவார்; அருவருப்பான செட்டைகளோடே பாழாக்குகிறவன் வந்து இறங்குவான், நிர்ணயிக்கப்பட்டிருக்கிற நிர்மூலம் பாழாக்குகிறவன்மேல் தீருமட்டும் சொரியும் என்றான்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>தானியேல் புத்தகத்தை மூன்று பிரிவுகளாகப் பிரிக்கலாம். முதல் அதிகாரம் எருசலேம் பாபிலோனியர்களால் கைப்பற்றப்படுவதை விவரிக்கிறது. பலருடன், தானியேலும் அவரது மூன்று நண்பர்களும் பாபிலோனுக்கு நாடு கடத்தப்பட்டனர், அவர்களுடைய தைரியம் மற்றும் அவர்கள்மீது தேவனுடைய வெளிப்படையான ஆசீர்வாதம் காரணமாக, அவர்கள் ராஜாவின் சேவையில் \"பதவி உயர்வு\" பெற்றனர் (தானியேல் 1: 17-20).</p><p>2-7 வரையிலுள்ள அதிகாரங்கள், நேபுகாத்நேச்சார் ஒரு சொப்பனம் கண்டதை பதிவு செய்கிறது. அந்த சொப்பனத்தை தானியேல் மட்டுமே சரியாக விளக்க முடியும் என்பதையும் விவரிக்கிறது. ஒரு பெரிய சிலை பற்றிய நேபுகாத்நேச்சாரின் சொப்பனம் இனிவரும் எதிர்காலத்தில் எழும்ப்பப்போகிற ராஜ்யங்களைக் குறிக்கிறது. நேபுகாத்நேச்சார் தன்னைப் பற்றிய ஒரு பெரிய சிலையை உருவாக்கி, அதை வணங்கும்படி அனைவரையும் கட்டாயப்படுத்துகிறார். சாத்ராக், மேஷாக், மற்றும் ஆபேத்நேகோ என்னும் யூத வாலிபர்கள் மறுத்ததினால், எரிகிற அக்கினிச் சுவாலைக்குள் வீசப்பட்டாலும் அற்புதமாக தேவனால் காப்பாற்றப்பட்டனர். நேபுகாத்நேச்சார் தனது பெருமைக்காக தேவனால் தண்டிக்கப்படுகிறார், ஆனால் தேவனுடைய இறையாண்மையை அங்கீகரித்து ஒப்புக்கொண்டவுடன் பின்னர் மீட்டெடுக்கப்படுகிறார்.</p><p>எருசலேமில் உள்ள ஆலயத்திலிருந்து எடுக்கப்பட்ட பொருட்களை நேபுகாத்நேச்சரின் மகன் பெல்ஷாத்சார் தவறாகப் பயன்படுத்துவதையும், தேவனிடமிருந்து ஒரு எச்சரிப்பின் செய்தியைப் பெறுவதையும் தானியேல் 5-ஆம் அதிகாரம் பதிவுசெய்கிறது. தேவனிடமிருந்து வரும் நியாயத்தீர்ப்பின் செய்தியை தானியேல் மட்டுமே அந்த எழுத்தை விளக்க முடியும்படியாயிற்று. ராஜாவினிடத்தில் ஜெபம் செய்ய மறுத்ததற்காக தானியேல் சிங்கங்களின் குகையில் வீசப்படுகிறார், ஆனால் அதிசயமாக தேவனால் காப்பாற்றப்படுகிறார். தேவன் தானியேலுக்கு தரிசனத்தில் நான்கு மிருகங்களைக் காண்பிக்கிறார். நான்கு மிருகங்களும் பாபிலோன், மேதிய-பெர்சியா, கிரேக்கம் மற்றும் ரோமாபுரி ஆகிய ராஜ்யங்களைக் குறிக்கின்றன.</p><p>8-12 வரையிலுள்ள அதிகாரங்களில், இரண்டு கொம்புகளுள்ள ஒரு ஆட்டுக்கடா, ஒரு வெள்ளாட்டுக்கடா மற்றும் பல கொம்புகள் சம்பந்தப்பட்ட ஒரு தரிசனம் கொடுக்கப்பட்டுள்ளது - இது எதிர்கால ராஜ்யங்களையும் அவற்றின் ராஜாக்களையும் குறிக்கிறது. தானியேல் 9 ஆம் அதிகாரம் தானியேலின் \"எழுபது வாரங்கள்\" குறித்த தீர்க்கதரிசனத்தை பதிவு செய்கிறது. மேசியா எப்போது வந்து சங்கரிக்கப்படுவார் என்பதற்கான துல்லியமான காலக்கெடுவை தேவன் தானியேலுக்கு கொடுத்தார். இஸ்ரவேலுடன் ஏழு ஆண்டுகள் உடன்படிக்கை செய்து பின்னர் மூன்றரை ஆண்டுகளுக்குப் பிறகு அதை முறித்துக் கொள்ளும் ஒரு எதிர்கால ராஜாவினைப் பற்றியும் இந்த தீர்க்கதரிசனம் குறிப்பிடுகிறது. இந்த பெரிய தரிசனத்திற்குப் பிறகு தானியேல் ஒரு தேவதூதனால் பார்வையிடப்பட்டு பலப்படுத்தப்படுகிறார், தேவதூதன் அந்த தரிசனத்தை தானியேலுக்கு மிக விரிவாக விளக்குகிறார்.</p><p><b>முன்னிழல்கள்:</b></p><p>எரிகிற அக்கினிச்சூளை மற்றும் சிங்கங்களின் குகையிலுள்ள தானியேல் சம்பவங்களில் கிறிஸ்துவால் வழங்கப்பட்ட இரட்சிப்பின் முன்னறிவிப்பை நாம் காண்கிறோம். மூன்று மனிதர்களும் தேவன் ஒரு இரட்சிக்கும்/விடுவிக்கும் தேவன் என்று அறிவிக்கிறார்கள், அவர் தப்பிக்க ஒரு வழியை வழங்க முடியும் என்றும் உறுதியாக நம்புகிறார்கள் (தானியேல் 3:17). அதேபோல், நம்முடைய பாவங்களுக்காக இயேசுவை அனுப்புவதன் மூலம், நரகத்தின் நெருப்பிலிருந்து தப்பிக்க தேவன் ஒரு வழியை வழங்கியுள்ளார் (1 பேதுரு 3:18). தானியேலின் விஷயத்தில், சிங்கங்களின் வாயை மூடுவதற்கு தேவன் ஒரு தேவதூதனை வழங்கினார், மேலும் தானியேலை மரணத்திலிருந்து காப்பாற்றினார். நம்மை பட்சிக்கும் அக்கினியாக அச்சுறுத்தும் பாவத்தின் ஆபத்துகளிலிருந்து நம்மை விடுவிக்கும் நம்முடைய ஏற்பாடாக இயேசு கிறிஸ்து இருக்கிறார்.</p><p>கடைசிக் காலங்களைப் பற்றிய தானியேலின் தரிசனம் இஸ்ரவேலின் மேசியாவை சித்தரிக்கிறது, அவர்களால் பலர் கழுவப்பட்டு பரிசுத்தமாவார்கள் (தானியேல் 12:10). அவர் நம்முடைய நீதியாக இருக்கிறார் (1 பேதுரு 5:21) நம்முடைய பாவங்கள் இரத்தாம்பரம்போல் சிவந்திருந்தாலும் அது கழுவப்பட்டு வெண்பனியைப் போல வெண்மையாக இருப்போம் (ஏசாயா 1:18).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>சாத்ராக், மேஷாக், மற்றும் ஆபேத்நேகோவைப் போலவே, நாம் எப்போதும் சரியானது எது என்று அறிந்தவற்றிற்காக தைரியமாக நிற்க வேண்டும். நம்மீது வரக்கூடிய எந்த தண்டனையையும் விட தேவன் பெரியவர். தேவன் நம்மை விடுவிக்க விரும்புகிறாரா இல்லையா என்பதல்லாமல், அவர் எப்போதும் நம் நம்பிக்கைக்கு தகுதியானவர் என்பதை கருத்தில் கொள்ளவேண்டும். நமக்கு எது சிறந்தது என்பதை தேவன் நன்கு அறிவார், மேலும் அவரை நம்பி அவருக்குக் கீழ்ப்படிபவர்களை அவர் கனம்பண்ணுகிறார்/கௌரவிக்கிறார்.</p><p>தேவனுக்கு ஒரு திட்டம் உள்ளது, அவருடைய திட்டம் சிக்கலான விவரங்களுக்குள் ஒளிந்து உள்ளது. தேவன் யாவற்றையும் அறிந்திருக்கிறார், அவர் எதிர்காலத்தைக் கட்டுப்படுத்துகிறார். தேவன் முன்னுரைத்த அனைத்தும் அவர் உரைத்தபடியே உண்மையாகிவிட்டன. ஆகவே, தேவன் அறிவித்தபடியே எதிர்காலத்திற்காக அவர் முன்னறிவித்த விஷயங்கள் ஒரு நாள் நிகழும் என்று நாம் உறுதியாக நம்ப வேண்டும்.</p><p>சுமார் கி.மு.561 (612) - நினிவேயின் வீழ்ச்சி, பாபிலோனின் எழுச்சி</p><p>சுமார் கி.மு. 555 (606) - பாபிலோனின் கார்கேமிஸ் வெற்றி தானியேலும் குழுவினரும் நேபுகாத்நேச்சாரால் சிறை பிடிக்கப்படல்</p><p>சுமார் கி.மு. 535 (586) - எருசலேமின் வீழ்ச்சி</p><p>சுமார் கி.மு. 527 (578) - தானியேலின் மூன்று நண்பர்கள் அக்கினிச் குளையில்</p><p>சுமார் கி.மு.502 (553) - பெல்ஷாத்சார் அரியணையில்</p><p>சுமார் கி.மு. 485 (536) - பெல்ஷாத்சாரின் வீழ்ச்சி கோரேசின் வெற்றி</p><p>சுமார் கி.மு. 485 (536) - கோரேசின் கட்டளை</p><p>சுமார் கி.மு. 484 (535) - தானியேல் சிங்கக் குகையில்?</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - தானியேல் (தேவன் என் நீதிபதி)</p><p>மாற்றப்பட்ட பெயர் - பெல்தெஷாத்சார் (பேல் தேவனின் பிரபு)</p><p>பெற்றோர் பெயர் - தெரியவில்லை</p><p>குடும்பம் - அரச குலத்தில்/ பிரபு குலத்தில் பிறந்தவர்</p><p>ஊர் - எருசலேம், பின்பு பாபிலோனில் சிறைவாசியாக</p><p>தொழில் - பாபிலோனிய மேதிய-பெர்சிய அரசர்கள் பலரின்</p><p>அரசியல் ஆலோசகர்</p><p>திறமைகள் - கனவு விளக்கம் உரைக்கும் வரமுடையவர், சிறந்த ஞானி, சிறந்த அரசியல் ஆலோசகர்</p><p>சிறப்பு - பரிசுத்தம், பக்தி கொள்கைப் பிடிப்பு ஆகியவற்றுக்குப் பெயர் பெற்றவர்</p><p>பட்டப்பெயர் - முன் மாதிரிமிக்க மானிட மகாத்மா, கனவு விளக்கச் சிற்பி. தேவனின் காலக் கட்டிடத்தை தீட்டிக்காட்டிய பொறியியல் வல்லுநர்</p><p>சாதனை - வருங்காலம் பற்றிய சிறந்த வேதாகம நூல் படைப்பு</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 27-வது நூல்</p><p>அதிகாரங்கள் - 12</p><p>வசனங்கள் - 357</p><p>கேள்விகள் - 16</p><p>வரலாற்றுத் தொடர்பு வசளங்கள் - 218</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 79</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 60</p><p>கட்டளைகள் - 7</p><p>வாக்குத்தத்தங்கள் - 4</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 16</p>'),
 (350,'<p><b>ஓசியா புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>ஓசியா 1:1, புத்தகத்தின் எழுத்தாளரை ஓசியா தீர்க்கதரிசி என்று அடையாளப்படுத்துகிறது. தேவனுடைய பிள்ளைகளுக்கும் உலகத்துக்கும் அவர் அளித்த தீர்க்கதரிசன செய்திகளைப் பற்றிய ஓசியா தனிப்பட்ட கணக்கு குறிப்பிடப்பட்டுள்ளது. ஓசியா இஸ்ரேலின் ஒரே தீர்க்கதரிசியாகும், அவருடைய வாழ்க்கையின் பிற்காலங்களில் பதிவு செய்யப்பட்டதும் நமக்கு கிடைக்கப்பெற்ற எழுதப்பட்ட தீர்க்கதரிசனங்களுமாகும்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>பெயேரியின் குமாரனாகிய ஓசியா கி.மு. 785 முதல் கி.மு. 725 வரையிலுள்ள காலக்கட்டத்தில் தீர்க்கதரிசனம் உரைத்தார். ஓசியாவின் புத்தகம் கி.மு. 755 முதல் 725 கி.மு. வரையிலுள்ள காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>நம்முடைய தேவன் ஒரு அன்பான தேவன் என்பதை இஸ்ரவேலர்களுக்கும் நமக்கும் நினைவூட்டுவதற்காக ஓசியா இந்த புத்தகத்தை எழுதினார் – அதாவது அவருடைய உடன்படிக்கை ஜனங்களுக்கு அவர் அளித்த வாக்கு நிலையானது. இஸ்ரவேல் தொடர்ந்து பொய்யான தெய்வங்களுக்கு நேராகத் திரும்பினாலும், தேவனுடைய உறுதியான அன்பு விசுவாசமற்ற மனைவியின் மீதுள்ள கணவனின் நீடித்த அன்பினால் சித்தரிக்கப்படுகிறது. தேவனுடைய அன்பிற்கு தங்கள் முதுகைத் திருப்பிக் காண்பிப்பவர்களுக்கு ஓசியாவின் செய்தி ஒரு எச்சரிக்கையாகும். ஓசியா மற்றும் கோமேரின் திருமண உறவின் அடையாள விளக்கக்காட்சியின் மூலம், தேவனைவிட்டுப் பிரிந்து விக்கிரகாராதனை செய்யும் இஸ்ரவேல் தேசத்தின் மீதான தேவனுடைய அன்பானது, பாவம், நியாயத்தீர்ப்பு மற்றும் மன்னிக்கும் அன்பு ஆகிய கருப்பொருள்களில் ஒரு வளமான உருவகத்தில் காட்டப்படுகிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>ஓசியா 1:2, \"கர்த்தர் ஓசியாவைக்கொண்டு உரைக்கத்தொடங்கினபோது, கர்த்தர் ஓசியாவை நோக்கி: நீ போய், ஒரு சோர ஸ்திரீயையும் சோரப்பிள்ளைகளையும் உன்னிடமாகச் சேர்த்துக்கொள்; தேசம் கர்த்தரை விட்டு விலகிச் சோரம்போயிற்று என்றார்.\"</p><p>ஓசியா 2:23, \"நான் அவளை எனக்கென்று பூமியிலே விதைத்து, இரக்கம் பெறாதிருந்தவளுக்கு இரங்குவேன்; என் ஜனமல்லாதிருந்தவர்களை நோக்கி நீ என் ஜனமென்று சொல்லுவேன்; அவர்கள் என் தேவனே என்பார்கள் என்றார்.\"</p><p>ஓசியா 6:6, \"பலியை அல்ல இரக்கத்தையும், தகனபலிகளைப்பார்க்கிலும் தேவனை அறிகிற அறிவையும், விரும்புகிறேன்.\"</p><p>ஓசியா 14:2-4, \"வார்த்தைகளைக்கொண்டு கர்த்தரிடத்தில் திரும்புங்கள்; அவரை நோக்கி: தேவரீர் எல்லா அக்கிரமத்தையும் நீக்கி, எங்களைத் தயவாய் அங்கீகரித்தருளும்; அப்பொழுது நாங்கள் எங்கள் உதடுகளின் காளைகளைச் செலுத்துவோம். அசீரியா எங்களை இரட்சிப்பதில்லை; நாங்கள் குதிரைகளின்மேல் ஏறமாட்டோம்; எங்கள் கைகளின் கிரியையைப்பார்த்து: நீங்கள் எங்கள் தேவர்களென்று இனிச் சொல்லமாட்டோம்; திக்கற்றவன் உம்மிடத்தில் இரக்கம்பெறுகிறான் என்று சொல்லுங்கள். நான் அவர்கள் சீர்கேட்டைக் குணமாக்குவேன்; அவர்களை மனப்பூர்வமாய்ச் சிநேகிப்பேன்; என் கோபம் அவர்களைவிட்டு நீங்கிற்று.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>ஓசியாவின் புத்தகத்தை இரண்டு பகுதிகளாகப் பிரிக்கலாம்: (1) ஓசியா 1:1-3:5 வரையிலுள்ள பகுதியில், விபச்சாரம் செய்கிற மனைவியையும் உண்மையுள்ள அவளது கணவனையும் விவரிக்கிறது, இது விக்கிரகாராதனை மூலம் தேவனை விட்டு விலகி இஸ்ரவேல் செய்த துரோகத்தின் அடையாளமாகும், மற்றும் (2) ஓசியா 3:6-14:9 வரையிலுள்ள பகுதியில், இஸ்ரவேலின், குறிப்பாக சமாரியாவின், சிலைகளை வழிபடுவதற்கும், இறுதியில் மீட்டெடுப்பதற்கும் கண்டனம் தெரிவிக்கிறது.</p><p>புத்தகத்தின் முதல் பகுதியில் மூன்று தனித்துவமான கவிதைகள் உள்ளன, தேவனுடைய பிள்ளைகள் விக்கிரகாராதனைக்கு காலத்திற்கு காலம் எப்படி திரும்பிச் சென்றார்கள் என்பதை விளக்குகிறது. கோமேரை திருமணம் செய்ய தேவன் ஓசியாவிடம் கட்டளையிடுகிறார், ஆனால் அவள் அவனுக்கு மூன்று குழந்தைகளைப் பெற்ற பிறகு, ஓசியாவைவிட்டுப் பிரிந்து தன் காதலர்களிடம்/காமுகர்களிடம் செல்கிறாள். முதல் அதிகாரத்தில் இந்த அடையாள குறியீட்டு முக்கியத்துவத்தை தெளிவாகக் காணலாம்,அதாவது ஓசியா இஸ்ரேலின் நடவடிக்கைகளை ஒரு திருமண பந்தத்திலிருந்து வழிவிலகி ஒரு விபச்சாரியாக மாற்றுவதோடு ஒப்பிடுகிறார். இரண்டாவது பிரிவில் ஓசியா இஸ்ரவேலரைக் கண்டிக்கிறார், ஆனால் அதைத் தொடர்ந்து வாக்குறுதிகள் மற்றும் தேவனுடைய இரக்கங்களும் அருளப்படுகின்றன.</p><p>ஓசியாவின் புத்தகம் தேவனுடையப் பிள்ளைகளின் மேல் இடைவிடாத தேவனின் அன்பினைக் குறித்த தீர்க்கதரிசன கணக்கு விவரமாகும். காலத்தின் தொடக்கத்திலிருந்தே தேவனுடைய நன்றியற்ற மற்றும் தகுதியற்ற படைப்பானது அவருடைய அன்பு, அருள் மற்றும் இரக்கம் ஆகியவற்றை ஏற்றுக்கொண்டாலும், அதன் துன்மார்க்கத்திலிருந்து விலகி இருக்க முடியவில்லை.</p><p>ஓசியாவின் கடைசி பகுதி, மனந்திரும்பிய இருதயத்தோடு அவரிடம் திரும்பிச் செல்லும்போது தேவனுடைய அன்பு அவருடைய பிள்ளைகளை எவ்வாறு மீட்கிறது என்பதைக் காட்டுகிறது. ஓசியாவின் தீர்க்கதரிசன செய்தி எதிர்காலத்தில் அதாவது 700 ஆண்டுகளுக்குப்பிறகு வரவிருக்கிற இஸ்ரவேலின் மேசியாவினுடைய வருகையை முன்னறிவிக்கிறது. புதிய ஏற்பாட்டில் ஓசியாவின் புத்தகம் பெரும்பாலும் மேற்கோள் காட்டப்படுகிறது.</p><p><b>முன்னிழல்கள்:</b></p><p>ஓசியா 2:23-ல், புறஜாதியாரை [யூதரல்லாதவர்களை] அவருடைய பிள்ளைகளாக சேர்க்கும்படி தேவனிடமிருந்து வந்த அற்புதமான தீர்க்கதரிசன செய்தியை கொண்டுள்ளது, ரோமர் 9:25 மற்றும் 1 பேதுரு 2:10 ஆகியவற்றிலும் இந்த செய்தியானது பதிவு செய்யப்பட்டுள்ளது. புறஜாதியார் முதலில் \"தேவனுடைய ஜனங்கள்\" அல்ல, ஆனால் அவருடைய இரக்கம் மற்றும் கிருபையின் மூலம் அவர் இயேசு கிறிஸ்துவை ஈவாக வழங்கியுள்ளார், அவர்மீதுள்ள விசுவாசத்தினால் நாம் அவருடைய ஜனமாகிய இஸ்ரவேலர்களின் மரத்தில் ஒட்டப்படுகிறோம் (ரோமர் 11:11-18). இது திருச்சபையைப் பற்றிய ஒரு அற்புதமான உண்மை, இது \"இரகசியம்\" என்று அழைக்கப்படுகிறது, ஏனென்றால் கிறிஸ்துவுக்கு முன்பு, தேவனுடைய ஜனங்கள் யூதர்களாக மட்டுமே கருதப்பட்டனர். கிறிஸ்து வந்தபோது, \"புறஜாதியாருடைய நிறைவு உண்டாகும்வரைக்கும் இஸ்ரவேலரிலொரு பங்குக்குக் கடினமான மனதுண்டாயிருக்கும்\" (ரோமர் 11:25) என்று வாசிக்கிறோம்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>ஓசியா புத்தகம் தேவனுடைய ஜனங்கள் மீதுள்ள அவரது நிபந்தனையற்ற அன்பை உறுதிப்படுத்துகிறது. ஆனால், தேவன் தனது பிள்ளைகளின் செயல்களால் எவ்வாறு அவமதிக்கப்படுகிறார், கோபப்படுகிறார் என்பதற்கான ஒரு சித்திரமாகவும் இது இருக்கிறது. அளவில்லா அன்பும், இரக்கமும், கிருபையும் பெற்றுக்கொண்ட ஒரு பிள்ளை தனது தந்தையை இவ்வளவு அவமதிப்புடன் எப்படி நடத்த முடியும்? ஆனாலும், பல நூற்றாண்டுகளாக நாம் அதைச் செய்துகொண்டுதான் இருக்கிறோம். இஸ்ரவேலர்கள் எவ்வாறு தேவனுக்கு தங்கள் முதுகை திருப்பி காண்பித்தார்கள் என்பதை நாம் கருத்தில் கொள்ளும்போது, அதே இஸ்ரவேலரின் பிரதிபலிப்பைக் காண நமக்கு முன்னால் இருக்கும் கண்ணாடியைத் தவிர வேறு எதையும் நாம் பார்க்க வேண்டியதில்லை.</p><p>தேவன் நம் ஒவ்வொருவருக்கும் எவ்வளவு செய்திருக்கிறார் என்பதை நினைவில் கொள்வதன் மூலம் மட்டுமே, நாம் தகுதியான நரகத்திற்குப் பதிலாக மகிமையில் நித்திய ஜீவனைக் கொடுக்கக்கூடியவரை நிராகரிப்பதைத் தவிர்க்க முடியும். நம்முடைய சிருஷ்டிகரை மதிக்க நாம் கற்றுக்கொள்வது மிகவும் அவசியம். நாம் தவறு செய்யும் போது, துக்கப்படுகிற இருதயமும் மனந்திரும்புதலின் வாக்குறுதியும் இருந்தால், தேவன் மீண்டும் நமக்கு ஒருபோதும் அழியாத நிலையான அன்பைக் காண்பிப்பார் என்று ஓசியாவின் புத்தகம் நமக்குக் காண்பிக்கிறது (1 யோவான் 1:9).</p><p>சுமார் கி.மு. 731 (782) - இரண்டாம் யெரொபெயாம் இஸ்ரவேலின் அரசராதல்</p><p>சுமார் கி.மு.716 (767) - உசியா யூதாவின் அரசராதல்</p><p>சுமார் கி.மு. 702 (753) - ஓசியா தீர்க்கதரிசனம் உரைக்கத் தொடங்குதல்</p><p>சுமார் கி.மு. 702 - 701 (753 - 752) - சகரியா, சல்லூம் ஆகியோர் இஸ்ரவேலை ஆண்டு மறைதலும், மெனாகேம் அரியணை ஏறுதலும்.</p><p>சுமார் கி.மு. 695 (748) - யோதாம் தந்தையுடன் ஆட்சி தொடங்குதல் -</p><p>சுமார் கி.மு. 691 (742) - இஸ்ரவேலில் மெனாகேம் ஆட்சி முடிவும் பெக்காகியா அரியணை ஏறுதலும்</p><p>சுமார் கி.மு. 689 (740) - யோதாம் யூத அரசராதல்: பெக்கா இஸ்ரவேல் அரசராதல்</p><p>சுமார் கி.மு. 694 (745) - அசீரியா திகில்லாத்பிலேசரின் கீழ் வலிமையடைதல்</p><p>சுமார் கி.மு. 681 (732) - யூதாவில் ஆகாஸ் அரியணையேறுதல்,</p><p>இஸ்ரவேலில் ஓசேயா அரியணையேறுதல்</p><p>சுமார் கி.மு. 670 (721/722) - ஓசேயாவின் ஆட்சி முடிவு, அசீரியர் இஸ்ரவேலைச் சிறைபிடித்துச் செல்லுதல்</p><p>சுமார் கி.மு. 665 (716) - எசேக்கியா யூத அரசராதல்</p><p>சுமார் கி.மு. 659 (710) - ஓசியா தீர்க்கதரிசனப் பணியை நிறைவேற்றி முடித்தல்?</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - ஓசியா ( இரட்சிப்பு / உதவி/ விடுதலை}</p><p>தகப்பனார் பெயர் - பெயேரி (கிணறு)</p><p>குடும்பம் -  கோமேர் (மனைவி)</p><p>பிள்ளைகள் - யெஸ்ரயேல் (மகன்) லோருகாமா (மகள்)</p><p>லோகம்மீ (மகன்)</p><p>திருப்புமுனை - தேவனின் திருப்பணி அழைப்பும் குடும்பச் சீர்குலைவும்</p><p>சிறப்பு - உடைந்த குடும்ப வாழ்வுடன் உன்னத தேவனின் வார்த்தைகளை அறிவித்தவர்</p><p>சிறப்பு பெயர் - உடைந்த இதயத்தின் தீர்க்கதரிசி</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 28-வது நூல்</p><p>அதிகாரங்கள் - 14</p><p>வசனங்கள் - 197</p><p>கேள்விகள் - 16</p><p>கட்டளைகள் - 26</p><p>வாக்குத்தத்தங்கள் - 10</p><p>எச்சரிக்கைகள் - 298</p><p>நீர்க்காரிசனங்கள் - 152</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 17</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 134</p><p>தேவளிடமிருந்து சிறப்புச் செய்திகள் -10</p>'),
 (360,'<p><b>யோவேலின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>யோவேலின் புத்தகம் அதன் எழுத்தாளரை தீர்க்கதரிசியாகிய யோவேல் தான் என்று கூறுகிறது (யோவேல் 1:1).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>யோவேலின் புத்தகம் கி.மு. 835 முதல் கி.மு. 800 வரையிலுள்ள காலங்களின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>புத்தகத்தின் அமைப்பான யூதா, வெட்டுக்கிளிகளின் பரந்த கூட்டத்தால் அழிக்கப்படுகிறது. வெட்டுக்கிளிகளின் இந்த படையெடுப்பு தானியங்கள், திராட்சைத் தோட்டங்கள், வயல்கள் மற்றும் மரங்கள் போன்ற அனைத்தையும் அழிக்கிறது. வெட்டுக்கிளிகளைப் போல அணிவகுத்துச் செல்லும் மனித இராணுவத்தை யோவேல் உருவக அடையாளமாக விவரிக்கிறார், இவை அனைத்தையும் தனது பாவங்களுக்காக தேசத்திற்கு எதிராக வரும் தெய்வீக நியாயத்தீர்ப்பாக கருதுகிறார். புத்தகம் இரண்டு முக்கிய நிகழ்வுகளால் சிறப்பிக்கப்படுகிறது. ஒன்று வெட்டுக்கிளிகளின் படையெடுப்பு, மற்றொன்று ஆவியானவரின் வெளிப்பாடு. இதன் ஆரம்ப நிறைவேறுதல் பெந்தெகொஸ்தே நாளில் நடந்ததாக அப்போஸ்தலர் 2-ல் பேதுரு மேற்கோள் காட்டியுள்ளார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>யோவேல் 1:4, \"பச்சைப்புழு விட்டதை வெட்டுக்கிளி தின்றது; வெட்டுக்கிளி விட்டதைப் பச்சைக்கிளி தின்றது; பச்சைக்கிளி விட்டதை முசுக்கட்டைப்பூச்சி தின்றது.\"</p><p>யோவேல் 2:25, \"நான் உங்களிடத்தில் அனுப்பின என் பெரிய சேனையாகிய வெட்டுக்கிளிகளும், பச்சைக்கிளிகளும், முசுக்கட்டைப் பூச்சிகளும், பச்சைப் புழுக்களும் பட்சித்த வருஷங்களின் விளைவை உங்களுக்குத் திரும்ப அளிப்பேன்.\"</p><p>யோவேல் 2:28, \"அதற்குப் பின்பு நான் மாம்சமான யாவர்மேலும் என் ஆவியை ஊற்றுவேன்; அப்பொழுது உங்கள் குமாரரும் உங்கள் குமாரத்திகளும் தீர்க்கதரிசனஞ் சொல்லுவார்கள்; உங்கள் மூப்பர் சொப்பனங்களையும், உங்கள் வாலிபர் தரிசனங்களையும் காண்பார்கள்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>வெட்டுக்கிளிகளின் கொடூரமான வாதையால் நிலம் முழுவதும் கடுமையான பஞ்சத்தைத் தொடர்ந்து சந்தித்தது. யூதாவிற்கு எச்சரிக்கை வார்த்தைகளை அனுப்ப யோவேல் இந்த நிகழ்வுகளை வினையூக்கியாக பயன்படுத்துகிறார். ஜனங்கள் விரைவாகவும் முழுமையாகவும் மனந்திரும்பாவிட்டால், இயற்கை கூறுகளைப் போலவே எதிரிப் படைகளும் தேசத்தை விழுங்கிவிடும் என்று எச்சரிக்கிறார். தேவனுடைய மன்னிப்பைப் பெறும்படிக்கு தங்களைத் தாங்களே உபவாசித்து தேவனுக்கு முன்பாக தாழ்த்தும்படிக்கு யோவேல் எல்லா ஜனத்திற்கும், தேசத்தின் ஆசாரியர்களுக்கும் வேண்டுகோள் விடுக்கின்றார். அவர்கள் பதிலளித்தால், தேசத்திற்கு புதுப்பிக்கப்பட்ட வஸ்துக்கள் மற்றும் ஆவிக்குரிய ஆசீர்வாதங்கள் இருக்கும். ஆனால் கர்த்தருடைய நாள் வருகிறது. இந்த நேரத்தில் அனைத்து தேசங்களும் அவருடைய நியாயத்தீர்ப்பைப் பெறுவதால், பயங்கரமான வெட்டுக்கிளிகள் ஒப்பிடுகையில் பித்தலாட்டங்களாகத் தோன்றும்.</p><p>யோவேல் புத்தகத்தின் முக்கிய கருப்பொருள் கர்த்தருடைய நாள், தேவனுடைய கோபம் மற்றும் நியாயத்தீர்ப்பின் நாள் ஆகியவைகளாகும். தேவனுடைய கோபம், வல்லமை மற்றும் பரிசுத்தத்தன்மை ஆகியவற்றின் பண்புகளை வெளிப்படுத்தும் நாள் இதுவாகும், அவருடைய எதிரிகளுக்கு இது ஒரு திகிலூட்டும் நாளுமாகும். முதல் அதிகாரத்தில், தேசத்தின் மீது வெட்டுக்கிளிகளின் படையெடுப்பால் கர்த்தருடைய நாள் வரலாற்று ரீதியாக அனுபவிக்கப்படுகிறது. 2:1-17 வரையிலுள்ள வேதபாகம், இடைக்கால அதிகாரமாகும், அதாவது இதில் யோவேல் தீர்க்கதரிசி வெட்டுக்கிளிகளின் வாதை மற்றும் பஞ்சத்தின் வறட்சியின் உருவகத்தை மனந்திரும்புதலுக்கான அழைப்பைப் புதுப்பிக்க பயன்படுத்துகிறார். 2:18-3:21 வரையிலுள்ள வேதபாகம், கர்த்தருடைய நாளை இனிச்சம்பவிக்கப்போகிற எதிர்கால சொற்களில் விவரிக்கிறது மற்றும் சரீரப் பிரகாரமான மறுசீரமைப்பு (2:21-27), ஆவிக்குரிய மறுசீரமைப்பு (2:28-32) மற்றும் தேசிய மறுசீரமைப்பு (3:1-21) ஆகியவை அடங்கியுள்ளன.</p><p><b>முன்னிழல்கள்:</b></p><p>பழைய ஏற்பாடு பாவத்திற்கான நியாயத்தீர்ப்பைப் பற்றி பேசும்போதெல்லாம், அது தனிநபராகவோ அல்லது தேசிய பாவமாகவோ இருந்தாலும், இயேசு கிறிஸ்துவின் வருகையானது அதில் முன்னறிவிக்கப்படுகிறது. பழைய ஏற்பாட்டின் தீர்க்கதரிசிகள் மனந்திரும்பும்படி இஸ்ரவேலை தொடர்ந்து எச்சரித்தனர், ஆனால் அவர்கள் அவ்வாறு செய்தபோதும், அவர்களின் மனந்திரும்புதல் நியாயப்பிரமாண சட்டத்தைக் கடைப்பிடிப்பதற்கும் அதன் செயல்களுக்கும் மட்டுப்படுத்தப்பட்டது. அவர்களுடைய ஆலய பலிகள் இறுதியாக செலுத்தப்படப்போகிற பலியின் நிழலாக இருந்தன, அவை எல்லா நேரத்திற்கும் ஒரேஒரு முறை வழங்கப்பட்டன, அது சிலுவையில் நிறைவேற்றப்பட்டது (எபிரெயர் 10:10). கர்த்தருடைய நாளில் வரும் தேவனுடைய கடைசி நியாயத்தீர்ப்பு \"பெரியதும் பயங்கரமானது\" என்று யோவேல் நமக்குச் சொல்லுகிறார். அதை யார் தாங்க முடியும்? \" (யோவேல் 2:11). பதில், நம்மால், அத்தகைய தருணத்தை ஒருபோதும் தாங்க முடியாது என்பதேயாகும். ஆனால் நம்முடைய பாவங்களுக்கு பரிகாரம் செய்வதற்காக கிறிஸ்துவில் விசுவாசம் வைத்திருந்தால், நியாயத்தீர்ப்பு நாளுக்கு நாம் பயப்பட ஒன்றுமில்லை/தேவையில்லை.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>மனந்திரும்புதல் இல்லாமல், நியாயத்தீர்ப்பு கடுமையானதாகவும், முழுமையானதாகவும், உறுதியாகவும் இருக்கும். நம்முடைய நம்பிக்கை விசுவாசம் நம்முடைய உடைமைகளில் இருக்கக்கூடாது, மாறாக நம்முடைய தேவனாகிய கர்த்தரிடத்தில் இருக்க வேண்டும். தேவன் சில சமயங்களில் இயற்கையையோ, துக்கத்தையோ அல்லது பிற பொதுவான நிகழ்வுகளையோ நம்மை அவரிடம் நெருங்கி வரவழைப்பதற்காக பயன்படுத்தலாம். ஆனால் அவருடைய இரக்கத்திலும் கிருபையிலும், நம்முடைய இரட்சிப்பிற்கான உறுதியான திட்டத்தை அவர் வழங்கியுள்ளார் – அதுதான் இயேசு கிறிஸ்து என்னும் நம்முடைய இரட்சகர், நம்முடைய பாவங்களுக்காக சிலுவையில் அறையப்பட்டு, அவருடைய அவருடைய பரிபூரண நீதிக்காக நம்முடைய பாவத்தை தம்மேல் எடுத்துக்கொண்டார் (2 கொரிந்தியர் 5:21). இழக்க நேரமில்லை. தேவனுடைய நியாயத்தீர்ப்பு இரவில் வருகிற ஒரு திருடனைப்போல சீக்கிரமாக விரைவாக வரும் (1 தெசலோனிக்கேயர் 5:2), நாம் அதற்கு தயாராக இருக்க வேண்டும். இன்றே இரட்சிப்பின் நாள் (2 கொரிந்தியர் 6:2). \"கர்த்தரைக் கண்டடையத்தக்க சமயத்தில் அவரைத் தேடுங்கள்; அவர் சமீபமாயிருக்கையில் அவரை நோக்கிக் கூப்பிடுங்கள். துன்மார்க்கன் தன் வழியையும், அக்கிரமக்காரன் தன் நினைவுகளையும்விட்டு, கர்த்தரிடத்தில் திரும்பக்கடவன்; அவர் அவன்மேல் மனதுருகுவார்; நம்முடைய தேவனிடத்திற்கே திரும்பக்கடவன்; அவர் மன்னிக்கிறதற்குத் தயை பெருத்திருக்கிறார்\" (ஏசாயா 55:6-7). தேவனுடைய இரட்சிப்பைப் பெறுவதன் மூலம் மட்டுமே கர்த்தருடைய நாளில் அவருடைய கோபத்திலிருந்து தப்பித்துக்கொள்ள முடியும்.</p><p>சுமார் கி.மு. 790 (841) - யெகூ இஸ்ரவேலின் அரசர் அத்தாலியாள் யூத அரசி</p><p>சுமார் கி.மு. 784 (835) - யோவாஸ் யூத அரசர்</p><p>சுமார் கி.மு. 784 (835) - யோவேல் தீர்க்கதரிசன பணிதொடங்குதல்?</p><p>சுமார் கி.மு. 765 (814) - யோவாகாஸ் இஸ்ரவேல் அரசர்</p><p>சுமார் கி.மு. 745 (796) - அமத்சியா யூத அரசர்</p><p>சுமார் கி.மு. 670 (721) - இஸ்ரவேலின் வீழ்ச்சி</p><p>சுமார் கி.மு. 535 (586) - யூதாவின் வீழ்ச்சி</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - யோவேல் (கர்த்தர் தேவன்/ கர்த்தர் தேவனாக இருக்கிறார்/ கர்த்தரே தேவன்)</p><p>தகப்பன் பெயர் - பெத்துவேல் (தேவ தரிசனம்/ தேவ வாசல்/ தேவ தூண்டுதல் பெற்றவர்)</p><p>குடும்பம் - வேறு விவரங்கள் தெரியவில்லை</p><p>தொழில் - தெளிவாகத் தெரியவில்லை. இவரது எழுத்தோவியத்தில் வரும் குறிப்புகளின் அடிப்படையில் இவர் ஆசாரியராக இருக்கலாம் எனக் கருதப்படுறது (1 : 9, 13,14, 16; 2:1, 14, 15, 17; 3: 17, 21)</p><p>ஊர் - சரியாகத் தெரியவில்லை. யூதா நாட்டைச் சார்ந்தவராகவே இருக்க வேண்டும்.</p><p>பிறவேதாகமக் குறிப்புகள்‌- இந்நூலைத் தவிர இவரைப் பற்றி புதிய ஏற்பாட்டில் அப் 2 : 16-ல் மட்டுமே வாசிக்க முடியும்.</p><p>சிறப்புப் பெயர் - பெந்தெகொஸ்து தீர்க்கதரிசி’ (2:28-39 வசன அடிப்படையில்)</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 29-வது நூல்</p><p>அதிகாரங்கள் - 3</p><p>வசனங்கள் - 73</p><p>கேள்விகள் - 7</p><p>கட்டளைகள் - 50</p><p>வாக்குத்தத்தங்கள் - 12</p><p>தீர்க்கதரிசனவசனங்கள் - 69</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் 11</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 59</p><p>தேவனிடமிருந்து சிறப்புச் செய்தி - 32</p>'),
 (370,'<p><b>ஆமோஸ் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>ஆமோஸ் 1:1-வது வசனம், ஆமோஸ் புத்தகத்தின் எழுத்தாளரை ஆமோஸ் தீர்க்கதரிசி என்று அடையாளப்படுத்துகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>ஆமோஸ் புத்தகம் கி.மு. 760 முதல் கி.மு. 753 வரையிலான காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டிருக்கலாம் என்று நம்பப்படுகிறது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>ஆமோஸ் தீர்க்கதரிசி ஆடு மேய்க்கும் ஒரு மேய்ப்பன் மற்றும் தெக்கோவா என்ற யூத கிராமத்திலிருந்து பழம் பொருக்குபராக இருந்தார், அவருக்கு கல்வி அல்லது ஆசாரியப் பின்னணி எதுவும் இல்லாதபோதிலும் தேவன் அவரை அழைத்தார். ஆமோஸின் ஊழியம் வடக்கே தனது அண்டை நாடான இஸ்ரேலுக்கு செய்யும்படியாக அனுப்பப்பட்டது. தேசம் செய்த பாவங்கள் காரணமாக தேசத்திற்கு வரவிருக்கும் அழிவு மற்றும் சிறைப்பிடிப்பு பற்றிய செய்திகள் பெரும்பாலும் செல்வாக்கற்றவை, கவனிக்கப்படாதவைகளாகவே இருந்தன, ஏனென்றால் சாலமோனின் காலம் இஸ்ரவேலில் மிகவும் சிறப்பாக இருந்ததால் என்பதற்காக அல்ல என்பதையும் கருத்தில்கொள்ள வேண்டும். ஆமோஸின் ஊழியம், இரண்டாம் யெரொபெயாம் இஸ்ரவேலையும், உசியா யூதாவை ஆளுகிறபோது உண்டாயிருந்தது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>ஆமோஸ் 2:4, \"மேலும்: யூதாவின் மூன்று பாதகங்களினிமித்தமும், நாலு பாதகங்களினிமித்தமும், நான் அவர்கள் ஆக்கினையைத் திருப்பமாட்டேன்; அவர்கள் கர்த்தருடைய வேதத்தை வெறுத்து, அவருடைய கட்டளைகளைக் கைக்கொள்ளாமல், தங்கள் பிதாக்கள் பின்பற்றின பொய்களினால் மோசம்போனார்களே.\"</p><p>ஆமோஸ் 3:7, \"கர்த்தராகிய ஆண்டவர் தீர்க்கதரிசிகளாகிய தம்முடைய ஊழியக்காரருக்குத் தமது இரகசியத்தை வெளிப்படுத்தாமல் ஒரு காரியத்தையும் செய்யார்.\"</p><p>ஆமோஸ் 9:14, \"என் ஜனமாகிய இஸ்ரவேலின் சிறையிருப்பைத் திருப்புவேன்; அவர்கள் பாழான நகரங்களைக் கட்டி, அவைகளில் குடியிருந்து, திராட்சத்தோட்டங்களை நாட்டி, அவைகளுடைய பழரசத்தைக் குடித்து, தோட்டங்களை உண்டாக்கி, அவைகளின் கனிகளைப் புசிப்பார்கள்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>இஸ்ரேலின் வெளிப்புற செழிப்பு மற்றும் வல்லமையின் அடியில், உட்புற நிலையில் தேசம் முக்கியமாக ஊழல் நிறைந்ததாக இருப்பதை ஆமோஸில் காணலாம். ஆமோஸ் ஜனங்களைத் தண்டிக்கும் பாவங்கள் விரிவானவை: தேவனுடைய வார்த்தையைப் புறக்கணித்தல், உருவ வழிபாடு, புறமத வழிபாடு, பேராசை, சிதைந்த தலைமை மற்றும் ஏழைகளின் அடக்குமுறை. ஆமோஸ் தீர்க்கதரிசி சுற்றியுள்ள எல்லா நாடுகளிலும், பின்னர் தனது சொந்த தேசமான யூதாவின் மீதும் ஒரு நியாயத்தீர்ப்பை உச்சரிப்பதன் மூலம் தனது பணியைத் தொடங்குகிறார், கடைசியில் இஸ்ரவேலுக்கு மிகக் கடுமையான நியாயத்தீர்ப்பு வழங்கப்படுகிறது. தேவனிடமிருந்து அவர் பெற்ற தரிசனங்கள் அதே உறுதியான செய்தியையே வெளிப்படுத்துகின்றன: நியாயத்தீர்ப்பு சமீபமாக இருக்கிறது. எதிர்காலத்தில் மீதமுள்ளவர்களை/மீதியானவர்களை மீட்டெடுப்பதாக ஆமோஸுக்கு தேவன் அளித்த வாக்குறுதியுடன் புத்தகம் முடிகிறது.</p><p><b>முன்னிழல்கள்:</b></p><p>ஆமோஸ் புத்தகம் இனிவரவிருக்கிற எதிர்காலத்திற்கான ஒரு மகத்தான வாக்குறுதியுடன் முடிவடைகிறது. \"அவர்களை அவர்கள் தேசத்திலே நாட்டுவேன்; நான் அவர்களுக்குக் கொடுத்த தேசத்திலிருந்து அவர்கள் இனிப் பிடுங்கப்படுவதில்லையென்று உன் தேவனாகிய கர்த்தர் சொல்லுகிறார் என்றார்\" (9:15). ஆபிரகாமுக்கு தேசத்தை வாக்குப்பண்ணின உறுதிமொழியின் இறுதி நிறைவேற்றம் (ஆதி. 12:7; 15:7; 17:8) கிறிஸ்துவின் பூமியின் ஆயிரமாண்டு ஆட்சியின் போது நிகழும் (யோவேல் 2:26, 27-ஐப் பார்க்கவும்). வெளிப்படுத்துதல் 20-ஆம் அதிகாரத்தில், பூமியில் கிறிஸ்து ஸ்தாபிக்கப்போகிற அவருடைய ஆயிரம் ஆண்டு ஆட்சியை விவரிக்கிறது, இது இரட்சகரின் பரிபூரணமான அரசாங்கத்தின் கீழ் இருக்கிற சமாதனம் மற்றும் மகிழ்ச்சியின் காலம் ஆகும். அந்த நேரத்தில், விசுவாசமுள்ள இஸ்ரவேலும் புறஜாதிய கிறிஸ்தவர்களும் திருச்சபையில் ஒன்றிணைந்து கிறிஸ்துவோடு வாழ்ந்து ஆட்சி செய்வார்கள்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>சில நேரங்களில் நாம் ஒரு \"வெறும்-ஒரு\" என்று நினைக்கிறோம்! அதாவது நாம் வெறுமனே ஒரு விற்பனையாளர், விவசாயி அல்லது இல்லத்தரசி என்று நினைக்கிறோம். ஆமோஸும் ஒரு \"வெறும்-ஒரு\" என்று கருதப்படுகிறார். அவர் ஒரு தீர்க்கதரிசி அல்லது ஆசாரியர் அல்லது பிரபலமான ஒருவரின் மகன் அல்ல. அவர் ஒரு சாதாரண ஆடு மேய்க்கும் மேய்ப்பன், யூதாவில் ஒரு சிறு தொழிலாளி. யார் செவிகொடுத்து அவரைக் கேட்பார்கள்? ஆனால் சாக்கு போக்கு சொல்லுவதற்குப் பதிலாக, ஆமோஸ் பூரணமாக கீழ்ப்படிந்து மாற்றத்திற்கான தேவனுடைய வல்லமையுள்ள குரலாக மாறினார்.</p><p>மேய்ப்பர்கள், தச்சர்கள், மீனவர்கள் போன்ற அனைவரையும் தேவன் வேதாகமத்தின் மூலம் பயன்படுத்தியுள்ளார். இந்த வாழ்க்கையில் நீங்கள் என்னவாக இருந்தாலும், தேவன் உங்களைப் பயன்படுத்தலாம். ஆமோஸ் மிகவும் அதிகமானவன் இல்லை. அவர் ஒரு \"வெறும்-ஒரு\" நபரே. தேவனுக்கு \"வெறும்-ஒரு\" வேலைக்காரன். தேவனுடைய \"வெறும்-ஒரு\" இருப்பது மெய்யாகவே நல்லது.</p><p>சுமார் கி.மு. 740 (791) - உசியா தந்தையுடன் கூட்டாட்சி தொடங்கிய ஆண்டு</p><p>சுமார் கி.மு. 731 (782) - 2-ம் யெரொபெயாம் ஆட்சி தொடங்குதல்</p><p>சுமார் கி.மு.716 (767) - உசியா அரியணையேறுகிறார்</p><p>சுமார் கி.மு. 709-699 - (760-750) ஆமோஸ் தீர்க்கதரிசனப் பணி யாற்றுதல்</p><p>சுமார் கி.மு. 702 (753) - ஓசியா தீர்க்கதரிசனப் பணி தொடங்குதல்?</p><p>சுமார் கி.மு. 697 (748) - யோதாம் குஷ்டரோகியான தந்தையுடன் கூட்டாட்சி தொடங்குதல்</p><p>சுமார் கி.மு. 870 (722) - இஸ்ரவேல் அசீரியாவின் கையில் வீழ்தல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - ஆமோஸ் (சுமை/ சுமை தாங்கியவர்/ தூது *சுமப்பவர்)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>தொழில் - ஆடுமேய்ப்பு, காட்டத்திப்பழம் பொறுக்குதல் (7 : 14)</p><p>சொந்த ஊர் - யூதாவைச் சார்ந்த தெக்கோவா கிராமம் (1:1)</p><p>ஊழியம் செய்த இடம் - வடக்கு அரசு சார்ந்த பெத்தேல் என்னும் விக்கிரகப் பட்டணம் (3 : 14, 7: 10, 13)</p><p>சமகால அரசர்கள்  - யூத அரசரான உசியா, இஸ்ரவேல் அரசரான இரண்டாம் யெரொபெயாம்</p><p>சிறப்புப் பெயர் - \"நீதி தாக பிரசங்கி\" (5 :-24)</p><p><b>சிலபுள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 30-வது நூல்</p><p>அதிகாரங்கள் - 9</p><p>வசனங்கள் - 146</p><p>கட்டளைகள் - 28</p><p>கேள்விகள் - 31</p><p>வாக்குத்தத்தங்கள் - 2</p><p>எச்சரிக்கைகள் - 117</p><p>தீர்க்கதரிசன வசனங்கள் - 121</p><p>நிறைவேறாத தீர்க்கதரிசனங்கள் - 8</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 113</p><p>தேவளின் சிறப்பு செய்திகள் - 35</p>'),
 (380,'<p><b>ஒபதியாவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>ஒபதியா புத்தகத்தின் முதலாவது வசனம், ஒபதியா புத்தகத்தின் எழுத்தாளரை ஓபதியா தீர்க்கதரிசி என்று அடையாளப்படுத்துகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>ஒபதியா புத்தகம் கி.மு. 848 முதல் கி.மு. 840 வரையிலான காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாக நம்பப்படுகிறது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>பழைய ஏற்பாட்டின் புத்தகங்களுள் மிகச் சிறிய புத்தகமான ஒபதியா 21 வசனங்கள் மட்டுமே கொண்டுள்ள புத்தகமாகும். தேவனுக்கும் இஸ்ரவேலுக்கும் எதிரான பாவங்களுக்காக ஏதோமைக் கண்டிக்க இந்த வாய்ப்பைப் பயன்படுத்தும் தேவனுடைய தீர்க்கதரிசி ஒபதியா, இந்த தீர்க்கதரிசன வார்த்தைகளை உரைக்கிறார். ஏதோமியர்கள் ஏசாவின் சந்ததியினர், இஸ்ரவேலர்கள் அவனுடைய இரட்டை சகோதரரான யாக்கோபின் சந்ததியினர் ஆகும். சகோதரர்களுக்கிடையில் ஒரு சண்டை அவர்களின் சந்ததியினரை 1,000 ஆண்டுகளுக்கும் மேலாக பாதித்துள்ளது. எகிப்திலிருந்து புறப்பட்டு இஸ்ரவேலர்கள் வெளியேறியப்போது ஏதோமியர்கள் இஸ்ரவேல் ஜனம் தங்கள் தேசத்தைக் கடக்க தடை விதித்தனர். ஏதோமின் பெருமையின் பாவங்களுக்கு இப்போது கர்த்தரிடமிருந்து ஒரு வலுவான நியாயத்தீர்ப்பு தேவைப்படுகிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>ஒபதியா வசனம் 4, \"நீ கழுகைப்போல உயரப்போனாலும் நீ நட்சத்திரங்களுக்குள்ளே உன் கூட்டைக் கட்டினாலும், அவ்விடத்திலிருந்தும் உன்னை விழத்தள்ளுவேனென்று கர்த்தர் சொல்லுகிறார்.\"</p><p>ஒபதியா வசனம் 12, \"உன் சகோதரன் அந்நியர்வசமான நாளாகிய அவனுடைய நாளை நீ பிரியத்தோடே பாராமலும், யூதா புத்திரருடைய அழிவின் நாளிலே அவர்கள் நிமித்தம் சந்தோஷப்படாமலும் அவர்கள் நெருக்கப்படுகிற நாளிலே நீ பெருமையாய்ப் பேசாமலும் இருக்க வேண்டியதாயிருந்தது.\"</p><p>ஒபதியா வசனம் 15, \"எல்லா ஜாதிகளுக்கும் விரோதமான நாளாகிய கர்த்தருடைய நாள் சமீபமாய் வந்திருக்கிறது; நீ செய்தபடியே உனக்கும் செய்யப்படும்; உன் செய்கையின் பலன் உன் தலையின்மேல் திரும்பும்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>ஒபதியாவின் செய்தி இறுதியானது, மற்றும் அது நிச்சயமானது: ஏதோம் ராஜ்யம் முற்றிலுமாக அழிக்கப்படும். ஏதோம் திமிர்பிடித்தவனாக இருக்கிறான், இஸ்ரவேலின் துரதிர்ஷ்டங்களைப் பற்றி மகிழ்ச்சியடைகிறான், எதிரிப் படைகள் இஸ்ரேலைத் தாக்கும்போது, இஸ்ரவேலர் உதவி கேட்கும்போது, ஏதோமியர்கள் மறுத்து, அவர்களுக்காக உதவி செய்யாமல், அவர்களுக்கு எதிராகப் போராடத் தேர்வு செய்கிறார்கள். பெருமையின் இந்த பாவங்களை இனி கவனிக்க முடியாது. கடைசி நாட்களில் சீயோனின் நிறைவேற்றம் மற்றும் விடுதலையின் வாக்குறுதியுடன் புத்தகம் முடிவடைகிறது, அப்போது தேவனுடைய ஜனங்களுக்கு அவர் ஆட்சி செய்யும்போது அவர்களது தேசம் மீண்டுமாக மீட்கப்படும்.</p><p><b>முன்னிழல்கள்:</b></p><p>ஒபதியா புத்தகத்தின் 21-வது வசனம் கிறிஸ்துவையும் அவருடைய திருச்சபையையும் முன்னறிவிக்கிறது. \"ஏசாவின் பர்வதத்தை நியாயந்தீர்ப்பதற்காக இரட்சகர்கள் சீயோன்பர்வதத்தில் வந்தேறுவார்கள்; அப்பொழுது ராஜ்யம் கர்த்தருடையதாய் இருக்கும்\". இந்த \"இரட்சகர்கள்\" (பல பதிப்புகளில் \"விடுவிப்பவர்கள்\" என்றும் அழைக்கப்படுகிறார்கள்) கிறிஸ்துவின் அப்போஸ்தலர்கள் ஆகும், அதாவது தேவனுடைய வார்த்தையின் ஊழியர்கள் மற்றும் குறிப்பாக இந்த பிந்தைய நாட்களில் நற்செய்தியின் போதகர்கள் அடங்குவார்கள். அவர்கள் \"இரட்சகர்கள்\" என்று அழைக்கப்படுகிறார்கள், அவர்கள் நம்முடைய இரட்சிப்பைப் பெறுவதால் அல்ல, மாறாக அவர்கள் கிறிஸ்துவின் நற்செய்தியின் மூலம் இரட்சிப்பைப் பிரசங்கிப்பதாலும், அந்த இரட்சிப்பைப் பெறுவதற்கான வழியை நமக்குக் காண்பிப்பதாலும் அவர்கள் இரட்சகர்கள் என்று கருதப்படுகிறார்கள். அவர்களும், அவர்களால் பிரசங்கிக்கப்பட்ட வார்த்தையும், இரட்சிப்பின் நற்செய்தி எல்லா மனிதர்களுக்கும் வழங்கப்படும் வழிமுறையாகும். இரட்சிப்பை வழங்குவதற்கு வந்த ஒரே இரட்சகராக கிறிஸ்து மட்டுமே இருக்கிறார், அவரே அதன் காரணகர்த்தாவாக இருக்கிறார், சுவிசேஷத்தை இரட்சகர்களும் விடுவிப்பவர்களும் யுகத்தின் முடிவில் மேலும் மேலும் இவைகளுக்கு ஆதாரமாக இருப்பார்கள்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நாம் அவரிடம் உண்மையாக இருந்தால் தேவன் நம் சார்பாக வெல்வார். ஏதோமைப் போலல்லாமல், தேவைப்படும் காலங்களில் மற்றவர்களுக்கு உதவ நாம் தயாராக இருக்க வேண்டும். பெருமை என்பது ஒரு பெரும் பாவம். இயேசு கிறிஸ்துவையும் அவர் நமக்காகச் செய்ததையும் தவிர நாம் வேறு எதைக் குறித்தும் பெருமைப்பட ஒன்றுமில்லை.</p><p>சுமார் கி.மு.880 (931) - இஸ்ரவேல் பிளவுபட்டது</p><p>சுமார் கி.மு. 797 (848) - யோராம் யூதாவின் அரசராதல் எலிசா ஊழியம் தொடங்குதல்</p><p>சுமார் கி.மு. 794 (845) - ஏதோமின் இஸ்ரவேலுக்கு எதிரான புரட்சி</p><p>சுமார் கி.மு. 790 (841) - யெகூ இஸ்ரவேலின் அரசராதல்</p><p>சுமார் கி.மு.789 (840) - ஒபதியாவின் தீர்க்கதரிசனம்? (சிலர் கருத்து)</p><p>சுமார் கி.மு.731 (782) - இரண்டாம் யெரொபெயாம் இஸ்ரவேல் அரசராதல்</p><p>சுமார் கி.மு.670 (722) - இஸ்ரவேல் அசீரியரின் கையில் விழுதல்</p><p>சுமார் கி.மு. 575 (626)  - எரேமியா தீர்க்கதரிசனப் பணியைத் தொடங்குதல்</p><p>சுமார் கி.மு.535 (586) - எருசலேமின் வீழ்ச்சி</p><p>சுமார் கி.மு. 534 (585) - ஒபதியாவின் தீர்க்கதரிசனம்? (வேறு சிலர் கருத்து)</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>ஆசிரியர் - ஒபதியா (கர்த்தரின் அடிமை/ கர்த்தரை ஆராதிப்பவர்), எபிரெயத்தில் \"ஒபத்யாஹ்\"</p><p>தகப்பனார் பெயர் - தெரியவில்லை</p><p>குடும்பம் - தெரியவில்லை</p><p>தொழில் - தெரியவில்லை</p><p>வேதாகமத்தில் காணப்படும் சுமார் 13 ஒபதியாக்களில் ஒருவர் இவர்</p><p>இவர் - பெயரைத் தவிர எதுவும் அறிய முடியாதவர் \"ஏதோமுக்கு எதிரான சுட்டுவிரல்\"</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 31-வது நூல்</p><p>அதிகாரம் - 1</p><p>வசனங்கள் - 21</p><p>கட்டளை - 1</p><p>கேள்விகள் - 4</p><p>எச்சரிக்கைகள் -20</p><p>தீர்க்கதரிசனங்கள் -12</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 5</p><p>நிறைவேறாதவை - 7</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 3</p>'),
 (390,'<p><b>யோனாவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>யோனா 1:1, யோனா தீர்க்கதரிசி தான் யோனா புத்தகத்தை எழுதியவர் என்று குறிப்பாக அடையாளம் காட்டுகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>யோனாவின் புத்தகம் கி.மு. 793 முதல் கி.மு. 758 வரையிலான காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாக நம்பபடுகிறது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>கீழ்ப்படியாமை மற்றும் எழுப்புதல் ஆகியவை இந்த புத்தகத்தின் முக்கிய பிரதானமான கருப்பொருள்கள். திமிங்கலத்தின் வயிற்றில் யோனாவின் அனுபவம் அவருக்கு ஒரு தனித்துவமான விடுதலையைத் தேடுவதற்கான ஒரு தனித்துவமான வாய்ப்பை வழங்குகிறது, ஏனெனில் அவர் இந்த தனித்துவமான பின்வாங்கலின் போது மனந்திரும்புகிறார். அவரது ஆரம்ப ஒத்துழையாமை/கீழ்ப்படியாமை அவரது தனிப்பட்ட எழுப்புதலுக்கு மட்டுமல்ல, நினிவே ஜனங்களுக்கும் வழிவகுக்கிறது. நினிவேவுக்கு யோனா கொண்டு வரும் எழுப்புதலை எல்லா காலத்திலும் மிகப்பெரிய சுவிசேஷ முயற்சிகளில் ஒன்றாக பலர் வகைப்படுத்துகின்றனர்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>யோனா 1:3, \"அப்பொழுது யோனா கர்த்தருடைய சமுகத்தினின்று விலகி, தர்ஷீசுக்கு ஓடிப்போகும்படி எழுந்து, யோப்பாவுக்குப் போய் தர்ஷீசுக்குப் போகிற ஒரு கப்பலைக்கண்டு, கூலிகொடுத்து, தான் கர்த்தருடைய சமுகத்தினின்று விலகும்படி, அவர்களோடே தர்ஷீசுக்குப் போகக் கப்பல் ஏறினான்.\"</p><p>யோனா 1:17, \"யோனாவை விழுங்கும்படி ஒரு பெரிய மீனைக் கர்த்தர் ஆயத்தப்படுத்தியிருந்தார்; அந்த மீன் வயிற்றிலே யோனா இராப்பகல் மூன்றுநாள் இருந்தான்.\"</p><p>யோனா 2:2, \"என் நெருக்கத்தில் நான் கர்த்தரை நோக்கிக் கூப்பிட்டேன்; அவர் எனக்கு உத்தரவு அருளினார்; நான் பாதாளத்தின் வயிற்றிலிருந்து கூக்குரலிட்டேன், நீர் என் சத்தத்தைக் கேட்டீர்.\"</p><p>யோனா 3:10, \"அவர்கள் தங்கள் பொல்லாத வழியைவிட்டுத் திரும்பினார்களென்று தேவன் அவர்களுடைய கிரியைகளைப் பார்த்து, தாம் அவர்களுக்குச் செய்வேன் என்று சொல்லியிருந்த தீங்கைக்குறித்து மனஸ்தாபப்பட்டு, அதைச் செய்யாதிருந்தார்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>யோனாவின் பயமும் பெருமையும் அவரை தேவனிடமிருந்து ஓடச் செய்கின்றன. தேவன் கட்டளையிட்டபடி, ஜனங்களுக்கு மனந்திரும்புதலைப் பிரசங்கிக்க அவர் நினிவேவுக்குச் செல்ல விரும்பவில்லை, ஏனென்றால் அவர்களை தம்முடைய எதிரிகள் என்று அவர் எண்ணினார், மேலும் நினிவே நகரத்தை அழிக்க தேவன் தமது அச்சுறுத்தலை நிறைவேற்ற மாட்டார் என்றும் அவர் உறுதியாக நம்பினார். அதற்குப் பதிலாக அவர் தர்ஷீசுக்குப் போக ஒரு கப்பலில் ஏறுகிறார், அது நினிவே பட்டணத்திற்கு எதிர் திசையில் உள்ளது. விரைவில் ஒரு பொங்கி எழும் புயற்காற்று மற்றும் கொந்தளிப்பு கப்பல் பயணிகளை நடுங்க வைக்கிறது மற்றும் யோனா தான் பிரச்சினை என்று தெரியவருகிறது. அவர்கள் யோனாவை கப்பலில் இருந்து கடலில் வீசுகிறார்கள், அப்பொழுது அவர் ஒரு பெரிய மீனால் விழுங்கப்படுகிறார். அதன் வயிற்றில் ஏறக்குறைய 3 பகல் மற்றும் 3 இரவுகளில், யோனா தனது பாவத்தை தேவனிடம் அறிக்கைச்செய்து மனந்திரும்புகிறார், மீன் அவரை வெட்டாந்தரையான நிலத்தில் வாந்தி எடுக்கிறது (மனந்திரும்புவதற்கு அவரை இவ்வளவு நேரம் எடுக்கச் செய்தது என்ன என்று நாம் ஆச்சரியப்படுகிறோம்). யோனா பின்னர் நினிவேவுக்கு ஏறக்குறைய 500 மைல் தூர பயணத்தை மேற்கொண்டு நகரத்தை ஒரு பெரிய மனந்திரும்புதலின் எழுச்சிக்கு கொண்டு செல்கிறார். ஆனால் நினிவே மனந்திரும்பும்போது நன்றி செலுத்துவதற்குப் பதிலாக தீர்க்கதரிசி அதிருப்தி அடைகிறார் (உண்மையில் கூச்சலிடுகிறார்). ஆயினும், தேவன் இரக்கமுள்ளவர் என்று அவருக்குக் கற்பிக்க அவர் ஒரு காற்றையும், ஆமணக்குச்செடியையும், புழுவையும் பயன்படுத்தும்போது, யோனா தனது பாடத்தைக் கற்றுக்கொள்கிறார்.</p><p><b>முன்னிழல்கள்:</b></p><p>யோனா ஒரு வகையில் கிறிஸ்துவின் மாதிரிப்படிவமாக இருக்கிறார் என்பது இயேசுவின் சொந்த வார்த்தைகளிலிருந்து தெளிவாகிறது. மத்தேயு 12:40-41-ல், யோனா திமிங்கலத்தின் வயிற்றில் இருந்த அதே காலளவு நேரம் கல்லறையில் இருப்பார் என்று இயேசு தம்மைக் குறித்து அறிவிக்கிறார். யோனாவின் பிரசங்கத்திற்கு செவிகொடுத்து நினிவே மக்கள் அவரது முகத்திற்கு நேராக மனந்திரும்பினாலும், இயேசுவை நிராகரித்த பரிசேயரும் நியாயப்பிரமாண ஆசிரியர்களும் யோனாவை விட மிகப் பெரியவரை நிராகரிக்கிறார்கள் என்று அவர் தொடர்ந்து கூறுகிறார். மனந்திரும்புதல் மற்றும் இரட்சிப்பு குறித்து யோனா நினிவே மக்களுக்கு தேவனுடைய சத்தியத்தைக் கொண்டு வந்ததைப் போலவே, இயேசுவும் தேவன் மூலமாக இரட்சிப்பின் அதே செய்தியை (யோனா 2:9; யோவான் 14:6) கொண்டு வருகிறார் (ரோமர் 11:36).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நாம் தேவனிடடமிருந்து மறைந்து ஒளிந்துகொள்ள முடியாது. நம்முடைய எல்லா ஆட்சேபனைகளையும், கால் பின்வாங்கலையும் மீறி, அவர் நம்மால் சாதிக்க விரும்புவது நிச்சையமாக நிறைவேறும். எபேசியர் 2:10 நமக்கு நினைவூட்டுகிறது, அவர் நமக்கென்று திட்டங்களை வைத்திருக்கிறார், அந்தத் திட்டங்களுக்கு நாம் இணங்குவதைக் காண்போம். யோனாவைப் போலல்லாமல், தாமதமின்றி அவருக்குக் கீழ்ப்படிவோமானால் எவ்வளவு எளிதாக இருக்கும்!</p><p>நம்முடைய நற்பெயர், தேசியம் அல்லது இனம் ஆகியவற்றைப் பொருட்படுத்தாமல், தேவனுடைய அன்பு அனைவருக்கும் அவர் அணுகுவதில் வெளிப்படுகிறது. நற்செய்தியின் இலவச சலுகை எல்லா மக்களுக்கும் எல்லா நேரங்களிலும் கிடைக்கிறது/உள்ளது. கிறிஸ்தவர்களாகிய நம்முடைய பணி, உலகத்தை தேவன் சொல்லும் சலுகையின் வழிமுறையாகவும், மற்றவர்களின் இரட்சிப்பில் மகிழ்ச்சியடையவும் செய்வதாகும். இது ஒரு அனுபவமாகும், \"கடைசி நிமிட மாற்றங்களில்\" கிறிஸ்துவிடம் வருபவர்களிடம் பொறாமைப்படவோ அல்லது கோபப்படவோ கூடாது அல்லது நம்முடைய சொந்த அனுபவத்திற்கு முரணான சூழ்நிலைகளில் வருபவர்களிடமும் நாம் அவரைப்பற்றி பகிர்ந்து கொள்ள வேண்டும் என்று தேவன் விரும்புகிறார்.</p><p>சுமார் கி.மு. 731 (782)  - 2-ஆம் யெரொபெயாம் அரியணையேறுதல்</p><p>சுமார் கி.மு.(733) - நான்காம் சல்மனாசாரின் மரணம்</p><p>சுமார் கி.மு. 731 - 702 (782-753) - யோனாவின் தீர்க்கதரிசனம்?</p><p>சுமார் கி.மு. 720 - 703 (771-754) - அசீரியாவில் மூன்றாம்</p><p>அசூர்தானின் ஆட்சிகாலம்</p><p>சுமார் கி.மு.670 (721)  - இஸ்ரவேலின் வீழ்ச்சி</p><p>சுமார் கி.மு. 654 (705) - சனகெரிப் அரசராதல்</p><p>சுமார் கி.மு. 561 (612) - நினிவே மேதிய பாபிலோனிய படைக்கு வீழ்தல்</p><p>சுமார் கி.மு. 535 (586) - யூதாவின் வீழ்ச்சி</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - யோனா ( புறா)</p><p>தகப்பன் பெயர் - அமித்தாய் (சத்தியம்/சத்தியம் நிறைந்த)</p><p>ஊர் - காத்தேப்பேர் (2இரா 14 : 25)</p><p>கோத்திரம் - செபுலோன் கோத்திரமாகலாம்</p><p>காலம் - இரண்டாம் யெரொபெயாமின் காலம் (2இரா 14:25)</p><p>சிறப்புப் பெயர் - விலகி ஓடிய தீர்க்கதரிசி\", \"பேதைப்புறா\"</p><p>சாதனை - மூன்று நாட்கள் மீன் வயிற்றில் வாழ்ந்தது</p><p>பொழுது போக்கு - தேவனோடு சண்டைபோடுவது</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 32-வது நூல்</p><p>அதிகாரங்கள் - 4</p><p>வுசனங்கள் - 48</p><p>கட்டளைகள் - 8</p><p>கேள்விகள் - 12</p><p>நிறைவேறிய தீர்க்கதரிசனம் - 1</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 6 (1:22 210, 32, 4,4, 9, 10)</p>'),
 (40,'<p><b>எண்ணாகமம் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>எண்ணாகமம் புத்தகத்தை எழுதியவர் மோசே.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>எண்ணாகமம் புத்தகம் கி.மு. 1440 முதல் கி.மு. 1400 வரையிலுள்ள இடைப்பட்ட காலத்தில் எழுதப்பட்டது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>எண்ணாகமம் புத்தகத்தின் செய்தியானது உலகளாவிய மற்றும் காலத்திற்கு அப்பாற்பட்டது. விசுவாசிகள், அவர்கள் ஈடுபட்டுள்ள ஆவிக்குரிய யுத்தத்தை இது நினைவூட்டுகிறது, ஏனென்றால் எண்ணாகமம் என்பது தேவனுடைய மக்களின் ஊழியம் மற்றும் நடையின் புத்தகமாகும். எண்ணாகமம் புத்தகம் இஸ்ரவேலர்கள் நியாயப்பிரமாணத்தை (யாத்திராகமம் மற்றும் லேவியராகமம்) பெற்றுக்கொள்வதற்கும் வாக்குப்பண்ணப்பட்ட தேசத்தில் (உபாகமம் மற்றும் யோசுவா) நுழைய அவர்களைத் தயார்படுத்துவதற்கும் இடையிலான இடைவெளியைக் நிரப்பி அவைகளுக்கு ஒரு பாலமாக இருக்கிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>எண்ணாகமம் 6:24-26, \"கர்த்தர் உன்னை ஆசீர்வதித்து, உன்னைக் காக்கக்கடவர். கர்த்தர் தம்முடைய முகத்தை உன்மேல் பிரகாசிக்கப்பண்ணி, உன்மேல் கிருபையாயிருக்கக்கடவர். கர்த்தர் தம்முடைய முகத்தை உன்மேல் பிரசன்னமாக்கி, உனக்குச் சமாதானம் கட்டளையிடக்கடவர் என்பதே.\"</p><p>எண்ணாகமம் 12:6-8, \"அப்பொழுது அவர்: என் வார்த்தைகளைக் கேளுங்கள்; உங்களுக்குள்ளே ஒருவன் தீர்க்கதரிசியாயிருந்தால், கர்த்தராகிய நான் தரிசனத்தில் என்னை அவனுக்கு வெளிப்படுத்தி, சொப்பனத்தில் அவனோடே பேசுவேன். என் தாசனாகிய மோசேயோ அப்படிப்பட்டவன் அல்ல, என் வீட்டில் எங்கும் அவன் உண்மையுள்ளவன். நான் அவனுடன் மறைபொருளாக அல்ல, முகமுகமாகவும் பிரத்தியட்சமாகவும் பேசுகிறேன்; அவன் கர்த்தரின் சாயலைக் காண்கிறான்; இப்படியிருக்க, நீங்கள் என் தாசனாகிய மோசேக்கு விரோதமாய்ப் பேச, உங்களுக்குப் பயமில்லாமற்போனதென்ன என்றார்.\"</p><p>எண்ணாகமம் 14:30-34, \"எப்புன்னேயின் குமாரன் காலேபும், நூனின் குமாரன் யோசுவாவும் தவிர, மற்றவர்களாகிய நீங்கள் நான் உங்களைக் குடியேற்றுவேன் என்று ஆணையிட்டுக்கொடுத்த தேசத்தில் பிரவேசிப்பதில்லை. கொள்ளையாவார்கள் என்று நீங்கள் சொன்ன உங்கள் குழந்தைகளையோ நான் அதில் பிரவேசிக்கச் செய்வேன்; நீங்கள் அசட்டைப்பண்ணின தேசத்தை அவர்கள் கண்டறிவார்கள். உங்கள் பிரேதங்களோ இந்த வனாந்தரத்திலே விழும். அவைகள் வனாந்தரத்திலே விழுந்து தீருமட்டும், உங்கள் பிள்ளைகள் நாற்பதுவருஷம் வனாந்தரத்திலே திரிந்து, நீங்கள் சோரம்போன பாதகத்தைச் சுமப்பார்கள். நீங்கள் தேசத்தை சுற்றிப்பார்த்த நாற்பதுநாள் இலக்கத்தின்படியே, ஒவ்வொரு நாள் ஒவ்வொரு வருஷமாக, நீங்கள் நாற்பது வருஷம் உங்கள் அக்கிரமங்களைச் சுமந்து, என் உடன்படிக்கைக்கு வந்த மாறுதலை உணருவீர்கள்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>எண்ணாகமம் புத்தகத்தின் பெரும்பாலான நிகழ்வுகள் வனாந்தரத்தில் நடைபெறுகின்றன, அதுவும் முதன்மையாக இஸ்ரவேலர்கள் அலைந்து திரிந்த இரண்டாம் மற்றும் நாற்பதாம் ஆண்டுகளுக்கு இடையில் உள்ளவைகள் விவரிக்கப்பட்டுள்ளன. புத்தகத்தின் முதல் 25 அதிகாரங்கள் வனாந்தரத்தில் இஸ்ரவேலர்களின் முதல் தலைமுறையின் அனுபவங்களை விவரிக்கின்றன, மீதமுள்ள புத்தகம் இரண்டாம் தலைமுறையின் அனுபவங்களை விவரிக்கிறது. கீழ்ப்படிதல் மற்றும் கலகத்தை தொடர்ந்து மனந்திரும்புதல் மற்றும் ஆசிர்வாதம் இந்த புத்தகத்தின் கருப்பொருள் ஆகும், இது முழு புத்தகத்திலும், பழைய ஏற்பாட்டிலும் இயங்குகிறது.</p><p>தேவனுடைய பரிசுத்தத்தின் கருப்பொருள் லேவியராகமம் புத்தகத்திலிருந்து எண்ணாகமம் புத்தகத்திலும் தொடர்கிறது, இது தேவனுடைய அறிவுறுத்தலையும் அவருடைய ஜனங்களை வாக்குறுதியளிக்கப்பட்ட கானான் தேசத்திற்குள் நுழையத் தயார்படுத்துவதையும் வெளிப்படுத்துகிறது. எண்ணாகமம் புத்தகத்தின் முக்கியத்துவம் புதிய ஏற்பாட்டில் பல முறை குறிப்பிடப்படுவதன் மூலம் குறிக்கப்படுகிறது. பரிசுத்த ஆவியானவர் 1 கொரிந்தியர் 10:1-12-ல் குறிப்பிடப்பட்டுள்ள காரியங்கள், எண்ணாகமம் புத்தகத்திற்கு சிறப்பு கவனம் செலுத்தும்படி சித்தமானார். \"இவைகளெல்லாம் திருஷ்டாந்தங்களாக அவர்களுக்குச் சம்பவித்தது\" என்ற வார்த்தைகள் இஸ்ரவேலர்களின் பாவத்தையும், தேவன் அவர்களுக்குள்ள அதிருப்தியாய் இருந்ததையும் குறிக்கிறது.</p><p>ரோமர் 11:22 ல் பவுல் \"தேவனுடைய தயவையும் கண்டிப்பையும்\" பற்றி பேசுகிறார். சுருக்கமாக, இதுதான் எண்ணாகமம் புத்தகத்தின் செய்தி. வாக்குப்பண்ணப்பட்ட தேசத்திற்குள் ஒருபோதும் நுழையாதவர்கள், வனாந்தரத்தில் கலகக்கார தலைமுறையினரின் மரணத்தில் தேவனுடைய தீவிரம் காணப்படுகிறது. தேவனுடைய நன்மை புதிய தலைமுறையில் உணரப்படுகிறது. இந்த ஜனங்கள் தங்கள் நிலத்தை வாக்குப்பண்ணப்பட்ட தேசத்தில் சுதந்தரிக்கும் வரை தேவன் அவர்களைப் பாதுகாத்து, போஷித்து வழி நடத்தினார். இது எப்போதும் இறையாண்மை ஒற்றுமையுடன் இருக்கும் தேவனுடைய நீதியையும் அன்பையும் நினைவூட்டுகிறது.</p><p><b>முன்னிழல்கள்:</b></p><p>தம்முடைய ஜனத்தின் சார்பாக நியாயப்பிரமாணத்தை நிறைவேற்ற வந்த இயேசு கிறிஸ்துவில் அவருடைய மக்கள் பரிசுத்தத்திற்கான தேவனுடைய கோரிக்கையை முழுமையாகவும் இறுதியாகவும் திருப்தி அடைகிற வகையில் செய்தது (மத்தேயு 5:17). வாக்குறுதியளிக்கப்பட்ட மேசியாவின் கருத்து புத்தகத்தில் பரவி இருக்கிறது. சிவப்பு கடாரியின் பலியானது 19 ஆம் அதிகாரத்திலுள்ள சம்பவம் \"கறைதிரை இல்லாமல் மாசற்ற\" கிறிஸ்துவை முன்னிலைப்படுத்துகிறது, நம்முடைய பாவங்களுக்காக பலியிடப்பட்ட மாசற்ற தேவனுடைய ஆட்டுக்குட்டியாக இயேசு இருக்கிறார். உடல் ரீதியான குணப்படுத்துதலுக்காக மரத்தில் உயர்த்தப்பட்ட வெண்கல பாம்பின் உருவம் (அத்தியாயம் 21) கிறிஸ்துவின் சிலுவையின் மரணம் அல்லது வார்த்தையின் ஊழியத்தை முன்னறிவிக்கிறதாக இருக்கிறது, விசுவாசத்தினாலே அவரைப் பார்க்கிறவருக்கு ஆவிக்குரிய சுகம் கிடைக்கும்.</p><p>24 ஆம் அத்தியாயத்தில், பிலேயாமின் நான்காவது தேவ வாக்கு யாக்கோபிலிருந்து புறப்படவிருக்கும் நட்சத்திரம் மற்றும் செங்கோல் பற்றி பேசுகிறது. வெளிப்படுத்துதல் 22:16-ல் \"அதிகாலையின் நட்சத்திரம்\" என்று அழைக்கப்படும் கிறிஸ்துவின் தீர்க்கதரிசனம் இங்கே உள்ளது, அவருடைய மகிமை, பிரகாசம், கனம் மற்றும் அவரால் ஒளியும் பிரகாசமும் வருகிறது. அவரது ராஜரீகத்தன்மை காரணமாக அவர் ஒரு செங்கோல், அதாவது செங்கோல் தாங்கி என்றும் ராஜாவாக இருக்கிறார் என்றும் அழைக்கப்படலாம். அவர் ஒரு ராஜாவின் பெயரை மட்டுமல்ல, ஒரு ராஜ்யத்தையும் கொண்டிருக்கிறார், மேலும் கிருபை, இரக்கம் மற்றும் நீதியின் செங்கோலுடன் அவர் ஆட்சி செய்கிறார்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>புதிய ஏற்பாட்டில் எண்ணாகமத்திலிருந்து உருவாக்கப்பட்ட ஒரு முக்கிய இறையியல் கருப்பொருள் என்னவென்றால், பாவமும் அவநம்பிக்கையும், குறிப்பாக கலகம் செய்து கிளர்ச்சி உண்டாக்குதல், தேவனுடைய நியாயத்தீர்ப்பை அறுவடை செய்கிறது. 1 கொரிந்தியர் குறிப்பாக கூறுகிறது - எபிரெயர் 3:7-4:13 வரையிலுள்ள வேதபாகமும் இதை வலுவாகக் குறிக்கிறது - இந்த நிகழ்வுகள் யாவும் விசுவாசிகள் மிகவும் கவனமாக கவனிக்கவும் தவிர்க்கவும் எடுத்துக்காட்டுகளாக எழுதப்பட்டுள்ளன. நாம் \"தீய காரியங்களில் நம் இருதயங்களை அமைத்துக் கொள்ளக்கூடாது\" (வச. 6), அல்லது பாலியல் ஒழுக்கக்கேடானவர்களாக இருக்கக்கூடாது (வச. 8), அல்லது தேவனை சோதனைக்குட்படுத்த கூடாது (வச. 9) அல்லது வலுக்கட்டாயமாக குறைகூறவும் கூடாது (வச. 10).</p><p>இஸ்ரவேலர் தங்கள் கிளர்ச்சியின் காரணமாக ஏறக்குறைய 40 வருடங்கள் வனாந்தரத்தில் அலைந்ததைப் போலவே, சில சமயங்களில் தேவன் நம்மை அவரிடமிருந்து விலகி அலையவும், தனக்கு எதிராக கலகம் செய்யும்போது தனிமையும் ஆசீர்வாதங்கள் இல்லாதிருக்கவும் அனுமதிக்கிறார். ஆனால் தேவன் உண்மையுள்ளவர், நீதியுள்ளவர், இஸ்ரவேலரை அவருடைய இருதயத்தில் சரியான இடத்திற்கு மீட்டெடுத்தது போலவே, நாம் மனந்திரும்பி அவரிடம் திரும்பி வந்தால், கிறிஸ்தவர்களை ஆசீர்வதிக்கும் இடத்திற்கு நெருக்கமான கூட்டுறவுக்கும் அவர் எப்போதும் மீட்டெடுப்பார் (1 யோவான் 1:9 ).</p><p>சுமார் கி.மு. 1571 (1527) - மோசேயின் பிறப்பு</p><p>சுமார் கி.மு.1491 (1446) - யாத்திராகம புறப்படுதல்</p><p>சுமார் கி.மு. 1490 (1445) - சீனாயில் முதல் கணக்கெடுப்பு</p><p>சுமார் கி.மு. 1490 (1445) - கானானை ஒற்று நோக்குதல்</p><p>சுமார் கி.மு.1452 (1407) - இரண்டாம் கணக்கெடுப்பு</p><p>சுமார் கி.மு. 1452 (1407) - ஆரோனும் மிரியாமும் மோசேயும் மரித்தல்</p><p>சுமார் கி.மு.1451 (1406) - இஸ்ரவேலர் கானானில் நுழைதல்</p><p>சுமார் கி.மு. 1434 (1375) - யோசுவாவின் மரணம்</p><p><b>ஆசிரியர் குறிப்பு.</b></p><p>பெயர் - மோசே (பொருள்: இழுத்தெடுக்கப்பட்டவர்)</p><p>பெற்றோர் - தந்தை அம்ராம்,</p><p>தாய் - யோகெபேத் (யாத் 6 : 20). பின்பு பார்வோனின் மகளால் தத்தெடுக்கப்பட்டவர்</p><p>சொந்த இடம் - எகிப்து</p><p>தொழில் - அரண்மனை கல்வி, பின்பு ஆடு மேய்ப்பு அதன்பின் இலட்சக்கணக்கான மக்களை கானானுக்கு வழிநடத்தியது\"</p><p>திருப்புமுனை  - மந்தைமேய்த்துக் கொண்டிருக்கும்போது\" முட்செடியில் தேவனைத் தரிசித்தபின் வந்த அழைப்பு</p><p>ஆர்வம் - எபிரெயரை விடுவித்து, பத்திரமாக</p><p>கானானுக்கு வழிநடத்துவது</p><p>சாதனைகள்  - பார்வோனுக்கு முன் அற்புதங்களைச் செய்தது, ஐந்தாகமங்களை எழுதியது. உலகத்தோற்றம் பற்றிய</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 4-ஆம் நூல்</p><p>அதிகாரங்கள் - 36</p><p>வசனங்கள் - 1,288</p><p>கேள்விகள் - 59</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 42</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 15</p><p>தேவனின் சிறப்புச் செய்திகள் - 72</p><p>கட்டளைகள் - 554</p><p>வாக்குத்தத்தங்கள் - 5</p><p>எச்சரிக்கைகள் - 79</p>'),
 (400,'<p><b>மீகாவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>மீகா புத்தகத்தின் எழுத்தாளர் மீகா தீர்க்கதரிசியாகும் (மீகா 1:1).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>மீகாவின் புத்தகம் கி.மு. 735 முதல் கி.மு. 700 வரையிலான காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாக நம்பபடுகிறது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>மீகா புத்தகத்தின் செய்தியானது, நியாயத்தீர்ப்பு மற்றும் நம்பிக்கையின் சிக்கலான கலவையாகும். ஒருபுறம், தீர்க்கதரிசனங்கள் சமூக தீமைகள், ஊழல் நிறைந்த தலைமை மற்றும் உருவ வழிபாடு ஆகியவற்றிற்காக இஸ்ரவேல் மீது நியாயத்தீர்ப்பை அறிவிக்கின்றன. இந்த தீர்ப்பு சமாரியா மற்றும் எருசலேமின் அழிவில் உச்சம் பெறும் என்று எதிர்பார்க்கப்பட்டது. மறுபுறம், புத்தகம் தேசத்தின் மறுசீரமைப்பை மட்டுமல்ல, இஸ்ரவேல் மற்றும் எருசலேமின் மாற்றத்தையும் உயர்த்தலையும் அறிவிக்கிறது. நம்பிக்கை மற்றும் அழிவின் செய்திகள் முரண்பாடானவை அல்ல, இருப்பினும், மறுசீரமைப்பு மற்றும் மாற்றம் நியாயத்தீர்ப்புக்குப் பிறகுதான் நடைபெறுகின்றன.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>மீகா 1:2, \"சகல ஜனங்களே, கேளுங்கள், பூமியே, அதிலுள்ளவைகளே, செவிகொடுங்கள்; கர்த்தராகிய ஆண்டவர் தம்முடைய பரிசுத்த ஆலயத்திலிருக்கிற ஆண்டவரே, உங்களுக்கு விரோதமாகச் சாட்சியாயிருப்பார்.\"</p><p>மீகா 5:2, \"எப்பிராத்தா என்னப்பட்ட பெத்லகேமே, நீ யூதேயாவிலுள்ள ஆயிரங்களுக்குள்ளே சிறியதாயிருந்தும், இஸ்ரவேலை ஆளப்போகிறவர் உன்னிடத்திலிருந்து புறப்பட்டு என்னிடத்தில் வருவார்; அவருடைய புறப்படுதல் அநாதி நாட்களாகிய பூர்வத்தினுடையது.\"</p><p>மீகா 6:8, \"மனுஷனே, நன்மை இன்னதென்று அவர் உனக்கு அறிவித்திருக்கிறார்; நியாயஞ்செய்து, இரக்கத்தைச் சிநேகித்து, உன் தேவனுக்கு முன்பாக மனத்தாழ்மையாய் நடப்பதை அல்லாமல் வேறே என்னத்தைக் கர்த்தர் உன்னிடத்தில் கேட்கிறார்.</p><p>மீகா 7:18-19, \"தமது சுதந்தரத்தில் மீதியானவர்களுடைய அக்கிரமத்தைப் பொறுத்து, மீறுதலை மன்னிக்கிற தேவரீருக்கு ஒப்பான தேவன் யார்? அவர் கிருபைசெய்ய விரும்புகிறபடியால் அவர் என்றென்றைக்கும் கோபம் வையார். அவர் திரும்ப நம்மேல் இரங்குவார்; நம்முடைய அக்கிரமங்களை அடக்கி, நம்முடைய பாவங்களையெல்லாம் சமுத்திரத்தின் ஆழங்களில் போட்டுவிடுவார்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>ஜனங்களை சுரண்டி தவறாக வழிநடத்தும் இஸ்ரவேலின் ஆட்சியாளர்கள், ஆசாரியர்கள் மற்றும் தீர்க்கதரிசிகளை மீகா தீர்க்கதரிசி கடுமையாகக் கண்டிக்கிறார். அவர்களுடைய செயல்களால் தான் எருசலேம் அழிக்கப்படும். எருசலேமிலிருந்து பாபிலோனுக்குச் செல்லும் மக்களின் விடுதலையை மீகா தீர்க்கதரிசி அறிவித்து, தனக்கு எதிராகக் கூடியிருந்த தேசங்களை அழிக்க எருசலேமுக்கு ஒரு புத்திமதியுடன் முடிக்கிறார். தேசத்தைப் பாதுகாக்க சிறந்த ஆட்சியாளர் பெத்லகேமில் இருந்து வருவார் என்று, தீர்க்கதரிசி யாக்கோபின் எஞ்சியவர்களின்/மீதியானவர்களின் வெற்றியை அறிவிக்கிறார், மேலும் ஒரு நாள் யெகோவா விக்கிரகாராதனை மற்றும் இராணுவ வலிமையை நம்பியிருக்கும் தேசத்தை சுத்திகரிக்கும் ஒரு நாளை முன்னறிவிப்பார். நீதி மற்றும் விசுவாசத்திற்கான யெகோவாவின் தேவையின் ஒரு சக்திவாய்ந்த மற்றும் சுருக்கமான திரட்டை தீர்க்கதரிசி முன்வைக்கிறார், மேலும் ஓம்ரி மற்றும் ஆகாபின் வழிகளைப் பின்பற்றியவர்கள் மீது நியாயத்தீர்ப்பை அறிவிக்கிறார். ஒரு புலம்பலின் கூறுகளை உள்ளடக்கிய ஒரு தீர்க்கதரிசன வழிபாட்டுடன் புத்தகம் நிறைவடைகிறது. இஸ்ரவேல் தனது பாவத்தை ஒப்புக்கொள்கிறது மற்றும் யெகோவாவின் வல்லமைமிக்க செயல்களின் மூலம் விடுதலையை உறுதி செய்கிறது.</p><p><b>முன்னிழல்கள்:</b></p><p>மீகா 5:2-ல், பெத்லகேமில் பிறந்த ராஜாவைத் தேடிய சாஸ்திரிகளால் மேற்கோள் காட்டப்பட்ட ஒரு மேசியா தீர்க்கதரிசனம் (மத்தேயு 2:6) கொடுக்கப்பட்டுள்ளது. கிழக்கிலிருந்து வந்த இந்த சாஸ்திரிகள் எபிரெய வேதாகமத்தை நன்கு அறிந்திருந்ததால், பெத்லகேம் என்ற சிறிய கிராமத்திலிருந்து உலகத்தின் மெய்யான ஒளியான சமாதான பிரபு வெளியே வருவார் என்பதை அவர்கள் அறிந்தார்கள். மீகாவின் பாவம், மனந்திரும்புதல் மற்றும் மீட்டெடுப்பு பற்றிய செய்தி அதன் இறுதி நிறைவேற்றத்தை இயேசு கிறிஸ்துவில் காண்கிறது, அவர் நம்முடைய பாவங்களுக்கான பரிகாரம் (ரோமர் 3:24-25) மற்றும் தேவனிடத்திற்கு செல்வதற்கான ஒரே வழியாகும் (யோவான் 14:6).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>தேவன் எச்சரிக்கைகளை அளிக்கிறார், எனவே அவருடைய கோபத்தை நாம் அனுபவிக்க வேண்டியதில்லை. தேவனுடைய எச்சரிக்கைகள் செவிசாய்க்கப்படாவிட்டால், அவருடைய குமாரனின் பலியில் பாவத்திற்கான அவரது ஏற்பாடு நிராகரிக்கப்பட்டால் நியாயத்தீர்ப்பு நிச்சயமாக வரும். கிறிஸ்துவை விசுவாசிக்கிறவர்களுக்கு, தேவன் நம்மை ஒழுங்குபடுத்துவார் – அதாவது வெறுப்பிலிருந்து அல்ல, ஆனால் அவர் நம்மை நேசிப்பதால் அப்படிச் செய்வார். பாவம் அழிக்கிறது என்பதை அவர் நன்கு அறிவார், நாம் பரிபூரணராய் இருக்க வேண்டும் என்று அவர் விரும்புகிறார். மறுசீரமைப்பின் வாக்குறுதியாக இருக்கும் இந்த பரிபூரணம் அவருக்குக் கீழ்ப்படிந்தவர்களுக்காக காத்திருக்கிறது.</p><p>சுமார் கி.மு. 731 (782) - இரண்டாம் யெரொபெயாம் அரியணையேறுதல்</p><p>சுமார் கி.மு.695 (748) - யோதாம் தந்தையுடன் கூட்டாட்சி தொடங்குதல்</p><p>சுமார் கி.மு.687 (740) - யோதாம் அரியணையேறுதல்</p><p>சுமார் கி.மு.695 - 643 (748-696) - மீகாவின் தீர்க்கதரிசனப் பணி?</p><p>சுமார் கி.மு. 681 (732) - ஆகாஸ் யூதாவின் அரசராதல், ஓசியா இஸ்ரவேலின் அரசராதல்</p><p>சுமார் கி.மு. 671 (722) - இரண்டாம் சர்கோன் அரசர் இஸ்ரவேலைச் சிறை பிடித்தல்</p><p>சுமார் கி.மு. 665 (716) - எசேக்கியா அரசர் யூதாவின் மேல் அரசராதல்</p><p>சுமார் கி.மு. 650 (701) - எருசலேம் அசீரியா முற்றுகை யிடலும் தோல்வியும்</p><p>சுமார் கி.மு. 645 (696) மனாசே எசேக்கியாவுடன் கூட்டாட்சி தொடங்குதல்?</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - மீகா (கர்த்தரைப் போன்றவர் யார்?) இது மிகாயா என்ற பெயரின் சுருக்க வடிவம்</p><p>தகப்பனார் பெயர் - தெரியவில்லை</p><p>ஊர் - மொரோசா (மோர்ஷேக்காத் (1 : 1, 14)</p><p>சிறப்புப் பெயர் - \"ஏழைகளின் தீர்க்கதரிசி’ \"ஒடுக்கப்பட்டோரின் குரல்\"</p><p>சாதனை - இவரது குரல் எசேக்கியா அரசரின் கால சீர்திருத்தத்துக்கு உதவியது என்பர்</p><p>புகழ் - மேசியாவின் பிறப்பிடத்தைச் சரியாக சுமார் 700 ஆண்டுகளுக்கு முன்பே கூறியவர் (5:2)</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 33-வது நூல்</p><p>அதிகாரங்கள் - 7</p><p>வசனங்கள் - 105</p><p>கட்டளைகள் - 20</p><p>கேள்விகள் - 23</p><p>வாக்குத்தத்தங்கள் - 2</p><p>எச்சரிக்கைகள் - 123</p><p>நிறைவேறாத தீர்க்கதரிசனங்கள் - 32</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 91</p><p>தேனிடமிருந்து சிறப்புச் செய்திகள் - 7</p>'),
 (410,'<p><b>நாகூம் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>நாகூம் புத்தகத்தின் எழுத்தாளர் தன்னை எல்கோசானாகிய நாகூம் (நாகூம் என்றால் எபிரேய மொழியில் \"தேற்றுகிறவர்\" அல்லது \"ஆறுதலுள்ளவர்\" என்று அர்த்தமாகும்) என்று அடையாளப்படுத்துகிறார் (1:1). எந்தவொரு உறுதியான ஆதாரமும் இல்லை என்றாலும் அந்த நகரம் எங்கிருந்தது என்பதற்கு பல கோட்பாடுகள் உள்ளன. அத்தகைய ஒரு கோட்பாடு என்னவென்றால், இது கலிலேயா கடலின் அருகாமையில் இருந்ததும் பின்னர் கப்பர்நகூம் என்று அழைக்கப்படுகிறது என்றும் கூறுகிறார்கள் (அதாவது \"நாகூம் கிராமம்\" என்று பொருள்படும்).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>நாகூமைப் பற்றி நமக்குத் தெரிந்த குறைந்த அளவிலான தகவல்களைக் கொண்டு நாம் செய்யக்கூடியது என்னவென்றால், நாகூம் புத்தகம் கி.மு. 663 முதல் கி.மு. 612 வரையிலுள்ள கால இடைவெளியில் எழுதப்பட்ட கால அளவைக் குறிப்பதாகும். இந்த காலத்தை தீர்மானிக்க உதவும் இரண்டு நிகழ்வுகள் குறிப்பிடப்பட்டுள்ளன. முதல் நாகூம் எகிப்தில் உள்ள தெபேஸ் (நோ அமோன்) கடந்த காலங்களில் அசீரியர்களிடம் (கி.மு. 663) விழுந்ததைக் குறிப்பிடுகிறார், எனவே அது ஏற்கனவே நடந்த சம்பவமாகும். இரண்டாவதாக, நாகூமின் தீர்க்கதரிசனங்களின் எஞ்சியவை கி.மு. 612 ல் நிறைவேறியது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>நாகூம் இந்த புத்தகத்தை நினிவே மக்களுக்கு ஒரு எச்சரிக்கையாகவோ அல்லது \"மனந்திரும்புதலுக்கான அழைப்பாகவோ\" எழுதவில்லை. அவர்கள் ஏற்கனவே துன்மார்க்கமான வழிகளில் தொடர்ந்தால் என்ன நடக்கும் என்ற வாக்குறுதியுடன் 150 ஆண்டுகளுக்கு முன்பே யோனா தீர்க்கதரிசியை தேவன் அவர்களிடத்தில் அனுப்பியிருந்தார். அந்த நேரத்தில் மக்கள் மனந்திரும்பியிருந்தார்கள், ஆனால் இப்போது முன்பு இருந்ததை விட இன்னும் மோசமாக வாழ்ந்தார்கள். அசீரியர்கள் தங்கள் வெற்றிகளில் முற்றிலும் மிருகத்தனமாகிவிட்டார்கள் (பாதிக்கப்பட்டவர்களின் உடல்களை மரங்களில் தொங்கவிட்டு, மற்ற கொடுமைகளுக்கிடையில் தங்கள் கூடாரங்களின் சுவர்களில் தோலை வைப்பார்கள்). தேவன் நியாயத்தீர்ப்பை அறிவித்ததாலும், அசீரியர்கள் தங்களுக்குத் தேவையானதைப் பெறுவார்கள் என்பதாலும் நாகூம் யூத ஜனத்தை விரக்தியடைய வேண்டாம் என்று சொல்லிக் கொண்டிருந்தார்.</p><p><b>திறவுகொல் வசனங்கள்:</b></p><p>நாகூம் 1:7, \"கர்த்தர் நல்லவர், இக்கட்டு நாளிலே அரணான கோட்டை; தம்மை நம்புகிறவர்களை அறிந்திருக்கிறார்.\"</p><p>நாகூம் 1:14அ, \"உன்னைக்குறித்துக் கர்த்தர் கட்டளைகொடுத்திருக்கிறார்; இனி உன் பேருக்கு வித்துவிதைக்கப்படுவதில்லை.\"</p><p>நாகூம் 1:15அ, \"இதோ, சமாதானத்தைக் கூறுகிற சுவிசேஷகனுடைய கால்கள் மலைகளின்மேல் வருகிறது.\" (ஏசாயா 52:7 மற்றும் ரோமர் 10:15 ஆகிய வசனங்களை காண்க)</p><p>நாகூம் 2:13அ, \"இப்போதும் நான் உன்மேல் இருக்கிற அவன் நுகத்தை முறித்து உன் கட்டுகளை அறுப்பேன்.\"</p><p>நாகூம் 3:19, \"உன் நொறுங்குதலுக்குப் பரிகாரம் இல்லை; உன் காயம் கொடியது; உன் செய்தியைக் கேட்பவர் யாவரும் உன்பேரில் கைகொட்டுவார்கள்; உன் பொல்லாப்பு எந்நேரமும் யார்பேரிலேதான் பாயாமற்போயிற்று?\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>நினிவே பட்டணம் ஒருமுறை யோனாவின் பிரசங்கத்திற்கு செவிகொடுத்து, கர்த்தராகிய யெகோவா தேவனை சேவிப்பதற்காக தீய வழிகளிலிருந்து விலகியது. ஆனால் 150 ஆண்டுகளுக்குப் பிறகு, நினிவே உருவ வழிபாடு, வன்முறை மற்றும் ஆணவத்திற்குத் திரும்பினது (நாகூம் 3:1-4). தேவன் தம்முடைய தீர்க்கதரிசிகளில் ஒருவரை நினிவேவுக்கு அனுப்புகிறார், நகரத்தின் அழிவில் தீர்ப்பைப் பிரசங்கித்து அவர்களை மனந்திரும்பும்படி அறிவுறுத்துகிறார். துரதிர்ஷ்டவசமாக, நினிவே மக்கள் நாகூமின் எச்சரிக்கையை கவனிக்கவில்லை, இறுதியில் நகரம் பாபிலோனின் ஆதிக்கத்தின் கீழ் கொண்டுவரப்பட்டது.</p><p><b>முன்னிழல்கள்:</b></p><p>மேசியா மற்றும் அவருடைய ஊழியத்தைப் பற்றியும், அவருடைய காலத்தில் கிறிஸ்துவின் அப்போஸ்தலர்களைப் பற்றியும் பவுல் ரோமர் 10:15-ல் நாகூம் 1:15 ஐ மீண்டும் மேற்கோள்காட்டி கூறுகிறார். நற்செய்தியை அறிவிக்கிற எந்தவொரு ஊழியக்காரராக இருந்தாலும் அவர்கள் \"சமாதானத்தின் நற்செய்தியைப் பிரசங்கிப்பதே\" அவர்களின் வேலையாக இருக்கிறது என்பதையும் புரிந்து கொள்ளலாம். தேவன் கிறிஸ்துவின் இரத்தத்தினாலே பாவிகளுடன் சமாதானம் ஏற்படுத்தி, \"எல்லா புத்திக்கும் மேலான\" சமாதானத்தைத் தம் மக்களுக்கு அளித்துள்ளார் (பிலிப்பியர் 4:7). சிலுவையில் அறையப்பட்ட கிறிஸ்துவால் ஒப்புரவு, நீதி, மன்னிப்பு, ஜீவன் மற்றும் நித்திய இரட்சிப்பு போன்ற \"நல்ல விஷயங்களைப் பற்றிய நற்செய்தியைக் கொண்டுவருவதும்\" ஒரு போதகரின் பணியாகும். அத்தகைய நற்செய்தியைப் பிரசங்கிப்பதும், இதுபோன்ற செய்திகளைக் கொண்டுவருவதும் அவர்களின் கால்களை மிகவும் அழகாக ஆக்குகிறது. இங்குள்ள உருவாக சித்திரம் மற்றவர்களிடம் ஓடி, நற்செய்தியை அறிவிக்க ஆர்வமாகவும் மகிழ்ச்சியாகவும் இருக்கின்றதை காண்பிக்கிறது.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>தேவன் பொறுமையாகவும் கோபத்திற்கு நீடிய பொறுமையுள்ளவராகவும் இருக்கிறார். ஒவ்வொரு தேசமும் அவரை தங்கள் தேவன் என்று அறிவிக்க அவகாசம் தருகிறார். ஆனால் அவர் கேலி செய்யப்பட அனுமதிப்பதில்லை. எந்த நேரத்திலும் ஒரு தேசம் தன்னுடைய சொந்த நோக்கங்களை நிறைவேற்ற அவரிடமிருந்து விலகினால், அவர் நியாயத்தீர்ப்போடு வருகிறார். ஏறக்குறைய 220 ஆண்டுகளுக்கு முன்பு அமெரிக்கா வேதாகமத்தில் காணப்படும் கொள்கைகளால் வழிநடத்தப்பட்ட ஒரு தேசமாக உருவாக்கப்பட்டது. ஆனால் கடந்த 50 ஆண்டுகளில் மிகப்பெரிய மாற்றம் அடைந்துள்ளது, நாம் தினமும் எதிர் திசையில் திரும்பிப் போய்க் கொண்டிருக்கிறோம். கிறிஸ்தவர்களாகிய நாம் வேதாகமக் கொள்கைகளுக்காகவும், சத்தியத்திற்கான வேதப்பூர்வ உண்மைகளுக்காகவும் நிற்பது நமது கடமையாகும், இது நம் நாட்டின் ஒரே நம்பிக்கையாகும்.</p><p>சுமார் கி.மு. 670 (721) - இரண்டாம் சர்கோனால் இஸ்ரவேல் சிறையாதல்</p><p>சுமார் கி.மு. 650 -649 (702-701) - அசீரியாவின் சனகெரிப் எருசலேமை முற்றுகையிடல்</p><p>சுமார் கி.மு. 636 (687)  - மனாசே யூத அரசராதல்</p><p>சுமார் கி.மு. 648 (699) - அசூர்பானிபால் அசீரிய அரசராதல்</p><p>சுமார் கி.மு. 612 (663) - எகிப்திய தலைநகரான தேபேஸ் (நோ-அம்மோன்) அசீரியாவால் பிடிக்கப்படல்</p><p>சுமார் கி.மு. 561 (612) - நினிவேயின் வீழ்ச்சி</p><p>சுமார் கி.மு. 612 561- (663 612) - நாகூமின் தீர்க்கதரிசன காலம்?</p><p>சுமார் கி.மு. 554 (605) - நேபுகாத்நேச்சார் பாபிலோனில் அரசராதல்</p><p>சுமார் கி.மு. 535 (586) - எருசலேம் பாபிலோனால் சிறைபிடிக்கப்படல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - நாகூம் ( ஆறுதல்)</p><p>தகப்பனார் பெயர் - தெரியவில்லை</p><p>ஊர் - எல்கோஸ்</p><p>தொழில் - தெரியவில்லை</p><p>கோத்திரம் - தெரியவில்லை</p><p>சாதனை - நினிவேயின் அழிவை அப்படியே முன்னுரைத்தது.</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதமத்தின் 34-வது நூல்</p><p>அதிகாரங்கள் - 3</p><p>வசனங்கள் - 47</p><p>கேள்விகள் - 8</p><p>கட்டளைகள் - 5</p><p>எச்சரிக்கைகள் - 72</p><p>தீர்க்கதரிசனவசனங்கள் - 46</p><p>நிறைவேறாத தீர்க்கதரிசனங்கள் - 6</p><p>நிறைவேற வேண்டிய தீர்க்கநரிசனங்கள் - 40</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 2 (12:21)</p>'),
 (420,'<p><b>ஆபகூக் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>ஆபகூக் 1:1 ஆபகூக் என்னும் தீர்க்கதரிசி தரிசனமாய்க் கண்ட பாரம் என்று அடையாளப்படுத்துகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>ஆபகூக் புத்தகம் கி.மு. 610 முதல் கி.மு. 605 வரையிலுள்ள காலங்களுக்கு இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>தம்முடைய தேர்ந்தெடுக்கப்பட்ட ஜனத்தை எதிரிகளின் கைகளில் இருக்கும் தற்போதைய துன்பங்களை அனுபவிக்க தேவன் ஏன் அனுமதிக்கிறார் என்று ஆபகூக் யோசித்துக்கொண்டிருந்தார். தேவன் அதற்கு பதிலளிக்கிறார், ஆபகூக்கின் நம்பிக்கையும் மீட்டெடுக்கப்படுகிறது.</p><p><b>திறவுகொல் வசனங்கள்:</b></p><p>ஆபகூக் 1:2, \"கர்த்தாவே, நான் எதுவரைக்கும் உம்மை நோக்கிக் கூப்பிடுவேன். நீர் கேளாமலிருக்கிறீரே! கொடுமையினிமித்தம் நான் எதுவரைக்கும் உம்மை நோக்கிக் கூப்பிடுவேன், நீர் இரட்சியாமலிருக்கிறீரே!\"</p><p>ஆபகூக் 1:5, \"நீங்கள் புறஜாதிகளை நோக்கிப் பார்த்து, ஆச்சரியப்பட்டுப் பிரமியுங்கள்; விவரிக்கப்பட்டாலும் நீங்கள் விசுவாசியாத ஒரு கிரியையை உங்கள் நாட்களில் நடப்பிப்பேன்.\"</p><p>ஆபகூக் 1:12, \"கர்த்தாவே, நீர் பூர்வகாலமுதல் என் தேவனும் என் பரிசுத்தருமானவர் அல்லவா? நாங்கள் சாவதில்லை, கர்த்தாவே, நியாயத்தீர்ப்பு செய்ய அவனை வைத்தீர்; கன்மலையே, தண்டனை செய்ய அவனை நியமித்தீர்.\"</p><p>ஆபகூக் 2:2-4, \"அப்பொழுது கர்த்தர் எனக்குப் பிரதியுத்தரமாக: நீ தரிசனத்தை எழுதி, அதைக் கடந்தோடுகிறவன் வாசிக்கும்படிப் பலகைகளிலே தீர்க்கமாக வரை. குறித்தகாலத்துக்குத் தரிசனம் இன்னும் வைக்கப்பட்டிருக்கிறது; முடிவிலே அது விளங்கும், அது பொய் சொல்லாது; அது தாமதித்தாலும் அதற்குக் காத்திரு; அது நிச்சயமாய் வரும், அது தாமதிப்பதில்லை. இதோ, அகங்காரியாயிருக்கிறானே, அவனுடைய ஆத்துமா அவனுக்குள் செம்மையானதல்ல; தன் விசுவாசத்தினாலே நீதிமான் பிழைப்பான்.\"</p><p>ஆபகூக் 2:20, \"கர்த்தரோவென்றால், தமது பரிசுத்த ஆலயத்தில் இருக்கிறார்; பூமியெல்லாம் அவருக்கு முன்பாக மௌனமாயிருக்கக்கடவது.\"</p><p>ஆபகூக் 3:2, \"கர்த்தாவே, நீர் வெளிப்படுத்தினதை நான் கேட்டேன், எனக்குப் பயமுண்டாயிற்று; கர்த்தாவே, வருஷங்களின் நடுவிலே உம்முடைய கிரியையை உயிர்ப்பியும், வருஷங்களின் நடுவிலே அதை விளங்கப்பண்ணும், கோபித்தாலும் இரக்கத்தை நினைத்தருளும்.\"</p><p>ஆபகூக் 3:19, \"ஆண்டவராகிய கர்த்தர் என்பெலன்; அவர் என் கால்களை மான்கால்களைப்போலாக்கி, உயரமான ஸ்தலங்களில் என்னை நடக்கப்பண்ணுவார்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>தேவனால் தேர்ந்தெடுக்கப்பட்ட ஜனம் தங்கள் அடிமைத்தனத்தின் சிறையிருப்பில் ஏன் துன்பப்பட அனுமதிக்கப்படுகிறார்கள் என்பதற்கான பதிலுக்காக ஆபகூக் தேவனிடம் மன்றாடுவதன் மூலம் ஆபகூக் புத்தகம் தொடங்குகிறது (ஆபகூக் 1:1-4). கர்த்தர் தனது பதிலை ஆபகூக்கிற்கு அளிக்கிறார், \"நான் சொன்னாலும் நீங்கள் அதை நம்ப மாட்டீர்கள்\" (ஆபகூக் 1:5-11). ஆபகூக் பிறகு பின்வருமாறு கூறுகிறார், \"சரி, நீரே தேவன், ஆனால் இது ஏன் நடக்கிறது என்பதைப் பற்றி கூறும்\" (ஆபகூக் 1:17-2:1). தேவன் ஆபகூக்கிற்கு அவருக்கு மீண்டும் பதிலளித்து மேலும் தகவல்களைத் தருகிறார், பின்னர் பூமியை தனக்கு முன்னால் அமைதியாக இருக்கச் சொல்கிறார் (ஆபகூக் 2:2-20). இந்த சோதனைகள் மூலமாகவும், தேவன்மீது தனது வலுவான நம்பிக்கையை வெளிப்படுத்தும் ஒரு ஜெபத்தை ஆபகூக் எழுதுகிறார் (ஆபகூக் 3:1-19).</p><p><b>முன்னிழல்கள்:</b></p><p>விசுவாசத்தினால் நீதிமான் பிழைப்பான் என்னும் கோட்பாட்டை மீண்டும் வலியுறுத்த இரண்டு வெவ்வேறு சந்தர்ப்பங்களில் (ரோமர் 1:17; கலாத்தியர் 3:11) அப்போஸ்தலனாகிய பவுல் ஆபகூக் 2:4 ஐ குறிப்பிட்டு மேற்கோள் காட்டுகிறார். தேவனுடைய ஈவாகவும், கிறிஸ்துவின் மூலமாகவும் கிடைக்கக்கூடிய விசுவாசம் ஒரே நேரத்தில் இரட்சிக்கும் விசுவாசம் (எபேசியர் 2:8-9) மற்றும் வாழ்நாள் முழுவதும் நீடிக்கும் விசுவாசம் ஆகும். விசுவாசத்தினால் நித்திய ஜீவனை அடைகிறோம், அதே விசுவாசத்தினால் கிறிஸ்தவ வாழ்க்கையை வாழ்கிறோம். வசனத்தின் தொடக்கத்தில் உள்ள \"பெருமை\" போலல்லாமல், அவருடைய ஆத்துமா அவருக்குள் சரியாக இல்லை (NASB) மற்றும் அவரது ஆசைகள் நேர்மையானதாக இல்லை (NIV). ஆனால் கிறிஸ்துவை விசுவாசிப்பதன் மூலம் நீதிமான்களாகிய நாம் முற்றிலும் நீதியுள்ளவர்களாக இருக்கிறோம், ஏனென்றால் அவர் நம்முடைய பாவத்திற்காக அவருடைய பரிபூரண நீதியை பரிமாறிக்கொண்டார் (2 கொரிந்தியர் 5:21), அதுதான் விசுவாசத்தினாலே வாழ நமக்கு உதவியது.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>மரியாதை மற்றும் பயபக்தியுடன் இருந்தாலும், தேவன் என்ன செய்கிறார் என்று கேள்வி கேட்பது அனுமதிக்கப்படுகிறது என்பதே ஆபகூக்கின் வாசகருக்குள்ள விண்ணப்பம் ஆகும். சில நேரங்களில் என்ன நடக்கிறது என்பது நமக்குத் தெரியவில்லை, குறிப்பாக ஒரு குறிப்பிட்ட காலத்திற்கு நாம் துன்பத்தில் தள்ளப்பட்டால் அல்லது நாம் வெறுமனே துன்பங்களைப் பெறும்போது நம் எதிரிகள் முன்னேறுகிறார்கள் என்று தோன்றினால். எவ்வாறாயினும், எல்லாவற்றையும் கட்டுப்பாட்டில் வைத்திருக்கும் தேவன் ஒரு இறையாண்மையுள்ள, சர்வ வல்லமையுள்ள தேவன் என்பதை ஆபகூக் புத்தகம் உறுதிப்படுத்துகிறது. நாம் மௌனமாக இருந்து அவர் நமக்காக இருப்பதையும் செயல்படுவதையும் அறிந்து கொள்ள வேண்டும். அவர் தான் யார் என்று கூறுகிறாரோ அவர் அவராகவே கூறுகிறார், அவருடைய வாக்குறுதிகளை மெய்யாகவே நிறைவேற்றுகிறார். அவர் துன்மார்க்கரைத் தண்டிப்பார். நம்மால் அதைப் பார்க்க முடியாதபோது கூட, அவர் இன்னும் இப்பிரபஞ்சத்தின் சிம்மாசனத்தில் இருக்கிறார். இதில் நாம் தொடர்ந்து கவனம் செலுத்த வேண்டும்: \"ஆண்டவராகிய கர்த்தர் என்பெலன்; அவர் என் கால்களை மான்கால்களைப்போலாக்கி, உயரமான ஸ்தலங்களில் என்னை நடக்கப்பண்ணுவார்\" (ஆபகூக் 3:19). நாம் உயரத்திற்கு செல்ல உதவுவது, உலகத்திடமிருந்து நாம் ஒதுக்கி வைக்கப்பட்டுள்ள நிலையில் அவருடன் உயர்ந்த இடங்களுக்கு நம்மை அழைத்துச் செல்கிறது. சில சமயங்களில் நம்மைச் சேர்ப்பதற்கு நாம் செல்ல வேண்டிய வழி துன்பம் மற்றும் துக்கம் தான், ஆனால் நாம் அவரில் நிலைத்திருந்து அவரை முழுமனதோடு நம்பினால், அவர் நம்மை இருக்க விரும்புகிற இடத்திற்கு வெளியே வருவோம்.</p><p>சுமார் கி.மு. 670 (721) - அசீரியாவின் இரண்டாம் சார்கோன் இஸ்ரவேலைச் சிறைபிடித்தல்</p><p>சுமார் கி.மு. 561 (612) - நினிவே வீழ்ச்சியடைதல்</p><p>சுமார் கி.மு. 557 (608) - யூதாவின் அரசரான யோசியா போரில் மடிதல்</p><p>சுமார் கி.மு. 554 (605) - நேபுகாத் நேச்சாரின் புகழ்பெற்ற கர்கேமிஸ் வெற்றி யூதாவின் மேல் நேபுகாத்நேச்சாரின் முதல் படையெடுப்பு</p><p>சுமார் கி.மு. 557 555 - (608 606) - ஆபகூக்கின் தீர்க்கதரிசனம்?</p><p>சுமார் கி.மு: 546 (597) - \"நேபுகாத்நேச்சாரின் இரண்டாம் படையெடுப்பு</p><p>சுமார் கி.மு. 535 (586)  - யூதாமேல் நேபுகாத்நேச்சாரின் மூன்றாம் படையெடுப்பும் எருசலேம் வீழ்ச்சியும்</p><p>சுமார் கி.மு. 488 (539) - பாபிலோனின் வீழ்ச்சி</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - ஆபகூக்</p><p>தகப்பனார் பெயர் - தெரியவில்லை</p><p>ஊர் - தெரியவில்லை</p><p>தொழில் - தீர்க்கதரிசி? (1 : 1) தேவாலயப்பாடகர்? (3 : 19)</p><p>சாதனை - கேள்விகளால் பதிலைக் கண்டடைந்து விசுவாசத்தின் வைரவரிகளை வடித்தது.</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 35-வது நூல்</p><p>அதிகாரங்கள் - 3</p><p>வசனங்கள் - 56</p><p>கேள்விகள் - 12</p><p>கட்டளை - 1</p><p>எச்சரிக்கைகள் - 20</p><p>தீர்க்கதரிசன வசனங்கள் - 11</p><p>தேவளிடமிருந்து சிறப்புச் செய்திகள் 2 (1: 5. 2: 2).</p>'),
 (430,'<p><b>செப்பனியா புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>செப்பனியா 1:1, எஸ்கியாவின் குமாரனாகிய ஆமரியாவுக்குக் குமாரனான கெதலியா என்பவனுடைய மகனாகிய கூஷின் குமாரன் செப்பனியாவுக்கு உண்டான கர்த்தருடைய வசனம் என்று இந்த புத்தகத்தின் எழுத்தாளரை தீர்க்கதரிசியாகிய செப்பனியா என்று அடையாளப்படுத்துகிறது. செப்பனியா என்ற பெயரின் அர்த்தம் \"தேவனால் பாதுகாக்கப்பட்டவன்\" என்பதாகும்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>செப்பனியா புத்தகம் கி.மு. 735 முதல் கி.மு. 725 வரையிலுள்ள காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>செப்பனியாவின் நியாயத்தீர்ப்பு மற்றும் ஊக்கமளித்தல் பற்றிய செய்தி மூன்று முக்கிய கோட்பாடுகளைக் கொண்டுள்ளது: 1) தேவன் எல்லா தேசங்களுக்கும் தேவனாக இருக்கிறார். 2) துன்மார்க்கர் தண்டிக்கப்படுவார்கள், நீதிமான்கள் நியாயத்தீர்ப்பு நாளில் நிரூபிக்கப்படுவார்கள். 3) மனந்திரும்பி, தன்னை நம்புகிறவர்களை தேவன் ஆசீர்வதிப்பார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>செப்பனியா 1:18, \"கர்த்தருடைய உக்கிரத்தின் நாளிலே அவர்கள் வெள்ளியும் அவர்கள் பொன்னும் அவர்களைத் தப்புவிக்கமாட்டாது; அவருடைய எரிச்சலின் அக்கினியினால் தேசமெல்லாம் அழியும், தேசத்தின் குடிகளையெல்லாம் சடிதியாய் நிர்மூலம்பண்ணுவார்.\"</p><p>செப்பனியா 2:3, \"தேசத்திலுள்ள எல்லாச் சிறுமையானவர்களே, கர்த்தருடைய நியாயத்தை நடப்பிக்கிறவர்களே, அவரைத் தேடுங்கள்; நீதியைத் தேடுங்கள், மனத்தாழ்மையைத் தேடுங்கள்; அப்பொழுது ஒருவேளை கர்த்தருடைய கோபத்தின்நாளிலே மறைக்கப்படுவீர்கள்.\"</p><p>செப்பனியா 3:17, \"உன் தேவனாகிய கர்த்தர் உன் நடுவில் இருக்கிறார்; அவர் வல்லமையுள்ளவர், அவர் இரட்சிப்பார்; அவர் உன்பேரில் சந்தோஷமாய் மகிழ்ந்து, தம்முடைய அன்பினிமித்தம் அமர்ந்திருப்பார்; அவர் உன்பேரில் கெம்பீரமாய்க் களிகூருவார் (மகிழ்வுடன் பாடுவார்).\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>பூமி முழுவதிலும், யூதாவிலும், சுற்றியுள்ள நாடுகளிலும், எருசலேமிலும், எல்லா நாடுகளிலும் மேலும் வரும் கர்த்தருடைய நியாயத்தீர்ப்பை செப்பனியா உச்சரிக்கிறார். இதைத் தொடர்ந்து எல்லா தேசங்களுக்கும் கர்த்தருடைய ஆசீர்வாதத்தின் பிரகடனங்களும், குறிப்பாக யூதாவிலுள்ள எஞ்சியவர்களாகிய உண்மையுள்ள அவருடைய ஜனங்களுக்கு அருளப்போவதையும் விவரிக்கிறது.</p><p>கர்த்தருடைய வார்த்தையை அறிவிப்பதை அறிந்ததால், அப்படியே உள்ளதை உள்ளபடியாக அப்பட்டமாக பேச செபனியாவுக்கு தைரியம் இருந்தது. அவரது புத்தகம் \"கர்த்தருடைய வார்த்தை\" என்று தொடங்கி \"கர்த்தர் கூறுகிறார்\" என்று முடிகிறது. ஜனங்கள் வணங்கிய பல தெய்வங்களோ அல்லது அசீரிய இராணுவத்தின் வலிமையோ கூட அவர்களைக் காப்பாற்ற முடியாது என்பதை அவர் அறிந்திருந்தார். தேவன் கிருபையும் இரக்கமும் உடையவர், ஆனால் அவருடைய எச்சரிக்கைகள் அனைத்தும் புறக்கணிக்கப்படும்போது, நியாயத்தீர்ப்பு எதிர்பார்க்கப்படுகிறது. தேவனுடைய நியாயத்தீர்ப்பு நாள் வேதவசனங்களில் அடிக்கடி குறிப்பிடப்பட்டுள்ளது. தீர்க்கதரிசிகள் அதை \"கர்த்தருடைய நாள்\" என்று அழைத்தனர். எருசலேமின் வீழ்ச்சி போன்ற பல்வேறு நிகழ்வுகளை அவர்கள் தேவனுடைய நாளின் வெளிப்பாடுகள் என்று குறிப்பிட்டனர், அவை ஒவ்வொன்றும் கர்த்தருடைய இறுதி நாளை சுட்டிக்காட்டின.</p><p><b>முன்னிழல்கள்:</b></p><p>14-20 வரையிலுள்ள வசனங்களில் சீயோனின் இறுதி ஆசீர்வாதம் உச்சரிக்கப்படுகிறது. பெரும்பாலும் நிறைவேறாதவை, இவை கிறிஸ்துவின் இரண்டாம் வருகையை நிறைவுசெய்யக் காத்திருக்கும் மேசியாவைப்பற்றிய தீர்க்கதரிசனங்கள் என்ற முடிவுக்கு இட்டுச் செல்கின்றன. கர்த்தர் தம்முடைய ஜனங்களின் பாவங்களுக்காக மரிக்க வந்த கிறிஸ்துவின் மூலம்தான் நம்முடைய தண்டனையை நீக்கிவிட்டார் (செப்பனியா 3:15; யோவான் 3:16) என்கிறது. ஆனால் இஸ்ரவேல் தனது உண்மையான இரட்சகரை இன்னும் அங்கீகரிக்கவில்லை. இது இன்னும் நடக்கப்போகிறதாக இருக்கிறது (ரோமர் 11:25-27).</p><p>இஸ்ரவேலுக்கு சமாதானமும் பாதுகாப்பும் பற்றிய வாக்குறுதி, அவர்களுடைய ராஜா அவர்கள் மத்தியில் இருக்கும் காலம், கிறிஸ்து உலகத்தை நியாயந்தீர்க்கவும், அதை தனக்காக மீட்டுக்கொள்ளவும் திரும்பும்போது. அவருடைய உயிர்த்தெழுதலுக்குப் பிறகு அவர் பரலோகத்திற்கு ஏறியதைப் போலவே, அவர் திரும்பி வந்து பூமியில் ஒரு புதிய எருசலேமை அமைப்பார் (வெளி. 21). அந்த நேரத்தில், இஸ்ரேலுக்கான தேவனுடைய வாக்குறுதிகள் அனைத்தும் நிறைவேறும்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>பெயர்கள் மற்றும் சூழ்நிலைகளில் சில மாற்றங்களுடன், கி.மு. 7 ஆம் நூற்றாண்டின் தீர்க்கதரிசியாகிய இவர் இன்று நம்முடைய பிரசங்க மேடைகளில் நின்று, துன்மார்க்கருக்கு வரும் நியாயத்தீர்ப்பின் அதே செய்தியையும், உண்மையுள்ளவர்களுக்கு நம்பிக்கையையும் அளிக்க முடியும். கடவுள் தம்முடைய மக்களின் தார்மீக மற்றும் மத பாவங்களால் புண்படுத்தப்படுகிறார் என்பதை செப்பனியா நமக்கு நினைவூட்டுகிறார். தேவனுடைய மக்கள் வேண்டுமென்றே பாவம் செய்யும்போது தண்டனையிலிருந்து தப்ப மாட்டார்கள். தண்டனை வேதனையாக இருக்கலாம், ஆனால் அதன் நோக்கம் தண்டனைக்கு மாறாக மீட்பாக இருக்கலாம். தீமை தடையற்றது மற்றும் வெற்றி பெற்றது என்று தோன்றும் ஒரு காலத்தில் துன்மார்க்கத்தின் தண்டனையின் தவிர்க்க முடியாத தன்மையானது ஆறுதலளிக்கிறது. தேவனுக்குக் கீழ்ப்படிமல் இருப்பதற்கான சுதந்திரம் நமக்கு இருக்கிறது, ஆனால் அந்த கீழ்ப்படியாமையின் விளைவுகளிலிருந்து தப்பித்துக் கொள்வதற்கான சுதந்திரம் நமக்கு இல்லை. தேவனுக்கு உண்மையுள்ளவர்கள் ஒப்பீட்டளவில் குறைவாக இருக்கலாம், ஆனால் அவர் அவர்களை மறக்கவில்லை.</p><p>சுமார் கி.மு. 670 (721) - அசீரியாவின் கையில் இஸ்ரவேல் வீழ்தல்</p><p>சுமார் கி.மு. 665 (716) - எசேக்கியா யூதாவின் அரசராதல்</p><p>சுமார் கி.மு.645 (696) - மனாசே தந்தையுடன் கூட்டாட்சி தொடங்குதல்</p><p>சுமார் கி.மு. 591 (642) - ஆமோன் யூதா அரசராதல்</p><p>சுமார் கி.மு.589 (640) - யோசியா யூதா அரசராதல்</p><p>சுமார் கி.மு. 589 - 575 (640-628) - செப்பனியாவின் தீர்க்கதரிசன ஊழியம்?</p><p>சுமார் கி.மு.561(612) - நினிவே வீழ்ச்சியடைதல்</p><p>சுமார் கி.மு. 557 (608) - யோசியா அரசரின் மரணம்</p><p>சுமார் கி.மு. 535 (586) - யூதாவின் வீழ்ச்சி எருசலேமின் அழிவு</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - செப்பனியா (கர்த்தர் மறைக்கிறார்)</p><p>தகப்பனார் பெயர் - கூஷ்</p><p>ஊர் - எருசலேம்</p><p>கோத்திரம் - யூதா? எசேக்கியா அரசரின் வழிமரபில் பிறந்தவர் எனக் கருதப்படுகிறார்.</p><p>சாதனை - யோசியா அரசரின் ஆன்மீக சீர்திருத்தத்துக்கு உந்துதலளிக்கும் செய்திகளை வழங்கியது</p><p>சிறப்புப் பெயர் - \"தீர்க்கதரிசன ராந்தல் ஏந்திய தீர்க்கதரிசி’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 36-வது நூல்</p><p>அதிகாரங்கள் - 3</p><p>வசனங்கள் - 53</p><p>கட்டளைகள் - 14</p><p>வாக்குத்தத்தங்கள் - 4</p><p>எச்சரிக்கைகள் - 86</p><p>தீர்க்கதரிசனங்கள் - 45</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 5</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 40</p><p>தேவனிடமிருந்து சிறப்பு செய்திகள் - 4 (1: 2.,2 :1, 3: 18)</p>'),
 (440,'<p><b>ஆகாய் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>ஆகாய் 1:1, ஆகாய் புத்தகத்தின் எழுத்தாளரை, கர்த்தருடைய வார்த்தை ஆகாய் என்னும் தீர்க்கதரிசியின் மூலமாய் உண்டாகி என்று கூறுவதன் மூலம் அடையாளப்படுத்துகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>ஆகாய் புத்தகம் சுமார் கி.மு. 520 ஆண்டு காலளவில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>ஆகாய் தேவனுடைய மக்களுக்கு அவர்களின் முன்னுரிமைகள் குறித்து சவால் விடுக்க முயன்றவராவார். உள்ளூர் மற்றும் உத்தியோகபூர்வ எதிர்ப்பையும் மீறி ஆலயத்தைக் கட்டுவதன் மூலம் தேவனைப் பயபக்தியுடன் மகிமைப்படுத்த அவர் அவர்களை அழைத்தார். இந்த ஆலயம் சாலமோனின் அலங்காரமாக கட்டப்பட்டதுபோல அலங்கரிக்கப்படாது என்பதால் ஆகாய் அவர்களை சோர்வடைய வேண்டாம் என்று அழைத்தார். அவர்களுடைய வழிகளின் அசுத்தத்திலிருந்து விலகி, தேவனுடைய இறையாண்மை சக்தியை நம்பும்படி அவர் அவர்களுக்கு அறிவுறுத்தினார். இந்த நேரத்தில் தேவனுடைய ஜனம் எதிர்கொண்ட பிரச்சினைகள், ஜனங்கள் எவ்வாறு தைரியமாக தேவன்மீது நம்பிக்கை வைத்தார்கள், தேவன் அவர்களின் தேவைகளுக்கு எவ்வாறு வழங்கினார் என்பதை நினைவூட்டுவதே ஆகாய் புத்தகத்தின் நோக்கமாகும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>ஆகாய் 1:4, \"இந்த வீடு பாழாய்க் கிடக்கும்போது, நீங்கள் மச்சுப்பாவப்பட்ட உங்கள் வீடுகளில் குடியிருக்கும்படியான காலம் இதுவோ?\"</p><p>ஆகாய் 1:5-6, \"இப்போதும் சேனைகளின் கர்த்தர் சொல்லுகிறார்: உங்கள் வழிகளைச் சிந்தித்துப்பாருங்கள். நீங்கள் திரளாய் விதைத்தும் கொஞ்சமாய் அறுத்துக்கொண்டுவருகிறீர்கள்; நீங்கள் புசித்தும் திருப்தியாகவில்லை; குடித்தும் பரிபூரணமடையவில்லை; நீங்கள் வஸ்திரம் உடுத்தியும் ஒருவனுக்கும் குளிர்விடவில்லை; கூலியைச் சம்பாதிக்கிறவன் பொத்தலான பையிலே போடுகிறவனாய் அதைச் சம்பாதிக்கிறான்.\"</p><p>ஆகாய் 2:9, \"முந்தின ஆலயத்தின் மகிமையைப் பார்க்கிலும், இந்தப் பிந்தின ஆலயத்தின் மகிமை பெரிதாயிருக்கும் என்று சேனைகளின் கர்த்தர் சொல்லுகிறார்; இவ்விடத்திலே சமாதானத்தைக் கட்டளையிடுவேன் என்று சேனைகளின் கர்த்தர் உரைக்கிறார் என்று சொல் என்றார்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>தேவனுடைய ஜனங்கள் தங்கள் முன்னுரிமைகளை மறுபரிசீலனை செய்து, தைரியம் கொண்டு, தேவனுடைய வாக்குறுதிகளின் அடிப்படையில் செயல்படுவார்களா? தம்முடைய வார்த்தைகளுக்கு செவிசாய்க்கும்படி மக்களை எச்சரிக்க தேவன் முயன்றார். தேவன் அவர்களை எச்சரித்தது மட்டுமல்லாமல், தம்மைப் பின்பற்றும்படி அவர்களை ஊக்குவிப்பதற்காக அவர் தம் ஊழியர் ஆகாய் மூலமாகவும் வாக்குறுதிகளை அளித்தார். தேவனுடைய மக்கள் தங்கள் முன்னுரிமைகளை மாற்றியமைத்து, தங்கள் வாழ்க்கையில் தேவனை முதலிடத்தில் வைக்கத் தவறியதால், யூதா பாபிலோனிய தேசத்திற்கு சிறைப்படுத்தப்பட்டு போனது. தானியேலின் ஜெபத்திற்கு பதிலளிக்கும் விதமாகவும், தேவனுடைய வாக்குறுதிகளை நிறைவேற்றுவதற்காகவும், நாடுகடத்தப்பட்ட யூதர்களை மீண்டும் எருசலேமுக்கு செல்ல அனுமதிக்கும்படி தேவன் பெர்சிய ராஜாவான கோரேஸை வழிநடத்தினார். யூதர்களின் ஒரு குழு மிகுந்த மகிழ்ச்சியுடன் தங்கள் தேசத்திற்குத் திரும்பி, தேவனுக்கு தங்கள் வாழ்க்கையில் முதலிடம் கொடுத்து, அவரை வணங்கி, பாலஸ்தீனத்தில் வாழ்ந்த உள்ளூர் மக்களின் உதவியின்றி எருசலேம் ஆலயத்தை மீண்டும் கட்டத் தொடங்கினர். அவர்களின் தைரியமான நம்பிக்கை சுமார் 15 ஆண்டுகளாக உள்ளூர் மக்களிடமிருந்தும் பெர்சிய அரசாங்கத்திலிருந்தும் பெரும் எதிர்ப்பை சந்தித்தது.</p><p><b>முன்னிழல்கள்:</b></p><p>சிறிய தீர்க்கதரிசிகளின் பெரும்பாலான புத்தகங்களைப் போலவே, ஆகாய் புத்தகம் மறுசீரமைப்பு மற்றும் ஆசீர்வாத வாக்குறுதிகளுடன் முடிவடைகிறது. கடைசி வசனமான ஆகாய் 2:23-ல், \"என் ஊழியக்காரன்\" என்று செருபாபேலைக் குறிக்க தேவன் ஒரு தெளிவான மேசியாவின் தலைப்பைப் பயன்படுத்துகிறார் (2 சாமுவேல் 3:18; 1 ராஜா. 11:34; ஏசாயா 42:1–9; எசேக்கியேல் 37:24, 25). ஆகாய் மூலம், தேவன் அவரை ஒரு முத்திரை மோதிரம் போல ஆக்குவார் என்று உறுதியளிக்கிறார், இது கனம், அதிகாரம் மற்றும் வல்லமையின் அடையாளமாக இருந்தது, கடிதங்கள் மற்றும் கட்டளைகளை முத்திரையிட பயன்படுத்தப்படும் ஒரு ராஜாவின் செங்கோல் போன்றது. தேவனுடைய முத்திர வளையமாக, செருபாபேல், தாவீதின் வீட்டைக் குறிக்கிறது மற்றும் நாடுகடத்தப்பட்டதால் இடையூறுக்குள்ளான மேசியாவின் வம்சாவளியை மீண்டும் தொடங்குகிறது. கிறிஸ்துவின் ஆயிரமாண்டு ஆட்சியில் உச்சக்கட்டத்தை அடையும் தாவீதின் வழியில் வந்த ராஜாக்களின் வரிசையை செருபாபேல் மீண்டும் நிறுவினார். யோசேப்பின் பக்கத்திலும் (மத் 1:12) மரியாளின் பக்கத்திலும் (லூக்கா 3:27) என கிறிஸ்துவின் வரிசையில் செருபாபேல் தோன்றுகிறார்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>ஆகாய் புத்தகம் இன்றும் பெரும்பாலான மக்கள் எதிர்கொள்ளும் பொதுவான பிரச்சினைகளுக்கு கவனத்தை ஈர்க்கிறது. ஆகாய் நம்மிடம் கேட்கிறார்: 1) தேவனுடைய வேலையைச் செய்வதை விட நம்முடைய சொந்த இன்பங்களில் நாம் அதிக அக்கறை கொண்டிருக்கிறோமா என்று பார்த்து நமது முன்னுரிமைகளை ஆராயவேண்டும்; 2) நாம் எதிர்ப்பில் ஈடுபடும்போது அல்லது சூழ்நிலைகளை ஊக்கப்படுத்தும் போது தோல்வியுற்ற அணுகுமுறையை நிராகரிக்க வேண்டும்; 3) நம்முடைய தோல்விகளை ஒப்புக்கொண்டு, தேவனுக்கு முன்பாக பரிசுத்தமான வாழ்க்கையை வாழ முற்படவேண்டும்; 4) தேவனுக்காக தைரியமாக செயல்படவேண்டும், ஏனென்றால் அவர் எப்போதும் நம்முடன் இருக்கிறார், நம்முடைய சூழ்நிலைகளை முழுமையாகக் கட்டுப்படுத்துகிறார் என்ற உறுதி நமக்கு இருக்கிறது; மற்றும் 5) நாம் அவரை உண்மையாக சேவிக்கும்போது அவர் நம்மை தாராளமாக ஆசீர்வதிப்பார் என்பதை அறிந்து தேவனுடைய கைகளில் பாதுகாப்பாக சார்ந்து/சாய்ந்து கொள்ளவேண்டும்.</p><p>சுமார் கி.மு.535 (586) - எருசலேம் நேபுகாத்நேச்சாரால் அழிக்கப்படல்</p><p>சுமார் கி.மு.485 (536) - கோரேசின் விடுதலை கட்டளை</p><p>சுமார் கி.மு. 484 (535) - தேவாலயப் பணி தொடக்கமும் பின்பு கைவிடப்படுதலும்</p><p>சுமார் கி.மு. 469 (520) - ஆகாயும் சகரியாவும் தீர்க்கதரிசனப் பணியைத் தொடங்குதல் தேவாலயப்பணி மீண்டும் தொடங்கப்படல்</p><p>சுமார் கி.மு. 465 (516) - தேவாலயப்பணி நிறைவடைதல்</p><p>சுமார் கி.மு. 465 (516) - பண்டிகை கொண்டாடுதல்</p><p>சுமார் கி.மு.407 (458) - எஸ்றா எருசலேமுக்கு வருதல்</p><p>சுமார் கி.மு. 394 (445) - நெகேமியா எருசலேமுக்கு வருதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - ஆகாய் (பண்டிகை/எனது பண்டிகை)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - பாபிலோனில் பிறந்து வளர்ந்து பின் எருசலேமில் குடியேறியிருக்கலாம்</p><p>தொழில் - தெரியவில்லை</p><p>சாதனை - அரைகுறையாக நின்ற ஆலயத்தைக் கட்டி முடிக்க அறைகூவல் விடுத்து, அப்பணி நிறைவேறி பண்டிகை கொண்டாட வழிநடத்தியது (எஸ்றா 6 : 19-22)</p><p>சிறப்புப் பெயர் - சிறை மீட்சியின் பின் முழங்கிய முதல் தேவ சத்தம்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 37-வது நூல்</p><p>அதிகாரங்கள் - 2</p><p>வசனங்கள் - 38</p><p>கேள்விகள் - 8</p><p>கட்டளைகள் - 9</p><p>வாக்குத்தத்தங்கள் - 3</p><p>எச்சரிக்கைகள் - 14</p><p>தீர்க்கதரிசனங்கள் - 9</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 6</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 3</p><p>தேவளிடமிருந்து சிறப்புச் செய்திகள் - 5 ( 1:2 ,12; 2:1,10:20)</p>'),
 (450,'<p><b>சகரியா புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>சகரியா 1:1, சகரியா புத்தகத்தின் எழுத்தாளரை இத்தோவின் மகனான பெரகியாவின் குமாரனாகிய சகரியாவுக்கு உண்டான கர்த்தருடைய வார்த்தை என்று அடையாளப்படுத்துகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>சகரியா புத்தகம் கி.மு. 520 முதல் கி.மு. 470 வரையிலுள்ள காலக்கட்டத்தில் இரண்டு முதன்மை பிரிவுகளில் எழுதப்பட்டிருக்கலாம்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>தம்முடைய ஜனத்தினை கற்பிக்கவும், எச்சரிக்கவும், திருத்தவும் தேவன் தம்முடைய தீர்க்கதரிசிகளைப் பயன்படுத்தினார் என்று சகரியா வலியுறுத்தினார். துரதிர்ஷ்டவசமாக, அவர்கள் கேட்க மறுத்துவிட்டார்கள். அவர்கள் செய்த பாவம் தேவனுடைய தண்டனையைக் கொண்டு வந்தது. தீர்க்கதரிசனம் கூட சீர்கேட்டிற்குள்ளாக சென்று சிதைக்கப்படலாம் என்பதற்கான சான்றுகளையும் இந்த புத்தகம் கொண்டுள்ளது. இந்த காலகட்டத்தில் தீர்க்கதரிசனம் யூதர்களிடையே வெறுப்பை ஏற்படுத்தியது என்று வரலாறு காட்டுகிறது, இந்த காரியம் தேவனுடைய மக்களிடம் நீடித்த நாட்கள் அல்லது காலமாக தீர்க்கதரிசனக் குரல் எதுவும் பேசாத/கேட்காத ஏற்பாட்டின் இடையேயான காலத்திற்கு வழிவகுத்தது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>சகரியா 1:3, \"ஆகையால் நீ அவர்களை நோக்கி: சேனைகளின் கர்த்தர் உரைக்கிறது என்னவென்றால்: என்னிடத்தில் திரும்புங்கள் என்று சேனைகளின் கர்த்தர் சொல்லுகிறார்; அப்பொழுது நான் உங்களிடத்துக்குத் திரும்புவேன் என்று சேனைகளின் கர்த்தர் சொல்லுகிறார்.\"</p><p>சகரியா 7:13, \"ஆதலால் நான் கூப்பிட்டபோது, அவர்கள் எப்படி கேளாமற்போனார்களோ அப்படியே அவர்கள் கூப்பிட்டபோது நானும் கேளாமலிருந்தேனென்று சேனைகளின் கர்த்தர் சொல்லுகிறார்.\"</p><p>சகரியா 9:9, \"சீயோன் குமாரத்தியே, மிகவும் களிகூரு; எருசலேம் குமாரத்தியே, கெம்பீரி; இதோ, உன் ராஜா உன்னிடத்தில் வருகிறார்; அவர் நீதியுள்ளவரும் இரட்சிக்கிறவரும் தாழ்மையுள்ளவரும், கழுதையின்மேலும் கழுதைக்குட்டியாகிய மறியின்மேலும் ஏறிவருகிறவருமாயிருக்கிறார்.\"</p><p>சகரியா 13:9, \"அந்த மூன்றாம் பங்கை நான் அக்கினிக்குட்படப்பண்ணி, வெள்ளியை உருக்குகிறதுபோல அவர்களை உருக்கி, பொன்னைப் புடமிடுகிறதுபோல அவர்களைப் புடமிடுவேன்; அவர்கள் என் நாமத்தைத் தொழுதுகொள்வார்கள்; நான் அவர்கள் விண்ணப்பத்தைக் கேட்பேன்; இது என் ஜனமென்று நான் சொல்லுவேன், கர்த்தர் என் தேவனென்று அவர்கள் சொல்லுவார்கள்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>இரட்சிப்பு அனைவராலும் பெறப்படலாம் என்று சகரியா புத்தகம் கற்பிக்கிறது. கடைசி அதிகாரத்தில் உலகெங்கிலுமுள்ள ஜனங்கள் தேவனை நமஸ்கரித்து வணங்க வருகிறார்கள், எல்லா மக்களும் அவரைப் பின்பற்ற வேண்டும் என்று விரும்புகிறார்கள் என்பதை விவரிக்கிறது. இது உலகளாவிய கோட்பாடு அல்ல, அதாவது, எல்லா மக்களும் இரட்சிக்கப்படுவார்கள் என்பதல்ல, ஏனெனில் இது தேவனுடைய இயல்பாகும். மாறாக, தேசிய அல்லது அரசியல் வெளிப்பாடுகளைப் பொருட்படுத்தாமல், எல்லா மக்களும் தன்னை வணங்குவதையும், ஏற்றுக்கொள்வதையும் தேவன் விரும்புகிறார் என்று புத்தகம் கற்பிக்கிறது. இறுதியாக, சகரியா தேவன் இந்த உலகத்தின் மீது இறையாண்மை உடையவர் என்று பிரசங்கித்தார், மாறாக எந்தவொரு தோற்றமும் இல்லை. எதிர்காலத்தைப் பற்றிய அவரது தரிசனங்கள், நடக்கும் அனைத்தையும் தேவன் காண்கிறார் என்பதைக் குறிக்கிறது. உலகில் தேவனுடைய தலையீட்டின் சித்தரிப்புகள் இறுதியில் அவர் தேர்ந்தெடுக்கும் மனித நிகழ்வுகளை அவர் கொண்டு வருவார் என்று கற்பிக்கிறது. தேவனைப் பின்பற்றவோ அல்லது கிளர்ச்சி செய்யவோ தனிநபரின் சுதந்திரத்தை அவர் அகற்றுவதில்லை, ஆனால் அவர்கள் செய்யும் தேர்வுகளுக்கு ஜனங்களே பொறுப்பேற்கிறார்கள். கடைசி அதிகாரத்தில், இயற்கையின் சக்திகள் கூட தேவனுடைய கட்டுப்பாட்டுக்கு அடங்கி பதிலளிக்கின்றன.</p><p><b>முன்னிழல்கள்:</b></p><p>இயேசு கிறிஸ்து மற்றும் மேசியாவின் சகாப்தம் பற்றிய தீர்க்கதரிசனங்கள் சகரியாவில் உள்ளன. மேசியா வந்து நம் நடுவில் வசிப்பார் என்ற வாக்குறுதியிலிருந்து (சகரியா 2:10-12; மத்தேயு 1:23) கிளை மற்றும் கல் ஆகியவற்றின் அடையாளத்திற்கு (சகரியா 3:8-9, 6:12-13; ஏசாயா 11: 1; லூக்கா 20:17-18) அவருடைய இரண்டாவது வருகையின் வாக்குறுதியின்படி, அவரைத் குத்தினவர்கள் அவரைப் பார்த்து துக்கப்படுவார்கள் (சகரியா 12:10; யோவான் 19: 33-37), கிறிஸ்து தான் இந்த சகரியா புத்தகத்தின் கருப்பொருளாக இருக்கிறார். இயேசு இஸ்ரவேலின் இரட்சகராக இருக்கிறார், இரட்சிப்புக்காக தன்னிடம் வரும் அனைவரின் பாவங்களையும் இரத்தம் உள்ளடக்கிய ஒரு நீரூற்று கழுவுகிறது (சகரியா 13:1; 1 யோவான் 1:7).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>இன்று நம்முடைய மெய்யான வழிபாட்டையும் தார்மீக வாழ்வையும் தேவன் எதிர்பார்க்கிறார். தேசிய தப்பெண்ணத்தை மீறுவதற்கான சகரியாவின் உதாரணம் நமது சமூகத்தின் அனைத்து பகுதிகளையும் சென்றடைய நினைவூட்டுகிறது. தேவனுடைய இரட்சிப்பின் அழைப்பை அனைத்து தேசிய தோற்றங்கள், மொழிகள், இனங்கள் மற்றும் கலாச்சாரங்களைச் சேர்ந்தவர்களுக்கு நாம் வழங்க வேண்டும். அந்த இரட்சிப்பு சிலுவையில் இயேசு கிறிஸ்துவின் சிந்தப்பட்ட இரத்தத்தின் மூலம் மட்டுமே கிடைக்கிறது, அவர் பாவத்திற்கு பரிகாரம் செய்ய நம் இடத்தில்/ஸ்தானத்தில் மரித்தார். ஆனால், அந்த பலியை நாம் நிராகரித்தால், வேறு எந்த பலியும் இல்லை, இதன் மூலம் நாம் தேவனோடு ஒப்புரவாக முடியும். மனிதர்கள் இரட்சிக்கப்படுவதற்கு வானத்தின் கீழ் வேறு நாமம் கொடுக்கப்படவில்லை (அப்போஸ்தலர் 4:12). நாம் இழப்பதற்கு நேரமில்லை; இன்றே இரட்சிப்பின் நாள் (2 கொரிந்தியர் 6:2).</p><p>சுமார் கி.மு.554 (605) - நேபுகாத்நேச்சாரின் முதல் படையெடுப்பும் யூதா சிறைபிடிப்பும்</p><p>சுமார் கி.மு. 435 (586) - எருசலேம் அழிப்பும் நேபுகாத் நேச்சாரின் இறுதி யூதா சிறைபிடிப்பும்</p><p>சுமார் கி.மு. 485 (536) - யூதர் நாடு திரும்ப கோரசு அரசர் அளித்த ஆணை</p><p>சுமார் கி.மு. 469 (520) - நிறுத்தப்பட்ட தேவாலயப்பணி மீண்டும் தொடங்கப்படல் சகரியா தீர்க்கதரிசனப் பணியைத் தொடங்குதல்</p><p>சுமார் கி.மு. 465 (516) - தேவாலயப்பணி நிறைவடைதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - சகரியா (கர்த்தர் நினைத்திருக்கிறார்)</p><p>தகப்பன் பெயர் - பெரகியா</p><p>கோத்திரம் - லேவி, ஆசாரியர்</p><p>ஊர் - பாபிலோனில் பிறந்து எருசலேமில் குடியேறினார்</p><p>திருப்புமுனை - தேவாலயப் பணி தடைபட்ட காலத்தில் ஆகாய் இடிமுழக்கமாய் எழுந்த போது, ஏற்பட்ட ஆன்மீக அனலும் தேவ அழைப்பும்</p><p>சாதனை - மென்மையாகப் பேசி பெரும் மறுமலர்ச்சிக்கு அழைப்பு கொடுத்தது</p><p>சிறப்புப் பெயர் - மென்மையான தீர்க்கதரிசி</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 38-வது நூல்</p><p>அதிகாரங்கள் - 14</p><p>வசனங்கள் - 211</p><p>கேள்விகள - 27</p><p>கட்டளைகள் - 35</p><p>வாக்குத்தத்தங்கள் - 4</p><p>எச்சரிக்கைகள் - 226</p><p>தீர்க்கதரிசன வசனங்கள் -  122</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 31</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 91</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள்  - 59</p>'),
 (460,'<p><b>மல்கியா புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>மல்கியா 1:1, மல்கியா புத்தகத்தின் எழுத்தாளரை மல்கியாவைக்கொண்டு கர்த்தர் இஸ்ரவேலுக்குச் சொன்ன வார்த்தையின் பாரம் என்று குறிப்பிட்டு அடையாளப்படுத்துகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>மல்கியா புத்தகம் கி.மு. 440 முதல் கி.மு. 400 வரையிலுள்ள காலக்கட்டத்தினுடைய இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>மல்கியா புத்தகம் மல்கியாவைக்கொண்டு கர்த்தர் இஸ்ரவேலுக்குச் சொன்ன வார்த்தையின் பாரம் ஆகும் (1:1). தேவனிடம் திரும்பும்படி மக்களுக்குச் சொல்ல இது மல்கியா வழியாக உரைக்கப்பட்ட தேவனுடைய எச்சரிக்கையாக இருந்தது. பழைய ஏற்பாட்டின் இறுதி புத்தகம் முடிவடையும் போது, தேவனுடைய நீதியின் அறிவிப்பும், வரவிருக்கும் மேசியா மூலம் அவர் மீட்கப்படுவதற்கான வாக்குறுதியும் இஸ்ரவேலரின் செவிகளில் ஒலிக்கிறது. நானூறு ஆண்டுகால மௌனம் தேவனுடைய அடுத்த தீர்க்கதரிசியாகிய யோவான் ஸ்நானகனிடமிருந்து இதேபோன்ற செய்தியுடன் முடிவடைகிறது, \"மனந்திரும்புங்கள், பரலோகராஜ்யம் சமீபமாக இருக்கிறது\" (மத்தேயு 3:2).</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>மல்கியா 1:6, \"குமாரன் தன் பிதாவையும், ஊழியக்காரன் தன் எஜமானையும் கனம்பண்ணுகிறார்களே; நான் பிதாவானால் என் கனம் எங்கே? நான் எஜமானானால் எனக்குப் பயப்படும் பயம் எங்கே என்று சேனைகளின் கர்த்தர் தமது நாமத்தை அசட்டைபண்ணுகிற ஆசாரியர்களாகிய உங்களைக் கேட்கிறார்; அதற்கு நீங்கள் உமது நாமத்தை எதினாலே அசட்டைபண்ணினோம் என்கிறீர்கள்.\"</p><p>மல்கியா 3:6-7, \"நான் கர்த்தர் நான் மாறாதவர்; ஆகையால் யாக்கோபின் புத்திரராகிய நீங்கள் நிர்மூலமாகவில்லை. நீங்கள் உங்கள் பிதாக்களின் நாட்கள் தொடங்கி என் கட்டளைகளைக் கைக்கொள்ளாமல், அவைகளைவிட்டு விலகிப்போனீர்கள்; என்னிடத்திற்குத் திரும்புங்கள், அப்பொழுது உங்களிடத்திற்குத் திரும்புவேன் என்று சேனைகளின் கர்த்தர் சொல்லுகிறார்; நாங்கள் எந்த விஷயத்தில் திரும்பவேண்டும் என்கிறீர்கள்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>வழிதவறிச் சென்ற தேவனுடைய தேர்ந்தெடுக்கப்பட்ட மக்களுக்கு, குறிப்பாக தேவனிடமிருந்து திரும்பிய ஆசாரியர்களுக்கு மல்கியா தேவனுடைய வார்த்தைகளை எழுதினார். ஆசாரியர்கள் அவர்கள் தேவனுக்கு செய்த பலிகளை பெரிதாக கருதவில்லை/நடத்தவில்லை. குறைபாடு இல்லாத விலங்குகளை நியாயப்பிரமாண சட்டம் கோரிய போதிலும் கறைகள்/குறைபாடுகள் உள்ள மிருகங்கள் பலியிடப்பட்டன (உபாகமம் 15:21). யூதாவின் ஆண்கள் தங்கள் இளமைக்கால மனைவிகளுடன் துரோகமாக நடந்துகொண்டார்கள், தேவன் பலிகளை ஏன் ஏற்றுக்கொள்ள மாட்டார் என்று யோசித்துக்கொண்டிருந்தார்கள். மேலும், மக்கள் இருந்திருக்க வேண்டிய அளவுக்கு தசமபாகம் செலுத்தவில்லை (லேவியராகமம் 27:30, 32). ஆனால் மக்கள் செய்த பாவம் இருந்தபோதிலும், தேவனிடமிருந்து விலகிச் சென்றாலும், மல்கியா தேவனுடைய மக்கள் மீதுள்ள அன்பை மீண்டும் வலியுறுத்துகிறார் (மல்கியா 1:1-5) மற்றும் வரவிருக்கும் செய்தியாளரைக் பற்றிய வாக்குறுதிகள் (மல்கியா 2:17–3: 5) கொடுக்கப்பட்டுள்ளன.</p><p><b>முன்னிழல்கள்:</b></p><p>மல்கியா 3:1-6 வரையிலுள்ள வேதபாகம் யோவான் ஸ்நானகனைப் பற்றிய ஒரு தீர்க்கதரிசனமாகும். மேசியாவாகிய இயேசு கிறிஸ்துவுக்கு வழியை ஆயத்தம் பண்ணுவதற்காக அனுப்பப்பட்ட கர்த்தருடைய தூதுவர் அவர் (மத்தேயு 11:10). யோவான் மனந்திரும்புதலைப் பிரசங்கித்து, கர்த்தருடைய நாமத்தில் ஞானஸ்நானம் வழங்கினார், இதனால் இயேசுவின் முதல் வருகைக்கு வழியை ஆயத்தம் பண்ணினார். ஆனால் \"திடீரென்று ஆலயத்திற்கு\" வரும் தூதுவர் கிறிஸ்துவே அதிகாரத்திலும் வல்லமையிலும் வரும்போது தனது இரண்டாவது வருகையில் தானே அப்படியாகும் (மத்தேயு 24). அந்த நேரத்தில், அவர் \"லேவியின் புத்திரர்களைத் பரிசுத்தப்படுத்துவார்\" (வச. 3), அதாவது மோசேயின் நியாயப்பிரமாணத்தை எடுத்துக்காட்டுவோர் இரட்சகரின் இரத்தத்தின் மூலம் பாவத்திலிருந்து சுத்திகரிப்பை தேவைப்படுவார்கள். அப்போதுதான் அவர்களால் \"நீதியிலுள்ள ஒரு பலியை\" வழங்க முடியும், ஏனென்றால் அது விசுவாசத்தின் மூலம் அவர்களுக்கு விதிக்கப்பட்ட கிறிஸ்துவின் நீதியாகும் (2 கொரிந்தியர் 5:21).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நாம் அவருடைய கட்டளைகளுக்குக் கீழ்ப்படியாதபோது தேவன் மகிழ்ச்சியடைவதில்லை. தன்னைப் புறக்கணிப்பவர்களுக்கு அவர் திருப்பிப் பதில் செய்வார். தேவன் விவாகரத்தை வெறுப்பதைப் பொறுத்தவரை (2:16), திருமண உடன்படிக்கையை தேவன் தீவிரமாக எடுத்துக்கொள்கிறார், அதை உடைக்க அவர் விரும்பவில்லை என்பது தெளிவாக விளங்குகிறது. நம் வாலிப வாழ்க்கைத் துணையுடன் வாழ்நாள் முழுவதும் உண்மையாக இருக்க வேண்டும். தேவன் நம் இருதயங்களைக் காண்கிறார், எனவே நம்முடைய நோக்கங்கள் என்ன என்பதை அவர் அறிவார்; அவரிடமிருந்து எதையும் மறைக்க முடியாது. அவர் திரும்பி வருவார், அவர் நீதியுள்ள நீதிபதியாக இருப்பார். ஆனால் நாம் அவரிடம் திரும்பினால், அவர் நம்மிடம் திரும்புவார் (மல்கியா 3:6).</p><p>சுமார் கி.மு. 485 (536) - செருபாபேல் தலைமையில் முதல் குழு எருசலேம் திரும்புதல்</p><p>சுமார் கி.மு. 485 - 465 - (536 - 516) - எருசலேம் தேவாலயம் கட்டப்படுதல்</p><p>சுமார் கி.மு.407 (458) - எஸ்றா தலைமையில் இரண்டாம் குழு எருசலேம் வருதல்</p><p>சுமார் கி.மு. 394 (445) - நெகேமியா தலைமையில் மூன்றாம் குழு எருசலேம் வருதல்</p><p>சுமார் கி.மு.394 (445) - எருசலேம் அலங்கம் கட்டப்படுதல்</p><p>சுமார் கி.மு. 382 (433) - நெகேமியா பெர்சியா திரும்புதல்</p><p>சுமார் கி.மு. 374 (425) - நெகேமியா மீண்டும் எருசலேம் வருதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - மல்கியா (என் தூதன்)</p><p>தகப்பனார் பெயர் - தெரியவில்லை</p><p>ஊர் - எருசலேமாக இருக்கலாம்</p><p>சாதனை - பழைய ஏற்பாட்டு நூலாக்கத்தில் இறுதி தீர்க்கதரிசியாக விளங்கியது</p><p>சிறப்புப் பெயர் - தீர்க்கதரிசிகளில் சாக்ரடீக</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 39-வது நூல்</p><p>அதிகாரங்கள் - 4</p><p>வசனங்கள் - 55</p><p>கேள்விகள் - 27</p><p>இஸ்ரவேலின் பாவங்கள் - 32</p><p>கட்டளைகள் - 5</p><p>வாக்குத்தத்தங்கள் - 5</p><p>எச்சரிக்கைகள் - 30</p><p>தீர்க்கதரிசன வசனங்கள் - 19</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 6</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 73</p><p>தேவளிடமிருந்து சிறப்புச்செய்திகள் - 28</p>'),
 (470,'<p><b>மத்தேயு எழுதின சுவிசேஷம்</b></p><p><b>எழுத்தாளர்:</b></p><p>இந்த சுவிசேஷப் புத்தகம் மத்தேயு எழுதின சுவிசேஷம் என்று அழைக்கப்படுகிறது, ஏனெனில் அது அதே பெயரில் உள்ள மத்தேயு என்னும் அப்போஸ்தலரால் எழுதப்பட்டதாகும். ஒரு காலத்தில் வரி வசூலித்த ஒரு மனிதரிடம் எதிர்பார்க்கப்படுவதுதான் இந்த புத்தகத்தின் பாணியாகும். மத்தேயு கணக்கியலில் மிகுந்த ஆர்வம் கொண்டவர் (18:23-24; 25:14-15). புத்தகம் மிகவும் ஒழுங்காகவும் சுருக்கமாகவும் மிகவும் நேர்த்தியாகவும் இருக்கிறது. காலவரிசைப்படி எழுதுவதற்கு பதிலாக, மத்தேயு இந்த சுவிசேஷத்தை ஆறு கலந்துரையாடல்கள் மூலம் ஏற்பாடு செய்கிறார்.</p><p>வரி வசூலிப்பவர் என்ற முறையில், மத்தேயு ஒரு திறமையைக் கொண்டிருந்தார், அது அவருடைய எழுத்தை கிறிஸ்தவர்களுக்கு மிகவும் உற்சாகப்படுத்துகிறது. வரி வசூலிப்பவர்கள் சுருக்கெழுத்தின் வடிவத்தில் எழுத முடியும் என்று எதிர்பார்க்கப்பட்டது, இதன் பொருள் மத்தேயு ஒரு நபரின் வார்த்தைகளை அவர்கள் பேசும்போது, அதே வார்த்தைக்கான வார்த்தையை துல்லியமாக பதிவு செய்ய முடியும் என்பதாகும். இந்த திறன் என்பது மத்தேயுவின் வார்த்தைகள் பரிசுத்த ஆவியினால் ஏவப்பட்டவை என்பது மட்டுமல்ல, கிறிஸ்துவின் சில பிரசங்கங்களின் உண்மையான பிரதியெடுத்தலையும் குறிக்க வேண்டும். உதாரணமாக, 5-7 வரையிலுள்ள அதிகாரங்களில் பதிவு செய்யப்பட்டுள்ளபடி, மலைப்பிரசங்கம், நிச்சயமாக அந்த சிறந்த மாபெரும் செய்தியின் சரியான மற்றும் தெளிவான பதிவாகும்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>ஒரு அப்போஸ்தலராக, மத்தேயு இந்த புத்தகத்தை திருச்சபையின் ஆரம்ப காலத்தில் எழுதினார், அநேகமாக கி.பி. 50-ல் இந்த புத்தகத்தை அவர் எழுதினார். பெரும்பாலான கிறிஸ்தவர்கள் யூத மதத்திற்கு மதமாற்றம் செய்த காலமாக இது இருந்தது, எனவே இந்த நற்செய்தியில் யூதர்களின் பார்வையில் மத்தேயு அதிக கவனம் செலுத்துவது புரிந்துகொள்ளத்தக்கது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>இயேசு கிறிஸ்து வாக்களிக்கப்பட்ட மேசியா என்பதை யூதர்களுக்கு நிரூபிக்க மத்தேயு விரும்புகிறார். வேறு எந்த நற்செய்தியையும் விட, யூத தீர்க்கதரிசிகளின் வார்த்தைகளை இயேசு எவ்வாறு நிறைவேற்றினார் என்பதைக் காட்ட பழைய ஏற்பாட்டை மேற்கோள் காட்டுகிறார் அப்போஸ்தலனாகிய மத்தேயு. மத்தேயு தாவீதிடமிருந்து இயேசுவின் வம்சாவளியை/பரம்பரையை விரிவாக விவரிக்கிறார், மற்றும் யூதர்கள் புரிந்துகொள்வதற்கு மிகவும் வசதியாக இருக்கும் நிலையில் பல வகையான உருவகப் பேச்சுகளைப் பயன்படுத்துகிறார். நற்செய்தி விவரணங்களை சொல்வதற்கான அவரது நுணுக்கமான அணுகுமுறையின் மூலம் மத்தேயுவின் மக்கள் மீதுள்ள கொண்டுள்ள அவருடைய அன்பும் அக்கறையும் தெளிவாகத் தெரிகிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>மத்தேயு 5:17: \"நியாயப்பிரமாணத்தையானாலும் தீர்க்கதரிசனங்களையானாலும் அழிக்கிறதற்கு வந்தேன் என்று எண்ணிக்கொள்ளாதேயுங்கள்; அழிக்கிறதற்கு அல்ல, நிறைவேற்றுகிறதற்கே வந்தேன்.\"</p><p>மத்தேயு 5:43-44: \"உனக்கடுத்தவனைச் சிநேகித்து, உன் சத்துருவைப் பகைப்பாயாக என்று சொல்லப்பட்டதைக் கேள்விப்பட்டிருக்கிறீர்கள். நான் உங்களுக்குச் சொல்லுகிறேன், உங்கள் சத்துருக்களைச் சிநேகியுங்கள்; உங்களைச் சபிக்கிறவர்களை ஆசீர்வதியுங்கள்; உங்களைப் பகைக்கிறவர்களுக்கு நன்மை செய்யுங்கள்; உங்களை நிந்திக்கிறவர்களுக்காகவும் உங்களைத் துன்பப்படுத்துகிறவர்களுக்காகவும் ஜெபம் பண்ணுங்கள்.\"</p><p>மத்தேயு 6:9-13: \"நீங்கள் ஜெபம்பண்ணவேண்டிய விதமாவது; பரமண்டலங்களிலிருக்கிற எங்கள் பிதாவே, உம்முடைய நாமம் பரிசுத்தப்படுவதாக; உம்முடைய ராஜ்யம் வருவதாக; உம்முடைய சித்தம் பரமண்டலத்திலே செய்யப்படுகிறதுபோல பூமியிலேயும் செய்யப்படுவதாக.</p><p>எங்களுக்கு வேண்டிய ஆகாரத்தை இன்று எங்களுக்குத் தாரும். எங்கள் கடனாளிகளுக்கு நாங்கள் மன்னிக்கிறதுபோல எங்கள் கடன்களை எங்களுக்கு மன்னியும். எங்களைச் சோதனைக்குட்படப்பண்ணாமல், தீமையினின்று எங்களை இரட்சித்துக்கொள்ளும், ராஜ்யமும், வல்லமையும், மகிமையும் என்றென்றைக்கும் உம்முடையவைகளே, ஆமென், என்பதே.\"</p><p>மத்தேயு 16:26: \"மனுஷன் உலகம் முழுவதையும் ஆதாயப்படுத்திக்கொண்டாலும், தன் ஜீவனை நஷ்டப்படுத்தினால் அவனுக்கு லாபம் என்ன? மனுஷன் தன் ஜீவனுக்கு ஈடாக என்னத்தைக் கொடுப்பான்?\"</p><p>மத்தேயு 22:37-40: \"இயேசு அவனை நோக்கி: உன் தேவனாகிய கர்த்தரிடத்தில் உன் முழு இருதயத்தோடும், உன் முழு ஆத்துமாவோடும் உன் முழு மனதோடும் அன்புகூருவாயாக; இது முதலாம் பிரதான கற்பனை. இதற்கு ஒப்பாயிருக்கிற இரண்டாம் கற்பனை என்னவென்றால், உன்னிடத்தில் நீ அன்புகூருவதுபோலப் பிறனிடத்திலும் அன்புகூருவாயாக என்பதே. இவ்விரண்டு கற்பனைகளிலும் நியாயப்பிரமாணம் முழுமையும் தீர்க்கதரிசனங்களும் அடங்கியிருக்கிறது என்றார்.\"</p><p>மத்தேயு 27:31: \"அவரைப் பரியாசம்பண்ணினபின்பு, அவருக்கு உடுத்தின மேலங்கியைக் கழற்றி, அவருடைய வஸ்திரங்களை அவருக்கு உடுத்தி, அவரைச் சிலுவையில் அறையும்படி கொண்டுபோனார்கள்.\"</p><p>மத்தேயு 28:5-6: \"தூதன் அந்த ஸ்திரீகளை நோக்கி: நீங்கள் பயப்படாதிருங்கள்; சிலுவையில் அறையப்பட்ட இயேசுவைத் தேடுகிறீர்கள் என்று அறிவேன். அவர் இங்கே இல்லை; தாம் சொன்னபடியே உயிர்த்தெழுந்தார்; கர்த்தரை வைத்த இடத்தை வந்து பாருங்கள்.\"</p><p>மத்தேயு 28:19-20: \"ஆகையால், நீங்கள் புறப்பட்டுப்போய் சகல ஜாதிகளையும் சீஷராக்கி, பிதா குமாரன் பரிசுத்த ஆவியின் நாமத்திலே அவர்களுக்கு ஞானஸ்நானங்கொடுத்து, நான் உங்களுக்குக் கட்டளையிட்ட யாவையும் அவர்கள் கைக்கொள்ளும்படி அவர்களுக்கு உபதேசம் பண்ணுங்கள்; இதோ, உலகத்தின் முடிவுபரியந்தம் சகல நாட்களிலும் நான் உங்களுடனேகூட இருக்கிறேன் என்றார். ஆமென்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>முதல் இரண்டு அதிகாரங்களில் கிறிஸ்துவின் வம்சாவளி, பிறப்பு மற்றும் ஆரம்பகால வாழ்க்கை குறித்து மத்தேயு கலந்துரையாடுகிறார். அங்கிருந்து, புத்தகம் இயேசுவின் ஊழியத்தைப் பற்றி கலந்துரையாடுகிறது. கிறிஸ்துவின் போதனைகளின் விளக்கங்கள் 5 முதல் 7 அதிகாரங்களில் உள்ள மலைப்பிரசங்கம் போன்ற \"சொற்பொழிவுகளை\" சுற்றி அமைக்கப்பட்டிருக்கின்றன. 10-ஆம் அதிகாரம் சீஷர்களின் ஊழியம் மற்றும் நோக்கத்தை உள்ளடக்கியது; 13-வது அதிகாரம் உவமைகளின் தொகுப்பு; 18-வது அதிகாரம் திருச்சபையைப் பற்றி கலந்துரையாடுகிறது; 23-ஆம் அதிகாரம் மாய்மாலத்தனம் மற்றும் எதிர்காலம் பற்றிய ஒரு சொற்பொழிவைத் தொடங்குகிறது. 21 முதல் 27 வரையிலுள்ள அதிகாரங்கள் இயேசுவைக் கைது செய்தல், சித்திரவதை செய்தல் மற்றும் சிலுவையில் மரணதண்டனை அடைதல் பற்றி மிகவும் தெளிவாக விரிவாக விவாதிக்கின்றன. இறுதி அதிகாரம் (28-ஆம் அதிகாரம்) இயேசுவின் உயிர்த்தெழுதல் மற்றும் அவர் அளிக்கும் பிரதான ஆணையத்தை விவரிக்கிறது.</p><p><b>இணைப்புகள்:</b></p><p>இயேசு கிறிஸ்துவை இஸ்ரவேலின் ராஜாவாகவும் மேசியாவாகவும் முன்வைப்பதே மத்தேயுவின் பிரதான நோக்கம் என்பதால், அவர் மற்ற மூன்று சுவிசேஷ புத்தகங்களின் எழுத்தாளர்களைக் காட்டிலும் பழைய ஏற்பாட்டில் இருந்து அதிக்கப்படியான காரியங்களை மேற்கோள் காட்டுகிறார். அப்போஸ்தலனாகிய மத்தேயு பழைய ஏற்பாட்டின் தீர்க்கதரிசன பத்திகளில் இருந்து 60-க்கும் மேற்பட்ட முறைகள் மேற்கோள் காட்டி, இயேசு அவற்றை எவ்வாறு நிறைவேற்றினார் என்பதை நிரூபிக்கிறார். அவர் இயேசுவின் வம்சாவளியைக் கொண்டு தனது நற்செய்தியைத் தொடங்குகிறார், யூதர்களின் முற்பிதாக்களான ஆபிரகாமிடம் இருந்து துவங்குகிறார். அங்கிருந்து, மத்தேயு தீர்க்கதரிசிகளிடமிருந்து விரிவாக மேற்கோள் காட்டுகிறார், \"தீர்க்கதரிசி (கள்) மூலம் பேசப்பட்டதைப் போல\" (மத்தேயு 1:22-23, 2:5-6, 2:15, 4:13-16, 8:16-17, 13:35, 21:4-5). இந்த வசனங்கள் பெத்லகேமில் (மீகா 5:2), கன்னிப் பிறப்பின் பழைய ஏற்பாட்டு தீர்க்கதரிசனங்களைக் குறிக்கின்றன (ஏசாயா 7:14), ஏரோது இறந்தபின் எகிப்திலிருந்து அவர் திரும்பினது (ஓசியா 11:1), புறஜாதியினருக்கு அவர் செய்த ஊழியம் (ஏசாயா 9:1-2; 60:1-3), சரீரம் மற்றும் ஆத்துமா இரண்டையும் அவர் அற்புதமாகக் குணப்படுத்துகிறார் (ஏசாயா 53:4), அவர் உவமைகளில் பேசுதல் (சங்கீதம் 78:2), எருசலேமுக்கு அவர் வெற்றிகரமாக பவனி வந்து நுழைதல் (சகரியா 9:9) போன்றவைகள் இதில் அடங்கும்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>மத்தேயு நற்செய்தி கிறிஸ்தவத்தின் முக்கிய போதனைகளுக்கு ஒரு சிறந்த அறிமுகமாகும். தர்க்கரீதியான திட்டவரைவு பாணி பல்வேறு தலைப்புகளின் விவாதங்களைக் கண்டறிவதை எளிதாக்குகிறது. பழைய ஏற்பாட்டின் தீர்க்கதரிசனங்களின் நிறைவேற்றமாக கிறிஸ்துவின் வாழ்க்கை எவ்வாறு இருந்தது என்பதைப் புரிந்துகொள்ள மத்தேயு மிகவும் பயனுள்ளதாக இருக்கிறது.</p><p>மத்தேயுவின் கருத்தில் கொண்ட வாசகர்கள் அவருடைய சக யூதர்கள் ஆகும், அவர்களில் பலர் - குறிப்பாக பரிசேயர்கள் மற்றும் சதுசேயர்கள் ஆகும் - இயேசுவை தங்கள் மேசியாவாக ஏற்றுக்கொள்வதற்கு பிடிவாதமாக மறுத்துவிட்டனர். பழைய ஏற்பாட்டைப் பல நூற்றாண்டுகள் படித்து படித்து அதில் ஊறிப்போனவர்களாக அவர்கள் இருந்தபோதிலும், இயேசு யார் என்ற உண்மையை அறிந்துகொள்ளும் விஷயத்தில் சரிவர புரிந்துகொள்ள முடியாமல் அவர்களின் கண்கள் கண்மூடி மறைக்கப்பட்ட நிலையில் இருந்தன. அவர்களுடைய கடினமான இருதயங்களுக்காகவும், அவர்கள் எதிர்பார்த்து காத்திருந்ததாகக் கருதப்பட்டவரை அடையாளம் காண மறுத்ததற்காகவும் இயேசு அவர்களை வன்மையாகக் கண்டித்தார் (யோவான் 5:38-40). அவர்கள் தங்கள் சொந்த விருப்பப்படி விளங்கும் ஒரு மேசியாவையே விரும்பினர், அவர்கள் தங்கள் சொந்த விருப்பங்களை நிறைவேற்றி, அவர்கள் என்ன செய்ய வேண்டுமோ அதைமட்டுமே செய்தார்கள். நம்முடைய சொந்த சொற்களில் நாம் எத்தனை முறை தேவனை நாடுகிறோம்? நாம் ஏற்றுக்கொள்ளக்கூடியதாகக் கருதப்படும் பண்புகளை, அவரின் அன்பு, இரக்கம், கிருபை போன்றவற்றை மட்டுமே அவரிடம் குறிப்பிடுவதன் மூலம் மற்றும் அதேவேளையில் அவருடைய கோபம், நியாயம் மற்றும் பரிசுத்த கோபத்தையும் நிராகரிக்க வேண்டாமா? பரிசேயர்களின் அதே தவறை நாமும் செய்யத் துணியவில்லை, தேவனை நம்முடைய சாயலில் படைத்து, பின்னர் அவர் நம்முடைய தரத்திற்கு ஏற்ப வாழ்வார் என்று எதிர்பார்க்கிறோம். அத்தகைய தேவன் ஒரு விக்கிரகத்தைத் தவிர வேறில்லை. நம்முடைய ஆராதனைக்கும் கீழ்ப்படிதலுக்கும் உத்தரவாதமளிக்க தேவன் மற்றும் இயேசு கிறிஸ்துவின் உண்மையான தன்மை மற்றும் அடையாளம் பற்றிய போதுமான தகவல்களை வேதாகமம் நமக்கு அளிக்கிறது.</p><p>சுமார் கி.மு 37-4 - பெரிய ஏரோது எருசலேமில் அரசராக</p><p>சுமார் கி.மு.31-கி.பி.4 - அகஸ்துராயர் ரோமப் பேரரசராக</p><p>சுமார் கிமு 6 - அன்னா பிரதான ஆசாரியராக</p><p>சுமார் கி.மு. 5/4 - இயேசு கிறிஸ்துவின் அவதரிப்பு</p><p>சுமார் கி.மு 4 - கி.பி. 39 ஏரோது அந்திப்பா‌ கலிலேயாவிலும்</p><p>பெரேயாவிலும் அரசராக</p><p>சுமார் கி.பி. 14-37 - திபேரியு சீசர் ரோமப் பேரரசராக</p><p>சுமார் கி.பி. 18 - காய்பா பிரதான ஆசாரியராகிறார்</p><p>சுமார் கி.பி. 25-27 - யோவான்ஸ்நானனின் திருப்பணி</p><p>சுமார் கி.பி 26-36 - பொந்தியு பிலாத்து யூதேயா ஆளுநர்</p><p>சுமார் கி.பி. 27-30 - கிறிஸ்துவின் வெளிப்படை ஊழியம்</p><p>சுமார் கி.பி. 29/30 கிறிஸ்துவின் சிலுவை மரணமும் உயிர்ப்பும்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் -  மத்தேயு  (பொருள். கர்த்தரின் பரிசு)</p><p>வேறுபெயர் - லேவி (மாற் 2:14)</p><p>தந்தை பெயர் - அல்பேயு</p><p>சொந்த இடம் - கப்பர் நகூம் (4:13, 11:23)</p><p>தொழில் - ஆயம் பிரித்தல் (9;9)</p><p>திருப்புமுனை - ஆயத்துறையில் இருக்கும்போது வந்த இயேசுவின் (அழைப்பு 19:9)</p><p>ஆர்வம் - இயேசுகிறிஸ்துவின் உவமைகளையும்</p><p>போதனைகளையும், சொற் பொழிவுகளையும் சேகரித்து நூலாக்குதல்</p><p>பட்டங்கள் - அப்போஸ்தலர் பட்டம் (லூக் 6:13)</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 40-வது நாள்</p><p>அதிகாரங்கள் - 28</p><p>வசனங்கள் - 1071</p><p>கேள்விகள் - 177</p><p>பழைய ஏற்பாட்டுத் தீர்க்கதரிசனங்கள் - 25</p><p>புதிய ஏற்பாட்டுத் தீர்க்கதரிசனங்கள் - 47</p><p>வரலாற்றுத் தொடர்பு வசனங்கள் - 815</p><p>தீர்க்கதரிசன வசனங்கள் - 256</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 92</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 164</p>'),
 (480,'<p><b>மாற்கு எழுதின சுவிசேஷம்</b></p><p><b>எழுத்தாளர்:</b></p><p>மாற்கு எழுதின சுவிசேஷம் அதன் எழுத்தாளரின் பெயரைக் குறிப்பாக குறிப்பிடவில்லை என்றாலும், ஆரம்பகால திருச்சபை பிதாக்களின் ஏகமனதான சாட்சியம் யோவான் மாற்கு தான் இதன் எழுத்தாளராக இருந்தார் என்பதாகும். அவர் அப்போஸ்தலனாகிய பேதுருவின் சக கூட்டாளியாக இருந்தார், அவருடைய ஆவிக்குரிய மகன் ஆவார் (1 பேதுரு 5:13). பேதுருவிடமிருந்து அவர் கர்த்தருடைய நிகழ்வுகள் மற்றும் போதனைகள் பற்றிய முதல் தகவல்களைப் பெற்றார், மேலும் தகவல்களை எழுத்து வடிவில் பாதுகாத்தார்.</p><p>மாற்கு என்பது புதிய ஏற்பாட்டின் யோவான் மாற்கு என்று பொதுவாக ஒப்புக்கொள்ளப்படுகிறது (அப்போஸ்தலர் 12:12). அவரது தாயார் எருசலேம் திருச்சபையில் ஒரு பணக்கார மற்றும் முக்கிய கிறிஸ்தவராக இருந்தார், அநேகமாக திருச்சபையானது அவரது வீட்டில் கூடிவந்தது. மாற்கு பவுல் மற்றும் பர்னபாவுடன் முதல் மிஷனரி பயணத்தில் சேர்ந்தார், ஆனால் இரண்டாவது மிஷினரி பயணத்தில் பங்குபெறவில்லை காரணம் இருவருக்கும் (பவுல் மற்றும் பர்னபா) இடையில் கடுமையான கருத்து வேறுபாடு இருந்தது (அப்போஸ்தலர் 15:37-38). இருப்பினும், பவுலினுடைய வாழ்க்கையின் முடிவில் (இறுதி காலத்தில்), மாற்கு தன்னுடன் இருக்கும்படி அவர் அழைத்தார் (2 தீமோத்தேயு 4:11).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>மாற்கு எழுதின சுவிசேஷம் புதிய ஏற்பாட்டில் எழுதப்பட்ட முதல் புத்தகங்களில் ஒன்றாகும், அநேகமாக கி.பி. 57-59 வரையிலுள்ள காலக்கட்டத்தில் எழுதப்பட்டிருக்கலாம்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>மத்தேயு எழுதின சுவிசேஷம் முதன்மையான நிலையில் அவருடைய சக யூதர்களுக்கு எழுதப்பட்டிருந்தாலும், மாற்குவின் சுவிசேஷப் புத்தகம் ரோம விசுவாசிகளுக்கு, குறிப்பாக புறஜாதியாரை கருத்திகொண்டு அவர்களுக்காக குறிப்பாக எழுதியதாக தெரிகிறது. முன்பு சுவிசேஷத்தைக் கேட்டு நம்பிய கிறிஸ்தவர்களுக்கு ஒரு போதகராக மாற்கு எழுதினார் (ரோமர் 1:8). கடுமையான துன்புறுத்தல்களுக்கு முகங்கொடுத்து தங்கள் நம்பிக்கையை வலுப்படுத்தவும், அவருடைய சீஷர்களாக இருப்பதன் அர்த்தத்தை அவர்களுக்குக் கற்பிக்கவும், கர்த்தருடைய ஊழியராகவும், உலக மீட்பராகவும் இயேசு கிறிஸ்துவின் வாழ்க்கை வரலாற்றுக் கதை இருக்க வேண்டும் என்று அவர் விரும்பினார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>மாற்கு 1:11: \"அன்றியும், நீர் என்னுடைய நேச குமாரன், உம்மில் பிரியமாயிருக்கிறேன் என்று, வானத்திலிருந்து ஒரு சத்தம் உண்டாயிற்று.\"</p><p>மாற்கு 1:17: \"இயேசு அவர்களை நோக்கி: என் பின்னே வாருங்கள், உங்களை மனுஷரைப் பிடிக்கிறவர்களாக்குவேன் என்றார்.\"</p><p>மாற்கு 10:14-15: \"இயேசு அதைக்கண்டு விசனமடைந்து: சிறு பிள்ளைகள் என்னிடத்தில் வருகிறதற்கு இடங்கொடுங்கள்; அவர்களைத் தடைபண்ணாதிருங்கள்; தேவனுடைய ராஜ்யம் அப்படிப்பட்டவர்களுடையது. எவனாகிலும் சிறு பிள்ளையைப்போல் தேவனுடைய ராஜ்யத்தை ஏற்றுக்கொள்ளாவிட்டால், அவன் அதில் பிரவேசிப்பதில்லையென்று, மெய்யாகவே உங்களுக்குச் சொல்லுகிறேன்.\"</p><p>மாற்கு 10:45: \"அப்படியே, மனுஷகுமாரனும் ஊழியங்கொள்ளும்படி வராமல், ஊழியஞ்செய்யவும், அநேகரை மீட்கும்பொருளாகத் தம்முடைய ஜீவனைக்கொடுக்கவும் வந்தார் என்றார்.\"</p><p>மாற்கு 12:33: \"முழு இருதயத்தோடும், முழு மனதோடும், முழு ஆத்துமாவோடும், முழுப் பலத்தோடும் அவரிடத்தில் அன்பு கூருகிறதும், தன்னிடத்தில் அன்புகூருகிறது போல் பிறனிடத்தில் அன்புகூருகிறதுமே சர்வாங்கதகனம் முதலிய பலிகளைப்பார்க்கிலும் முக்கியமாயிருக்கிறது என்றான்.\"</p><p>மாற்கு 16:6: \"அவன் அவர்களை நோக்கி: பயப்படாதிருங்கள், சிலுவையில் அறையப்பட்ட நசரேயனாகிய இயேசுவைத் தேடுகிறீர்கள்; அவர் உயிர்த்தெழுந்தார், அவர் இங்கேயில்லை; இதோ, அவரை வைத்த இடம்.\"</p><p>மாற்கு 16:15: \"பின்பு, அவர் அவர்களை நோக்கி: நீங்கள் உலகமெங்கும் போய், சர்வ சிருஷ்டிக்கும் சுவிசேஷத்தைப் பிரசங்கியுங்கள்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>இந்த சுவிசேஷப் புத்தகமானது தனித்துவமானது ஆகும், ஏனெனில் அது இயேசுவின் போதனைகளை விட அவருடைய செயல்களையே கூடுதலாக வலியுறுத்துகிறது. இது மிகவும் எளிமையான நடையில் எழுதப்பட்டுள்ளது, கிறிஸ்துவின் வாழ்க்கையில் ஒரு அத்தியாயத்திலிருந்து இன்னொரு அத்தியாயத்திற்கு விரைவாக நகரும் விவரணங்களைக் கொண்டுள்ள புத்தகமாகும். மத்தேயுவைப் போல இது ஒரு வம்சாவளியுடன் தொடங்குவதில்லை, ஏனென்றால் புறஜாதியார் அவருடைய பரம்பரையில் அவ்வளவாக அக்கறை காட்ட மாட்டார்கள். ஞானஸ்நானத்தில் இயேசுவை அறிமுகப்படுத்திய பிறகு, இயேசு கலிலேயாவில் தனது பொதுவான வெளியரங்கமான ஊழியத்தைத் தொடங்கினார், அவருடைய பன்னிரண்டு சீஷர்களில் முதல் நான்கு பேரை அழைத்தார். பின்வருவது இயேசுவின் வாழ்க்கை, மரணம் மற்றும் உயிர்த்தெழுதல் பற்றிய பதிவு.</p><p>மாற்குவின் கணக்கு வெறும் சம்பவங்களின் தொகுப்பு மட்டுமல்ல, யூதர்களுக்கு மட்டுமல்லாது, புறஜாதியினருக்கும் இயேசு மேசியா என்பதை வெளிப்படுத்த எழுதப்பட்ட ஒரு உரைநடை சரித்திரமாகும். ஒரு மாற்றத்தின் நிலையில், பேதுரு தலைமையிலான சீஷர்கள், அவருடைய உயிர்த்தெழுதல் வரையிலும் அவர்களுடைய மேசியாவை முழுமையாகப் புரிந்து கொள்ளத் தவறியிருந்தாலும் அவர்கள் இயேசுவின்மீதுள்ள தங்களது நம்பிக்கையை ஒப்புக் கொண்டனர் (மாற்கு 8:29-30).</p><p>கலிலேயா, சுற்றியுள்ள பகுதிகள், பின்னர் யூதேயா வழியாக அவருடைய பயணங்களை நாம் பின்பற்றும்போது, அவர் எவ்வளவு விரைவான வேகத்தை அமைத்த்துக்கொண்டார் என்பதை நாம் உணர்கிறோம். அவர் பலரின் வாழ்க்கையைத் தொட்டார், ஆனால் அவர் தம்முடைய சீஷர்கள் மீது அழியாத அடையாளத்தை வைத்தார். மறுரூபமானபோது (மாற்கு 9:1-9), அவர்களில் மூன்று பேருக்கு அவர் எதிர்காலத்தில் அதிகாரத்திலும் மகிமையிலும் திரும்புவதற்கான முன்னோட்டத்தைக் கொடுத்தார், மீண்டும் அவர் யார் என்பது அவர்களுக்குத் தெரியவந்தது.</p><p>இருப்பினும், எருசலேமுக்கான அவரது இறுதிப் பயணத்திற்கு வழிவகுத்த நாட்களில், அவர்கள் திகைத்து, பயந்து, சந்தேகிக்கிறார்கள். இயேசுவின் கைது நேரத்தில், அவர்கள் தப்பி ஓடியபின் அவர் தனியாக நின்றார். பரியாச சோதனைகளின் அடுத்த மணிநேரங்களில், இயேசு தான் கிறிஸ்து, ஆசீர்வதிக்கப்பட்டவரின் குமாரன் என்றும், அவர் திரும்பி வரும்போது அவர் வெற்றி பெறுவார் என்றும் தைரியமாக அறிவித்தார் (மாற்கு 14:61-62). சிலுவையில் அறையப்படுதல், மரணம், அடக்கம் மற்றும் உயிர்த்தெழுதல் ஆகியவற்றைச் சுற்றியுள்ள காலநிலை நிகழ்வுகள் அவருடைய சீஷர்களில் பெரும்பாலோர் காணவில்லை. ஆனால் உண்மையுள்ள பல பெண்கள் அவருடைய ஆர்வத்திற்கு சாட்சியாக இருந்தார்கள். ஓய்வுநாளுக்குப் பிறகு, வாரத்தின் முதல் நாளின் அதிகாலையில், அவர்கள் அடக்கம் செய்யப்பட்ட சுகந்த வர்க்கப் பொருட்களுடன் கல்லறைக்குச் சென்றார்கள். மூடியிருந்த பெரிய கல் உருட்டப்பட்டதைக் கண்ட அவர்கள் கல்லறைக்குள் நுழைந்தார்கள். அவர்கள் பார்க்க வந்த இயேசுவின் உடல் அங்கெ இல்லை, ஆனால் ஒரு தேவதூதன் வெண்ணிற வஸ்திரத்தில் தோன்றி காட்சியளித்தான். அவர்களுக்குக் கிடைத்த மகிழ்ச்சியான செய்தி என்னவென்றால், \"அவர் உயிர்த்தெழுந்தார்!\" அவருடைய உயிர்த்தெழுதல் பற்றிய நற்செய்தியை பரப்பிய விஷயத்தில் ஸ்திரீகள் முதல் சுவிசேஷகர்கள் ஆவர். இதே செய்தி பின்வரும் நூற்றாண்டுகளில் உலகம் முழுவதும் பரப்பப்பட்டுள்ளது.</p><p><b>இணைப்புகள்:</b></p><p>மாற்குவின் வாசகர்கள் புறஜாதியார் என்பதால், அவர் பழைய ஏற்பாட்டிலிருந்து மத்தேயு தனது நூலில் அடிக்கடி மேற்கோள் காட்டினதுபோல மேற்கோள் காட்டவில்லை, மத்தேயு தனது புத்தகத்தை முதன்மையாக யூதர்களுக்கு எழுதினார் என்பது குறிப்பிடத்தக்கது. இயேசுவை யூத தேசபக்தர்களுடன் இணைப்பதற்கான ஒரு வம்சாவளியில் அவர் தொடங்கவில்லை, மாறாக அவருடைய ஞானஸ்நானத்தோடு தொடங்குகிறார், அது அவருடைய பூமிக்குரிய ஊழியத்தின் ஆரம்பம் ஆகும். ஆனால் அங்கே கூட, மாற்கு தூதுவர் யோவான் ஸ்நானகனைப் பற்றிய ஒரு பழைய ஏற்பாட்டு தீர்க்கதரிசனத்திலிருந்து மேற்கோள் காட்டுகிறார், அவர் \"கர்த்தருக்கு வழியை ஆயத்தம்பண்ணி\" ஜனங்களை அவர்கள் மேசியாவின் வருகையை எதிர்பார்த்துக் காத்திருந்தபோது அறிவுறுத்துவார் என்பதாகும் (மாற்கு 1:3; ஏசாயா 40:3).</p><p>இயேசு பழைய ஏற்பாட்டை மாற்குவில் பல பத்திகளில் குறிப்பிடுகிறார். மாற்கு 7:6-ல், பரிசேயர்களை அவர்கள் தங்கள் உதடுகளால் மேலோட்டமாக தேவனை வணங்குவதற்காக இயேசு கடுமையாக கடிந்துகொண்டு வலியுறுத்துகிறார், அவர்களுடைய இருதயங்கள் அவரிடமிருந்து வெகு தொலைவில் இருந்தன என்றும், அவர்களுடைய சொந்த மனப்பான்மையான ஏசாயா குறிப்பிடுகின்றது, அவர்களுடைய கடின மனப்பான்மையைக் காட்டும்படி (ஏசாயா 29:13) இந்த பகுதியை மேற்கோள் காட்டுகிறார். இயேசு கைது செய்யப்பட்டு கொல்லப்படும்போது ஒரு மேய்ப்பன் இல்லாமல் சீடர்கள் ஆடுகளைப் போல சிதறடிக்கப்படுவார்கள் என்று அன்றிரவு நிறைவேற வேண்டிய மற்றொரு பழைய ஏற்பாட்டு தீர்க்கதரிசனத்தை இயேசு குறிப்பிட்டார் (மாற்கு 14:27; சகரியா 13:7). பணத்தை மாற்றுவோரின் விஷயத்தில் ஆலயத்தை அவர் தூய்மைப்படுத்தியபோது அவர் மீண்டும் ஏசாயாவைக் குறிப்பிட்டார் (மாற்கு 11:15-17; ஏசாயா 56:7; எரேமியா 7:11) மற்றும் அவர் சங்கீதத்தில் நம்முடைய மற்றும் திருச்சபையின் விசுவாசத்தின் பிரதான மூலக்கல்லாகவும் சித்தரிக்கப்பட்டுள்ளார் (மாற்கு 12:10-11; சங்கீதம் 118:22-23).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>மாற்கு இயேசுவை தேவனுடைய பாடு அனுபவிக்கிற ஊழியராகவும் (மாற்கு 10:45), மேலும் நமக்காக சேவை செய்யவும் பலியாகவும் வந்தவர், ஒரு பகுதியாக இதைச் செய்ய தூண்டுகிறார் என்பதையும் முன்வைக்கிறார். அவர் செய்ததைப் போலவே நாம் ஊழியம் செய்ய வேண்டும், அதே மனத்தாழ்மையும், மற்றவர்களின் சேவைக்கு பக்தியும் உண்டாக வேண்டும். தேவனுடைய ராஜ்யத்தில் பெரியவராக இருக்க, நாம் அனைவருக்கும் ஊழியராக இருக்க வேண்டும் என்பதை நினைவில் கொள்ளும்படி இயேசு நமக்கு அறிவுறுத்தினார் (மாற்கு 10:44). சுய தியாகம் என்பது அங்கீகாரம் அல்லது வெகுமதிக்கான நமது தேவைக்கு மேலானதாக இருக்கவேண்டும், இயேசு ஆடுகளுக்காக தனது உயிரைக் கொடுத்தபடியே அவமதிக்கப்படுவதற்கும் தயாராக இருந்தார்.</p><p>சுமார் கி.மு. 4 - கி.பி. 39 - ஏரோது அந்திப்பா. கலிலேயா, பெரேயா பகுதிகளில் \" ஆட்சி செய்தல்</p><p>சுமார் கி.பி. 14 - 37 - திபேரியு அரசர் ரோமப் பேரரசர்</p><p>சுமார் கி.பி. 25 -27 - யோவான்ஸ்நானனின் திருப்பணி</p><p>சுமார் கி.பி 26 - 36 - பொந்தியுபிலாத்து யூதேயா ஆளுநர்</p><p>சுமார் கி.பி. 27 - கிறிஸ்துவின் திருப்பணித் தொடக்கம்</p><p>சுமார் கி.பி. 29/30 - கிறிஸ்துவின் மரண அடக்க உயிர்ப்பு</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - மாற்கு</p><p>வேறு பெயர் - யோவான்</p><p>தாய் - மரியாள் (அப் 12: 11,12)</p><p>ஊர் -  எருசலேம்</p><p>உறவினர் - பர்னபா (கொலோ 4 : 10)</p><p>தொழில் - தெரியவில்லை /கிறிஸ்துவைப் பிடித்துச் செல்லும் போது வேடிக்கை பார்த்து நின்றவராக கருதப்படுகிறார் (மாற் 14 : 51,52). பின்பு மிஷனரியாக பணியாற்றினார். அப்போது பவுலும் பர்னபாவும் பிரியக் காரணமானார் (அப் 15 : 37, 38), பிற்காலத்தில் பவுலாலும் பேதுருவாலும் மிகவும் பாராட்டப்படத் தகுந்த நிலையில் நல்ல தேவ சேவகனாக விளங்கினார்.</p><p>சாதனை - முதன் முதலாக கிறிஸ்துவைப் பற்றிய சுவிசேஷ நூலை எழுதியது</p><p>சிறப்புப் பெயர் - முதல் சுவிசேஷ நூலாசிரியர்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 41-வது நான்</p><p>அதிகாரங்கள் - 16</p><p>வசனங்கள் - 678</p><p>கேள்விகள் - 121</p><p>பழைய ஏற்பாட்டுத் தீர்க்கதரிசனங்களின் நிறைவேறியவை - 12</p><p>புதிய ஏற்பாட்டுத் தீர்க்கதரிசனங்கள் - 30</p><p>வரலற்றுத் தொடர்பு வசனங்கள் - 582</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 43</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 53</p>'),
 (490,'<p><b>லூக்கா எழுதின சுவிசேஷம்</b></p><p><b>எழுத்தாளர்:</b></p><p>லூக்கா எழுதின சுவிசேஷம் அதன் எழுத்தாளரை குறிப்பாக யாரென்று அடையாளம் காண்பிக்கவில்லை. லூக்கா 1:1-4 மற்றும் அப்போஸ்தலர் 1:1-3 ஆகியவற்றிலிருந்து, ஒரே எழுத்தாளர் தான் லூக்கா எழுதின சுவிசேஷம் மற்றும் அப்போஸ்தலருடைய நடபடிகள் ஆகிய இரண்டையும் எழுதினார் என்பது தெளிவாகிறது, இரண்டையும் \"மகா கனம்பொருந்திய தெயோப்பிலுவே\" என்று அழைத்தார், ஒருவேளை இவர் ரோமாப் பிரமுகராக இருக்கலாம். திருச்சபையின் ஆரம்ப நாட்களிலிருந்து வந்த பாரம்பரியம் என்னவென்றால், ஒரு மருத்துவரும் அப்போஸ்தலனாகிய பவுலின் நெருங்கிய கூட்டாளியுமான லூக்கா தான் இந்த லூக்கா மற்றும் அப்போஸ்தலர் இரண்டையும் எழுதினார் என்பதாகும் (கொலோசெயர் 4:14; 2 தீமோத்தேயு 4:11). இது வேதாகமத்தின் புத்தகங்களை எழுதும் ஒரே புறஜாதியார் லூக்காவை உருவாக்குகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>லூக்காவின் நற்செய்தி கி.பி. 58 முதல் கி.பி. 65 ஆகிய காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>மத்தேயு மற்றும் மாற்கு ஆகிய மற்ற இரண்டு ஒருங்கிணைந்த சுவிசேஷப் புத்தகங்களைப் போலவே, இந்த புத்தகத்தின் நோக்கம் கர்த்தராகிய இயேசு கிறிஸ்துவையும் அவர் \"பரலோகத்திற்கு எடுத்துக்கொள்ளப்பட்ட நாள் வரை அவர் செய்யத் தொடங்கவும் கற்பிக்கவும்\" செய்ததை அனைத்தையும் வெளிப்படுத்துவதாகும் (அப்போஸ்தலர் 1:1-2). லூக்காவின் சுவிசேஷப் புத்தகமானது தனித்துவமானது, இது ஒரு துல்லியமான வரலாறு - லூக்காவின் மருத்துவ மனதுடன் ஒத்துப்போகின்ற ஒரு \"ஒழுங்கான கணக்கு\" (லூக்கா 1: 3) - பெரும்பாலும் மற்ற கணக்குகள் தவிர்க்கும் விவரங்களைத் இது தருகிறது. மாபெரும் வைத்தியரின் வாழ்க்கையை லூக்காவின் வரலாறு, அவருடைய ஊழியத்தை புறஜாதியினர், சமாரியர்கள், ஸ்திரீகள், குழந்தைகள், வரி வசூலிப்பவர்கள், பாவிகள் மற்றும் இஸ்ரேலில் வெளியேற்றப்பட்டவர்களாகக் கருதப்படும் மற்றவர்களுக்கும் அவருடைய இரக்கத்தை வலியுறுத்துகிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>லூக்கா 2:4-7: \"அப்பொழுது யோசேப்பும், தான் தாவீதின் வம்சத்தானும் குடும்பத்தானுமாயிருந்தபடியினாலே, தனக்கு மனைவியாக நியமிக்கப்பட்டுக் கர்ப்பவதியான மரியாளுடனே குடிமதிப்பெழுதப்படும்படி, கலிலேயா நாட்டிலுள்ள நாசரேத்தூரிலிருந்து யூதேயா நாட்டிலுள்ள பெத்லகேம் என்னும் தாவீதின் ஊருக்குப்போனான். அவ்விடத்திலே அவர்கள் இருக்கையில், அவளுக்குப் பிரசவகாலம் நேரிட்டது. அவள் தன் முதற்பேறான குமாரனைப்பெற்று, சத்திரத்திலே அவர்களுக்கு இடமில்லாதிருந்தபடியினால், பிள்ளையைத் துணிகளில் சுற்றி, முன்னணையிலே கிடத்தினாள்.\"</p><p>லூக்கா 3:16: \"யோவான் எல்லாருக்கும் பிரதியுத்தரமாக: நான் ஜலத்தினால் உங்களுக்கு ஞானஸ்நானங் கொடுக்கிறேன், என்னிலும் வல்லவர் ஒருவர் வருகிறார், அவருடைய பாதரட்சைகளின் வாரை அவிழ்க்கிறதற்கும், நான் பாத்திரன் அல்ல, அவர் பரிசுத்த ஆவியினாலும், அக்கினியினாலும் உங்களுக்கு ஞானஸ்நானங் கொடுப்பார்.\"</p><p>லூக்கா 4:18-19, 21: \"கர்த்தருடைய ஆவியானவர் என்மேலிருக்கிறார்; தரித்திரருக்குச் சுவிசேஷத்தைப் பிரசங்கிக்கும்படி என்னை அபிஷேகம்பண்ணினார்; இருதயம் நருங்குண்டவர்களைக் குணமாக்கவும், சிறைப்பட்டவர்களுக்கு விடுதலையையும், குருடருக்குப் பார்வையையும் பிரசித்தப்படுத்தவும், நொறுங்குண்டவர்களை விடுதலையாக்கவும், கர்த்தருடைய அநுக்கிரக வருஷத்தைப் பிரசித்தப்படுத்தவும், என்னை அனுப்பினார், என்று எழுதியிருக்கிற இடத்தை அவர் கண்டு, அப்பொழுது அவர் அவர்களோடே பேசத்தொடங்கி: உங்கள் காதுகள் கேட்க இந்த வேதவாக்கியம் இன்றையத்தினம் நிறைவேறிற்று என்றார்.\"</p><p>லூக்கா 18:31-32: \"பின்பு அவர் பன்னிருவரையும் தம்மிடத்தில் அழைத்து: இதோ, எருசலேமுக்குப் போகிறோம், மனுஷகுமாரனைக் குறித்துத் தீர்க்கதரிசிகளால் எழுதப்பட்டவைகளெல்லாம் நிறைவேறும். எப்படியெனில், அவர் புறஜாதியாரிடத்தில் ஒப்புக்கொடுக்கப்பட்டு, பரியாசமும் நிந்தையும் அடைந்து, துப்பப்படுவார்.\"</p><p>லூக்கா 23:33-34: \"கபாலஸ்தலம் என்று சொல்லப்பட்ட இடத்தில் அவர்கள் சேர்ந்தபொழுது, அவரையும், அவருடைய வலதுபக்கத்தில் ஒரு குற்றவாளியையும், அவருடைய இடதுபக்கத்தில் ஒரு குற்றவாளியையும் சிலுவைகளில் அறைந்தார்கள். அப்பொழுது இயேசு: பிதாவே இவர்களுக்கு மன்னியும், தாங்கள் செய்கிறது இன்னதென்று அறியாதிருக்கிறார்களே என்றார். அவருடைய வஸ்திரங்களை அவர்கள் பங்கிட்டுச் சீட்டுப்போட்டார்கள்.\"</p><p>லூக்கா 24:1-3: \"வாரத்தின் முதலாம்நாள் அதிகாலையிலே தாங்கள் ஆயத்தம்பண்ணின அந்த கந்தவர்க்கங்களை அவர்கள் எடுத்துக்கொண்டு வேறு சில ஸ்திரீகளோடுங்கூடக் கல்லறையினிடத்தில் வந்தார்கள். கல்லறையை அடைத்திருந்த கல் புரட்டித் தள்ளப்பட்டிருக்கிறதைக் கண்டு, உள்ளே பிரவேசித்து, கர்த்தராகிய இயேசுவின் சரீரத்தைக் காணாமல்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>இதுவரையில் எழுதப்பட்ட புத்தகங்களில் மிகவும் அழகான புத்தகம் என்று அழைக்கப்படும் லூக்கா எழுதின சுவிசேஷம் இயேசுவின் பெற்றோரைப் பற்றி நமக்குக் கூறித் தொடங்குகிறது; அவரது உறவினர் யோவான்ஸ்நானனின் பிறப்பு; மரியாள் மற்றும் யோசேப்பின் பெத்லகேம் பயணம், அங்கு இயேசு ஒரு மாட்டுத்தொழுவத்தில் பிறந்தார்; மரியாள் மூலம் வருகிற கிறிஸ்துவின் பரம்பரை விவரிக்கப்பட்டுள்ளது. இயேசுவின் பொதுவான பகிரங்க ஊழியம் கெட்டகுமாரன், ஐசுவரியவான் மற்றும் லாசரு, மற்றும் நல்ல சமாரியனின் கதைகள் மூலம் அவருடைய மனதுருக்கம் மற்றும் மன்னிப்பை வெளிப்படுத்துகிறது. எல்லா மனித வரம்புகளையும் மீறும் இந்த பாரபட்சமற்ற அன்பை பலர் நம்புகிறார்கள், இன்னும் பலர் நம்பிக்கை வைக்கிறார்கள், இருப்பினும் இயேசுவின் கூற்றுக்களை பலர் சவால் செய்கிறார்கள், எதிர்க்கிறார்கள் குறிப்பாக மதத் தலைவர்கள். கிறிஸ்துவின் சீஷர்கள் சீஷத்துவத்தின் விலையை கணக்கிட ஊக்குவிக்கப்படுகிறார்கள், அதே நேரத்தில் அவருடைய எதிரிகள் சிலுவையில் அவருடைய மரணத்தை நாடுகிறார்கள். இறுதியாக, இயேசு காட்டிக் கொடுக்கப்படுகிறார், விசாரிக்கப்படுகிறார், தண்டிக்கப்படுகிறார், சிலுவையில் அறையப்படுகிறார். ஆனால் கல்லறை அவரைப் பிடித்து வைக்க முடியாமல் போனது! இழந்துபோனவர்களைத் தேடுவதும் இரட்சிப்பதுமே அவருடைய ஊழியத்தின் தொடர்ச்சியை அவருடைய உயிர்த்தெழுதலில் உறுதிப்படுத்துகிறது.</p><p><b>இணைப்புகள்:</b></p><p>ஒரு புறஜாதியார் என்ற முறையில், பழைய ஏற்பாட்டைப் பற்றிய லூக்காவின் குறிப்புகள் மத்தேயுவின் நற்செய்தியுடன் ஒப்பிடும்போது மிகக் குறைவுதான், மேலும் பழைய ஏற்பாட்டுக் குறிப்புகள் பெரும்பாலானவை லூக்காவின் சரிதைகளில் அல்லாமல் இயேசு தாம் பேசிய வார்த்தைகளில் அடங்கியுள்ளன. இயேசு பழைய ஏற்பாட்டை சாத்தானின் தாக்குதல்களுக்கு எதிராகப் பயன்படுத்தினார், அவனுக்கு \"எழுதியிருக்கிறதே\" என்று பதிலளித்தார் (லூக்கா 4:1-13); வாக்குறுதியளிக்கப்பட்ட மேசியா என்று தன்னை அடையாளம் காண்பிக்க (லூக்கா 4:17-21); பரிசேயருக்கு நியாயப்பிரமாணத்தைக் கடைப்பிடிக்க இயலாமை மற்றும் இரட்சகரின் தேவை ஆகியவற்றை நினைவூட்டுவதற்காக (லூக்கா 10: 25-28, 18: 18-27); அவரைப் பிடிக்கவும் ஏமாற்றவும் முயன்றபோது அவர்களின் கற்றலைக் குழப்பவும் (லூக்கா 20) மேற்கோள் காட்டப்பட்டுள்ளது.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நம்முடைய இரக்கமுள்ள இரட்சகரின் அழகிய உருவப்படத்தை லூக்கா நமக்குத் தருகிறார். ஏழைகள் மற்றும் ஏழைகளால் இயேசு \"அணைக்கப்படவில்லை\"; உண்மையில், அவைகள்தான் அவருடைய ஊழியத்தின் முதன்மையான மையமாக இருந்தன. அந்த நேரத்தில் இஸ்ரவேல் தேசம் இயேசு வாழ்ந்த நாட்களில் மிகவும் ஜாதி இன வர்க்க உணர்வுள்ள ஒரு சமூகமாக இருந்தது. பலவீனமான மற்றும் நலிந்தவர்கள் வாழ்க்கையில் தங்கள் வாழ்க்கையை மேம்படுத்துவதற்கு உண்மையில் சக்தியற்றவர்களாக இருந்தனர், குறிப்பாக \"தேவனுடைய ராஜ்யம் உங்களுக்குச் சமீபமாய் வந்திருக்கிறது\" (லூக்கா 10:9) என்ற செய்தியைத் திறந்திருந்தது. இது நம்மைச் சுற்றியுள்ளவர்களும் கேட்க வேண்டிய ஒரு முக்கியமான செய்தியாகும். ஒப்பீட்டளவில் செல்வந்த நாடுகளில் கூட - ஒருவேளை குறிப்பாக – ஆவிக்குரியத் தேவை மிகவும் மோசமானதாக இருக்கிறது. கிறிஸ்தவர்கள் இயேசுவின் முன்மாதிரியைப் பின்பற்றி, ஆவிக்குரிய ரீதியில் ஏழைகளுக்கும் நலிந்தோர்களுக்கும் இரட்சிப்பின் நற்செய்தியைக் கொண்டு செல்ல வேண்டும். தேவனுடைய ராஜ்யம் நெருங்கிவிட்டது, ஒவ்வொரு நாளும் செல்லச்செல்ல நேரம் குறைந்துகொண்டே இருக்கிறது.</p><p>சுமார் கி.மு. 37 - 4 - பெரிய ஏரோதின் ஆட்சி</p><p>சுமார் கி.மு. 31 - கி.பி. 14 - அகஸ்துராயன் ரோமப் பேரரசர்</p><p>சுமார் கி.மு. 4/5 - கிறிஸ்துவின் பிறப்பு</p><p>சுமார் கி.மு. 4 - கி.பி. 39 ஏரோது அந்திப்பா கலிலேயா பெரேயா பகுதி அரசர்</p><p>சுமார் கி.பி. 14 – 37 - திபேரரியுராயர் ரோமப் பேரரசர்</p><p>சுமார் கி.பி. 25 - 27 - யோவான்ஸ்நானனின் திருப்பணி</p><p>சுமார் கி.பி. 26 - 36 - பொந்தியு பிலாத்து யூதேயா. ஆளுநர்</p><p>சுமார் கி.பி. 29/30 - கிறிஸ்துவின் சிலுவை மரணமும் உயிர்ப்பும்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - டாக்டர். லூக்கா</p><p>குலம் - கிரேக்கர்/ ஒரே புதிய ஏற்பாட்டு புறஜாதி எழுத்தாளர்</p><p>பிறந்த ஊர் - அந்தியோகியாவாக இருக்கலாம்</p><p>குடும்பம் - சிறந்த கல்விமிக்க, கலாச்சாரம்மிக்க குடும்பம்</p><p>தொழில் - மருத்துவர். பின்பு மருத்துவ மிஷனரி (?)</p><p>படைப்புகள் - லூக்கா எழுதிய சுவிசேஷம் அப்போஸ்தல நடபடிகள்</p><p>சாதனை - புதிய ஏற்பாட்டின் கால் (1/4) பகுதியை தமது வரலாற்று ஆதாரமிக்க படைப்புகளால் நிறைத்தது</p><p>சிறப்பு பட்டம் - பிரியமான வைத்தியனான லூக்கா\" (கொலோ 4 : 4)</p><p>\"முழுமை மனிதனைப் பற்றிய ஆராய்சியாளர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 42-வது நூல்</p><p>அதிகாரங்கள் - 24</p><p>வசனங்கள் - 1,151</p><p>கேள்விகள் - 165</p><p>பழைய ஏற்பாட்டுத் தீர்க்கதரிசனங்கள் - 9</p><p>பதிய ஏற்பாட்டுத் தீர்க்க தரிசனங்கள் - 54</p><p>வரலாற்று வசனங்கள் - 930</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள்  - 118</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 103</p>'),
 (50,'<p><b>உபாகமம் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>மோசே உபாகமம் புத்தகத்தை எழுதினார், இது உண்மையில் இஸ்ரவேலர்கள் யோர்தானைக் கடப்பதற்கு சற்று முன்பு இஸ்ரவேலர்களுக்கு அவர் ஆற்றிய பிரசங்கங்களின் தொகுப்பாகும். \"மோசே இஸ்ரவேலர் எல்லாரையும் நோக்கிச் சொன்ன வசனங்களாவன\" (1:2). வேறு யாரோ ஒருவர் (ஒருவேளை யோசுவாவாக இருக்கலாம்) இந்த புத்தகத்தின் கடைசி அதிகாரத்தை எழுதியிருக்கலாம்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>இஸ்ரவேலர்கள் வாக்குப்பண்ணப்பட்ட தேசத்திற்குள் நுழைவதற்கு 40 நாட்களுக்கு முன்னர் இந்த பிரசங்கங்கள் மோசேயினால் வழங்கப்பட்டன. முதல் பிரசங்கம் பதினோராம் மாதம் முதல் தேதியிலே (1:4) வழங்கப்பட்டது, இஸ்ரவேலர்கள் 70 நாட்களுக்குப் பிறகு, முதல் மாதம் பத்தாம் தேதியிலே ஜனங்கள் யோர்தானிலிருந்து கரையேறி, எரிகோவுக்குக் கீழ் எல்லையான கில்காலிலே பாளயமிறங்கினார்கள் (யோசுவா 4:19). மோசேயின் மரணத்திற்குப் பிறகு 30 நாட்கள் துக்கத்தை ஆசரித்ததை கழித்தால் (உபாகமம் 34:8), நமக்கு மீதமுள்ளது 40 நாட்கள். ஆக, இந்த புத்தகம் எழுதப்பட்ட ஆண்டு கி.மு. 1410.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>புதிய தலைமுறை இஸ்ரவேலர்கள் வாக்குப்பண்ணப்பட்ட தேசத்திற்குள் நுழையவிருந்தனர். இந்த கூட்டம் செங்கடலில் நடந்த அதிசயத்தை அனுபவிக்கவில்லை அல்லது சீனாய் மலையில் கொடுக்கப்பட்ட நியாயப்பிரமாண சட்டத்தைக் கேட்கவில்லை, மேலும் அவர்கள் பல ஆபத்துகளையும் சோதனையையும் கொண்டு ஒரு புதிய தேசத்திற்குள் நுழையவிருந்தனர். தேவனுடைய நியாயப்பிரமாணம் மற்றும் தேவனுடைய வல்லமை ஆகியவற்றை நினைவூட்டுவதற்காக இந்த உபாகமம் புத்தகம் எழுதப்பட்டது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>\"நான் உங்களுக்குக் கற்பிக்கும் உங்கள் தேவனாகிய கர்த்தரின் கட்டளைகளை நீங்கள் கைக்கொள்ளும்படி, நான் உங்களுக்குக் கற்பிக்கிற வசனத்தோடே நீங்கள் ஒன்றும் கூட்டவும் வேண்டாம், அதில் ஒன்றும் குறைக்கவும் வேண்டாம்.\" (உபாகமம் 4:2)</p><p><b>\"இஸ்ரவேலே, கேள்:</b></p><p>நம்முடைய தேவனாகிய கர்த்தர் ஒருவரே கர்த்தர். நீ உன் தேவனாகிய கர்த்தரிடத்தில் உன் முழு இருதயத்தோடும், உன் முழு ஆத்துமாவோடும், உன் முழுப் பலத்தோடும் அன்புகூருவாயாக. இன்று நான் உனக்குக் கட்டளையிடுகிற இந்த வார்த்தைகளை உன் இருதயத்தில் இருக்கக்கடவது. நீ அவைகளை உன் பிள்ளைகளுக்குக் கருத்தாய்ப் போதித்து, நீ உன் வீட்டில் உட்கார்ந்திருக்கிறபோதும், வழியில் நடக்கிறபோதும், படுத்துக்கொள்ளுகிறபோதும், எழுந்திருக்கிறபோதும் அவைகளைக் குறித்துப் பேசுங்கள்.\" (உபாகமம் 6:4-7)</p><p><b>\"அவர்களை நோக்கி:</b></p><p>இந்த நியாயப்பிரமாண வார்த்தைகளின்படியெல்லாம் உங்கள் பிள்ளைகள் செய்யும்படி கவனமாயிருக்க, நீங்கள் அவர்களுக்குக் கற்பிக்கும்படி, நான் இன்று உங்களுக்குச்சாட்சியாய் ஒப்புவிக்கிற வார்த்தைகளையெல்லாம் உங்கள் மனதிலே வையுங்கள். இது உங்களுக்கு வியர்த்தமான காரியம் அல்லவே; இது உங்கள் ஜீவனாயிருக்கிறது, நீங்கள் சுதந்தரித்துக்கொள்ளும்படி யோர்தானைக் கடந்துபோய்ச் சேரும்தேசத்தில் இதினால் உங்கள் நாட்களை நீடிக்கப்பண்ணுவீர்கள் என்றான்.\" (உபாகமம் 32:46-47)</p><p><b>சுருக்கமான திரட்டு:</b></p><p>தேவனுடைய உண்மை, தேவனுடைய பரிசுத்தம், தேவனுடைய ஆசீர்வாதம் மற்றும் தேவனுடைய எச்சரிக்கைகள் ஆகிய நான்கு விஷயங்களை நினைவில் வைக்கவேண்டும் என்று இஸ்ரவேலர்களுக்கு கட்டளையிடப்பட்டுள்ளது. முதல் மூன்று அதிகாரங்கள் எகிப்திலிருந்து தாங்கள் தற்போது வந்து சேர்ந்திருக்கிற இடமான மோவாபிற்கு முந்தைய பயணத்தை மீண்டும் ஞாபகம் மூட்டுகின்றன. 4ஆம் அதிகாரம் கீழ்ப்படிதலுக்கான அழைப்பு, அவர்களுக்கு உண்மையுள்ள தேவனுக்கு அவர்கள் உண்மையாக இருக்க வேண்டும் என்பதை வலியுறுத்துகின்றன.</p><p>5 முதல் 26 வரையிலுள்ள அதிகாரங்கள் நியாயப்பிரமாண சட்டத்தை மறுபடியும் எடுத்துகூறல் ஆகும். பத்து கட்டளைகள், பலிகள் மற்றும் விசேஷித்த நாட்கள் தொடர்பான சட்டங்கள் மற்றும் மீதமுள்ள சட்டம் புதிய தலைமுறைக்கு வழங்கப்படுகின்றன. கீழ்ப்படிவோருக்கு ஆசீர்வாதமும் வாக்குறுதி அளிக்கப்படுகிறது (5:29; 6:17-19; 11:13-15), அவரது சட்டத்தை மீறுபவர்களுக்கு பஞ்சம் வாக்குறுதி அளிக்கப்படுகிறது (11:16-17).</p><p>ஆசீர்வாதம் மற்றும் சாபம் என்கிற கருப்பொருள் 27-30 வரையிலுள்ள அதிகாரங்களில் தொடர்கிறது. புத்தகத்தின் இந்த பகுதி இஸ்ரவேலர்களுக்கு முன்பாக ஒரு தெளிவான தேர்வோடு முடிவடைகிறது: \"நான் ஜீவனையும் மரணத்தையும், ஆசீர்வாதத்தையும் சாபத்தையும் உனக்குமுன் வைத்தேன் என்று உங்கள்மேல் வானத்தையும் பூமியையும் இன்று சாட்சிவைக்கிறேன்; ஆகையால், நீயும் உன் சந்ததியும் பிழைக்கும்படிக்கு, நீ ஜீவனைத் தெரிந்துகொள்ளுங்கள்\" (30:19) .</p><p>கடைசி அதிகாரங்களில், மோசே ஜனங்களை ஊக்குவிக்கிறார்; அவருக்குப் பதிலாக அவருடைய ஸ்தானத்தில் இஸ்ரவேலர்களை நடத்தும்படிக்கு யோசுவாவை நியமிக்கிறார்; ஒரு பாடலும் பதிவுசெய்யப்படுகிறது; இஸ்ரவேலின் ஒவ்வொரு கோத்திரங்களுக்கும் இறுதியான ஆசீர்வாதம் அளிக்கப்படுறது. 34-ஆம் அதிகாரம் மோசேயின் மரணத்தின் சூழ்நிலைகளைப் பற்றியது. அவர் பிஸ்கா மலையின்மேல் ஏறினார், அங்கு தேவன் அவனுக்கு அவனால் நுழைய முடியாத வாக்குறுதியளிக்கப்பட்ட கானான் தேசத்தைக் காட்டினார். மோசே தனது 120வது வயதில், ஆனால் நல்ல பார்வை மற்றும் இளமையின் வலிமையுடன், கர்த்தருடைய சந்நிதியில் மரணத்தை தழுவினார். உபாகமம் புத்தகம் இந்த பெரிய தீர்க்கதரிசி பற்றிய ஒரு குறுகிய இரங்கலுடன் முடிகிறது.</p><p><b>முன்னிழல்கள்:</b></p><p>உபாகமம் புத்தகத்தில் பல புதிய ஏற்பாட்டு கருப்பொருள்கள் அடங்கியுள்ளன. அவற்றில் முதன்மையானது மோசேயின் நியாயப்பிரமாணத்தை முழுமையாகக் கடைப்பிடிக்க வேண்டியதன் அவசியமும் அவ்வாறு செய்ய இயலாமலும் இருக்கிற நிலையை குறிப்பிடுகிறது. நியாயப்பிரமாணத்தை தொடர்ந்து மீறிய மக்களின் பாவங்களுக்கு பரிகாரம் செய்வதற்குத் தேவையான முடிவற்ற பலிகள், கிறிஸ்துவின் \"அனைவருக்குமுள்ள\" இறுதி பலியில் அவற்றின் நிறைவேற்றத்தைக் காண்கிறது (எபிரெயர் 10:10). சிலுவையில் அவர் செய்த பாவப்பரிகார வேலையின் காரணமாக, பாவத்திற்காக நமக்கு மேலும் பலிகள் தேவையில்லை என்பதை காண்பிக்கின்றன.</p><p>தேவன் இஸ்ரவேலரைத் தம்முடைய விசேஷித்த மக்களாகத் தேர்ந்தெடுப்பது கிறிஸ்துவை விசுவாசிக்கிறவர்களை அவர் தேர்ந்தெடுப்பதை முன்னறிவிக்கிறது (1 பேதுரு 2:9). உபாகமம் 18:15-19-ல் மோசே மற்றொரு பெரிய தீர்க்கதரிசியைப் பற்றி தீர்க்கதரிசனமாக கூறுகிறார் – இறுதியாக வரும் மேசியாவே அந்த தீர்க்கத்தரிசி. மோசேயைப் போலவே, அவர் தெய்வீக வெளிப்பாட்டைப் பெற்று பிரசங்கிப்பார், மேலும் அவர் தம் மக்களை வழிநடத்துவார் (யோவான் 6:14; 7:40).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>உபாகமம் புத்தகம் தேவனுடைய வார்த்தையின் முக்கியத்துவத்தை அடிக்கோடிட்டுக் காட்டுகிறது. இது நம் வாழ்வின் ஒரு முக்கிய பகுதியாகும். நாம் இனி பழைய ஏற்பாட்டுச் சட்டத்தின் கீழ் இல்லை என்றாலும், நம் வாழ்வில் தேவனுடைய சித்தத்திற்கு அடிபணிவது இன்னும் ஏற்ற பொறுப்பாக இருக்கிறது. எளிய கீழ்ப்படிதல் ஆசீர்வாதத்தைத் தருகிறது, பாவத்திற்கு அதன் சொந்த விளைவுகள் உண்டு.</p><p>நம்மில் யாரும் \"நியாயப்பிரமாணத்திற்கு மேலானவர்கள்\" அல்ல. தேவனால் தேர்ந்தெடுக்கப்பட்ட தலைவரும் தீர்க்கதரிசியுமான மோசே கூட கீழ்ப்படிய வேண்டியிருந்தது. அவர் வாக்குப்பண்ணப்பட்ட தேசத்திற்குள் நுழைய அனுமதிக்கப்படாததற்குக் காரணம், அவர் கர்த்தருடைய தெளிவான கட்டளைக்கு கீழ்ப்படியாததுதான் (எண்ணாகமம் 20:13).</p><p>வனாந்தரத்தில் இயேசு பிசாசினால் சோதிக்கப்பட்ட காலத்தில், அவர் உபாகமம் புத்தகத்திலிருந்து மூன்று முறையும் மேற்கோள் காட்டினார் (மத்தேயு 4). அவ்வாறு அவர் செய்து, நாம் அவருக்கு எதிராக பாவம் செய்யக்கூடாதபடிக்கு தேவனுடைய வார்த்தையை நம் இருதயங்களில் மறைத்து வைப்பதன் அவசியத்தை இயேசு நமக்கு விளக்கினார் (சங்கீதம் 119:11).</p><p>தேவனுடைய உண்மையை இஸ்ரவேலர்கள் நினைவில் வைத்திருப்பதால், நாமும் அவ்வாறு செய்ய வேண்டும். செங்கடலைக் கடந்தது, சீனாய் மலையில் தேவனுடைய பரிசுத்த பிரசன்னம், வனாந்திரத்தில் தேவன் அவர்களுக்கு கொடுத்த மன்னாவின் ஆசீர்வாதம் ஆகியவை நமக்கும் ஒரு ஊக்கமாக இருக்க வேண்டும். முன்னோக்கிச் செல்ல ஒரு சிறந்த வழி, சிறிது நேரம் எடுத்துக்கொண்டு திரும்பிப் பார்த்து, தேவன் நமக்கு என்ன செய்திருக்கிறார் என்பதைப் பார்ப்பதாகும்.</p><p>அவருடைய பிள்ளைகளுடனான உறவை விரும்பும் அன்பான தேவனுடைய இருதயம் உபாகமத்தில் ஒரு அழகான சித்திரமாக உள்ளது. இஸ்ரவேலர்களை எகிப்திலிருந்து \"வல்லமையுள்ள கரத்தைக்\" கொண்டு அவர்களை மீட்டுக்கொண்டதற்கு அன்பு என்று கர்த்தர் பெயரிடுகிறார் (உபாகமம் 7:7-9). பாவத்தின் அடிமைத்தனத்திலிருந்து விடுபட்டு, சர்வ வல்லமையுள்ள தேவனால் நேசிக்கப்படுவது எவ்வளவு அற்புதமான விஷயம்!</p><p>சுமார் கி.மு. 1571 (1527) - மோசேயின் பிறப்பு</p><p>சுமார் கி.மு.1491 (1446) - யாத்திராகம புறப்படுதல்</p><p>சுமார் கி.மு. 1490 (1445)  - பத்து கட்டளைகளைப் பெறுதல்</p><p>சுமார் கி.மு.1490 (1445) - கானானை ஒற்று நோக்கல்</p><p>சுமார் கி.மு. 1452 (1407) - மோசேயின் உபாகம பிரசங்கம்</p><p>சுமார் கி.மு. 1452 (1407) - மோசேயின் மரணம்</p><p>சுமார் கி.மு. 1452 (1407) - யோசுவாவின் தலைமைப் பொறுப்பு</p><p>ஏற்பு</p><p>சுமார் கி.மு. 1451 (1406) - இஸ்ரவேலர் கானானில் செல்லுதல்</p><p><b>ஆசிரியர் குறிப்பு.</b></p><p>பெயர் - மோசே (பொருள்: இழுத்தெடுக்கப்பட்டவர்)</p><p>பெற்றோர் - தந்தை அம்ராம்,</p><p>தாய் - யோகெபேத் (யாத் 6 : 20). பின்பு பார்வோனின் மகளால் தத்தெடுக்கப்பட்டவர்</p><p>சொந்த இடம் - எகிப்து</p><p>தொழில் - அரண்மனை கல்வி, பின்பு ஆடு மேய்ப்பு அதன்பின் இலட்சக்கணக்கான மக்களை கானானுக்கு வழிநடத்தியது\"</p><p>திருப்புமுனை  - மந்தைமேய்த்துக் கொண்டிருக்கும்போது\" முட்செடியில் தேவனைத் தரிசித்தபின் வந்த அழைப்பு</p><p>ஆர்வம் - எபிரெயரை விடுவித்து, பத்திரமாக</p><p>கானானுக்கு வழிநடத்துவது</p><p>சாதனைகள்  - பார்வோனுக்கு முன் அற்புதங்களைச் செய்தது, ஐந்தாகமங்களை எழுதியது. உலகத்தோற்றம் பற்றிய</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 5-வது நூல்</p><p>அதிகாரங்கள் - 34</p><p>வசனங்கள் - 958</p><p>கேள்விகள் - 33</p><p>வரலாற்று அடிப்படையிலான வசனங்கள் - 690</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 230</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 37</p><p>தேவளிடமிருந்து சிறப்புச் செய்திகள் - 33</p><p>கட்டளைகள் - 519</p><p>வாக்குத்தத்தங்கள் - 47</p><p>எச்சரிப்புகள் - 497</p>'),
 (500,'<p><b>யோவான் எழுதின சுவிசேஷம்</b></p><p><b>எழுத்தாளர்:</b></p><p>யோவான் 21:20-24, எழுத்தாளர் தன்னை \"இயேசுவுக்கு அன்பாயிருந்த சீஷன்\" என்று விவரிக்கிறார், வரலாற்று மற்றும் உள்ளான காரணங்களால் இது செபுதேயுவின் குமாரர்களில் ஒருவரான யோவான் அப்போஸ்தலன் என்று புரிந்து கொள்ளப்படுகிறது (லூக்கா 5:10).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>கி.பி. 135-ல் தேதியிட்ட சில பாப்பிரஸ் துண்டுகளை கண்டுபிடித்ததன் அடிப்படையில், அதற்கு முன்னர் இந்த புத்தகம் எழுதப்பட்டு, நகலெடுக்கப்பட்டு, புழக்கத்தில் விடப்பட்டிருக்க வேண்டும் என்பது தெளிவாகிறது. அதே வேளையில் எருசலேம் அழிக்கப்படுவதற்கு (கி.பி. 70), முன்பு இது எழுதப்பட்டதாக சிலர் நினைக்கிறார்கள், ஆகவே கி.பி. 85-90 வரையிலுள்ள காலம் இதன் எழுத்துக்கு மிகவும் ஏற்றுக்கொள்ளப்பட்ட காலமாக இருக்கிறது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>யோவான் 20:31ல், பின்வருமாறு நோக்கத்தை யோவான் மேற்கோளிடுகிறார்: \"இயேசு தேவனுடைய குமாரனாகிய கிறிஸ்து என்று நீங்கள் விசுவாசிக்கும்படியாகவும், விசுவாசித்து அவருடைய நாமத்தினாலே நித்தியஜீவனை அடையும்படியாகவும், இவைகள் எழுதப்பட்டிருக்கிறது.\" மூன்று ஒருங்கிணைந்த சுவிசேஷப் புத்தகங்களைப் போலல்லாமல், யோவானின் நோக்கம் கிறிஸ்துவின் வாழ்க்கையைப் பற்றிய காலவரிசைக் கதையை முன்வைப்பதல்ல, மாறாக அவருடைய தெய்வத்துவத்தைக் காண்பிப்பதாகும். யோவான் இரண்டாம் தலைமுறை விசுவாசிகளின் நம்பிக்கையை வலுப்படுத்தவும், மற்றவர்களையும் இந்த விசுவாசத்திற்குள்ளாக வரும்படிக்கு வளர்க்கவும் முயன்றது மட்டுமல்லாமல், பரவி வரும் ஒரு தவறான போதனையையும் சரிசெய்ய முயன்றார். யோவான் இயேசு கிறிஸ்துவை \"தேவனுடைய குமாரன்\" என்று வலியுறுத்தினார், பரிபூரணமான தேவனாகவும், பரிபூரணமான மனிதனாகவும், \"கிறிஸ்து-ஆவி\" என்கிற மனித இயேசுவின் ஞானஸ்நானத்தில் வந்து அவரை சிலுவையில் அறையும்படி பார்த்த பொய்யான கோட்பாட்டிற்கு மாறாக யோவான் இதை விவரித்து தெளிவு படுத்துகிறார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>\"ஆதியிலே வார்த்தை இருந்தது, அந்த வார்த்தை தேவனிடத்திலிருந்தது, அந்த வார்த்தை தேவனாயிருந்தது. அந்த வார்த்தை மாம்சமாகி, கிருபையினாலும் சத்தியத்தினாலும் நிறைந்தவராய், நமக்குள்ளே வாசம்பண்ணினார்; அவருடைய மகிமையைக் கண்டோம்; அது பிதாவுக்கு ஒரே பேறானவருடைய மகிமைக்கு ஏற்ற மகிமையாகவே இருந்தது.\" (யோவான் 1:1,14).</p><p>\"மறுநாளிலே யோவான் இயேசுவைத் தன்னிடத்தில் வரக்கண்டு: இதோ, உலகத்தின் பாவத்தைச் சுமந்துதீர்க்கிற தேவ ஆட்டுக்குட்டி.\" (யோவான் 1:29).</p><p>\"தேவன், தம்முடைய ஒரேபேறான குமாரனை விசுவாசிக்கிறவன் எவனோ அவன் கெட்டுப்போகாமல் நித்தியஜீவனை அடையும்படிக்கு, அவரைத் தந்தருளி, இவ்வளவாய் உலகத்தில் அன்புகூர்ந்தார்.\" (யோவான் 3:16).</p><p><b>\"இயேசு அவர்களுக்குப் பிரதியுத்தரமாக:</b></p><p>அவர் அனுப்பினவரை நீங்கள் விசுவாசிப்பதே தேவனுக்கேற்ற கிரியையாயிருக்கிறது என்றார்.\" (யோவான் 6:29).</p><p>\"நான் அவைகளுக்கு நித்தியஜீவனைக் கொடுக்கிறேன்; அவைகள் ஒருக்காலும் கெட்டுப்போவதில்லை, ஒருவனும் அவைகளை என் கையிலிருந்து பறித்துக்கொள்வதுமில்லை.\" (யோவான் 10:28).</p><p><b>\"இயேசு அவளை நோக்கி:</b></p><p>நானே உயிர்த்தெழுதலும் ஜீவனுமாயிருக்கிறேன், என்னை விசுவாசிக்கிறவன் மரித்தாலும் பிழைப்பான்; உயிரோடிருந்து என்னை விசுவாசிக்கிறவனெவனும் என்றென்றைக்கும் மரியாமலும் இருப்பான்; இதை விசுவாசிக்கிறாயா என்றார்.\" (யோவான் 11:25-26).</p><p><b>\"அதற்கு இயேசு:</b></p><p>நானே வழியும் சத்தியமும் ஜீவனுமாயிருக்கிறேன்; என்னாலேயல்லாமல் ஒருவனும் பிதாவினிடத்தில் வரான்.\" (யோவான் 14:6).</p><p><b>\"அதற்கு இயேசு:</b></p><p>பிலிப்புவே, இவ்வளவுகாலம் நான் உங்களுடனேகூட இருந்தும் நீ என்னை அறியவில்லையா? என்னைக் கண்டவன் பிதாவைக் கண்டான்; அப்படியிருக்க, பிதாவை எங்களுக்குக் காண்பியும் என்று நீ எப்படி சொல்லுகிறாய்?\" (யோவான் 14:9).</p><p>\"உம்முடைய சத்தியத்தினாலே அவர்களைப் பரிசுத்தமாக்கும்; உம்முடைய வசனமே சத்தியம்.\" (யோவான் 17:17).</p><p>\"இயேசு காடியை வாங்கினபின்பு, முடிந்தது என்று சொல்லி, தலையைச்சாய்த்து, ஆவியை ஒப்புக்கொடுத்தார்.\" (யோவான் 19:30).</p><p>\"அதற்கு இயேசு: தோமாவே, நீ என்னைக் கண்டதினாலே விசுவாசித்தாய், காணாதிருந்தும் விசுவாசிக்கிறவர்கள் பாக்கியவான்கள் என்றார்.\" (யோவான் 20:29).</p><p><b>சுருக்கமான திரட்டு:</b></p><p>கிறிஸ்துவின் தெய்வத்துவத்தை நிரூபிப்பதற்கும் அவருடைய ஊழியத்தை விளக்குவதற்கும் அடையாளங்களாக யோவானின் நற்செய்தி ஏழு அற்புதங்களை மட்டுமே தேர்ந்தெடுக்கிறது. இந்த அறிகுறிகள் மற்றும் சம்பவங்கள் சில யோவானில் மட்டுமே காணப்படுகின்றன. நான்கு நற்செய்திகளில் இது மிகவும் இறையியல் மற்றும் பிற நற்செய்திகளில் குறிப்பிடப்பட்டுள்ள நிகழ்வுகளுக்குப் பின்னால் இருக்கும் காரணத்தைக் கூறுகிறது. பரிசுத்த ஆவியானவர் தனது பரமேறுதலுக்குப் பிறகு இறங்கி வரும் ஊழியத்தைப் பற்றி அவர் அதிகம் பகிர்ந்து கொள்கிறார். யோவான் தனது நற்செய்தியின் தொடர்ச்சியான கருப்பொருள்களைக் காட்டும் சில சொற்கள் அல்லது சொற்றொடர்கள் உள்ளன: விசுவாசியுங்கள், சாட்சி, தேற்றரவாளர், ஜீவன் - மரணம், ஒளி - இருள், நானே ... (இயேசு \"நானே\" என மொழிந்த கூற்றுக்கள்), மற்றும் அன்பு.</p><p>யோவான் நற்செய்தி கிறிஸ்துவை அவரது பிறப்பிலிருந்து அல்ல, மாறாக \"ஆதியில்\" இருந்த \"வார்த்தை\" (லோகோஸ்) என்று அறிமுகப்படுத்துகிறது, அவர் தேவனாக, படைப்பின் ஒவ்வொரு அம்சத்திலும் ஈடுபட்டுள்ளார் (1:1-3) பின்னர் அவர் இந்த பூமிக்கு வரும்படிக்கு மாம்சமாக மாறுகிறார் (1:14) அவர் குற்றமில்லாத, பழுதற்ற பலியிடப்பட்ட ஆட்டுக்குட்டியாக நம் பாவங்களை அகற்றுவதற்காக (யோவான் 1:29) ஜீவனையே தந்தார். இயேசு மேசியா என்பதைக் காட்டும் ஆவிக்குரிய உரையாடல்களை யோவான் தேர்ந்தெடுக்கிறார் (4:26) மற்றும் சிலுவையில் அவர் அடைந்த மரணத்தின் மூலம் ஒருவர் எவ்வாறு இரட்சிக்கப்படுகிறார் என்பதை விளக்குகிறார் (3:14-16). யூதத் தலைவர்களைத் திருத்துவதன் மூலம் அவர் பலமுறை கோபப்படுகிறார் (2:13-16); ஓய்வுநாளில் குணப்படுத்துதல், மற்றும் தேவனுக்கு சொந்தமான சுபாவ குணாதிசயங்கள் (5:18; 8:56-59; 9:6,16; 10:33) அவரில் காணப்பட்டன. இயேசு தம்முடைய சீஷர்களை அவருக்கு நேரிடவிருக்கும் மரணத்துக்காகவும், அவருடைய உயிர்த்தெழுதலுக்கும் பரமேறுதலுக்கும் பின்னர் அவர்கள் செய்யும் ஊழியத்திற்கும் தயார் செய்கிறார் (யோவான் 14-17). பின்னர் அவர் நம் ஸ்தானத்தில் சிலுவையில் மனமுவந்து சிலுவையில் மரிக்கிறார் (10:15-18), நம்முடைய பாவக் கடனை முழுவதுமாக செலுத்துகிறார் (19:30) இதனால் பாவத்திலிருந்து இரட்சிக்கும் இரட்சகராக அவரையே நம்புகிற எவரும் இரட்சிக்கப்படுவார்கள் (யோவான் 3:14-16 ). பின்னர் அவர் மரித்தோரிலிருந்து உயிர்த்தெழுந்து, தம்முடைய அவர் தேவன் மற்றும் கர்த்தர் என்று சந்தேகிக்கும் தமது சீஷர்களுக்கு தெளிவு படுத்துகிறார் (20:24-29).</p><p><b>இணைப்புகள்:</b></p><p>இயேசுவை பழைய ஏற்பாட்டின் தேவன் என்று யோவான் சித்தரிப்பது இயேசுவின் ஏழு \"நானே/நான்\" என்னும் அறிக்கைகளில் மிகவும் உறுதியாகக் காணப்படுகிறது. அவர் \"ஜீவ அப்பம்\" (யோவான் 6:35), வனாந்தரத்தில் இஸ்ரவேலருக்கு உணவளிக்க வானத்திலிருந்து மன்னாவை வழங்கியதைப் போலவே, அவருடைய மக்களின் ஆத்துமாக்களுக்கு உணவளிக்க தேவன் வழங்கினார் (யாத்திராகமம் 16:11-36). இயேசு \"உலகத்தின் ஒளி\" (யோவான் 8:12), பழைய ஏற்பாட்டில் தேவன் தம் மக்களுக்கு வாக்குறுதியளித்த அதே ஒளி (ஏசாயா 30:26, 60:19-22), அதன் உச்சத்தை புதிய எருசலேமில் காணலாம், அங்கெ ஆட்டுக்குட்டியானவராகிய கிறிஸ்து அதன் வெளிச்சமாக இருக்கும் போது தெளிவாகும் (வெளிப்படுத்துதல் 21:23). \"நான்\" அறிக்கைகளில் இரண்டு இயேசுவை \"நல்ல மேய்ப்பன்\" மற்றும் \"ஆடுகளின் வாசல்\" என்று குறிப்பிடுகின்றன. பழைய ஏற்பாட்டின் தேவன், இஸ்ரேலின் மேய்ப்பர் என்று இயேசுவைப் பற்றிய தெளிவான குறிப்புகள் இங்கே (சங்கீதம் 23:1; 80:1; எரேமியா 31:10; எசேக்கியேல் 34:23), ஆடுகளுக்குள் ஒரே வாசலாக, இரட்சிப்பின் ஒரே வழியாக இயேசு இருக்கிறார்.</p><p>யூதர்கள் உயிர்த்தெழுதலை நம்பினர், உண்மையில், அந்த கோட்பாட்டை பயன்படுத்தி இயேசுவை அவருக்கு எதிராகப் பயன்படுத்தக்கூடிய அறிக்கைகளை கூறி அவரை ஏமாற்ற முயன்றனர். ஆனால் லாசருவின் கல்லறையில் அவர் கூறியது \"நானே உயிர்த்தெழுதலும் ஜீவனுமாயிருக்கிறேன்\" (யோவான் 11:25) என்னும் கூற்று அவர்களை வியப்பில் ஆழ்த்தியிருக்க வேண்டும். அவர் உயிர்த்தெழுதலுக்கான காரணம் என்றும், ஜீவன் மற்றும் மரணம் மீதான அதிகாரத்தை வைத்திருப்பவர் என்றும் அவர் கூறிக்கொண்டிருந்தார். தேவனைத் தவிர வேறு எவருக்கும் இதுபோன்ற ஒன்றைக் கோர முடியாது செய்யவும் இயலாது. இதேபோல், \"நானே வழியும், சத்தியமும் மற்றும் ஜீவனுமாயிருக்கிறேன்\" என்று அவர் கூறுவது (யோவான் 14:6) அவரை பழைய ஏற்பாட்டுடன் தொடர்புபடுத்தியது. ஏசாயா 35:8-ல் தீர்க்கதரிசனமாக சொல்லப்பட்ட \"பரிசுத்த பாதை\" அவருடையது; சகரியாவின் சத்திய நகரத்தை அவர் ஸ்தாபித்தார் 8:3 \"சத்தியம்\" தானே எருசலேமில் இருந்தபோது, நற்செய்தியின் சத்தியங்கள் அவரும் அவருடைய அப்போஸ்தலர்களும் அங்கு பிரசங்கித்தார்கள்; \"ஜீவன்\" என்று, அவர் தனது தெய்வத்துவத்தை, ஜீவனின் படைப்பாளராக, தேவனின் அவதாரம் என்பதில் விளங்கிற்று (யோவான் 1:1-3). இறுதியாக, \"மெய்யான திராட்சைச்செடி\" (யோவான் 15:1, 5) பல பழைய ஏற்பாட்டுப் பத்திகளில் கர்த்தருடைய திராட்சைத் தோட்டம் என்று அழைக்கப்படும் இஸ்ரவேல் தேசத்தோடு இயேசு தன்னை அடையாளப்படுத்துகிறார். இஸ்ரவேலின் திராட்சைத் தோட்டத்தின் உண்மையான திராட்சைத் தோட்டமாக, அவர் தன்னை \"உண்மையான இஸ்ரவேலின்\" தேவன் என்று சித்தரிக்கிறார் - விசுவாசத்தோடு அவரிடம் வருவோர் அனைவருமே மெய்யான இஸ்ரவேலர்கள், ஏனென்றால் \"… இஸ்ரவேலிலிருந்து வந்தவர்கள் அனைவரும் இஸ்ரவேலர்கள் அல்ல\" (ரோமர் 9:6).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>சுவிசேஷத்திற்கு மிகவும் பயனுள்ள தகவல்களைக் கொண்டுவருவதற்கான அதன் நோக்கத்தை யோவானின் நற்செய்தி தொடர்ந்து நிறைவேற்றுகிறது (யோவான் 3:16 என்பது பலரால் சரியாகப் புரிந்து கொள்ளப்படாவிட்டாலும் கூட, நன்கு அறியப்பட்ட வசனம்) மற்றும் இந்த வசனம் பெரும்பாலும் சுவிசேஷ வேதாகமப் படிப்புகளில் பயன்படுத்தப்படுகிறது. இயேசுவிற்கும் நிக்கொதேமுவோடும் மற்றும் கிணற்றின் அருகே சமாரிய ஸ்திரீக்கும் இடையில் பதிவுசெய்யப்பட்ட சந்திப்புகளில் (அத்தியாயங்கள் 3-4), இயேசுவின் தனிப்பட்ட சுவிசேஷத்தின் மாதிரியிலிருந்து நாம் அதிகம் கற்றுக்கொள்ளலாம். மரிப்பதற்கு முன்னர் அவருடைய சீஷர்களிடம் அவர் அளித்த ஆறுதலான வார்த்தைகள் (14:1-6,16; 16:33) கிறிஸ்துவில் நம்முடைய அன்புக்குரியவர்களை மரணம் நேரிடும் மற்றும் வருத்தப்படுத்தும்போது உள்ள காலங்களில் இன்னும் மிகுந்த ஆறுதலளிக்கிறது, அதேபோல் 17-ஆம் அதிகாரத்தில் விசுவாசிகளுக்காக அவர் செய்த \"உயர் ஆசாரிய ஜெபமும்\" அவரது அக்கறை மற்றும் இரக்கத்திற்கு வலுச்சேர்க்கிறது. கிறிஸ்துவின் தெய்வத்துவத்தைப் பற்றிய யோவானின் போதனைகள் (1:1-3,14; 5:22-23; 8:58; 14:8-9; 20:28, முதலியன) இயேசுவை முழு தேவனை விட குறைவாக இருப்பதைக் காணும் வழிபாட்டு முறைகளாகிய சிலரின் தவறான போதனைகளை எதிர்ப்பதற்கு மிகவும் உதவியாக இருக்கும்.</p><p>சுமார் கி.மு. 4 - கி.பி. 39 - ஏரோது அந்திப்பா கலிலேயா, பெரேயாவில் ஆளுதல்</p><p>சுமார் கி.பி. 14 - 37 - திபேரியு ராய்ன் ரோமப் பேரரசர்</p><p>சுமார் கி.பி. 25 - 27 - யோவான்ஸ்நானனின் திருப்பணி</p><p>சுமார் கி.பி. 26 - 36 - பொந்தியு பிலாத்து யூதேயா ஆளுநர்</p><p>சுமார் கி.பி. 27 - கிறிஸ்து திருப்பணியைத் தொடங்குதல்</p><p>சுமார் கி.பி. 29/30 - கிறிஸ்துவின் மரண , அடக்க, உயிர்ப்பு</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - யோவான் (தேவன் கிருபையுள்ளவர்)</p><p>குடும்பம் - தந்தை - செபதேயு / தாய் - சலோமே /அண்ணன் - யாக்கோபு</p><p>ஊர் - கலிலேயாவின் கப்பர்நகூம் பின்பு எபேசுவுக்கு சென்றார். பத்மு தீவுக்கு நாடுகடத்தப்பட்டதுண்டு (வெளி 1 : 9)</p><p>தொழில் - மீன் பிடிப்புக்குள்</p><p>ஆர்வம் - ஆன்மீக நாட்டம் /(முதலில் யோவான்ஸ்நானனின் சீடராக இருந்தார் (1: 19-51), பின்பு கிறிஸ்துவின் சீடரானார்)</p><p>திருப்பு முனை - கிறிஸ்துவின் அழைப்பு (லூக் 5: 1-11)</p><p>பட்டங்கள்- அண்ணனுடன் சேர்ந்து \"பொவனெர்கேஸ்\"</p><p>(இடிமுழக்கத்தின் மக்கள்) அப்போஸ்தலர்</p><p>சாதனைகள் - புதிய ஏற்பாட்டில் ஐந்து நூல்களைப் படைத்துள்ளார் (யோவான் சுவிசேஷ நூல், 1,2,3 யோவான் நிருபங்கள். வெளிப்படுத்தின விசேஷம்)</p><p>சிறப்புப் பெயர் - கிறிஸ்துவின் அன்பு சீடர்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 43-வது நூல்</p><p>அதிகாரங்கள் - 21</p><p>வசனங்கள் - 876</p><p>கேள்விகள் - 167</p><p>நிறைவேறிய பழைய ஏற்பாட்டுத் தீர்க்கதரிசனங்கள் -15</p><p>நிறைவேறிய புதிய ஏற்பாட்டுத் தீர்க்கதரிசனங்கள் - 85</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 7</p>'),
 (510,'<p><b>அப்போஸ்தலருடைய நடபடிகள் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>அப்போஸ்தலருடைய நடபடிகள் புத்தகம் அதன் எழுத்தாளரை குறிப்பாக யாரென்று அடையாளம் காண்பிக்கவில்லை. லூக்கா 1:1-4 மற்றும் அப்போஸ்தலர் 1:1-3 ஆகியவற்றிலிருந்து, ஒரே எழுத்தாளர்தான் லூக்கா மற்றும் அப்போஸ்தலருடைய நடபடிகள் புத்தகம் ஆகிய இரண்டையும் எழுதினார் என்பது தெளிவாகிறது. அப்போஸ்தலனாகிய பவுலின் கூட்டாளியான மருத்துவர் லூக்கா தான் லூக்கா மற்றும் அப்போஸ்தலருடைய நடபடிகள் புத்தகம் ஆகிய இரண்டையும் எழுதினார் என்பது திருச்சபையின் ஆரம்ப நாட்களிலிருந்து வந்த பாரம்பரியமாகும் (கொலோசெயர் 4:14; 2 தீமோத்தேயு 4:11).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>அப்போஸ்தலருடைய நடபடிகள் புத்தகம் கி.பி. 61-64 வரையிலுள்ள காலக்கட்டத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>ஆரம்பகால திருச்சபையின் வரலாற்றை வழங்குவதற்காக அப்போஸ்தலருடைய நடபடிகள் புத்தகம் எழுதப்பட்டது. புத்தகத்தின் பிரதான முக்கியத்துவம் பெந்தெகொஸ்தே நாளின் முக்கியத்துவம் மற்றும் இயேசு கிறிஸ்துவுக்கு பயனுள்ள சாட்சிகளாக இருக்க அதிகாரம் பெற்றது ஆகியவைகளாகும். அப்போஸ்தலர்கள் எருசலேம், யூதேயா, சமாரியா மற்றும் சுற்றியுள்ள உலகின் பிற பகுதிகளுக்கும் கிறிஸ்துவின் சாட்சிகளாக இருப்பதை அப்போஸ்தலருடைய நடபடிகள் புத்தகம் பதிவு செய்கிறது. நம்முடைய ஆலோசகராக அதிகாரம், வழிகாட்டுதல், கற்பித்தல் மற்றும் சேவை செய்யும் பரிசுத்த ஆவியின் இணையற்ற ஈவை இந்த புத்தகம் வெளிச்சம் போட்டுக் காட்டுகிறது. அப்போஸ்தலருடைய நடபடிகள் புத்தகத்தைப் படிக்கும்போது, சீஷர்களான பேதுரு, யோவான் மற்றும் பவுல் ஆகியோரால் நிகழ்த்தப்பட்ட பல அற்புதங்களால் நாம் அறிவொளி பெறுகிறோம், ஊக்குவிக்கப்படுகிறோம். தேவனுடைய வார்த்தைக்குக் கீழ்ப்படிவதன் முக்கியத்துவத்தையும், கிறிஸ்துவை அறிந்ததன் விளைவாக ஏற்படும் மாற்றத்தையும் அப்போஸ்தலருடைய நடபடிகள் புத்தகம் வலியுறுத்துகிறது. கர்த்தராகிய இயேசு கிறிஸ்துவைப் பற்றி சீஷர்கள் பிரசங்கித்த சத்தியத்தை நிராகரித்தவர்கள் பற்றிய பல குறிப்புகள் உள்ளன. வல்லமை, பேராசை மற்றும் பிசாசின் பல தீமைகள் அப்போஸ்தலருடைய நடபடிகள் புத்தகத்தில் சாட்சியமாக உள்ளன.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>அப்போஸ்தலர் 1:8: \"பரிசுத்த ஆவி உங்களிடத்தில் வரும்போது நீங்கள் பெலனடைந்து, எருசலேமிலும், யூதேயா முழுவதிலும், சமாரியாவிலும், பூமியின் கடைசிபரியந்தமும், எனக்குச் சாட்சிகளாயிருப்பீர்கள் என்றார்.\"</p><p>அப்போஸ்தலர் 2:4: \"அவர்களெல்லாரும் பரிசுத்த ஆவியினாலே நிரப்பப்பட்டு, ஆவியானவர் தங்களுக்குத் தந்தருளின வரத்தின்படியே வெவ்வேறு பாஷைகளிலே பேசத்தொடங்கினார்கள்.\"</p><p>அப்போஸ்தலர் 4:12: \"அவராலேயன்றி வேறொருவராலும் இரட்சிப்பு இல்லை; நாம் இரட்சிக்கப்படும்படிக்கு வானத்தின் கீழெங்கும், மனுஷர்களுக்குள்ளே அவருடைய நாமமேயல்லாமல் வேறொரு நாமம் கட்டளையிடப்படவும் இல்லை என்றான்.\"</p><p>அப்போஸ்தலர் 4:19-20: \"பேதுருவும் யோவானும் அவர்களுக்குப் பிரதியுத்தரமாக: தேவனுக்குச் செவிகொடுக்கிறதைப்பார்க்கிலும் உங்களுக்குச் செவிகொடுக்கிறது தேவனுக்கு முன்பாக நியாயமாயிருக்குமோ நீங்களே நிதானித்துப்பாருங்கள். நாங்கள் கண்டவைகளையும் கேட்டவைகளையும் பேசாமலிருக்கக்கூடாதே என்றார்கள்.\"</p><p>அப்போஸ்தலர் 9:3-6: \"அவன் பிரயாணமாய்ப் போய், தமஸ்குவுக்குச் சமீபித்தபோது சடிதியிலே வானத்திலிருந்து ஒரு ஒளி அவனைச் சுற்றிப் பிரகாசித்தது; அவன் தரையிலே விழுந்தான். அப்பொழுது: சவுலே, சவுலே, நீ என்னை ஏன் துன்பப்படுத்துகிறாய் என்று தன்னுடனே சொல்லுகிற ஒரு சத்தத்தைக் கேட்டான். அதற்கு அவன்: ஆண்டவரே, நீர் யார், என்றான். அதற்குக் கர்த்தர்: நீ துன்பப்படுத்துகிற இயேசு நானே, முள்ளில் உதைக்கிறது உனக்குக் கடினமாம் என்றார். அவன் நடுங்கித் திகைத்து: ஆண்டவரே, நான் என்னசெய்யச் சித்தமாயிருக்கிறீர் என்றான். அதற்குக் கர்த்தர்: நீ எழுந்து, பட்டணத்துக்குள்ளே போ, நீ செய்யவேண்டியது அங்கே உனக்குச் சொல்லப்படும் என்றார்.\"</p><p>அப்போஸ்தலர் 16:31: \"அதற்கு அவர்கள்: கர்த்தராகிய இயேசுகிறிஸ்துவை விசுவாசி, அப்பொழுது நீயும் உன் வீட்டாரும் இரட்சிக்கப்படுவீர்கள் என்று சொன்னார்கள்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>அப்போஸ்தலருடைய நடபடிகள் புத்தகம் கிறிஸ்தவ திருச்சபையின் வரலாற்றையும் இயேசு கிறிஸ்துவின் நற்செய்தியின் பரவலையும், அதற்கு பெருகிய எதிர்ப்பையும் தொகுத்து தருகிறது. இயேசு கிறிஸ்துவின் நற்செய்தியைப் பிரசங்கிக்கவும் கற்பிக்கவும் பல உண்மையுள்ள ஊழியர்கள் பயன்படுத்தப்பட்டிருந்தாலும், பவுல் என்று பெயர் மாற்றப்பட்ட சவுல் மிகவும் செல்வாக்கு பெற்றவர் ஆவார். அவர் மனமாற்றப்படுவதற்கு முன்பு, கிறிஸ்தவர்களைத் துன்புறுத்துவதிலும் கொலை செய்வதிலும் பவுல் மிகுந்த மகிழ்ச்சி அடைந்தார். தமஸ்கு சாலையில் பவுலின் வியத்தகு மாற்றம் (அப்போஸ்தலர் 9:1-31) அப்போஸ்தலருடைய நடபடிகள் புத்தகத்தின் சிறப்பம்சமாகும். அவர் மாற்றப்பட்ட பிறகு, தேவனை நேசிப்பதற்கும், அவருடைய வார்த்தையை வல்லமை, உற்சாகம் மற்றும் உண்மையான மற்றும் ஜீவனுள்ள தேவனுடைய ஆவியால் பிரசங்கிப்பதற்கும் நேர்மாறான நிலைக்குச் சென்றார். எருசலேமில் (1–8:3 அதிகாரங்கள்), யூதேயா மற்றும் சமாரியாவிலும் (அதிகாரங்கள் 8:4–12:25), பூமியின் எல்லா முனைகளிலும் (அதிகாரங்கள் 13:1–28) பரிசுத்த ஆவியானவர் சீஷர்களுக்கு அதிகாரம் அளித்தார். கடைசி பகுதியில் பவுலின் மூன்று மிஷனரி பயணங்கள் (13:1–21:16), எருசலேம் மற்றும் சிசரியாவில் அவர் சந்தித்த சோதனைகள் (21:17–26: 32) மற்றும் ரோமாபுரிக்கு அவர் மேற்கொண்ட இறுதி பயணம் (27:1–28:31)ஆகிய விவரணங்களை இந்த அப்புத்தகம் அளிக்கிறது.</p><p><b>இணைப்புகள்:</b></p><p>நியாயப்பிரமான சட்டங்களின் பழைய உடன்படிக்கையிலிருந்து இரக்கம் மற்றும் விசுவாசத்தின் புதிய உடன்படிக்கைக்கு மாறுவதற்கு அப்போஸ்தலருடைய நடபடிகள் புத்தகம் மிகவும் உதவுகிறது. இந்த மாற்றம் நியாயப்பிரமான சட்டங்களில் பல முக்கிய நிகழ்வுகளில் காணப்படுகிறது. முதலாவதாக, பரிசுத்த ஆவியின் ஊழியத்தில் ஒரு மாற்றம் ஏற்பட்டது, பழைய ஏற்பாட்டில் முதன்மையான செயல்பாடு தேவனுடைய மக்களின் வெளிப்புற \"அபிஷேகம்\" ஆகும், அவர்களில் மோசே (எண்கள் 11:17), ஒத்தனியேல் (நியாயாதிபதிகள் 3:8-10) , கிதியோன் (நியாயாதிபதிகள் 6:34), சவுல் (1 சாமுவேல் 10:6-10) அடங்குவர். இயேசுவின் உயிர்த்தெழுதலுக்குப் பிறகு, ஆவியானவர் விசுவாசிகளின் இருதயங்களில் தங்கி வாசம் செய்யும்படி வந்தார் (ரோமர் 8:9-11; 1 கொரிந்தியர் 3:16), அவர்களை உள்ளே இருந்து வழிநடத்தி அதிகாரம் அளித்தார். இது விசுவாசத்தில் தம்மிடம் வருபவர்களுக்கு தேவன் அளிக்கும் அவருடைய ஈவாகும்.</p><p>பழைய உடன்படிக்கையிலிருந்து புதியதாக மாறுவதற்கு பவுலின் மனமாற்றம் ஒரு வியத்தகு எடுத்துக்காட்டு. உயிர்த்தெழுந்த இரட்சகரைச் சந்திப்பதற்கு முன்பு, அவர் இஸ்ரவேலர்களில் மிகவும் வைராக்கியமுள்ளவர் என்றும், \"நியாயப்பிரமாணத்தின் நீதியைப்\" பொறுத்தமட்டில் (பிலிப்பியர் 3:6) குற்றமற்றவர் என்றும் பவுல் ஒப்புக்கொண்டார். கிறிஸ்துவில் நம்பிக்கை வைக்கும் முன்னர் கிறிஸ்தவர்களை துன்புறுத்த வைராக்கியம் கொண்டு கொதித்தெழுந்தார். ஆனால் அவர் மாற்றப்பட்ட பின்னர், அவருடைய சட்டபூர்வமான முயற்சிகள் அனைத்தும் பயனற்றவை என்பதை அவர் உணர்ந்தார், அவர் அவைகளை வெறும் \"குப்பைகளாக\" கருதினார், \"நான் கர்த்தராகிய கிறிஸ்து இயேசுவை அறிகிற அறிவின் மேன்மைக்காக எல்லாவற்றையும் நஷ்டமென்று எண்ணிக்கொண்டிருக்கிறேன். நான் கிறிஸ்துவை ஆதாயப்படுத்திக்கொள்ளும்படிக்கும், நியாயப்பிரமாணத்தினால் வருகிற சுயநீதியை உடையவனாயிராமல், கிறிஸ்துவைப் பற்றும் விசுவாசத்தினால் வருகிறதும் விசுவாசமூலமாய் தேவனால் உண்டாயிருக்கிறதுமான நீதியை உடையவனாயிருந்து, கிறிஸ்துவுக்குள் இருக்கிறவனென்று காணப்படும்படிக்கும்\" (பிலிப்பியர் 3: 8-9). இப்போது நாமும் விசுவாசத்தினாலே வாழ்கிறோம், நியாயப்பிரமாணத்தின் கிரியைகளால் அல்ல, எனவே மேன்மை பாராட்ட நமது சொந்த முயற்சிகள் எதுவும் இல்லை (எபேசியர் 2:8-9).</p><p>அப்போஸ்தலர் 10:9-15-ல் உள்ள புசிக்கும் உணவுகளைக் குறித்த துப்பட்டியைப் பற்றிய பேதுருவின் பார்வை பழைய உடன்படிக்கையிலிருந்து மாறுவதற்கான மற்றொரு அறிகுறியாகும் இந்த விஷயத்தில் யூதர்களுக்கு குறிப்பாக உணவுச் சட்டங்கள் இருந்தன - புதிய உடன்படிக்கையின் யூத மற்றும் புறஜாதியாரின் ஒற்றுமைக்கு ஒரு உலகளாவிய திருச்சபையில் இப்படியானது. யூதர்களைக் குறிக்கும் \"பரிசுத்தமான\" விலங்குகள் மற்றும் புறஜாதியாரைக் குறிக்கும் \"அசுத்தமான\" விலங்குகள் இரண்டும் கிறிஸ்துவின் சிலுவைப் பலியின் மரணத்தின் மூலம் தேவனால் \"சுத்திகரிக்கப்பட்டவை\" என்று அறிவிக்கப்பட்டன. பழைய நியாயப்பிரமாண சட்டத்தின் கீழ் இனி இராமல், இருகூட்டத்தார்களும் இப்போது கிறிஸ்துவின் சிலுவையில் சிந்தப்பட்ட இரத்தத்தினால் விசுவாசம் மூலம் கிருபையின் புதிய உடன்படிக்கையில் ஒன்றுபட்டுள்ளனர்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>தேவன் தம்முடைய ஆவியின் மூலம் அவர்களுக்கு அதிகாரம் அளிக்கும்போது சாதாரண மனிதர்கள் மூலமாக அற்புதமான காரியங்களைச் செய்ய முடியும். தேவன் அடிப்படையில் ஒரு மீனவர் குழுவை எடுத்து உலகை தலைகீழாக மாற்ற பயன்படுத்தினார் (அப்போஸ்தலர் 17:6). தேவன் கிறிஸ்தவர்களை வெறுக்கும் கொலைபாதகனை அழைத்து, புதிய ஏற்பாட்டின் கிட்டத்தட்ட பாதி புத்தகங்களை எழுதிய மிகப் பெரிய கிறிஸ்தவ சுவிசேஷகராக அவரை மாற்றினார். உலக வரலாற்றில் ஒரு \"புதிய நம்பிக்கையின்\" விரைவான விரிவாக்கத்தை ஏற்படுத்த தேவன் உபவத்திரவத்தைப் பயன்படுத்தினார். நம்முடைய இருதயங்களை மாற்றுவது, பரிசுத்த ஆவியினால் நமக்கு அதிகாரம் அளிப்பது, கிறிஸ்துவின் மூலமாக இரட்சிப்பின் நற்செய்தியை பரப்புவதற்கான ஆர்வத்தை நமக்குக் கொடுப்பதன் மூலம் தேவன் நம் மூலமாகவும் அதைச் செய்ய முடியும். இவற்றை நம் நமது சொந்த சக்தியால்/பெலத்தால் நிறைவேற்ற முயன்றால், நாம் தோல்வியடைவோம். அப்போஸ்தலர் 1:8-ல் உள்ள சீஷர்களைப் போலவே, ஆவியின் அதிகாரம் மற்றும் வல்லமை பெறுவதற்காக நாம் காத்திருக்க வேண்டும், பின்னர் நமதாண்டவர் நமக்கு அருளிய பெரிய ஆணையத்தை நிறைவேற்ற அவருடைய வல்லமையுடன் செல்லுவோம் (மத்தேயு 28:19-20).</p><p>சுமார் கி.பி. 14 - 37 - திபேரியு அரசர் ரோமப் பேரரசராக</p><p>சுமார் கி.பி.30 - திருச்சபை உருவாதல்</p><p>சுமார் கி.பி. 37 - 41 - கலிகூலா ரோமப் பேரரசராக</p><p>சுமார் கி.பி.37 - 44 - ஏரோது அகிரிப்பா யூதேயா ஆளுநர்</p><p>சுமார் கி.பி. 41 - 54 - கிலவுதியு அரசர் ரோம அரசராக</p><p>சுமார் கி.பி. 44 - யாக்கோபு கொலை செய்யப்படல்</p><p>சுமார் கி.பி. 51 - 60  - பேலிக்ஸ் யூதேயா ஆளுநர்</p><p>சுமார் கி.பி. 54 - 68 - நீரோ ரோமப் பேரரசராக</p><p>சுமார் கி.பி.60 - 62 - பெஸ்து யூதேயா ஆளுநராக</p><p>சுமார் கி.பி, 60 - 62 பவுல் ரோம சிறையில்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - டாக்டர். லூக்கா</p><p>குலம் - கிரேக்கர்/ ஒரே புதிய ஏற்பாட்டு புறஜாதி எழுத்தாளர்</p><p>பிறந்த ஊர் - அந்தியோகியாவாக இருக்கலாம்</p><p>குடும்பம் - சிறந்த கல்விமிக்க, கலாச்சாரம்மிக்க குடும்பம்</p><p>தொழில் - மருத்துவர். பின்பு மருத்துவ மிஷனரி (?)</p><p>படைப்புகள் - லூக்கா எழுதிய சுவிசேஷம் அப்போஸ்தல நடபடிகள்</p><p>சாதனை - புதிய ஏற்பாட்டின் கால் (1/4) பகுதியை தமது வரலாற்று ஆதாரமிக்க படைப்புகளால் நிறைத்தது</p><p>சிறப்பு பட்டம் - பிரியமான வைத்தியனான லூக்கா\" (கொலோ 4 : 4)</p><p>\"முழுமை மனிதனைப் பற்றிய ஆராய்சியாளர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 44-வது நூல்</p><p>அதிகாரங்கள் - 28</p><p>வசனங்கள் - 1,007</p><p>கேள்விகள் - 75</p><p>பழைய ஏற்பாட்டுத் தீர்க்கதரிசனங்கள் - 21</p><p>பதிய தீர்க்கதரிசனங்கள் - 20</p><p>வரலாற்று வசனங்கள் - 949</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 49</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 14</p>'),
 (520,'<p><b>ரோமாபுரியாருக்கு எழுதின நிருபம்</b></p><p><b>எழுத்தாளர்:</b></p><p>ரோமர் 1:1, ரோமாபுரியாருக்கு எழுதின நிருபத்தின் எழுத்தாளர் அப்போஸ்தலனாகிய பவுல் என்று அடையாளம் காட்டுகிறது. ரோமர் 16:22-ல், பவுல் தனது வார்த்தைகளை எழுத தெர்தியு என்னும் மனிதரைப் பயன்படுத்தினார் என்பதை வாசிக்கிறோம்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>ரோமாபுரியாருக்கு எழுதின நிருபம் கி.பி. 56 முதல் கி.பி. 58 வரையிலுள்ள காலகட்டத்தில் எழுதப்பட்டிருக்கலாம் என்று நம்பப்படுகிறது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>திருச்சபைகளுக்கு பவுல் எழுதிய அனைத்து நிருபங்களையும் போலவே, இந்த நிருபத்திலும் அவருடைய எழுத்தின் நோக்கம் கர்த்தராகிய இயேசு கிறிஸ்துவின் மகிமையை பிரஸ்தாப படுத்ததக்கதான கோட்பாட்டைக் கற்பிப்பதும், அவருடைய நிருபத்தை பெறும் விசுவாசிகளைத் நல்வழிப்படுத்தி ஆவிக்குரிய வாழ்வில் வளரத்தக்கதாக ஊக்குவிப்பதும் ஆகும். இந்த நிருபம் யாருக்கு எழுதப்பட்டதோ அவர்களைக் குறித்து பவுல் குறிப்பாக அக்கறை கொண்டிருந்தார் – அவர்கள் தான் \"ரோமாபுரியிலுள்ள தேவப்பிரியரும் பரிசுத்தவான்களாகும்படி அழைக்கப்பட்டவர்களுமானவர்கள்\" (ரோமர் 1:2). அவரே ஒரு ரோமக் குடியுரிமை பெற்ற குடிமகனாக இருந்ததால், ரோமிலுள்ள விசுவாசிகளின் கூட்டத்தில் இருப்பவர்கள் மீது அவருக்கு ஒரு தனித்துவமான அக்கறை மற்றும் ஆர்வம் இருந்தது. அவர் இதுவரை, ரோமில் உள்ள திருச்சபைக்கு விஜயம் செய்யவில்லை என்பதால், இந்த நிருபம் பவுலைக் குறித்து அவர்களுக்கு ஒரு அறிமுகமாகவும் இருந்தது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>ரோமர் 1:16, \"கிறிஸ்துவின் சுவிசேஷத்தைக் குறித்து நான் வெட்கப்படேன்; முன்பு யூதரிலும் பின்பு கிரேக்கரிலும் விசுவாசிக்கிறவனெவனோ அவனுக்கு இரட்சிப்பு உண்டாவதற்கு அது தேவபெலனாயிருக்கிறது.\"</p><p>ரோமர் 3:9-11, \"ஆனாலும் என்ன? அவர்களைப்பார்க்கிலும் நாங்கள் விசேஷித்தவர்களா? எவ்வளவேனும் விசேஷித்தவர்களல்ல. யூதர் கிரேக்கர் யாவரும் பாவத்திற்குட்பட்டவர்களென்பதை முன்பு திருஷ்டாந்தப்படுத்தினோமே. அந்தப்படியே: நீதிமான் ஒருவனாகிலும் இல்லை; உணர்வுள்ளவன் இல்லை; தேவனைத் தேடுகிறவன் இல்லை.\"</p><p>ரோமர் 3:21, \"இப்படியிருக்க, நியாயப்பிரமாணமில்லாமல் தேவநீதி வெளியாக்கப்பட்டிருக்கிறது; அதைக்குறித்து நியாயப்பிரமாணமும் தீர்க்கதரிசனங்களும் சாட்சியிடுகிறது.\"</p><p>ரோமர் 3:23, \"எல்லாரும் பாவஞ்செய்து, தேவமகிமையற்றவர்களாகிப் போனார்கள்.\"</p><p>ரோமர் 5:8, \"நாம் பாவிகளாயிருக்கையில் கிறிஸ்து நமக்காக மரித்ததினாலே, தேவன் நம்மேல் வைத்த தமது அன்பை விளங்கப்பண்ணுகிறார்.\"</p><p>ரோமர் 6:23, \"பாவத்தின் சம்பளம் மரணம்; தேவனுடைய கிருபைவரமோ நம்முடைய கர்த்தராகிய இயேசுகிறிஸ்துவினால் உண்டான நித்தியஜீவன்.\"</p><p>ரோமர் 8:9, \"தேவனுடைய ஆவி உங்களில் வாசமாயிருந்தால், நீங்கள் மாம்சத்துக்குட்பட்டவர்களாயிராமல் ஆவிக்குட்பட்டவர்களாயிருப்பீர்கள். கிறிஸ்துவின் ஆவியில்லாதவன் அவருடையவனல்ல.\"</p><p>ரோமர் 8:28, \"அன்றியும், அவருடைய தீர்மானத்தின்படி அழைக்கப்பட்டவர்களாய் தேவனிடத்தில் அன்புகூருகிறவர்களுக்குச் சகலமும் நன்மைக்கு ஏதுவாக நடக்கிறதென்று அறிந்திருக்கிறோம்.\"</p><p>ரோமர் 8:37-39, \"இவையெல்லாவற்றிலேயும் நாம் நம்மில் அன்புகூருகிறவராலே முற்றும் ஜெயங்கொள்ளுகிறவர்களாயிருக்கிறோமே. மரணமானாலும், ஜீவனானாலும், தேவதூதர்களானாலும், அதிகாரங்களானாலும், வல்லமைகளானாலும், நிகழ்காரியங்களானாலும், வருங்காரியங்களானாலும், உயர்வானாலும், தாழ்வானாலும், வேறெந்தச் சிருஷ்டியானாலும் நம்முடைய கர்த்தராகிய கிறிஸ்து இயேசுவிலுள்ள தேவனுடைய அன்பைவிட்டு நம்மைப் பிரிக்கமாட்டாதென்று நிச்சயித்திருக்கிறேன்.\"</p><p>ரோமர் 10:9-10, \"என்னவென்றால், கர்த்தராகிய இயேசுவை நீ உன் வாயினாலே அறிக்கையிட்டு, தேவன் அவரை மரித்தோரிலிருந்து எழுப்பினாரென்று உன் இருதயத்திலே விசுவாசித்தால் இரட்சிக்கப்படுவாய். நீதியுண்டாக இருதயத்திலே விசுவாசிக்கப்படும், இரட்சிப்புண்டாக வாயினாலே அறிக்கைபண்ணப்படும்.\"</p><p>ரோமர் 12:1, \"அப்படியிருக்க, சகோதரரே, நீங்கள் உங்கள் சரீரங்களைப் பரிசுத்தமும் தேவனுக்குப் பிரியமுமான ஜீவபலியாக ஒப்புக்கொடுக்கவேண்டுமென்று, தேவனுடைய இரக்கங்களை முன்னிட்டு உங்களை வேண்டிக்கொள்ளுகிறேன்; இதுவே நீங்கள் செய்யத்தக்க புத்தியுள்ள ஆராதனை.\"</p><p>ரோமர் 12:19, \"பிரியமானவர்களே, பழிவாங்குதல் எனக்குரியது, நானே பதிற்செய்வேன், என்று கர்த்தர் சொல்லுகிறார் என்று எழுதியிருக்கிறபடியால், நீங்கள் பழிவாங்காமல், கோபாக்கினைக்கு இடங்கொடுங்கள்.\"</p><p>ரோமர் 16:17, \"அன்றியும் சகோதரரே, நீங்கள் கற்றுக்கொண்ட உபதேசத்திற்கு விரோதமாய்ப் பிரிவினையும் இடறல்களையும் உண்டாக்குகிறவர்களைக்குறித்து எச்சரிக்கையாயிருந்து, அவர்களை விட்டு விலகவேண்டுமென்று உங்களுக்குப் புத்திசொல்லுகிறேன்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>இந்த திருச்சபையில் கடைசியாக ஊழியம் செய்ய முடிந்ததைப் பற்றி பவுல் உற்சாகமாக இருந்தார், எல்லோரும் அந்த உண்மையை நன்கு அறிந்திருந்தார்கள் (ரோமர் 1:8-15). எருசலேமிலுள்ள ஏழைகளுக்காக வழங்கப்பட்ட தர்மபணத்தை வழங்குவதற்காக பவுல் எருசலேமுக்குச் செல்வதற்கு சற்று முன்பு கொரிந்துவிலிருந்து இந்த நிருபத்தை ரோமர்களுக்கு எழுதினார். பவுல் ஸ்பானியா தேசத்திற்கு செல்லவும் பின்னர் அங்கிருந்து ரோமாபுரி செல்லவும் விரும்பினார் (ரோமர் 15:24), ஆனால் அவர் எருசலேமில் கைது செய்யப்பட்டபோது அவரது திட்டங்கள் தடைபட்டன. அவர் இறுதியில் ஒரு கைதியாக ரோமாபுரிக்கு செல்லும்படியாயிற்று. கொரிந்துக்கு அருகிலுள்ள கெங்கிரேயா ஊர் சபைக்கு ஊழியக்காரியாகிய பெபேயாள் (ரோமர் 16:1), பெரும்பாலும் இந்தக் நிருபத்தை ரோமுவிற்கு கொண்டு சென்றிருக்கலாம்.</p><p>ரோமர் புத்தகம் முதன்மையாக ஒரு உபதேசத்தின் கிரியையாகும் மற்றும் அதை நான்கு பிரிவுகளாகப் பிரிக்கலாம்: தேவையான நீதி, 1:18–3:20; வழங்கப்பட்ட நீதி, 3:21–8:39; நிரூபிக்கப்பட்ட நீதி, 9:1–11:36; மற்றும் நடைமுறைப்படுத்தப்பட்ட நீதி, 12:1–15:13. இந்த நிருபத்தின் முக்கிய கருப்பொருள் நிச்சயமாக வெளிப்படையானதாகும் – அதாவது நீதி. பரிசுத்த ஆவியினால் வழிநடத்தப்பட்ட பவுல் முதலில் எல்லா மனிதர்களையும் அவர்கள் செய்த பாவத்தை கண்டிக்கிறார். தேவனுடைய வார்த்தையின் சத்தியத்தை ரோமில் உள்ளவர்களுக்கும் பிரசங்கிப்பதற்கான தனது விருப்பத்தை அவர் வெளிப்படுத்துகிறார். அவர்கள் சரியான பாதையில் தங்கியிருப்பதாக உறுதியளிப்பது அவருடைய நம்பிக்கையாக இருந்தது. அவர் சுவிசேஷத்தைப் பற்றி வெட்கப்படவில்லை என்று அவர் வலுவாக சுட்டிக்காட்டுகிறார் (ரோமர் 1:16), ஏனென்றால் எல்லோரும் இரட்சிக்கப்படுவதற்கு அதுவே தேவ வல்லமையாக இருக்கிறது.</p><p>ரோமர் புத்தகம் தேவனைப் பற்றியும், அவர் யார், அவர் என்ன செய்தார் என்பதையும் சொல்லுகிறது. இது இயேசு கிறிஸ்துவைப் பற்றியும் அவருடைய மரணம் என்ன சாதித்தது என்பதைப் பற்றியும் சொல்லுகிறது. இது நம்மைப் பற்றியும், கிறிஸ்து இல்லாமல் நாம் எப்படி இருந்தோம், கிறிஸ்துவை விசுவாசித்து அவர்மேல் நம்பிக்கை வைத்தபின் நாம் யார் என்பதையுங்குறித்து சொல்லுகிறது. கிறிஸ்துவிடம் வருவதற்கு முன்பு மனிதர்கள் தங்கள் வாழ்க்கையை நேராக்க வேண்டும் என்று தேவன் கோரவில்லை என்று பவுல் சுட்டிக்காட்டுகிறார். மாறாக நாம் பாவிகளாக இருந்தபோது கிறிஸ்து நம்முடைய பாவங்களுக்காக சிலுவையில் மரித்தார் என்று அறிவிக்கிறது.</p><p><b>இணைப்புகள்:</b></p><p>பவுல் பல பழைய ஏற்பாட்டு நபர்களையும் நிகழ்வுகளையும் ரோமர் புத்தகத்தில் மேற்கோள் காண்பித்து அவைகளை புகழ்பெற்ற சத்தியங்களின் எடுத்துக்காட்டுகளாகப் பயன்படுத்துகிறார். ஆபிரகாம் விசுவாசித்தார், தேவன் அதை அவருக்கு நீதியாக கணக்கிட்டார், இது ஆபிரகாமுடைய செயல்களால் அல்ல (ரோமர் 4:1-5). ரோமர் 4:6-9-ல், அதே சத்தியத்தை மீண்டும் வலியுறுத்திய தாவீதைப் பவுல் குறிப்பிடுகிறார்: \"எவனுடைய மீறுதல் மன்னிக்கப்பட்டதோ, எவனுடைய பாவம் மூடப்பட்டதோ, அவன் பாக்கியவான். எவனுடைய அக்கிரமத்தைக் கர்த்தர் எண்ணாதிருக்கிறாரோ, எவனுடைய ஆவியில் கபடமில்லாதிருக்கிறதோ, அவன் பாக்கியவான்.\" பவுல் ஆதாமைப் பயன்படுத்தி ரோமர்களுக்கு மரபுரிமையான பாவத்தின் கோட்பாட்டை விளக்குகிறார், மேலும் கிறிஸ்தவர்களின் கொள்கையை விளக்குவதற்கு வாக்குறுதியின் பிள்ளையான சாரா மற்றும் ஈசாக்கின் ஜீவசரிதையைப் பயன்படுத்துகிறார். அதாவது கிறிஸ்துவின் மூலம் தேவனுடைய தெய்வீக கிருபையின் வாக்குத்தத்த பிள்ளைகளாக மாறியிருக்கிறோம். 9-11 வரையிலுள்ள அதிகாரங்களில், பவுல் இஸ்ரவேல் தேசத்தின் வரலாற்றை விவரிக்கிறார், மேலும் தேவன் இஸ்ரவேலை முற்றிலுமாக நிராகரிக்கவில்லை (ரோமர் 11:11-12) என்று அறிவிக்கிறார், ஆனால் புறஜாதியார்கள் இரட்சிப்புக்குள் கொண்டு வரப்படுவதற்கான முழு எண்ணிக்கையும் வரும் வரை மட்டுமே அவர்களை சிறிது \"தடுமாற\" அனுமதித்திருக்கிறார்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நம்மை இரட்சித்துக்கொள்ள நம்மால் எதுவும் செய்ய இயலாது என்பதை ரோமர் புத்தகம் தெளிவுபடுத்துகிறது. நாம் செய்த ஒவ்வொரு \"நல்ல\" செயலும் தேவனுக்கு முன்பாக ஒரு அழுக்கான கந்தையைப் போன்றதாகும். நாம் நம்முடைய அக்கிரமங்களிலும் பாவங்களிலும் மரித்துவிட்டோம், தேவனுடைய கிருபையும் இரக்கமும் மட்டுமே நம்மைக் இரட்சிக்க முடியும். தேவன் தம்முடைய ஒரே பேறான குமாரனாகிய இயேசு கிறிஸ்துவை சிலுவையில் மரிக்கும்படி அனுப்புவதன் மூலம் அந்த கிருபையையும் இரக்கத்தையும் அவர் வெளிப்படுத்தினார். நாம் நம் வாழ்க்கையை கிறிஸ்துவிடமாய் திருப்பும்போது, நம்முடைய பாவ இயல்புகளால் இனி நாம் கட்டுப்படுத்தப்படுவதில்லை, ஆனால் அதற்கு மாறாக ஆவியினால் கட்டுப்படுத்தப்படுகிறோம். இயேசுவே கர்த்தர் என்று நாம் அறிக்கை செய்து, அவர் மரித்தோரிலிருந்து உயிரோடெழுப்பப்பட்டார் என்று விசுவாசித்தால், நாம் இரட்சிக்கப்படுவோம், அதன் மூலமாக நாம் மறுபடியும் பிறக்கிறோம். நமது வாழ்க்கையை ஜீவ பலியாக தேவனுக்கு ஒப்புக்கொடுத்து நம் வாழ்க்கையை நாம் வாழ வேண்டும். நம்மை இரட்சித்த தேவனை ஆராதிப்பது நம்முடைய உயர்ந்த விருப்பமாக இருக்க வேண்டும். ரோமர் 1:16-ஐப் பயன்படுத்துவதும், சுவிசேஷத்தைப் பற்றி வெட்கப்படாமல் இருப்பதும் ரோமர் புத்தகத்தின் சிறந்த பயன்பாடாகும். மாறாக, அதை அறிவிப்பதில் நாம் அனைவரும் உண்மையுள்ளவர்களாக இருப்போமாக!</p><p>சுமார் கி.பி. 45-47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி.50 - எருசலேம் கவுன்சில்</p><p>சுமார் கி.பி. 51-54 - பவுலின் இரண்டாம். மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 54 - 58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 57 - 58 - ரோம நிருபம் எழுதப்படல்</p><p>சுமார் கி.பி.58 - பவுல் எருசலேமில் கைது செய்யப்படல்</p><p>சுமார் கி.பி. 60 - பவுல் ரோமுக்கு அனுப்பப்படல்</p><p>சுமார் கி.பி. 60 - 62 - பவுல் ரோமச் சிறைச்சாலையில்</p><p>சுமார் கி.பி. 67 - பவுலும் பேதுருவும் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 45-வது நூள்</p><p>அதிநரங்கள் - 16</p><p>வசனங்கள் - 433</p><p>கேள்விகள் - 87</p><p>பழைய ஏற்பாட்டுத் தீர்ககதரிசனங்கள் - 19</p><p>புதிய ஏற்பாட்டுத் தீர்க்கதரிகளாங்கள் - 4</p><p>யரலாற்று யசனங்கள் - 388</p><p>நிறைவேறிய நீர்க்கதரிசனங்கள் - 29</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 16</p>'),
 (530,'<p><b>1 கொரிந்தியர் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>1 கொரிந்தியர் முதலாம் அதிகாரம் 1-வது வசனம், 1 கொரிந்தியர் புத்தகத்தின் எழுத்தாளர் அப்போஸ்தலனாகிய பவுல் என்று அடையாளப்படுத்துகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>1 கொரிந்தியர் புத்தகம் ஏறக்குறைய கி.பி. 55-ல் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>அப்போஸ்தலன் பவுல் கொரிந்துவில் திருச்சபையை நிறுவினார். அங்குள்ள சபையிலிருந்து வெளியேறிய சில ஆண்டுகளுக்குப் பிறகு, கொரிந்திய திருச்சபையைப் பற்றி அப்போஸ்தலனாகிய பவுல் சில பிரச்சனைகளான அறிக்கைகளைக் கேள்விப்பட்டார். அவர்கள் பெருமை நிறைந்தவர்கள் மற்றும் பாலியல் ஒழுக்கக்கேட்டை ஆமோதித்து சமரசம் செய்தனர். ஆவிக்குரிய வரங்கள் முறையற்ற கிரமமில்லாத முறையில் பயன்படுத்தப்பட்டு வருகின்றன எனவும், மேலும் முக்கிய கிறிஸ்தவ உபதேச கோட்பாடுகளின் தவறான புரிதல் இருந்தது எனவும் அறிந்தார். கொரிந்து பட்டண திருச்சபையை அதன் அஸ்திபாரமான இயேசு கிறிஸ்துவுக்கு மீட்டெடுக்கும் முயற்சியில் அப்போஸ்தலனாகிய பவுல் கொரிந்தியருக்கு தனது முதல் கடிதத்தை எழுதினார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>1 கொரிந்தியர் 3:3, \"பொறாமையும் வாக்குவாதமும் பேதகங்களும் உங்களுக்குள் இருக்கிறபடியால், நீங்கள் மாம்சத்திற்குரியவர்களாயிருந்து மனுஷமார்க்கமாய் நடக்கிறீர்களல்லவா?\"</p><p>1 கொரிந்தியர் 6:19-20, \"உங்கள் சரீரமானது நீங்கள் தேவனாலே பெற்றும் உங்களில் தங்கியும் இருக்கிற பரிசுத்த ஆவியினுடைய ஆலயமாயிருக்கிறதென்றும், நீங்கள் உங்களுடையவர்களல்லவென்றும் அறியீர்களா? கிரயத்துக்குக் கொள்ளப்பட்டீர்களே; ஆகையால் தேவனுக்கு உடையவைகளாகிய உங்கள் சரீரத்தினாலும் உங்கள் ஆவியினாலும் தேவனை மகிமைப்படுத்துங்கள்.\"</p><p>1 கொரிந்தியர் 10:31, \"ஆகையால் நீங்கள் புசித்தாலும், குடித்தாலும், எதைச் செய்தாலும், எல்லாவற்றையும் தேவனுடைய மகிமைக்கென்று செய்யுங்கள்.\"</p><p>1 கொரிந்தியர் 12:7, \"ஆவியினுடைய அநுக்கிரகம் அவனவனுடைய பிரயோஜனத்திற்கென்று அளிக்கப்பட்டிருக்கிறது.\"</p><p>1 கொரிந்தியர் 13:4-7, \"அன்பு நீடிய சாந்தமும் தயவுமுள்ளது; அன்புக்குப் பொறாமையில்லை; அன்பு தன்னைப் புகழாது, இறுமாப்பாயிராது, அயோக்கியமானதைச் செய்யாது, தற்பொழிவை நாடாது, சினமடையாது, தீங்கு நினையாது, அநியாயத்தில் சந்தோஷப்படாமல், சத்தியத்தில் சந்தோஷப்படும். சகலத்தையும் தாங்கும், சகலத்தையும் விசுவாசிக்கும், சகலத்தையும் நம்பும், சகலத்தையும் சகிக்கும்.\"</p><p>1 கொரிந்தியர் 15:3-4, \"நான் அடைந்ததும் உங்களுக்குப் பிரதானமாக ஒப்புவித்ததும் என்னவென்றால், கிறிஸ்துவானவர் வேதவாக்கியங்களின்படி நமது பாவங்களுக்காக மரித்து, அடக்கம்பண்ணப்பட்டு, வேதவாக்கியங்களின்படி மூன்றாம் நாளில் உயிர்த்தெழுந்தார்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>கொரிந்துவிலுள்ள திருச்சபையானது பல்வேறு உட்பிவுகளால் பாதிக்கப்பட்டிருந்தது. கொரிந்துவிலுள்ள விசுவாசிகள் சில ஆவிக்குரியத் தலைவர்களுக்கு விசுவாசமுள்ள குழுக்களாகப் பிரிந்து இருந்தார்கள் (1 கொரிந்தியர் 1:12; 3:1-6). கிறிஸ்துவுக்குள்ள தேவபக்தியால் கொரிந்து சபை விசுவாசிகள் ஒன்றுபட வேண்டும் என்று பவுல் அறிவுறுத்தினார் (1 கொரிந்தியர் 3:21-23). திருச்சபையில் பலர் அடிப்படையில் ஒழுக்கக்கேடான உறவை அங்கீகரித்து ஏற்றுக்கொண்டனர் (1 கொரிந்தியர் 5:1-2). துன்மார்க்கரை சபையிலிருந்து வெளியேற்றும்படி பவுல் அவர்களுக்குக் கட்டளையிட்டார் (1 கொரிந்தியர் 5:13). கொரிந்து சபை விசுவாசிகள் ஒருவருக்கொருவர் வழக்குண்டாக்கிக்கொண்டு அவர்களுக்கு எதிராக நீதிமன்றத்திற்கு சென்றார்கள் (1 கொரிந்தியர் 6:1-2). கிறிஸ்தவ சாட்சியை சேதப்படுத்துவதை விட சாதகமாகப் பயன்படுத்துவது நல்லது என்று பவுல் கொரிந்தியருக்குக் கற்பித்தார் (1 கொரிந்தியர் 6:3-8).</p><p>பவுல் கொரிந்து சபையிலுள்ள விசுவாசிகளுக்கு திருமணம் மற்றும் பிரம்மச்சரியம் (7-ஆம் அதிகாரம்), விக்கிரகங்களுக்குப் படைக்கப்பட்ட உணவு (8 மற்றும் 10 வது அதிகாரங்கள்), கிறிஸ்தவ சுதந்திரம் (9-ஆம் அதிகாரம்), ஸ்திரீகள் தலையை முக்காடிட்டுக்கொண்டிருத்தல் (1 கொரிந்தியர் 11:1-16), கர்த்தருடைய பந்தி (1 கொரிந்தியர் 11:17-34), ஆவிக்குரிய வரங்கள் (12-14 வரையிலுள்ள அதிகாரங்கள்), மற்றும் உயிர்த்தெழுதல் (15-ஆம் அதிகாரம்) ஆகியவைகளைக் குறித்த போதனைகள் மற்றும் அறிவுரைகளை வழங்கினார். கொரிந்து சபை விசுவாசிகள் அவரிடம் கேட்ட கேள்விகளுக்கு பதிலளிப்பதன் மூலமும், அவர்கள் ஏற்றுக்கொண்ட தவறான நடத்தை மற்றும் தவறான நம்பிக்கைகளுக்கு பதிலளிப்பதன் மூலமும் பவுல் 1 கொரிந்தியர் புத்தகத்தை சீராக மற்றும் நேர்த்தியாக எழுதினார்/வடிவமைத்தார்.</p><p><b>இணைப்புகள்:</b></p><p>1 கொரிந்தியர் புத்தகத்தின் 10-ஆம் அதிகாரத்தில், பவுல் வனாந்தரத்தில் அலைந்து திரிந்த இஸ்ரவேலர்களின் சரித்திரத்தை கொரிந்து சபை விசுவாசிகளுக்கு எடுத்துக்காட்டி விளக்குகிறார். கொரிந்தியர்களுக்கு சுய ஒழுக்கம் மற்றும் கட்டுப்பாடு இல்லாததைப் பற்றி பவுல் கடுமையாக எச்சரித்திருக்கிறார் (1 கொரிந்தியர் 9:24-27). தேவனுடைய அற்புதங்களைப் பார்த்து, அவர்களை தேவன் எவ்வாறு கருதினார் என்பதை அறிந்தபோதிலும், செங்கடலை இரண்டாகப் பிரித்தது, வானத்திலிருந்து மன்னா மற்றும் ஒரு பாறையிலிருந்து தண்ணீர் போன்ற அற்புதமான ஏற்பாடுகளைச் செய்தபோதிலும், அவர்கள் தங்கள் சுதந்திரத்தை தவறாகப் பயன்படுத்தினார்கள், தேவனுக்கு எதிராகக் கலகம் செய்தார்கள், ஒழுக்கக்கேடு மற்றும் விக்கிரக ஆராதனை போன்றவற்றில் ஈடுபட்டார்கள். இஸ்ரவேலரின் முன்மாதிரியைக் கவனிக்கவும், காமங்களையும் பாலியல் ஒழுக்கக்கேட்டையும் தவிர்க்கவும் மற்றும் கிறிஸ்துவை சோதனைக்கு உட்படுத்தி புகார் கூறுகிறதை தவிர்க்கவும் பவுல் கொரிந்து சபை விசுவாசிகளை அறிவுறுத்துகிறார் (வச. 6-10). எண்ணாகமம் 11:4, 34, 25:1-9; யாத்திராகமம் 16:2, 17:2, 7 ஆகிய வசனங்களையும் காண்க.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>கொரிந்து சபையானது கையாண்ட பல பிரச்சினைகள் மற்றும் கேள்விகள் இன்றும் இன்றைய திருச்சபைகளில் காணப்படுகின்றன. திருச்சபைகள் இன்றும் பிளவுகளுடன், ஒழுக்கக்கேட்டோடு, ஆவிக்குரிய வரங்களைப் பயன்படுத்துகின்றன. 1 கொரிந்தியர் புத்தகம் இன்றுள்ள திருச்சபைக்கும் மிக நன்றாக எழுதப்பட்டிருக்கிறது, ஆகையால் பவுலின் எச்சரிக்கைகளுக்கு செவிசாய்த்து அவற்றை நமக்குப் பயன்படுத்துவோமாக. எல்லா கண்டனங்களும் திருத்தங்களும் இருந்தபோதிலும், 1 கொரிந்தியர் புத்தகம் கிறிஸ்துவின் மீது நமக்கு இருக்க வேண்டிய இடத்திற்கு நம் கவனத்தை மீண்டும் கொண்டு வருகிறது. உண்மையான கிறிஸ்தவ அன்பு பல பிரச்சினைகளுக்கு விடையாக இருக்கிறது (13-வது அதிகாரம்). கிறிஸ்துவின் உயிர்த்தெழுதல் பற்றிய சரியான புரிதல், 15 ஆம் அதிகாரத்தில் வெளிப்படுத்தப்பட்டுள்ளபடி, அதன் மூலம் நம்முடைய சொந்த உயிர்த்தெழுதலைப் பற்றிய சரியான புரிதலும்,</p><p>நம்மைப் பிரித்து தோற்கடிப்பதற்கான காரணிகளுக்கு தீர்வாகும்.</p><p>சுமார் கி.பி.45 - 47 - பவுவின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி.50 - எருசலேம் கவுன்சில்</p><p>சுமார் கி.பி. 51 - 54 - பவுலின் இரண்டாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 52 53 - கொரிந்தில் சபை நிறுவப்படல்</p><p>சுமார் கி.பி. 54-58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 55/ 56 - 1கொரிந்தியர் நிருபம் எழுதப்படல்</p><p>சுமார் கி.பி. 58 - பவுல் எருசலேமில் கைது செய்யப்படல்</p><p>சுமார் கி.பி. 61-62 - பவுல் ரோமச் சிறையில்</p><p>சுமார் கி.பி. 67 - பவுல் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 45-வது நூல்</p><p>அதிகாரங்கள் - 15</p><p>வானஙகள் - 437</p><p>கேள்விகள் - 113</p><p>பழைய ஏற்பாட்டுத் தீர்க்க தரிசனங்கள் - 5</p><p>புதிய ஏற்பாட்டுத் தீர்க்கதரிசனங்கள் - 13</p><p>வரலாற்று வசனங்கள் - 377</p><p>நிறைவேறாத தீர்க்கதரிசனங்கள் - 55</p><p>நிறைவேறியவை - 5</p>'),
 (540,'<p><b>2 கொரிந்தியர் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>2 கொரிந்தியர் புத்தகம் முதலாம் அதிகாரத்தின் முதலாவது வசனம், 2 கொரிந்தியர் புத்தகத்தின் எழுத்தாளர் அப்போஸ்தலனாகிய பவுல் என்று அடையாளம் காட்டுகிறது, ஒருவேளை தீமோத்தேயுவுடன் சேர்ந்து பவுல் இதை எழுதியிருக்கலாம்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>2 கொரிந்தியர் புத்தகம் ஏறக்குறைய கி.பி. 55-57 வரையிலுள்ள காலக்கட்டத்தில் எழுதப்பட்டிருக்கலாம்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>கொரிந்து திருச்சபை கி.பி. 52-ல் பவுல் தனது இரண்டாவது சுவிசேஷப் பயணத்தில் அங்கு சென்றபோது ஆரம்பிக்கப்பட்டதாகும். அப்போதுதான் அவர் ஒன்றரை ஆண்டுகள் காலம் அங்கே தங்கியிருந்தார், இங்குதான் முதல் முறையாக அவர் விரும்பிய வரை ஒரே இடத்தில் தங்க அனுமதிக்கப்பட்டார். இந்த பயணம் மற்றும் திருச்சபையின் ஆரம்பம் பற்றிய பதிவு அப்போஸ்தலர் 18:1-18-ல் காணப்படுகிறது.</p><p>கொரிந்தியருக்கு எழுதிய இரண்டாவது நிருபத்தில், கொரிந்தியர்கள் (விசுவாசிகள்) தன்னுடைய \"கடுமையான\" நிருபத்தை (இப்போது அது இல்லை, அது இழந்துபோய்விட்டது) நேர்மறையான முறையில் பெற்றிருப்பதாக பவுல் தனது நிம்மதியையும் மகிழ்ச்சியையும் வெளிப்படுத்துகிறார். அந்த கடிதம் திருச்சபையை கிழித்தெறியும் பிரச்சினைகளைக் குறித்து உரையாற்றியது, முதன்மையாக சுய பாணியில் (தவறான) அப்போஸ்தலர்களின் வருகை (2 கொரிந்தியர் 11:13) அவர்கள் பவுலின் தன்மையைத் தாக்கி, விசுவாசிகளிடையே கருத்து வேறுபாட்டை விதைத்து, தவறான கோட்பாட்டைக் கற்பித்தனர். அவருடைய உண்மைத்தன்மை (2 கொரிந்தியர் 1:15-17), அவர் பேசும் திறன் (2 கொரிந்தியர் 10:10; 11:6) மற்றும் கொரிந்து சபையின் ஆதரவை ஏற்க அவர் விரும்பாதது போன்றவற்றை அவர்கள் கேள்விக்குள்ளாக்கியதாகத் தெரிகிறது (2 கொரிந்தியர் 11:7- 9; 12:13). அவர்களுடைய உரிமம் பெற்ற நடத்தையிலிருந்து மனந்திரும்பாத சிலரும் இருந்தார்கள் (2 கொரிந்தியர் 12:20-21).</p><p>கொரிந்தியர்களில் பெரும்பாலானோர் பவுலுக்கு எதிரான கிளர்ச்சியிருந்து மனந்திரும்பியதாக தீத்துவிடமிருந்து பவுல் கேட்டறிந்து பெரும் மகிழ்ச்சியடைந்தார் (2 கொரிந்தியர் 2:12-13; 7:5-9). அப்போஸ்தலனாகிய பவுல் இதற்காக தனது உண்மையான அன்பின் வெளிப்பாடாக அவர்களை ஊக்குவிக்கிறார் (2 கொரிந்தியர் 7:3-16). ஏழைகளுக்காக ஒரு தர்மபணத்தை சேகரிப்பதை முடிக்கவும் (8—9 அதிகாரங்கள்) பொய்யான போதகர்களுக்கு எதிராக கடுமையான நிலைப்பாட்டை எடுக்கவும் பவுல் கொரிந்தியர்களை வலியுறுத்தினார் (10—13 வரையிலுள்ள அதிகாரங்கள்). இறுதியாக, பவுல் தான் அப்போஸ்தலனாக இருப்பதை நிரூபித்தார், ஏனெனில் சபையில் சிலர் அவருடைய அப்போஸ்தல அதிகாரத்தை கேள்விக்குள்ளாக்கியிருக்கலாம் (2 கொரிந்தியர் 13:3).</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>2 கொரிந்தியர் 3:5, \"எங்களால் ஏதாகிலும் ஆகும் என்பதுபோல ஒன்றை யோசிக்கிறதற்கு நாங்கள் எங்களாலே தகுதியானவர்கள் அல்ல; எங்களுடைய தகுதி தேவனால் உண்டாயிருக்கிறது.\"</p><p>2 கொரிந்தியர் 3:18, \"நாமெல்லாரும் திறந்த முகமாய்க் கர்த்தருடைய மகிமையைக் கண்ணாடியிலே காண்கிறதுபோலக் கண்டு, ஆவியாயிருக்கிற கர்த்தரால் அந்தச் சாயலாகத்தானே மகிமையின்மேல் மகிமையடைந்து மறுரூபப்படுகிறோம்.\"</p><p>2 கொரிந்தியர் 5:17, \"இப்படியிருக்க, ஒருவன் கிறிஸ்துவுக்குள்ளிருந்தால் புதுச்சிருஷ்டியாயிருக்கிறான்; பழையவைகள் ஒழிந்துபோயின, எல்லாம் புதிதாயின.\"</p><p>2 கொரிந்தியர் 5:21, \"நாம் அவருக்குள் தேவனுடைய நீதியாகும்படிக்கு, பாவம் அறியாத அவரை நமக்காகப் பாவமாக்கினார்.\"</p><p>2 கொரிந்தியர் 10:5, \"அவைகளால் நாங்கள் தர்க்கங்களையும், தேவனை அறிகிற அறிவுக்கு விரோதமாய் எழும்புகிற எல்லா மேட்டிமையையும் நிர்மூலமாக்கி, எந்த எண்ணத்தையும் கிறிஸ்துவுக்குக் கீழ்ப்படியச் சிறைப்படுத்துகிறவர்களாயிருக்கிறோம்.\"</p><p>2 கொரிந்தியர் 13:4, \"ஏனெனில் அவர் பலவீனத்தால் சிலுவையில் அறையப்பட்டிருந்தும், தேவனுடைய வல்லமையினால் பிழைத்திருக்கிறார்; அப்படி நாங்களும் அவருக்குள் பலவீனராயிருந்தும், உங்களிடமாய் விளங்கிய தேவனுடைய வல்லமையினால் அவருடனேகூடப் பிழைத்திருப்போம்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>கொரிந்து திருச்சபையிலுள்ள விசுவாசிகளை வாழ்த்தி, முதலில் திட்டமிட்டபடி அவர் ஏன் அவர்களை சந்திக்கவில்லை என்பதை விளக்கிய பிறகு (வச. 1: 3–2:2), பவுல் தனது ஊழியத்தின் தன்மையை விளக்குகிறார். கிறிஸ்துவின் மூலம் வெற்றியும், தேவனுக்கு முன்பாக நேர்மையும் அவர் திருச்சபைகளுக்கு செய்த ஊழியத்தின் அடையாளங்களாக இருந்தன (2:14-17). அவர் கிறிஸ்துவினுடைய நீதியின் புகழ்பெற்ற ஊழியத்தை நியாயப்பிரமாணமான \"கண்டன ஊழியத்திற்கு\" ஒப்பிடுகிறார் (வசனம் 3:9) மற்றும் கடுமையான துன்புறுத்தல்களுக்கு மத்தியிலும் தனது ஊழியத்தின் செல்லுபடியாகும் நம்பிக்கையை அவர் அறிவிக்கிறார் (4:8-18) . 5-ஆம் அதிகாரம் கிறிஸ்தவ விசுவாசத்தின் அடிப்படையைக் கோடிட்டுக் காட்டுகிறது - புதிய சுபாவம் (வச. 17) மற்றும் கிறிஸ்துவின் நீதிக்காக நம்முடைய பாவத்தை பரிமாறிக்கொள்வது (வச. 21).</p><p>6 மற்றும் 7-வது அதிகாரங்கள் பவுல் தன்னையும் ஊழியத்தையும் பாதுகாத்து வருவதைக் காண்பிக்கின்றன, கொரிந்தியர்களிடம் அவர்மீது வைத்திருக்கும் நேர்மையான அன்பை மீண்டும் உறுதிப்படுத்துவதோடு மனந்திரும்புதலுக்கும் பரிசுத்த வாழ்க்கைக்கும் அவர்களை அறிவுறுத்துகின்றன. 8 மற்றும் 9-ஆம் அதிகாரங்களில், கொரிந்திலுள்ள விசுவாசிகளுக்கு மக்கதொனியாவில் உள்ள சகோதரர்களின் முன்மாதிரிகளைப் பின்பற்றவும், தேவைப்படும் பரிசுத்தவான்களுக்கு தாராள மனப்பான்மையை வழங்கவும் பவுல் அறிவுறுத்துகிறார். இரக்கத்துடன் கொடுப்பதன் கொள்கைகளையும் வெகுமதிகளையும் அவர் அவர்களுக்குக் கற்றுக்கொடுக்கிறார்.</p><p>பவுல் தமது அப்போஸ்தல அதிகாரத்தை மீண்டும் வலியுறுத்துவதன் மூலம் தனது கடிதத்தை முடிக்கிறார் (10வது அதிகாரம்) மற்றும் பொய்யான கள்ள அப்போஸ்தலர்களிடமிருந்து கடுமையான எதிர்ப்பை எதிர்கொள்வதில் அவர்கள் உண்மையுள்ளவர்களாக இருப்பதைக் கவனித்துக்கொள்கிறார். தன்னுடைய தகுதிகளையும், கிறிஸ்துவுக்காக அவர் அனுபவித்த துன்பங்களையும் தயக்கமின்றி பெருமைப்படுத்தியதற்காக அவர் தன்னை ஒரு \"முட்டாள்\" என்று அழைக்கிறார் (அத்தியாயம் 11). அவர் அனுபவிக்க அனுமதிக்கப்பட்ட பரலோகத்தின் தரிசனத்தையும், அவருடைய மனத்தாழ்மையையும் உறுதிப்படுத்த தேவனால் அவருக்கு வழங்கப்பட்ட \"மாம்சத்தில் உள்ள முள்ளையும்\" விவரிப்பதன் மூலம் அவர் தனது நிருபத்தை முடிக்கிறார் (12வது அதிகாரம்). கடைசி அதிகாரத்தில் கொரிந்தியருக்கு அவர்களுக்கு அறிவுறுத்துவது யதார்த்தமானதா என்று தங்களை ஆராய்ந்து பார்க்க வேண்டும் என்றும், மேலும் அன்பு மற்றும் சமாதானத்தின் ஒரு முடிவோடு முடிகிறது.</p><p><b>இணைப்புகள்:</b></p><p>பவுல் தனது நிருபங்கள் முழுவதும், மோசேயின் சட்டத்தை அடிக்கடி மேற்கொள்காட்டிக் குறிப்பிடுகிறார், அதை இயேசு கிறிஸ்துவின் நற்செய்தியின் மிகைப்படுத்தப்பட்ட மகத்துவத்துடனும், கிருபையால் உண்டாகும் இரட்சிப்பிற்கும் ஒப்பிடுகிறார். 2 கொரிந்தியர் 3:4-11-ல், பவுல் பழைய ஏற்பாட்டு நியாயப்பிரமாணச் சட்டத்தை கிருபையின் புதிய உடன்படிக்கையுடன் முரண்படுத்துகிறார், நியாயப்பிரமாணம் கொல்கிறது என்றும் ஆவியானது உயிர்ப்பிக்கிறது என்றும் நியாயப்பிரமாண சட்டத்தைக் குறித்துக் குறிப்பிடுகிறார். நியாயப்பிரமாணச் சட்டம் என்பது \"எழுத்துக்களினால் எழுதப்பட்டுக் கற்களில் பதிந்திருந்த மரணத்துக்கேதுவான ஊழியம்\" (வச. 7; யாத்திராகமம் 24:12) ஏனெனில் அது பாவத்தைப் பற்றிய அறிவையும் அதன் கண்டனத்தையும் மட்டுமே தருகிறது. நியாயப்பிரமாணத்தின் மகிமை என்னவென்றால், அது தேவனுடைய மகிமையை பிரதிபலிக்கிறது, ஆனால் ஆவியின் ஊழியம் நியாயப்பிரமாணத்தின் ஊழியத்தை விட மிகவும் மகிமையானது, ஏனென்றால் அது கிறிஸ்துவை நியாயப்பிரமாணத்தின் நிறைவேறுதலாக வழங்குவதில் அவருடைய இரக்கம், கிருபை மற்றும் அன்பை பிரதிபலிக்கிறது.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>இந்த நிருபம் பவுலின் நிருபங்களில் மிகவும் கூடுதல் சுயசரிதை மற்றும் குறைந்தளவு போதனைக்கோட்பாடு அடங்கியதாகும். இந்த நிருபமானது மற்றெல்லாவற்றைக் காட்டிலும் பவுலைப் பற்றி ஒரு நபராகவும் ஊழியராகவும் நமக்கு அதிகம் சொல்லுகிறது. இவற்றிலிருந்து சில விஷயங்களை நாமும் எடுத்து இன்று நம் வாழ்விற்குப் பயன்படுத்தலாம். முதல் விஷயம் உக்கிராணத்துவம், பண விஷயத்தில் மட்டுமல்ல, நேரமும் கூட. மக்கதொனியாவில் உள்ளவர்கள் தாராளமாகக் கொடுத்ததோடு மட்டுமல்லாமல், \"தேவனுடைய சித்தத்தினாலே முன்பு தங்களைத்தாமே கர்த்தருக்கும், பின்பு எங்களுக்கும் ஒப்புக்கொடுத்தார்கள்\" (2 கொரிந்தியர் 8:5). அதேபோல், தேவனுக்காக நம்மிடமுள்ள அனைத்தையும் மட்டுமல்ல, நம்மையே முழுமையாக அர்ப்பணிக்க வேண்டும். அவருக்கு உண்மையில் நம்முடைய பணம் தேவையில்லை. அவர் சர்வ வல்லமையுள்ளவர்! அவர் விரும்புவது நம் இதயத்தை தான், நாம் முழு இருதயத்தோடு சேவை செய்ய விரும்புகிறார், நம்மேல் தயவு காண்பித்து நேசிக்கிறார். உக்கிராணத்துவம் மற்றும் தேவனுக்கு கொடுத்தல் என்பது பணத்தை விட மேலானதாகும். ஆம், நம்முடைய வருமானத்தின் ஒரு பகுதியை நாம் தசமபாகமாக கொடுக்க வேண்டும் என்று தேவன் விரும்புகிறார், நாம் அவருக்குக் கொடுக்கும்போது அவர் நம்மை ஆசீர்வதிப்பார் என்று வாக்குறுதியும் அளிக்கிறார். இன்னும் அதிகம் உள்ளது. தேவன் 100% விரும்புகிறார். நம்முடைய அனைத்தையும் அவருக்குக் கொடுக்க வேண்டும் என்று அவர் விரும்புகிறார். நாமும் நமக்குள்ளது எல்லாமும் அவருக்கே உரியதாகும். நம்முடைய பிதாவுக்கு சேவை செய்வதற்காக நாம் நம் வாழ்க்கையை வாழ வேண்டும். நம்முடைய சம்பளக் காசோலையிலிருந்து நாம் தேவனுக்குக் கொடுக்கக் கூடாது, ஆனால் நம்முடைய வாழ்க்கையே அவருக்கு கொடுக்கவேண்டும், அது அவரைப் பிரதிபலிப்பதாக இருக்க வேண்டும். நாம் முதலில் கர்த்தருக்கும், பின்னர் திருச்சபைக்கும், இயேசு கிறிஸ்துவினுடைய ஊழியத்தின் வேலைக்காகவும் கொடுக்க வேண்டும்.</p><p>கி.பி. 45 - 47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>கி.பி. 50 - எருசலேம் கவுன்சில்</p><p>கி.பி. 51-54 - பவுலின் இரண்டாம் மிஷனரிப் பயணம்</p><p>கி.பி. 52 - கொரிந்தில் சபை உருவாதல்</p><p>கி.பி. 54 - 58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>கி.பி. 56 - 1கொரிந்தியர் எழுதப்படல்</p><p>கி.பி. 56 - 57 - 2கொரிந்தியர் எழுதப்படல்</p><p>கி.பி. 58 - பவுல் எருசலேமில் சிறையாதல்</p><p>கி.பி.61-62 - பவுல் ரோமச் சிறையில்</p><p>கி.பி. 67 - பவுல் சிரச்சேதம் செய்யப்படல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 47-வது நூல்</p><p>அதிகாரங்கள் - 13</p><p>வசனங்கள - 257</p><p>கேள்விகள் - 29</p><p>பழைய ஏற்பாட்டுத் தீர்க்கதரிசனங்கள் - 4</p><p>புதிய ஏற்பாட்டுத்தீர்க்கதரிசனங்கள் - 4</p><p>வரலாற்று வசனங்கள் - 249</p><p>நிறைவேறாத தீர்க்கதரிசனங்கள் - 4</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 4</p>'),
 (550,'<p><b>கலாத்தியருக்கு எழுதின நிருபம்</b></p><p><b>எழுத்தாளர்:</b></p><p>கலாத்தியர் 1:1-வது வசனம் அப்போஸ்தலனாகிய பவுலை கலாத்தியருக்கு எழுதின நிருபத்தின் எழுத்தாளராக தெளிவாக அடையாளம் காட்டுகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>கலாத்தியருக்கு எழுதின நிருபம் சரியாக எங்கு அனுப்பப்பட்டது என்பதையும், எந்த மிஷனரி பயணத்தின் போது பவுல் அந்த பகுதியில் திருச்சபைகளை ஸ்தாபித்தார் என்பதையும் பொறுத்து, கலாத்தியருக்கு எழுதின நிருபம் கி.பி. 48 முதல் கி.பி. 55 வரையிலுள்ள காலக்கட்டத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>கலாத்தியாவில் உள்ள திருச்சபைகள் மனந்திரும்பி கிறிஸ்துவை விசுவாசித்த யூதர்கள் மற்றும் புறஜாதியினரை கொண்டிருந்தது. பவுல் தனது அப்போஸ்தல குணத்தையும், அவர் கற்பித்த கோட்பாடுகளையும் வலியுறுத்துகிறார், அவர் கிறிஸ்துவின்மேலுள்ள விசுவாசத்தில் கலாத்திய திருச்சபைகளை உறுதிப்படுத்தும் நோக்கத்தில், குறிப்பாக விசுவாசத்தால் மட்டுமே நீதிமானாக்கப்பட முடியும் என்பதான முக்கியமான கருத்தை வலியுறுத்தினார். ஆகவே இந்த பொருள் முக்கியமாக ரோமர்களுக்கு எழுதிய நிருபத்தில் விவாதிக்கப்பட்டதைப் போன்றது, அதாவது விசுவாசத்தால் மட்டுமே நீதிமானாக்கப்படுகிறார்கள். எவ்வாறாயினும், இந்த நிருபத்தில் மோசேயின் நியாயப்பிரமாணத்தின் செயல்கள் இல்லாமல் மனிதர்கள் விசுவாசத்தினால் நீதிமானாக்கப்படுகிறார்கள் என்பதில் கவனம் செலுத்தப்படுகிறது.</p><p>சமகால வரலாறு அடங்கிய ஒரு கட்டுரையாக இந்த கலாத்தியர் நிருபம் எழுதப்படவில்லை. இது கிறிஸ்துவின் சுவிசேஷத்தை அசூசிப்படுத்துதலுக்கு எதிரான போராட்டமாகும். நியாயப்பிரமாணத்தின் செயல்களால் அல்லாமல் விசுவாசத்தால் நீதிமானாக்கப்படுவதற்கான அத்தியாவசிய சத்தியத்தை யூதர்கள் புறக்கணித்து, தேவனுக்கு முன்பாக பரிபூரணமாக இருக்க வேண்டுமானால் கிறிஸ்தவ விசுவாசிகள் நியாயப்பிரமாண சட்டத்தைக் கடைப்பிடிக்க வேண்டும் என்று வலியுறுத்தினார்கள். இந்த போதனை கலாத்திய திருச்சபைகளில் ஊடுருவத் தொடங்கியிருப்பதாகவும், அது அவர்களின் சுதந்திரத்தின் பாரம்பரியத்திலிருந்து அவர்களை அந்நியப்படுத்தியதாகவும் பவுல் அறிந்தபோது, இந்த நிருபத்தில் உள்ள உணர்ச்சிமிக்க மறுபரிசீலனை ஒன்றை எழுதினார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>கலாத்தியர் 2:16, \"நியாயப்பிரமாணத்தின் கிரியைகளினாலே எந்த மனுஷனும் நீதிமானாக்கப்படுவதில்லையே.\"</p><p>கலாத்தியர் 2:20, \"கிறிஸ்துவுடனேகூடச் சிலுவையிலறையப்பட்டேன்; ஆயினும், பிழைத்திருக்கிறேன்; இனி நான் அல்ல, கிறிஸ்துவே எனக்குள் பிழைத்திருக்கிறார்; நான் இப்பொழுது மாம்சத்தில் பிழைத்திருக்கிறதோ, என்னில் அன்புகூர்ந்து எனக்காகத் தம்மைத்தாமே ஒப்புக்கொடுத்த தேவனுடைய குமாரனைப்பற்றும் விசுவாசத்தினாலே பிழைத்திருக்கிறேன்.\"</p><p>கலாத்தியர் 3:11, \"நியாயப்பிரமாணத்தினாலே ஒருவனும் தேவனிடத்தில் நீதிமானாகிறதில்லையென்பது வெளியரங்கமாயிருக்கிறது. ஏனெனில், விசுவாசத்தினாலே நீதிமான் பிழைப்பான் என்று எழுதியிருக்கிறதே.\"</p><p>கலாத்தியர் 4:5-6, \"காலம் நிறைவேறினபோது, ஸ்திரீயினிடத்திற் பிறந்தவரும் நியாயப்பிரமாணத்திற்குக் கீழானவருமாகிய தம்முடைய குமாரனை தேவன் அனுப்பினார். மேலும் நீங்கள் புத்திரராயிருக்கிறபடியினால், அப்பா, பிதாவே! என்று கூப்பிடத்தக்கதாக தேவன் தமது குமாரனுடைய ஆவியை உங்கள் இருதயங்களில் அனுப்பினார்.\"</p><p>கலாத்தியர் 5:22-23, \"ஆவியின் கனியோ, அன்பு, சந்தோஷம், சமாதானம், நீடியபொறுமை, தயவு, நற்குணம், விசுவாசம், சாந்தம், இச்சையடக்கம்; இப்படிப்பட்டவைகளுக்கு விரோதமான பிரமாணம் ஒன்றுமில்லை.\"</p><p>கலாத்தியர் 6:7, \"மோசம்போகாதிருங்கள், தேவன் தம்மைப் பரியாசம்பண்ணவொட்டார்; மனுஷன் எதை விதைக்கிறானோ அதையே அறுப்பான்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>விசுவாசத்தின் மூலம் கிருபையால் நீதிமானாக்கப்பட்டதன் விளைவாக ஆவிக்குரிய சுதந்திரம் கிடைத்திருக்கிறது. பவுல் கலாத்தியரை அவர்களது கிறிஸ்தவ சுதந்திரத்தில் நிலைத்து நிற்கும்படிக்கு வேண்டுகோள் விடுத்தார், மேலும் \"அவர்களை மறுபடியும் அடிமைத்தனத்தின் நுகத்துக்குட்படாமல் (அதாவது மோசேயின் நியாயப்பிரமாணம்), கிறிஸ்து நமக்கு உண்டாக்கின சுயாதீன நிலைமையிலே நிலைகொண்டிருங்கள்\" (கலாத்தியர் 5:1) என்று கூறினார். கிறிஸ்தவ சுதந்திரம் என்பது ஒருவரின் தாழ்ந்த தன்மையைப் உயர்த்திக் காண்பித்து அதனால் திருப்தி அடைந்துகொள்வது அல்ல; மாறாக, இது ஒருவருக்கொருவர் அன்பு செலுத்துவதற்கான ஒரு வாய்ப்பாகும் (கலாத்தியர் 5:13; 6:7-10). இத்தகைய சுதந்திரம் ஒருவரை அவரது வாழ்க்கைப் போராட்டங்களிலிருந்து இரட்சிக்காது. உண்மையில், அது ஆவிக்கும் மாம்சத்திற்கும் இடையிலான போரை தீவிரப்படுத்தக்கூடும். ஆயினும், மாம்சமானது (கீழான சுபாவம்) கிறிஸ்துவுடன் சிலுவையில் அறையப்பட்டுள்ளது (கலாத்தியர் 2:20); அதன் விளைவாக, ஆவியானவர் விசுவாசியின் வாழ்க்கையில் அன்பு, சந்தோஷம், மற்றும் சமாதானம் போன்ற ஆவியின் கனியதைத் தரும்படிச் செய்வார் (கலாத்தியர் 5:22-23).</p><p>கலாத்தியர்களுக்கு எழுதிய நிருபம் ஈர்க்கப்பட்ட கிளர்ச்சியின் உந்துதலால் எழுதப்பட்டது. பவுலைப் பொறுத்தமட்டில், ஒரு நபர் விருத்தசேதனம் செய்யப்பட்டாரா என்பது அல்ல, ஆனால் அவர் \"ஒரு புதிய சிருஷ்டி\" ஆகிவிட்டாரா என்பதுதான் (கலாத்தியர் 6:15) முக்கியமான காரியமாகும். விசுவாசத்தால் மட்டுமே நீதிமானாக்கப்படுவதற்கான விவாதத்தில் பவுல் வெற்றிபெறவில்லை என்றால், கிறிஸ்தவ மதம் உலகளாவிய இரட்சிப்பின் வழியாக இருப்பதற்குப் பதிலாக யூத மதத்திற்குள் ஒரு பிரிவாகவே இருந்திருக்கும். ஆகவே, கலாத்தியருக்கு எழுதப்பட்ட நிருபம் லூத்தரின் நிருபம் மட்டுமல்ல; பவுலுடன் அறிக்கைசெய்யும் ஒவ்வொரு விசுவாசியின் நிருபமும் இதுதான்: \"கிறிஸ்துவுடனேகூடச் சிலுவையிலறையப்பட்டேன்; ஆயினும், பிழைத்திருக்கிறேன்; இனி நான் அல்ல, கிறிஸ்துவே எனக்குள் பிழைத்திருக்கிறார்; நான் இப்பொழுது மாம்சத்தில் பிழைத்திருக்கிறதோ, என்னில் அன்புகூர்ந்து எனக்காகத் தம்மைத்தாமே ஒப்புக்கொடுத்த தேவனுடைய குமாரனைப்பற்றும் விசுவாசத்தினாலே பிழைத்திருக்கிறேன்\" (கலாத்தியர் 2:20).</p><p>கிறிஸ்தவத்தின் இரண்டு அம்சங்களை யாக்கோபு மற்றும் கலாத்தியர் புத்தகங்கள் விளக்குகின்றன, ஆரம்பத்தில் இருந்தே அவைகள் இரண்டும் ஒன்றுக்கொன்று முரண்பாடாகத் தெரிகின்றன, ஆனால் அவை உண்மையில் ஒன்றுக்கொன்று துணை நிற்கின்றன. கிறிஸ்துவின் நன்நெறிமுறையை யாக்கோபு வலியுறுத்துகிறார், விசுவாசமானது அதன் பலன்களால் அதனுடைய இருப்பை நிரூபிக்க வேண்டும் என்ற கோரிக்கையை முன்வைக்கிறார். ஆயினும், யாக்கோபு, பவுலுக்கு எந்த விதத்திலும் குறையாமல், தேவனுடைய கிருபையால் தான் தனிநபரின் மனமாற்றம் என்கிற அவசியத்தை வலியுறுத்துகிறார் (யாக்கோபு 1:18). மறுபுறம் நன்நெறிமுறையை உருவாக்கும் நற்செய்தியின் ஆற்றலை கலாத்தியர் நிருபம் வலியுறுத்துகிறது (கலாத்தியர் 3:13-14). நன்நெறிமுறை வாழ்க்கையைப் பற்றி பவுல் யாக்கோபை விடக் குறைவாக அக்கறை காட்டவில்லை (கலாத்தியர் 5:13). ஒரு நாணயத்தின் இரு பக்கங்களைப் போலவே, கிறிஸ்தவ சத்தியத்தின் இந்த இரண்டு அம்சங்களும் எப்போதும் ஒன்றுக்கொன்று நிகராக துல்லியமாக இருக்க வேண்டும்.</p><p><b>இணைப்புகள்:</b></p><p>கலாத்தியருக்கு பவுல் எழுதிய இந்த நிருபம் முழுவதும், கிருபையால் இரட்சிக்கப்டுதல் – அது தேவனுடைய ஈவு – அது இரட்சிக்க இயலாத மோசேயின் நியாயப்பிரமாணத்திற்கு எதிராக இணைக்கப்பட்டுள்ளது. நீதிமானாக்கப்படுத்துதலுக்கான ஆதாரமாக மோசேயின் நியாயப்பிரமாணத்திற்கு திரும்பும் யூதர்கள், ஆரம்பகால திருச்சபையில் முக்கியத்துவம் வாய்ந்தவர்கள், பேதுரு போன்ற ஒரு முக்கிய கிறிஸ்தவரை தற்காலிகமாக தங்கள் வஞ்சக வலையில் இவர்கள் இழுக்கிறார்கள் (கலாத்தியர் 2:11-13). கிருபையினாலே உண்டாகும் இரட்சிப்புக்கும் நியாயப்பிரமாணத்தைக் கடைப்பிடிப்பதற்கும் எந்த விதமான சம்பந்தமும் இல்லை என்ற உண்மையை பவுல் தொடர்ந்து மீண்டும் மீண்டும் வலியுறுத்த வேண்டிய அளவிற்கு ஆரம்பகால கிறிஸ்தவர்கள் நியாயப்பிரமாணத்துடன் இணைந்திருந்தனர். நியாயப்பிரமாணத்தைச் சுற்றியுள்ள பழைய ஏற்பாட்டு மையத்துடன் கலாத்தியர் நிருபத்தை இணைக்கும் கருப்பொருள்கள்: கிருபை vs நியாயப்பிரமாணம்: நீதிமானாக்கமுடியாத நியாயப்பிரமாணம் (2:16); விசுவாசி நியாயப்பிரமாணத்திற்கு மரித்தவராக இருக்கிறார் (2:19); விசுவாசத்தால் ஆபிரகாம் நீதிமானாக்கப்படுகிறார் (3:6); நியாயப்பிரமாணம் இரட்சிப்பைக் கொண்டுவருவதில்லை, ஆனால் தேவனுடைய கோபத்தை அது கொண்டுவருகிறதாய் இருந்தது (3:10); அன்பு, கிரியை அல்ல, நியாயப்பிரமாணத்தை நிறைவேற்றுகிறது (5:14).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>கலாத்தியர் புத்தகத்தின் முக்கிய கருப்பொருளில் ஒன்று 3:11-ல் காணப்படுகிறது: \"விசுவாசத்தினாலே நீதிமான் பிழைப்பான்.\" விசுவாசத்தினால் நாம் இரட்சிக்கப்படுவது மட்டுமல்ல (யோவான் 3:16; எபேசியர் 2:8-9), ஆனால் கிறிஸ்துவை விசுவாசிப்பவரின் வாழ்க்கை - நாளுக்கு நாள், ஒவ்வொரு கணமும் - அந்த விசுவாசத்தினாலும் அதன் மூலமும் வாழ்கிறது. விசுவாசம் என்பது நாம் சொந்தமாகக் கற்பனை செய்யும் ஒன்று அல்ல – அது தேவனுடைய ஈவாக இருக்கிறது, கிரியைகளால் அல்ல - ஆனால் (1) நம்முடைய விசுவாசத்தை வெளிப்படுத்துவது நம்முடைய பொறுப்பும் மகிழ்ச்சியும் ஆகும், இதனால் மற்றவர்கள் கிறிஸ்துவின் வேலையை நம்மில் காண்பார்கள், (2) ஆவிக்குரிய நடைமுறை செயல்பாடுகளைக் (அதாவது வேத வாசிப்பு, ஜெபம், கீழ்ப்படிதல்) கையாண்டு அதன் மூலம் நம் நம்பிக்கையை மென்மேலும் அதிகரிக்கும்படிச் செய்யலாம்.</p><p>நம்முடைய வாழ்க்கையின் கனிகளால் நாம் அறியப்படுவோம் என்று இயேசு சொன்னார் (மத்தேயு 7:16), இது நமக்குள் இருக்கும் நம்பிக்கையின் சான்றுகளைத் தருகிறது. எல்லா கிறிஸ்தவர்களும் தங்களுக்குள் இருக்கும் இரட்சிப்பின் நம்பிக்கையை கட்டியெழுப்ப முயற்சிப்பதில் முனைப்புடன் இருக்க வேண்டும், இதனால் கிறிஸ்துவை மற்றவர்களுக்கு முன்பாக பிரதிபலிக்கும் நம் வாழ்க்கை அவர்கள் நம்மில் காணும்படிச் செய்யும், மேலும் அது \"பரலோகத்திலிருக்கிற உங்கள் பிதாவை மகிமைப்படுத்தும்\" (மத்தேயு 5:16).</p><p>சுமார் கி.பி. 45-47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 49 - கலாத்திய நிருபம் எழுதப் படல்? (சிலர் விளக்கம்)</p><p>சுமார் கி.பி. 50 - எருசலேம் கவுன்சில்</p><p>சுமார் கி.பி. 51-54 - பவுலின் இரண்டாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 54-58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி 55 - கலாத்திய நிருபம் எழுதப்படல்? (வேறு சிலர் விளக்கம்)</p><p>சுமார் கி.பி. 58 - பவுல் எருசலேமில் சிறையாதல்</p><p>சுமார் கி.பி. 61-62 - பவுல் ரோமச் சிறையில்</p><p>சுமார் கி.பி. 67 -  பவுல் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 48-வது நூல்</p><p>அதிகாரங்கள் - 6</p><p>வசனங்கள் - 149</p><p>வரலாற்று வசனங்கள் - 144</p><p>நிறை வேறாத தீர்க்கதரிசனங்கள் - 4</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள்</p><p>கேள்விகள் - 19</p>'),
 (560,'<p><b>எபேசியருக்கு எழுதின நிருபம்</b></p><p><b>எழுத்தாளர்:</b></p><p>எபேசியர் 1:1-வது வசனம், எபேசியருக்கு எழுதின நிருபத்தின் எழுத்தாளரை அப்போஸ்தலனாகிய பவுல் என்று அடையாளம் காட்டுகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>எபேசியருக்கு எழுதின நிருபம் கி.பி. 60-63 வரையிலுள்ள காலக்கட்டத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>கிறிஸ்துவைப் போலாகும் முதிர்ச்சிக்காக ஏங்கும் அனைவருக்கும்ம் இந்த நிருபத்தின் எழுத்துக்கள் ஏற்றதாக இருக்கும் என்று பவுல் சித்தங்கொண்டார். தேவனுடைய உண்மையான பிள்ளைகளாக வளரத் தேவையான ஒழுக்கம் எபேசியர் புத்தகத்தில் இணைக்கப்பட்டுள்ளது. மேலும், எபேசியர் புத்தகத்தின் படிப்பும் ஆய்வும் விசுவாசியை பலப்படுத்துவதற்கும் நிலைநிறுத்துவதற்கும் உதவும், இதனால் தேவன் அழைத்து நமக்களித்த அவர் நோக்கத்தை நிறைவேற்றமுடியும். இந்த நிருபத்தின் நோக்கம் ஒரு முதிர்ச்சியடைந்த திருச்சபையை உறுதிப்படுத்துவதும் கட்டியெழுப்புவதும் ஆகும். இது கிறிஸ்துவின் சரீரத்தைப் பற்றிய ஒரு சீரான பார்வையையும் தேவனுடைய பொருளாதாரத்தில் அதன் முக்கியத்துவத்தையும் முன்வைக்கிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>எபேசியர் 1:3, \"நம்முடைய கர்த்தராகிய இயேசுகிறிஸ்துவின் பிதாவாகிய தேவனுக்கு ஸ்தோத்திரம்; அவர் கிறிஸ்துவுக்குள் உன்னதங்களிலே ஆவிக்குரிய சகல ஆசீர்வாதத்தினாலும் நம்மை ஆசீர்வதித்திருக்கிறார்.\"</p><p>எபேசியர் 2:8-10, \"கிருபையினாலே விசுவாசத்தைக்கொண்டு இரட்சிக்கப்பட்டீர்கள்; இது உங்களால் உண்டானதல்ல, இது தேவனுடைய ஈவு; ஒருவரும் பெருமைபாராட்டாதபடிக்கு இது கிரியைகளினால் உண்டானதல்ல; ஏனெனில், நற்கிரியைகளைச் செய்கிறதற்கு நாம் கிறிஸ்து இயேசுவுக்குள் சிருஷ்டிக்கப்பட்டு, தேவனுடைய செய்கையாயிருக்கிறோம்; அவைகளில் நாம் நடக்கும்படி அவர் முன்னதாக அவைகளை ஆயத்தம்பண்ணியிருக்கிறார்.\"</p><p>எபேசியர் 4:4-6, \"உங்களுக்கு உண்டான அழைப்பினாலே நீங்கள் ஒரே நம்பிக்கைக்கு அழைக்கப்பட்டதுபோல, ஒரே சரீரமும் ஒரே ஆவியும் உண்டு; ஒரே கர்த்தரும், ஒரே விசுவாசமும், ஒரே ஞானஸ்நானமும், எல்லாருக்கும் ஒரே தேவனும் பிதாவும் உண்டு; அவர் எல்லார்மேலும், எல்லாரோடும், உங்கள் எல்லாருக்குள்ளும் இருக்கிறவர்.\"</p><p>எபேசியர் 5:21, \"தெய்வ பயத்தோடே ஒருவருக்கொருவர் கீழ்ப்படிந்திருங்கள்.\"</p><p>எபேசியர் 6:10-11, \"கடைசியாக, என் சகோதரரே, கர்த்தரிலும் அவருடைய சத்துவத்தின் வல்லமையிலும் பலப்படுங்கள். நீங்கள் பிசாசின் தந்திரங்களோடு எதிர்த்துநிற்கத் திராணியுள்ளவர்களாகும்படி, தேவனுடைய சர்வாயுதவர்க்கத்தையும் தரித்துக்கொள்ளுங்கள்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>எபேசியர் புத்தகத்தின் மிகப் பெரிய பகுதியை போதனைக்கோட்பாடு ஆக்கிரமித்துள்ளது. இந்த நிருபத்திலுள்ள போதனைகளில் பாதி கிறிஸ்துவில் நாம் நிற்பது தொடர்பானதாகும், மீதமுள்ளவை நம் நிலையை பாதிக்கிறதாய் இருக்கிறது. பெரும்பாலும் இந்த புத்தகத்திலிருந்து கற்பிப்பவர்கள் அனைத்து அடித்தள வழிமுறைகளையும் கடந்து நேரடியாக இறுதி அதிகாரத்திற்கு செல்கிறார்கள். இந்த அதிகாரம்தான் ஆவிக்குரிய யுத்தம் அல்லது பரிசுத்தவான்களின் ஆவிக்குரிய போராட்டத்தை வலியுறுத்துகிறது. எவ்வாறாயினும், இந்த நிருபத்தின் உள்ளடக்கங்களிலிருந்து முழுமையாக பயனடைய, இந்த நிருபத்தில் பவுலின் அறிவுறுத்தலின் ஆரம்பத்தில் இருந்து ஒருவர் தொடங்க வேண்டும்.</p><p>முதலாவதாக, கிறிஸ்துவின் சீஷர்களாகிய நம்மை, தேவன் யார் என்று அறிவிக்கிறார் என்பதை நாம் முழுமையாக புரிந்து கொள்ள வேண்டும். எல்லா மனிதர்களுக்குமான தேவனுடைய சாதனையைப் பற்றிய அறிவில் நாம் அடித்தளம் கொண்டவர்களாக இருக்க வேண்டும். அடுத்து, நம்முடைய தற்போதைய இருப்பு மற்றும் நடை ஆகியவை நடைமுறைப் படுத்தப்பட்டு அது பலப்படுத்தப்பட வேண்டும். புருஷர்களின் கற்பித்தல் மற்றும் நுணுக்கத்தின் ஒவ்வொரு ஆவியுடனும் நாம் இனிமேல் பின்மாறவோ அல்லது தடுமாறவோ கூடாது.</p><p>பவுலின் எழுத்துக்கள் மூன்று முக்கிய பகுதிகளாக பிரிந்து காணப்படுகிறது. (1) முதல் மூன்று அதிகாரங்கள் தேவனுடைய சாதனை தொடர்பான கொள்கைகளை அறிமுகப்படுத்துகின்றன. (2) நான்கு மற்றும் ஐந்தாவது அதிகாரங்கள் நமது தற்போதைய இருப்பைப் பற்றிய கொள்கைகளை முன்வைக்கின்றன. இறுதியாக (3) ஆறாம் அதிகாரம் நமது அன்றாட கிறிஸ்தவ வாழ்க்கையிலுள்ள ஆவிக்குரியப் போராட்டத்தைப் பற்றிய கொள்கைகளை முன்வைக்கிறது.</p><p><b>இணைப்புகள்:</b></p><p>எபேசியரில் உள்ள பழைய ஏற்பாட்டின் முதன்மையான இணைப்பு திருச்சபையானது கிறிஸ்துவின் சரீரம் என்ற திடுக்கிடும் (யூதர்களுக்கு) கருத்தில் உள்ளது (எபேசியர் 5:32). திருச்சபையின் இந்த அற்புதமான மர்மம் (முன்னர் வெளிப்படுத்தப்படாத ஒரு உண்மை) என்னவென்றால், \"புறஜாதிகள் சுவிசேஷத்தினாலே உடன் சுதந்தரருமாய், ஒரே சரீரத்திற்குள்ளானவர்களுமாய், கிறிஸ்துவுக்குள் அவர் பண்ணின வாக்குத்தத்தத்துக்கு உடன்பங்காளிகளுமாயிருக்கிறார்களென்பதாகும்\" (எபேசியர் 3:3). இது பழைய ஏற்பாட்டு பரிசுத்தவான்களிடமிருந்து முற்றிலும் மறைக்கப்பட்ட ஒரு இரகசியமாகும்/மர்மமாகும் (எபேசியர் 3:6, 9). தேவனை மெய்யாகப் பின்பற்றுபவர்களாக இருந்த இஸ்ரவேலர்கள் தாங்கள் மட்டுமே தேவனால் தேர்ந்தெடுக்கப்பட்ட ஜனம் என்று எப்போதும் நம்பினர் (உபாகமம் 7:6). புறஜாதியாரை சமமான நிலையில் யூதர்களுக்கு நிகராக ஏற்றுக்கொள்வது மிகவும் கடினம், இந்த புதிய முன்னுதாரணத்தில் யூத விசுவாசிகள் மற்றும் புறஜாதிய விசுவாசிகளுக்கிடையே பல மோதல்களை ஏற்படுத்தியது. திருச்சபையின் மர்மத்தை \"கிறிஸ்துவின் மணவாட்டி\" என்றும் பவுல் கூறுகிறார், இது பழைய ஏற்பாட்டில் முன்னர் கேள்விப்படாத ஒரு கருத்தாகும்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>வேதாகமத்திலுள்ள வேறு எந்த புத்தகத்தையும் விட, எபேசியர் புத்தகம் கிறிஸ்தவ வாழ்க்கையில் ஆரோக்கியமான உபதேச கோட்பாட்டிற்கும் சரியான நடைமுறை வாழ்க்கைக்கும் இடையிலான தொடர்பை பலமாக வலியுறுத்துகிறது. பலர் \"இறையியலை\" புறக்கணிக்கிறார்கள், அதற்கு பதிலாக \"நடைமுறை\" விஷயங்களை மட்டுமே விவாதிக்க விரும்புகிறார்கள். எபேசியரில், இறையியல் நடைமுறை என்று பவுல் வாதிடுகிறார். நம் வாழ்வில் தேவனுடைய சித்தத்தை நடைமுறையில் வாழ்வதற்கு, நாம் முதலில் கிறிஸ்துவில் யார் என்னும் உபதேசக்கோட்பாட்டு ரீதியாக புரிந்து கொள்ள வேண்டும்.</p><p>சுமார் கி.பி. 45-47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 50 - எருசலேம் கவுன்சில்</p><p>சுமார் கி.பி.51-54 - பவுலின் இரண்டாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 54 - 58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 58 - பவுல் எருசலேமில் சிறையாதல்</p><p>சுமார் கி.பி.61-62 -  பவுல் ரோமச் சிறையில் எபேசியர் நிருபம் எழுதப்படல்</p><p>சுமார் கி.பி. 63 – 64 - பவுல் விடுதலை பெற்று மீண்டும் பல</p><p>இடங்களைச் சந்தித்ததாகக் கருதப்படல்</p><p>சுமார் கி.பி. 66-67 - பவுல் மீண்டும் சிறையாதலும் இரத்த சாட்சியாதலும்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 49-வது நூல்</p><p>அதிகாரங்கள் - 6</p><p>வசனங்கள் - 155</p><p>கேள்வி - 1</p><p>வரலாற்று வசனங்கள் - 146</p><p>நிறைவேறிய தீர்க்கதரிசனம் -</p><p>திறைவேறாத தீர்க்கதரிசனங்கள் - 8</p>'),
 (570,'<p><b>பிலிப்பியருக்கு எழுதின நிருபம்</b></p><p><b>எழுத்தாளர்:</b></p><p>பிலிப்பியர் 1:1-வது வசனம், பிலிப்பியருக்கு எழுதின நிருபத்தின் எழுத்தாளரை அப்போஸ்தலனாகிய பவுல் என்று அடையாளம் காட்டுகிறது, மேலும் பவுல் இந்த நிருபத்தை தீமோத்தேயுவின் உதவியுடன் எழுதியிருக்கலாம்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>பிலிப்பியர் புத்தகம் ஏறக்குறைய கி.பி. 61-ல் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>பவுலின் சிறையிருப்பின் காலத்தில் எழுதப்பட்ட நிருபங்களில் ஒன்றான பிலிப்பியர் எழுதிய நிருபம் ரோமாபுரியிலிருந்து எழுதப்பட்டதாகும். பிலிப்பு பட்டணத்திற்கு அப்போஸ்தலனாகிய பவுல் தனது இரண்டாவது மிஷனரி பயணத்தில் (அப்போஸ்தலர் 16:12) விஜயம் செய்தார், லீதியாள் என்னும் பேருள்ள ஒரு ஸ்திரீ மற்றும் சிறை அதிகாரியும் அவரது குடும்பத்தினரும் கிறிஸ்துவுக்குள் மாற்றப்பட்டனர். இப்போது, சில ஆண்டுகளுக்குப் பிறகு, திருச்சபை அங்கு நிறுவப்பட்டது என்பது, இந்த நிருபத்தின் ஆரம்ப வரிகளில் பவுல், \"பிலிப்பி பட்டணத்தில் கிறிஸ்து இயேசுவுக்குள்ளான பரிசுத்தவான்கள் அனைவருக்கும், கண்காணிகளுக்கும், உதவிக்காரருக்கும் எழுதுகிறதாவது\" (பிலிப்பியர் 1:1) என்பதிலிருந்து தெளிவாக விளங்குகிறது.</p><p>இந்த நிருபத்தின் சூழ்நிலை சந்தர்ப்பம், பிலிப்பியில் உள்ள திருச்சபையிலிருந்து ஒரு காணிக்கைப் பரிசை ஏற்றுக்கொள்வதாகும், அதன் சபை உறுப்பினர்களில் ஒருவரான எப்பாப்பிரோதீத்துவின் கையில் கொடுத்தனுப்பப்பட்டது (பிலி 4:10-18). இது பவுலின் இருதயத்திற்கு குறிப்பாக நெருக்கமாக இருந்த ஒரு கிறிஸ்தவர்களுக்கு எழுதப்பட்ட நிருபமாகும் (2 கொரிந்தியர் 8:1-6), மற்றும் ஒப்பீட்டளவில் உபதேச கோட்பாட்டு பிழையைப் பற்றி மிகவும் குறைவாகவே இந்த நிருபத்தில் கூறப்பட்டுள்ளது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>பிலிப்பியர் 1:21, \"கிறிஸ்து எனக்கு ஜீவன், சாவு எனக்கு ஆதாயம்.\"</p><p>பிலிப்பியர் 3:7, \"ஆகிலும், எனக்கு லாபமாயிருந்தவைகளெவைகளோ அவைகளைக் கிறிஸ்துவுக்கு நஷ்டமென்று எண்ணினேன்.\"</p><p>பிலிப்பியர் 4:4, \"கர்த்தருக்குள் எப்பொழுதும் சந்தோஷமாயிருங்கள்; சந்தோஷமாயிருங்கள் என்று மறுபடியும் சொல்லுகிறேன்.\"</p><p>பிலிப்பியர் 4:6-7, \"நீங்கள் ஒன்றுக்குங் கவலைப்படாமல், எல்லாவற்றையுங்குறித்து உங்கள் விண்ணப்பங்களை ஸ்தோத்திரத்தோடே கூடிய ஜெபத்தினாலும் வேண்டுதலினாலும் தேவனுக்குத் தெரியப்படுத்துங்கள். அப்பொழுது, எல்லாப் புத்திக்கும்மேலான தேவசமாதானம் உங்கள் இருதயங்களையும் உங்கள் சிந்தைகளையும் கிறிஸ்து இயேசுவுக்குள்ளாகக் காத்துக்கொள்ளும்.\"</p><p>பிலிப்பியர் 4:13, \"என்னைப் பெலப்படுத்துகிற கிறிஸ்துவினாலே எல்லாவற்றையுஞ்செய்ய எனக்குப் பெலனுண்டு.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>பிலிப்பியர் நிருபம் \"துன்பத்தின் மூலம் வளங்கள்\" என்று அழைக்கப்படலாம். இந்த புத்தகம் நம் வாழ்க்கையில் கிறிஸ்துவைப் பற்றியும், நம் மனதில் கிறிஸ்துவைப் பற்றியும், கிறிஸ்து நம் இலக்காகவும், கிறிஸ்து நம்முடைய பலமாகவும், மற்றும் பாடுகளின் துன்பத்தின் மூலம் மகிழ்ச்சியாகவும் இருக்கிறது. இது ரோமாபுரியில் பவுலின் சிறைவாசத்தின் போது எழுதப்பட்டது, கிறிஸ்துவின் பரமேறுதலுக்கு சுமார் முப்பது ஆண்டுகளுக்குப் பிறகு, அல்லது பிலிப்பியில் பவுல் முதன்முதலில் பிரசங்கித்த பத்து ஆண்டுகளுக்குப் பிறகு எழுதப்பட்டதாகும்.</p><p>பவுல் ரோமச் சக்கிரவர்த்தி நீரோவின் கைதியாக இருந்தார், ஆனால் இந்த நிருபம் சந்தோஷமாயிருங்கள் சந்தோஷமாயிருங்கள் என்று மறுபடியும் சொல்லி வெற்றியுடன் பறைச்சாட்டுகிறது (பிலிப்பியர் 1:4, 18, 25, 26; 2:2, 28; பிலிப்பியர் 3:1, 4:1 , 4, 10). சரியான கிறிஸ்தவ அனுபவம் என்பது நம் சூழ்நிலைகள் எதுவாக இருந்தாலும், நம்மில் வாழும் கிறிஸ்துவின் ஜீவன், சுபாவம் மற்றும் மனம் ஆகியவற்றின் செயல்பாடாகும் (பிலிப்பியர் 1:6, 11; 2:5, 13). நம்முடைய கர்த்தராகிய இயேசு கிறிஸ்துவில் தாழ்மைப்படுத்தப்பட்ட அவமானப்படுத்துவதும் பின்பு மேலாக உயர்த்துவதும் பற்றிய மகிமையான மற்றும் ஆழமான அறிவிப்புடன் பிலிப்பியர் 2:5-11 வரையிலுள்ள வேதப்பாகம் உச்சத்தை அடைகிறது.</p><p><b>பிலிப்பியர் நிருபத்தைப் பின்வருமாறு பிரிக்கலாம்:</b></p><p><b>முன்னுரை, 1:1-7</b></p><p>I. கிறிஸ்தவனின் ஜீவனாகிய கிறிஸ்து: துன்பத்தின் மத்தியிலும் மகிழ்ச்சி, 1:8-30</p><p>II. கிறிஸ்தவனின் முறையாகிய கிறிஸ்து: தாழ்ந்த சேவையில் மகிழ்ச்சி, 2:1-30</p><p>III. கிறிஸ்தவனின் விசுவாசம், விருப்பம் மற்றும் எதிர்பார்ப்பின் பொருளாகிய கிறிஸ்து, 3:1-21</p><p>IV. கிறிஸ்தவனின் பெலனாகிய கிறிஸ்து: கவலையின் மூலம் மகிழ்ச்சி, 4:1-9</p><p>முடிவுரை, 4: 10-23</p><p><b>இணைப்புகள்:</b></p><p>பவுல் தனது பல நிருபங்களைப் போலவே, பிலிப்பி பட்டணத்து திருச்சபையில் புதிய விசுவாசிகளை ஆரம்பகால திருச்சபைகளில் தொடர்ந்து வளர்த்துக் கொண்ட பழக்கவழக்கமான போக்கைப் பற்றி எச்சரிக்கையாக இருக்குமாறு எச்சரித்தார். பழைய ஏற்பாட்டுச் நியாயப்பிரமாண சட்டத்துடன் பிணைக்கப்பட்ட யூதர்கள், யூதர்கள் கிரியைகளின் மூலம் இரட்சிப்பு என்னும் போதனைக்குத் திரும்புவதற்கான ஒரு நிலையான முயற்சி இருந்தது. ஆனால், இரட்சிப்பு என்பது கிறிஸ்துவை விசுவாசிப்பதினால் மட்டுமே என்றும் விசுவாசிப்பதால் மட்டுமே இரட்சிப்பு உண்டாகிறது என்று பவுல் மீண்டும் வலியுறுத்தினார், யூதர்களை \"நாய்கள்\" மற்றும் \"தீமை செய்யும் மனிதர்கள்\" என்று முத்திரை குத்தினார். குறிப்பாக, கிறிஸ்துவில் இரட்சிக்கப்பட்டு வந்த புதிய விசுவாசிகள் தேவைகளுக்கு ஏற்ப விருத்தசேதனம் செய்யப்பட வேண்டும் என்று நியாயப்பிரமாண சட்டத்தை மேற்கோள்காட்டி பழைய உடன்படிக்கையின் (ஆதியாகமம் 17:10-12; லேவியராகமம் 12:3) ஆசரிப்பை யூதர்கள் வலியுறுத்தி வந்தனர். இந்த வழியில், அவர்கள் தங்கள் சொந்த முயற்சியால் தேவனைப் பிரியப்படுத்தவும், சடங்கில் பங்கேற்காத புறஜாதி கிறிஸ்தவர்களுக்கு மேலாக தங்களை உயர்த்தவும் முயன்றனர். ஆட்டுக்குட்டியானவரின் இரத்தத்தால் கழுவப்பட்டவர்கள் இனி தூய்மையான இருதயத்தின் அவசியத்தைக் குறிக்கும் சடங்கைச் செய்ய மாட்டார்கள் என்று பவுல் விளக்கினார்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>பிலிப்பியருக்கு எழுதின நிருபம் பவுலின் மிகவும் தனிப்பட்ட நிருபங்களில் ஒன்றாகும், மேலும் இது விசுவாசிகளுக்கு பல தனிப்பட்ட நடைமுறைப் பயன்பாடுகளைக் கொண்டுள்ளது. ரோமாபுரியில் சிறைவாசம் அனுபவித்தபோது எழுதப்பட்ட பிலிப்பியர் நிருபம், பவுல் தனது முன்மாதிரியைப் பின்பற்றும்படி அறிவுறுத்துகிறார், துன்புறுத்தலின் போது அல்லது பாடுகளின் மத்தியில் \"கர்த்தருக்குள் திடன்கொண்டு பயமில்லாமல் திருவசனத்தைச் சொல்லும்படி அதிகமாய்த் துணிவு கொள்ளவேண்டும்\" (பிலிப்பியர் 1:14). கிறிஸ்தவர்கள் அனைவரும் கிறிஸ்துவின் நற்செய்திக்கு எதிரான அவிசுவாசிகளின் விரோதத்தை ஒரு காலத்தில் அல்லது இன்னொரு காலத்தில் அனுபவித்திருக்கிறார்கள். ஆகவே இதை நாம் எதிர்பார்க்க வேண்டும். உலகம் அவரை வெறுத்தது மெய்யானால், அது அவருடைய சீஷர்களையும் வெறுக்கும் என்று இயேசு கூறினார் (யோவான் 15:18). துன்புறுத்தல்களை எதிர்கொள்வதில் விடாமுயற்சியுடன் இருக்கவும், \"ஒரே ஆவியிலே உறுதியாய் நின்று, ஒரே ஆத்துமாவினாலே சுவிசேஷத்தின் விசுவாசத்திற்காகக் கூடப்போராடி, எதிர்க்கிறவர்களால் ஒன்றிலும் மருளாதிருக்கவும்\" வேண்டும் என்று பவுல் நமக்கு அறிவுறுத்துகிறார் (பிலிப்பியர் 1:27).</p><p>பிலிப்பியர் நிருபத்தின் மற்றொரு பயன்பாடு, கிறிஸ்தவர்கள் மனத்தாழ்மையுடன் ஒன்றுபட வேண்டும் என்பதாகும். நாம் கிறிஸ்துவோடு ஐக்கியமாக இருக்கிறோம், அதே வழியில் ஒருவருக்கொருவர் சக விசுவாசிகளுடன் ஐக்கியமாக இருக்க நாம் முயற்சி செய்ய வேண்டும். பவுல் நமக்கு \" நீங்கள் ஏக சிந்தையும் ஏக அன்புமுள்ளவர்களாயிருந்து, இசைந்த ஆத்துமாக்களாய் ஒன்றையே சிந்தித்து, என் சந்தோஷத்தை நிறைவாக்குங்கள் என்றும் ஒன்றையும் வாதினாலாவது வீண்பெருமையினாலாவது செய்யாமல், மனத்தாழ்மையினாலே ஒருவரையொருவர் தங்களிலும் மேன்மையானவர்களாக எண்ணக்கடவீர்கள் என்றும் அவனவன் தனக்கானவைகளையல்ல, பிறருக்கானவைகளையும் நோக்குவானாக\" (பிலிப்பியர் 2:2-4) என்று அறிவுறுத்துகிறார். பவுலின் ஆலோசனையை நாம் அனைவரும் மனதில் கொண்டால் இன்று திருச்சபைகளில் மிகக் குறைவான மோதல்களே இருக்கும்.</p><p>பிலிப்பியர் நிருபத்தில் காணப்படும் மற்றொரு பயன்பாடு, அவருடைய நிருபம் முழுவதும் காணப்படும் மகிழ்ச்சியையும் சந்தோஷமுமாகும். எப்படியோ கிறிஸ்து அறிவிக்கப்படுகிறார் என்று பவுல் மகிழ்ச்சியடைகிறார் (பிலிப்பியர் 1:8); அவர் தனது துன்புறுத்தலில் மகிழ்ச்சியடைகிறார் (2:18); கர்த்தரிடத்தில் சந்தோஷப்படும்படி அவர் மற்றவர்களுக்கும் அறிவுறுத்துகிறார் (3:1); அவர் பிலிப்பி சபை சகோதரர்களை தனது \"மகிழ்ச்சி மற்றும் கிரீடம்\" என்று குறிப்பிடுகிறார் (4:1). விசுவாசிகளுக்கு இந்த அறிவுரையை அவர் சுருக்கமாகக் கூறுகிறார்: \"கர்த்தருக்குள் எப்பொழுதும் சந்தோஷமாயிருங்கள்; சந்தோஷமாயிருங்கள் என்று மறுபடியும் சொல்லுகிறேன்\" (4:4-7). விசுவாசிகளாகிய, நம்முடைய எல்லா கவலைகளையும் அவர்மீது வைப்பதன் மூலம் நாம் மகிழ்ச்சியடைந்து, தேவனுடைய சமாதானத்தை அனுபவிக்க முடியும், \"நீங்கள் ஒன்றுக்குங் கவலைப்படாமல், எல்லாவற்றையுங்குறித்து உங்கள் விண்ணப்பங்களை ஸ்தோத்திரத்தோடே கூடிய ஜெபத்தினாலும் வேண்டுதலினாலும் தேவனுக்குத் தெரியப்படுத்துங்கள்\" (4:6). பவுலின் சந்தோஷமானது, அவருக்கு துன்பம் மற்றும் சிறைவாசம் இருந்தபோதிலும், இந்த நிருபத்தின் மூலம் பிரகாசிக்கிறது, மேலும் நம்முடைய எண்ணங்களை தேவன் மீது மையப்படுத்தும்போது பவுல் அனுபவித்த அதே சந்தோஷம் நமக்கும் உண்டாயிருக்கும் என்று வாக்குறுதி அளிக்கப்படுகிறது (பிலிப்பியர் 4:8).</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 50-வது நூல்</p><p>அதிகாரங்கள் - 4</p><p>வசனங்கள் - 104</p><p>கேள்வி - 1</p><p>வரலாற்று வசனங்கள் - 96</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 5</p>'),
 (580,'<p><b>கொலோசெயருக்கு எழுதின நிருபம்</b></p><p><b>எழுத்தாளர்:</b></p><p>அப்போஸ்தலனாகிய பவுல் கொலோசெயருக்கு எழுதின நிருபத்தின் முதன்மையான எழுத்தாளர் ஆவார் (கொலோசெயர் 1:1). தீமோத்தேயுவுக்கும் சிறிது பங்கும் நன்மதிப்பும் வழங்கப்படுகிறது (கொலோசெயர் 1:1, \"தேவனுடைய சித்தத்தினாலே இயேசுகிறிஸ்துவின் அப்போஸ்தலனாகிய பவுலும், சகோதரனாகிய தீமோத்தேயும், கொலோசெ பட்டணத்தில் கிறிஸ்துவுக்குள் பரிசுத்தவான்களும் விசுவாசிகளுமாயிருக்கிற சகோதரர்களுக்கு எழுதுகிறதாவது\").</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>கொலோசெயர் புத்தகம் கி.பி. 58-62 வரையிலுள்ள காலத்தின் இடைப்பட்ட காலத்தில் எழுதப்பட்டிருக்கலாம்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>கொலோசெயர் புத்தகம் ஒரு சிறு நன்நெறிமுறை பாடமாகும், இது நமது கிறிஸ்தவ வாழ்க்கையின் ஒவ்வொரு பகுதியையும் குறிக்கிறது. பவுல் தனிப்பட்ட வாழ்க்கையிலிருந்து வீடு மற்றும் குடும்பம் வரை, வேலையிலிருந்து மற்றவர்களோடு நாம் நடந்துகொள்ள வேண்டிய விதத்தில் முன்னேறுகிறார். நம்முடைய வாழ்வின் ஒவ்வொரு பகுதியிலும் நம்முடைய தேவைகளைப் பூர்த்தி செய்வதில் நம்முடைய கர்த்தராகிய இயேசு கிறிஸ்து போதுமானவராக இருக்கிறார் என்பதுதான் இந்த புத்தகத்தின் கருப்பொருள் ஆகும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>கொலோசெயர் 1:15-16, \"அவர் அதரிசனமான தேவனுடைய தற்சுரூபமும், சர்வ சிருஷ்டிக்கும் முந்தின பேறுமானவர். ஏனென்றால் அவருக்குள் சகலமும் சிருஷ்டிக்கப்பட்டது; பரலோகத்திலுள்ளவைகளும் பூலோகத்திலுள்ளவைகளுமாகிய காணப்படுகிறவைகளும் காணப்படாதவைகளுமான சகல வஸ்துக்களும், சிங்காசனங்களானாலும், கர்த்தத்துவங்களானாலும், துரைத்தனங்களானாலும், அதிகாரங்களானாலும், சகலமும் அவரைக்கொண்டும் அவருக்கென்றும் சிருஷ்டிக்கப்பட்டது.\"</p><p>கொலோசெயர் 2:8, \"லௌகிக ஞானத்தினாலும், மாயமான தந்திரத்தினாலும், ஒருவனும் உங்களைக் கொள்ளைகொண்டுபோகாதபடிக்கு எச்சரிக்கையாயிருங்கள்; அது மனுஷர்களின் பாரம்பரிய நியாயத்தையும் உலகவழிபாடுகளையும் பற்றினதேயேல்லாமல் கிறிஸ்துவைப் பற்றினதல்ல.\"</p><p>கொலோசெயர் 3:12-13, \"ஆகையால், நீங்கள் தேவனால் தெரிந்துகொள்ளப்பட்ட பரிசுத்தரும் பிரியருமாய், உருக்கமான இரக்கத்தையும், தயவையும், மனத்தாழ்மையையும், சாந்தத்தையும், நீடிய பொறுமையையும் தரித்துக்கொண்டு; ஒருவரையொருவர் தாங்கி, ஒருவர்பேரில் ஒருவருக்குக் குறைபாடு உண்டானால், கிறிஸ்து உங்களுக்கு மன்னித்ததுபோல, ஒருவருக்கொருவர் மன்னியுங்கள்.\"</p><p>கொலோசெயர் 4:5-6, \"திருவசனம் செல்லும்படியான வாசலை தேவன் திறந்தருளும்படி எங்களுக்காகவும் வேண்டிக்கொள்ளுங்கள். புறம்பேயிருக்கிறவர்களுக்கு முன்பாக ஞானமாய் நடந்து காலத்தைப் பிரயோஜனப்படுத்திக்கொள்ளுங்கள்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>கொலோசேயில் எழுந்த தோல்வியுற்ற மத மரபுகளுக்கு எதிரான கொள்கைக்கு கொலோசெயர் நிருபம் வெளிப்படையாக எழுதப்பட்டது, இந்த துர்உபதேச போலிக் கொள்கைகள் திருச்சபையின் இருப்புக்கு ஆபத்தை விளைவித்தது. பவுலுக்கு என்ன காரியங்கள் சொல்லப்பட்டது என்பது நமக்குத் தெரியாது என்றாலும், இந்த நிருபமானது இப்படிப்பட்ட குழுக்களுக்கும் அவர்களது கொள்கைகளுக்கும் அப்போஸ்தலனாகிய பவுலுடைய பதிலாகும்.</p><p>கிறிஸ்துவைப் பற்றிய குறைபாடுள்ள பார்வையை அல்லது கண்ணோட்டத்தை பவுல் கையாண்டார் என்பாத்து அவரின் பதிலின் அடிப்படையில் நாம் ஊகிக்க முடியும். அதாவது இயேசு கிறிஸ்துவினுடைய மெய்யான மற்றும் உண்மையான மனிதத்தன்மையையும் அவருடைய பரிபூரணமான தெய்வத்தன்மையையும் ஏற்றுக் அநேகர் கொள்ளவில்லை. விருத்தசேதனம் மற்றும் மரபுகளுக்கு \"யூதர்களின்\" முக்கியத்துவத்தை பவுல் முற்றிலுமாக மறுக்கிறார் (கொலோசெயர் 2:8-11; 3:11). கலாபேதங்களுக்கு எதிரான கொள்கையானது ஒரு யூத-ஞானவாதம் அல்லது யூத-சன்யாசத்திற்கும் கிரேக்க (ஸ்டோயிக்?) தத்துவத்திற்கும் இடையிலான கலவையாகத் தோன்றுகிறது. கிறிஸ்துவின் போதுமானவராக இருக்கும் தன்மையை சுட்டிக்காட்டுவதில் அவர் ஒரு குறிப்பிடத்தக்க பணியைச் செய்கிறார்.</p><p>கொலோசெயர் புத்தகமானது கிறிஸ்துவின் தெய்வீகம் மற்றும் தவறான தத்துவங்கள் (1: 15-2: 23) பற்றிய கோட்பாட்டு அறிவுறுத்தல்களை கொண்டுள்ளது, மேலும் கிறிஸ்தவ நன்னடத்தை உட்பட நண்பர்கள் மற்றும் சம்பாஷணை பற்றிய நடைமுறை அறிவுரைகளும் இதில் அடங்கியுள்ளன (3:1-4:18).</p><p><b>இணைப்புகள்:</b></p><p>அனைத்து ஆரம்பகால திருச்சபைகளையும் போலவே, கொலோசேயில் யூதர்கள் தொடர்மானமாக செய்துவருகிற காரியங்களின் பிரச்சினையும் பவுலுக்கு மிகுந்த கவலையாக இருந்தது. பழைய ஏற்பாட்டு நியாயப்பிரமாணச் சட்டத்தில் மூழ்கியவர்கள் கிரியைகளைப் புரிந்துகொள்வது மிகவும் கடினம் என்று கருதிய கிரியைகளைத் தவிர, கிருபையால் மட்டுமே இரட்சிப்பு என்கிற கருத்து மிகவும் தீவிரமானதாகும். இதன் விளைவாக, இந்த புதிய நம்பிக்கைக்கு நியாயப்பிரமாண சட்டத்திலிருந்து சில தேவைகளைச் சேர்க்க சட்டவாதிகளிடையே தொடர்ச்சியான இயக்கம் இருந்து வந்தது. அவைகளில் முதன்மையானது விருத்தசேதனம் செய்ய வேண்டிய தேவை யூத மதமாற்றம் செய்தவர்களிடையே இன்னும் நடைமுறையில் இருந்தது. பவுல் கொலோசெயர் 2:11-15-ல் இந்த பிழையை எதிர்கொண்டார், அதில் கிறிஸ்து வந்ததால் மாம்சத்தின் விருத்தசேதனம் இனி தேவையில்லை என்று அறிவித்தார். பழைய ஏற்பாட்டு நியாயப்பிரமாணச் சட்டத்தின் சடங்குகள் மற்றும் ஆசாரிப்புகள் இனி அவசியமில்லை (உபாகமம் 10:16, 30:6; எரேமியா 4:4, 9:26; அப்போஸ்தலர் 7:51; ரோமர் 2:29).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>பவுல் பல காரியங்களைக் குறிப்பிட்டு அந்த பகுதிகளைக் குறித்து உரையாற்றினாலும், இன்று நம்முடைய அடிப்படை பயன்பாடு, நம்முடைய இரட்சிப்புக்கும் பரிசுத்தமாக்கப்படுதலுக்கும் கிறிஸ்துவின் முழுமையான மற்றும் பரிபூரணமான போதுமானவராக இருக்கும் தன்மை நமக்குப் போதுமானதாகும். சமய மரபுகள் மற்றும் சட்டபூர்வமான செயல்பாடுகளுக்கு எதிரான கொள்கைகளால் வழிதவறாமல் இருக்க நாம் சுவிசேஷத்தை அறிந்து கொள்ள வேண்டும். கர்த்தரும் இரட்சகருமாக இருக்கும் கிறிஸ்துவின் மையத்தை குறைக்கும் எந்தவொரு விலகலுக்கும் நாம் மிகவும் எச்சரிக்கையாக இருக்க வேண்டும். வேதாகமத்தின் சமமான அதிகாரத்தில் நிற்பதாகக் கூறப்படும் புத்தகங்களைப் பயன்படுத்தி சத்தியத்துடன் தன்னை சமன் செய்ய முயற்சிக்கும் அல்லது \"இரட்சிப்பில் தெய்வீக செயல்பாடுடன் மனித முயற்சியை இணைக்கும் எந்தவொரு\" மதமும் முற்றிலுமாக தவிர்க்கப்பட வேண்டும். பிற மதங்களை கிறிஸ்தவத்துடன் இணைக்கவோ சேர்க்கவோ முடியாது மற்றும் கூடாது. தார்மீக நடத்தை பற்றிய முழுமையான தரங்களை கிறிஸ்து நமக்குத் தருகிறார். கிறிஸ்தவம் என்பது ஒரு குடும்பம், ஒரு வாழ்க்கை முறை மற்றும் ஒரு உறவாகும் - ஒரு மதம் அல்ல. கர்மங்கள், ஜோதிடம், அமானுஷ்யம் மற்றும் ஜாதகம் ஆகியவை தேவனுடைய வழிகளைக் காண்பிக்காது. கிறிஸ்து மட்டுமே அதைச் செய்கிறார். அவருடைய சித்தம் அவருடைய வார்த்தையில் வெளிப்படுகிறது, அவர் நமக்கு எழுதிய அன்பின் கடிதம் தான் அவர் விளம்பின வேதம்; நாம் அதை அறிந்து கொள்ள வேண்டும்!</p><p>சுமார் கி.பி. 45-47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 51-54 - பவுலின் இரண்டாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 54-58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி, 55 - 57 - கொலோசே சபை உருவாதல்</p><p>சுமார் கி.பி. 58 - பவுல் எருசலேமில கைதாதல்</p><p>சுமார் கி.பி.61-62 - பவுல் ரோமச் சிறையில் கொலேசே நிருபத்தை</p><p>எழுதுதல்</p><p>சுமார் கி.பி. 67 - பவுல் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 51-வது நூல்</p><p>அதிகாரங்கள் - 4</p><p>வசனங்கள் - 95</p><p>கேள்வி - 1</p><p>வரலாற்று வசனங்கள் - 92</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள்</p>'),
 (590,'<p><b>1 தெசலோனிக்கேயர் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>1 தெசலோனிக்கேயர் புத்தகத்தின் முதலாம் அதிகாரத்தின் முதல் வசனம், 1 தெசலோனிக்கேயர் புத்தகம் அப்போஸ்தலனாகிய பவுலால் எழுதப்பட்டது என்று தெளிவுபடுத்துகிறது, அநேகமாக சீலா மற்றும் தீமோத்தேயுவுடன் சேர்ந்து இந்த நிருபத்தை எழுதியிருக்கலாம்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>1 தெசலோனிக்கேயர் புத்தகம் ஏறக்குறைய கி.பி. 50-ல் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>தெசலோனிக்கேயா திருச்சபையில் கிறிஸ்துவின் வருகையைப் பற்றி சில தவறான புரிதல்கள் இருந்தன. பவுல் தனது நிருபத்தில் அவற்றை தீர்க்க விரும்பினார். அவர் அதை பரிசுத்த வாழ்வின் அறிவுறுத்தலாக எழுதுகிறார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>1 தெசலோனிக்கேயர் 3:5, \"ஆகையால், நான் இனிப் பொறுத்திருக்கக்கூடாமல், எங்கள் வேலை வீணாய்ப் போகத்தக்கதாகச் சோதனைக்காரன் உங்களைச் சோதனைக்குட்படுத்தினதுண்டோவென்று, உங்கள் விசுவாசத்தை அறியும்படிக்கு, அவனை அனுப்பினேன்.\"</p><p>1 தெசலோனிக்கேயர் 3:7, \"சகோதரரே, எங்களுக்கு நேரிட்ட எல்லா இக்கட்டிலும் உபத்திரவத்திலும் உங்கள் விசுவாசத்தினாலே உங்களை குறித்து ஆறுதலடைந்தோம்.\"</p><p>1 தெசலோனிக்கேயர் 4:14-17, \"இயேசுவானவர் மரித்து பின்பு எழுந்திருந்தாரென்று விசுவாசிக்கிறோமே; அப்படியே இயேசுவுக்குள் நித்திரையடைந்தவர்களையும் தேவன் அவரோடேகூடக் கொண்டுவருவார். கர்த்தருடைய வார்த்தையை முன்னிட்டு நாங்கள் உங்களுக்குச் சொல்லுகிறதாவது: கர்த்தருடைய வருகைமட்டும் உயிரோடிருக்கும் நாம் நித்திரையடைந்தவர்களுக்கு முந்திக்கொள்வதில்லை. ஏனெனில், கர்த்தர் தாமே ஆரவாரத்தோடும், பிரதான தூதனுடைய சத்தத்தோடும், தேவ எக்காளத்தோடும் வானத்திலிருந்து இறங்கிவருவார்; அப்பொழுது கிறிஸ்துவுக்குள் மரித்தவர்கள் முதலாவது எழுந்திருப்பார்கள். பின்பு உயிரோடிருக்கும் நாமும் கர்த்தருக்கு எதிர்கொண்டுபோக மேகங்கள்மேல், அவர்களோடேகூட ஆகாயத்தில் எடுத்துக்கொள்ளப்பட்டு, இவ்விதமாய் எப்பொழுதும் கர்த்தருடனேகூட இருப்போம்.\"</p><p>1 தெசலோனிக்கேயர் 5:16-18, \"எப்பொழுதும் சந்தோஷமாயிருங்கள். இடைவிடாமல் ஜெபம்பண்ணுங்கள். எல்லாவற்றிலேயும் ஸ்தோத்திரஞ்செய்யுங்கள்; அப்படிச் செய்வதே கிறிஸ்து இயேசுவுக்குள் உங்களைக்குறித்துத் தேவனுடைய சித்தமாயிருக்கிறது.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>முதல் மூன்று அதிகாரங்கள் தெசலோனிக்கேயாவில் உள்ள திருச்சபையை பார்வையிட பவுல் ஏங்குகின்றதை விவரிக்கின்றன, ஆனால் சாத்தான் அவர்களைத் தடுத்து நிறுத்தியதால் அது முடியாமல் போனது (1 தெசலோனிக்கேயர் 2:18), பவுல் அவர்களை எவ்வாறு கருதினார், மற்றும் அவர்கள் எப்படி இருந்தார்கள் என்பதைக் கேட்கவும் ஊக்கப்படுத்தப்பட்டார். பின்னர் பவுல் அவர்களுக்காக ஜெபிக்கிறார் (1 தெசலோனிக்கேயர் 3:11-13). 4-ஆம் அதிகாரத்தில், பவுல் தெசலோனிக்கேயாவில் உள்ள விசுவாசிகளுக்கு பரிசுத்த வாழ்க்கையை கிறிஸ்து இயேசுவில் எப்படி வாழ வேண்டும் என்று அறிவுறுத்துகிறார் (1 தெசலோனிக்கேயர் 4:1-12). பவுல் தொடர்ந்து அவர்களிடம் இருந்த தவறான கருத்தை அவர்களுக்கு அறிவுறுத்துகிறார். கிறிஸ்து இயேசுவில் மரித்த ஜனங்கள் அவர் திரும்பி மீண்டும் வானத்தின் மேகங்களில் வரும்போது பரலோகத்திற்குக் கொண்டு செல்லப்படுவார்கள் என்று பவுல் அவர்களுக்குச் சொல்லுகிறார் (1 தெசலோனிக்கேயர் 4:13-18, 5:1-11). கிறிஸ்தவ வாழ்க்கையை வாழ்வதற்கான இறுதி அறிவுறுத்தல்களுடன் இந்த புத்தகம் முடிகிறது.</p><p><b>இணைப்புகள்:</b></p><p>தெசலோனிக்கேயர்கள் தங்கள் \"சொந்த தேசத்து ஜனத்திடமிருந்து\" அவர்கள் பெற்ற துன்புறுத்தல்களையும் இன்னல்களையும் (வச. 2:15), தங்கள் மேசியாவை நிராகரித்த யூதர்கள் பழைய ஏற்பாட்டுக் காலத்தில் உண்டாயிருந்த தீர்க்கதரிசிகளுக்கு செய்ததைப் போலவே இவர்களும் துன்பப்படுகிறார்கள் என்று பவுல் நினைவுபடுத்துகிறார் (எரேமியா 2:30; மத்தேயு 23:31). தேவனுடைய உண்மையான தீர்க்கதரிசிகள் எப்போதும் அநியாயக்காரர்களால் எதிர்க்கப்படுவார்கள் என்று ஆண்டவர் இயேசு எச்சரித்தார் (லூக்கா 11:49). கொலோசெயரில், பவுல் அந்த உண்மையை அவர்களுக்கு நினைவுபடுத்துகிறார்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>இந்த புத்தகத்தை நமது வாழ்க்கை சூழ்நிலைகளின் பல நிலைகளுக்குப் பயன்படுத்தலாம். கிறிஸ்து மீண்டும் திரும்பி வரும்போது மரித்தவர்கள் அல்லது உயிருடன் இருக்கிறவர்கள் என யாவருக்கும் நம்பிக்கையை கிறிஸ்தவர்களாக இருக்கிற நமக்கு இது அளிக்கிறது (1 தெசலோனிக்கேயர் 4:13-18). தேவனுடைய கோபாக்கினையை / கோபத்தை நாம் பெறமாட்டோம் மற்றும் அது நமக்குரியது அல்ல என்று கிறிஸ்தவர்களாகிய நமக்கு இது உறுதியளிக்கிறது (1 தெசலோனிக்கேயர் 5:8-9). கிறிஸ்தவ வாழ்க்கையை தினமும் எவ்வாறு நடத்துவது என்று இது நமக்கு அறிவுறுத்துகிறது (1 தெசலோனிக்கேயர் 4-5).</p><p>சுமார் கி.பி. 45-47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 51-53 - பவுலின் இரண்டாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 52 - தெசலோனிக்கேயாவில் சபை உருவாதல்</p><p>சுமார் கி.பி. 51/52 - 1தெசலோனிக்கேயர் நிருபம் எழுதப்படல்</p><p>சுமார் கி.பி. 54-58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 58 - பவுல் எருசலேமில் சிறையாதல்</p><p>சுமார் கி.பி. 61-62 - பவுல் ரோமச் சிறையில்</p><p>சுமார் கி.பி. 67 - பவுல் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 52-வது நூல்</p><p>அதிகாரங்கள் - 5</p><p>வசனங்கள் - 89</p><p>கேள்விகள் - 3</p><p>வரலாற்று வசனங்கள் - 69</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 20</p>'),
 (60,'<p><b>யோசுவாவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>யோசுவாவின் புத்தகம் அதன் எழுத்தாளரை யார் என்று வெளிப்படையாக எதுவும் குறிப்பிடவில்லை. மோசேயின் ஸ்தானத்தில் இஸ்ரவேலின் தலைவராக இருந்த நூனின் குமாரனாகிய யோசுவா இந்த புத்தகத்தை எழுதியிருக்கலாம். புத்தகத்தின் பிற்பகுதி அதாவது யோசுவாவின் மரணம் மற்றும் மரணத்திற்குப் பிறகுள்ள பகுதி வேறொரு நபரால் எழுதப்பட்டிருக்கலாம். யோசுவாவின் மரணத்தைத் தொடர்ந்து பல பிரிவுகள் திருத்தப்பட்டன / தொகுக்கப்பட்டன.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>யோசுவாவின் புத்தகம் ஏறக்குறைய கி.மு. 1400 முதல் கி.மு. 1370 வரையிலுள்ள ஆண்டுகளுக்கு இடையில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>தேவனாகிய கர்த்தர் வாக்குறுதியளித்த தேசத்தை கைப்பற்றுவதற்கான இராணுவ தளவாடங்களையும் அவர்கள் முகாமிட்ட மற்றும் கைப்பற்றின ஸ்தலங்களையும் குறித்த ஒரு கண்ணோட்டத்தை யோசுவா புத்தகம் வழங்குகிறது. இஸ்ரவேலர்கள் எகிப்திலிருந்து புறப்பட்டதைத் தொடர்ந்து, நாற்பது ஆண்டுகாலம் வனாந்திரத்தில் அலைந்து திரிந்ததைத் தொடர்ந்து, புதிதாக உருவான தேசம் இப்போது வாக்குறுதியளிக்கப்பட்ட தேசத்திற்குள் நுழைவதற்கும், மக்களைக் கைப்பற்றுவதற்கும், பிரதேசத்தை ஆக்கிரமிப்பதற்கும் தயாராக உள்ளது. இங்கே நாம் வைத்திருக்கும் கண்ணோட்டம் பல போர்களின் சுருக்கமான மற்றும் தேர்ந்தெடுக்கப்பட்ட விவரங்களையும், நிலம் கைப்பற்றப்பட்ட விதம் மட்டுமல்லாமல், அது எவ்வாறு ஒவ்வொரு கோத்திரப் பகுதிகளாகப் பிரிக்கப்பட்டது என்பதையும் தருகிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>யோசுவா 1:6-9, \"பலங்கொண்டு திடமனதாயிரு; இந்த ஜனத்தின் பிதாக்களுக்கு நான் கொடுப்பேன் என்று ஆணையிட்ட தேசத்தை நீ இவர்களுக்குப் பங்கிடுவாய். என் தாசனாகிய மோசே உனக்குக் கற்பித்த நியாயப்பிரமாணத்தின்படியெல்லாம் செய்யக் கவனமாயிருக்கமாத்திரம் மிகவும் பலங்கொண்டு திடமனதாயிரு; நீ போகும் இடமெல்லாம் புத்திமானாய் நடந்துகொள்ளும்படிக்கு, அதை விட்டு வலது இடதுபுறம் விலகாதிருப்பாயாக. இந்த நியாயப்பிரமாண புஸ்தகம் உன் வாயைவிட்டுப் பிரியாதிருப்பதாக; இதில் எழுதியிருக்கிறவைகளின்படியெல்லாம் நீ செய்யக் கவனமாயிருக்கும்படி, இரவும் பகலும் அதைத் தியானித்துக்கொண்டிருப்பாயாக; அப்பொழுது நீ உன் வழியை வாய்க்கப்பண்ணுவாய், அப்பொழுது புத்திமானாகவும் நடந்துகொள்ளுவாய். நான் உனக்குக் கட்டளையிடவில்லையா? பலங்கொண்டு திடமனதாயிரு; திகையாதே, கலங்காதே, நீ போகும் இடமெல்லாம் உன் தேவனாகிய கர்த்தர் உன்னோடே இருக்கிறார் என்றார்.\"</p><p>யோசுவா 24:14-15, \"ஆகையால் நீங்கள் கர்த்தருக்குப் பயந்து, அவரை உத்தமமும் உண்மையுமாய்ச் சேவித்து, உங்கள் பிதாக்கள் நதிக்கு அப்புறத்திலும் எகிப்திலும் சேவித்த தேவர்களை அகற்றிவிட்டு, கர்த்தரைச் சேவியுங்கள். கர்த்தரைச் சேவிக்கிறது உங்கள் பார்வைக்கு ஆகாததாய்க் கண்டால், பின்னை யாரைச் சேவிப்பீர்கள் என்று இன்று தெரிந்து கொள்ளுங்கள்; நதிக்கு அப்புறத்தில் உங்கள் பிதாக்கள் சேவித்த தேவர்களைச் சேவிப்பீர்களோ? நீங்கள் வாசம்பண்ணுகிற தேசத்துக் குடிகளாகிய எமோரியரின் தேவர்களைச் சேவிப்பீர்களோ? நானும் என் வீட்டாருமோவென்றால், கர்த்தரையே சேவிப்போம் என்றான்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>எகிப்திலிருந்து வெளியேறிய பின்னர் உள்ள இஸ்ரவேலரின் கதையை யோசுவாவின் புத்தகம் தொடர்கிறது. உபாகமத்தின் முடிவில் மோசே யோசுவாவை ஜனங்களின் தலைவராக அபிஷேகம் செய்தபின், சுமார் 20 ஆண்டுகளை இந்த புத்தகம் விவரிக்கிறது. யோசுவா புத்தகத்தின் இருபத்தி நான்கு அதிகாரங்களின் பிரிவுகளை பின்வருமாறு சுருக்கமாகக் கூறலாம்:</p><p>அதிகாரங்கள் 1-12: வாக்குறுதியளிக்கப்பட்ட தேசத்தில் நுழைந்து வெற்றி பெறுதல்.</p><p>அதிகாரங்கள் 13-22: வாக்குறுதியளிக்கப்பட்ட தேசத்தின் பகுதிகளை விநியோகிப்பதற்கான வழிமுறைகள்.</p><p>அதிகாரங்கள் 23-24: யோசுவாவின் பிரியாவிடை முகவரி</p><p><b>முன்னிழல்கள்:</b></p><p>ராகாப் என்னும் வேசியின் கதை மற்றும் இஸ்ரவேலரின் தேவன்மீது அவள் கொண்டிருந்த மிகுந்த நம்பிக்கையானது, எபிரெயர் 11:31-ல் விசுவாச வீரர்களின் பட்டியலில் கவுரவிக்கப்பட்டவர்களுடன் அவளுக்கு ஒரு இடத்தை அளிக்கிறது. அவளுடைய கதையானது பாவிகளுக்கு தேவன் அருளும் கிருபை மற்றும் விசுவாசத்தால் மட்டுமே இரட்சிப்பு என்பதை காண்பிக்கிறது. மிக முக்கியமாக, தேவனுடைய கிருபையால் அவள் மேசியாவின் வம்ச வழியில் இருக்கும்படியாயிற்று (மத்தேயு 1:15).</p><p>யோசுவா 5-ல் கொடுக்கப்பட்டுள்ளா சம்பிரதாய சடங்குகளில் ஒன்று புதிய ஏற்பாட்டில் அதன் முழுமையான நிறைவேற்றத்தைக் காண்கிறது. 1-9 வரையிலுள்ள வசனங்கள் வனாந்தரத்தில் பிறந்தவர்கள் வாக்குப்பண்ணப்பட்ட தேசத்திற்குள் வரும்போது விருத்தசேதனம் செய்யப்பட வேண்டும் என்ற தேவனுடைய கட்டளையை விவரிக்கின்றன. அவ்வாறு செய்வதன் மூலம், தேவன் அவர்களிடமிருந்து \"எகிப்தின் நிந்தையை கடந்துபோகும்படி செய்தார்\", அதாவது அவர்களுடைய முந்தைய வாழ்க்கையின் பாவங்களிலிருந்து அவர்களைத் பரிசுத்தப்படுத்தினார். கொலோசெயர் 2:10-12ல், பவுல் விசுவாசிகளை கிறிஸ்துவே அவர்களுடைய இருதயங்களில் விருத்தசேதனம் செய்ததாக விவரிக்கிறார், கிறிஸ்து இல்லாமல் உள்ள நம்முடைய முந்தைய வாழ்க்கையின் பாவ இயல்புகளை நாம் புறம்பாக்கி களைந்துள்ளோம்.</p><p>தற்செயலாக ஒருவரைக் கொன்றவர்கள் பழிவாங்கலுக்கு அஞ்சாமல் அங்கே தங்கி வாழக் கூடிய வகையில் தேவன் அவர்களுக்கு அடைக்கல பட்டணங்களை நிறுவினார். கிறிஸ்து நம்முடைய அடைக்கலம், \"நமக்கு முன் வைக்கப்பட்ட நம்பிக்கையைப் பற்றிக்கொள்ளும்படி அடைக்கலமாய் ஓடிவந்த நமக்கு\" (எபிரெயர் 6:18) என்று வாசிக்கிறோம்.</p><p>யோசுவாவின் புத்தகம் இளைப்பாறுதல் பற்றிய ஒரு இறையியல் கருப்பொருளைக் கொண்டுள்ளது. இஸ்ரவேலர்கள், 40 ஆண்டுகளாக வனாந்தரத்தில் அலைந்து திரிந்தபின், கானான் தேசத்தில் தேவன் அவர்களுக்காகத் தயார் செய்திருந்த இளைப்பாறுதலுக்குள் நுழைந்தார்கள். எபிரேயர் புத்தகத்தின் எழுத்தாளர் இந்த சம்பவத்தை கிறிஸ்துவில் தேவனுடைய இளைப்பாறுதலுக்குள் நுழைவதைத் தடுக்கும் அவிசுவாசம் என்ற எச்சரிக்கையை கூற இந்த சம்பவத்தைப் பயன்படுத்துகிறார் (எபிரெயர் 3:7-12).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>யோசுவா புத்தகத்தின் முக்கிய வசனங்களில் ஒன்று 1:8 \"இந்த நியாயப்பிரமாண புஸ்தகம் உன் வாயைவிட்டுப் பிரியாதிருப்பதாக; இதில் எழுதியிருக்கிறவைகளின்படியெல்லாம் நீ செய்யக் கவனமாயிருக்க வேண்டும்.\" பழைய ஏற்பாட்டில் ஜனங்கள் தேவனையும் அவருடைய வார்த்தையையும் எவ்வாறு மறந்துபோனார்கள், அதினிமித்தம் என்னென்ன பயங்கரமான விளைவுகளை அனுபவித்தார்கள் என்ற கதைகள் நிறைந்திருக்கின்றன. கிறிஸ்தவர்களைப் பொறுத்தவரை, தேவனுடைய வார்த்தை நம்முடைய உயிர்நாடி. நாம் அதை புறக்கணித்தால், அதற்கேற்ப நம் வாழ்க்கை பாதிக்கப்படும். ஆனால் 1:8வது வசனத்தின் கொள்கையை நாம் மனதில் கொண்டால், நாம் தேவனுடைய ராஜ்யத்தில் பூரணர்களாகவும், பயனடையக்கூடியவர்களாகவும் இருப்போம் (2 தீமோத்தேயு 3:16-17), யோசுவா 1:8-9 ல் கொடுக்கப்பட்டுள்ள தேவனுடைய வாக்குறுதிகள் நம்முடையதாகவும் இருப்பதைக் காண்போம்.</p><p>ஒரு தகுதியான வழிகாட்டியின் நன்மைகளுக்கு யோசுவா ஒரு பிரதான எடுத்துக்காட்டு. பல ஆண்டுகளாக அவர் மோசேயுடன் நெருக்கமாக இருந்தார். மோசேயை ஏறக்குறைய குறைபாடற்ற முறையில் தேவனைப் பின்தொடர்ந்தபோது அவர் அதைப் பார்த்தார். மோசேயிடமிருந்து தனிப்பட்ட முறையில் ஜெபிக்க கற்றுக்கொண்டார். மோசேயின் முன்மாதிரி மூலம் எவ்வாறு கீழ்ப்படிய வேண்டும் என்பதை அவர் கற்றுக்கொண்டார். வாக்குப்பண்ணப்பட்ட தேசத்தின் மகிழ்ச்சிக்குள் நுழையமுடியாமல் போன மோசேயின் வாழ்க்கையில் காணும் எதிர்மறையான உதாரணத்திலிருந்து யோசுவா கற்றுக்கொண்டார். நீங்கள் உயிருடன் இருந்தால், நீங்கள் ஒரு வழிகாட்டியாக இருக்கிறீர்கள் என்று அர்த்தம். யாரோ, எங்கோ, உங்களைப் பார்த்துக் கொண்டிருக்கிறார்கள். சில இளைய நபர் அல்லது நீங்கள் செல்வாக்கு செலுத்தும் ஒருவர் நீங்கள் எப்படி வாழ்கிறீர்கள், எப்படி நடந்துகொள்கிறீர்கள் என்பதைப் பார்த்துக் கொண்டிருக்கிறார். உங்களிடமிருந்து ஒருவர் கற்றுக்கொள்கிறார். உங்கள் முன்மாதிரியை யாராவது பின்பற்றுவார்கள். வழிகாட்டியால் பேசப்படும் சொற்களை விட அவரது வழிகாட்டுதல் மிக அதிகம். அவரது முழு வாழ்க்கையும் காட்சிக்கு வைக்கப்பட்டுள்ளது.</p><p>சுமார் கி.மு. 1544 (1499) - யோசுவாவின் பிறப்பு</p><p>சுமார் கி.மு.1491 (1446) - யாத்திராகம புறப்படுதல்</p><p>சுமார் கி.மு.1490 (1445) - பத்து கட்டளைகளைப் பெறுதல்</p><p>சுமார் கி.மு.1490 (1445) - கானானை ஒற்று நோக்கல்</p><p>சுமார் கி.மு. 1452 (1407) - தலைமைத்துவ பொறுப்பை யோசுவா ஏற்றல்</p><p>சுமார் கி.மு. 1451 (1406) - இஸ்ரவேலர் கானானை அடைதல்</p><p>சுமார் கி.மு. 1444 (1382) - தூய போர்கள் முடிவு</p><p>சுமார் கி.மு.1434 (1375) - யோசுவாவின் மரணம்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - யோசுவா (கர்த்தர் இரட்சிக்கிறார்/இரட்சகர்}</p><p>பழைய பெயர் - ஓசேயா (எண் 13 : 8)</p><p>பெற்றோர் - தந்தை பெயர் நூன்</p><p>கோத்திரம் - எப்பிராயீம்</p><p>பிறந்த இடம் - எகிப்து</p><p>தொழில் - எகிப்தில் அடிமை. பின்பு மோசேயின் உத்தம சீடர். கானானை ஒற்று நோக்கிய ஒற்றரில் ஒருவராக பணியாற்றியது.</p><p>நண்பர் - காலேப்</p><p>திருப்பு முனை - மோசேயின் இறப்புடன், இஸ்ரவேலின் தலைமைத்துவத்தை ஏற்கத் தேவன் அழைத்தார்.</p><p>ஆர்வம் - ஆசரிப்புக் கூடாரத்தில் இருத்தல், இளமையிலேயே கர்த்தருக்காக வாள் சுழற்றுதல்</p><p>சாதனைகள் - இளமையிலேயே போருக்குத் தலைமை தாங்கி அமலேக்கியரை அழித்தது. கானானை இஸ்ரவேலருக்குச்</p><p>சொந்தமாக்கிப் பங்கிட்டது.</p><p>பட்டப்பெயர் - விசுவாசப் போர் தளபதி</p><p>இறப்பு - கனவு கண்ட கானாளில் 110 வது வயதில்</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 6-வது நூல்</p><p>அதிகாரங்கள் - 24</p><p>வசனங்கள் - 658</p><p>வரலாற்றுத் தொடர்பு வசனங்கள் - 624</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 42</p><p>கேள்விகள் - 21</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 14</p><p>கட்டளைகள் - 98</p><p>எச்சரிக்கைகள் - 44</p><p>வாக்குத்தத்தங்கள் - 15</p>'),
 (600,'<p><b>2 தெசலோனிக்கேயர் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>2 தெசலோனிக்கேயர் முதலாம் அதிகாரத்தின் முதலாவது வசனம், 2 தெசலோனிக்கேயர் புத்தகம் அப்போஸ்தலனாகிய பவுலால் எழுதப்பட்டது என்பதை தெளிவுபடுத்துகிறது, அநேகமாக சீலா மற்றும் தீமோத்தேயுவுடன் சேர்ந்து பவுல் இதை எழுதியிருக்கலாம்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>2 தெசலோனிக்கேயர் புத்தகம் கி.பி. 51-52-ன் காலக்கட்டத்தில் எழுதப்பட்டிருக்கலாம்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>தெசலோனிகேயாவில் உள்ள திருச்சபையில் கர்த்தருடைய நாள் குறித்து சில தவறான எண்ணங்கள் இருந்தன. இது ஏற்கனவே வந்துவிட்டதாக அவர்கள் நினைத்தார்கள், அதனால் அவர்கள் தாங்கள் செய்து வந்ததான தங்கள் வேலையை நிறுத்திவிட்டார்கள். அவர்கள் மோசமாக துன்புறுத்தப்பட்டனர். அவர்களுடைய தவறான எண்ணங்களைத் தீர்த்து, அவர்களுக்கு ஆறுதல் கூறும்படியாக பவுல் இந்த நிருபத்தை எழுதினார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>2 தெசலோனிக்கேயர் 1:6-7, \"உங்களை உபத்திரவப்படுத்துகிறவர்களுக்கு உபத்திரவத்தையும், உபத்திரவப்படுகிற உங்களுக்கு எங்களோடேகூட இளைப்பாறுதலையும் பிரதிபலனாகக்கொடுப்பது தேவனுக்கு நீதியாயிருக்கிறதே. தேவனை அறியாதவர்களுக்கும், நம்முடைய கர்த்தராகிய இயேசுகிறிஸ்துவின் சுவிசேஷத்திற்குக் கீழ்ப்படியாதவர்களுக்கும் நீதியுள்ள ஆக்கினையைச் செலுத்தும்படிக்கு.\"</p><p>2 தெசலோனிக்கேயர் 2:13, \"கர்த்தருக்குப் பிரியமான சகோதரரே, நீங்கள் ஆவியினாலே பரிசுத்தமாக்கப்படுகிறதினாலும், சத்தியத்தை விசுவாசிக்கிறதினாலும் இரட்சிப்படையும்படிக்கு, ஆதிமுதல் தேவன் உங்களைத் தெரிந்துகொண்டபடியினாலே, நாங்கள் உங்களைக்குறித்து எப்பொழுதும் தேவனை ஸ்தோத்திரிக்கக் கடனாளிகளாயிருக்கிறோம்.\"</p><p>2 தெசலோனிக்கேயர் 3:3, \"கர்த்தரோ உண்மையுள்ளவர், அவர் உங்களை ஸ்திரப்படுத்தி, தீமையினின்று விலக்கிக் காத்துக்கொள்ளுவார்.\"</p><p>2 தெசலோனிக்கேயர் 3:10, \"ஒருவன் வேலைசெய்ய மனதில்லாதிருந்தால் அவன் சாப்பிடவும் கூடாதென்று நாங்கள் உங்களிடத்தில் இருந்தபோது உங்களுக்குக் கட்டளையிட்டோமே.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>தெசலோனிகேயாவில் உள்ள திருச்சபையை பவுல் வாழ்த்தி அவர்களை ஊக்குவித்து அறிவுறுத்துகிறார். கர்த்தருக்குள்ளாக அவர்கள் செய்கிறதைக் கேட்டு அவர் அவர்களைப் பாராட்டுகிறார், அவர்களுக்காக ஜெபிக்கிறார் (2 தெசலோனிக்கேயர் 1:11-12). கர்த்தருடைய நாளில் என்ன நடக்கும் என்று பவுல் 2-ஆம் அதிகாரத்தில் தெளிவாக விளக்குகிறார் (2 தெசலோனிக்கேயர் 2:1-12). பவுல் அவர்களை உறுதியாக நிற்கவேண்டும் என்று ஊக்குவிக்கிறார், சுவிசேஷத்தின்படி வாழாமல் சோம்பேறிகளாக இருக்கும் மனிதர்களிடமிருந்து விலகி இருக்கும்படி அவர் அவர்களுக்கு அறிவுறுத்துகிறார் (2 தெசலோனிக்கேயர் 3:6).</p><p><b>இணைப்புகள்:</b></p><p>பவுல் தனது சம்பாஷணையில் பல பழைய ஏற்பாட்டு பகுதிகளை இறுதி காலங்களில் சம்பவிக்கப்போவது தொடர்புபடுத்திக் குறிப்பிடுகிறார், இதன் மூலம் பழைய ஏற்பாட்டுத் தீர்க்கதரிசிகளை உறுதிப்படுத்தி ஒப்புரவாக்குகிறார். இந்த கடிதத்தின் இறுதி காலங்களில் அவர் கற்பித்தவற்றில் பெரும்பாலானவை தீர்க்கதரிசி தானியேல் மற்றும் அவரது தரிசனங்களை அடிப்படையாகக் கொண்டவையாகும். 2 தெசலோனிக்கேயர் 2:3-9-ல், \"பாவ மனுஷன்\" (தானியேல் 7–8) பற்றிய தானியேலின் தீர்க்கதரிசனத்தை அவர் குறிப்பிடுகிறார்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>2 தெசலோனிக்கேயர் புத்தகம் கடைசிக் காலங்களில் சம்பவிக்கப்போகிறவைகளை விளக்கும் தகவல்களால் நிரப்பப்பட்டுள்ளது. செம்பெரித்தனமுள்ளவர்களாக இருக்கக்கூடாது என்றும் நம்மிடம் உள்ளவற்றில் இருப்பதற்காக வேலை செய்ய வேண்டும் என்றும் இது அறிவுறுத்துகிறது. 2 தெசலோனிக்கேயரில் சில பிரதான ஜெபங்களும் உள்ளன, அவை இன்றும் மற்ற விசுவாசிகளுக்காக எவ்வாறு ஜெபிக்க வேண்டும் என்பதற்கு ஒரு சிறந்த எடுத்துக்காட்டாகும்.</p><p>சுமார் கி.பி. 45-47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 51-53 - பவுலின் இரண்டாம். மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 52 - தெசலோனிக்கேயாவில் சபை உருவாதல்</p><p>சுமார் கி.பி. 51/52 - 1தெசலோனிக்கேயர் நிருபம் எழுதப்படல்</p><p>சுமார் கி.பி. 54-58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 58 - பவுல் எருசலேமில் சிறையாதல்</p><p>சுமார் கி.பி. 61-62 - பவுல் ரோமச் சிறையில்</p><p>சுமார் கி.பி. 67 - பவுல் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 53-வது நூல்</p><p>அதிகாரங்கள் - 3</p><p>வசனங்கள் - 47</p><p>கேள்வி - 1</p><p>வரலாற்று வசனங்கள் - 31</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் -</p>'),
 (610,'<p><b>1 தீமோத்தேயுவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>1 தீமோத்தேயு புத்தகம் அப்போஸ்தலன் பவுலால் எழுதப்பட்டது என்பது, \"இயேசுகிறிஸ்துவின் அப்போஸ்தலனாயிருக்கிற பவுல், விசுவாசத்தில் உத்தம குமாரனாகிய தீமோத்தேயுவுக்கு எழுதுகிறதாவது\" (1 தீமோத்தேயு 1:1, 2) என்னும் வார்த்தைகளில் தெளிவாகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>1 தீமோத்தேயுவின் புத்தகம் கி.பி. 62-66 வரையிலுள்ள காலக்கட்டத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>எபேசு திருச்சபையின் பணிகளையும், ஆசியா மாகாணத்தில் உள்ள பிற திருச்சபைகளை மேற்பார்வையிடும் பொறுப்பில் அவரை ஊக்குவிக்க பவுல் தீமோத்தேயுவுக்கு இந்த நிருபத்தை எழுதினார் (1 தீமோத்தேயு 1:3). இந்த நிருபம் மூப்பர்களை நியமிப்பதற்கான அடித்தளத்தை அமைக்கிறது (1 தீமோத்தேயு 3:1-7), மேலும் ஜனத்தை திருச்சபை அலுவலகங்களுக்குள் நியமிப்பதற்கான வழிகாட்டுதலை வழங்குகிறது (1 தீமோத்தேயு 3:8-13). சாராம்சத்தில், 1 தீமோத்தேயுவின் புத்தகம் திருச்சபை அமைப்பு மற்றும் நிர்வாகத்திற்கான தலைமை கையேடு ஆகும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>1 தீமோத்தேயு 2:5, தேவன் ஒருவரே, தேவனுக்கும் மனுஷருக்கும் மத்தியஸ்தரும் ஒருவரே. எல்லாரையும் மீட்கும் பொருளாகத் தம்மை ஒப்புக்கொடுத்த மனுஷனாகிய கிறிஸ்து இயேசு அவரே.\"</p><p>1 தீமோத்தேயு 2:12, \"உபதேசம்பண்ணவும், புருஷன்மேல் அதிகாரஞ்செலுத்தவும், ஸ்திரீயானவளுக்கு நான் உத்தரவு கொடுக்கிறதில்லை; அவள் அமைதலாயிருக்கவேண்டும்.\"</p><p>1 தீமோத்தேயு 3:1-3, \"கண்காணிப்பை விரும்புகிறவன் நல்லவேலையை விரும்புகிறான், இது உண்மையான வார்த்தை. ஆகையால் கண்காணியானவன் குற்றஞ்சாட்டப்படாதவனும், ஒரே மனைவியை உடைய புருஷனும், ஜாக்கிரதையுள்ளவனும், தெளிந்த புத்தியுள்ளவனும், யோக்கியதையுள்ளவனும், அந்நியரை உபசரிக்கிறவனும், போதகசமர்த்தனுமாய் இருக்கவேண்டும். அவன் மதுபானப்பிரியனும், அடிக்கிறவனும், இழிவான ஆதாயத்தை இச்சிக்கிறவனுமாயிராமல், பொறுமையுள்ளவனும், சண்டைபண்ணாதவனும், பண ஆசையில்லாதவனுமாயிருக்கவேண்டும்.\"</p><p>1 தீமோத்தேயு 4:9-10, \"இந்த வார்த்தை உண்மையும் எல்லா அங்கிகரிப்புக்கும் பாத்திரமுமாயிருக்கிறது. இதினிமித்தம் பிரயாசப்படுகிறோம், நிந்தையும் அடைகிறோம்; ஏனெனில் எல்லா மனுஷருக்கும், விசேஷமாக விசுவாசிகளுக்கும் இரட்சகராகிய ஜீவனுள்ள தேவன்மேல் நம்பிக்கை, வைத்திருக்கிறோம்.\"</p><p>1 தீமோத்தேயு 6:12, \"விசுவாசத்தின் நல்ல போராட்டத்தைப் போராடு, நித்தியஜீவனைப் பற்றிக்கொள்; அதற்காகவே நீ அழைக்கப்பட்டாய்; அநேக சாட்சிகளுக்கு முன்பாக நல்ல அறிக்கை பண்ணினவனுமாயிருக்கிறாய்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>பவுலுக்கு உதவியாக இருந்த ஒரு இளம் போதகராகிய தீமோத்தேயுவுக்கு பவுல் எழுதிய முதல் நிருபம் இது. தீமோத்தேயு ஒரு கிரேக்கன் ஆவார். அவரது தாயார் ஒரு யூதர், அவரது தந்தை கிரேக்கன். பவுல் தீமோத்தேயுவுக்கு ஒரு வழிகாட்டியாகவும் தலைவராகவும் இருந்தார், அவர் அவருக்கு ஒரு தந்தையைப் போலவும், தீமோத்தேயு பவுலுக்கு ஒரு மகனைப் போலவும் இருந்தார் (1 தீமோத்தேயு 1:2). கள்ளப் போதகர்களுக்கும் கள்ள உபதேசங்களுக்கும் எச்சரிக்கையாக இருக்கும்படி தீமோத்தேயுவை அறிவுறுத்துவதன் மூலம் பவுல் இந்த நிருபத்தைத் தொடங்குகிறார். இருப்பினும், இந்த கடிதத்தின் பெரும்பகுதி மேய்ப்பர்களின்/ஆயர்களின் நடத்தையைப் பற்றியதாகும். பவுல் தீமோத்தேயுவை ஆராதனையில் அறிவுறுத்துகிறார் (2-ஆம் அதிகாரம்) மற்றும் திருச்ச்சபைக்கான முதிர்ச்சியான தலைவர்களை வளர்த்துக் கொள்ளும் படிக்கு அறிவுறுத்துகிறார் (3-ஆம் அதிகாரம்). நிருபத்தின் பெரும்பகுதி மேய்ப்பரின் நடத்தை, கள்ளப் போதகர்களைப் பற்றிய எச்சரிக்கைகள் மற்றும் பாவம் செய்கிற சபை உறுப்பினர்கள், சபையிலுள்ள விதவைகள், முதியவர்கள் மற்றும் அடிமைகள் மீதான திருச்சபையின் பொறுப்பு ஆகியவற்றைக் குறிக்கிறது. நிருபம் முழுவதும், பவுல் தீமோத்தேயுவை உறுதியாக நிலை நிற்கவும், விடாமுயற்சியுடன் இருக்கவும், அவருடைய அழைப்பிற்கு உண்மையாக இருக்கவும் பவுல் ஊக்குவிக்கிறார்.</p><p><b>இணைப்புகள்:</b></p><p>1 தீமோத்தேயு புத்தகத்தில் உள்ள பழைய ஏற்பாட்டுக்கான ஒரு சுவாரஸ்யமான இணைப்பு, திருச்சபை மூப்பர்களை \"இரட்டை கனத்திற்கு\" தகுதியானவர்கள் என்று கருதுவதற்கும், தவறு செய்ததாகக் குற்றம் சாட்டப்படும்போது கனத்திற்கு தகுதியானவர் என்பதற்கும் பவுல் மேற்கோள் காட்டியுள்ளார் (1 தீமோத்தேயு 5:17-19). உபாகமம் 24:15, 25:4 மற்றும் லேவியராகமம் 19:13 அனைத்துமே ஒரு வேலையாள் சம்பாதித்த ஊதியத்தைச் செலுத்த வேண்டிய அவசியத்தையும், அதை சரியான நேரத்தில் செய்ய வேண்டியதன் அவசியத்தையும் குறித்துப் பேசுகின்றன. ஒரு மனிதனுக்கு எதிராக ஒரு குற்றச்சாட்டைக் கொண்டுவர இரண்டு அல்லது மூன்று சாட்சிகள் அவசியம் என்று மோசேயின் நியாயப்பிரமாண சட்டத்தின் ஒரு பகுதி கோரியது (உபாகமம் 19:15). தீமோத்தேயு மேய்ப்பராக இருந்த சபைகளில் இருந்த யூத கிறிஸ்தவர்கள் இந்த பழைய ஏற்பாட்டு தொடர்புகளை நன்கு அறிந்திருப்பார்கள்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>தேவனுக்கும் மனிதனுக்கும் இடையிலான மத்தியஸ்தராக இயேசு கிறிஸ்துவைப் பவுல் முன்வைக்கிறார் (1 தீமோத்தேயு 2:5), மேலும் அவரை நம்புகிற யாவருக்கும் அவர் இரட்சகராக இருக்கிறார். அவர் திருச்சபையின் கர்த்தராக இருக்கிறார், தீமோத்தேயு அவருடைய திருச்சபையை மேய்ப்பதன் மூலம் அவருக்கு சேவை செய்கிறார். ஆகவே, பவுல் தனது \"விசுவாசமுள்ள மகனுக்கு\" எழுதிய முதல் கடிதத்தின் முக்கிய பயன்பாட்டை இங்கேக் காண்கிறோம். சபைக் கோட்பாடு, சபைத் தலைமை மற்றும் சபையின் நிர்வாகம் போன்ற விஷயங்களில் பவுல் தீமோத்தேயுவுக்கு அறிவுறுத்துகிறார். இன்று நாம் நம்முடைய உள்ளூர் திருச்சபையை நிர்வகிப்பதில் அதே வழிமுறைகளைப் பயன்படுத்தலாம் / கையாளலாம். அதேபோல், ஒரு போதகரின் பணி மற்றும் அவரது ஊழியம், ஒரு மூப்பருக்கான தகுதிகள் மற்றும் ஒரு உதவிக்காரரின் தகுதிகள் ஆகியவை தீமோத்தேயுவின் நாட்களில் இருந்ததைப் போலவே இன்றும் அவைகள் முக்கியமானவை மற்றும் பொருத்தமானவைகளாக இருக்கின்றன. தீமோத்தேயுவுக்கு பவுலின் முதல் நிருபம் உள்ளூர் திருச்சபையை வழிநடத்துவது, நிர்வகிப்பது மற்றும் மேய்த்து பராமரிப்பது குறித்த அறிவுறுத்தல்கள் அடங்கிய புத்தகமாகும். இந்த நிருபத்திலுள்ள வழிமுறைகள் கிறிஸ்துவினுடைய திருச்சபையின் எந்தவொரு தலைவருக்கும் அல்லது வருங்காலத் தலைவருக்கும் பொருந்தும், அவை பவுலின் நாட்களில் இருந்ததைப் போலவே இன்றும் பொருந்தும். தங்கள் திருச்சபையில் தலைமைப் பொறுப்புகளுக்கு அழைக்கப்படாதவர்களுக்கு, புத்தகம் முன்வைக்கிற தகுதிகள் இன்னும் நடைமுறையில் உள்ளது. கிறிஸ்துவைப் பின்பற்றுகிற ஒவ்வொருவரும் விசுவாசத்திற்காக தைரியமாகப் போராட வேண்டும் மற்றும் தவறான கள்ளப்போதனைகளைத் தவிர்க்க வேண்டும். பின்பற்றுகிற ஒவ்வொருவரும் தங்களை அழைத்த பொறுப்புகளில் உறுதியாக நிற்க வேண்டும், விடாமுயற்சியுடன் இருக்க வேண்டும்.</p><p>சுமார் கி.பி. 45-47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 51-53 - பவுலின் இரண்டாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 51 - தீமோத்தேயு பவுல்-சீலாவுடன் சேர்ந்து கொள்ளல்</p><p>சுமார் கி.பி. 54-58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 58 - பவுல் எருசலேமில் கைது செய்யப்படல்</p><p>சுமார் கி.பி. 61-62 - பவுல் ரோமச் சிறையில்</p><p>சுமார் கி.பி. 62 - 66 பவுல் விடுதலை பெறுதலும் சுற்றுப் பயணமும்,</p><p>1தீமோத்தேயு எழுதுதலும்</p><p>சுமார் கி.பி. 66 - பவுல் மீண்டும் கைது செய்யப்படல்</p><p>சுமார் கி.பி. 67 - பவுல் இரத்தசாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 54-வது நூல்</p><p>அதிகாரங்கள் - 6</p><p>வசனங்கள் - 114</p><p>கேள்வி - 1</p><p>வரலாற்று வசனங்கள் - 106</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 5</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 2</p>'),
 (620,'<p><b>2 தீமோத்தேயு புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>2 தீமோத்தேயு புத்தகத்தின் முதலாம் அதிகாரத்தின் முதலாம் வசனம், 2 தீமோத்தேயு புத்தகத்தின் எழுத்தாளரை அப்போஸ்தலனாகிய பவுல் என்று தெளிவாக அடையாளம் காட்டுகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>2 தீமோத்தேயு புத்தகம் அப்போஸ்தலனாகிய பவுல் ரோமாபுரியில் சிரச்சேதம் பண்ணப்பட்டு கொல்லப்படுவதற்கு சற்று முன்பதாக ஏறக்குறைய கி.பி. 67-ல் இந்த நிருபத்தை எழுதினார்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>ரோமாபுரியில் மீண்டும் சிறையில் அடைக்கப்பட்ட அப்போஸ்தலனாகிய பவுல் தனிமையாகவும் எல்லோராலும் கைவிடப்பட்டதையும் உணர்ந்தார். தனது பூமிக்குரிய வாழ்க்கை விரைவில் முடிவுக்கு வரக்கூடும் என்பதை பவுல் அறிந்திருந்தார். 2 தீமோத்தேயுவின் புத்தகம் அடிப்படையில் பவுலின் \"கடைசி வார்த்தைகள்\" ஆகும். திருச்சபைகள் மீது குறிப்பாக தீமோத்தேயு மீதுள்ள அக்கறையை வெளிப்படுத்த பவுல் தனது சொந்த சூழ்நிலைகளை கடந்தார். பவுல் தனது கடைசி வார்த்தைகளைப் பயன்படுத்தி தீமோத்தேயுவையும் மற்ற எல்லா விசுவாசிகளையும் விசுவாசத்தில் விடாமுயற்சியுடன் இருக்கும்படிக்கு ஊக்குவிக்க விரும்பினார் (2 தீமோத்தேயு 3:14) மற்றும் இயேசு கிறிஸ்துவின் நற்செய்தியை அறிவிக்க திடப்படும்படியாகவும் விரும்பினார் (2 தீமோத்தேயு 4:2).</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>2 தீமோத்தேயு 1:7, \"தேவன் நமக்குப் பயமுள்ள ஆவியைக் கொடாமல், பலமும் அன்பும் தெளிந்த புத்தியுமுள்ள ஆவியையே கொடுத்திருக்கிறார்.\"</p><p>2 தீமோத்தேயு 3:16-17, \"வேதவாக்கியங்களெல்லாம் தேவஆவியினால் அருளப்பட்டிருக்கிறது; தேவனுடைய மனுஷன் தேறினவனாகவும், எந்த நற்கிரியையுஞ் செய்யத் தகுதியுள்ளவனாகவும் இருக்கும்படி, அவைகள் உபதேசத்துக்கும், கடிந்துகொள்ளுதலுக்கும் சீர்திருத்தலுக்கும், நீதியைப் படிப்பிக்குதலுக்கும் பிரயோஜனமுள்ளவைகளாயிருக்கிறது.\"</p><p>2 தீமோத்தேயு 4:2, \"சமயம் வாய்த்தாலும் வாய்க்காவிட்டாலும் ஜாக்கிரதையாய்த் திருவசனத்தைப் பிரசங்கம்பண்ணு; எல்லா நீடிய சாந்தத்தோடும் உபதேசத்தோடும் கண்டனம் பண்ணி, கடிந்துகொண்டு, புத்திசொல்லு.\"</p><p>2 தீமோத்தேயு 4:7-8, \"நல்ல போராட்டத்தைப் போராடினேன், ஓட்டத்தை முடித்தேன், விசுவாசத்தைக் காத்துக்கொண்டேன். இதுமுதல் நீதியின் கிரீடம் எனக்காக வைக்கப்பட்டிருக்கிறது, நீதியுள்ள நியாயாதிபதியாகிய கர்த்தர் அந்நாளிலே அதை எனக்குத் தந்தருளுவார்; எனக்கு மாத்திரமல்ல, அவர் பிரசன்னமாகுதலை விரும்பும் யாவருக்கும் அதைத் தந்தருளுவார்.</p><p><b>சுருக்கமான திரட்டு:</b></p><p>பவுல் தீமோத்தேயுவை கிறிஸ்துவின் மீது ஆர்வமாக இருக்கும்படி ஊக்குவிக்கிறார், மேலும் நல்ல ஆரோக்கியமான உபதேசத்தில் உறுதியாக இருக்க வேண்டும் என்று கூறுகிறார் (2 தீமோத்தேயு 1:1-2, 13-14). தேவபக்தியற்ற நம்பிக்கைகளையும் பழக்கவழக்கங்களையும் தவிர்க்கவும் ஒழுக்கக்கேடான எதையும் விட்டு விலகவும் பவுல் தீமோத்தேயுவை நினைவுபடுத்துகிறார் (2 தீமோத்தேயு 2:14-26). கடைசிக் காலங்களில் கிறிஸ்தவ விசுவாசத்திலிருந்து கடுமையான உபத்திரவம் மற்றும் விசுவாசத் துரோகம் ஆகிய இரண்டுமே இருக்கும் (2 தீமோத்தேயு 3:1-17) என்று கூறுகிறார். விசுவாசிகள் தங்கள் விசுவாசத்தில் உறுதியாக நிற்கவும், தங்களுக்குள்ள விசுவாச ஓட்டத்தை வலுவாக முடிக்கவும் வேண்டுமென பவுல் ஒரு தீவிர வேண்டுகோளுடன் தனது நிருபத்தை முடிக்கிறார் (2 தீமோத்தேயு 4:1-8).</p><p><b>இணைப்புகள்:</b></p><p>மோசேயை எதிர்த்த எகிப்திய மந்திரவாதிகளின் கதையை மேற்கோள்காட்டி, கள்ளப்போதகர்களின் ஆபத்துக்களைப் பற்றி அவர் மேய்ப்பராக இருக்கக் கூடிய சபைகளில் தீமோத்தேயு கவனமாக இருக்கும்படிக்கு பவுல் எச்சரிக்கிறார் (யாத்திராகமம் 7:11, 22; 8:7, 18, 19; 9:11 ). பழைய ஏற்பாட்டில் அவர்களின் பெயர்கள் குறிப்பிடப்படவில்லை என்றாலும், இந்த மனிதர்கள் பொற்க்காளைக் கன்றைக் கட்டியெழுப்பத் தூண்டினர் மற்றும் மீதமுள்ளவர்களையும் விக்கிரகாராதனையுடன் சேர்ந்து கொல்லப்படுபடியாக செய்தனர் (யாத்திராகமம் 32). கிறிஸ்துவின் சத்தியத்தை எதிர்ப்பவர்களுக்கு அதே கதியை / நிலைமையை பவுல் முன்னறிவிக்கிறார், அவர்களின் முட்டாள்தனம் வெளிப்பட்டதுபோல, இறுதியில் \"இவர்களுடைய மதிகேடும் வெளிப்படும்\" (2 தீமோத்தேயு 3:9).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>கிறிஸ்தவ வாழ்க்கையில் பக்க கண்காணிப்புகளில் ஈர்க்கப்பட்டு வழிவிலகிப் போவதென்பது மிகவும் எளிது. ஈவைப் பெற்ற நாம் நமது கண்களை அவைகளின்மேல் வைத்திருக்க வேண்டும் – அது இயேசுவால் பரலோகத்தில் வெகுமதி அளிக்கப்படுகிறது (2 தீமோத்தேயு 4:8). கள்ளப்போதனை மற்றும் தேவபக்தியற்ற நடைமுறைகள் இரண்டையும் தவிர்க்க நாம் பாடுபட வேண்டும். தேவனுடைய வார்த்தையைப் பற்றிய நமது அறிவில் அடித்தளமாக உறுதியாக இருப்பதன் மூலமும், வேதாகமமற்ற எதையும் ஏற்க மறுப்பதில் உறுதியாக இருப்பதன் மூலமும் இதைச் செய்ய முடியும்.</p><p>சுமார் கி.பி. 45-47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 51-53 - பவுலின் இரண்டாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 51 - தீமோத்தேயு பவுல் - சீலாவுடன் இணைகிறார்</p><p>சுமார் கி.பி. 54-58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 58 - பவுல் எருசலேமில் சிறையாதல்</p><p>சுமார் கி.பி. 61-62 -  பவுல் ரோமச் சிறையில்</p><p>சுமார் கி.பி. 62-66 -  பவுல் விடுதலை பெறலும் 1தீமோத்தேயு எழுதுதலும்</p><p>சுமார் கி.பி. 66 - பவுல் மீண்டும் கைது செய்யப்படல் 2தீமோத்தேயு எழுதுதல்</p><p>சுமார் கி.பி. 67 - பவுல் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 55-வது நூல்</p><p>அதிகாரங்கள் - 4</p><p>வசனங்கள் - 83</p><p>கேள்விகள் - இல்லை</p><p>வரலாற்று வசனங்கள் - 68</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 10</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 5</p>'),
 (630,'<p><b>தீத்துவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>தீத்து முதலாம் அதிகாரத்தின் முதலாவது வசனம், அப்போஸ்தலனாகிய பவுல்தான் தீத்து புத்தகத்தின் எழுத்தாளர் என்று அடையாளப்படுத்துகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>தீத்துவுக்கு எழுதின நிருபம் ஏறக்குறைய கி.பி. 66-ல் எழுதப்பட்டதாகும். பவுலின் பல சுவிசேஷப் பயணங்கள் நன்கு ஆவணப்படுத்தப்பட்டுள்ளன, மேலும் அவர் எபிரஸில் உள்ள நிக்கொப்போலிக்கிலிருந்து தீத்துவுக்கு இந்த நிருபத்தை எழுதியதைக் காட்டுகிறது. சில வேதாகம மொழிபெயர்ப்புகளில், மக்கெதோனியாவில் உள்ள நிக்கொப்போலிக்கிலிருந்து பவுல் இந்த நிருபத்தை எழுதியதாக நிருபத்தின் மேற்குறிப்பில் குறிப்பிடப்பட்டுள்ளது. இருப்பினும், அத்தகைய ஒரு இடம் எதுவும் இல்லை மற்றும் இந்த மேற்குறிப்புக்கள் உண்மையானவை அல்ல என்பதால் அவைகள் அதிகாரமற்றதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>தீமோத்தேயுவுக்கு எழுதிய இரண்டு கடிதங்களைப் போலவே தீத்துவிற்கும் பவுல் எழுதிய இந்த நிருபம் மேய்ப்பர்களுக்கு எழுதப்பட்ட நிருபங்களில் ஒன்றாக அறியப்படுகிறது. இந்த நிருபத்தை அப்போஸ்தலனாகிய பவுல் விசுவாசத்தில் தன் சகோதரரான தீத்துவை ஊக்குவிப்பதற்காக எழுதினார், பவுல் தனது மிஷனரி பயணங்களின்பொது நிறுவிய திருச்சபைகளுள் ஒரு திருச்சபையை வழிநடத்தும்படியாக தீத்துவை கிரேத்தா தீவில் விட்டுவிட்டுப் புறப்பட்டார் (தீத்து 1:5). இந்த நிருபம் தீத்துவினை திருச்ச்சபைக்கான தலைவர்களுக்கு என்னென்ன தகுதிகள் காணப்பட வேண்டும் என்று அறிவுறுத்துகிறது. கிரேத்தா தீவில் வசிப்பவர்களின் பண்புகளைக் குறித்தும் அவர் தீத்துவை எச்சரிக்கிறார் (தீத்து 1:12).</p><p>திருச்சபையில் ஒரு தலைவரில் காணப்படவேண்டிய தகுதிகளைக் குறித்து தீத்துவிற்கு அறிவுறுத்தியதோடு மட்டுமல்லாமல், தீத்துவை நிக்கொபோலிக்கு வருகை தரும்படியும் பவுல் ஊக்குவித்தார். வேறு வார்த்தைகளில் கூறுவதானால், பவுல் தீத்துவையும் அதுபோல் மற்றவர்களையும் தொடர்ந்து கர்த்தருடைய கிருபையில் வளர்த்து அவர்களை சீஷராக்கினார் (தீத்து 3:13).</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>தீத்து 1:5, \"நீ குறைவாயிருக்கிறவைகளை ஒழுங்குபடுத்தும்படிக்கும், நான் உனக்குக் கட்டளையிட்டபடியே, பட்டணங்கள்தோறும் மூப்பரை ஏற்படுத்தும்படிக்கும், உன்னைக் கிரேத்தாதீவிலே விட்டுவந்தேனே.\"</p><p>தீத்து 1:16, \"அவர்கள் தேவனை அறிந்திருக்கிறோமென்று அறிக்கைபண்ணுகிறார்கள், கிரியைகளினாலோ அவரை மறுதலிக்கிறார்கள்; அவர்கள் அருவருக்கப்படத்தக்கவர்களும், கீழ்ப்படியாதவர்களும், எந்த நற்கிரியையுஞ்செய்ய ஆகாதவர்களுமாயிருக்கிறார்கள்.\"</p><p>தீத்து 2:15, \"இவைகளை நீ பேசி, போதித்து, சகல அதிகாரத்தோடும் கடிந்துகொள். ஒருவனும் உன்னை அசட்டைபண்ண இடங்கொடாதிருப்பாயாக.\"</p><p>தீத்து 3:3-6, \"ஏனெனில், முற்காலத்திலே நாமும் புத்தியீனரும், கீழ்ப்படியாதவர்களும், வழிதப்பி நடக்கிறவர்களும், பலவித இச்சைகளுக்கும் இன்பங்களுக்கும். அடிமைப்பட்டவர்களும், துர்க்குணத்தோடும் பொறாமையோடும் ஜீவனம்பண்ணுகிறவர்களும், பகைக்கப்படத்தக்கவர்களும், ஒருவரையொருவர் பகைக்கிறவர்களுமாயிருந்தோம். நம்முடைய இரட்சகராகிய தேவனுடைய தயையும் மனுஷர்மேலுள்ள அன்பும் பிரசன்னமானபோது, நாம் செய்த நீதியின் கிரியைகளினிமித்தம் அவர் நம்மை இரட்சியாமல், தமது இரக்கத்தின்படியே, மறுஜென்ம முழுக்கினாலும், பரிசுத்த ஆவியினுடைய புதிதாக்குதலினாலும் நம்மை இரட்சித்தார். தமது கிருபையினாலே நாம் நீதிமான்களாக்கப்பட்டு, நித்திய ஜீவனுண்டாகும் என்கிற நம்பிக்கையின்படி சுதந்தரமாகத்தக்கதாக, அவர் நமது இரட்சகராகிய இயேசுகிறிஸ்து மூலமாய், அந்தப் பரிசுத்தாவியை நம்மேல் சம்பூரணமாய்ப் பொழிந்தருளினார்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>தீத்து தனது வழிகாட்டியான அப்போஸ்தலனாகிய பவுலிடமிருந்து ஒரு கடிதத்தைப் பெற்றபோது அது எவ்வளவு அருமையானதாக இருந்திருக்க வேண்டும். பவுல் மிகவும் மரியாதைக்குரிய ஒரு மனிதராக இருந்தார், கிழக்கத்திய நாடுகள் முழுவதும் பல திருச்சபைகளை நிறுவியதால் பவுல் மிகவும் கனம்பெற்று விளங்கினார். அப்போஸ்தலரிடமிருந்து வந்த இந்த புகழ்பெற்ற அறிமுகம் தீத்துவால் நிச்சயமாக வாசிக்கப்பட்டிருக்கும், \"பொதுவான விசுவாசத்தின்படி உத்தம குமாரனாகிய தீத்துவுக்கு எழுதுகிறதாவது: பிதாவாகிய தேவனாலும், நம்முடைய இரட்சகராயிருக்கிற கர்த்தராகிய இயேசு கிறிஸ்துவினாலும், கிருபையும் இரக்கமும் சமாதானமும் உண்டாவதாக\" (தீத்து 1:4).</p><p>திருச்சபையை வழிநடத்துவதற்காக தீத்துவை பவுல் விட்டுச்சென்ற கிரேத்தா தீவில், தீவின் பூர்வீகவாசிகள் மற்றும் இயேசு கிறிஸ்துவைப்பற்றிய உண்மையை அறியாத யூதர்கள் வசித்து வந்தனர் (தீத்து 1:12-14). கிரேத்தா தீவிலுள்ள திருச்சபையில் தலைவர்களை வளர்த்து அவர்களை ஏற்ப்படுத்துவதில் தீத்துவை அறிவுறுத்துவதற்கும் மற்றும் ஊக்குவிப்பதற்கும் தீத்துவை பின்தொடர்ந்து அவரை போதனைகளால் அறிவுறுத்துவதை தனது பொறுப்பாக பவுல் உணர்ந்தார். அப்போஸ்தலனாகிய பவுல் தலைவர்களைத் கண்டறிவதில் தீத்துவை வழிநடத்தியபோது, கிறிஸ்து மீதான விசுவாசத்தில் வளரும்படி தீத்து தலைவர்களுக்கு எவ்வாறு அறிவுறுத்த வேண்டும் என்றும் பவுல் பரிந்துரைக்கிறார். அவருடைய அறிவுறுத்தல்கள் எல்லா வயதினருக்கும் ஆண்களுக்கும் பெண்களுக்கும் (தீத்து 2:1-8) ஏற்ற வகையில் இருந்தன.</p><p>கிறிஸ்துவை விசுவாசிப்பதில் தீத்துக்கு உதவுவதற்காக, தீத்து நிக்கொபோலிக்கு வந்து திருச்சபையிலுள்ள மற்ற இரண்டு உறுப்பினர்களையும் தன்னுடன் அழைத்துக்கொண்டு வரும்படி பவுல் பரிந்துரைக்கிறார் (தீத்து 3:12-13).</p><p><b>இணைப்புகள்:</b></p><p>இரட்சிப்பைத் தரும் ஈவாகிய கிருபையோடு கிரியைகளைச் சேர்க்க முற்படுகிற யூதமதத்தவர்களுக்கு எதிராக எச்சரிக்கையாக இருக்கும்படி திருச்சபையின் தலைவர்களுக்கு அறிவுறுத்துவது அவசியம் என்று பவுல் மீண்டும் காண்கிறார். கலகக்கார ஏமாற்றுபவர்களுக்கு எதிராக, குறிப்பாக விருத்தசேதனம் செய்வதாகவும், மோசேயின் நியாயப்பிரமாண சடங்குகள் மற்றும் ஆசரிப்புகளைக் கடைபிடிக்கும் விஷயத்தில் தொடர்ந்து அது தேவையானது என்று வாதிடுபவர்களுக்கு எதிராக அவர் எச்சரிக்கிறார் (தீத்து 1:10-11). பவுலின் நிருபங்கள் முழுவதிலும் இது ஒரு தொடர்ச்சியான கருப்பொருள் மற்றும் தீத்து புத்தகத்தில், அவர்களின் வாயானது அடைக்கப்பட வேண்டும் என்று சொல்லும் அளவிற்கு அவர் எடுத்துரைக்கிறார்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நம்முடைய கர்த்தருக்குப் பிரியமான வாழ்க்கையை எவ்வாறு வாழ்வது என்பது குறித்த அறிவுறுத்தலுக்காக வேதாகமத்தை நாம் பார்க்கும்போது அப்போஸ்தலனாகிய பவுல் நம் கவனத்திற்கு தகுதியானவராக இருக்கிறார். நாம் எதைத் தவிர்க்க வேண்டும் என்பதையும் நாம் பின்பற்ற முயற்சிக்கவேண்டியதையும் கற்றுக்கொள்ளலாம். நம் மனதையும் மனசாட்சியையும் தீட்டுப்படுத்தும் விஷயங்களைத் தவிர்ப்பதால் நாம் பரிசுத்தமாக இருக்க முற்படுகிறோம் என்று பவுல் அறிவுறுத்துகிறார். பின்னர் பவுல் ஒருபோதும் மறக்கக் கூடாத ஒரு அறிக்கையை அளிக்கிறார்: \"அவர்கள் தேவனை அறிந்திருக்கிறோமென்று அறிக்கைபண்ணுகிறார்கள், கிரியைகளினாலோ அவரை மறுதலிக்கிறார்கள்; அவர்கள் அருவருக்கப்படத்தக்கவர்களும், கீழ்ப்படியாதவர்களும், எந்த நற்கிரியையுஞ்செய்ய ஆகாதவர்களுமாயிருக்கிறார்கள்\" (தீத்து 1:16). கிறிஸ்தவர்களாகிய நம்முடைய வாழ்க்கையானது கிறிஸ்துவை விசுவாசிக்கும் அறிக்கையுடன் ஒத்துப்போகிறதா என்பதை உறுதிப்படுத்திக் கொள்ள வேண்டும் (2 கொரிந்தியர் 13:5).</p><p>இந்த எச்சரிக்கையுடன், தேவனை மறுப்பதை / மறுதலிப்பதைத் தவிர்ப்பது எப்படி என்பதையும் பவுல் நமக்குச் சொல்லுகிறார்: \"மறுஜென்ம முழுக்கினாலும், பரிசுத்த ஆவியினுடைய புதிதாக்குதலினாலும் நம்மை இரட்சித்தார். தமது கிருபையினாலே நாம் நீதிமான்களாக்கப்பட்டு, நித்திய ஜீவனுண்டாகும் என்கிற நம்பிக்கையின்படி சுதந்தரமாகத்தக்கதாக, அவர் நமது இரட்சகராகிய இயேசுகிறிஸ்து மூலமாய், அந்தப் பரிசுத்தாவியை நம்மேல் சம்பூரணமாய்ப் பொழிந்தருளினார்\" (தீத்து 3:5-6). பரிசுத்த ஆவியினால் நம் மனதை தினசரி புதுப்பிக்க முற்படுவதன் மூலம், நாம் வாழும் வாழ்வின் முறையால் தேவனை மதிக்கும் கிறிஸ்தவர்களாக நாம் வளர முடியும்.</p><p>சுமார் கி.பி. 45-47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 50 - எருசலேம் கவுன்சில்</p><p>சுமார் கி.பி. 51-53 - பவுலின் இரண்டாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 54-58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 58 - பவுல் எருசலேமில் கைது செய்யப்படல்</p><p>சுமார் கி.பி. 61-62 - பவுல் ரோம் சிறையில்</p><p>சுமார் கி.பி. 62-66 - பவுல் விடுதலையை பெறுதலும் சுற்றுப்பயண மும் தீத்து நிருபத்தை எழுதுதலும்</p><p>சுமார் கி.பி. 66 - பவுல் மீண்டும் கைதாதல்</p><p>சுமார் கி.பி. 67 - பவுல் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 56-வது நூல்</p><p>அதிகாரங்கள் - 3</p><p>வசனங்கள் - 46</p><p>வரலாற்று வசனங்கள் - 45</p><p>நிறைவேறிய தீர்க்கதரிசனம் - 1</p>'),
 (640,'<p><b>பிலேமோன் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>பிலேமோன் புத்தகத்தை எழுதிய எழுத்தாளர் அப்போஸ்தலனாகிய பவுல் (பிலேமோன் 1:1).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>பிலேமோன் புத்தகம் ஏறக்குறைய கி.பி. 60-ல் எழுதப்பட்டது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>அப்போஸ்தலனாகிய பவுல் பிலேமோனுக்கு எழுதிய நிருபம் பவுலின் மற்ற நிருபங்களோடு ஒப்பிடும்போது குறுகியதாகும், மேலும் இந்த நிருபம் அடிமைத்தனத்தின் நடைமுறையைப் பற்றியது ஆகும். இந்த நிருபத்தை எழுதும் நேரத்தில் பவுல் ரோமாப்புரியில் சிறையில் இருந்ததாக அறிவுறுத்துகிறது. பிலேமோன் ஒரு அடிமையின் உரிமையாளராக இருந்தார், மேலும் அவர் தனது வீட்டில் ஒரு திருச்சபையின் கூடி வருதலையும் கொண்டிருந்தார். எபேசுவில் பவுல் ஊழியம் செய்த காலத்தில், பிலேமோன் எபேசு நகரத்திற்குச் சென்று, பவுலின் பிரசங்கத்தைக் கேட்டு, அதன் மூலமாக ஒரு கிறிஸ்தவராக மாறியிருக்கலாம். ஒநேசிமு என்கிற அடிமை தன் எஜமானனான பிலேமோனைக் கொள்ளையடித்து ஓடிப்போனபோது, பிடிக்கப்பட்டு ரோமாபுரிக்கு கொண்டுசெல்லப்பட்டு, இறுதியில் சிறையில் இருக்கும் பவுலுக்கும் அறிமுகமாகிறார். ஒநேசிமு இன்னும் தனது எஜமானனாகிய பிலேமோனின் சொத்தாக இருக்கிறார், பவுல் அவரை தன் எஜமானனிடம் திரும்புவதற்கான வழியை மென்மையாக்க இந்த நிருபத்தை எழுதினார். பவுல் ஒநேசிமுவினிடம் கிறிஸ்துவைப்பற்றிய சாட்சியம் அளித்ததன் மூலம், ஒநேசிமு சிறையிலிருக்கும் போது ஒரு கிறிஸ்தவராக மாறுகிறார் (பிலேமோன் 10), பிலேமோன் ஒநேசிமசை கிறிஸ்துவுக்குள் வெறும் ஒரு அடிமையாக அல்லாமல் ஒரு சகோதரனாக ஏற்றுக்கொள்ள வேண்டும் என்று பவுல் விரும்பினார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>பிலேமோன் 6, \"உங்களிலுள்ள சகல நன்மைகளும் தெரியப்படுகிறதினாலே உம்முடைய விசுவாசத்தின் அந்நியோந்நியம் கிறிஸ்து இயேசுவுக்காகப் பயன்படவேண்டுமென்று வேண்டுதல் செய்கிறேன்.\"</p><p>பிலேமோன் 16, \"எனக்கு அவன் பிரியமான சகோதரனானால், உமக்கு சரீரத்தின்படியேயும் கர்த்தருக்கும் எவ்வளவு பிரியமுள்ளவனாயிருக்கவேண்டும்!\"</p><p>பிலேமோன் 18, \"அவன் உமக்கு யாதொரு அநியாயஞ்செய்ததும், உம்மிடத்தில் கடன்பட்டதும் உண்டானால், அதை என் கணக்கிலே வைத்துக்கொள்ளும்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>அடிமைகளின் உரிமையாளர்களுக்கு தங்கள் அடிமைகளின்மேல் ஒரு பொறுப்பு இருப்பதாக பவுல் எச்சரித்தார், மேலும் அடிமைகள் தேவனுக்குப் பயப்பட வேண்டிய பொறுப்புள்ள தார்மீக மனிதர்களாகவும் இருக்கவேண்டும் என்பதையும் சுட்டிக் காண்பிக்கிறார். பிலேமோனில், பவுல் அடிமைத்தனத்தை கண்டிக்கவில்லை, ஆனால் மாறாக அவர் ஒநேசிமுவை ஒரு அடிமை என்பதற்குப் பதிலாக ஒரு கிறிஸ்தவ சகோதரனாக முன்வைக்கிறார். ஒரு உரிமையாளர் தனது அடிமையை சகோதரர் என்று குறிப்பிடும்போது, அடிமை என்பது சட்டபூர்வமான தலைப்பு என்ற அர்த்தமற்ற நிலையை அடைகிறது. ஆரம்பகால திருச்சபையானது அடிமைத்தனத்தை நேரடியாகத் தாக்கவில்லை, ஆனால் அது உரிமையாளருக்கும் அடிமைக்கும் இடையிலான புதிய உறவுக்கு அடித்தளம் அமைத்தது. பிலேமோன் மற்றும் ஒநேசிமு ஆகிய இருவரையும் கிறிஸ்தவ அன்போடு ஒன்றிணைக்க பவுல் முயன்றார், இதனால் விடுதலையானது மிகவும் அவசியமாயிற்று. சுவிசேஷத்தின் வெளிச்சத்தை வெளிப்படுத்திய பின்னரே அடிமைத்தனத்தின் நிறுவனம் மரித்துப்போக முடியும்.</p><p><b>இணைப்புகள்:</b></p><p>புதிய ஏற்பாட்டில் வேறு எங்கும் நியாயப்பிரமாண சட்டத்திற்கும் கிருபைக்குமுள்ள வேறுபாடு இவ்வளவு மிகவும் அழகாக சித்தரிக்கப்படவில்லை. ரோமர்களின் சட்டம் மற்றும் பழைய ஏற்பாட்டின் மோசேயினுடைய நியாயப்பிரமாண சட்டம் ஆகிய இரண்டும் பிலேமோனுக்கு சொந்தமான சொத்து என்று கருதப்பட்ட ஓடிப்போன அடிமையை தண்டிக்கும் உரிமையை வழங்கின. ஆனால் கர்த்தராகிய இயேசு கிறிஸ்துவின் மூலமாக கிருபையினுடைய உடன்படிக்கையின் எஜமானன் மற்றும் அடிமை ஆகிய இருவரையும் கிறிஸ்துவின் சரீரத்தில் சமம் என்கிற அடிப்படையில் அன்பில் கூட்டுறவு ஐக்கியம் கொள்ள அனுமதித்தது.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>முதலாளிகள், அரசியல் தலைவர்கள், தலைமை நிர்வாகத்தின் நிர்வாகிகள் மற்றும் பெற்றோர்கள் ஆகியோர்கள் கிறிஸ்தவ ஊழியர்கள், சக ஊழியர்கள் மற்றும் குடும்ப உறுப்பினர்களை கிறிஸ்துவின் சரீரத்தினுடைய உறுப்பினர்களாகக் கருதி பவுலின் போதனையின் உணர்வைப் பின்பற்றலாம். நவீன சமுதாயத்தில் உள்ள கிறிஸ்தவர்கள் உதவியாளர்களை தங்கள் லட்சியங்களை அடைய உதவும் ஒரு படியாக பார்க்கக்கூடாது, ஆனால் அதற்கு மாறாக கிறிஸ்தவ சகோதர சகோதரிகளாக இரக்கமிக்க நிலையில் நடத்தப்பட வேண்டும். கூடுதலாக, எல்லா கிறிஸ்தவ தலைவர்களும், அவர்களுக்கு உதவி செய்பவர்கள் கிறிஸ்தவர்களாக இருந்தாலும் இல்லாவிட்டாலும், அவர்களுக்காக வேலை செய்பவர்கள் நடத்தப்பட வேண்டிய நிலையை அளிக்க தேவனே பொறுப்பேற்கிறார் என்பதை அங்கீகரிக்க வேண்டும். அவர்கள் செய்த செயல்களுக்கு அவர்கள் இறுதியில் தேவனுக்கு பதிலளிக்க வேண்டும் (கொலோசெயர் 4:1).</p><p>சுமார் கி.பி. 45-47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 50 - எருசலேம் கவுன்சில்</p><p>சுமார் கி.பி.51-53 - பவுலின் இரண்டாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 54-58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 58 - பவுல் எருசலேமில் கைதாதல்</p><p>சுமார் கி.பி. 61-62 - பவுல் ரோமச் சிறையில்; பிலேமோன் நிருபம்</p><p>எழுதப்படல்</p><p>சுமார் கி.பி. 67 - பவுல் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 57-வது நூல்</p><p>அதிகாரம் - 1</p><p>வசனங்கள் - 25</p><p>கேள்வி - 1</p>'),
 (650,'<p><b>எபிரேயருக்கு எழுதின நிருபம்</b></p><p><b>எழுத்தாளர்:</b></p><p>அப்போஸ்தலனாகிய பவுலின் எழுத்துக்களில் எபிரெயர் புத்தகத்தை சிலர் உள்ளடக்கியிருந்தாலும், எழுத்தாளர் யார் என்பதைக் குறித்து குறிப்பாக அடையாளம் கண்டுகொள்வதென்பது ஒரு புதிராகவே உள்ளது. பவுலின் வழக்கமான வழ்த்துரையானது அவரது மற்ற அனைத்து எழுத்துக்களுக்கும் பொதுவானதாகும், அது இந்த நிருபத்தில் காணாமல்போய்விட்டது. கூடுதலாக, இந்த நிருபத்தின் எழுத்தாளர் கிறிஸ்து இயேசுவின் உண்மையான நேரில் கண்ட சாட்சிகளாக இருந்த மற்றவர்கள் வழங்கிய அறிவு மற்றும் தகவல்களை நம்பியிருந்தார் என்கிற கருத்து (2:3) பவுலின் எழுத்துக்கள் தான் இந்த நிருபம் என்பது மேலும் சந்தேகத்திற்குரியதாக ஆக்குகிறது. சிலர் லூக்காவை இதன் எழுத்தாளர் என்று கூறுகிறார்கள்; மற்றவர்கள் இந்த நிருபமானது அப்பொல்லோ, பர்னபா, சீலா, பிலிப்பு அல்லது ஆக்கில்லா மற்றும் பிரிஸ்கில்லா எழுதியிருக்கலாம் என்று கூறுகிறார்கள். பேனாவைப் பிடித்த மனித கையைப் பொருட்படுத்தாமல், தேவனுடைய பரிசுத்த ஆவியானவர் எல்லா வேதவாக்கியங்களையும் எழுதிய தெய்வீக எழுத்தாளர் என்கிற நிலையில் இருக்கிறார் (2 தீமோத்தேயு 3:16); ஆகையால், வேதாகமத்தின் மற்ற அறுபத்தைந்து புத்தகங்களைப் போலவே இந்த நிருபமும் அதே நியமன அதிகாரத்துடன் பேசுகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>ஆரம்பகால திர்ச்ச்சபையின் பிதாக்களில் ஒருவராகிய கிளெமென்ட் என்பவர் கி.பி 95-ல் எபிரெயர் புத்தகத்திலிருந்து மேற்கோள் காட்டியிருக்கிறார். எனினும், நிருபம் எழுதப்பட்ட நேரத்தில் தீமோத்தேயு உயிருடன் இருந்தார் என்பதும், பழைய ஏற்பாட்டின் ஆசாரிய முறைமைகளின் முடிவைக் காட்டும் கி.பி. 70-ல் எருசலேமின் அழிவுடன் ஏற்பட்ட எந்த ஆதாரமும் இல்லாதது போன்ற உள்ளான சான்றுகள், இந்த நிருபமானது கி.பி. 65-ல் புத்தகம் எழுதப்பட்டதைக் குறிக்கிறது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>கிறிஸ்தவ ஆராய்ச்சி நிறுவனத்தின் நிறுவனர் மற்றும் சிறந்த விற்பனையான புத்தகமான கிங்டம் ஆஃப் தி கல்ட்ஸ் (Kingdom of the Cults) என்னும் புத்தகத்தின் எழுத்தாளர் மறைந்த டாக்டர் வால்டர் மார்ட்டின் தனது வழக்கமான எதுகை மோனை சொல்லாற்றலில் இந்த நிருபத்தை விவரித்தார், அதாவது எபிரேயர் புத்தகம் எபிரேயனால் பிற எபிரேயர்கள் எபிரேயர்களைப் போல நடந்துகொள்ளுவதை நிறுத்தும்படி எபிரேயர்களுக்கு எழுதப்பட்டது என்று விவரித்தார். உண்மையில், ஆரம்பகால யூத விசுவாசிகளில் பலர் பெருகிவரும் உபத்திரவம் மற்றும் துன்புறுத்தல்களிலிருந்து தப்பிப்பதற்காக யூத மதத்தின் ஆசரிப்புகள் மற்றும் சடங்குகளில் மீண்டும் நழுவிக் கொண்டிருந்தார்கள். இந்த நிருபம், உபத்திரவப்படுத்தப்பட்ட விசுவாசிகளை இயேசு கிறிஸ்துவின் கிருபையில் தொடர அறிவுறுத்துகிறது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>எபிரெயர் 1:1-2, \"பூர்வகாலங்களில் பங்குபங்காகவும் வகைவகையாகவும், தீர்க்கதரிசிகள் மூலமாய்ப் பிதாக்களுக்குத் திருவுளம்பற்றின தேவன், இந்தக் கடைசி நாட்களில் குமாரன் மூலமாய் நமக்குத் திருவுளம்பற்றினார்; இவரைச் சர்வத்துக்கும் சுதந்தரவாளியாக நியமித்தார், இவரைக்கொண்டு உலகங்களையும் உண்டாக்கினார்.\"</p><p>எபிரெயர் 2:4, \"இவ்வளவு பெரிதான இரட்சிப்பைக்குறித்து நாம் கவலையற்றிருப்போமானால் தண்டனைக்கு எப்படித் தப்பித்துக்கொள்ளுவோம்.\"</p><p>எபிரெயர் 4:14-16, \"வானங்களின் வழியாய்ப் பரலோகத்திற்குப்போன தேவகுமாரனாகிய இயேசு என்னும் மகா பிரதான ஆசாரியர் நமக்கு இருக்கிறபடியினால், நாம் பண்ணின அறிக்கையை உறுதியாய்ப் பற்றிக்கொண்டிருக்கக்கடவோம். நம்முடைய பலவீனங்களைக்குறித்துப் பரிதபிக்கக்கூடாத பிரதான ஆசாரியர் நமக்கிராமல், எல்லாவிதத்திலும் நம்மைப்போல் சோதிக்கப்பட்டும், பாவமில்லாதவராயிருக்கிற பிரதான ஆசாரியரே நமக்கிருக்கிறார். ஆதலால், நாம் இரக்கத்தைப் பெறவும், ஏற்ற சமயத்தில் சகாயஞ்செய்யுங்கிருபையை அடையவும், தைரியமாய்க் கிருபாசனத்தண்டையிலே சேரக்கடவோம்.\"</p><p>எபிரெயர் 11:1, \"விசுவாசமானது நம்பப்படுகிறவைகளின் உறுதியும், காணப்படாதவைகளின் நிச்சயமுமாயிருக்கிறது.\"</p><p>எபிரெயர் 12:1-2, \"ஆகையால், மேகம்போன்ற இத்தனை திரளான சாட்சிகள் நம்மைச் சூழ்ந்துகொண்டிருக்க, பாரமான யாவற்றையும், நம்மைச் சுற்றி நெருங்கி நிற்கிற பாவத்தையும் தள்ளிவிட்டு, விசுவாசத்தைத் துவக்குகிறவரும் முடிக்கிறவருமாயிருக்கிற இயேசுவை நோக்கி, நமக்கு நியமித்திருக்கிற ஓட்டத்தில் பொறுமையோடே ஓடக்கடவோம்; அவர் தமக்குமுன் வைத்திருந்த சந்தோஷத்தின்பொருட்டு, அவமானத்தை எண்ணாமல், சிலுவையைச் சகித்து, தேவனுடைய சிங்காசனத்தின் வலதுபாரிசத்தில் வீற்றிருக்கிறார்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>எபிரேயருக்கு எழுதின நிருபம் மூன்று தனித்தனி குழுக்களை மையைப்படுத்தி உரையாற்றுகிறது: முதலாவதாக கிறிஸ்துவை விசுவாசிப்பவர்கள், இரண்டாவதாக அறிவைக் கொண்ட மற்றும் கிறிஸ்துவின் உண்மைகளை அறிவார்ந்த முறையில் ஏற்றுக்கொண்ட அவிசுவாசிகள், இறுதியாக கிறிஸ்துவிடமாக ஈர்க்கப்பட்ட அவிசுவாசிகள், ஆனால் முடிவில் அவர்கள் அவரை நிராகரித்தவர்கள். இந்த மூன்று குழுக்களில் எந்தக் குழுவில் உள்ளவர்களுக்கு எந்த செய்தியானது உரையாற்றப்படுகிறது என்பதைப் புரிந்துகொள்வது மிகவும் முக்கியம். அவ்வாறு செய்யத் தவறினால், மற்ற வேதவசனங்களுடன் பொருந்தாத முடிவுகளை அல்லது அர்த்தங்களை எடுக்க நேரிடும்.</p><p>எபிரேயர் நிருபத்தின் எழுத்தாளர் கிறிஸ்துவின் மேலாலான தன்மை மற்றும் நிலையை அவரது ஊழியப் பணிகள் மற்றும் நபரில் தொடர்ந்து குறிப்பிட்டு விளக்குகிறார். பழைய ஏற்பாட்டின் எழுத்துக்களில், யூத மதத்தின் சடங்குகள் மற்றும் ஆசரிப்புகள் மேசியாவின் வருகையை அடையாளமாக சுட்டிக்காட்டுகின்றன. வேறு வார்த்தைகளில் கூறுவதானால், யூத மதத்தின் சடங்குகள் அனைத்து ஆசரிப்பு முறைமைகளும் இனி வரவிருக்கும் விஷயங்களின் நிழல்கள் மட்டுமே. வெறும் மதம் வழங்கும் எதையும் விட கிறிஸ்து இயேசு சிறந்தவர் என்று எபிரேயர் புத்தகம் சொல்லுகிறது. கிறிஸ்து இயேசுவின் நபர், வேலை மற்றும் ஊழியத்துடன் ஒப்பிடுகையில் மதத்தின் அனைத்து ஆடம்பரங்களும் சூழ்நிலைகளும் மங்கலாகிப்போகின்றன. ஆகவே, நம்முடைய கர்த்தராகிய இயேசுவின் மேலான நிலை மற்றும் தன்மையே இந்த சொற்பொழிவாக எழுதப்பட்ட நிருபத்தின் கருப்பொருளாக இருக்கிறது.</p><p><b>இணைப்புகள்:</b></p><p>எபிரெயர் புத்தகமானது பழைய ஏற்பாட்டைக் குறித்து கவனம் செலுத்துவதுபோல புதிய ஏற்பாட்டில் வேறு எங்கும் எந்த புத்தகமும் அதிக கவனம் செலுத்தவில்லை, அதன் அடித்தளமாக லேவியர்களின் ஆசாரியத்துவம் உள்ளது. எபிரேயர் நிருபத்தின் எழுத்தாளர் பழைய ஏற்பாட்டின் பலி முறைமையின் போதாமைகளை கிறிஸ்துவில் முழுமையுடனும் பரிபூரண நிறைவுடனும் தொடர்ந்து ஒப்பிடுகிறார். பழைய உடன்படிக்கைக்கு உட்பட்டு ஒரு மனித ஆசாரியனால் வழங்கப்படும் / ஏறெடுக்கப்படும் பாவத்திற்கான தொடர்ச்சியான பலிகளும் வருடத்திற்கு ஒரு முறை செலுத்தப்படும் பாவநிவாரணமும் தேவைப்படுமானால், புதிய உடன்படிக்கை கிறிஸ்துவின் மூலமாக அனைவருக்கும் ஒரேஒரு முறை மட்டும் பலியை வழங்குகிறது (எபிரெயர் 10:10) மற்றும் தேவனுடைய கிருபாசனத்திற்கு நேரடி அணுகல் அவரிடத்தில் உள்ள அனைவருக்கும் கிடைக்கும்படிச் செய்தது.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>அடித்தள கிறிஸ்தவ கோட்பாட்டில் மேலான உபதேசங்களைக் கொண்ட எபிரேயருக்கு எழுதின நிருபம், தேவனுடைய \"விசுவாச வீரர்களின் / வீராங்கனைகளின்\" ஆறுதலளிக்கும் எடுத்துக்காட்டுகளையும் நமக்குத் தருகிறது, அவர்கள் பெரும் சிரமங்கள், பாடுகள் மற்றும் பாதகமான சூழ்நிலைகளுக்கு மத்தியிலும் விடாமுயற்சியுடன் தேவனுக்காக விசுவாசமாக இருந்தனர் (எபிரெயர் 11). தேவனுடைய விசுவாச மண்டபத்திலுள்ள இந்த உறுப்பினர்கள் தேவனுடைய நிபந்தனையற்ற உறுதி மற்றும் முழுமையான நம்பகத்தன்மைக்கு ஏராளமான ஆதாரங்களை வழங்குகிறார்கள். அதேபோல், நம்முடைய பழைய ஏற்பாட்டுப் பரிசுத்தவான்களின் வாழ்க்கையில் தேவனுடைய செயற்பாடுகளின் உறுதியான விசுவாசத்தை தியானிப்பதன் மூலம், நம்முடைய சூழ்நிலைகளைப் பொருட்படுத்தாமல், தேவனுடைய வளமான வாக்குறுதிகள் மீது நாம் நம்முடைய முழுமையான நம்பிக்கையைத் தக்கவைத்துக் கொள்ள முடியும்.</p><p>எபிரேயருக்கு எழுதின நிருபத்தின் எழுத்தாளர் விசுவாசிகளுக்கு ஏராளமான ஆறுதலையும் உற்சாகத்தையும் அளிக்கிறார், ஆனால் நாம் கவனிக்க வேண்டிய ஐந்து பவித்திரமான எச்சரிக்கைகள் உள்ளன. புறக்கணிப்பின் ஆபத்து (எபிரெயர் 2: 1-4), அவநம்பிக்கையின் ஆபத்து (எபிரெயர் 3:7–4: 13), ஆவிக்குரிய முதிர்ச்சியில்லாமையின் ஆபத்து (எபிரெயர் 5:11–6: 20), தொடர்ந்து சகித்துக்கொள்ளாமல் தோல்வியடையும் ஆபத்து (எபிரெயர் 10:26-39), தேவனை மறுப்பதன் உள்ளார்ந்த ஆபத்து (எபிரெயர் 12: 25-29) ஆகிய எச்சரிக்கைகள் உள்ளன. ஆகவே, இந்த முடிசூட்டப்பட்ட தலைசிறந்த இலக்கியப் படைப்பில் ஒரு சிறந்த கோட்பாடு, புத்துணர்ச்சியூட்டும் ஊக்கமளிக்கும் வசந்தம், மற்றும் நம்முடைய கிறிஸ்தவ நடைப்பயணத்தில் சோம்பலுக்கு எதிராகயுள்ள அறைகூவல், நடைமுறை எச்சரிக்கைகள் ஆகியவற்றைக் காணலாம். ஆனால் இன்னும் பல உள்ளன, ஏனென்றால் எபிரேயர் புத்தகத்தில் நம்முடைய கர்த்தராகிய இயேசு கிறிஸ்துவின் அற்புதமான சித்திரத்தை நாம் காண்கிறோம் - நம்முடைய பெரிதான இரட்சிப்பினைத் துவக்குகிறவரும் முடிக்கிறவருமாயிருக்கிறார் (எபிரெயர் 12:2).</p><p>சுமார் கி.பி. 45-47 - பவுலின் முதல் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 51-53 - பவுலின் இரண்டாம் arab. மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 51 - லூக்கா பவுலுடன் இணைதல்</p><p>சுமார் கி.பி. 54-58 - பவுலின் மூன்றாம் மிஷனரிப் பயணம்</p><p>சுமார் கி.பி. 58 - பவுல் எருசலேமில் சிறையாதல்</p><p>சுமார் கி.பி.61-62 - பவுல் ரோமச் சிறையில்</p><p>சுமார் கி.பி. 63 - பவுல் விடுதலை பெறலும் சுற்றுப் பயணமும்</p><p>சுமார் கி.பி. 66 - பவுல் மீண்டும் கைது செய்யப்படல் எபிரெய நிருபம் எழுதுதல் (?)</p><p>சுமார் கி.பி. 67 - பவுல் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பவுல் (சிறியவர்)</p><p>வேறு பெயர் - சவுல் (கேட்டுப் பெற்ற)</p><p>தகப்பன் பெயர் - தெரியவில்லை</p><p>ஊர் - தர்சு (அப் 11 : 25), ரோமக் குடியுரிமை பெற்றவர். எருசலேமில் வளர்ச்சி. அந்தியோகியாவை மையமாகக் கொண்டு திருப்பணி பயணங்கள்</p><p>உறவினர் - சகோதரியின் மகன் (அப் 23 : 16)</p><p>கல்வி - கமாலியேலின் குருகுலத்தில் நியாயப்பிரமாண பண்டித கல்வி</p><p>குலம் - எபிரெயர், பென்யமீன் கோத்திரம்</p><p>தொழில் - கூடாரத் தொழில்: பரிசேயப் பணி; நசரேய மார்க்கத்தாரை ஒழித்தல் பின்பு சுவிசேஷம் பிரசங்கித்து சபைகளை நிறுவுதல்</p><p>திருப்பு முனை - தமஸ்கு பாதையில் கர்த்தர் ஒளியில் சந்தித்தல்</p><p>சாதனைகள் - சுமார் 14 நிருபங்களை எழுதியது</p><p>சிறப்பு பெயர் - \"சுவிசேஷ படைத்தளபதி\" \"திரளான வெளிப்பாடுகளைப் பெற்ற அப்போஸ்தலர்’ \"புறஜாதிகளின் அப்போஸ்தலர்’</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 58-வது நூல்</p><p>அதிகாரங்கள் - 13</p><p>வசனங்கள் - 303</p><p>கேள்விகள் - 17</p><p>வரலாற்று வசனங்கள் - 270</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 9</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 24</p>'),
 (660,'<p><b>யாக்கோபின் நிருபம்</b></p><p><b>எழுத்தாளர்:</b></p><p>இந்த நிருபத்தின் (கடிதத்தின்) எழுத்தாளர் யாக்கோபு, இவர் நேர்மையுள்ள யாக்கோபு என்றும் அழைக்கப்படுகிறார், இவர் இயேசு கிறிஸ்துவின் சகோதரர் என்றும் கருதப்படுகிறார் (மத்தேயு 13:55; மாற்கு 6:3). ஆண்டவராகிய இயேசு கிறிஸ்துவின் உயிர்த்தெழுதல் வரை யாக்கோபு ஒரு விசுவாசி அல்ல (யோவான் 7: 3-5; அப்போஸ்தலர் 1:14; 1 கொரிந்தியர் 15:7; கலாத்தியர் 1:19). அவர் எருசலேமில் உண்டாயிருந்த திருச்சபையின் தலைவராக இருந்தார், இவர் முதலில் திருச்சபையின் தூணாக இருந்ததாகக் குறிப்பிடப்படுகிறார் (கலாத்தியர் 2:9).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>யாக்கோபின் புத்தகம் புதிய ஏற்பாட்டின் மிகப் பழமையான புத்தகமாகும், அதாவது இது கி.பி. 45-ல் எழுதப்பட்டதாகும், குறிப்பாக எருசலேமின் முதல் ஆலோசனை சங்கத்தின் கூடுகைக்கு முன்பு அதாவது கி.பி. 50-ற்கு முன்பாகவே எழுதப்பட்டதாகும். வரலாற்றாசிரியர் ஜோசிப்பஸின் கூற்றுப்படி, யாக்கோபு ஏறக்குறைய கி.பி. 62-ல் இரத்தச் சாட்சியாக தனது மரணத்தைத் தழுவினார்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>விசுவாசத்தைப் பற்றிய பவுலினுடைய போதனையின் மிகைப்படுத்தப்பட்ட விளக்கத்திற்கு பதிலளிக்கும் விதமாக இந்த நிருபம் எழுதப்பட்டதாக சிலர் நினைக்கிறார்கள். ஆண்டினோமியனிசம் என்று அழைக்கப்படும் இந்த தீவிர பார்வை, கிறிஸ்துவை விசுவாசிப்பதன் மூலம் ஒருவர் பழைய ஏற்பாட்டு நியாயப்பிரமாண சட்டம், அனைத்து பாரம்பரிய பழக்கவழக்கங்கள், அனைத்து மதச்சார்பற்ற சட்டங்கள் மற்றும் ஒரு சமூகத்தின் அனைத்து ஒழுக்கநெறிகளிலிருந்தும் முற்றிலும் விடுபட்டுள்ளார்கள் என்று போதித்து வந்தனர். யாக்கோபின் புத்தகம் எல்லா நாடுகளிலும் சிதறியுள்ள யூத கிறிஸ்தவர்களுக்கு எழுதி அனுப்பப்பட்டதாகும் (யாக்கோபு 1:1). இந்த நிருபத்தை வெறுத்து, அதை ஒரு \"வைக்கோலின் நிருபம்\" என்று மார்ட்டின் லூதர் அழைத்தார், கிரியைகளைப் பற்றிய யாக்கோபின் போதனையானது பவுலுடைய விசுவாசத்தைப் பற்றிய போதனையோடு முரண்படவில்லை மாறாக அதைப் பூர்த்தி செய்கிறதாக இருக்கிறது என்பதை மார்ட்டின் லூத்தர் சரிவரப் புரிந்துகொள்ளாமல் போனார். பவுலின் போதனைகள் தேவனோடு நாம் நீதிமானாக்கப்படுதலில் கவனம் செலுத்துகையில், யாக்கோபின் நிருபத்திலுள்ள போதனைகள் அந்த நீதிமானாக்கப்படுதலை எடுத்துக்காட்டுகின்ற அல்லது வெளிக்கொணர்கிற கிரியைகளில் கவனம் செலுத்துகின்றன. இந்த புதிய கிறிஸ்தவ விசுவாசத்தில் தொடர்ந்து வளர ஊக்குவிப்பதற்காக யூதர்களுக்கு யாக்கோபு இந்த நிருபத்தை எழுதினார். ஆவியானவரால் நிரப்பப்பட்டவர்களிடமிருந்து நல்ல செயல்கள் அல்லது நற்கிரியைகள் இயல்பாகவே புறப்பட்டு வரும் என்று யாக்கோபு வலியுறுத்துகிறார், கலாத்தியர் 5:22-23-ல் பவுல் விவரிக்கிற ஆவியின் கனிகளைக் காண முடியாவிட்டால் ஒருவருக்கு அவருடைய இரட்சிப்பு நம்பிக்கை மெய்யாகவே இருக்கக்கூடுமா இல்லையா என்று யாக்கோபு கேள்வி எழுப்புகிறார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>யாக்கோபு 1:2-3, \"என் சகோதரரே, நீங்கள் பலவிதமான சோதனைகளில் அகப்படும்போது, உங்கள் விசுவாசத்தின் பரீட்சையானது பொறுமையை உண்டாக்குமென்று அறிந்து, அதை மிகுந்த சந்தோஷமாக எண்ணுங்கள்.\"</p><p>யாக்கோபு 1:19, \"ஆகையால், என் பிரியமான சகோதரரே, யாவரும் கேட்கிறதற்குத் தீவிரமாயும், பேசுகிறதற்குப் பொறுமையாயும், கோபிக்கிறதற்குத் தாமதமாயுமிருக்கக்கடவர்கள்.\"</p><p>யாக்கோபு 2:17-18, \"அப்படியே விசுவாசமும் கிரியைகளில்லாதிருந்தால் தன்னிலேதானே செத்ததாயிருக்கும். ஒருவன்: உனக்கு விசுவாசமுண்டு, எனக்குக் கிரியைகளுண்டு; கிரியைகளில்லாமல் உன் விசுவாசத்தை எனக்குக்காண்பி, நான் என் விசுவாசத்தை என் கிரியைகளினாலே உனக்குக் காண்பிப்பேன் என்பானே.\"</p><p>யாக்கோபு 3:5, \"அப்படியே, நாவானதும் சிறிய அவயவமாயிருந்தும் பெருமையானவைகளைப் பேசும். பாருங்கள், சிறிய நெருப்பு எவ்வளவு பெரிய காட்டைக் கொளுத்திவிடுகிறது!\"</p><p>யாக்கோபு 5:16, \"நீதிமான் செய்யும் ஊக்கமான வேண்டுதல் மிகவும் பெலனுள்ளதாயிருக்கிறது.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>மெய்யான மதத்தின் நடப்பைக் குறித்து (1:1-27), மெய்யான நம்பிக்கை (2:1-3:12) மற்றும் மெய்யான ஞானம் (3:13-5: 20) ஆகியவற்றின் மூலம் விசுவாசம் நடப்பை யாக்கோபின் புத்தகம் கோடிட்டுக் காட்டுகிறது. இந்த புத்தகத்தில் மத்தேயு 5-7 வரையிலுள்ள இயேசுவின் மலைப்பிரசங்கத்திற்கு ஒரு குறிப்பிடத்தக்க இணையானதாக உள்ளது. யாக்கோபு முதல் அதிகாரத்தில் விசுவாச நடைப்பயணத்தின் ஒட்டுமொத்த பண்புகளை விவரிப்பதன் மூலம் தொடங்குகிறார். இரண்டாம் அதிகாரத்திலும், மூன்றாம் அதிகாரத்தின் தொடக்கத்திலும் அவர் சமூக நீதி மற்றும் செயலில் உள்ள விசுவாசத்தைப் பற்றி விவரிக்கிறார். பின்னர் அவர் உலக மற்றும் தெய்வீக ஞானத்திற்கு இடையிலான வேறுபாட்டை ஒப்பிட்டுப் பார்க்கிறார், மேலும் தீமையிலிருந்து விலகி தேவனிடமாய் நெருங்கி வரும்படி கேட்கிறார். பதுக்கி வைத்திருக்கும் பணக்காரர்களுக்கும், தன்னம்பிக்கை உடையவர்களுக்கும் யாக்கோபு குறிப்பாக கடுமையான கண்டனத்தைத் தருகிறார். கடைசியாக அவர் பாடநுபவிக்கிற விசுவாசிகளுக்கு ஜெபம் மற்றும் ஒருவரையொருவர் கருதிக்கொள்வது மற்றும் கூட்டுறவு ஐக்கியம் மூலம் நம் விசுவாசத்தை உயர்த்துவதில் ஊக்கமளிக்கிறார்.</p><p><b>இணைப்புகள்:</b></p><p>விசுவாசத்திற்கும் கிரியைகளுக்கும் இடையிலான உறவின் இறுதி விளக்கமே யாக்கோபின் புத்தகம். மோசேயின் நியாயப்பிரமாணத்திலும் அதன் செயற்பாடுகளிலும் ஆழமாகப் பதிந்த யூத கிறிஸ்தவர்கள், நியாயப்பிரமாண சட்டத்தின் செயல்களால் யாரும் நீதிமானாக்கப்படுவதில்லை என்கிற கடினமான சத்தியத்தை விளக்குவதற்கு கணிசமான நேரத்தை செலவிட்டு யாக்கோபு இந்த நிருபத்தை எழுதுகிறார் (கலாத்தியர் 2:16). பல்வேறு நியாயப்பிரமாண சட்டங்களையும் சடங்குகளையும் கடைப்பிடிக்க அவர்கள் மிகுந்த முயற்சி செய்தாலும், அவ்வாறு செய்வது சாத்தியமற்றது என்றும், அந்த சட்டத்தின் மிகச்சிறிய பகுதியை மீறுவது அவர்கள் அனைவரையும் குற்றவாளியாக்கும் என்றும் அவர் அறிவிக்கிறார் (யாக்கோபு 2:10), ஏனெனில் நியாயப்பிரமாண சட்டம் என்பது ஒரு முழு பகுதியாகும், அதன் ஒரு பகுதியை உடைப்பது எல்லாவற்றையும் உடைக்கிறதற்கு சமமாகும்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>இயேசு கிறிஸ்துவின் மெய்யான சீஷர்களுக்கு \"பேச்சு பேசுவது\" மட்டுமல்ல, \"நடைமுறைப்படுத்தும் பயிற்சி\" செய்வதும் ஒரு சவாலாக இருக்கிறது என்பதை யாக்கோபின் புத்தகத்தில் காண்கிறோம். நம்முடைய விசுவாசம் நடக்கும்போது, உறுதியாக இருக்க, அதைப் பற்றிய அறிவின் வளர்ச்சியின் வார்த்தை தேவைப்படுகிறது, ஆகவே யாக்கோபு அங்கே நிறுத்த வேண்டாம் என்று நம்மை அறிவுறுத்துகிறார். 108 வசனங்களில் யாக்கோபு நாம் நிறைவேற்ற வேண்டிய அல்லது கைக்கொள்ளவேண்டிய 60 பொறுப்புக்களை/ கடமைகளை முன்வைப்பதால் பல கிறிஸ்தவர்கள் இந்த நிருபத்தை ஒரு சவாலாகக் காண்பார்கள். அவர் மலைப்பிரசங்கத்தில் இயேசுவின் வார்த்தைகளின் சத்தியத்தில் கவனம் செலுத்துகிறார், மேலும் அவர் கற்பித்தவற்றின் அடிப்படையில் செயல்படவும் நம்மைத் தூண்டுகிறார்.</p><p>ஒருவர் கிறிஸ்தவராக மாறலாம், ஆனால் அதேவேளையில் அவர் தொடர்ந்து பாவத்திலும் வாழலாம் என்றும் அப்படிப்பட்ட வாழ்க்கை நீதியின் பலனை வெளிப்படுத்தாது என்கிற கருத்தையும் இந்த நிருபம் முன் வைக்கிறது. அத்தகைய \"விசுவாசம்\" \"விசுவாசித்து நடுங்கும்\" பிசாசுகளால் பகிரப்படுகிறது (யாக்கோபு 2:19). ஆயினும் அத்தகைய \"விசுவாசத்தினால்\" இரட்சிக்க முடியாது, ஏனென்றால் உண்மையான இரட்சிப்பானது விசுவாசத்துடன் எப்போதும் வரும் செயல்களால் அல்லது கிரியைகளால் அது சரிபார்க்கப்படவில்லை (எபேசியர் 2:10). நற்கிரியைகளானது இரட்சிப்பின் காரணம் அல்ல, ஆனால் அவைகள் அதன் விளைவுகளாகும்.</p><p>சுமார் கி.பி. 29/30 - கிறிஸ்துவின் மரண உயிர்ப்பு</p><p>சுமார் கி.பி. 44 - யாக்கோபு சபைப் பொறுப்பில் இருக்கிறார்</p><p>சுமார் கி.பி.45-49 - யாக்கோபு நிருபம் எழுதப்படல்</p><p>சுமார் கி.பி. 50. - எருசலேம் கவுன்சில்</p><p>சுமார் கி.பி. 62 - எருசலேமில் கல்லெறிந்து கொல்லப்படல் (?)</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - யாக்கோபு</p><p>குடும்பம் - தந்தை/ யோசேப்பு - தாய் /மரியாள் - சகோதரர்கள் - யோசே, சீமோன், யூதா சகோதரிகள் பலர் உண்டு (மத் 13 : 55)</p><p>பணி - எருசலேம் சபையில் மூப்பராக இருந்தார் (அப் 12 : 17, 15 : 13-21, 21: 8. கலா 2:9.12)</p><p>திருப்புமுனை - கிறிஸ்துவின் உயிர்த்தெழுதலின் பின்பு இரட்சிக்கப்படுதல்</p><p>படைப்பு - யாக்கோபு எழுதிய நிருபம்</p><p>சிறப்புபெயர் - புதிய ஏற்பாட்டின் ஆமோஸ்</p><p>முடிவு - பரம்பரை நம்பிக்கைப்படி எருசலேமில் கல்லெறிந்து கொல்லப்பட்டார்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் - 59 வது நூல்</p><p>அதிகாரங்கள் - 5</p><p>வசனங்கள் - 108</p><p>கேள்விகள் - 24</p><p>வரலாற்று வசனங்கள் - 100</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 8</p>'),
 (670,'<p><b>1 பேதுருவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>1 பேதுரு 1:1-ல் குறிப்பிடப்பட்டுள்ள \"இயேசுகிறிஸ்துவின் அப்போஸ்தலனாகிய பேதுரு\" என்னும் சொற்றொடர், 1 பேதுரு புத்தகத்தின் எழுத்தாளரை அப்போஸ்தலனாகிய பேதுரு என்று தெளிவாக அடையாளம் காட்டுகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>1 பேதுருவின் புத்தகம் கி.பி. 60 முதல் கி.பி. 65 வரையிலுள்ள காலங்களில் எழுதப்பட்டிருக்கலாம்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>1 பேதுரு புத்தகம் பண்டைய உலகம் முழுவதும் அதாவது திருச்சபையின் ஆரம்ப நாட்களில் சிதறி கலைந்துபோன மற்றும் கடுமையான உபத்திரவத்திற்கு ஆளான விசுவாசிகளுக்கு பேதுரு எழுதிய கடிதமாகும். உபத்திரவத்தை யாராவது புரிந்து கொண்டாரென்றால், அது பேதுருவேயாகும். தேவனுடைய வார்த்தையைப் பிரசங்கித்ததற்காக அவர் அடித்து, அச்சுறுத்தப்பட்டு, தண்டிக்கப்பட்டு சிறையில் அடைக்கப்பட்டார். கசப்பு இல்லாமல், தனது விசுவாசத்தையும் நம்பிக்கையையும் இழக்காமல், மிகுந்த விசுவாசத்துடன் கீழ்ப்படிதலான, வெற்றிகரமான வாழ்க்கையை வாழ்வதற்கு என்ன தேவை என்பதை அவர் அறிந்திருந்தார். இயேசுவில் வாழும் நம்பிக்கையைப் பற்றிய இந்த அறிவு செறிந்த செய்தி மற்றும் கிறிஸ்துவின் முன்மாதிரி மெய்யாகவே பின்பற்றப்பட வேண்டியதாகும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>1 பேதுரு 1:3-4, \"நம்முடைய கர்த்தராகிய இயேசுகிறிஸ்துவின் பிதாவாகிய தேவனுக்கு ஸ்தோத்திரம் உண்டாவதாக; அவர், இயேசுகிறிஸ்து மரித்தோரிலிருந்து எழுந்ததினாலே, அழியாததும் மாசற்றதும் வாடாததுமாகிய சுதந்தரத்திற்கேதுவாக, ஜீவனுள்ள நம்பிக்கை உண்டாகும்படி, தமது மிகுந்த இரக்கத்தின்படியே நம்மை மறுபடியும் ஜெநிப்பித்தார்.\"</p><p>1 பேதுரு 2:9, \"நீங்களோ, உங்களை அந்தகாரத்தினின்று தம்முடைய ஆச்சரியமான ஒளியினிடத்திற்கு வரவழைத்தவருடைய புண்ணியங்களை அறிவிக்கும்படிக்குத் தெரிந்துகொள்ளப்பட்ட சந்ததியாயும், ராஜரீகமான ஆசாரியக்கூட்டமாயும், பரிசுத்த ஜாதியாயும், அவருக்குச் சொந்தமான ஜனமாயும் இருக்கிறீர்கள்.\"</p><p>1 பேதுரு 2:24, \"நாம் பாவங்களுக்குச் செத்து, நீதிக்குப் பிழைத்திருக்கும்படிக்கு, அவர்தாமே தமது சரீரத்திலே நம்முடைய பாவங்களைச் சிலுவையின்மேல் சுமந்தார்; அவருடைய தழும்புகளால் குணமானீர்கள்.\"</p><p>1 பேதுரு 5:8-9, \"தெளிந்த புத்தியுள்ளவர்களாயிருங்கள், விழித்திருங்கள்; ஏனெனில், உங்கள் எதிராளியாகிய பிசாசானவன் கெர்ச்சிக்கிற சிங்கம்போல் எவனை விழுங்கலாமோ என்று வகைதேடிச் சுற்றித்திரிகிறான். விசுவாசத்தில் உறுதியாயிருந்து, அவனுக்கு எதிர்த்து நில்லுங்கள்; உலகத்திலுள்ள உங்கள் சகோதரரிடத்திலே அப்படிப்பட்ட பாடுகள் நிறைவேறிவருகிறதென்று அறிந்திருக்கிறீர்களே.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>உபத்திரவத்தின் இந்த நேரம் மிகவும் அவநம்பிக்கையானது என்றாலும், அது உண்மையில் சந்தோஷப்பட வேண்டிய நேரம் என்பதை அப்போஸ்தலனாகிய பேதுரு வெளிப்படுத்துகிறார். அவர்களுடைய இரட்சகர் அவர்களுக்காக அனுபவித்ததைப் போல, கிறிஸ்துவின் நிமித்தம் உபத்திரவப்படுவது ஒரு பாக்கியமானதாக எண்ணவேண்டும் என்று அவர் கூறுகிறார். இந்த கடிதம் இயேசுவுடனான பேதுருவின் தனிப்பட்ட அனுபவங்களையும், அப்போஸ்தலருடைய நடபடிகள் புத்தகத்திலிருந்து அவருடைய பிரசங்கங்களையும் குறிக்கிறது. ஒவ்வொரு கிறிஸ்தவனுக்கும் சாத்தானானவன் பெரும் எதிரியாக இருக்கிறான் என்று பேதுரு உறுதிப்படுத்துகிறார், ஆனால் கிறிஸ்துவின் மீண்டும் வருகிற இரண்டாம் வருகையானது நம்பிக்கையின் உறுதியையும் ஊக்கத்தையும் அளிக்கிறது.</p><p><b>இணைப்புகள்:</b></p><p>பழைய ஏற்பாட்டு நியாயப்பிரமாணம் மற்றும் தீர்க்கதரிசிகள் பற்றிய பேதுருவின் பரிச்சயம், மேசியாவாகிய இயேசு கிறிஸ்துவின் வாழ்க்கை மற்றும் வேலையின் வெளிச்சத்தில் பல்வேறு பழைய ஏற்பாட்டுப் பகுதிகளை விளக்க அவருக்கு உதவியது. 1 பேதுரு 1:16-ல், அவர் லேவியராகமம் 11:44-ஐ மேற்கோள் காட்டுகிறார்: \"நான் பரிசுத்தர், ஆகையால் நீங்களும் பரிசுத்தராயிருங்கள்.\" ஆனால் அவர் அதை நியாயப்பிரமாணத்தைக் கடைப்பிடிப்பதன் மூலம் பரிசுத்தத்தை அடைய முடியாது என்று முன்னுரைக்கிறார், ஆனால் கிறிஸ்துவில் விசுவாசிக்கிற அனைவருக்கும் தேவனுடைய கிருபையால் அது வழங்கப்படுகிறது (வசனம் 13). மேலும், ஏசாயா 28:16 மற்றும் சங்கீதம் 118:22-ல் உள்ள \"மூலக்கல்லை\" கிறிஸ்து என்று பேதுரு விளக்குகிறார், யூதர்களால் கீழ்ப்படியாமை மற்றும் அவிசுவாசம் ஆகியவற்றால் மேசியாவாகிய இயேசு நிராகரிக்கப்பட்டார். கூடுதல் பழைய ஏற்பாட்டு குறிப்புகளில் பாவமில்லாத கிறிஸ்து (1 பேதுரு 2:22 / ஏசாயா 53:9) மற்றும் ஆசீர்வாதங்களைத் தரும் தேவனுடைய வல்லமையால் பரிசுத்த வாழ்க்கைக்கான அறிவுரைகள் (1 பேதுரு 3:10:12; சங்கீதம் 34:12-16; 1 பேதுரு 5:5; நீதிமொழிகள் 3:34).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நித்திய ஜீவனின் உறுதி அனைத்து கிறிஸ்தவர்களுக்கும் வழங்கப்படுகிறது. கிறிஸ்துவுடன் அடையாளம் காண ஒரு வழி, அவருடைய பாடுகளில் பங்கு பெறுவது. நமக்கு அது \"நல்ல இரண்டு காலணிகள்\" அல்லது \"உங்களைவிட விட பரிசுத்தர்\" என்று அழைப்பவர்களிடமிருந்து அவமானங்களையும் அவதூறுகளையும் தாங்குவதாகும். சிலுவையில் கிறிஸ்து நமக்காக அனுபவித்ததை ஒப்பிடும்போது இது மிகவும் சிறியது மற்றும் ஒன்றுமேயில்லை. உங்களுக்குத் தெரிந்தவற்றிற்காக எழுந்து நின்று சரியானது என்று விசுவாசியுங்கள், உலகமும் சாத்தானும் உங்களைத் துன்புறுத்தும் போது மகிழ்ச்சியாயிருங்கள்.</p><p>சுமார் கி.பி. 27 - பேதுரு கிறிஸ்துவிடம் வருதல்</p><p>சுமார் கி.பி. 29/30 - கிறிஸ்துவின் சிலுவை - மரணம் பேதுருவின் பெந்தெகொஸ்து பிரசங்கம்</p><p>சுமார் கி.பி. 50 - எருசலேம் கவுன்சில்</p><p>சுமார் கி.பி. 62-65 - 1 பேதுரு எழுதப்படல்</p><p>சுமார் கி.பி. 65-67 - 2 பேதுரு எழுதப்படல்</p><p>சுமார் கி.பி. 67 - பேதுரு ரோமில் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பேதுரு என்ற சீமோன் கேபா என்றொரு பெயருமுண்டு (1கொரி 9 :5)</p><p>தகப்பனார் பெயர் - யோனா (மத் 16: 17)</p><p>குடும்பம் - மனைவி உண்டு (1கொரி 9 : 5) மாமியாரைப் பற்றிய குறிப்பு உண்டு. அண்ணன் பெயர் அந்திரேயா (யோவா 1:40)</p><p>தொழில் - மீன் பிடித்தல்</p><p>திருப்பு முனை - கிறிஸ்துவின் அழைப்பு</p><p>சிறப்பு பதவி - அப்போஸ்தலர்</p><p>சாதனை - பெந்தெகொஸ்து நாளில் 3,000 பேர் மனந்திரும்பிய பிரசங்கம் நிகழ்த்தியது</p><p>பெலவீனம் - சூழலைக் கண்டு பயந்து கடலில் அமிழ்ந்தது; கிறிஸ்துவை மறுதலித்தது.</p><p>சிறப்பு பெயர் -  யூதர்களின் அப்போஸ்தலர் நம்பிக்கையின் அப்போஸ்தலர்</p><p>படைப்புகள் -  1, 2 பேதுரு நிருபங்கள்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் - 60 வது நூல்</p><p>அதிகாரங்கள் - 5</p><p>வசனங்கள் - 105</p><p>கேள்விகள் - 4</p><p>வரலாற்று வசனங்கள் - 92</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 3</p><p>நிறைவேறாத தீர்க்கதரிசனங்கள் - 10</p>'),
 (680,'<p><b>2 பேதுருவின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>2 பேதுரு 1:1வது வசனத்தில், \"இயேசுகிறிஸ்துவின் ஊழியக்காரனும் அப்போஸ்தலனுமாகிய சீமோன் பேதுரு எழுதுகிறதாவது\" என்னும் குறிப்பிலிருந்து அப்போஸ்தலனாகிய பேதுருதான் 2 பேதுருவின் எழுத்தாளர் என்பது தெளிவாகிறது. புதிய ஏற்பாட்டில் உள்ள வேறு எந்த புத்தகத்தையும் விட 2 பேதுருவின் புத்தகம் மட்டும்தான் இதன் எழுத்தாளரைக் குறித்து அதிக சவால்களை சந்தித்து இருக்கிறது. இருப்பினும், ஆரம்பகால சபை பிதாக்கள் பேதுரு இதை எழுதவில்லை என்று அதை நிராகரிக்க எந்த நல்ல காரணத்தையும் காணவில்லை. நாமும் அவ்வாறே பேதுரு இதை எழுதவில்லை என்று அதை நிராகரிக்க எந்த நல்ல காரணத்தையும் காணவில்லை.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>2 பேதுருவின் புத்தகம் பேதுருவின் வாழ்க்கையின் முடிவில் எழுதப்பட்டதாகும். ரோமச் சக்ரவர்த்தி நீரோவின் காலத்தில் பேதுரு ரோமில் இரத்த சாட்சியாக மரித்ததால், அவரது மரணம் கி.பி. 68-க்கு முன்னர் நிகழ்ந்திருக்க வேண்டும். அப்படியானால் கி.பி. 65 மற்றும் கி.பி. 68-க்கு இடையில் அவர் 2 பேதுரு நிருபத்தை எழுதியிருக்கவேண்டும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>கள்ளப்போதகர்கள் திருச்சபைகளுக்குள் ஊடுருவத் தொடங்குவதாக பேதுரு கவலைப்பட்டார். பரவுகின்ற விசுவாசத் துரோகத்தைக் கண்டறிந்து அவைகளை எதிர்த்துப் போராடுவதற்காக, கிறிஸ்தவர்கள் தங்கள் விசுவாசத்தில் வளரவும் வலிமையாகவும் இருக்கும்படி அவர் அழைப்பு விடுத்தார். தேவனுடைய வார்த்தையின் நம்பகத்தன்மையையும் கர்த்தராகிய இயேசு நிச்சயமாக மீண்டும் திரும்பி வருவதையும் அவர் வலியுறுத்தினார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>2 பேதுரு 1:3-4, \"தம்முடைய மகிமையினாலும் காருணியத்தினாலும் நம்மை அழைத்தவரை அறிகிற அறிவினாலே ஜீவனுக்கும் தேவபக்திக்கும் வேண்டிய யாவற்றையும். அவருடைய திவ்விய வல்லமையானது நமக்குத் தந்தருளினதுமன்றி, இச்சையினால் உலகத்திலுண்டான கேட்டுக்குத் தப்பி, திவ்விய சுபாவத்துக்குப் பங்குள்ளவர்களாகும்பொருட்டு, மகா மேன்மையும் அருமையுமான வாக்குத்தத்தங்களும் அவைகளினாலே நமக்கு அளிக்கப்பட்டிருக்கிறது.\"</p><p>2 பேதுரு 3:9, \"தாமதிக்கிறார் என்று சிலர் எண்ணுகிறபடி கர்த்தர் தமது வாக்குத்தத்தத்தைக்குறித்துத் தாமதமாயிராமல்; ஒருவரும் கெட்டுப்போகாமல் எல்லாரும் மனந்திரும்பவேண்டுமென்று விரும்பி, நம்மேல் நீடிய பொறுமையுள்ளவராயிருக்கிறார்.\"</p><p>2 பேதுரு 3:18, \"நம்முடைய கர்த்தரும் இரட்சகருமாகிய இயேசுகிறிஸ்துவின் கிருபையிலும் அவரை அறிகிற அறிவிலும் வளருங்கள். அவருக்கு இப்பொழுதும் என்றென்றைக்கும் மகிமையுண்டாவதாக. ஆமென்.\"</p><p>இந்த நிருபத்தின் திறவுச்சொல் \"அறிவு\" என்பதாகும்; அதனுடன் தொடர்புடைய சொற்களால், இந்த சொல்லானது 2 பேதுரு புத்தகத்தில் குறைந்தது 13 முறை வருகிறது.</p><p><b>சுருக்கமான திரட்டு:</b></p><p>அவருடைய நேரம் குறைவு என்பதை அறிந்து (2 பேதுரு 1:13-15), இந்த திருச்சபைகள் உடனடி ஆபத்தை எதிர்கொண்டன (2 பேதுரு 2:1-3), வாசகர்களின் நினைவுகளைப் புதுப்பிக்கும்படி இந்த நிருபத்தை எழுதி அவர் அவர்களை அழைத்தார் (2 பேதுரு 1:13 ) மற்றும் அவர்களின் சிந்தனையைத் தூண்டினார் (2 பேதுரு 3:1-2), இதனால் அவர்கள் அவருடைய போதனையை நினைவில் கொள்வார்கள் (2 பேதுரு 1:15). விசுவாசிகளுக்கு குறிப்பிட்ட கிறிஸ்தவ நற்பண்புகளைச் சேர்ப்பதன் மூலம் அவர்களின் விசுவாசத்தில் இன்னும் முதிர்ச்சியடையும்படி அவர் சவால் விடுத்தார், இதன் மூலம் இயேசு கிறிஸ்துவைப் பற்றிய அறிவில் திறம்படவும் பயனுள்ளவராகவும் மாறினார் (2 பேதுரு 1:5-9). பழைய மற்றும் புதிய ஏற்பாட்டின் எழுத்தாளர்கள் தங்கள் விசுவாசத்திற்கான அதிகாரமாக அமைந்தார்கள் (2 பேதுரு 1:12-21, 3:2, 3:15-16). திருச்சபைகளில் நுழைந்து, மோசமாக பாதித்த கள்ளப்போதகர்களை எதிர்த்து நிற்க அவர்கள் விசுவாசத்தில் பலமடைய வேண்டும் என்று பேதுரு விரும்பினார். அவர்களைக் கண்டித்ததில், அவர்களுடைய நடத்தை, கண்டனம் மற்றும் அவற்றின் பண்புகள் (2 பேதுரு அத்தியாயம் 2) ஆகியவற்றை அவர் விவரிக்கிறார், மேலும் அவர்கள் கர்த்தருடைய இரண்டாவது வருகையை கேலி செய்தார்கள் (2 பேதுரு 3:3-7). கிறிஸ்தவர்களைப் பொறுத்தவரை, இரண்டாவது வருகை பரிசுத்த வாழ்க்கைக்கு ஊக்கமளிப்பதாக பேதுரு கற்பித்தார் (2 பேதுரு 3:14). ஒரு இறுதி எச்சரிக்கைக்குப் பிறகு, தங்கள் கர்த்தரும் இரட்சகருமாகிய இயேசு கிறிஸ்துவின் கிருபையிலும் அறிவிலும் வளர பேதுரு மீண்டும் அவர்களை ஊக்குவித்தார். அவர் அவருடைய கர்த்தரும் இரட்சகருமானவருக்கு துதி பாராட்டு வார்த்தையுடன் கூறி முடிக்கிறார் (2 பேதுரு 3:18).</p><p><b>இணைப்புகள்:</b></p><p>கள்ளத் தீர்க்கதரிசிகளைக் கண்டித்ததில், பேதுரு தனது வாசகர்களுக்கு மிகவும் தெரிந்திருக்கிற நடைமுறையிலுள்ள பழைய ஏற்பாட்டு கருப்பொருளை மீண்டும் கூறுகிறார். ஆரம்பகால கிறிஸ்தவர்களில் பலர் யூதர்களாகவும், நியாயப்பிரமாணத்திலும் தீர்க்கதரிசிகளிலும் நன்கு கற்பிக்கப்பட்ட யூதர்களாக மாற்றப்பட்டனர். 2 பேதுரு 1:19-21-ல் பழைய ஏற்பாட்டின் \"தீர்க்கதரிசிகளின் வார்த்தையை\" பேதுரு குறிப்பிட்டபோது, அவர் கள்ளத்தீர்க்கதரிசிகளைக் கண்டித்தார், உண்மையான தீர்க்கதரிசிகள் அவர்கள் மூலமாகப் பேசிய பரிசுத்த ஆவியினால் தூண்டப்பட்டதாக உறுதிப்படுத்தினார் (2 சாமுவேல் 23:2). கள்ளத்தீர்க்கதரிசிகளை விமர்சிப்பதில் எரேமியாவும் சமமாக பலமாக இருந்தார், \"எதுவரைக்கும் இப்படியிருக்கும்? பொய்த்தீர்க்கதரிசனம் சொல்லுகிற தீர்க்கதரிசிகளின் இருதயத்திலே ஏதாகிலுமுண்டோ? இவர்கள் தங்கள் இருதயத்தின் வஞ்சகத்தையே தீர்க்கதரிசனமாகச் சொல்லுகிறவர்கள்\" (எரேமியா 23:26). பழைய மற்றும் புதிய ஏற்பாடுகள் இரண்டிலும் தேவனுடைய ஜனங்களைப் பாதித்த அதே ஏமாற்றப்பட்ட கள்ளப்போதகர்கள் இன்னும் நம்முடன் நம் மத்தியில் இருக்கிறார்கள் என்பது தெளிவாகத் தெரிகிறது, இது பேதுருவின் இரண்டாவது நிருபத்தை 2000 ஆண்டுகளுக்கு முன்பு இருந்ததைப் போலவே இன்றும் பொருத்தமாக ஆக்குகிறது.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நிச்சயமாக, 21-ஆம் நூற்றாண்டில் வாழ்கிற கிறிஸ்தவர்களுக்கு, இந்த நிருபம் எழுதப்பட்ட முதல் நூற்றாண்டு கிறிஸ்தவர்களை விட இன்னும் கூடுதலாக நம்முடைய கர்த்தர் திரும்பி வரும் வருகைக்கு மிக அருகில் நாம் இருக்கிறோம். தொலைக்காட்சி மற்றும் பிற மாபெரும் தகவல்தொடர்புகளின் மூலம், முதிர்ச்சியடைந்த கிறிஸ்தவர்கள் பல கிறிஸ்தவ தலைவர்கள் உண்மையான கிறிஸ்தவ தலைவர்களாக அணிவகுத்து வருகிறார்கள் என்பதையும், முதிர்ச்சியற்ற கிறிஸ்தவர்கள் வேதவசனங்களின் தவறான மற்றும் தவறான விளக்கத்தால் \"உள்ளே அழைத்துச் செல்லப்படுகிறார்கள்\" என்பதையும் அறிந்திருக்கிறார்கள். மறுபடியும் பிறந்த கிறிஸ்தவர்கள் அனைவருமே கர்த்தருடைய வார்த்தையில் மிகவும் அடித்தளமாக இருக்க வேண்டும், அதனால் சத்தியத்தை பிழையிலிருந்து நாம் அறிந்துகொள்ள முடியும்.</p><p>பேதுரு அளித்திருக்கும் விசுவாசத்தின் வளர்ச்சிக்கான அதே மருந்தை (2 பேதுரு 1:5-11), நாம் நம் வாழ்வில் பயன்படுத்தப்படும்போது, \"நம்முடைய கர்த்தரும் இரட்சகருமாகிய இயேசுகிறிஸ்துவினுடைய நித்திய ராஜ்யத்துக்குட்படும்பிரவேசம் உங்களுக்குப் பரிபூரணமாய் அளிக்கப்படும்\" (2 பேதுரு 1:10-11). நம்முடைய விசுவாசத்திற்கான அடித்தளம் எப்போதுமே பேதுரு பிரசங்கித்த தேவனுடைய வார்த்தையாகவே இருக்கும்.</p><p>சுமார் கி.பி. 27 - பேதுரு கிறிஸ்துவிடம் வருதல்</p><p>சுமார் கி.பி. 29/30 - கிறிஸ்துவின் மரணம் சபையின் உருவாக்கம்</p><p>பேதுருவின் பெந்தெகொஸ்து பிரசங்கம்</p><p>சுமார் கி.பி. 50 - எருசலேம் கவுன்சில்</p><p>சுமார் கி.பி. 62-65 - 1 பேதுரு எழுதப்படல்</p><p>சுமார் கி.பி.65-67 - 2 பேதுரு எழுதப்படல்</p><p>சுமார் கி.பி. 67 பேதுரு ரோமில் இரத்த சாட்சியாதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - பேதுரு என்ற சீமோன் கேபா என்றொரு பெயருமுண்டு (1கொரி 9 :5)</p><p>தகப்பனார் பெயர் - யோனா (மத் 16: 17)</p><p>குடும்பம் - மனைவி உண்டு (1கொரி 9 : 5) மாமியாரைப் பற்றிய குறிப்பு உண்டு. அண்ணன் பெயர் அந்திரேயா (யோவா 1:40)</p><p>தொழில் - மீன் பிடித்தல்</p><p>திருப்பு முனை - கிறிஸ்துவின் அழைப்பு</p><p>சிறப்பு பதவி - அப்போஸ்தலர்</p><p>சாதனை - பெந்தெகொஸ்து நாளில் 3,000 பேர் மனந்திரும்பிய பிரசங்கம் நிகழ்த்தியது</p><p>பெலவீனம் - சூழலைக் கண்டு பயந்து கடலில் அமிழ்ந்தது; கிறிஸ்துவை மறுதலித்தது.</p><p>சிறப்பு பெயர் -  யூதர்களின் அப்போஸ்தலர் நம்பிக்கையின் அப்போஸ்தலர்</p><p>படைப்புகள் -  1, 2 பேதுரு நிருபங்கள்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் - 61 வது நூல்</p><p>அதிகாரங்கள் - 3</p><p>வசனங்கள் - 61</p><p>கேள்விகள் - 2</p><p>வரலாற்று வசனங்கள் - 51</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 2</p><p>நிறைவேறாத தீர்க்கதரிசனங்கள் - 8</p>'),
 (690,'<p><b>1 யோவான் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>1, 2, மற்றும் 3 யோவான் ஆகிய மூன்று நிருபங்களும் ஆரம்ப காலத்திலிருந்தே அப்போஸ்தலனாகிய யோவானே எழுதினார் என்றும், அவர் யோவானின் நற்செய்தியையும் எழுதினார் என்று நம்பப்பட்டு வருகிறது. இந்த மூன்று நிருபங்களும் யோவானின் நற்செய்தியைப் போலவே அதே வாசகர்களிடம் உரையாற்றப்பட்டன என்ற முடிவுக்கு அவைகளின் உள்ளடக்கம், பாணி மற்றும் சொற்களஞ்சியம் ஆகியவைகள் உத்திரவாதப்படுத்துகிறது.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>1 யோவான் புத்தகம் கி.பி. 85-95 க்கு இடையில் எழுதப்பட்டிருக்கலாம்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>1 யோவானின் புத்தகம் யோவான் எழுதிய நற்செய்தியைப் பற்றிய வாசகர்களின் அறிவைக் கருதி, கிறிஸ்துவை விசுவாசிப்பதற்கான உறுதியை அளிக்கும் சுருக்கமாகத் தெரிகிறது. முதல் நிருபம் வாசகர்கள் ஞானமார்க்கத்தின் பிழையை எதிர்கொண்டதைக் குறிக்கிறது, இது இரண்டாம் நூற்றாண்டில் மிகவும் கடுமையான ஒரு பிரச்சினையாக மாறியது. மதத்தின் ஒரு தத்துவமாக, விஷயமானது தீமை என்றும் ஆவி நல்லது என்றும் அது கூறியது. இந்த இரண்டிற்கும் இடையேயான பதட்டத்திற்கு தீர்வு அறிவு தான், அல்லது க்னோசிஸ் ஆகும், இதன் மூலம் மனிதன் இவ்வுலகத்திலிருந்து ஆவிக்குரிய நிலைக்கு உயர்ந்தான். நற்செய்தி செய்தியில், இது கிறிஸ்துவின் நபரைப் பற்றிய இரண்டு தவறான கோட்பாடுகளுக்கு வழிவகுத்தது, டோசட்டிசிசம் – இயேசுவின் மனிதத்தன்மையை ஒரு பேயாகக் கருதினார்கள் மற்றும் செரிந்தியனிசம் – இது இயேசுவை இரட்டை ஆளுமையுள்ளவராக, அதாவது சில சமயங்களில் மனிதனாகவும், சில சமயங்களில் தெய்வமாகவும் ஆக்குகிறது. 1 யோவானின் முக்கிய நோக்கம் விசுவாசத்தின் உள்ளடக்கத்திற்கு எல்லைகளை நிர்ணயிப்பதும், விசுவாசிகளுக்கு அவர்களின் இரட்சிப்பின் உறுதியை அளிப்பதும் ஆகும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>1 யோவான் 1:9, \"நம்முடைய பாவங்களை நாம் அறிக்கையிட்டால், பாவங்களை நமக்கு மன்னித்து எல்லா அநியாயத்தையும் நீக்கி நம்மைச் சுத்திகரிப்பதற்கு அவர் உண்மையும் நீதியும் உள்ளவராயிருக்கிறார்.\"</p><p>1 யோவான் 3:6, \"அவரில் நிலைத்திருக்கிற எவனும் பாவஞ்செய்கிறதில்லை; பாவஞ்செய்கிற எவனும் அவரைக் காணவுமில்லை, அவரை அறியவுமில்லை.\"</p><p>1 யோவான் 4:4, \"பிள்ளைகளே, நீங்கள் தேவனாலுண்டாயிருந்து, அவர்களை ஜெயித்தீர்கள்; ஏனெனில் உலகத்திலிருக்கிறவனிலும் உங்களிலிருக்கிறவர் பெரியவர்.\"</p><p>1 யோவான் 5:13, \"உங்களுக்கு நித்தியஜீவன் உண்டென்று நீங்கள் அறியவும், தேவகுமாரனுடைய நாமத்தின் மேல் நீங்கள் விசுவாசமாயிருக்கவும், தேவகுமாரனுடைய நாமத்தின் மேல் விசுவாசமாயிருக்கிற உங்களுக்கு இவைகளை எழுதியிருக்கிறேன்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>ஆரம்பகால திருச்சபையில் கள்ள ஆவிக்குரிய போதகர்கள் ஒரு பெரிய பிரச்சினையாக இருந்தனர். விசுவாசிகள் ஆராய்ந்து குறிப்பிட்டுப் பார்க்கும்படிக்கு ஒரு முழுமையான புதிய ஏற்பாடு இல்லாததால், பல திருச்சபைகள் தங்களது சொந்தக் கருத்துக்களைக் கற்பித்து, தலைவர்களாக முன்னேறிய பாசாங்குக்காரர்களுக்கு இரையாகிவிட்டன. யோவான் இந்த கடிதத்தை சில முக்கியமான விஷயங்களில், குறிப்பாக இயேசு கிறிஸ்துவின் அடையாளத்தைப் பற்றி நேரானதாக அமைப்பதற்காக எழுதினார்.</p><p>யோவானின் நிருபம் கிறிஸ்துவின் மீதான விசுவாசத்தின் அடிப்படைகளைப் பற்றியது என்பதால், அவருடைய வாசகர்கள் தங்கள் விசுவாசத்தை நேர்மையாக பிரதிபலிக்க இது உதவியது. தாங்கள் உண்மையான விசுவாசிகளா? என்ற கேள்விக்கு பதிலளிக்க இது அவர்களுக்கு உதவியது. அவர்களின் செயல்களைப் பார்த்து அவர்கள் சொல்ல முடியும் என்று யோவான் அவர்களிடம் கூறினார். அவர்கள் ஒருவருக்கொருவர் அன்பு கூறுகிறவர்களாக இருந்தால், அது அவர்களின் வாழ்க்கையில் தேவன் இருப்பதற்கு சான்றாகும் என்றார். ஆனால் அவர்கள் எப்போதுமே சண்டையிட்டு வழக்கு உண்டாக்கினால் அல்லது சுயநலமாக, ஒருவருக்கொருவர் கவனிக்காமல் இருந்தால், அவர்கள் உண்மையில் தேவனை அறியவில்லை என்று தங்களையே காட்டிக்கொடுக்கிறார்கள்.</p><p>அதற்காக அவர்கள் பரிபூரணமான நிலையில் சரியானவர்களாக இருக்க வேண்டும் என்று அர்த்தமல்ல. உண்மையில், விசுவாசம் என்பது நாம் நம்முடைய பாவங்களை ஒப்புக்கொள்வதும் தேவனிடமிருந்து மன்னிப்பைக் கோருவதும் சம்பந்தப்பட்டிருப்பதை யோவான் உணர்ந்தார். குற்றத்திலிருந்து தூய்மைப்படுத்துவதற்காக தேவனைப் பொறுத்து, மற்றவர்களுக்கு எதிரான நமது தவறுகளை ஒப்புக்கொள்வதோடு, திருத்தங்களைச் செய்வதும் தேவனைப் பற்றி அறிந்து கொள்வதில் மற்றொரு முக்கிய பகுதியாகும்.</p><p><b>இணைப்புகள்:</b></p><p>பாவத்தைப் பற்றி அடிக்கடி மேற்கோள் காட்டப்பட்ட பகுதிகளில் ஒன்று 1 யோவான் 2:16-ல் காணப்படுகிறது. இந்த வசனத்தில், பாவத்தின் மூன்று அம்சங்களை யோவான் விவரிக்கிறார், இது வேதவாக்கியங்களில் முதல் மற்றும் மிகவும் பூமியை சிதறடிக்கும் சோதனையை நினைவுபடுத்துகிறது. முதல் பாவம்-ஏவாளின் கீழ்ப்படியாமை-ஆதியாகமம் 3:6-ல் நாம் காணும் அதே மூன்று சோதனைகளுக்கு அவள் பலியானதன் விளைவாகும்: மாம்சத்தின் இச்சை (\"உணவுக்கு நல்லது\"); கண்களின் இச்சை (\"கண்ணுக்கு மகிழ்ச்சி\"); மற்றும் ஜீவனத்தின் பெருமை (\"ஞானத்தைப் பெற விரும்பத்தக்கது\").</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>1 யோவானின் புத்தகம் அன்பு மற்றும் மகிழ்ச்சியின் புத்தகம். மற்றவர்களுடனும் இயேசு கிறிஸ்துவுடனும் நமக்குள்ள கூட்டுறவின் ஐக்கியத்தை இது விளக்குகிறது. இது மகிழ்ச்சிக்கு இடையில் வேறுபடுகிறது, இது தற்காலிகமானது மற்றும் விரைவானது மற்றும் உண்மையான மகிழ்ச்சி, 1 யோவான் புத்தகம் இந்த மகிழ்ச்சியை எவ்வாறு பெறமுடியும் என்று சொல்லுகிறது. யோவான் எழுதிய சொற்களை எடுத்து, அவற்றை நாம் நம் அன்றாட வாழ்க்கையில் பயன்படுத்தினால், நாம் விரும்பும் உண்மையான அன்பு, அர்ப்பணிப்பு, ஐக்கியம் மற்றும் மகிழ்ச்சி நம்முடையதாக இருக்கும்.</p><p>அப்போஸ்தலனாகிய யோவான் கிறிஸ்துவை நன்கு அறிந்திருந்தார். இயேசு கிறிஸ்துவுடன் நாம் அனைவரும் அந்த நெருக்கமான உறவை வைத்திருக்க முடியும் என்று அவர் நமக்குச் சொல்கிறார். அவருடன் நேரடி மற்றும் தனிப்பட்ட தொடர்பு கொண்டிருந்த மனிதர்களின் சாட்சி நம்மிடம் உள்ளது. நற்செய்தி எழுத்தாளர்கள் ஒரு வரலாற்று யதார்த்தத்தின் மீது உறுதியான அடிப்படையிலான சாட்சியங்களை முன்வைக்கின்றனர். இப்போது, அது நம் வாழ்விற்கு எவ்வாறு பொருந்தும்? அவருடைய கிருபை, இரக்கம், அன்பு, ஏற்றுக்கொள்ளல் ஆகியவற்றின் அடிப்படையில் நம்முடன் ஒரு ஐக்கியத்தை உருவாக்க இயேசு தேவனுடைய குமாரனாக இங்கு வந்தார் என்று அது நமக்கு விளக்குகிறது. இயேசு ஏதோ தொலைதூர இடத்தில் இருக்கிறார் என்றும் நம்முடைய அன்றாட போராட்டங்கள், பிரச்சினைகள் மற்றும் கவலைகள் குறித்து அவர் கவலைப்படுவதில்லை என்றும் மக்கள் நினைக்கிறார்கள். ஆனால், நம்முடைய வாழ்க்கையின் எளிய, சாதாரணமான பகுதிகளிலும், சிக்கலான, ஆத்மாவை திருகிப் பறிக்கும் பகுதிகளிலும் இயேசு இங்கே இருக்கிறார் என்று யோவான் சொல்கிறார். தேவன் மாம்சமாகி மனிதர்களிடையே வாழ்ந்தார் என்பதற்கு யோவான் தனது தனிப்பட்ட அனுபவங்களுக்கு சாட்சியாக சாட்சியமளிக்கிறார். அதாவது கிறிஸ்து நம்முடன் வாழ இங்கே வந்தார், அவர் இன்னும் நம்முடன் வாழ்கிறார். அவர் யோவானுடன் பூமியில் நடந்ததுபோலவே, அவர் ஒவ்வொரு நாளும் நம்முடன் நடந்து செல்கிறார். இந்த உண்மையை நாம் நம் வாழ்வில் பயன்படுத்திக் கொள்ள வேண்டும், மேலும் ஒவ்வொரு நாளும் ஒவ்வொரு நொடியும் இயேசு நமக்கு அருகில் நிற்கிறார் என்பதுபோல நாம் வாழ வேண்டும். இந்த உண்மையை நாம் நடைமுறைக்குக் கொண்டுவந்தால், கிறிஸ்து நம் வாழ்வில் பரிசுத்தத்தைச் சேர்ப்பார், மேலும் அவரைப் போலவே நம்மை மேலும் மேலும் ஆக்குவார்.</p><p>சுமார் கி.பி. 27 - யோவான் கிறிஸ்துவிடம் வருதல்</p><p>சுமார் கி.பி. 29/30 - கிறிஸ்துவின் மரண உயிர்ப்பு யோவான்</p><p>சபையின் பொறுப்புக்களில் ஈடுபடத் தொடங்குதல்</p><p>சுமார் கி.பி. 67 - பேதுருவும் பவுலும் இரத்த சாட்சிகளாதல்</p><p>யோவான் எபேசு செல்லுதல்?</p><p>சுமார் கி.பி. 70 - ரோம படை எருசலேமை. அழித்தல் சபை சிதறுதல்</p><p>சுமார் கி.பி. 90-95 - யோவான் சுவிசேஷ நூலையும் நிருபங்களையும் எழுதுதல்</p><p>சுமார் கி.பி. 90-96 - யோவான் வெளிப்படுத்தின விசேஷத்தை எழுதுதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - யோவான் (தேவன் கிருபையுள்ளவர்)</p><p>குடும்பம் - தந்தை - செபதேயு / தாய் - சலோமே /அண்ணன் - யாக்கோபு</p><p>ஊர் - கலிலேயாவின் கப்பர்நகூம் பின்பு எபேசுவுக்கு சென்றார். பத்மு தீவுக்கு நாடுகடத்தப்பட்டதுண்டு (வெளி 1 : 9)</p><p>தொழில் - மீன் பிடிப்புக்குள்</p><p>ஆர்வம் - ஆன்மீக நாட்டம் /(முதலில் யோவான்ஸ்நானனின் சீடராக இருந்தார் (1: 19-51), பின்பு கிறிஸ்துவின் சீடரானார்)</p><p>திருப்பு முனை - கிறிஸ்துவின் அழைப்பு (லூக் 5: 1-11)</p><p>பட்டங்கள்- அண்ணனுடன் சேர்ந்து \"பொவனெர்கேஸ்\"</p><p>(இடிமுழக்கத்தின் மக்கள்) அப்போஸ்தலர்</p><p>சாதனைகள் - புதிய ஏற்பாட்டில் ஐந்து நூல்களைப் படைத்துள்ளார் (யோவான் சுவிசேஷ நூல், 1,2,3 யோவான் நிருபங்கள். வெளிப்படுத்தின விசேஷம்)</p><p>சிறப்புப் பெயர் - கிறிஸ்துவின் அன்பு சீடர்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 62-வது நூல்</p><p>அதிகாரங்கள் - 5</p><p>வசனங்கள் - 105</p><p>கேள்விகள் - 5</p><p>நிறைவேறிய பழைய ஏற்பாட்டுத் தீர்க்கதரிசனங்கள் - 100</p><p>நிறைவேறிய புதிய ஏற்பாட்டுத் தீர்க்கதரிசனங்கள் - 5</p>'),
 (70,'<p><b>நியாயாதிபதிகள் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>நியாயாதிபதிகள் புத்தகம் குறிப்பாக அதன் எழுத்தாளரின் பெயரைக் குறிப்பிடவில்லை. சாமுவேல் தீர்க்கதரிசி தான் நியாயாதிபதிகள் புத்தகத்தை எழுதியவர் என்பது பாரம்பரியம். நியாயாதிபதிகளின் எழுத்தாளர் நியாயாதிபதிகளின் காலத்திற்குப் பிறகு வாழ்ந்ததாக உள்ளான சான்றுகள் சுட்டிக்காட்டுகின்றன. சாமுவேல் இந்த தகுதிக்கு மிகவும் சரியாகப் பொருந்துகிறார்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>நியாயாதிபதிகள் புத்தகம் கி.மு. 1045 முதல் கி.மு. 1000 வரையிலுள்ள ஆண்டுகளுக்கு இடையில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>நியாயாதிபதிகள் புத்தகத்தை இரண்டு பிரிவுகளாகப் பிரிக்கலாம்: 1) 1-16 வரையிலுள்ள அதிகாரங்கள், இஸ்ரவேலர் கானானியர்களைத் தோற்கடித்து, பெலிஸ்தியரின் தோல்வி மற்றும் சிம்சோனின் மரணத்துடன் முடிவடையும் விடுதலைப் போர்களைப் பற்றிய விவரத்தை அளிக்கிறது; 2) 17-21 வரையிலுள்ள அதிகாரங்கள் பின் இணைப்பு என குறிப்பிடப்படுகின்றன மற்றும் முந்தைய அதிகாரங்களுடன் தொடர்புபடுத்தவில்லை. இந்த அதிகாரங்கள் \"இஸ்ரவேலில் ராஜா இல்லாத காலம்\" என்று குறிப்பிடப்பட்டுள்ளது (நியாயாதிபதிகள் 17:6; 18: 1; 19:1; 21:25). ரூத் புத்தகம் முதலில் நியாயாதிபதிகள் புத்தகத்தின் ஒரு பகுதியாக இருந்தது, ஆனால் கி.பி. 450-ல் அது அதன் தனிப்பட்ட ஒரு புத்தகமாக மாற்றப்பட்டது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>நியாயாதிபதிகள் 2:16-19: \"கர்த்தர் நியாயாதிபதிகளை எழும்பப்பண்ணினார்; அவர்கள் கொள்ளையிடுகிறவர்களின் கைக்கு அவர்களை நீங்கலாக்கி இரட்சித்தார்கள். அவர்கள் தங்கள் நியாயாதிபதிகளின் சொல்லைக் கேளாமல், அந்நிய தேவர்களைப் பின்பற்றிச் சோரம்போய், அவைகளைப் பணிந்துகொண்டார்கள்; தங்கள் பிதாக்கள் கர்த்தரின் கற்பனைகளுக்குக் கீழ்ப்படிந்து நடந்த வழியை அவர்கள் சீக்கிரமாய் விட்டு விலகி, அவர்கள் செய்தபடி செய்யாமற்போனார்கள். கர்த்தர் அவர்களுக்கு நியாயாதிபதிகளை எழும்பப்பண்ணுகிறபோது, கர்த்தர் நியாயாதிபதியோடேகூட இருந்து, அந்த நியாயாதிபதியின் நாட்களிலெல்லாம் அவர்கள் சத்துருக்களின் கைக்கு அவர்களை நீங்கலாக்கி இரட்சித்துவருவார்; அவர்கள் தங்களை இறுகப்பிடித்து ஒடுக்குகிறவர்களினிமித்தம் தவிக்கிறதினாலே, கர்த்தர் மனஸ்தாபப்படுவார். நியாயாதிபதி மரணமடைந்த உடனே, அவர்கள் திரும்பி, அந்நிய தேவர்களைப் பின்பற்றவும் சேவிக்கவும் பணிந்து கொள்ளவும், தங்கள் பிதாக்களைப்பார்க்கிலும் கேடாய் நடந்து, தங்கள் கிர்த்தியங்களையும் தங்கள் முரட்டாட்டமான வழியையும் விடாதிருப்பார்கள்.\"</p><p>நியாயாதிபதிகள் 10:15: \"இஸ்ரவேல் புத்திரர் கர்த்தரை நோக்கி: பாவஞ்செய்தோம், தேவரீர் உம்முடைய பார்வைக்கு நலமானதை எங்களுக்குச் செய்யும்; இன்றைக்குமாத்திரம் எங்களை இரட்சித்தருளும் என்று சொன்னார்கள்.\"</p><p>நியாயாதிபதிகள் 21:25: \"அந்நாட்களிலே இஸ்ரவேலில் ராஜா இல்லை; அவனவன் தன்தன் பார்வைக்குச் சரிப்போனபடி செய்துவந்தான்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>யெகோவா [தேவன்] தனது பிள்ளைகளால் எவ்வளவு சாதாரணமாக ஆண்டுதோறும், நூற்றாண்டுக்குப் பின் நூற்றாண்டுகளாக எடுத்துக்கொள்ளப்பட்டார் என்பதற்கான ஒரு சோகமான கணக்கு தான் நியாயாதிபதிகள் புத்தகம். நியாயாதிபதிகள் புத்தகம் யோசுவாவின் புத்தகத்திற்கு ஒரு சோகமான வேறுபாடாகும், இது தேசத்தை கைப்பற்றுவதில் தேவனுக்கு கீழ்ப்படிந்ததற்காக இஸ்ரவேலருக்கு தேவன் அளித்த ஆசீர்வாதங்களை விவரிக்கிறது. நியாயாதிபதிகளில், அவர்கள் கீழ்ப்படியாதவர்களாகவும் விக்கிரகாராதனைக்காரர்களாகவும் இருந்தார்கள், இது அவர்களின் பல தோல்விகளுக்கு வழிவகுத்தது. தம்முடைய ஜனம் தங்கள் துன்மார்க்க வழிகளிலிருந்து மனந்திரும்பி, அவருடைய பெயரைக் கூப்பிடும்போதெல்லாம் தேவன் தம்முடைய அன்பைக் காண்பிக்கத் தவறியதில்லை. (நியாயாதிபதிகள் 2:18) இஸ்ரவேலின் 15 நியாயாதிபதிகள் மூலமாக, ஆபிரகாமுக்கு அவருடைய சந்ததியினரைப் பாதுகாக்கவும் ஆசீர்வதிக்கவும் தேவன் அளித்த வாக்குறுதியை தேவன் நினைவுகூர்ந்தார் மற்றும் மதித்தார் (ஆதியாகமம் 12:2-3).</p><p>யோசுவா மற்றும் அவரது சமகாலத்தவர்கள் இறந்த பிறகு, இஸ்ரவேலர்கள் பாகால் மற்றும் அஷ்டரோத்துக்கு அடிபணிந்து அவைகளை நமஸ்கரிக்கவும் அவைகளை சேவிக்கவும் திரும்பினர். பொய்யான கடவுள்களை வணங்குவதன் விளைவுகளை இஸ்ரவேலர்கள் அனுபவிக்க தேவன் அனுமதித்தார். அப்போதுதான் தேவனுடைய ஜனம் யெகோவாவிடம் உதவி கேட்கிறார்கள். தேவன் தம் பிள்ளைகளை நீதியுள்ள வாழ்க்கைக்கு வழிநடத்த நியாயாதிபதிகளை அனுப்பினார். ஆனால் காலப்போக்கில் அவர்கள் தேவனைவிட்டு விலகி, தங்கள் துன்மார்க்க வாழ்க்கைக்குத் திரும்பினார்கள். ஆயினும், ஆபிரகாமுடனான உடன்படிக்கையின் ஒரு பகுதியை வைத்துக்கொண்டு, நியாயாதிபதிகள் புத்தகத்தின் 480 ஆண்டு காலம் முழுவதும் தேவன் தம் ஜனங்களை ஒடுக்குபவர்களிடமிருந்து அவர்களை காப்பாற்றினார்.</p><p>அநேகமாக மிகவும் குறிப்பிடத்தக்க நியாயாதிபதி 12-வது நியாயாதிபதியாகிய சிம்சோன், இரக்கமற்ற பெலிஸ்தியரின் ஆட்சியின் கீழ் 40 ஆண்டுகால சிறைவாசத்திற்குப் பிறகு இஸ்ரவேலரை வழிநடத்த வந்தார். இஸ்ரவேலின் நியாயாதிபதியாக 20 ஆண்டுகளுக்குப் பிறகு தனது சொந்த ஜீவனை இழந்து பெலிஸ்தர்களை வென்றெடுத்து சிம்சோன் தேவனுடைய ஜனங்களை வழிநடத்தினார்.</p><p><b>முன்னிழல்கள்:</b></p><p>இஸ்ரேலை வழிநடத்த ஒரு குமாரனைப் பெறுவாய் என்று சிம்சோனின் தாய்க்கு அறிவித்திருப்பது, மேசியாவின் பிறப்பு மரியாளுக்கு அறிவித்ததை முன்னறிவிப்பதாகும். தேவன் தம்முடைய தூதனை இரு ஸ்திரீகளுக்கும் அனுப்பி, அவர்கள் \"கர்ப்பமாகி ஒரு குமாரனைப் பெறுவார்கள்\" என்று சொன்னார் (நியாயாதிபதிகள் 13:7; லூக்கா 1:31), அவர்கள் தேவனுடைய மக்களை வழிநடத்துவார்கள்.</p><p>தேவனுடைய ஜனங்கள் பாவம் செய்தபோதும், அவரை நிராகரித்த போதிலும் தேவனுடைய இரக்கமுள்ள மீட்பு, சிலுவையில் மரித்த கிறிஸ்துவின் சித்திரத்தை முன்வைக்கிறது. தம் ஜனங்களை தம்மை நம்புகிற அனைவரையும் அவர்கள் பாவத்திலிருந்து விடுவிப்பதற்காக இயேசு மரித்தார். அவருடைய ஊழியத்தின்போது அவரைப் பின்தொடர்ந்தவர்களில் பெரும்பாலோர் இறுதியில் வீழ்ந்து அவரை நிராகரிப்பார்கள் என்றாலும், அவர் தம்முடைய வாக்குறுதியை நிறைவேற்றுவதில் உண்மையாகக் கடைப்பிடித்து, நமக்காக மரிக்க சிலுவைக்கு சென்றார்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>கீழ்ப்படியாமை எப்போதும் நியாயத்தீர்ப்பைக் கொண்டுவருகிறது. நாம் என்ன செய்யக்கூடாது என்பதற்கு இஸ்ரவேலர் ஒரு சிறந்த உதாரணத்தை முன்வைக்கிறார்கள். தேவன் எப்போதும் அவருக்கு எதிரான கிளர்ச்சியைத் தண்டிப்பார் என்று அனுபவத்திலிருந்து கற்றுக்கொள்வதற்குப் பதிலாக, அவர்கள் தொடர்ந்து கீழ்ப்படியாமல் தேவனுடைய அதிருப்தியையும் ஒழுக்கத்தையும் அனுபவித்தனர். நாம் கீழ்ப்படியாமல் தொடர்ந்தால், தேவனுடைய ஒழுங்கு நடவடிக்கையை வரவழைக்கிறவர்களாக இருப்போம், காரணம் அவர் நம்முடைய துன்பங்களை விரும்பி அனுபவிக்கிறார் என்றர்த்தமல்ல, மாறாக \"கர்த்தர் எவனிடத்தில் அன்புகூருகிறாரோ அவனை அவர் சிட்சித்து, தாம் சேர்த்துக்கொள்ளுகிற எந்த மகனையும் தண்டிக்கிறார்\" (எபிரெயர் 12:6).</p><p>நியாயாதிபதிகள் புத்தகம் தேவனுடைய உண்மைத்தன்மைக்கு ஒரு சான்றாகும். \"நாம் உண்மையில்லாதவர்களாயிருந்தாலும், அவர் உண்மையுள்ளவராயிருக்கிறார்\" (2 தீமோத்தேயு 2:13). இஸ்ரவேலரைப் போலவே நாம் அவரிடம் விசுவாசமற்றவர்களாக இருந்தாலும், நம்மைக் காப்பாற்றுவதற்கும், நம்மை போஷிப்பதற்கும் அவர் உண்மையுள்ளவராகவே இருக்கிறார் (1 தெசலோனிக்கேயர் 5:24) மற்றும் நாம் மன்னிப்பைத் தேடும்போது மன்னிக்கவும் செய்கிறார் (1 யோவான் 1:9). \" நம்முடைய கர்த்தராகிய இயேசு கிறிஸ்துவின் நாளிலே நீங்கள் குற்றஞ்சாட்டப்படாதவர்களாயிருக்கும்படி முடிவுபரியந்தம் அவர் உங்களை ஸ்திரப்படுத்துவார். தம்முடைய குமாரனும் நம்முடைய கர்த்தருமாயிருக்கிற இயேசுகிறிஸ்துவுடனே ஐக்கியமாயிருப்பதற்கு உங்களை அழைத்த தேவன் உண்மையுள்ளவர்\" (1 கொரிந்தியர் 1:8-9).</p><p>சுமார் கி.மு.1434 (1375) - யோசுவாவின் மரணம்</p><p>சுமார் கி.மு.1409 (1367) - ஒத்தினியேல் நியாயாதிபதி</p><p>சுமார் கி.மு. 1359 (1309  - ஏகூத் நியாயாதிபதி</p><p>சுமார் கி.மு. 1277 (1209) - பாராக் நியாயாதிபதி</p><p>சுமார் கி.மு. 1250 (1162) - கிதியோன் நியாயாதிபதி</p><p>சுமார் கி.மு.1151 (1078) - யெப்தா நியாயாதிபதி</p><p>சுமார் கி.மு. 1081 (1130) - ஏலி நியாயாதிபதி</p><p>சுமார் கி.மு. 1041 (1090) - சாமுவேல் நியாயாதிபதி</p><p>சுமார் கி.மு. 1001 (1050) - சவுல் அரசராகிறார்</p><p>சுமார் கி.மு. 991 (1040)  - தாவீதின் பிறப்பு</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>தெரியவில்லை, சாமுவேலாக இருக்கலாம்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 7-வது நூல்</p><p>அதிகாரங்கள் - 21</p><p>வசனங்கள் - 618</p><p>வரலாற்றுத் தொடர்பு வசளங்கள் - 585</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 33</p><p>கேள்விகள் - 92</p><p>தேவனிடமிருந்து சிறப்புச் செய்திகள் - 23</p><p>கட்டளைகள் - 71</p><p>எச்சரிக்கைகள் - 26</p><p>வாக்குத்தத்தங்கள் - 5</p>'),
 (700,'<p><b>2 யோவான் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>2 யோவானின் புத்தகம் அதன் எழுத்தாளரை நேரடியாக அவரது பெயரைக் குறிப்பிட்டு கூறவில்லை. திருச்சபையின் ஆரம்ப நாட்களிலிருந்து வந்த பாரம்பரிய நம்பிக்கையானது, இந்த புத்தகத்தின் எழுத்தாளர் அப்போஸ்தலனாகிய யோவான் என்று கூறுகிறது. கிறிஸ்துவின் மற்றொரு சீடரான யோவான் இந்த கடிதத்திற்கு காரணமாக இருக்கலாம் என்று பல ஆண்டுகளாக பல்வேறு கருத்துக்கள் உள்ளன. இருப்பினும், எல்லா ஆதாரங்களும் எழுத்தாளரை யோவானின் சுவிசேஷத்தை எழுதிய அன்பான சீஷனாகிய யோவான் என்று சுட்டிக்காட்டுகின்றன.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>2 யோவானின் புத்தகம் யோவானின் மற்ற நிருபங்களான 1 மற்றும் 3 யோவான், கி.பி. 85-95 க்கு இடையில் எழுதப்பட்டிருக்கலாம் என்று நம்பப்படுகிறது.</p><p><b>எழுதப்பட்ட நோக்கம்:</b></p><p>2 யோவானின் புத்தகம், யோவானின் கடிதத்தைப் படிப்பவர்கள் ஒருவருக்கொருவர் அன்பு செலுத்துவதற்கும், வேதவசனங்களுக்குக் கீழ்ப்படிந்து தங்கள் வாழ்க்கையை வாழ்வதற்கும் கட்டளையிடுவதன் மூலம் தேவன் மீதும் அவருடைய குமாரனாகிய இயேசு மீதும் தங்கள் அன்பைக் காட்ட வேண்டும் என்கிற அவசர வேண்டுகோளை விடுக்கிறது. 2 யோவானின் புத்தகமும் கிறிஸ்து மாம்சத்தில் உண்மையில் உயிர்த்தெழுப்பவில்லை என்று சொல்லிக்கொண்டிருக்கும் ஏமாற்றுக்காரர்களைத் தேடுவதற்கான ஒரு வலுவான எச்சரிக்கையாகும்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>2 யோவான் 6, \"நாம் அவருடைய கற்பனைகளின்படி நடப்பதே அன்பு; நீங்கள் ஆதிமுதல் கேட்டிருக்கிறபடி நடந்துகொள்ளவேண்டிய கற்பனை இதுவே.\"</p><p>2 யோவான் 8-9, \"உங்கள் செய்கைகளின் பலனை இழந்துபோகாமல், பூரண பலனைப் பெறும்படிக்கு எச்சரிக்கையாயிருங்கள். கிறிஸ்துவின் உபதேசத்திலே நிலைத்திராமல் மீறி நடக்கிற எவனும் தேவனை உடையவனல்ல; கிறிஸ்துவின் உபதேசத்தில் நிலைத்திருக்கிறவனோ பிதாவையும் குமாரனையும் உடையவன்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>2 யோவானின் புத்தகம் தெரிந்துகொள்ளப்பட்டவளாகிய அம்மாளுக்கு மற்றும் அவரது குழந்தைகளுக்கு எழுதப்பட்டது. இவர் திருச்சபையில் முக்கியமான ஒரு பெண்மணியாகவோ அல்லது உள்ளூர் திருச்சபையையும் அதன் கூடிவரவையும் குறிக்கும் ஒரு குறியீடாக இருந்திருக்கலாம். கிறிஸ்தவர்கள் துன்புறுத்தப்பட்ட அந்த நாட்களில் இதுபோன்ற குறியீட்டு வாழ்த்துதல்கள் பெரும்பாலும் பயன்படுத்தப்பட்டன.</p><p>2 யோவான் புத்தகம் பெரும்பாலும் கிறிஸ்துவின் சரியான உபதேச கோட்பாட்டைக் கற்பிக்காத ஏமாற்றுக்காரர்களைப் பற்றிய ஒரு அவசர எச்சரிக்கையுடன் அக்கறை கொண்டுள்ளது, இயேசு உண்மையில் மாம்சத்தில் எழுந்திருக்கவில்லை, ஆனால் ஆவிக்குரிய நிலையில் மட்டுமே இருந்தார் என்கிறார்கள். உண்மையான விசுவாசிகள் இந்த கள்ளப்போதகர்களை அறிந்திருக்க வேண்டும் என்றும், அவர்களுடன் எந்த நமக்கு எந்த தொடர்பும் இல்லை என்றும் யோவான் மிகவும் வலுவாக கூறுகிறார்.</p><p><b>இணைப்புகள்:</b></p><p>யோவான் அன்பை ஒரு உணர்ச்சி அல்லது உணர்வு என்று விவரிக்கவில்லை, ஆனால் தேவனுடைய கட்டளைகளுக்குக் கீழ்ப்படிதல் என்று விவரிக்கிறார். கட்டளைகளின் முக்கியத்துவத்தை இயேசு மீண்டும் வலியுறுத்தினார், குறிப்பாக \"முதலாவது மற்றும் மிகப் பிரதானமான கற்பனை\", தேவன் மீது அன்பு கூறுவதாகும் (உபாகமம் 6:5), இரண்டாவதாக ஒருவருக்கொருவர் அன்பு செலுத்துதல் (மத்தேயு 22:37-40; லேவியராகமம் 19:18). தேவனுடைய பழைய ஏற்பாட்டு நியாயப்பிரமாணத்தை ஒழிப்பதற்குப் பதிலாக, இயேசு அதை நிறைவேற்றுவதற்கான வழிகளை வழங்குவதன் மூலம் அதை நிறைவேற்றினார்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>வேதவசனங்களுடன் \"கிறிஸ்தவர்\" என்று கூறும் நாம் பார்க்கும், கேட்கும், படிக்கும் அனைத்தையும் சரிபார்க்க வேண்டியது மிகவும் முக்கியமாகும். இதை மிகவும் வலுவாக வலியுறுத்த முடியாது, ஏனெனில் சாத்தானின் மிகப்பெரிய ஆயுதங்களில் ஒன்று வஞ்சகம். வேதத்தை அடிப்படையாகக் கொண்டதாகத் தோன்றும் ஒரு புதிய மற்றும் உற்சாகமான கோட்பாட்டின் மூலம் எடுத்துக்கொள்வது மிகவும் எளிதானது, ஆனால் இது உன்னிப்பாக ஆராய்ந்தால், உண்மையில் தேவனுடைய வார்த்தையிலிருந்து வழுவிப் புறப்படுவதாகும். என்ன நடக்கிறது என்று தோன்றுகிறதோ அது வேதவசனத்துடன் வெளிப்படையாக பொருந்தவில்லை என்றால், அது தவறானது, அது ஆவியினால் அல்ல, அதற்கும் நமக்கு எந்த சம்பந்தமும் இருக்கக்கூடாது.</p><p>சுமார் கி.பி. 27 - யோவான் கிறிஸ்துவிடம் வருதல்</p><p>சுமார் கி.பி. 29/30 - கிறிஸ்துவின் மரண உயிர்ப்பு. யோவான் சபையின் பொறுப்புக்களில் ஈடுபடத் தொடங்குதல்</p><p>சுமார் கி.பி. 50 - எருசலேம் கவுன்சில்</p><p>சுமார் கி.பி. 67 - பவுலும் பேதுருவும் இரத்த சாட்சிகளாதல்</p><p>யோவான் எபேசு செல்லுதல்</p><p>சுமார் கி.பி. 70 - ரோம படை எருசலேமை அழித்தல் சபை சிதறுதல்</p><p>சுமார் கி.பி. 90-95 2யோவான் எழுதப்படல் (?)</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - யோவான் (தேவன் கிருபையுள்ளவர்)</p><p>குடும்பம் - தந்தை - செபதேயு / தாய் - சலோமே /அண்ணன் - யாக்கோபு</p><p>ஊர் - கலிலேயாவின் கப்பர்நகூம் பின்பு எபேசுவுக்கு சென்றார். பத்மு தீவுக்கு நாடுகடத்தப்பட்டதுண்டு (வெளி 1 : 9)</p><p>தொழில் - மீன் பிடிப்புக்குள்</p><p>ஆர்வம் - ஆன்மீக நாட்டம் /(முதலில் யோவான்ஸ்நானனின் சீடராக இருந்தார் (1: 19-51), பின்பு கிறிஸ்துவின் சீடரானார்)</p><p>திருப்பு முனை - கிறிஸ்துவின் அழைப்பு (லூக் 5: 1-11)</p><p>பட்டங்கள்- அண்ணனுடன் சேர்ந்து \"பொவனெர்கேஸ்\"</p><p>(இடிமுழக்கத்தின் மக்கள்) அப்போஸ்தலர்</p><p>சாதனைகள் - புதிய ஏற்பாட்டில் ஐந்து நூல்களைப் படைத்துள்ளார் (யோவான் சுவிசேஷ நூல், 1,2,3 யோவான் நிருபங்கள். வெளிப்படுத்தின விசேஷம்)</p><p>சிறப்புப் பெயர் - கிறிஸ்துவின் அன்பு சீடர்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 63-வது நூல்</p><p>அதிகாரங்கள் - 1</p><p>வசனங்கள் - 13</p>'),
 (710,'<p><b>3 யோவான் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>3 யோவானின் புத்தகம் அதன் எழுத்தாளரை நேரடியாக அவரது பெயரைக் குறிப்பிட்டு கூறவில்லை. திருச்சபையின் ஆரம்ப நாட்களிலிருந்து வந்த பாரம்பரிய நம்பிக்கையானது, இந்த புத்தகத்தின் எழுத்தாளர் அப்போஸ்தலனாகிய யோவான் என்று கூறுகிறது. கிறிஸ்துவின் மற்றொரு சீடரான யோவான் இந்த கடிதத்திற்கு காரணமாக இருக்கலாம் என்று பல ஆண்டுகளாக பல்வேறு கருத்துக்கள் உள்ளன. இருப்பினும், எல்லா ஆதாரங்களும் எழுத்தாளரை யோவானின் சுவிசேஷத்தை எழுதிய அன்பான சீஷனாகிய யோவான் என்று சுட்டிக்காட்டுகின்றன.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>3 யோவானின் புத்தகம் யோவானின் மற்ற நிருபங்களான 1 மற்றும் 2 யோவான், கி.பி. 85-95 க்கு இடையில் எழுதப்பட்டிருக்கலாம் என்று நம்பப்படுகிறது.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>இந்த மூன்றாவது நிருபத்தை எழுதுவதில் யோவானின் நோக்கம் மும்மடங்கு. முதலாவதாக, கிறிஸ்துவின் நற்செய்தியைப் பிரசங்கிப்பதற்காக ஒரு இடத்திலிருந்து வேறு இடத்திற்குச் சென்று கொண்டிருந்த பயண பிரசங்கிகளுக்கு விருந்தோம்பும் ஊழியத்தில் தனது அன்பான சக ஊழியரான காயுவைப் பாராட்டவும் ஊக்குவிக்கவும் அவர் எழுதுகிறார். இரண்டாவதாக, ஆசியா மாகாணத்தில் உள்ள திருச்சபைகளில் ஒன்றைக் கைப்பற்றிய ஒரு சர்வாதிகாரத் தலைவரான ஒரு தியோத்திரேப்பின் நடத்தையை அவர் மறைமுகமாக எச்சரிக்கிறார், கண்டிக்கிறார், அவருடைய நற்செய்தியானது அப்போஸ்தலருக்கும் அவர்கள் நிலைத்து நின்ற அனைத்திற்கும் நேரடியாக எதிர்த்து நின்றார். மூன்றாவதாக, அனைவரிடமிருந்தும் ஒரு நல்ல சாட்சியம் இருப்பதாக அறிவிக்கப்பட்ட தேமேத்திரியுவின் உதாரணத்தை அவர் பாராட்டுகிறார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>3 யோவான் 4, \"என் பிள்ளைகள் சத்தியத்திலே நடக்கிறார்கள் என்று கேள்விப்படுகிற சந்தோஷத்திலும் அதிகமான சந்தோஷம் எனக்கு இல்லை.\"</p><p>3 யோவான் 11, \"பிரியமானவனே, நீ தீமையானதைப் பின்பற்றாமல், நன்மையானதைப் பின்பற்று, நன்மைசெய்கிறவன் தேவனால் உண்டாயிருக்கிறான்; தீமைசெய்கிறவன் தேவனைக் காணவில்லை.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>எபேசுவிற்கு அருகிலுள்ள ஒரு நகரத்தில் ஏதோவொரு செல்வத்தையும் வேறுபாட்டையும் கொண்ட ஒரு சாதாரண மனிதரான காயுவாகிய கிறிஸ்துவில் மிகவும் விரும்பப்படும் இந்த சகோதரருக்கு சத்தியத்தை யோவான் தனது வழக்கமான வலுவான முக்கியத்துவத்துடன் எழுதுகிறார். காயுவின் கவனிப்பையும் விருந்தோம்பலையும் அவர் மிகவும் பாராட்டுகிறார், அவருடைய தூதுவர்களுக்கு நற்செய்தியை ஒரு இடத்திலிருந்து வேறு இடத்திற்கு எடுத்துச் செல்வதே அவர்களின் நோக்கம், அவர்கள் அவருக்குத் தெரிந்தவர்களாக இருந்தாலும் அல்லது அந்நியர்களாக இருந்தாலும் சரி, உபசரிப்பில் சலிப்படையாமல் செய்து வந்தார். தியோத்திரேப்புவின் உதாரணத்தைப் போலில்லாமல், தொடர்ந்து நன்மை செய்யவும், தீமையைப் பின்பற்ற வேண்டாம் என்றும் யோவான் அறிவுறுத்துகிறார். இந்த மனிதன் ஆசியாவில் ஒரு திருச்சபையின் தலைமையை எடுத்துக் கொண்டார், யோவானின் அதிகாரத்தை ஒரு அப்போஸ்தலனாக அங்கீகரிக்க மறுத்ததோடு மட்டுமல்லாமல், அவருடைய கடிதங்களைப் பெற்று அவருடைய அறிவுறுத்தல்களுக்கு அடிபணியவும் மறுத்துவிட்டார். யோவானுக்கு எதிராக தீங்கிழைக்கும் அவதூறுகளையும், யோவான் அனுப்பிய செய்தியாளர்களுக்கு ஆதரவையும் விருந்தோம்பலையும் காட்டிய உறுப்பினர்களை வெளியேற்றினான். அவர் தனது கடிதத்தை முடிப்பதற்கு முன், தேமேத்திரியுவின் உதாரணத்தையும் பாராட்டுகிறார், அவர்களில் சிறந்த அறிக்கைகளைக் கேட்டிருக்கிறார்.</p><p><b>இணைப்புகள்:</b></p><p>அந்நியர்களுக்கு விருந்தோம்பல் வழங்குவதற்கான கருத்து பழைய ஏற்பாட்டில் ஏராளமான முன்னுதாரணங்களைக் கொண்டுள்ளது. இஸ்ரவேலில் விருந்தோம்பல் செயல்களில் உணவு, உறைவிடம் மற்றும் பாதுகாப்புக்காக அந்நியர்களை வீட்டிற்கு தாழ்மையுடன் வரவேற்பது (ஆதியாகமம் 18:2-8, 19:1-8; யோபு 31:16-23, 31-32) போன்றவைகள் அடங்கும். கூடுதலாக, பழைய ஏற்பாட்டுப் போதனை இஸ்ரவேலரை தேவனுடைய விருந்தோம்பலைச் சார்ந்து இருக்கும் அந்நியப்பட்ட மனிதர்களாகவும் (சங்கீதம் 39:12) சித்தரிக்கிறது, மேலும் தேவன் அவர்களுடைய தேவைகளை பூர்த்திசெய்து, அவர்களை எகிப்திலிருந்து மீட்டு, அவர்களுக்கு வனாந்தரத்தில் உணவளித்து ஆடை உடுத்துவித்தார் (யாத்திராகமம் 16; உபாகமம் 8:2-5).</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>யோவான், எப்போதும் போலவே, நற்செய்தியின் சத்தியத்தில் நடப்பதன் முக்கியத்துவத்தை வலியுறுத்துகிறார். நம்முடைய சக கிறிஸ்தவர்களுக்கு விருந்தோம்பல், ஆதரவு மற்றும் ஊக்கம் ஆகியவை இயேசுவின் போதனைகளின் முக்கிய கட்டளைகளில் ஒன்றாகும், மேலும் காயு இந்த ஊழியத்தின் ஒரு சிறந்த எடுத்துக்காட்டு. நம்மால் முடிந்த போதெல்லாம் அதைச் செய்ய வேண்டும், வருகை தரும் மிஷனரிகள், பிரசங்கிகள் மற்றும் அந்நியர்கள் (அவர்கள் உண்மையான விசுவாசிகள் என்று நமக்குத் தெரிந்தவரை) நம் சபைகளுக்கு மட்டுமல்ல, நம் வீடுகளுக்கும் வரவேற்பதுடன், அவர்களுக்குத் தேவையான ஆதரவையும் ஊக்கத்தையும் அவர்களுக்கு வழங்குகிறவர்களாக இருக்கவேண்டும்.</p><p>நற்செய்திக்கு ஏற்ப சொற்களும் செயல்களும் உள்ளவர்களின் உதாரணத்தை மட்டுமே பின்பற்றுவதற்கும், தேமேத்திரியு போன்றவர்களைப் பற்றி விழிப்புடன் இருப்பதற்கு போதுமான விவேகத்துடன் இருப்பதற்கும் நாம் எப்போதும் கவனமாக இருக்க வேண்டும். இதையேதான் இயேசுவும் கற்பித்தார்.</p><p>சுமார் கி.பி. 27 - யோவான் கிறிஸ்துவிடம் வருதல்</p><p>சுமார் கி.பி. 29/30 - கிறிஸ்துவின் மரண உயிர்ப்பு யோவான்</p><p>சபையின் பொறுப்புக்களில் ஈடுபடத் தொடங்குதல்</p><p>சுமார் கி.பி.50 - எருசலேம் கவுன்சில்</p><p>சுமார் கி.பி. 67 - பவுலும் பேதுருவும் இரத்த சாட்சிகளாதல் யோவான் எபேசு செல்லுதல் (?)</p><p>சுமார் கி.பி. 70 - ரோம படை எருசலேமை அழித்தல்</p><p>சுமார் கி.பி. 90-95 - 3 யோவான் நிருபத்தை எழுதுதல்?</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - யோவான் (தேவன் கிருபையுள்ளவர்)</p><p>குடும்பம் - தந்தை - செபதேயு / தாய் - சலோமே /அண்ணன் - யாக்கோபு</p><p>ஊர் - கலிலேயாவின் கப்பர்நகூம் பின்பு எபேசுவுக்கு சென்றார். பத்மு தீவுக்கு நாடுகடத்தப்பட்டதுண்டு (வெளி 1 : 9)</p><p>தொழில் - மீன் பிடிப்புக்குள்</p><p>ஆர்வம் - ஆன்மீக நாட்டம் /(முதலில் யோவான்ஸ்நானனின் சீடராக இருந்தார் (1: 19-51), பின்பு கிறிஸ்துவின் சீடரானார்)</p><p>திருப்பு முனை - கிறிஸ்துவின் அழைப்பு (லூக் 5: 1-11)</p><p>பட்டங்கள்- அண்ணனுடன் சேர்ந்து \"பொவனெர்கேஸ்\"</p><p>(இடிமுழக்கத்தின் மக்கள்) அப்போஸ்தலர்</p><p>சாதனைகள் - புதிய ஏற்பாட்டில் ஐந்து நூல்களைப் படைத்துள்ளார் (யோவான் சுவிசேஷ நூல், 1,2,3 யோவான் நிருபங்கள். வெளிப்படுத்தின விசேஷம்)</p><p>சிறப்புப் பெயர் - கிறிஸ்துவின் அன்பு சீடர்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 64-வது நூல்</p><p>அதிகாரங்கள் - 1</p><p>வசனங்கள் - 15</p>'),
 (720,'<p><b>யூதாவின் நிருபம்</b></p><p><b>எழுத்தாளர்:</b></p><p>யூதா நிருபத்தின் முதலாவது வசனம் \"இயேசுகிறிஸ்துவினுடைய ஊழியக்காரனும், யாக்கோபினுடைய சகோதரனுமாயிருக்கிற யூதா\" என்று யூதா புத்தகத்தின் எழுத்தாளர் யூதா, மற்றும் யாக்கோபின் சகோதரர் என்றும் அடையாளம் காட்டுகிறார். இது இயேசுவின் ஒன்றுவிட்ட சகோதரர் யூதாவைக் குறிக்கிறது, ஏனெனில் இயேசுவுக்கு யாக்கோபு என்ற ஒன்றுவிட்ட ஒரு சகோதரரும் இருந்தார் (மத்தேயு 13:55) என்பதை தெளிவாக்குகிறது. யூதா தனது தாழ்மையை வெளிப்படுத்தும் பொருட்டும் இயேசுவிற்கு கனத்தை வழங்கும் பொருட்டும் தன்னை அவர் இயேசுவின் சகோதரர் என்று அடையாளம் காட்டிக்கொள்ளவில்லை.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>யூதாவின் புத்தகம் 2 பேதுருவின் புத்தகத்துடன் மிகவும் நெருங்கிய தொடர்புடையதாக இருக்கிறது. எழுத்தாளர் எழுதப்பட்ட காலம் யூதா 2 பேதுருவின் உள்ளடக்கத்தைப் பயன்படுத்தினாரா, அல்லது 2 பேதுரு எழுதும் போது பேதுரு அப்போஸ்தலன் யூதாலிருந்து உள்ளடக்கத்தைப் பயன்படுத்தினாரா என்பதைப் பொறுத்தது. ஆக யூதாவின் புத்தகம் கி.பி. 60 முதல் கி.பி. 80 வரையிலுள்ள காலத்தில் எழுதப்பட்டதாகும்.</p><p><b>எழுதப்பட்ட நோக்கம்:</b></p><p>யூதாவின் புத்தகம் இன்று நமக்கு ஒரு முக்கியமான புத்தகமாகும், ஏனெனில் இது கடைசிக் காலத்திற்காக, திருச்சபை யுகத்தின் முடிவுக்கு எழுதப்பட்டுள்ளது. திருச்சபையின் யுகம் பெந்தெகொஸ்தே நாளில் தொடங்கியது. பெரும் விசுவாச துரோகத்திற்கு முழுமையாக வழங்கப்பட்ட ஒரே புத்தகம் யூதாவின் நிருபம். தீய செயல்கள் விசுவாச துரோகத்திற்கு சான்றுகள் என்று யூதா எழுதுகிறார். விசுவாசத்திற்காக போராட அவர் நமக்கு அறிவுறுத்துகிறார், ஏனென்றால் கோதுமையில் களைகள் இருக்கிறது. கள்ளத்தீர்க்கதரிசிகள் திருச்சபையில் இருக்கிறார்கள், பரிசுத்தவான்கள் ஆபத்தில் உள்ளனர். யூதாவின் புத்தகம் சிறிய புத்தகம் என்பது ஒரு சிறிய ஆனால் முக்கியமான புத்தகம், இது இன்றைய கிறிஸ்தவர்களுக்காக எழுதப்பட்டுள்ளது.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>யூதா 3, \"பிரியமானவர்களே, பொதுவான இரட்சிப்பைக்குறித்து உங்களுக்கு எழுதும்படி நான் மிகவும் கருத்துள்ளவனாயிருக்கையில், பரிசுத்தவான்களுக்கு ஒருவிசை ஒப்புக்கொடுக்கப்பட்ட விசுவாசத்திற்காக நீங்கள் தைரியமாய்ப் போராடவேண்டுமென்று உங்களுக்கு எழுதி உணர்த்துவது எனக்கு அவசியமாய்க் கண்டது.\"</p><p>யூதா 17-19, \"நீங்களோ பிரியமானவர்களே, நம்முடைய கர்த்தராகிய இயேசுகிறிஸ்துவின் அப்போஸ்தலரால் முன் சொல்லப்பட்ட வார்த்தைகளை நினைவுகூருங்கள். கடைசிக்காலத்திலே தங்கள் துன்மார்க்கமான இச்சைகளின்படி நடக்கிற பரியாசக்காரர் தோன்றுவார்கள் என்று உங்களுக்குச் சொன்னார்களே. இவர்கள் பிரிந்து போகிறவர்களும், ஜென்மசுபாவத்தாரும், ஆவியில்லாதவர்களுமாமே.\"</p><p>யூதா 24-25, \"வழுவாதபடி உங்களைக் காக்கவும், தமது மகிமையுள்ள சந்நிதானத்திலே மிகுந்த மகிழ்ச்சியோடே உங்களை மாசற்றவர்களாய் நிறுத்தவும் வல்லமையுள்ளவரும், தாம் ஒருவரே ஞானமுள்ளவருமாகிய நம்முடைய இரட்சகரான தேவனுக்குக் கனமும் மகத்துவமும் வல்லமையும் அதிகாரமும் இப்பொழுதும் எப்பொழுதும் உண்டாவதாக. ஆமென்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>3-வது வசனத்தின்படி, யூதா நம்முடைய இரட்சிப்பைப் பற்றி எழுத ஆர்வமாக இருந்தார்; இருப்பினும், விசுவாசத்திற்காக போட்டியிடுவதற்கு அவர் தலைப்புகளை மாற்றினார். இந்த விசுவாசம் கிறிஸ்துவால் கற்பிக்கப்பட்ட கிறிஸ்தவ கோட்பாட்டின் முழுமையான நிலையைக் குறிக்கிறது, பின்னர் அப்போஸ்தலர்களுக்கு அனுப்பப்பட்டது. யூதா கள்ளப்போதகர்களைப் பற்றி எச்சரித்த பிறகு (4-16 வசனங்கள்) ஆவிக்குரிய போரில் நாம் எவ்வாறு வெற்றிபெற முடியும் என்பதைப் பற்றியும் அவர் அறிவுறுத்துகிறார் (வசனங்கள் 20-21). கடைசிக் காலத்தின் இந்த நாட்களில் நாம் செல்லும்போது ஏற்றுக்கொள்வதும் பின்பற்றுவதுமே ஞானம்.</p><p><b>இணைப்புகள்:</b></p><p>யூதாவின் புத்தகம் பழைய ஏற்பாட்டைப் பற்றிய குறிப்புகளால் நிரப்பப்பட்டுள்ளது, இதில் யாத்திராகமம் (வச. 5); சாத்தானின் கலகம் (வச. 6); சோதோம் மற்றும் கொமோரா (வச. 7); மோசேயின் மரணம் (வச. 9); காயீன் (வச. 11); பிலேயாம் (வச. 11); கோரா (வச. 11); ஏனோக்கு (வச. 14,15); மற்றும் ஆதாம் (வச. 14) ஆகியோரைக் குறிப்பிடுகிறது. சோதோம் மற்றும் கொமோரா, காயீன், பிலேயாம் மற்றும் கோரா ஆகியோரின் நன்கு அறியப்பட்ட வரலாற்று எடுத்துக்காட்டுகளை யூதா பயன்படுத்தி யூத கிறிஸ்தவர்களுக்கு மெய்யான விசுவாசம் மற்றும் கீழ்ப்படிதலின் அவசியத்தை நினைவூட்டுகிறது.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நாம் வரலாற்றில் ஒரு தனித்துவமான காலத்தில் வாழ்கிறோம், இந்த சிறிய புத்தகம் கடைசிக் காலங்களில் வாழமுடியாத சொல்லப்படாத சவால்களுக்கு நம்மை சித்தப்படுத்த உதவும். இன்றைய கிறிஸ்தவர்கள் தவறான கோட்பாடுகளுக்கு எச்சரிக்கையாக இருக்க வேண்டும், இது நமக்கு வார்த்தையில் நன்கு தெரியாவிட்டால் எளிதில் ஏமாற்றும். நற்செய்தியை நாம் அறிந்து கொள்ள வேண்டும் - அதைப் பாதுகாக்கவும் விடுவிக்கவும் - கிறிஸ்துவின் கர்த்தரை ஏற்றுக்கொள்ளவும், இது ஒரு வாழ்க்கை மாற்றத்தால் சாட்சியமளிக்கப்படுகிறது. உண்மையான விசுவாசம் எப்போதும் கிறிஸ்து போன்ற நடத்தையை பிரதிபலிக்கிறது. கிறிஸ்துவில் உள்ள நம்முடைய வாழ்க்கை சர்வவல்லமையுள்ள சிருஷ்டிகரின் மற்றும் விசுவாசத்தை நடைமுறைக்குக் கொண்டுவரும் பிதாவின் அதிகாரத்தின் மீது தங்கியிருக்கும் நம்முடைய சொந்த இருதய அறிவைப் பிரதிபலிக்க வேண்டும். அவருடனான அந்த தனிப்பட்ட உறவு நமக்குத் தேவை, அப்போதுதான் அவருடைய சப்தத்தை நாம் நன்கு அறிந்துகொள்வோம், வேறு எவரையும் நாம் பின்பற்றவும் மாட்டோம்.</p><p>சுமார் கி.பி. 29/30 - கிறிஸ்துவின் மரண உயிர்ப்பும் தரிசனமும் யூதாவின் மனந்திரும்புதலும்</p><p>சுமார் கி.பி.65-70 - யூதா நிருபம் எழுதப்படல்</p><p>சுமார் கி.பி. 67 - பேதுருவும் பவுலும் இரத்த சாட்சிகளாதல்</p><p>சுமார் கி.பி. 70 - எருசலேம் அழிக்கப்படல் சபையின் சிதறல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - யூதா</p><p>பெற்றோர் - தந்தை - யோசேப்பபு தாய் - மரியாள் அண்ணன் - யாக்கோபு பிற சகோதரர்கள் - யோசே. சீமோன் சகோதரிகள் - பலர்</p><p>திருப்புமுனை - கிறிஸ்துவின் உயிர்த்தெழுதலின் \"பின்பு ஏற்பட்ட மனமாற்றம்</p><p>படைப்பு - யூதா நிருபம்</p><p>சிறப்புபெயர் - விசுவாசத் துரோகிகளுக்கு எதிரானவாள்</p><p><b>சில புள்ளி விவரங்கள்</b></p><p>வேதாகமத்தின் 65-வது நூல்</p><p>அதிகாரங்கள் - 1</p><p>வசனங்கள் - 25</p><p>வரலாற்று வசனங்கள் -22</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள்  தரிசனம்  - 1</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 2</p>'),
 (730,'<p><b>வெளிப்படுத்தின விசேஷம் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>வெளிப்படுத்துதல் 1:1, 4, 9 மற்றும் 22:8 ஆகிய வசனங்கள் வெளிப்படுத்தின விசேஷம் புத்தகத்தின் எழுத்தாளரை அப்போஸ்தலனாகிய யோவான் என்று குறிப்பாக அடையாளம் காட்டுகின்றன.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>வெளிப்படுத்தின விசேஷம் புத்தகம் கி.பி. 90 மற்றும் கி.பி. 95 க்கு இடையில் எழுதப்பட்டிருக்கலாம்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>இயேசு கிறிஸ்துவின் வெளிப்பாடு யோவானுக்கு \"விரைவில் சம்பவிக்க வேண்டியதை அவருடைய ஊழியர்களுக்குக் காண்பிப்பதற்காக\" வழங்கப்பட்டது. இந்த புத்தகம் இனி வரவிருக்கும் விஷயங்களைப் பற்றிய மர்மங்களால் / இரகசியங்களால் நிரப்பப்பட்டுள்ளது. உலகம் நிச்சயமாக முடிவடையும், நியாயத்தீர்ப்பு நிச்சயம் இருக்கும் என்பது இறுதி எச்சரிக்கையாகும். இது நமக்கு பரலோகத்தின் ஒரு சிறிய காட்சியைத் தருகிறது, மேலும் அவர்களின் ஆடைகளை வெண்மையாக வைத்திருப்பவர்களுக்கு காத்திருக்கும் எல்லா மகிமைகளும் விவரிக்கப்பட்டுள்ளன. வெளிப்படுத்துதல் அதன் எல்லா உபத்திரவங்களுடனும், அவிசுவாசிகள் அனைவரும் நித்தியத்திற்காக எதிர்கொள்ளும் இறுதி அக்கினியினாலும் பெரும் உபத்திரவத்தின் மூலம் நம்மை அழைத்துச் செல்கிறது. புத்தகம் சாத்தானின் வீழ்ச்சியையும், அவனும் அவனுடைய தேவதூதர்களும் பிணைக்கப்பட்டுள்ள அழிவை மீண்டும் வலியுறுத்துகிறது. பரலோகத்தின் அனைத்து ஜீவராசிகள் மற்றும் தேவதூதர்களின் கடமைகளும், புதிய எருசலேமில் இயேசுவோடு என்றென்றும் வாழும் பரிசுத்தவான்களின் வாக்குறுதிகளும் நமக்குக் காட்டப்பட்டுள்ளன. யோவானைப் போலவே, வெளிப்படுத்துதல் புத்தகத்தில் நாம் படித்ததை விவரிக்க வார்த்தைகளைக் கண்டுபிடிப்பது என்பது மிகவும் கடினம்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>வெளிப்படுத்துதல் 1:19, \"நீ கண்டவைகளையும், இருக்கிறவைகளையும், இவைகளுக்குப்பின்பு சம்பவிப்பவைகளையும் எழுது.\"</p><p>வெளிப்படுத்துதல் 13:16-17, \"அது சிறியோர், பெரியோர், ஐசுவரியவான்கள், தரித்திரர், சுயாதீனர், அடிமைகள், இவர்கள் யாவரும் தங்கள் தங்கள் வலதுகைகளிலாவது நெற்றிகளிலாவது ஒரு முத்திரையைப் பெறும்படிக்கும், அந்த மிருகத்தின் முத்திரையையாவது அதின் நாமத்தையாவது அதின் நாமத்தின் இலக்கத்தையாவது தரித்துக்கொள்ளுகிறவன் தவிர வேறொருவனும் கொள்ளவும் விற்கவுங் கூடாதபடிக்கும் செய்தது.\"</p><p>வெளிப்படுத்துதல் 19:11, \"பின்பு, பரலோகம் திறந்திருக்கக்கண்டேன்; இதோ, ஒரு வெள்ளைக்குதிரை காணப்பட்டது, அதின்மேல் ஏறியிருந்தவர் உண்மையும் சத்தியமுமுள்ளவரென்னப்பட்டவர்; அவர் நீதியாய் நியாயந்தீர்த்து யுத்தம்பண்ணுகிறார்.\"</p><p>வெளிப்படுத்துதல் 20:11, \"பின்பு, நான் பெரிய வெள்ளைச் சிங்காசனத்தையும் அதின்மேல் வீற்றிருக்கிறவரையும் கண்டேன்; அவருடைய சமுகத்திலிருந்து பூமியும் வானமும் அகன்றுபோயின; அவைகளுக்கு இடங்காணப்படவில்லை.\"</p><p>வெளிப்படுத்துதல் 21:1, \"பின்பு, நான் புதிய வானத்தையும் புதிய பூமியையும் கண்டேன்; முந்தின வானமும் முந்தின பூமியும் ஒழிந்துபோயின; சமுத்திரமும் இல்லாமற்போயிற்று.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>கிறிஸ்துவின் வருகைக்கு முந்தைய நாட்களிலும், புதிய வானத்தையும் புதிய பூமியையும் கொண்டுவருவதற்கு கடைசி நாட்களில் நமக்கு அறிவிக்கும் தரிசனங்களின் வண்ணமயமான விளக்கங்களில் வெளிப்பாடு பகட்டானது. ஆசியா மைனரின் ஏழு திருச்சபைகளுக்கான கடிதங்களுடன் வெளிப்பாடு தொடங்குகிறது, பின்னர் பூமியில் கொட்டப்பட்ட பேரழிவுகளின் தொடர்ச்சியை வெளிப்படுத்துகிறது; மிருகத்தின் குறியீடு \"666\"; அர்மகெதோனின் உச்சகட்ட போர்; சாத்தானின் கட்டப்படுதல்; கர்த்தருடைய ஆயிரவருட ஆட்சி; பெரிய வெள்ளை சிங்காசன தீர்ப்பு; தேவனுடைய நித்திய நகரத்தின் தன்மை. இயேசு கிறிஸ்துவைப் பற்றிய தீர்க்கதரிசனங்கள் நிறைவேறுகின்றன, அவருடைய கர்த்தத்துவத்திற்கு ஒரு இறுதி அழைப்பு அவர் விரைவில் திரும்புவார் என்று நமக்கு உறுதியளிக்கிறது.</p><p><b>இணைப்புகள்:</b></p><p>வெளிப்படுத்துதல் புத்தகம் பழைய ஏற்பாட்டில் தொடங்கிய அனைத்து இறுதி காலங்களைப் பற்றிய தீர்க்கதரிசனங்களின் நிறைவேறுதலின் உச்சமாகும். தானியேல் 9:27-ல் குறிப்பிடப்பட்டுள்ள எதிர்க்கிறிஸ்துவின் விளக்கம் வெளிப்படுத்துதல் 13-ஆம் அதிகாரத்தில் முழுமையாக விவரிக்கப்பட்டுள்ளது. வெளிப்படுத்துதலுக்கு வெளியே, வேதாகமத்தில் வெளிப்படுத்தல் இலக்கியத்தின் எடுத்துக்காட்டுகள் தானியேல் 7-12 வரையிலுள்ள அதிகாரங்கள், ஏசாயா 24-27 வரையிலுள்ள அதிகாரங்கள், எசேக்கியேல் 37-41 வரையிலுள்ள அதிகாரங்கள் மற்றும் சகரியா 9-14 வரையிலுள்ள அதிகாரங்கள். இந்த தீர்க்கதரிசனங்கள் அனைத்தும் வெளிப்படுத்துதல் புத்தகத்தில் ஒன்றாக வந்துள்ளன.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>கிறிஸ்துவை உங்கள் இரட்சகராக ஏற்றுக்கொண்டீர்களா? அப்படியானால், வெளிப்படுத்துதல் புத்தகத்தில் விவரிக்கப்பட்டுள்ளபடி உலகத்தைப் பற்றிய தேவனுடைய நியாயத்தீர்ப்பிற்கு நீங்கள் பயப்பட ஒன்றுமில்லை. பிரதான நீதிபதி நம் பக்கத்தில் இருக்கிறார். இறுதித் தீர்ப்பு தொடங்குவதற்கு முன், கிறிஸ்துவில் நித்திய ஜீவனை தேவன் அளிப்பதைப் பற்றி நண்பர்களுக்கும் அயலகத்தார்களுக்கும் நாம் சாட்சி கொடுக்க வேண்டும். இந்த புத்தகத்தில் உள்ள நிகழ்வுகள் யாவும் உண்மையாகவே சம்பவிக்கப்போகிறவைகள் ஆகும். நாம் விசுவாசிப்பதைப் போலவே நாம் நம் வாழ்க்கையையும் வாழ வேண்டும், இதனால் மற்றவர்கள் நம் எதிர்காலத்தைப் பற்றிய மகிழ்ச்சியைக் கவனிப்பார்கள், மேலும் புதிய மற்றும் புகழ்பெற்ற நகரத்தில் நம்முடன் சேர விரும்புவார்கள்.</p><p>சுமார் கி.பி. 27 - யோவான் சீஷனாக அழைக்கப்படல்</p><p>சுமார் கி.பி. 29/30 - கிறிஸ்துவின் மரணம்</p><p>சுமார் கி.பி. 30 - யோவான் திருச்சபையில் முக்கியமானவராதல்</p><p>சுமார் கி.பி. 70 - எருசலேம் அழிவு</p><p>சுமார் கி.பி. 90-95 - யோவான் நிருபங்களை எழுதுதல்</p><p>சுமார் கி.பி.93 - யோவான் நாடு கடத்தப்படல்</p><p>சுமார் கி.பி.90-96 - யோவான் வெளிப்படுத் தின விசேஷம் எழுதுதல்</p><p>சுமார் கி.பி. 29-100 - எபேசு சபைக் காலகட்டம்</p><p>சுமார் கி.பி. 100-300 - சிமிர்னா சபைக் கால கட்டம்</p><p>சுமார் கி.பி.300-800 - பெர்கமு சபைக் காலகட்டம்</p><p>சுமார் கி.பி. 800-1517 - தியத்தீரா சபைக் கால கட்டம்</p><p>சுமார் கி.பி.1517 - சர்தை சபைக் காலகட்டம் இறுதிகாலம்</p><p>பிலதெல்பியா லவோதிக்கேயா சபைகளின் காலகட்டம்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - யோவான் அப்போஸ்தலர்</p><p>நூல் எழுதிய இடம் - பத்மு தீவு, ஆசியா மைனர் கடல் துறைக்கு அண்மையில், ஏஜியன் கடல் தீவு. எரிமலைகள் நிறைந்த பகுதி, ரோம அரசு குற்றவாளிகளை நாடு கடத்தும் தீவு</p><p>யோவானும் நாடு கடத்தலும் - கிறிஸ்துவின் சாட்சியாக வாழ்ந்த காரணத் தால் ரோமப் பேரரசின் டொமீஷயன் பேரரசரால் இவர் கி.பி 90 - 95க்கும் இடைப்பட்ட காலத்தில் நாடு கடத்தப் பட்டார். டொமீஷியன் கி.பி. 81 - 96 வரை ரோமாபுரியை ஆண்டவர்</p><p>ஆர்வம் - இனி சம்பவிக்கும் காரியங்களை திரைவிலக்கிக் காட்டும் காரியங்களை எழுதுதல்</p><p>சாதனை - அழகிய குறியீட்டு மொழி நடையில் அவற்றைச் சொல்லோவியமாக்கியது</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 66-வது நூல்</p><p>அதிகாரங்கள் - 22</p><p>வசனங்கள் - 404</p><p>கேள்விகள் - 9</p><p>வரலாற்று வசனங்கள் - 53</p><p>நிறைவேறிய தீர்க்கதரிசனங்கள் - 10</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனங்கள் - 341</p>'),
 (80,'<p><b>ரூத்தின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>ரூத்தின் புத்தகம் குறிப்பாக அதன் எழுத்தாளர் யார் என்று அவரது பெயரைக் குறிப்பிடவில்லை. பாரம்பரிய மரபு என்னவென்றால், ரூத்தின் புத்தகம் சாமுவேல் தீர்க்கதரிசியால் எழுதப்பட்டது என்பதாகும்.</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>ரூத்தின் புத்தகம் எழுதப்பட்ட சரியான காலம் தெரியவில்லை. இருப்பினும், நடைமுறையில் உள்ள முதன்மையான பார்வை இந்த புத்தகம் கி.மு. 1011 முதல் கி.மு. 931 வரையிலுள்ள ஆண்டுகளுக்கு இடையில் எழுதப்பட்டது என்பதாகும்.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>ரூத்தின் புத்தகம் இஸ்ரவேலருக்கு எழுதப்பட்டது. சில சமயங்களில் உண்மையான அன்புக்கு சமரசமற்ற தியாகம் தேவைப்படலாம் என்று அது கற்பிக்கிறது. நம்முடைய வாழ்க்கையில் உள்ள நிறைய விஷயங்களைப் பொருட்படுத்தாமல், தேவனுடைய கட்டளைகளின்படி வாழ முடியும். உண்மையான அன்பும் தயவும் வெகுமதி அளிக்கும். கீழ்ப்படிதலுள்ள வாழ்க்கையை வாழ முற்படுபவர்களை தேவன் ஏராளமாக ஆசீர்வதிக்கிறார். கீழ்ப்படிதலுள்ள வாழ்க்கை தேவனுடைய திட்டத்தில் \"விபத்துக்களை\" அனுமதிக்காது. தேவன் இரக்கமுள்ளவர்களுக்கு இரக்கம் காட்டுகிறார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>ரூத் 1:16, \"அதற்கு ரூத்: நான் உம்மைப் பின்பற்றாமல் உம்மைவிட்டுத் திரும்பிப் போவதைக்குறித்து, என்னோடே பேசவேண்டாம்; நீர் போகும் இடத்திற்கு நானும் வருவேன்; நீர் தங்கும் இடத்திலே நானும் தங்குவேன்; உம்முடைய ஜனம் என்னுடைய ஜனம்; உம்முடைய தேவன் என்னுடைய தேவன்.\"</p><p>ரூத் 3:9, \"நீ யார் என்று கேட்டான்; அவள், நான் உம்முடைய அடியாளாகிய ரூத்; நீர் உம்முடைய அடியாள்மேல் உம்முடைய போர்வையை விரியும்; நீர் சுதந்தரவாளி என்றாள்.\"</p><p>ரூத் 4:17, \"அயல் வீட்டுக்காரிகள் நகோமிக்கு ஒரு ஆண்பிள்ளை பிறந்தது என்று வாழ்த்தி, அதற்கு ஓபேத் என்று பேரிட்டார்கள்; அவன் தாவீதின் தகப்பனாகிய ஈசாயின் தகப்பன்.\"</p><p><b>சுருக்கமான திரட்டு:</b></p><p>ரூத் புத்தகத்திற்கான அமைப்பு சவக்கடலின் வடகிழக்கில் ஒரு பகுதியான மோவாப் என்ற புறஜாதி நாட்டில் தொடங்குகிறது, ஆனால் பின்னர் பெத்லகேமுக்கு நகர்கிறது. இந்த உண்மையான கணக்கு இஸ்ரவேலர்களின் தோல்வி மற்றும் கலகத்தின் மோசமான நாட்களில் நடைபெறுகிறது, இது நியாயாதிபதிகளின் காலம் என்று அழைக்கப்படுகிறது. தேசத்தில் உண்டாயிருந்த ஒரு பஞ்சம் எலிமெலேக்கையும் அவருடைய மனைவி நகோமியையும் இஸ்ரவேல் தேசத்திலிருந்து அதாவது பெத்லேமிலிருந்து மோவாப் நாட்டுக்குப் போகத் தூண்டுகிறது. எலிமெலேக் அங்கெ இறந்துவிடுகிறார், நகோமி தனது 2 மகன்களுடன் எஞ்சியிருக்கிறார், அவர்கள் விரைவில் 2 மோவாபிய பெண்களான ஓர்பா மற்றும் ரூத்தை திருமணம் செய்து கொள்கிறார்கள். பின்னர் மகன்கள் இருவரும் இறந்துவிடுகிறார்கள், நகோமி ஓர்பா மற்றும் ரூத்துடன் ஒரு அந்நிய தேசத்தில் தனியாக இருக்கிறார். ஓர்பா தனது பெற்றோரிடம் திரும்பி வருகிறாள், ஆனால் பெத்லகேமுக்குச் செல்லும்போது நகோமியுடன் செல்ல ரூத் தீர்மானிக்கிறாள். அன்பு மற்றும் பக்தியின் இந்த கதை, போவாஸ் என்ற ஒரு செல்வந்தனுடன் ரூத் திருமணம் செய்துகொள்வதைக் கூறுகிறது, அவளால் ஓபேத் என்ற மகனைப் பெற்றெடுத்தார், அவர் தாவீதின் தாத்தாவாகவும் அதாவது இயேசுவின் மூதாதையராகவும் மாறுகிறார். கீழ்ப்படிதல் ரூத்தை கிறிஸ்துவின் சலுகை பெற்ற வம்சாவளியில் கொண்டுவருகிறது.</p><p><b>முன்னிழல்கள்:</b></p><p>ரூத் புத்தகத்தின் ஒரு முக்கிய கருப்பொருள் உறவின்முறை-மீட்பர் ஆகும். ரூத்தின் கணவரின் அடுத்த உறவினரான போவாஸ், மோசே நியாயப்பிரமாணத்தில் கோடிட்டுக் காட்டப்பட்டுள்ளபடி, ஒரு வறிய உறவினரை அவனது சூழ்நிலைகளிலிருந்து மீட்பதற்காக தனது கடமையைச் செய்தான் (லேவி. 25:47-49). இந்த காட்சியை கிறிஸ்து மீண்டும் செய்கிறார், அவர் நம்மை ஆவிக்குரிய ரீதியில் வறியவர்களாக உள்ளவர்களின் பாவத்தின் அடிமைத்தனத்திலிருந்து மீட்டுக்கொள்கிறார். நம்முடைய பரலோகப் பிதா தம்முடைய குமாரனை சிலுவையில் மரிக்கும் படியாக அனுப்பினார், இதனால் நாம் தேவனுடைய பிள்ளைகளாகவும் கிறிஸ்துவின் சகோதர சகோதரிகளாகவும் ஆகிவிட்டோம். நம்முடைய மீட்பராக இருப்பதன் மூலம், நாம் அவருடைய உறவினர்களாக மாறுகிறோம்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>நம்முடைய பெரிய தேவனின் இறையாண்மை ரூத்தின் கதையில் தெளிவாகக் காணப்படுகிறது. அவர் தனது பிள்ளையாக மாறுவதற்கான ஒவ்வொரு அடியையும் அவளுக்கு காண்பித்து வழிகாட்டினார், மேலும் இயேசு கிறிஸ்துவின் மூதாதையராக ஆவதற்கான தனது திட்டத்தையும் நிறைவேற்றினார் (மத்தேயு 1:5). அதேபோல், நம் ஒவ்வொருவருக்கும் தேவன் ஒரு திட்டத்தை வைத்திருக்கிறார் என்பதில் நமக்கும் உறுதியுள்ளது. நகோமியும் ரூத்தும் அவருக்காக விசுவாசம் வைத்து நம்பிக்கையோடு இருந்தது போலவே, நாமும் அவ்வாறு செய்ய வேண்டும்.</p><p>நீதிமொழிகள் 31-ல் கூறப்பட்டுள்ள குணாசாலியான ஸ்திரீயின் உதாரணத்தை ரூத்தில் காண்கிறோம். அவளுடைய குடும்பத்தினருக்காக அர்ப்பணிப்புடன் (ரூத் 1:15-18; நீதிமொழிகள் 31:10-12) மற்றும் தேவனையே மெய்யாக நம்பியிருக்கும் (ரூத் 2:12; நீதிமொழிகள் 31:30), தேவபக்தியுள்ள ஒரு பெண்ணை ரூத்தில் காண்கிறோம். நகோமி மற்றும் போவாஸ் ஆகியோருக்கு அவளுடைய அன்பான, கனிவான, மற்றும் மரியாதைக்குரிய வார்த்தைகளைக் காண்கிறோம். நீதிமொழிகள் 31-ன் குணாசாலியான ஸ்திரீ \"தன் வாயை ஞானம் விளங்கத் திறக்கிறாள்; தயையுள்ள போதகம் அவள் நாவின்மேல் இருக்கிறது\" (வச. 26). நம்முடைய முன்மாதிரியாக இருப்பதற்கு ரூத் போன்ற தகுதியான ஒரு பெண்ணை இன்று கண்டுபிடிக்க நாம் இங்கும் அங்குமாக தேடி அலைய வேண்டும்.</p><p>சுமார் கி.மு. 1451 (1406) - இஸ்ரவேலர் கானானை அடைதல்</p><p>சுமார் கி.மு. 1434 (1375) - யோகவாவின் மரணம்</p><p>சுமார் கி.மு.1409 (1367) - ஒத்னியேல் முதல் நியாயாதிபதியாதல்</p><p>சுமார் கி.மு.1041 (1090) - சாமுவேல் இறுதி நியாயாதிபதியாதல்</p><p>சுமார் கி.மு.1001 (1050) - சவுல் அரசராதல்</p><p>சுமார் கி.மு.991 (1040) - தாவீதின் பிறப்பு</p><p>சுமார் கி.மு. 962 (1010) - தாவீது அரசராதல்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>ரூத்தின் சரித்திரம் - பெயர் ரூத் (நட்பு/நண்பி)</p><p>இடம் - மோவாப்</p><p>கணவர் - மக்லோன் (4: 10)</p><p>கணவர் பெற்றோர் - எலிமெலேக்கு/நகோமி</p><p>தோழி - ஓர்பாள், கணவரின் தம்பி மனைவி</p><p>திருப்பு முனை - கணவனின் மறைவின் பின்மாமியான நகோமி தாய்நாடு திரும்பிய போது அவள் எடுத்த தீர்மானம் (1: 16)</p><p>சாதனை - போவாஸ் என்னும் பணக்காரர். தனக்கு உறவின் முறையான் என அறிந்த போது விசுவாசத் துணிச்சலுடன் திருமணம் செய்யக் கேட்டது.</p><p>பட்டப்பெயர் - குணசாலி (3 : 11)</p><p>சிறப்பு - தாவீது அரசருக்கும், இயேசு கிறிஸ்துவுக்கும் மூதாதையாக மாறியது (மத் 1: 5)</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 8 வது நூல்</p><p>அதிகாரங்கள் - 4</p><p>வசனங்கள் - 85</p><p>கேள்விகள் - 16</p><p>தீர்க்கதரிசனங்கள் - இஸ்ரவேலிற்கு ஒரு தீர்க்கதரிசி வழியானச் செய்தி பொரிக்கப்பட்டதான முதல் நூல்</p><p>கட்டளைகள் - 30</p><p>வாக்குகக்கங்கள் - 2</p>'),
 (90,'<p><b>1 சாமுவேலின் புத்தகம்</b></p><p><b>எழுத்தாளர்:</b></p><p>இந்த புத்தகத்தின் எழுத்தாளர் யார் என்று அறியப்படவில்லை. சாமுவேல் தீர்க்கதரிசி ஒரு புத்தகத்தை எழுதினார் என்பதை நாம் அறிவோம் (1 சாமுவேல் 10:25), இந்த புத்தகத்தின் ஒரு பகுதியையும் அவர் எழுதியது மிகவும் சாத்தியம். 1 சாமுவேல் புத்தகத்தை எழுதினதாக பரிந்துரைக்கப்படும் மற்றவர்கள் தீர்க்கதரிசிகள் / வரலாற்றாசிரியர்கள் நாத்தன் மற்றும் காத் (1 நாளாகமம் 29:29).</p><p><b>எழுதப்பட்ட காலம்:</b></p><p>முதலில், 1 மற்றும் 2 சாமுவேலின் புத்தகங்கள் ஒரேஒரு புத்தகமாக இருந்தன. செப்டுவஜின்ட்டின் (கிரேக்க மொழி பழைய ஏற்பாடு) மொழிபெயர்ப்பாளர்கள் இந்த புத்தகங்களை இரண்டாகப் பிரித்தனர், அன்றிலிருந்து அந்த பிரிகளை நாம் தக்க வைத்துக் கொண்டோம். கி.மு. 1100 முதல் கி.மு. 1000 வரையிலுள்ள சுமார் 100 ஆண்டுகள் நிகழ்வுகளை 1 சாமுவேலின் புத்தகம் கொண்டுள்ளது. 2 சாமுவேலின் நிகழ்வுகள் மேலும் 40 ஆண்டுகளை உள்ளடக்கியுள்ளது. ஆகவே இந்த புத்தகம் எழுதப்பட்ட காலம் கி.மு. 960.</p><p><b>எழுதப்பட்டதன் நோக்கம்:</b></p><p>1 சாமுவேல் புத்தகம் கானான் தேசத்தில் இஸ்ரவேலின் வரலாற்றை பதிவு செய்கிறது, அதாவது அவர்கள் நியாயாதிபதிகளின் ஆட்சியில் இருந்து ராஜாக்களின் கீழ் ஒரு ஒருங்கிணைந்த தேசமாக மாறுகிறார்கள். சாமுவேல் கடைசி நியாயாதிபதியாக தோன்றுகிறார், அவர் முதல் இரண்டு ராஜாக்களான சவுல் மற்றும் தாவீதை அபிஷேகம் செய்கிறார்.</p><p><b>திறவுகோல் வசனங்கள்:</b></p><p>\"எங்களை நியாயம் விசாரிக்க ஒரு ராஜாவை ஏற்படுத்தும் என்று அவர்கள் சொன்ன வார்த்தை சாமுவேலுக்குத் தகாததாய்க் காணப்பட்டது; ஆகையால் சாமுவேல் கர்த்தரை நோக்கி விண்ணப்பம்பண்ணினான். அப்பொழுது கர்த்தர் சாமுவேலை நோக்கி: ஜனங்கள் உன்னிடத்தில் சொல்வதெல்லாவற்றிலும் அவர்கள் சொல்லைக் கேள்; அவர்கள் உன்னைத் தள்ளவில்லை, நான் அவர்களை ஆளாதபடிக்கு, என்னைத்தான் தள்ளினார்கள். (1 சாமுவேல் 8:6-7).</p><p><b>\"சாமுவேல் சவுலைப் பார்த்து:</b></p><p>புத்தியீனமாய்ச் செய்தீர்; உம்முடைய தேவனாகிய கர்த்தர் உமக்கு விதித்த கட்டளையைக் கைக்கொள்ளாமற்போனீர்; மற்றப்படி கர்த்தர் இஸ்ரவேலின் மேல் உம்முடைய ராஜ்யபாரத்தை என்றைக்கும் ஸ்திரப்படுத்துவார். இப்போதோ உம்முடைய ராஜ்யபாரம் நிலைநிற்காது; கர்த்தர் தம்முடைய இருதயத்திற்கு ஏற்ற ஒரு மனுஷனைத் தமக்குத் தேடி, அவனைக் கர்த்தர் தம்முடைய ஜனங்கள்மேல் தலைவனாயிருக்கக் கட்டளையிட்டார்; கர்த்தர் உமக்கு விதித்த கட்டளையை நீர் கைக்கொள்ளவில்லையே என்று சொன்னான்’’ (1 சாமுவேல் 13:13-14).</p><p><b>\"அதற்குச் சாமுவேல்:</b></p><p>கர்த்தருடைய சத்தத்திற்குக் கீழ்ப்படிகிறதைப்பார்க்கிலும், சர்வாங்க தகனங்களும் பலிகளும் கர்த்தருக்குப் பிரியமாயிருக்குமோ? பலியைப்பார்க்கிலும் கீழ்ப்படிதலும், ஆட்டுக்கடாக்களின் நிணத்தைப்பார்க்கிலும் செவிகொடுத்தலும் உத்தமம். இரண்டகம்பண்ணுதல் பில்லிசூனியபாவத்திற்கும், முரட்டாட்டம்பண்ணுதல் அவபக்திக்கும் விக்கிரகாராதனைக்கும் சரியாய் இருக்கிறது; நீர் கர்த்தருடைய வார்த்தையைப் புறக்கணித்தபடியினாலே, அவர் உம்மை ராஜாவாயிராதபடிக்குப் புறக்கணித்துத் தள்ளினார் என்றான்\" (1 சாமுவேல் 15:22-23).</p><p><b>சுருக்கமான திரட்டு:</b></p><p>1 சாமுவேலின் புத்தகத்தை நேர்த்தியாக இரண்டு பிரிவுகளாகப் பிரிக்கலாம்: சாமுவேலின் வாழ்க்கை (1-12 வரையிலுள்ள அதிகாரங்கள்) மற்றும் சவுலின் வாழ்க்கை (13-31 வரையிலுள்ள அதிகாரங்கள்).</p><p>சாமுவேல் தாயாரின் அற்புதமான பிரார்த்தனைக்கு பதிலளிக்கும் விதமாக இந்த புத்தகம் தொடங்குகிறது. ஒரு குழந்தையாக இருந்தபோது, சாமுவேல் ஆலயத்தில் வாழ்ந்து சேவை செய்தார். தேவன் அவரை ஒரு தீர்க்கதரிசி என்று தனித்துவப்படுத்தினார் (3:19-21), பிள்ளையின் முதல் தீர்க்கதரிசனம் ஊழல் நிறைந்த ஆசாரியர்கள் மீதான தீர்ப்பில் ஒன்றாகும்.</p><p>இஸ்ரவேலர் தங்கள் வற்றாத எதிரிகளான பெலிஸ்தர்களுடன் போருக்குச் செல்கிறார்கள். பெலிஸ்தர்கள் உடன்படிக்கைப் பெட்டியைக் கைப்பற்றி அதை தற்காலிகமாக வைத்திருக்கிறார்கள், ஆனால் கர்த்தர் நியாயத்தீர்ப்பை அனுப்பும்போது, பெலிஸ்தர்கள் உடன்படிக்கைப் பெட்டியைத் திருப்பித் தருகிறார்கள். சாமுவேல் இஸ்ரவேலை மனந்திரும்புதலுக்கும் (7 3-6) பின்னர் பெலிஸ்தர்களுக்கு எதிரான வெற்றிக்கும் அழைக்கிறார்.</p><p>இஸ்ரவேல் ஜனம், மற்ற தேசங்களைப் போல இருக்க விரும்புகிறார்கள், தங்களுக்கு ஒரு ராஜாவை வேண்டும் என்று விரும்புகிறார்கள். சாமுவேல் அவர்களின் கோரிக்கைகளால் அதிருப்தி அடைகிறார், ஆனால் அவர்கள் நிராகரிப்பது சாமுவேலின் தலைமையை அல்ல, ஆனால் அவர்களுடைய தேவனை என்று கர்த்தர் அவரிடம் கூறுகிறார். ஒரு ராஜாவைக் கொண்டிருப்பதன் அர்த்தம் என்ன என்று மக்களுக்கு எச்சரித்தபின், சாமுவேல் மிஸ்பாவில் முடிசூட்டப்பட்ட சவுல் என்ற பென்யமீன் கோத்திரத்தில் பட்டவனை அபிஷேகம் செய்கிறான் (10:7-25).</p><p>சவுல் ஆரம்ப வெற்றியைப் பெற்று பூரிக்கிறார், அம்மோனியர்களை போரில் தோற்கடித்தார் (அதிகாரம் 11). ஆனால் பின்னர் அவர் தொடர்ச்சியான தவறான அடிகளை எடுத்து வைக்கிறார்: அவர் ஒரு பலியை செலுத்துகிறார் (அதிகாரம் 13), அவர் தனது குமாரன் யோனாத்தானை இழக்க இழப்பில் ஒரு முட்டாள்தனமான சபதம் செய்கிறார் (அதிகாரம் 14), மேலும் அவர் கர்த்தருடைய நேரடி கட்டளைக்கு கீழ்ப்படியவில்லை (அதிகாரம் 15). சவுலின் கிளர்ச்சியின் விளைவாக, சவுலின் இடத்தைப் நிரப்ப தேவன் வேறொருவரைத் தேர்ந்தெடுக்கிறார். இதற்கிடையில், தேவன் தம்முடைய ஆசீர்வாதத்தை சவுலிடமிருந்து நீக்குகிறார், ஒரு தீய ஆவி சவுலை பைத்தியக்காரத்தனமாக செயல்பட அவனை நோக்கித் தொடங்குகிறது (16:14).</p><p>தாவீது என்ற வாலிபனை அடுத்த ராஜாவாக அபிஷேகம் செய்ய சாமுவேல் பெத்லகேமுக்குச் செல்கிறார் (அதிகாரம் 16). பின்னர், தாவீது பெலிஸ்தியரான கோலியாத்துடன் தனது புகழ்பெற்ற மோதலை சந்திக்கிறார், மேலும் அவர் ஒரு தேசிய வீரனாக மாறுகிறார் (அதிகாரம் 17). தாவீது சவுலின் மன்றத்தில் பணியாற்றுகிறார், சவுலின் மகளை மணக்கிறார், சவுலின் மகனுடன் நட்பு கொள்கிறார். தாவீதின் வெற்றி மற்றும் புகழ் குறித்து சவுல் பொறாமை கொள்கிறான், அவன் தாவீதைக் கொல்ல முயற்சிக்கிறான். தாவீது அவனிடமிருந்து அவன் கைக்குத் தப்பி ஓடுகிறார், எனவே சாகசப்பயணம், சூழ்ச்சி மற்றும் காதல் ஆகியவற்றின் அசாதாரண காலத்தைத் தாவீது தொடங்குகிறார். இயற்கைக்கு அப்பாற்பட்ட தெய்வீக உதவியுடன், தாவீது இரத்தவெறி கொண்ட சவுலை குறுகியதாக ஆனால் தொடர்ந்து தவிர்க்கிறார் (அதிகாரங்கள் 19-26). இதன் மூலம், தாவீது தனது நேர்மையையும், யோனாத்தானுடனான நட்பையும் பராமரிக்கிறார்.</p><p>புத்தகத்தின் முடிவில், சாமுவேல் இறந்துவிடுகிறார், சவுல் ஒரு இழந்த மனிதர் போலாகிறார். பெலிஸ்தியாவுடனான ஒரு போருக்கு முன்பு, சவுல் பதில்களைத் தேடுகிறான். தேவனை நிராகரித்த அவர், பரலோகத்திலிருந்து எந்த உதவியையும் காணவில்லை, அதற்கு பதிலாக ஒரு குறிச்சொல்லுபவளிடம் இருந்து ஆலோசனையை நாடுகிறார். அப்பொழுது போது, சாமுவேலின் ஆவி மரித்தோரிலிருந்து ஒரு கடைசி தீர்க்கதரிசனத்தை உரைக்கிறது: சவுல் மறுநாள் போரில் இறந்துவிடுவான். தீர்க்கதரிசனம் நிறைவேறியது; சவுலின் மூன்று மகன்கள், யோனாத்தான் உட்பட யாவரும் போரில் மடிகிறார்கள், சவுல் தற்கொலை செய்து கொள்கிறான்.</p><p><b>முன்னிழல்கள்:</b></p><p>1 சாமுவேல் 2:1-10-ல் அன்னாளின் ஜெபம் கிறிஸ்துவைப் பற்றிய பல தீர்க்கதரிசன குறிப்புகளைக் கொண்டுள்ளது. அவள் தேவனை தன் பாறை என்று புகழ்கிறாள் (வச. 2), நம்முடைய ஆவிக்குரிய வீடுகளை நாம் கட்டியெழுப்ப வேண்டிய பாறை இயேசு என்று சுவிசேஷக் கணக்குகளிலிருந்து நாம் அறிவோம். பவுல் இயேசுவை யூதர்களுக்கு \"இடறுதற்கான பாறை\" என்று குறிப்பிடுகிறார் (ரோமர் 9:33). கிறிஸ்து \"ஆவிக்குரிய பாறை\" என்று அழைக்கப்படுகிறார், அவர் இஸ்ரவேலருக்கு வனாந்தரத்தில் ஆவிக்குரிய பானத்தை வழங்கினார், அவர் நம்முடைய ஆத்துமாக்களுக்கு \"ஜீவ தண்ணீரை\" வழங்குகிறார் (1 கொரிந்தியர் 10:4; யோவான் 4:10). அன்னாளின் ஜெபம் பூமியின் முனைகளை நியாயந்தீர்க்கும் கர்த்தரைக் குறிப்பிடுகிறது (வச. 2:10), மத்தேயு 25:31-32ல் இயேசுவை மனுஷகுமாரன் என்று குறிப்பிடுகிறது, அவர் அனைவரையும் நியாயந்தீர்க்க மகிமையுடன் வருவார்.</p><p><b>நடைமுறை பயன்பாடு:</b></p><p>சவுலின் சோகமான கதை வீணான வாய்ப்பைப் பற்றிய ஒரு ஆய்வாகும். மரியாதை, அதிகாரம், செல்வம், நல்ல தோற்றம் மற்றும் பலவற்றைக் கொண்டிருந்த ஒரு மனிதனாக சவுல் இருந்தான். ஆனாலும் அவன் விரக்தியில் இறந்தான், எதிரிகளைப் பார்த்து பயந்து, அவர் தனது தேசத்தையும், குடும்பத்தையும், கடவுளையும் தோல்வியுற்றதை அறிந்திருந்தான்.</p><p>கீழ்ப்படியாமை மூலம் தேவனைப் பிரியப்படுத்த முடியும் என்று நினைப்பதில் சவுல் தவறு செய்தார். இன்றைய பலரைப் போலவே, ஒரு விவேகமான நோக்கம் மோசமான நடத்தைக்கு ஈடுசெய்யும் என்று அவர் நம்பினார். ஒருவேளை அவரது வல்லமை அவரது தலைக்குச் சென்றிருக்கலாம், அவர் விதிகளுக்கு மேலே இருப்பதாக அவர் நினைக்கத் தொடங்கினார். எப்படியாவது அவர் தேவனுடைய கட்டளைகளைப் பற்றிய குறைந்த கருத்தையும், தன்னைப் பற்றிய உயர்ந்த கருத்தையும் வளர்த்துக் கொண்டார். அவர் செய்த தவறுகளை எதிர்கொள்ளும்போது கூட, அவர் தன்னை நிரூபிக்க முயன்றார், அப்பொழுதுதான் தேவன் அவரை நிராகரித்தார் (15:16-28).</p><p>சவுலின் பிரச்சினை நாம் அனைவரும் எதிர்கொள்ளும் ஒன்றாகும் – இது ஒரு இதயத்தின் பிரச்சினை. தேவனுடைய சித்தத்திற்குக் கீழ்ப்படிதல் வெற்றிக்கு அவசியம், நாம் பெருமையுடன் அவருக்கு எதிராகக் கிளர்ந்தெழுந்தால், இழப்புக்கு நம்மை அமைத்துக் கொள்கிறோம்.</p><p>மறுபுறம், தாவீது முதலில் பெரிதாகத் தெரியவில்லை. சாமுவேல் கூட அவரைப் புறக்கணிக்க ஆசைப்பட்டார் (16:6-7). ஆனால் தேவன் இருதயத்தைக் காண்கிறார், தாவீதை தனது இருதயத்திற்கு ஏற்ற ஒரு மனிதனாக பார்த்தார் (13:14). தாவீதின் மனத்தாழ்மையும், நேர்மையும், கர்த்தருக்கு அவர் காட்டிய பக்தி வைராக்கியமும் தைரியமும், ஜெபத்தில் அவர் கொண்டிருந்த அர்ப்பணிப்பும், நம் அனைவருக்கும் ஒரு சிறந்த முன்மாதிரியாக அமைந்தது.</p><p>சுமார் கி.மு.1056 (1105) - சாமுவேலின் பிறப்பு</p><p>சுமார் கி.மு. 1041 (1090) - சாமுவேல் நியாயாதிபதியாதல்</p><p>சுமார் கி.மு. 1031 (1080) - சவுலின் பிறப்பு.</p><p>சுமார் கி.மு.1001 (1050) - சவுல் அரசராதல்</p><p>சுமார் கி.மு.991 (1040) - தாவீது பிறத்தல்</p><p>சுமார் கி.மு. 976 (1025) - தாவீது அபிஷேகம் பண்ணப்படல்</p><p>சுமார் கி.மு.962 (1010) - சவுவின் மரணம்</p><p>சுமார் கி.மு. 962 (1010) - தாவீது யூதாவின் அரசராதல்</p><p>சுமார் கி.மு. 954 (1003) - தாவீது முழு இஸ்ரவேலின் அரசரால்</p><p>சுமார் கி.மு. 921 (970) - தாவீதின் மரணம்</p><p><b>ஆசிரியர் குறிப்பு</b></p><p>பெயர் - சாமுவேல் (தேவனிடம் கேட்டுப் பெற்ற/ தேவனின் நாமம்)</p><p>இடம் - ராமா (1சாமு 1: 17:17) இது வட எருசலேமின் எப்பிராயீம் மலைப் பகுதியில் இருக்கிறது.</p><p>குடும்பம் - தந்தை - எல்க்கானா /தாய் - அன்னாள்</p><p>உறவினர் - மூன்று சகோதரர்கள், 2 சகோதரிகள் (2 : 21), தந்தையின் பிற பிள்ளைகள்</p><p>பிள்ளைகள் - யோவேல், அபியா (8 : 2)</p><p>ஆன்மீக வழிகாட்டி - ஏலி நியாயாதிபதி</p><p>தொழில் - நியாயம் விசாரித்தல், தீர்க்கதரிசனம் உரைத்தல்</p><p>ஆர்வம் - நசரேயராக நடந்து கொள்வது (1: 11)</p><p>பட்டப்பெயர் - நடமாடும் நீதிமன்றம்</p><p>சாதனை - இறுதி நியாயாதிபதியாக பணியாற்றியது இஸ்ரவேலின் (1சாமு 7:15-7) இரு பெரிய அரசர்களை அபிஷேகம் பண்ணியது.</p><p><b>சில புள்ளிவிவரங்கள்</b></p><p>வேதாகமத்தின் 9-வது நூல்</p><p>அதிகாரங்கள் - 31</p><p>வசனங்கள் - 810</p><p>கேள்விகள் - 157</p><p>நிறைவேறிய தீர்க்க தரிசனங்கள் - 50</p><p>நிறைவேற வேண்டிய தீர்க்கதரிசனம் - 1</p><p>தேவளிடமிருந்து சிறப்புச் செய்திகள் - 29</p><p>வாக்குத்தத்தங்கள் - 4</p><p>கட்டளைகள் - 117</p><p>எச்சரிப்புகள் - 57</p>');
COMMIT;
